def connect_server_point_db(timeout: int = 30):
    conn = sqlite3.connect(SERVER_POINT_DB, timeout=timeout)
    conn.row_factory = sqlite3.Row
    return conn

def connect_user_point_db(timeout: int = 30):
    conn = sqlite3.connect(USER_POINT_DB, timeout=timeout)
    conn.row_factory = sqlite3.Row
    return conn

def _normalize_server_boss_counts(raw_counts) -> dict[str, int]:
    if raw_counts is None:
        return {}
    if isinstance(raw_counts, str):
        try:
            raw_counts = json.loads(raw_counts) if raw_counts.strip() else {}
        except json.JSONDecodeError:
            raw_counts = {}
    if not isinstance(raw_counts, dict):
        return {}

    cleaned = {}
    for tier, amount in raw_counts.items():
        tier_key = str(tier).strip().upper()
        if tier_key not in SERVER_POINT_VALID_BOSS_TIERS:
            continue
        try:
            clean_amount = int(amount)
        except (TypeError, ValueError):
            continue
        if clean_amount > 0:
            cleaned[tier_key] = clean_amount
    return cleaned


def _merge_server_boss_counts(base_counts, add_counts) -> dict[str, int]:
    merged = _normalize_server_boss_counts(base_counts)
    for tier, amount in _normalize_server_boss_counts(add_counts).items():
        merged[tier] = merged.get(tier, 0) + int(amount)
    return merged


def setup_server_point_db():
    conn = connect_server_point_db()
    c = conn.cursor()
    c.execute(
        """
        CREATE TABLE IF NOT EXISTS server_points (
            server_id INTEGER PRIMARY KEY,
            monthly_points INTEGER DEFAULT 0,
            claim_time INTEGER DEFAULT 0,
            total_points INTEGER DEFAULT 0,
            server_invite TEXT,
            server_duels INTEGER DEFAULT 0,
            server_boss TEXT DEFAULT '{}'
        )
        """
    )
    column_migrations = {
        "monthly_points": "ALTER TABLE server_points ADD COLUMN monthly_points INTEGER DEFAULT 0",
        "claim_time": "ALTER TABLE server_points ADD COLUMN claim_time INTEGER DEFAULT 0",
        "total_points": "ALTER TABLE server_points ADD COLUMN total_points INTEGER DEFAULT 0",
        "server_invite": "ALTER TABLE server_points ADD COLUMN server_invite TEXT",
        "server_duels": "ALTER TABLE server_points ADD COLUMN server_duels INTEGER DEFAULT 0",
        "server_boss": "ALTER TABLE server_points ADD COLUMN server_boss TEXT DEFAULT '{}'",
    }
    for statement in column_migrations.values():
        try:
            c.execute(statement)
        except sqlite3.OperationalError:
            pass
    conn.commit()
    conn.close()
