def _tower_required_wins(tower_id: int) -> int:
    return int(TOWER_BOSS_WINS_TO_REACH.get(int(tower_id), TOWER_STANDARD_WINS_TO_BOSS))


def _tower_user_progress(user_id: int) -> dict:
    uid = int(user_id)
    with connect_user_point_db() as conn:
        c = conn.cursor()
        c.execute("INSERT OR IGNORE INTO tower1 (user_id, tower_floor) VALUES (?, 0)", (uid,))
        conn.commit()
        rows = {}
        for table in ("tower1", "tower2", "tower3", "tower4", "tower5"):
            c.execute(f"SELECT * FROM {table} WHERE user_id = ?", (uid,))
            row = c.fetchone()
            rows[table] = dict(row) if row else None
    return rows


def _tower_unlocked_level(progress: dict) -> int:
    if progress.get("tower5"):
        return 5
    if progress.get("tower4"):
        return 4
    if progress.get("tower3"):
        return 3
    if progress.get("tower2"):
        return 2
    return 1


def _tower_alive_count(data: dict, slot: str = "p1") -> int:
    number = int(data.get("number", 3) or 3)
    alive = 0
    for i in range(1, number + 1):
        if int(data.get(f"{slot}_hp{i}") or 0) > 0:
            alive += 1
    return max(0, min(3, alive))


def _tower_display_floor(floor_value: int) -> int:
    return max(1, int(floor_value) + 1)


TOWER_DAILY_CHALLENGE_LIMIT = 60
TOWER_DAILY_RESET_SECONDS = 24 * 60 * 60
tower_daily_timer_cache: dict[int, dict] = {}
tower_weekly_currency_reset_date = None


def _tower_daily_state(user_id: int) -> dict:
    uid = int(user_id)
    now = int(time.time())
    cache = tower_daily_timer_cache.get(uid)
    if cache and now - cache.get("last_reset", 0) < TOWER_DAILY_RESET_SECONDS:
        return cache

    with connect_user_point_db() as conn:
        c = conn.cursor()
        c.execute(
            "INSERT OR IGNORE INTO tower_daily_limit (user_id, daily_count, last_reset) VALUES (?, 0, 0)",
            (uid,)
        )
        c.execute("SELECT daily_count, last_reset FROM tower_daily_limit WHERE user_id = ?", (uid,))
        row = c.fetchone() or (0, 0)
        daily_count = int(row[0] or 0)
        last_reset = int(row[1] or 0)
        if now - last_reset >= TOWER_DAILY_RESET_SECONDS:
            daily_count = 0
            last_reset = now
            c.execute(
                "UPDATE tower_daily_limit SET daily_count = 0, last_reset = ? WHERE user_id = ?",
                (last_reset, uid)
            )
            conn.commit()

    state = {"daily_count": daily_count, "last_reset": last_reset}
    tower_daily_timer_cache[uid] = state
    return state


def _tower_daily_challenges_remaining(user_id: int) -> tuple[int, int, int]:
    state = _tower_daily_state(user_id)
    remaining = max(0, TOWER_DAILY_CHALLENGE_LIMIT - int(state["daily_count"] or 0))
    return remaining, int(state["daily_count"] or 0), int(state["last_reset"] or 0)


def _tower_increment_daily_challenge(user_id: int) -> bool:
    uid = int(user_id)
    state = _tower_daily_state(uid)
    if int(state["daily_count"] or 0) >= TOWER_DAILY_CHALLENGE_LIMIT:
        return False
    new_count = int(state["daily_count"] or 0) + 1
    now = int(time.time())
    with connect_user_point_db() as conn:
        c = conn.cursor()
        c.execute(
            "INSERT OR IGNORE INTO tower_daily_limit (user_id, daily_count, last_reset) VALUES (?, 0, 0)",
            (uid,)
        )
        c.execute(
            "UPDATE tower_daily_limit SET daily_count = ?, last_reset = ? WHERE user_id = ?",
            (new_count, now, uid)
        )
        conn.commit()
    tower_daily_timer_cache[uid] = {"daily_count": new_count, "last_reset": now}
    return True


def _tower_next_weekly_reset_time() -> datetime:
    now = datetime.now(timezone.utc)
    next_monday = now + timedelta(days=(7 - now.weekday()) % 7)
    next_reset = next_monday.replace(hour=0, minute=0, second=0, microsecond=0)
    if next_reset <= now:
        next_reset += timedelta(days=7)
    return next_reset


def _tower_time_until_next_reset() -> str:
    delta = _tower_next_weekly_reset_time() - datetime.now(timezone.utc)
    total_seconds = int(delta.total_seconds())
    days = total_seconds // 86400
    hours = (total_seconds % 86400) // 3600
    minutes = (total_seconds % 3600) // 60
    parts = []
    if days:
        parts.append(f"{days}d")
    if hours:
        parts.append(f"{hours}h")
    if minutes or not parts:
        parts.append(f"{minutes}m")
    return " ".join(parts)


