def _tower_has_cosmetic(cos_conn: sqlite3.Connection, user_id: int, category: str,
                       cosmetic: str, pokemon_name: str | None = None) -> bool:
    if category == "pokemon":
        row = cos_conn.execute(
            "SELECT available_cosmetics FROM pokemon WHERE user_id=? AND pokemon_name=?",
            (user_id, pokemon_name)
        ).fetchone()
        if not row:
            return False
        return cosmetic in [x for x in (row[0] or "").split(",") if x]

    if category not in _TABLE_MAP:
        return False
    table, col = _TABLE_MAP[category]
    row = cos_conn.execute(f"SELECT {col} FROM {table} WHERE user_id=?", (user_id,)).fetchone()
    if not row:
        return False
    return cosmetic in [x for x in (row[0] or "").split(",") if x]


def _tower_has_unlocked_next_tower(conn: sqlite3.Connection, user_id: int, tower_id: int) -> bool:
    next_tower = tower_id + 1
    if next_tower > 5:
        return False
    return bool(conn.execute(f"SELECT 1 FROM tower{next_tower} WHERE user_id=?", (user_id,)).fetchone())


def _tower_floor_status_line(tower_id: int, row: dict | None) -> str:
    if row is None:
        return f"{TOWER_TEXT[tower_id]}: Locked"
    floor_value = int(row.get("tower_floor") or 0)
    required = _tower_required_wins(tower_id)
    on_boss = floor_value >= required
    boss_tag = " (Boss Floor)" if on_boss else ""
    return f"{TOWER_TEXT[tower_id]}: Floor {_tower_display_floor(floor_value)}{boss_tag}"


