def _tower_add_currency(user_id: int, currency: str, amount: int) -> tuple[bool, str]:
    if amount <= 0:
        return False, "Invalid refund amount."
    currency = str(currency or "").strip().lower()
    if currency in {"arc", "arcs"}:
        modify_coins(user_id, amount)
        return True, f"Refunded {amount} ARCs."
    if currency == "dragon_scale":
        with connect_user_point_db() as conn:
            c = conn.cursor()
            c.execute("INSERT OR IGNORE INTO tower2 (user_id, tower_floor, dragon_scale) VALUES (?, 0, 0)", (user_id,))
            c.execute("UPDATE tower2 SET dragon_scale = dragon_scale + ? WHERE user_id = ?", (amount, user_id))
            conn.commit()
        return True, f"Refunded {amount} Dragon Scale."
    if currency == "fantasy_gem":
        with connect_user_point_db() as conn:
            c = conn.cursor()
            c.execute("INSERT OR IGNORE INTO tower3 (user_id, tower_floor, fantasy_gem) VALUES (?, 0, 0)", (user_id,))
            c.execute("UPDATE tower3 SET fantasy_gem = fantasy_gem + ? WHERE user_id = ?", (amount, user_id))
            conn.commit()
        return True, f"Refunded {amount} Fantasy Gem."
    if currency in {"exchange_coupon", "coupon"}:
        with sqlite3.connect("cosmetics.db") as conn:
            c = conn.cursor()
            _ensure_exchange_coupon_tables(c)
            _increment_coupon(c, user_id, shiny=False, amount=amount)
            conn.commit()
        return True, f"Refunded {amount} Exchange Coupon(s)."
    if currency in {"shiny_exchange_coupon", "shiny_coupon", "sec"}:
        with sqlite3.connect("cosmetics.db") as conn:
            c = conn.cursor()
            _ensure_exchange_coupon_tables(c)
            _increment_coupon(c, user_id, shiny=True, amount=amount)
            conn.commit()
        return True, f"Refunded {amount} Shiny Exchange Coupon(s)."
    return False, "Unknown refund currency."


