@tasks.loop(minutes=1)
async def sync_collection_points():
    global collection_points_cache

    if not collection_points_cache:
        return

    try:
        conn = connect_user_point_db()
        c = conn.cursor()

        for user_id, points in collection_points_cache.items():
            c.execute("""
                INSERT INTO user_points (user_id, collection_points)
                VALUES (?, ?)
                ON CONFLICT(user_id)
                DO UPDATE SET collection_points = excluded.collection_points
            """, (user_id, points))
        
        for user_id, points in clan_collection_points_cache.items():
            c.execute("""
                INSERT INTO user_points (user_id, clan_collection_points)
                VALUES (?, ?)
                ON CONFLICT(user_id)
                DO UPDATE SET clan_collection_points = excluded.clan_collection_points
            """, (user_id, points))

        conn.commit()
        conn.close()

        collection_points_cache = {}

        print(f"[Collection Sync] Saved {len(collection_points_cache)} users.")

    except Exception:
        traceback.print_exc()


