# Helper function to load the JSON data from a file
def load_json_data(filepath):
    with open(filepath) as file:
        return json.load(file)

# Assuming your pokemon data is in a folder called 'pokemon_data_folder'
pokemon_data_folder = 'pokemon_data'
fakemon_data_folder = 'fakemon_data'
move_data_folder = 'move_data'

def _normalize_pokemon_lookup_name(pokemon_name: str) -> str:
    return str(pokemon_name or "").strip().lower()

def _resolve_pokemon_json_path(
    pokemon_name: str,
    allow_fake: bool = False,
    prefer_fake: bool = False
):
    name = _normalize_pokemon_lookup_name(pokemon_name)
    if not name:
        return None, False
    normal_path = os.path.join(pokemon_data_folder, f"{name}.json")
    fake_path = os.path.join(fakemon_data_folder, f"{name}.json")

    paths = []
    if allow_fake and prefer_fake:
        paths = [(fake_path, True), (normal_path, False)]
    elif allow_fake:
        paths = [(normal_path, False), (fake_path, True)]
    else:
        paths = [(normal_path, False)]

    for path, is_fake in paths:
        if os.path.exists(path):
            return path, is_fake
    return None, False

def load_pokemon_data_for_lookup(
    pokemon_name: str,
    allow_fake: bool = False,
    prefer_fake: bool = False
):
    path, is_fake = _resolve_pokemon_json_path(
        pokemon_name,
        allow_fake=allow_fake,
        prefer_fake=prefer_fake,
    )
    if not path:
        return None, None, False
    try:
        return load_json_data(path), path, is_fake
    except Exception:
        return None, path, is_fake


def _normalize_fakemon_signature(types: list[str], stats: dict, moves: list[str]) -> tuple[list[str], dict[str, int], list[str]]:
    clean_types = sorted([str(t).strip().lower() for t in (types or []) if str(t).strip()])
    clean_stats = {key: int(value) for key, value in (stats or {}).items()}
    clean_moves = sorted([str(m).strip().lower() for m in (moves or []) if str(m).strip()])
    return clean_types, clean_stats, clean_moves


def _find_duplicate_fakemon(types: list[str], stats: dict, moves: list[str]) -> str | None:
    if not os.path.isdir(fakemon_data_folder):
        return None

    target_types, target_stats, target_moves = _normalize_fakemon_signature(types, stats, moves)
    for entry in os.listdir(fakemon_data_folder):
        if not entry.endswith(".json"):
            continue
        file_path = os.path.join(fakemon_data_folder, entry)
        try:
            existing = load_json_data(file_path)
        except Exception:
            continue

        existing_types, existing_stats, existing_moves = _normalize_fakemon_signature(
            existing.get("types", []),
            existing.get("stats", {}),
            [mv.get("move", "") for mv in existing.get("moves_via_level_up", []) if isinstance(mv, dict)],
        )

        if existing_types == target_types and existing_stats == target_stats and existing_moves == target_moves:
            return existing.get("name") or os.path.splitext(entry)[0]

    return None

# Fetches the height, weight, and sprite URL of a Pokémon (from local JSON files)
def get_pokemon_info(pokemon_name: str, shiny=True, allow_fake=False, prefer_fake=False):
    pokemon_data, _, _ = load_pokemon_data_for_lookup(
        pokemon_name,
        allow_fake=allow_fake,
        prefer_fake=prefer_fake,
    )
    if pokemon_data:
        height = pokemon_data.get("height", 0) / 10  # Convert to meters (handle missing data gracefully)
        weight = pokemon_data.get("weight", 0) / 10  # Convert to kilograms (handle missing data gracefully)
        sprites = pokemon_data.get("sprites", "none")
        if shiny == True:
            sprite = sprites.get("shiny_front", f"{'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/shiny/' + str(pokemon_data.get('id', 0)) + '.png'}")
        else:
            sprite = sprites.get("default_front", f"{'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/' + str(pokemon_data.get('id', 0)) + '.png'}")
        return height, weight, sprite
    return None, None, None  # Return None if Pokémon not found

def get_pokemon_name(index):
    name = pokemon_id_name_map.get(str(index)) or pokemon_id_name_map.get(int(index))
    if name:
        return name.capitalize()
    return f"Pokémon with index {index} not found."
def get_move_name(index):
    for filename in os.listdir(move_data_folder):
        move_filepath = os.path.join(move_data_folder, filename)
        move_data = load_json_data(move_filepath)
        if move_data and move_data.get("id") == index:
            return move_data["name"].capitalize()
    return f"Pokémon with index {index} not found."

def _resolve_move_data_filepath(move_name: str) -> str | None:
    move_key = str(move_name or "").strip().lower()
    if not move_key:
        return None
    aliases = [move_key]
    aliases.append(move_key.replace("-", " "))
    aliases.append(move_key.replace(" ", "-"))
    if move_key == "double edge":
        aliases.insert(0, "double-edge")

    seen = set()
    for key in aliases:
        if not key or key in seen:
            continue
        seen.add(key)
        filepath = os.path.join("move_data", f"{key}.json")
        if os.path.exists(filepath):
            return filepath
    return None

