def fetch_type_effectiveness():
    """Fetch the type effectiveness from the PokeAPI and build a type chart."""
    url = "https://pokeapi.co/api/v2/type/"
    try:
        response = requests.get(url, timeout=10)
        if response.status_code != 200:
            logging.warning("Failed to fetch type data")
            return {}
    except (requests.Timeout, requests.ConnectionError, Exception) as e:
        logging.warning(f"Error fetching type effectiveness: {e}")
        return {}

    type_data = response.json()
    type_chart = {}

    # Initialize type chart for all types with default effectiveness (neutral, 1x)
    all_types = [type_info['name'] for type_info in type_data['results']]
    for type_name in all_types:
        type_chart[type_name] = {other_type: 1 for other_type in all_types}  # Start with neutral (1x) effectiveness

    # For each type, get its effectiveness against other types
    for type_info in type_data['results']:
        type_name = type_info['name']
        
        # Fetch the detailed effectiveness information for this type
        type_url = type_info['url']
        type_details = requests.get(type_url).json()

        # Loop through each damage relation category and apply to the chart
        for damage_class, related_types in type_details['damage_relations'].items():
            # Define effectiveness based on the damage class
            if damage_class == 'no_damage_to':
                effectiveness = 0  # No effect
            elif damage_class == 'half_damage_to':
                effectiveness = 0.5  # Not very effective
            elif damage_class == 'double_damage_to':
                effectiveness = 2  # Super effective
            else:
                continue  # Skip other categories

            # Update the effectiveness chart
            for related_type in related_types:
                related_type_name = related_type['name']
                type_chart[type_name][related_type_name] = effectiveness

    return type_chart
