def generate_effectiveness_table(types):
    # Initialize a dictionary to store effectiveness results
    effectiveness_table = {
        "super effective (4)": [],
        "effective (2)": [],
        "neutral (1)": [],
        "ineffective (0.5)": [],
        "super ineffective (0.25)": [],
        "immune (0)": []
    }

    # List of all possible move types
    all_types = [
        'normal', 'fighting', 'flying', 'poison', 'ground', 'rock', 'bug', 'ghost', 
        'steel', 'fire', 'water', 'grass', 'electric', 'psychic', 'ice', 'dragon', 
        'dark', 'fairy', 'stellar', 'unknown'
    ]

    # Generate the effectiveness for each type
    for move_type in all_types:
        effectiveness = get_effectiveness(move_type, types)
        
        # Categorize based on effectiveness
        if effectiveness == 4:
            effectiveness_table["super effective (4)"].append(move_type)
        elif effectiveness == 2:
            effectiveness_table["effective (2)"].append(move_type)
        elif effectiveness == 1:
            effectiveness_table["neutral (1)"].append(move_type)
        elif effectiveness == 0.5:
            effectiveness_table["ineffective (0.5)"].append(move_type)
        elif effectiveness == 0.25:
            effectiveness_table["super ineffective (0.25)"].append(move_type)
        elif effectiveness == 0:
            effectiveness_table["immune (0)"].append(move_type)

    return effectiveness_table
def dmg_calc(move:str, attacker:str, defender:str, atkiv:int=31, defiv:int=31, hpiv:int=31, atk_mint:str='neutral, neutral', def_mint:str='neutral, neutral', atk_debuff:int=0, def_debuff:int=0, atk_ev: int = None, def_ev: int = None, hp_ev: int = 20, atk_buff: int = 0, def_buff:int = 0):
    atk_mint_list = atk_mint.split(', ')
    def_mint_list = def_mint.split(', ')
    if attacker.lower() == "zenith marshadow":
        attacker = "marshadow"
    if defender.lower() == "zenith marshadow":
        defender = "marshadow"
    bp, cata, move_type = get_move_info(move)
    atk, atk_type = get_pokemon_stats(attacker)
    df, df_type = get_pokemon_stats(defender)
    hp = df[0]
    if move.lower() == 'judgment':
        move_type = atk_type[0]
    type_multiplier = get_effectiveness(move_type, df_type)
    stab = 1.5 if move_type in atk_type else 1
    mint1 = 1
    mint2 = 1
    if cata == "physical":
        if atk_mint_list[0] == '+atk':
           mint1 = 1.1
        elif atk_mint_list[1] == '-atk':
           mint1 = 0.9
        if def_mint_list[0] == '+def':
           mint2 = 1.1
        elif def_mint_list[1] == '-def':
           mint2 = 0.9
        if atk_ev and def_ev:
            value = round((42 * bp * math.floor((2 * atk[1] + atkiv + 5 + atk_ev/4) * mint1 *(2/(2+atk_debuff)) * ((2+atk_buff)/2) ) / ((2 * df[2] + defiv + 5 + def_ev/4) *mint2 *(2/(2+def_debuff)) * ((2+def_buff)/2)) / 50  + 2)) * (stab) * (type_multiplier)
        else:
            value = math.floor(42 * bp * math.floor((2 * atk[1] + atkiv + 10) * mint1 *(2/(2+atk_debuff))*((2+atk_buff)/2) ) / math.floor((2 * df[2] + defiv + 10) *mint2 *(2/(2+def_debuff))* ((2+def_buff)/2)) / 50  + 2) * (stab) * (type_multiplier)
        percent = round(value / (hp * 2 + hpiv + 110 + hp_ev/4) * 100, 2)
        print_out = f'{move} from {attacker}{get_pokemon_emoji(attacker)} deals **{value}** dmg to {defender}{get_pokemon_emoji(defender)} \n**{percent}%** of its hp (Total HP: {hp * 2 + hpiv + 110 + hp_ev/4}) \nAttacker Nature: {atk_mint} \nDefender Nature: {def_mint} \nAttacker Debuffs: {atk_debuff} \nDefender Debuff: {def_debuff} '
    elif cata == "special":
        if atk_mint_list[0] == '+spatk':
           mint1 = 1.1
        elif atk_mint_list[1] == '-spatk':
           mint1 = 0.9
        else:
           mint1 = 1
        if def_mint_list[0] == '+spdef':
           mint2 = 1.1
        elif def_mint_list[1] == '-spdef':
           mint2 = 0.9
        if atk_ev or def_ev:
            if not atk_ev:
                atk_ev = 0
            if not def_ev:
                def_ev = 0
            value = round((42 * bp * math.floor((2 * atk[3] + atkiv + 5 + atk_ev/4) * mint1 *(2/(2+atk_debuff))* ((2+atk_buff)/2) ) / ((2 * df[4] + defiv + 5 + def_ev/4) *mint2 *(2/(2+def_debuff)* (2+def_buff)/2)) / 50  + 2)) * (stab) * (type_multiplier)
        else:
            value = math.floor(42 * bp * math.floor((2 * atk[3] + atkiv + 10) *mint1 *(2/(2+atk_debuff))* ((2+atk_buff)/2)) / math.floor((2 * df[4] + defiv + 10) * mint2 *(2/(2+def_debuff)* (2+def_buff)/2)) / 50 + 2) * (stab) * (type_multiplier)
        percent = round(value / (hp * 2 + hpiv + 110 + hp_ev/4) * 100, 2)
        print_out = f'{move} from {attacker}{get_pokemon_emoji(attacker)} deals **{value}** dmg to {defender}{get_pokemon_emoji(defender)} \n**{percent}%** of its hp (Total HP: {hp * 2 + hpiv + 110 + hp_ev/4}) \nAttacker Nature: {atk_mint} \nDefender Nature: {def_mint} \nAttacker Debuffs: {atk_debuff} \nDefender Debuff: {def_debuff} '
    else:
        print_out = 'No such move, remember for move with 2 words like giga impact, use giga impact'
        value = 0 
        percent = 0
    print_out += "\n-# Duel with /battle. Create your own fakemon with !cp."
    return print_out, value, percent
