USER_FETCH_DELAY_SECONDS = 0.35

async def get_user_safely(user_id: int, cache: dict[int, discord.User]):
    user = cache.get(user_id) or bot.get_user(user_id)
    if user:
        return user

    for attempt in range(3):
        try:
            user = await bot.fetch_user(user_id)
            cache[user_id] = user
            return user
        except discord.NotFound:
            return None
        except discord.HTTPException as e:
            if e.status == 429 and attempt < 2:
                retry_after = getattr(e, "retry_after", 1.0)
                await asyncio.sleep(float(retry_after) + 0.25)
                continue
            return None
        finally:
            await asyncio.sleep(USER_FETCH_DELAY_SECONDS)

    return None


def _extract_member_id(value: str) -> int | None:
    if value is None:
        return None
    match = re.search(r"([0-9]{15,20})", str(value))
    if not match:
        return None
    try:
        return int(match.group(1))
    except ValueError:
        return None


async def get_member_safely(
    guild: discord.Guild,
    member_id: int | None = None,
    *,
    display_name: str | None = None,
    nickname: str | None = None,
) -> discord.Member | None:
    if guild is None:
        return None

    if member_id is not None:
        cached = guild.get_member(member_id)
        if cached:
            return cached
        try:
            return await guild.fetch_member(member_id)
        except (discord.NotFound, discord.Forbidden, discord.HTTPException):
            return None

    def exact_match(member: discord.Member, value: str) -> bool:
        lower = value.casefold()
        return (
            (member.display_name or "").casefold() == lower
            or (member.name or "").casefold() == lower
            or (getattr(member, "global_name", None) or "").casefold() == lower
            or (member.nick or "").casefold() == lower
        )

    def partial_match(member: discord.Member, value: str) -> bool:
        lower = value.casefold()
        return (
            lower in (member.display_name or "").casefold()
            or lower in (member.name or "").casefold()
            or lower in (getattr(member, "global_name", None) or "").casefold()
            or lower in (member.nick or "").casefold()
        )

    if nickname:
        member = discord.utils.find(
            lambda m: exact_match(m, nickname),
            guild.members,
        )
        if member:
            return member
        if hasattr(guild, "query_members"):
            try:
                candidates = await guild.query_members(query=nickname, limit=50)
            except Exception:
                candidates = []
            for m in candidates:
                if exact_match(m, nickname) or partial_match(m, nickname):
                    return m

    if display_name:
        member = discord.utils.find(
            lambda m: exact_match(m, display_name),
            guild.members,
        )
        if member:
            return member
        if hasattr(guild, "query_members"):
            try:
                candidates = await guild.query_members(query=display_name, limit=50)
            except Exception:
                candidates = []
            for m in candidates:
                if exact_match(m, display_name) or partial_match(m, display_name):
                    return m

    return None


async def get_member_display_name_safely(guild: discord.Guild | None, user_id: int) -> str:
    if guild is not None:
        member = await get_member_safely(guild, user_id)
        if member is not None:
            return member.display_name

    user = bot.get_user(user_id)
    if user is not None:
        return getattr(user, "display_name", None) or user.name

    try:
        user = await bot.fetch_user(user_id)
        return getattr(user, "display_name", None) or user.name
    except Exception:
        return str(user_id)


_MEMBER_MENTION_RE = re.compile(r"<@!?([0-9]{15,20})>$")


class FetchFirstMemberConverter(commands.MemberConverter):
    async def convert(self, ctx: commands.Context, argument: str) -> discord.Member:
        guild = ctx.guild
        if guild is not None:
            match = self._get_id_match(argument) or _MEMBER_MENTION_RE.match(argument)
            if match:
                member = await get_member_safely(guild, int(match.group(1)))
                if member is not None:
                    return member
        return await super().convert(ctx, argument)


try:
    commands.converter.CONVERTER_MAPPING[discord.Member] = FetchFirstMemberConverter
except Exception as e:
    print(f"Failed to install custom discord.Member converter: {e}")

async def restore_persistent_gw_views_slowly():
    filepath = "persistent_gw_views.json"
    if not os.path.exists(filepath):
        print(f"{filepath} not found; skipping persistent GW view restore.")
        return

    with open(filepath, "r") as f:
        try:
            views_data = json.load(f)
        except json.JSONDecodeError:
            views_data = []

    if not views_data:
        print("No persistent GW views found to restore.")
        return

    updated_data = []
    total_views = len(views_data)

    for index, data in enumerate(views_data, start=1):
        try:
            # Fetch channel and message for this persisted entry.
            channel = await bot.fetch_channel(data["channel_id"])
            message = await channel.fetch_message(data["message_id"])

            # Fetch host and weighted users.
            user_cache = {}
            host = await get_user_safely(data["host_id"], user_cache)
            if host is None:
                print(f"Host {data.get('host_id')} not found; skipping {data.get('message_id')}.")
                continue

            weighted_users = []
            for uid in data.get("weighted_users", []):
                u = await get_user_safely(uid, user_cache)
                if u is not None:
                    weighted_users.append(u)


            # Restore view for this one message only.
            view = GwClose(channel, weighted_users, data["prize"], host)
            bot.add_view(view, message_id=message.id)
            print(f"Restored persistent view for message {message.id} ({index}/{total_views})")

            # Keep valid entries in file.
            updated_data.append(data)

        except discord.NotFound:
            print(f"Message {data.get('message_id')} not found; removing from persistent file.")
            # Skip adding to updated_data -> effectively deletes it

        except discord.Forbidden:
            print(f"No access to channel {data.get('channel_id')}; keeping entry for retry later.")
            updated_data.append(data)

        except Exception as e:
            print(f"Failed to restore view for message {data.get('message_id')}: {e}")
            updated_data.append(data)

        if index < total_views:
            await asyncio.sleep(GW_VIEW_RESTORE_INTERVAL_SECONDS)

    with open(filepath, "w") as f:
        json.dump(updated_data, f, indent=4)

    print(f"Finished restoring persistent GW views. Kept {len(updated_data)}/{total_views} entries.")


def start_persistent_gw_view_restore_task():
    global gw_view_restore_task
    if gw_view_restore_task and not gw_view_restore_task.done():
        print("Persistent GW view restore task already running; skipping duplicate start.")
        return
    gw_view_restore_task = asyncio.create_task(restore_persistent_gw_views_slowly())
    print("Started persistent GW view restore task (1 view every 10 seconds).")
