# --- Cache Helpers ---
def load_emoji_cache():
    if os.path.exists(EMOJI_CACHE_FILE):
        with open(EMOJI_CACHE_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    return {}

def save_emoji_cache(cache):
    with open(EMOJI_CACHE_FILE, "w", encoding="utf-8") as f:
        json.dump(cache, f, indent=2)

def sanitize_emoji_name(name: str) -> str:
    """
    Discord emoji name rules: Alphanumeric + underscores, 2-32 chars.
    """
    name = name.lower()
    name = re.sub(r"[^a-z0-9_]", "_", name)
    return name[:32]

# --- Core Refactored Functions ---

def delete_discord_emoji(emoji_id: str, pokemon_name: str):
    """Deletes an application emoji from Discord."""
    url = f"https://discord.com/api/v10/applications/{APP_ID}/emojis/{emoji_id}"
    headers = {
        "Authorization": f"Bot {BOT_TOKEN}"
    }
    try:
        response = requests.delete(url, headers=headers, timeout=10)
        if response.status_code == 204:
            print(f"Successfully deleted old emoji for {pokemon_name} from Discord.")
            return True
        elif response.status_code == 404:
            print(f"Old emoji for {pokemon_name} already removed or not found on Discord.")
            return True
        else:
            print(f"Failed to delete old emoji for {pokemon_name}: {response.status_code} - {response.text}")
            return False
    except Exception as e:
        print(f"Error deleting old emoji for {pokemon_name}: {e}")
        return False


def upload_pokemon_emoji(pokemon_name: str, sprite_url: str):
    """Downloads a sprite URL and uploads it as an Application Emoji to Discord."""
    if not sprite_url:
        print(f"No sprite URL available for {pokemon_name}")
        return None

    # --- Download sprite ---
    try:
        r = requests.get(sprite_url, timeout=10)
        if r.status_code != 200:
            logging.warning(f"Failed to download sprite from {sprite_url}")
            return None
    except (requests.Timeout, requests.ConnectionError, Exception) as e:
        logging.warning(f"Error downloading sprite: {e}")
        return None

    image_bytes = r.content

    # --- Convert to base64 ---
    b64 = base64.b64encode(image_bytes).decode("utf-8")

    # Detect png vs gif
    mime = "image/png"
    if sprite_url.lower().endswith(".gif") or ".gif" in sprite_url.lower():
        mime = "image/gif"

    payload = {
        "name": sanitize_emoji_name(pokemon_name),
        "image": f"data:{mime};base64,{b64}"
    }

    headers = {
        "Authorization": f"Bot {BOT_TOKEN}",
        "Content-Type": "application/json"
    }

    url = f"https://discord.com/api/v10/applications/{APP_ID}/emojis"

    response = requests.post(url, json=payload, headers=headers)

    if response.status_code in (200, 201):
        data = response.json()
        emoji_id = data["id"]
        print(f"Uploaded {pokemon_name} -> {emoji_id}")
        return emoji_id

    print("Upload failed:", response.status_code, response.text)
    return None


def upload_all_pokemon_emojis(input_folder="pokemon_data", new_sprite_folder="new_sprite_data"):
    if not os.path.exists(input_folder):
        print(f"Error: Directory '{input_folder}' does not exist.")
        return

    emoji_cache = load_emoji_cache()
    
    uploaded = 0
    skipped = 0
    failed = 0

    # Sorting files alphabetically guarantees base forms (e.g. arceus.json) 
    # run before variant forms (e.g. arceus-bug.json)
    files = sorted(os.listdir(input_folder))

    for file_name in files:
        if not file_name.endswith('.json'):
            continue

        file_path = os.path.join(input_folder, file_name)
        
        # 1. Read name and ID from files in pokemon_data
        try:
            with open(file_path, "r", encoding="utf-8") as f:
                local_data = json.load(f)
        except Exception as e:
            print(f"Skipped: Error reading local file '{file_name}': {e}")
            continue

        pokemon_name = local_data.get("name")
        pokemon_id = local_data.get("id")

        if not pokemon_name or pokemon_id is None:
            print(f"Skipped: Missing 'name' or 'id' in '{file_name}'")
            continue

        name_lower = pokemon_name.lower()

        # Exception Rule: Ignore thunder rider calyrex
        if "thunder rider calyrex" in name_lower:
            print(f"Skipped: Explicitly ignoring {pokemon_name}")
            continue

        # Exception Rule: Arceus, Koraidon, Miraidon sub-forms mapping
        base_legendary = None
        for base in ["arceus", "koraidon", "miraidon"]:
            if base in name_lower and name_lower != base:
                base_legendary = base
                break

        if base_legendary:
            if base_legendary in emoji_cache:
                emoji_cache[name_lower] = emoji_cache[base_legendary]
                save_emoji_cache(emoji_cache)
                print(f"Mapped variant '{name_lower}' to base '{base_legendary}' emoji without uploading.")
                skipped += 1
                continue
            else:
                print(f"Warning: Base form '{base_legendary}' not found in cache yet while processing '{name_lower}'. Proceeding standard flow.")

        # 2 & 3. If emoji exists, delete it from Discord and cache
        if name_lower in emoji_cache:
            old_emoji_id = emoji_cache[name_lower]
            print(f"Found existing emoji for {name_lower} ({old_emoji_id}). Deleting...")
            delete_discord_emoji(old_emoji_id, name_lower)
            del emoji_cache[name_lower]
            save_emoji_cache(emoji_cache)

        # 4. Attempt to fetch URL from new_sprite_data using ID mapping
        sprite_url = None
        new_sprite_path = os.path.join(new_sprite_folder, f"{pokemon_id}.json")
        
        if os.path.exists(new_sprite_path):
            try:
                with open(new_sprite_path, "r", encoding="utf-8") as nsf:
                    new_sprite_data = json.load(nsf)
                    sprite_url = new_sprite_data.get("showdown_gif")
            except Exception as e:
                print(f"Error reading path {new_sprite_path}: {e}")

        # 5. Fallback: Use the original link from the pokemon_data file
        if not sprite_url:
            print(f"Could not find ID {pokemon_id} in {new_sprite_folder}. Falling back to original file.")
            # Looking up common image keys in your primary file structure
            if "showdown_gif" in local_data:
                sprite_url = local_data["showdown_gif"]
            elif "sprite_url" in local_data:
                sprite_url = local_data["sprite_url"]
            elif "sprites" in local_data and isinstance(local_data["sprites"], dict):
                # Dig into traditional pokeapi layout if available
                sprites_obj = local_data["sprites"]
                other_obj = sprites_obj.get("other", {}) if sprites_obj else {}
                showdown_obj = other_obj.get("showdown", {}) if other_obj else {}
                sprite_url = showdown_obj.get("front_default") or sprites_obj.get("front_default")

        # Execute upload process
        print(f"Processing upload for {name_lower}...")
        new_emoji_id = upload_pokemon_emoji(name_lower, sprite_url)

        if new_emoji_id:
            emoji_cache[name_lower] = new_emoji_id
            save_emoji_cache(emoji_cache)
            uploaded += 1
        else:
            failed += 1

        # Rate limit safety delay
        time.sleep(0.5)

    print(f"""
    ======================================
    Done processing Pokémon emojis:
    Uploaded (or Replaced): {uploaded}
    Skipped/Mapped:         {skipped}
    Failed:                 {failed}
    ======================================
    """)


