AUTO_ACTION_CACHE = {}

@tasks.loop(count=1)
async def post_ready_guild_init():

    await bot.wait_until_ready()

    total = 0
    guilds_added = []

    loop = asyncio.get_running_loop()

    def load_auto_actions(guild_id: int):

        conn = sqlite3.connect("auto_action.db")
        conn.row_factory = sqlite3.Row

        cur = conn.cursor()

        cur.execute(
            """
            SELECT *
            FROM auto_actions
            WHERE guild_id=?
            ORDER BY id
            """,
            (guild_id,)
        )

        rows = [
            dict(row)
            for row in cur.fetchall()
        ]

        conn.close()

        return rows

    with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:

        for guild in bot.guilds:

            try:

                AUTO_ACTION_CACHE[guild.id] = (
                    await loop.run_in_executor(
                        executor,
                        load_auto_actions,
                        guild.id
                    )
                )

                total += 1
                guilds_added.append(guild.name)

                await asyncio.sleep(0.02)

                if total % 10 == 0:
                    print(total)
                    print(guilds_added)
                    guilds_added = []

            except Exception as e:
                print(
                    f"Error loading auto actions for guild "
                    f"{guild.id}: {e}"
                )

    print(
        f"Loaded auto action cache for "
        f"{len(AUTO_ACTION_CACHE)} guilds."
    )

    if total > 1100:
        post_server_count(total)

    channel_id = 1333642558743515186

    alert_channel = bot.get_channel(
        channel_id
    )

    if alert_channel is None:
        alert_channel = await bot.fetch_channel(
            channel_id
        )

    await alert_channel.send(
        f"<a:green_dot:1383016833040515142>"
        f"Bot is Up\n"
        f"New updates\n"
        f"{total} servers synced\n"
        f"{sum(len(v) for v in AUTO_ACTION_CACHE.values())} "
        f"auto actions cached"
    )

