def setup_invite_code_db():
    conn = sqlite3.connect("invite_codes.db")
    cursor = conn.cursor()
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS invite_codes (
            guild_id INTEGER,
            code TEXT PRIMARY KEY,
            inviter_id INTEGER
        )
    """)
    conn.commit()
    conn.close()
def store_invite_code(guild_id: int, code: str, inviter_id: int):
    conn = sqlite3.connect("invite_codes.db")
    cursor = conn.cursor()
    cursor.execute("""
        INSERT OR REPLACE INTO invite_codes (guild_id, code, inviter_id)
        VALUES (?, ?, ?)
    """, (guild_id, code, inviter_id))
    conn.commit()
    conn.close()
def reschedule_all_reminders():
    data = load_reminders()
    now = datetime.now(timezone.utc)
    for r in data:
        run_time = datetime.fromisoformat(r["run_time"])
        if r["recursive"]:
            scheduler.add_job(
                run_async_reminder,
                trigger='interval',
                seconds=r["interval"],
                start_date=run_time,
                args=[r["channel_id"], r["user_id"], r["message"], r["is_dm"]]
            )
        else:
            if run_time > now:
                scheduler.add_job(
                    run_async_reminder,
                    trigger='date',
                    run_date=run_time,
                    args=[r["channel_id"], r["user_id"], r["message"], r["is_dm"]]
                )

