# ─── SAFE EVAL ───
SAFE_FUNCTIONS = {
    "sqrt": math.sqrt,
    "root": lambda x: math.sqrt(x),
    "pow": pow
}

SAFE_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Pow: operator.pow,
    ast.USub: operator.neg
}

def eval_expr(node, chain):
    if isinstance(node, ast.Constant):  # Python 3.8+
        return node.value
    elif isinstance(node, ast.Num):  # older Python
        return node.n
    elif isinstance(node, ast.BinOp):
        return SAFE_OPERATORS[type(node.op)](eval_expr(node.left, chain), eval_expr(node.right, chain))
    elif isinstance(node, ast.UnaryOp):
        return SAFE_OPERATORS[type(node.op)](eval_expr(node.operand, chain))
    elif isinstance(node, ast.Name):
        if node.id == "chain":
            return chain
        raise ValueError(f"Invalid variable {node.id}")
    elif isinstance(node, ast.Call):
        func_name = node.func.id
        if func_name not in SAFE_FUNCTIONS:
            raise ValueError(f"Function {func_name} not allowed")
        args = [eval_expr(arg, chain) for arg in node.args]
        return SAFE_FUNCTIONS[func_name](*args)
    else:
        raise TypeError(node)

def parse_formula(formula: str, chain: int):
    formula = formula.replace("^", "**").replace("root", "sqrt")
    tree = ast.parse(formula, mode="eval")
    return eval_expr(tree.body, chain)

def cumulative_shiny_probability(chains: int, formula: str, boost: float = 0.0):
    prob_no_shiny = 1.0
    for chain in range(chains):
        p = parse_formula(formula, chain) / 3413.3
        p *= (1 + boost / 100)
        if p > 1:
            p = 1
        prob_no_shiny *= (1 - p)
    # Probability of at least one shiny
    return 1 - prob_no_shiny

def next_shiny_probability(chain: int, formula: str, boost: float = 0.0):
    p = parse_formula(formula, chain) / 4096
    p *= (1 + boost / 100)
    return min(p, 1.0)

