@bot.tree.command(name="shinychance", description="Calculate cumulative shiny probability for a chain")
@app_commands.describe(
    chains="Number of shiny chain",
    boost="Shiny % boost (optional)",
    formula="Shiny formula, e.g., '1+sqrt(chain)/7' or '1+chain^0.5/10'"
)
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def shiny_chain(
    interaction: discord.Interaction,
    chains: int,
    boost: float = 0.0,
    formula: str = "1+sqrt(chain)/7"
):
    # Prevent extremely large requests from monopolizing CPU.
    if chains < 0 or chains > 500_000:
        return await interaction.response.send_message(
            "❌ `chains` must be between 0 and 500000.",
            ephemeral=True
        )

    def _compute():
        cumulative_prob = cumulative_shiny_probability(chains, formula, boost)
        next_prob = next_shiny_probability(chains, formula, boost)
        return cumulative_prob, next_prob

    try:
        # Defer quickly so Discord sees the command as acknowledged.
        await interaction.response.defer(thinking=True)

        # Run CPU-heavy work in a thread and cap total wait time.
        cumulative_prob, next_prob = await asyncio.wait_for(
            asyncio.to_thread(_compute),
            timeout=8
        )

        embed = discord.Embed(
            title="✨ Shiny Chain Probability",
            color=discord.Color.gold(),
            description=(
                f"Shiny chain length: {chains}\n"
                f"Shiny boost: {boost}%\n"
                f"Formula: `{formula}`/4096\n\n"
                f"✅ Probability of at least one shiny within the chain: **{cumulative_prob*100:.2f}%**\n"
                f"🎯 Probability for the next encounter to be shiny: **{next_prob*100:.2f}%**"
            )
        )
        await interaction.followup.send(embed=embed)
    except asyncio.TimeoutError:
        await interaction.followup.send(
            "⏰ This calculation took too long and was cancelled. Try fewer chains or a simpler formula.",
            ephemeral=True
        )
    except Exception as e:
        if interaction.response.is_done():
            await interaction.followup.send(f"❌ Error: {e}", ephemeral=True)
        else:
            await interaction.response.send_message(f"❌ Error: {e}", ephemeral=True)

def name_finder(pokemon_name):
    pokemon_name = _normalize_pokemon_lookup_name(pokemon_name)
    if not pokemon_name:
        return "wrong name"
    if _resolve_pokemon_json_path(pokemon_name, allow_fake=True)[0]:
        return pokemon_name
    pokemon_names = []
    file_path = 'pokemon_names.txt'
    with open(file_path, 'r') as file:
        lines = file.readlines()
        for line in lines:
            pokemon_names.append(line[:-1])
    matches = difflib.get_close_matches(pokemon_name, pokemon_names, n=1, cutoff=0.8)
    if matches:
        return matches[0]
    else:
        return pokemon_name

