def get_server_ev(guild_id: int) -> int:
    folder = "calc_configs"
    path = os.path.join(folder, f"{guild_id}.json")

    if not os.path.exists(path):
        return 20  # default fallback

    try:
        with open(path, "r") as f:
            data = json.load(f)
            return int(data.get("ev", 20))
    except Exception:
        return 20
