# Define Modal for user input
class DmgCalcModal(Modal):
    def __init__(self, title: str, field_name: str, initial_value: str):
        super().__init__(title=title)
        self.field_name = field_name
        self.input_value = TextInput(label=f"Enter {field_name}", default=initial_value, required=True)

        self.add_item(self.input_value)

        # Nature dictionary to map the input to the corresponding stat changes
        self.nature_dict = {
            'Adamant': '+atk, -spatk',
            'Brave': '+atk, -spd',
            'Lonely': '+atk, -def',
            'Naughty': '+atk, -spdef',
            'Jolly': '+spd, -spatk',
            'Timid': '+spd, -atk',
            'Naive': '+spd, -spdef',
            'Hasty': '+spd, -def',
            'Bold': '+def, -atk',
            'Impish': '+def, -spatk',
            'Lax': '+def, -spdef',
            'Relaxed': '+def, -spd',
            'Modest': '+spatk, -atk',
            'Mild': '+spatk, -def',
            'Rash': '+spatk, -spdef',
            'Quiet': '+spatk, -spd',
            'Calm': '+spdef, -atk',
            'Gentle': '+spdef, -def',
            'Careful': '+spdef, -spatk',
            'Sassy': '+spdef, -spd',
            'Hardy': 'neutral, neutral'
        }

    async def on_submit(self, interaction: discord.Interaction):
        # Get the input value
        value = self.input_value.value

        # Check if the input value is a valid nature and map it
        if self.field_name == "Atk Nature" or self.field_name == "Def Nature":
            if value in self.nature_dict:
                value = self.nature_dict[value]
            else:
                await interaction.response.send_message(f"Invalid nature: {value}", ephemeral=True)
                return

        # Update the corresponding argument based on the field name
        if self.field_name == "Atk IV":
            self.view.atkiv = int(value)
        elif self.field_name == "Def IV":
            self.view.defiv = int(value)
        elif self.field_name == "HP IV":
            self.view.hpiv = int(value)
        elif self.field_name == "Atk Nature":
            self.view.atk_mint = value
        elif self.field_name == "Def Nature":
            self.view.def_mint = value
        elif self.field_name == "Atk Debuff":
            self.view.atk_debuff = int(value)
        elif self.field_name == "Def Debuff":
            self.view.def_debuff = int(value)

        # Recalculate and update the message
        await self.view.update_message()
        await interaction.response.send_message('Updated', ephemeral=True)
        self.stop()

# Modify View class to handle the button presses and trigger modals
class DmgCalcView(View):
    def __init__(self, interaction, move, attacker, defender, atkiv, defiv, hpiv, atk_mint, def_mint, atk_debuff, def_debuff):
        super().__init__()
        self.interaction = interaction
        self.move = move
        self.attacker = attacker
        self.defender = defender
        self.atkiv = atkiv
        self.defiv = defiv
        self.hpiv = hpiv
        self.atk_mint = atk_mint
        self.def_mint = def_mint
        self.atk_debuff = atk_debuff
        self.def_debuff = def_debuff
        self.initial_message = None

    async def update_message(self):
        try:
            print_out, value, percent = dmg_calc(self.move, self.attacker, self.defender, 
                                                 self.atkiv, self.defiv, self.hpiv, 
                                                 self.atk_mint, self.def_mint, 
                                                 self.atk_debuff, self.def_debuff)
            if self.initial_message:
                # Edit the original message
                await self.initial_message.edit(content=print_out, view=self)
            else:
                # If the message doesn't exist (this shouldn't happen now), send a new one
                await self.interaction.followup.send(print_out, view=self)
        except Exception as e:
            print(f"Error: {e}")
            print_out = 'There was an error in processing your request.\nPokemon name should be same as pokedex'
            await self.initial_message.edit(content=print_out, view=self)

