class EditIVModal(discord.ui.Modal):
    def __init__(self, panel_view: PokemonEditPanelView):
        super().__init__(title=f"Edit IVs: {panel_view.pokemon_name}")
        self.panel_view = panel_view
        state = panel_view.session_view.get_state(panel_view.pokemon_name, role="generic")

        self.hpiv = TextInput(label="HP IV", default=str(state.hpiv), required=True)
        self.atkiv = TextInput(label="Atk IV", default=str(state.atkiv), required=True)
        self.defiv = TextInput(label="Def IV", default=str(state.defiv), required=True)
        self.spatkiv = TextInput(label="SpAtk IV", default=str(state.spatkiv), required=True)
        self.spdefiv = TextInput(label="SpDef IV", default=str(state.spdefiv), required=True)

        for item in (self.hpiv, self.atkiv, self.defiv, self.spatkiv, self.spdefiv):
            self.add_item(item)

    async def on_submit(self, interaction: discord.Interaction):
        if interaction.user.id != self.panel_view.session_view.owner_id:
            return await interaction.response.send_message("This editor is not for you.", ephemeral=True)

        try:
            hpiv = int(self.hpiv.value)
            atkiv = int(self.atkiv.value)
            defiv = int(self.defiv.value)
            spatkiv = int(self.spatkiv.value)
            spdefiv = int(self.spdefiv.value)
        except Exception:
            return await interaction.response.send_message("All IVs must be numbers.", ephemeral=True)

        def apply(state: PokemonState):
            state.hpiv = hpiv
            state.atkiv = atkiv
            state.defiv = defiv
            state.spatkiv = spatkiv
            state.spdefiv = spdefiv
            state.spdiv = 31

        self.panel_view.session_view.apply_pokemon_update(self.panel_view.pokemon_name, apply)
        self.panel_view.session_view = await self.panel_view.session_view.sync_message()
        await interaction.response.send_message("IVs updated.", ephemeral=True)


class EditDebuffModal(discord.ui.Modal):
    def __init__(self, panel_view: PokemonEditPanelView):
        super().__init__(title=f"Edit Debuff: {panel_view.pokemon_name}")
        self.panel_view = panel_view
        state = panel_view.session_view.get_state(panel_view.pokemon_name, role="generic")

        self.atk_debuff = TextInput(label="Attack debuff", default=str(state.atk_debuff), required=True)
        self.def_debuff = TextInput(label="Defense debuff", default=str(state.def_debuff), required=True)
        self.add_item(self.atk_debuff)
        self.add_item(self.def_debuff)

    async def on_submit(self, interaction: discord.Interaction):
        if interaction.user.id != self.panel_view.session_view.owner_id:
            return await interaction.response.send_message(
                "This editor is not for you.",
                ephemeral=True
            )

        try:
            atk_debuff = int(self.atk_debuff.value)
            def_debuff = int(self.def_debuff.value)
        except Exception:
            return await interaction.response.send_message(
                "Debuff values must be numbers.",
                ephemeral=True
            )

        # convert positive inputs into negative stages
        # user enters 1 => becomes -1 stage
        atk_debuff = -abs(atk_debuff)
        def_debuff = -abs(def_debuff)

        def apply(state: PokemonState):
            state.atk_debuff = atk_debuff
            state.def_debuff = def_debuff

        self.panel_view.session_view.apply_pokemon_update(
            self.panel_view.pokemon_name,
            apply
        )

        await self.panel_view.session_view.sync_message()

        await interaction.response.send_message(
            f"Debuffs updated to {atk_debuff}/{def_debuff}.",
            ephemeral=True
        )


