async def info(interaction: discord.Interaction, pokemon:str, hpiv:int=31,atkiv:int=31,defiv:int=31,spatkiv:int=31,spdefiv:int=31,spdiv:int=31, mint:str = 'neutral, neutral'):
    pokemon = name_finder(pokemon.lower())
    poke_data, _, _ = load_pokemon_data_for_lookup(pokemon, allow_fake=True)
    if not poke_data:
        return await interaction.response.send_message('Wrong Pokemon Name, name should be same as pokedex')
    ability_list = poke_data["abilities"]
    abilities = ''
    for ability in ability_list:
        abilities += ability + " | "
    pokemon = pokemon.capitalize()
    mint_list = mint.split(', ')
    mint_atk = 1
    mint_spatk = 1
    mint_def = 1
    mint_spdef = 1
    mint_spd = 1
    if mint_list[0] == '+atk':
        mint_atk = 1.1
    elif mint_list[0] == '+spatk':
        mint_spatk = 1.1
    elif mint_list[0] == '+def':
        mint_def = 1.1
    elif mint_list[0] == '+spdef':
        mint_spdef = 1.1
    elif mint_list[0] == '+spd':
        mint_spd = 1.1
    if mint_list[1] == '-atk':
        mint_atk = 0.9
    elif mint_list[1] == '-spatk':
        mint_spatk = 0.9
    elif mint_list[1] == '-def':
        mint_def = 0.9
    elif mint_list[1] == '-spdef':
        mint_spdef = 0.9
    elif mint_list[1] == '-spd':
        mint_spd = 0.9
    poke_stats, poke_type = get_pokemon_stats(pokemon)
    if isinstance(poke_stats, list):
        hp = math.floor(2*poke_stats[0] + hpiv + 5 + 110 )
        atk = math.floor((2*poke_stats[1] + atkiv + 5 + 5) * mint_atk)
        df = math.floor((2*poke_stats[2] + defiv + 5 + 5) * mint_def)
        spatk = math.floor((2*poke_stats[3] + spatkiv + 5 + 5) * mint_spatk)
        spdef = math.floor((2*poke_stats[4] + spdefiv + 5 + 5) * mint_spdef)
        spd = math.floor((2*poke_stats[5] + spdiv + 5 + 5) * mint_spd)
        types =  ', '.join([type_.capitalize() for type_ in poke_type])
        folder_path = 'moves'
        file_path = os.path.join(folder_path, f"{pokemon}_moves.txt")
        if os.path.exists(file_path):
            with open(file_path, 'r') as file:
                lines = file.readlines()
                moves = lines[0].strip()
        else:
            moves = 'Not yet added'
        thumbnail = get_pokemon_info(pokemon.lower(), allow_fake=True)[2]
        embed = discord.Embed(title=f"{pokemon.capitalize()}{get_pokemon_emoji(pokemon)}", description= f'**Type:** {types}\n**Nature:** {mint}',  color=discord.Color.random())
        embed.add_field(name = "Stats", value = f"**HP:** {hp} ({poke_stats[0]})\n**Attack:** {atk} ({poke_stats[1]})\n**Defence:** {df} ({poke_stats[2]})\n**Sp.Attack:** {spatk} ({poke_stats[3]})\n**Sp.Defence:** {spdef} ({poke_stats[4]})\n**Speed:** {spd} ({poke_stats[5]})")
        embed.add_field(name = "Moves", value = f'{moves}')
        embed.add_field(name = "Abilities", value = f"{abilities}")
        try:
            embed.set_thumbnail(url = thumbnail)
        except Exception as e:
            print(e)
        await interaction.response.send_message(embed=embed)
    else:
        await interaction.response.send_message('Wrong Pokemon Name, name should be same as pokedex')

@bot.tree.command(name="move_add", description="Help complete pokemon wiki by adding prefered moves to them")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def move_add(interaction: discord.Interaction, pokemon:str, moves: str):
    pokemon = pokemon.capitalize()
    folder_path = 'moves'
    file_path = os.path.join(folder_path, 'editors.txt')
    ids = []
    with open(file_path, 'r') as file:
        lines = file.readlines()
        for i in range(0, len(lines)):
            ids.append(lines[i].strip())
    if any(interaction.user.id == int(id) for id in ids):
        BASE_DIR = os.path.dirname(os.path.abspath(__file__))
        MOVES_DIR = os.path.join(BASE_DIR, "moves")
        os.makedirs(MOVES_DIR, exist_ok=True)
        await interaction.response.send_message('Format: move1/move2/move3/move4', ephemeral=True)
        file_path = os.path.join(folder_path, f'{pokemon}_moves.txt')
        if os.path.exists(file_path):
            with open(file_path, 'w') as file:
                file.write(moves + "\n")
                await interaction.followup.send("edited moves")
        else:
            with open(file_path, 'w') as file:
                file.write(moves + "\n")
                await interaction.followup.send("Added moves")
    else:
        await interaction.response.send_message('You do not have permission to add moves to pokemon, please contact @Best1111 if you wish to contribute', ephemeral=True)

