@bot.tree.command(name="weakness", description="Find the weakness and strength of a pokemon")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def weakness(interaction: discord.Interaction, pokemon:str):
    try:
        if pokemon.capitalize() in GYM_TYPES:
            pokemon = f"{pokemon} arceus".lower()
        else:
            pokemon = name_finder(pokemon.lower())
        poke_stats, poke_type = get_pokemon_stats(pokemon)
        effectiveness_table = generate_effectiveness_table(poke_type)
        if poke_stats[2] > poke_stats[4]+20:
            atk_weak = 'Special Attack'
        elif poke_stats[4] > poke_stats[2]+20:
            atk_weak = 'Attack'
        else:
            atk_weak = 'N/A'
        embed = discord.Embed(title=f"{pokemon.capitalize()}",description= ', '.join([type_.capitalize() for type_ in poke_type]),  color=discord.Color.random())
        # Capitalize the types and join them into a string with a comma separator
        embed.add_field(
            name="x4 Super Effective", 
            value=', '.join([type_.capitalize() for type_ in effectiveness_table["super effective (4)"]]) if effectiveness_table["super effective (4)"] else "None", 
            inline=False)
        embed.add_field(
            name="x2 Super Effective", 
            value=', '.join([type_.capitalize() for type_ in effectiveness_table["effective (2)"]]) if effectiveness_table["effective (2)"] else "None", 
            inline=False)
        embed.add_field(
            name="x1 Neutral", 
            value=', '.join([type_.capitalize() for type_ in effectiveness_table["neutral (1)"]]) if effectiveness_table["neutral (1)"] else "None", 
            inline=False)
        embed.add_field(
            name="x0.5 Ineffective", 
            value=', '.join([type_.capitalize() for type_ in effectiveness_table["ineffective (0.5)"]]) if effectiveness_table["ineffective (0.5)"] else "None", 
            inline=False)
        embed.add_field(
            name="x0.25 Ineffective", 
            value=', '.join([type_.capitalize() for type_ in effectiveness_table["super ineffective (0.25)"]]) if effectiveness_table["super ineffective (0.25)"] else "None", 
            inline=False)
        embed.add_field(
            name="x0 Immune", 
            value=', '.join([type_.capitalize() for type_ in effectiveness_table["immune (0)"]]) if effectiveness_table["immune (0)"] else "None", 
            inline=False)
        embed.add_field(
            name="Attack Weakness", 
            value=f'{atk_weak}\n*This pokemon has 20 less stats on that defence comparatively*', 
            inline=False)
        await interaction.response.send_message(embed=embed)
    except:
        await interaction.response.send_message('Wrong Pokemon Name')

