@bot.tree.command(name="register", description="Register for a tournament")
@app_commands.allowed_contexts(guilds=True, dms=False, private_channels=True)
async def register(
    interaction: discord.Interaction,
    tournament: str = None,
    member: discord.User = None,
    role: discord.Role = None
):
    server = interaction.guild.name
    tourn_name = tournament or "default tournament"
    folder_path = "register"
    os.makedirs(folder_path, exist_ok=True)
    file_path = os.path.join(folder_path, f"{server}_{tourn_name}.txt")

    # Determine users to register
    users_to_register = []

    if role and not member:
        # Register everyone with the selected role
        await interaction.guild.chunk()
        users_to_register = [m.id for m in role.members]
        if not users_to_register:
            return await interaction.response.send_message(
                f"No members found in role {role.mention}.", ephemeral=True
            )
    else:
        # Register single user (either selected or the one who invoked)
        user_id = member.id if member else interaction.user.id
        users_to_register = [user_id]

    # Write to file (avoid duplicates)
    existing_users = set()
    if os.path.exists(file_path):
        with open(file_path, "r") as file:
            existing_users = {line.strip() for line in file.readlines()}

    with open(file_path, "a") as file:
        for user_id in users_to_register:
            mention = f"<@{user_id}>"
            if mention not in existing_users:
                file.write(f"{mention}\n")

    if role and not member:
        msg = f"Registered all members of {role.mention} for **{tourn_name}** in **{server}**."
    else:
        msg = f"<@{users_to_register[0]}> registered for **{tourn_name}** in **{server}**."

    await interaction.response.send_message(msg)

class TeamModal(Modal):
    def __init__(self, title, server, tourn_name):
        super().__init__(title=title)
        self.server = server
        self.tourn_name = tourn_name
        self.team_name = TextInput(label="Team Name", placeholder="Name of the team")
        self.member = TextInput(label="Index of Members", placeholder="Write index of members separated by , (no space) e.g. 1,3,7,15,28")
        self.add_item(self.team_name)
        self.add_item(self.member)
    async def on_submit(self, interaction: discord.Interaction):
        indexs = str(self.member).split(',')
        file_path = os.path.join('register', f'{self.server}_{self.tourn_name}.txt')
        with open(file_path, 'r') as file:
            lines = file.readlines()
        for index in indexs:
            user_id = lines[int(index) - 1].strip()
            lines[int(index) - 1] = f'{user_id}({self.team_name})\n'
        with open(file_path, 'w') as file:
            file.writelines(lines)
        await interaction.response.send_message('Team added')

class RemoveModal(Modal):
    def __init__(self, title, server, tourn_name):
        super().__init__(title=title)
        self.server = server
        self.tourn_name = tourn_name
        self.index = TextInput(label="Index of members that you want to remove", placeholder="Write index of members separated by , (no space) e.g. 1,3,7,15,28")
        self.add_item(self.index)
    async def on_submit(self, interaction: discord.Interaction):
        indexs = str(self.index).split(',')
        file_path = os.path.join('register', f'{self.server}_{self.tourn_name}.txt')
        with open(file_path, 'r') as file:
            lines = file.readlines()
        for index in indexs:
            lines.pop(int(index)-1)
        with open(file_path, 'w') as file:
            file.writelines(lines)
        await interaction.response.send_message('Removed')

class PostModal(Modal):
    def __init__(self, title, server, tourn_name):
        super().__init__(title=title)
        self.server = server
        self.tourn_name = tourn_name
        self.format = TextInput(label="Format of the tournament", placeholder="rare ou, rare uu, comm ou, comm uu, mega etc")
        self.prize = TextInput(label="Prize of the tournament", placeholder="e.g. winner: 3m, 2nd place: 2m")
        self.invite_link = TextInput(label="Invite link of your server", placeholder="discord.gg/abcdef")
        self.start_date = TextInput(label="Start Date of the tournament", placeholder="e.g. 1/4/2025")
        self.add_item(self.format)
        self.add_item(self.prize)
        self.add_item(self.invite_link)
        self.add_item(self.start_date)
    async def on_submit(self, interaction: discord.Interaction):
        channel_id = 1335616952156295260  # Replace with your desired channel ID
        channel = bot.get_channel(channel_id)
        guild_name = self.server
        tournament = self.tourn_name
        format = self.format
        prize = self.prize
        invite_link = self.invite_link
        start_date = self.start_date
        if channel is None:
            await interaction.response.send_message("Channel not found.", ephemeral=True)
            return
        try:
            dm = await interaction.user.create_dm()
            await dm.send(f"Your tournament '{tournament}' has been posted for approval. You will be notified once it's approved or disapproved.")
        except discord.Forbidden:
            await interaction.response.send_message("Could not send you a DM. Please ensure you have DMs enabled.", ephemeral=True)

        message_content = f"Tournament Name: {tournament}\nFormat: {format}\nPrize: {prize}\nPlease approve or disapprove."
        approve_button = Button(label="Approve", style=discord.ButtonStyle.green, custom_id="approve")
        disapprove_button = Button(label="Disapprove", style=discord.ButtonStyle.red, custom_id="disapprove")
        view = View(timeout = None)
        view.add_item(approve_button)
        view.add_item(disapprove_button)
        async def approve_callback(interaction: discord.Interaction):
            approve_button.disabled = True
            await interaction.response.edit_message(content="Button clicked! It has been disabled.", view=view)
            # Save the tournament to a file if approved
            folder_path = 'tournaments'
            if not os.path.exists(folder_path):
                os.makedirs(folder_path)

            file_path = os.path.join(folder_path, f'{guild_name}_{tournament}.txt')
            password = random.randint(100000, 999999)
            with open(file_path, 'w') as file:
                file.write(f"{guild_name}\n")
                file.write(f"{tournament}\n")
                file.write(f"{format}\n")
                file.write(f"{prize}\n")
                file.write(f"{invite_link}\n")
                file.write(f"{start_date}\n")
                file.write(f'{password}\n')
            try:
                dm = await interaction.user.create_dm()
                await dm.send(f'Tournament {tournament} posted, use /tournament to view it.\nYour tournament password is {password}, You need it to delete your tournament\nPlease delete your tournament within 1 month (contact support if you need tournament posting to stay longer)')
            except discord.Forbidden:
                await interaction.response.send_message("Could not send you a DM. Please ensure you have DMs enabled.", ephemeral=True)
        async def disapprove_callback(interaction: discord.Interaction):
            disapprove_button.disabled = True
            await interaction.response.edit_message(content="Button clicked! It has been disabled.", view=view)
            # Send DM to the user who posted the tournament
            try:
                dm = await interaction.user.create_dm()
                await dm.send(f"Your tournament '{tournament}' has been disapproved and will not be saved.\n if you think this is a mistake, contact @Best1111")
            except discord.Forbidden:
                await interaction.response.send_message("Could not send you a DM. Please ensure you have DMs enabled.", ephemeral=True)
        approve_button.callback = approve_callback
        disapprove_button.callback = disapprove_callback
        await channel.send(message_content, view=view)
        await interaction.response.send_message("The tournament has been posted for approval. You will be notified via DM once it's approved or disapproved.", ephemeral=True)
class RegisterView(View):
    def __init__(self, server, tourn_name):
        super().__init__()
        self.server = server
        self.tourn_name = tourn_name
    @discord.ui.button(label="Form Team", style=discord.ButtonStyle.green)
    async def form_team(self, interaction: discord.Interaction, button: discord.Button):
        user = interaction.user
        if user.guild_permissions.manage_roles:
            modal = TeamModal(title='Team', server = self.server, tourn_name=self.tourn_name)
            await interaction.response.send_modal(modal)
        else:
            await interaction.response.send_message('Missing Permissions (manage roles)')

    @discord.ui.button(label="Remove", style=discord.ButtonStyle.red)
    async def remove(self, interaction: discord.Interaction, button: discord.Button):
        user = interaction.user
        if user.guild_permissions.manage_roles:
            modal = RemoveModal(title='Remove', server=self.server, tourn_name=self.tourn_name)
            await interaction.response.send_modal(modal)
        else:
            await interaction.response.send_message('Missing Permissions (manage roles)')

    @discord.ui.button(label="End", style=discord.ButtonStyle.primary)
    async def end(self, interaction: discord.Interaction, button: discord.Button):
        await interaction.response.defer()
        user = interaction.user
        if user.guild_permissions.manage_roles:
            # File path for local registration file
            file_path = os.path.join('register', f'{self.server}_{self.tourn_name}.txt')
            try:
                # Delete the tournament on Challonge
                name = f"{self.server}_{self.tourn_name}"
                safe_tourn_name = re.sub(r'[^a-zA-Z0-9_]', '_', name)
                challonge_name = f"{safe_tourn_name}".replace(" ", "_").lower()
                tournament_info = get_challonge_tournament_info(f'{challonge_name}')
                tournament_id = tournament_info.get('id', 'No bracket found')
                response = requests.delete(
                    f"https://api.challonge.com/v1/tournaments/{tournament_id}.json",
                    params={'api_key': CHALLONGE_API_KEY},
                    auth=(CHALLONGE_API_KEY, CHALLONGE_USERNAME), headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'})
                if response.status_code == 200:
                    await interaction.followup.send(f'Tournament {self.tourn_name} has been deleted from Challonge.')
                else:
                    await interaction.followup.send(f"Failed to delete tournament on Challonge: {response.text}")

            except Exception as e:
                await interaction.followup.send(f"An error occurred while deleting the tournament from Challonge: {e}\nPlease check tournament name again")
                return
            if os.path.exists(file_path):
                os.remove(file_path)
                await interaction.followup.send(f'{self.tourn_name} in {self.server} has been deleted locally.')
        else:
            await interaction.followup.send('Missing Permissions (manage roles)')
    
    @discord.ui.button(label="Post Tournament Globally", style=discord.ButtonStyle.green)
    async def post_tourn(self, interaction: discord.Interaction, button: discord.Button):
        user = interaction.user
        if user.guild_permissions.manage_roles:
            modal = PostModal(title='Post Tournament Globally', server = self.server, tourn_name=self.tourn_name)
            await interaction.response.send_modal(modal)
        else:
            await interaction.response.send_message('Missing Permissions (manage roles)')

@bot.tree.command(name="register_view", description="View players registered for a tournament")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def register_view(interaction: discord.Interaction, server_name: str = None, tournament: str = None, raw_dm: bool = False):
    await interaction.response.defer()
    if tournament:
        tourn_name = tournament
    else:
        tourn_name = 'default tournament'
    if server_name:
        server = server_name
    else:
        server = interaction.guild.name
    file_path = os.path.join('register', f'{server}_{tourn_name}.txt')
    if not os.path.exists(file_path):
        await interaction.followup.send(f'{tourn_name} in {server} not found!\nIf you are not using this command in a server with the tournament, please add the server name\nIf the tournament has a non-default name, please enter that as well')
        return
    with open(file_path, 'r') as file:
        lines = file.readlines()
        p_id = ''
        for i in range(len(lines)):
            p_id += str(i) + '. ' + str(lines[i].strip()) + '\n'
    embed = discord.Embed(title=f'{server} {tourn_name} Participant List', description=p_id, color=discord.Color.random())
    if raw_dm:
        with open(file_path, 'r') as file:
            lines = file.readlines()
            r_id = ''
            for i in range(len(lines)):
                r_id += str(lines[i].strip())
        await interaction.user.send(r_id)
    view = RegisterView(server, tourn_name)
    await interaction.followup.send(embed=embed, view=view)


CHALLONGE_API_KEY = '8nMVRVIS5Lr5zcvrO33fdjhnuzXpdEO8JBgPLgQZ'
CHALLONGE_USERNAME = 'best1111'
TOURNAMENT_LOG = 'tournament_log.json'


def load_tournament_log():
    try:
        with open(TOURNAMENT_LOG, 'r') as f:
            return json.load(f)
    except FileNotFoundError:
        return {}

def save_tournament_log(data):
    with open(TOURNAMENT_LOG, 'w') as f:
        json.dump(data, f, indent=4)

def can_create_tournament(user_id):
    data = load_tournament_log()
    today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    user_entry = data.get(str(user_id), {"dates": {}})
    count = user_entry["dates"].get(today, 0)
    return count < 5

def record_tournament_creation(user_id, challonge_id):
    data = load_tournament_log()
    today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    if str(user_id) not in data:
        data[str(user_id)] = {"dates": {}, "tournaments": {}}
    data[str(user_id)]["dates"][today] = data[str(user_id)]["dates"].get(today, 0) + 1
    data[str(user_id)]["tournaments"][challonge_id] = datetime.now(timezone.utc).isoformat()
    save_tournament_log(data)

