def setup_tournament_funds_db():
    with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
        c = conn.cursor()
        c.execute("""
            CREATE TABLE IF NOT EXISTS oranguru_academy (
                user_id INTEGER PRIMARY KEY,
                added_at INTEGER,
                added_by INTEGER
            )
        """)
        c.execute("""
            CREATE TABLE IF NOT EXISTS tournament_signups (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                guild_id INTEGER NOT NULL,
                user_id INTEGER NOT NULL,
                tier TEXT NOT NULL,
                signed_at INTEGER NOT NULL
            )
        """)
        c.execute("CREATE INDEX IF NOT EXISTS idx_tourn_signups_user_time ON tournament_signups(user_id, signed_at)")
        c.execute("CREATE INDEX IF NOT EXISTS idx_tourn_signups_guild_tier_time ON tournament_signups(guild_id, tier, signed_at)")
        c.execute("""
            CREATE TABLE IF NOT EXISTS tournament_prizepools (
                guild_id INTEGER NOT NULL,
                tier TEXT NOT NULL,
                amount INTEGER NOT NULL,
                signups_count INTEGER NOT NULL,
                assigned_at INTEGER NOT NULL,
                PRIMARY KEY (guild_id, tier)
            )
        """)
        c.execute("""
            CREATE TABLE IF NOT EXISTS tournament_delay_pending (
                message_id INTEGER PRIMARY KEY,
                user_id INTEGER NOT NULL,
                guild_id INTEGER NOT NULL,
                tier TEXT NOT NULL,
                created_at INTEGER NOT NULL
            )
        """)
        c.execute("""
            CREATE TABLE IF NOT EXISTS tournament_duel_counts (
                guild_id INTEGER PRIMARY KEY,
                duel_count INTEGER NOT NULL,
                updated_at INTEGER NOT NULL
            )
        """)
        conn.commit()

def _is_oranguru_member(user_id: int) -> bool:
    try:
        with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
            c = conn.cursor()
            c.execute("SELECT 1 FROM oranguru_academy WHERE user_id = ?", (int(user_id),))
            return c.fetchone() is not None
    except Exception:
        return False

def _add_oranguru_member(user_id: int, added_by: int | None = None) -> bool:
    try:
        with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
            c = conn.cursor()
            c.execute(
                "INSERT OR IGNORE INTO oranguru_academy (user_id, added_at, added_by) VALUES (?, ?, ?)",
                (int(user_id), int(time.time()), int(added_by) if added_by is not None else None),
            )
            conn.commit()
            return c.rowcount > 0
    except Exception:
        return False

def _tournament_user_cooldown_remaining(user_id: int) -> int:
    cutoff = int(time.time()) - TOURNAMENT_SIGNUP_COOLDOWN_SECS
    with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
        c = conn.cursor()
        c.execute(
            "SELECT signed_at FROM tournament_signups WHERE user_id = ? AND signed_at >= ? ORDER BY signed_at DESC LIMIT 1",
            (int(user_id), cutoff),
        )
        row = c.fetchone()
        if not row:
            return 0
        last_signed = int(row[0])
        remaining = (last_signed + TOURNAMENT_SIGNUP_COOLDOWN_SECS) - int(time.time())
        return max(0, int(remaining))

def _record_tournament_signup(guild_id: int, user_id: int, tier: str):
    with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
        c = conn.cursor()
        c.execute(
            "INSERT INTO tournament_signups (guild_id, user_id, tier, signed_at) VALUES (?, ?, ?, ?)",
            (int(guild_id), int(user_id), str(tier), int(time.time())),
        )
        conn.commit()

def _count_recent_signups(guild_id: int, tier: str, since_ts: int) -> int:
    with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
        c = conn.cursor()
        c.execute(
            "SELECT COUNT(*) FROM tournament_signups WHERE guild_id = ? AND tier = ? AND signed_at >= ?",
            (int(guild_id), str(tier), int(since_ts)),
        )
        row = c.fetchone()
        return int(row[0] or 0)

def _assign_tournament_prizepool_if_ready(guild_id: int, tier: str):
    tier_cfg = TOURNAMENT_TIERS.get(str(tier))
    if not tier_cfg:
        return
    min_signups = int(tier_cfg.get("min_signups", 0))
    per_signup = int(tier_cfg.get("per_signup", 0))
    cutoff = int(time.time()) - TOURNAMENT_SIGNUP_COOLDOWN_SECS
    signups = _count_recent_signups(guild_id, tier, cutoff)
    if signups < min_signups:
        return
    amount = signups * per_signup
    with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
        c = conn.cursor()
        c.execute(
            """
            INSERT INTO tournament_prizepools (guild_id, tier, amount, signups_count, assigned_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(guild_id, tier)
            DO UPDATE SET amount = excluded.amount, signups_count = excluded.signups_count, assigned_at = excluded.assigned_at
            """,
            (int(guild_id), str(tier), int(amount), int(signups), int(time.time())),
        )
        conn.commit()

def _schedule_prizepool_check(guild_id: int, tier: str):
    _schedule_prizepool_check_with_delay(guild_id, tier, TOURNAMENT_PRIZE_ASSIGN_DELAY_SECS)

def _schedule_prizepool_check_with_delay(guild_id: int, tier: str, delay_seconds: int):
    job_id = f"tourn_prize_{int(guild_id)}_{str(tier)}"
    run_at = datetime.now(timezone.utc) + timedelta(seconds=int(delay_seconds))
    existing = scheduler.get_job(job_id)
    if existing and existing.next_run_time and existing.next_run_time <= run_at:
        return
    scheduler.add_job(
        _assign_tournament_prizepool_if_ready,
        trigger="date",
        id=job_id,
        run_date=run_at,
        args=[int(guild_id), str(tier)],
        replace_existing=True,
    )

def _increment_tournament_duel_count(guild_id: int):
    if not guild_id:
        return
    with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
        c = conn.cursor()
        c.execute(
            """
            INSERT INTO tournament_duel_counts (guild_id, duel_count, updated_at)
            VALUES (?, 1, ?)
            ON CONFLICT(guild_id)
            DO UPDATE SET duel_count = duel_count + 1, updated_at = excluded.updated_at
            """,
            (int(guild_id), int(time.time())),
        )
        conn.commit()

def _get_tournament_duel_count(guild_id: int) -> int:
    if not guild_id:
        return 0
    with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
        c = conn.cursor()
        c.execute("SELECT duel_count FROM tournament_duel_counts WHERE guild_id = ?", (int(guild_id),))
        row = c.fetchone()
        return int(row[0] or 0) if row else 0

async def _send_tournament_award_log(guild: discord.Guild, author: discord.abc.User, target: discord.abc.User, amount: int):
    bot_server = bot.get_guild(BOT_SERVER_ID)
    if not bot_server:
        return
    log_channel = bot_server.get_channel(BOT_SERVER_TOURNAMENT_LOG_CHANNEL_ID)
    if not log_channel:
        return
    try:
        await log_channel.send(
            f"🏆 Tournament award\n"
            f"Server: **{guild.name}** (`{guild.id}`)\n"
            f"Awarded by: {author.mention} (`{author.id}`)\n"
            f"Recipient: {target.mention} (`{target.id}`)\n"
            f"Amount: **{int(amount)} ARCs**"
        )
    except Exception:
        pass

async def _handle_tournament_award(
    guild: discord.Guild | None,
    author: discord.abc.User,
    target: discord.abc.User,
    amount: int,
    send_func,
):
    if guild is None:
        return await send_func("❌ This command can only be used in a server.")
    try:
        amount = int(amount)
    except Exception:
        return await send_func("❌ Please provide a valid amount.")
    if amount <= 0:
        return await send_func("❌ Amount must be greater than 0.")
    duel_count = _get_tournament_duel_count(guild.id)
    if duel_count < TOURNAMENT_AWARD_MIN_DUELS:
        return await send_func(
            f"❌ Not enough duels have been completed in this server yet "
            f"(need at least {TOURNAMENT_AWARD_MIN_DUELS})."
        )
    with connect_poke_db() as conn:
        ensure_player(conn, target.id)
        c = conn.cursor()
        c.execute("UPDATE poke SET coins = coins + ? WHERE player_id = ?", (amount, target.id))
        conn.commit()
    await send_func(f"✅ Awarded **{amount} ARCs** to {target.mention}.")
    await _send_tournament_award_log(guild, author, target, amount)

TOURNAMENT_LOCAL_DB_FILE = "tournament.db"

def _tournament_db_connect():
    conn = sqlite3.connect(TOURNAMENT_LOCAL_DB_FILE)
    conn.row_factory = sqlite3.Row
    return conn

def setup_tournament_db():
    conn = _tournament_db_connect()
    c = conn.cursor()
    c.execute(
        """
        CREATE TABLE IF NOT EXISTS tournaments (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            slug TEXT UNIQUE NOT NULL,
            name TEXT NOT NULL,
            server_name TEXT,
            tournament_name TEXT,
            tournament_type TEXT NOT NULL,
            status TEXT NOT NULL DEFAULT 'ongoing',
            current_round INTEGER NOT NULL DEFAULT 1,
            challonge_id TEXT,
            challonge_url TEXT,
            created_at TEXT NOT NULL,
            updated_at TEXT NOT NULL
        )
        """
    )
    c.execute(
        """
        CREATE TABLE IF NOT EXISTS tournament_participants (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            tournament_id INTEGER NOT NULL,
            seed INTEGER NOT NULL,
            display_name TEXT NOT NULL,
            external_id TEXT,
            losses INTEGER NOT NULL DEFAULT 0,
            eliminated INTEGER NOT NULL DEFAULT 0,
            eliminated_round INTEGER,
            created_at TEXT NOT NULL,
            UNIQUE(tournament_id, display_name)
        )
        """
    )
    c.execute(
        """
        CREATE TABLE IF NOT EXISTS tournament_matches (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            tournament_id INTEGER NOT NULL,
            bracket TEXT NOT NULL DEFAULT 'W',
            round_id INTEGER NOT NULL,
            match_order INTEGER NOT NULL,
            player1_participant_id INTEGER,
            player2_participant_id INTEGER,
            winner_participant_id INTEGER,
            loser_participant_id INTEGER,
            state TEXT NOT NULL DEFAULT 'open',
            scores_csv TEXT,
            player1_prereq_match_id INTEGER,
            player2_prereq_match_id INTEGER,
            next_match_win_id INTEGER,
            next_match_win_slot INTEGER,
            next_match_lose_id INTEGER,
            next_match_lose_slot INTEGER,
            created_at TEXT NOT NULL,
            updated_at TEXT NOT NULL
        )
        """
    )
    c.execute(
        """
        CREATE TABLE IF NOT EXISTS tournament_manager_roles (
            guild_id INTEGER PRIMARY KEY,
            role_id INTEGER NOT NULL,
            updated_at TEXT NOT NULL
        )
        """
    )
    c.execute("CREATE INDEX IF NOT EXISTS idx_tm_tournament_round ON tournament_matches(tournament_id, bracket, round_id)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_tm_tournament_state ON tournament_matches(tournament_id, state)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_tp_tournament_seed ON tournament_participants(tournament_id, seed)")
    try:
        c.execute("ALTER TABLE tournament_participants ADD COLUMN losses INTEGER NOT NULL DEFAULT 0")
    except Exception:
        pass
    conn.commit()
    conn.close()

def _set_tournament_manager_role(guild_id: int, role_id: int):
    setup_tournament_db()
    conn = _tournament_db_connect()
    c = conn.cursor()
    c.execute(
        """
        INSERT INTO tournament_manager_roles (guild_id, role_id, updated_at)
        VALUES (?, ?, ?)
        ON CONFLICT(guild_id) DO UPDATE SET role_id = excluded.role_id, updated_at = excluded.updated_at
        """,
        (int(guild_id), int(role_id), datetime.now(timezone.utc).isoformat()),
    )
    conn.commit()
    conn.close()

def _get_tournament_manager_role_id(guild_id: int | None) -> int | None:
    if not guild_id:
        return None
    setup_tournament_db()
    conn = _tournament_db_connect()
    c = conn.cursor()
    c.execute("SELECT role_id FROM tournament_manager_roles WHERE guild_id = ?", (int(guild_id),))
    row = c.fetchone()
    conn.close()
    if not row:
        return None
    try:
        return int(row["role_id"])
    except Exception:
        return None

def _is_tournament_manager_member(member: discord.Member | None, guild: discord.Guild | None) -> bool:
    if member is None or guild is None:
        return False
    role_id = _get_tournament_manager_role_id(guild.id)
    if not role_id:
        return False
    return any(int(r.id) == int(role_id) for r in (member.roles or []))

def _tournament_slug(server_name: str, tournament_name: str) -> str:
    base = f"{server_name}_{tournament_name}"
    return re.sub(r"[^a-zA-Z0-9_]", "_", base.replace(" ", "_").lower())

def _normalize_tournament_name(name: str) -> str:
    n = str(name or "").strip()
    if ". " in n and n.split(". ", 1)[0].isdigit():
        return n.split(". ", 1)[1].strip().lower()
    return n.lower()

def _next_power_of_two(n: int) -> int:
    if n <= 1:
        return 2
    p = 1
    while p < n:
        p <<= 1
    return p

def _highest_power_of_two_leq(n: int) -> int:
    if n <= 1:
        return 1
    p = 1
    while (p << 1) <= n:
        p <<= 1
    return p

def _refresh_tournament_round_and_status(conn: sqlite3.Connection, tournament_id: int):
    c = conn.cursor()
    c.execute(
        """
        SELECT MIN(round_id) AS min_round
        FROM tournament_matches
        WHERE tournament_id = ? AND bracket = 'W' AND state = 'open'
        """,
        (int(tournament_id),),
    )
    w_row = c.fetchone()
    c.execute(
        """
        SELECT MIN(round_id) AS min_round
        FROM tournament_matches
        WHERE tournament_id = ? AND bracket = 'L' AND state = 'open'
        """,
        (int(tournament_id),),
    )
    l_row = c.fetchone()

    if w_row and w_row["min_round"] is not None:
        current_round = int(w_row["min_round"])
        status = "ongoing"
    elif l_row and l_row["min_round"] is not None:
        current_round = int(l_row["min_round"])
        status = "ongoing"
    else:
        c.execute(
            "SELECT MAX(round_id) AS max_round FROM tournament_matches WHERE tournament_id = ? AND bracket = 'W'",
            (int(tournament_id),),
        )
        row2 = c.fetchone()
        current_round = int((row2["max_round"] if row2 and row2["max_round"] is not None else 1) or 1)
        status = "completed"
    now_iso = datetime.now(timezone.utc).isoformat()
    c.execute(
        "UPDATE tournaments SET current_round = ?, status = ?, updated_at = ? WHERE id = ?",
        (current_round, status, now_iso, int(tournament_id)),
    )

def _set_match_player_slot(conn: sqlite3.Connection, match_id: int, slot: int, participant_id: int | None):
    col = "player1_participant_id" if int(slot) == 1 else "player2_participant_id"
    c = conn.cursor()
    c.execute(
        f"UPDATE tournament_matches SET {col} = ?, updated_at = ? WHERE id = ?",
        (participant_id, datetime.now(timezone.utc).isoformat(), int(match_id)),
    )

def _advance_match_winner(conn: sqlite3.Connection, match_row: sqlite3.Row, winner_pid: int):
    c = conn.cursor()
    p1 = match_row["player1_participant_id"]
    p2 = match_row["player2_participant_id"]
    loser_pid = p2 if int(winner_pid) == int(p1 or 0) else p1
    scores_csv = "1-0" if int(winner_pid) == int(p1 or 0) else "0-1"
    now_iso = datetime.now(timezone.utc).isoformat()
    c.execute(
        """
        UPDATE tournament_matches
        SET winner_participant_id = ?, loser_participant_id = ?, state = 'complete',
            scores_csv = ?, updated_at = ?
        WHERE id = ?
        """,
        (int(winner_pid), loser_pid, scores_csv, now_iso, int(match_row["id"])),
    )
    next_win = match_row["next_match_win_id"]
    next_slot = match_row["next_match_win_slot"]
    if next_win and next_slot:
        _set_match_player_slot(conn, int(next_win), int(next_slot), int(winner_pid))
    next_lose = match_row["next_match_lose_id"]
    next_lose_slot = match_row["next_match_lose_slot"]
    if loser_pid and next_lose and next_lose_slot:
        _set_match_player_slot(conn, int(next_lose), int(next_lose_slot), int(loser_pid))

def _create_match_from_tokens(
    conn: sqlite3.Connection,
    tournament_id: int,
    bracket: str,
    round_id: int,
    match_order: int,
    token1,
    token2,
) -> int:
    now_iso = datetime.now(timezone.utc).isoformat()
    p1 = token1 if isinstance(token1, int) else None
    p2 = token2 if isinstance(token2, int) else None
    p1_pre = token1[1] if isinstance(token1, tuple) and token1 and token1[0] in ("winner", "loser") else None
    p2_pre = token2[1] if isinstance(token2, tuple) and token2 and token2[0] in ("winner", "loser") else None
    c = conn.cursor()
    c.execute(
        """
        INSERT INTO tournament_matches (
            tournament_id, bracket, round_id, match_order,
            player1_participant_id, player2_participant_id,
            player1_prereq_match_id, player2_prereq_match_id,
            state, created_at, updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'open', ?, ?)
        """,
        (
            int(tournament_id),
            str(bracket),
            int(round_id),
            int(match_order),
            p1,
            p2,
            p1_pre,
            p2_pre,
            now_iso,
            now_iso,
        ),
    )
    mid = c.lastrowid
    for idx, token in enumerate((token1, token2), start=1):
        if not isinstance(token, tuple) or len(token) < 2:
            continue
        src_match_id = int(token[1])
        if token[0] == "winner":
            c.execute(
                "UPDATE tournament_matches SET next_match_win_id = ?, next_match_win_slot = ?, updated_at = ? WHERE id = ?",
                (int(mid), int(idx), now_iso, src_match_id),
            )
        elif token[0] == "loser":
            c.execute(
                "UPDATE tournament_matches SET next_match_lose_id = ?, next_match_lose_slot = ?, updated_at = ? WHERE id = ?",
                (int(mid), int(idx), now_iso, src_match_id),
            )
    return int(mid)

def _create_round_from_tokens(
    conn: sqlite3.Connection,
    tournament_id: int,
    bracket: str,
    round_id: int,
    tokens: list,
) -> list[int]:
    padded = list(tokens)
    if len(padded) % 2 == 1:
        padded.append(None)
    match_ids = []
    order = 1
    for i in range(0, len(padded), 2):
        mid = _create_match_from_tokens(
            conn,
            int(tournament_id),
            str(bracket),
            int(round_id),
            int(order),
            padded[i],
            padded[i + 1],
        )
        match_ids.append(int(mid))
        order += 1
    return match_ids

def _build_winners_opening_tokens(participant_ids: list[int]):
    ids = list(participant_ids)
    random.shuffle(ids)
    n = len(ids)
    base = _highest_power_of_two_leq(n)
    extras = n - base
    prelim_players = ids[: 2 * extras] if extras > 0 else []
    direct_players = ids[2 * extras :] if extras > 0 else ids
    return base, extras, prelim_players, direct_players

def _auto_progress_byes(conn: sqlite3.Connection, tournament_id: int):
    while True:
        c = conn.cursor()
        # Only progress matches where one player is missing AND there is no prerequisite match feeding that missing slot
        c.execute(
            """
            SELECT * FROM tournament_matches
            WHERE tournament_id = ? AND state = 'open'
            AND (
                (player1_participant_id IS NOT NULL AND player2_participant_id IS NULL AND player2_prereq_match_id IS NULL)
                OR
                (player2_participant_id IS NOT NULL AND player1_participant_id IS NULL AND player1_prereq_match_id IS NULL)
            )
            """,
            (int(tournament_id),),
        )
        matches_to_progress = c.fetchall()
        if not matches_to_progress:
            break

        progressed_any = False
        for match in matches_to_progress:
            winner_pid = match["player1_participant_id"] if match["player1_participant_id"] is not None else match["player2_participant_id"]
            _advance_match_winner(conn, match, winner_pid)
            progressed_any = True

        if progressed_any:
            _refresh_tournament_round_and_status(conn, tournament_id)
        else:
            break

def _create_single_elim_bracket(conn: sqlite3.Connection, tournament_id: int, participant_ids: list[int]):
    if len(participant_ids) < 2:
        return
    base, extras, prelim_players, direct_players = _build_winners_opening_tokens(participant_ids)
    current_round = 1
    opening_tokens = []
    if extras > 0:
        prelim_ids = _create_round_from_tokens(
            conn,
            int(tournament_id),
            "W",
            current_round,
            prelim_players,
        )
        opening_tokens.extend([("winner", int(mid)) for mid in prelim_ids])
        current_round += 1
    opening_tokens.extend(int(pid) for pid in direct_players)
    random.shuffle(opening_tokens)
    while len(opening_tokens) > 1:
        mids = _create_round_from_tokens(
            conn,
            int(tournament_id),
            "W",
            current_round,
            opening_tokens,
        )
        opening_tokens = [("winner", int(mid)) for mid in mids]
        current_round += 1
    _auto_progress_byes(conn, int(tournament_id))

def _create_double_elim_bracket(conn: sqlite3.Connection, tournament_id: int, participant_ids: list[int]):
    if len(participant_ids) < 2:
        return
    base, extras, prelim_players, direct_players = _build_winners_opening_tokens(participant_ids)
    wb_rounds = []
    wb_round_id = 1
    opening_tokens = []
    if extras > 0:
        prelim_ids = _create_round_from_tokens(conn, int(tournament_id), "W", wb_round_id, prelim_players)
        wb_rounds.append([int(mid) for mid in prelim_ids])
        opening_tokens.extend([("winner", int(mid)) for mid in prelim_ids])
        wb_round_id += 1
    opening_tokens.extend(int(pid) for pid in direct_players)
    random.shuffle(opening_tokens)

    while len(opening_tokens) > 1:
        mids = _create_round_from_tokens(conn, int(tournament_id), "W", wb_round_id, opening_tokens)
        wb_rounds.append([int(mid) for mid in mids])
        opening_tokens = [("winner", int(mid)) for mid in mids]
        wb_round_id += 1

    lb_round_id = 1
    lb_survivor_tokens = []
    for i, wb_ids in enumerate(wb_rounds):
        incoming = [("loser", int(mid)) for mid in wb_ids]
        entrants = []
        left = list(lb_survivor_tokens)
        right = list(incoming)
        random.shuffle(left)
        random.shuffle(right)
        while left or right:
            if right:
                entrants.append(right.pop(0))
            if left:
                entrants.append(left.pop(0))
        if entrants:
            mids = _create_round_from_tokens(conn, int(tournament_id), "L", lb_round_id, entrants)
            lb_survivor_tokens = [("winner", int(mid)) for mid in mids]
            lb_round_id += 1

        next_wb_loser_count = len(wb_rounds[i + 1]) if i + 1 < len(wb_rounds) else 0
        while next_wb_loser_count > 0 and len(lb_survivor_tokens) > next_wb_loser_count:
            mids = _create_round_from_tokens(conn, int(tournament_id), "L", lb_round_id, lb_survivor_tokens)
            lb_survivor_tokens = [("winner", int(mid)) for mid in mids]
            lb_round_id += 1

    while len(lb_survivor_tokens) > 1:
        mids = _create_round_from_tokens(conn, int(tournament_id), "L", lb_round_id, lb_survivor_tokens)
        lb_survivor_tokens = [("winner", int(mid)) for mid in mids]
        lb_round_id += 1

    if wb_rounds and lb_survivor_tokens:
        wb_champ = ("winner", int(wb_rounds[-1][0]))
        gf_round_id = wb_round_id
        _create_round_from_tokens(conn, int(tournament_id), "W", gf_round_id, [wb_champ, lb_survivor_tokens[0]])

    _auto_progress_byes(conn, int(tournament_id))

def _db_tournament_row(slug: str):
    conn = _tournament_db_connect()
    c = conn.cursor()
    c.execute("SELECT * FROM tournaments WHERE slug = ?", (slug,))
    row = c.fetchone()
    conn.close()
    return row

def _db_tournament_participants(tournament_id: int):
    conn = _tournament_db_connect()
    c = conn.cursor()
    c.execute(
        "SELECT * FROM tournament_participants WHERE tournament_id = ? ORDER BY seed ASC, id ASC",
        (int(tournament_id),),
    )
    rows = c.fetchall()
    conn.close()
    return rows

def _db_tournament_matches(tournament_id: int, bracket: str = "W", only_open: bool = False):
    conn = _tournament_db_connect()
    c = conn.cursor()
    if only_open:
        c.execute(
            """
            SELECT * FROM tournament_matches
            WHERE tournament_id = ? AND bracket = ? AND state = 'open'
            ORDER BY round_id ASC, match_order ASC, id ASC
            """,
            (int(tournament_id), bracket),
        )
    else:
        c.execute(
            """
            SELECT * FROM tournament_matches
            WHERE tournament_id = ? AND bracket = ?
            ORDER BY round_id ASC, match_order ASC, id ASC
            """,
            (int(tournament_id), bracket),
        )
    rows = c.fetchall()
    conn.close()
    return rows

def _participant_lookup_for_tournament(tournament_id: int) -> dict[int, str]:
    rows = _db_tournament_participants(int(tournament_id))
    return {int(r["id"]): str(r["display_name"]) for r in rows}

def _matches_as_challonge_shape(rows) -> list[dict]:
    out = []
    for m in rows:
        out.append(
            {
                "id": int(m["id"]),
                "round": int(m["round_id"]),
                "state": str(m["state"]),
                "player1_id": m["player1_participant_id"],
                "player2_id": m["player2_participant_id"],
                "winner_id": m["winner_participant_id"],
                "loser_id": m["loser_participant_id"],
                "scores_csv": m["scores_csv"],
                "player1_prereq_match_id": m["player1_prereq_match_id"],
                "player2_prereq_match_id": m["player2_prereq_match_id"],
            }
        )
    return out

def create_challonge_tournament(name, participants, tournament_type="single elimination"):
    setup_tournament_db()
    safe_name = re.sub(r"[^a-zA-Z0-9_]", "_", str(name or "").strip())
    if "_instant_" in safe_name:
        server_part, rest = safe_name.split("_instant_", 1)
        server_name = server_part
        tourn_name = f"instant_{rest}"
    elif "_" in safe_name:
        server_name, tourn_name = safe_name.split("_", 1)
    else:
        server_name, tourn_name = safe_name, "default_tournament"
    slug = _tournament_slug(server_name, tourn_name)
    now_iso = datetime.now(timezone.utc).isoformat()
    cleaned = []
    seen = set()
    for p in (participants or []):
        if isinstance(p, dict):
            display = str(p.get("name") or "").strip()
            ext_id = str(p.get("user_id") or "").strip() or None
        else:
            display = str(p or "").strip()
            ext_id = None
        if not display:
            continue
        key = display.lower()
        if key in seen:
            continue
        seen.add(key)
        cleaned.append({"name": display, "external_id": ext_id})
    if len(cleaned) < 2:
        raise Exception("Need at least 2 participants to create a bracket.")

    conn = _tournament_db_connect()
    c = conn.cursor()
    c.execute("DELETE FROM tournament_matches WHERE tournament_id IN (SELECT id FROM tournaments WHERE slug = ?)", (slug,))
    c.execute("DELETE FROM tournament_participants WHERE tournament_id IN (SELECT id FROM tournaments WHERE slug = ?)", (slug,))
    c.execute("DELETE FROM tournaments WHERE slug = ?", (slug,))
    c.execute(
        """
        INSERT INTO tournaments (slug, name, server_name, tournament_name, tournament_type, status, current_round, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, 'ongoing', 1, ?, ?)
        """,
        (slug, safe_name, server_name, tourn_name, str(tournament_type), now_iso, now_iso),
    )
    tournament_id = c.lastrowid
    participant_ids = []
    for i, pentry in enumerate(cleaned, start=1):
        pname = str(pentry.get("name") or "").strip()
        external_id = pentry.get("external_id")
        c.execute(
            """
            INSERT INTO tournament_participants (tournament_id, seed, display_name, external_id, created_at)
            VALUES (?, ?, ?, ?, ?)
            """,
            (int(tournament_id), int(i), pname, external_id, now_iso),
        )
        participant_ids.append(c.lastrowid)

    ttype = str(tournament_type or "single elimination").strip().lower()
    if ttype == "double elimination":
        _create_double_elim_bracket(conn, int(tournament_id), participant_ids)
    else:
        _create_single_elim_bracket(conn, int(tournament_id), participant_ids)
    conn.commit()
    conn.close()
    row = _db_tournament_row(slug)
    print("create_challonge_tournament name", row["name"])
    return {
        "id": int(row["id"]),
        "url": slug,
        "name": row["name"],
        "tournament_type": row["tournament_type"],
        "full_challonge_url": f"local://tournament/{slug}",
    }

class EndButton(View):
    def __init__(self, server, tourn_name):
        super().__init__()
        self.server = server
        self.tourn_name = tourn_name

    @discord.ui.button(label="Delete Tournament", style=discord.ButtonStyle.red)
    async def end(self, interaction: discord.Interaction, button: discord.Button):
        await interaction.response.defer()
        user = interaction.user
        if user.guild_permissions.manage_roles:
            # File path for local registration file
            file_path = os.path.join('register', f'{self.server}_{self.tourn_name}.txt')
            try:
                setup_tournament_db()
                slug = _tournament_slug(self.server, self.tourn_name)
                conn = _tournament_db_connect()
                c = conn.cursor()
                c.execute("SELECT id FROM tournaments WHERE slug = ?", (slug,))
                row = c.fetchone()
                if row:
                    tid = int(row["id"])
                    c.execute("DELETE FROM tournament_matches WHERE tournament_id = ?", (tid,))
                    c.execute("DELETE FROM tournament_participants WHERE tournament_id = ?", (tid,))
                    c.execute("DELETE FROM tournaments WHERE id = ?", (tid,))
                    conn.commit()
                    await interaction.followup.send(f"Tournament {self.tourn_name} has been deleted from local tournament.db.")
                else:
                    await interaction.followup.send(f"Tournament {self.tourn_name} was not found in tournament.db.")
                conn.close()
            except Exception as e:
                await interaction.followup.send(f"An error occurred while deleting the tournament from tournament.db: {e}\nPlease check tournament name again")
                return
            if os.path.exists(file_path):
                os.remove(file_path)
                await interaction.followup.send(f'{self.tourn_name} in {self.server} has been deleted locally.')
        else:
            await interaction.followup.send('Missing Permissions (manage roles)')

def get_challonge_tournament_info(tournament_name):
    setup_tournament_db()
    row = _db_tournament_row(str(tournament_name))
    if not row:
        raise Exception("Tournament not found in local DB.")
    return {
        "id": int(row["id"]),
        "name": row["name"],
        "url": row["slug"],
        "full_challonge_url": f"local://tournament/{row['slug']}",
        "tournament_type": row["tournament_type"],
        "current_round": int(row["current_round"] or 1),
        "status": row["status"],
    }
def get_tournament_id(tournament_name):
    # Make an API request to list all tournaments
    response = requests.get(
        'https://api.challonge.com/v1/tournaments.json',
        params={'api_key': CHALLONGE_API_KEY},
        auth=(CHALLONGE_USERNAME, 'X')
    )
    
    if response.status_code == 200:
        tournaments = response.json()
        
        # Loop through tournaments to find the matching name
        for tournament in tournaments:
            if tournament['name'].lower() == tournament_name.lower():  # Compare names case-insensitively
                return tournament['id']  # Return the tournament ID
        return None  # If tournament with that name is not found
    else:
        print(f"Error fetching tournaments: {response.status_code}")
        return None

def _import_challonge_tournament_to_local(tournament_slug: str):
    setup_tournament_db()
    base_url = f"https://api.challonge.com/v1/tournaments/{tournament_slug}"
    headers = {"User-Agent": "Mozilla/5.0"}
    t_res = requests.get(
        f"{base_url}.json",
        params={"api_key": CHALLONGE_API_KEY},
        auth=(CHALLONGE_API_KEY, CHALLONGE_USERNAME),
        headers=headers,
        timeout=20,
    )
    t_res.raise_for_status()
    tourn = t_res.json()["tournament"]

    p_res = requests.get(
        f"{base_url}/participants.json",
        params={"api_key": CHALLONGE_API_KEY},
        auth=(CHALLONGE_API_KEY, CHALLONGE_USERNAME),
        headers=headers,
        timeout=20,
    )
    p_res.raise_for_status()
    participants = [x["participant"] for x in p_res.json() if "participant" in x]

    m_res = requests.get(
        f"{base_url}/matches.json",
        params={"api_key": CHALLONGE_API_KEY},
        auth=(CHALLONGE_API_KEY, CHALLONGE_USERNAME),
        headers=headers,
        timeout=20,
    )
    m_res.raise_for_status()
    matches = [x["match"] for x in m_res.json() if "match" in x]

    conn = _tournament_db_connect()
    c = conn.cursor()
    now_iso = datetime.now(timezone.utc).isoformat()

    c.execute("DELETE FROM tournament_matches WHERE tournament_id IN (SELECT id FROM tournaments WHERE slug = ?)", (tournament_slug,))
    c.execute("DELETE FROM tournament_participants WHERE tournament_id IN (SELECT id FROM tournaments WHERE slug = ?)", (tournament_slug,))
    c.execute("DELETE FROM tournaments WHERE slug = ?", (tournament_slug,))

    raw_name = tourn.get("name") or tournament_slug
    if "_" in tournament_slug:
        server_name, tourn_name = tournament_slug.split("_", 1)
    else:
        server_name, tourn_name = tournament_slug, "default_tournament"
    c.execute(
        """
        INSERT INTO tournaments (
            slug, name, server_name, tournament_name, tournament_type, status, current_round,
            challonge_id, challonge_url, created_at, updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, 1, ?, ?, ?, ?)
        """,
        (
            tournament_slug,
            raw_name,
            server_name,
            tourn_name,
            tourn.get("tournament_type") or "single elimination",
            tourn.get("state") or "ongoing",
            str(tourn.get("id") or ""),
            tourn.get("full_challonge_url") or "",
            now_iso,
            now_iso,
        ),
    )
    tournament_id = c.lastrowid

    challonge_to_local_pid = {}
    for i, p in enumerate(sorted(participants, key=lambda x: int(x.get("seed", 0) or 0)), start=1):
        display = str(p.get("name") or f"Participant_{i}")
        c.execute(
            """
            INSERT INTO tournament_participants (
                tournament_id, seed, display_name, external_id, eliminated, created_at
            ) VALUES (?, ?, ?, ?, ?, ?)
            """,
            (
                int(tournament_id),
                int(p.get("seed") or i),
                display,
                str(p.get("id") or ""),
                1 if p.get("final_rank") else 0,
                now_iso,
            ),
        )
        challonge_to_local_pid[int(p.get("id"))] = c.lastrowid

    challonge_to_local_mid = {}
    for idx, m in enumerate(matches, start=1):
        bracket = "L" if int(m.get("round", 1) or 1) < 0 else "W"
        local_round = abs(int(m.get("round", 1) or 1))
        state = "complete" if m.get("winner_id") else "open"
        p1 = challonge_to_local_pid.get(int(m.get("player1_id") or 0))
        p2 = challonge_to_local_pid.get(int(m.get("player2_id") or 0))
        w = challonge_to_local_pid.get(int(m.get("winner_id") or 0))
        l = challonge_to_local_pid.get(int(m.get("loser_id") or 0))
        c.execute(
            """
            INSERT INTO tournament_matches (
                tournament_id, bracket, round_id, match_order, player1_participant_id, player2_participant_id,
                winner_participant_id, loser_participant_id, state, scores_csv, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                int(tournament_id), bracket, local_round, idx, p1, p2, w, l, state, m.get("scores_csv"), now_iso, now_iso
            ),
        )
        challonge_to_local_mid[int(m.get("id"))] = c.lastrowid

    for m in matches:
        local_mid = challonge_to_local_mid.get(int(m.get("id")))
        if not local_mid:
            continue
        p1_pre = challonge_to_local_mid.get(int(m.get("player1_prereq_match_id") or 0))
        p2_pre = challonge_to_local_mid.get(int(m.get("player2_prereq_match_id") or 0))
        c.execute(
            """
            UPDATE tournament_matches
            SET player1_prereq_match_id = ?, player2_prereq_match_id = ?, updated_at = ?
            WHERE id = ?
            """,
            (p1_pre, p2_pre, now_iso, int(local_mid)),
        )
        if p1_pre:
            c.execute(
                "UPDATE tournament_matches SET next_match_win_id = ?, next_match_win_slot = 1, updated_at = ? WHERE id = ?",
                (int(local_mid), now_iso, int(p1_pre)),
            )
        if p2_pre:
            c.execute(
                "UPDATE tournament_matches SET next_match_win_id = ?, next_match_win_slot = 2, updated_at = ? WHERE id = ?",
                (int(local_mid), now_iso, int(p2_pre)),
            )

    _refresh_tournament_round_and_status(conn, int(tournament_id))
    conn.commit()
    conn.close()
    return tournament_id, len(participants), len(matches)
    
import requests
from PIL import Image, ImageDraw, ImageFont, ImageFont, ImageChops, ImageOps
import math
