import requests

def fetch_open_challonge_data(tournament_name):
    setup_tournament_db()
    row = _db_tournament_row(str(tournament_name))
    if not row:
        raise Exception("Tournament not found in local DB.")
    participants = []
    for i, p in enumerate(_db_tournament_participants(int(row["id"])), start=1):
        participants.append({"participant": {"id": int(p["id"]), "name": f"{i}. {p['display_name']}"}})
    winner_rows = _db_tournament_matches(int(row["id"]), bracket="W", only_open=True)
    loser_rows = _db_tournament_matches(int(row["id"]), bracket="L", only_open=True)
    return participants, _matches_as_challonge_shape(winner_rows), _matches_as_challonge_shape(loser_rows)

def fetch_challonge_data(tournament_name):
    setup_tournament_db()
    row = _db_tournament_row(str(tournament_name))
    if not row:
        raise Exception("Tournament not found in local DB.")
    participants = []
    for i, p in enumerate(_db_tournament_participants(int(row["id"])), start=1):
        participants.append({"participant": {"id": int(p["id"]), "name": f"{i}. {p['display_name']}"}})
    winner_rows = _db_tournament_matches(int(row["id"]), bracket="W", only_open=False)
    loser_rows = _db_tournament_matches(int(row["id"]), bracket="L", only_open=False)
    return participants, _matches_as_challonge_shape(winner_rows), _matches_as_challonge_shape(loser_rows)

def draw_bracket2(participants_json, matches_json, double, current_round=None):
    import math
    from io import BytesIO
    from PIL import Image, ImageDraw, ImageFont

    id_to_name = {
        p["participant"]["id"]: p["participant"]["name"]
        for p in participants_json
    }

    if not matches_json:
        img = Image.new("RGBA", (820, 300), (20, 24, 30, 255))
        draw = ImageDraw.Draw(img)
        draw.text((30, 30), "No bracket matches available.", fill="white")
        output = BytesIO()
        img.save(output, format="PNG")
        output.seek(0)
        return output

    for m in matches_json:
        m["round"] = abs(int(m.get("round", 1) or 1))

    match_by_id = {
        m["id"]: m
        for m in matches_json
    }

    open_rounds = [
        m["round"]
        for m in matches_json
        if str(m.get("state", "")).lower() == "open"
        and not m.get("winner_id")
    ]

    if current_round is None:
        current_round = (
            min(open_rounds)
            if open_rounds
            else max(m["round"] for m in matches_json)
        )

    visible_matches = [
        m
        for m in matches_json
        if m["round"] == current_round
    ]

    if not visible_matches:
        img = Image.new("RGBA", (820, 300), (20, 24, 30, 255))
        draw = ImageDraw.Draw(img)
        draw.text(
            (30, 30),
            f"No matches in round {current_round}.",
            fill="white"
        )
        output = BytesIO()
        img.save(output, format="PNG")
        output.seek(0)
        return output

    def get_player_name(match_obj, player_num):
        pid = match_obj.get(f"player{player_num}_id")

        if pid:
            return id_to_name.get(pid, "TBD")

        prereq = match_obj.get(
            f"player{player_num}_prereq_match_id"
        )

        if not prereq:
            return "TBD"

        feeder = match_by_id.get(prereq)

        if not feeder:
            return "TBD"

        # Only show "A or B" if feeder is immediately
        # one round behind this match.
        if feeder["round"] != match_obj["round"] - 1:
            return "TBD"

        p1 = id_to_name.get(feeder.get("player1_id"))
        p2 = id_to_name.get(feeder.get("player2_id"))

        if p1 and p2:
            return f"{p1} / {p2}"

        return "TBD"

    box_w = 300
    box_h = 56
    col_gap = 140
    row_gap = 34
    margin_x = 24
    margin_y = 24

    MAX_MATCHES_PER_COLUMN = 8

    num_matches = len(visible_matches)
    num_cols = math.ceil(
        num_matches / MAX_MATCHES_PER_COLUMN
    )

    rows_in_tallest_col = min(
        MAX_MATCHES_PER_COLUMN,
        num_matches
    )

    img_w = (
        margin_x * 2
        + num_cols * box_w
        + max(0, num_cols - 1) * col_gap
    )

    img_h = (
        margin_y * 2
        + rows_in_tallest_col * box_h
        + max(0, rows_in_tallest_col - 1) * row_gap
    )

    img_h = max(img_h, 240)

    try:
        bg = (
            Image.open("background.png")
            .convert("RGBA")
            .resize((img_w, img_h))
        )
    except Exception:
        bg = Image.new(
            "RGBA",
            (img_w, img_h),
            (16, 22, 30, 255)
        )

    img = Image.new("RGBA", (img_w, img_h))
    img.paste(bg, (0, 0))

    draw = ImageDraw.Draw(img)

    try:
        font = ImageFont.truetype(
            "comic.ttf",
            16
        )
    except Exception:
        font = ImageFont.load_default()

    for idx, m in enumerate(visible_matches):

        col = idx // MAX_MATCHES_PER_COLUMN
        row = idx % MAX_MATCHES_PER_COLUMN

        x = margin_x + col * (box_w + col_gap)
        y = margin_y + row * (box_h + row_gap)

        p1 = get_player_name(m, 1)
        p2 = get_player_name(m, 2)

        if m.get("winner_id"):
            winner = id_to_name.get(
                m.get("winner_id"),
                "TBD"
            )

            line1 = p1
            line2 = f"{p2} | Winner: {winner}"
        else:
            line1 = p1
            line2 = p2

        fill = (36, 44, 56, 230)
        outline = (220, 220, 220, 255)

        draw.rounded_rectangle(
            [
                x,
                y,
                x + box_w,
                y + box_h
            ],
            radius=8,
            fill=fill,
            outline=outline,
            width=2
        )

        draw.text(
            (x + 10, y + 8),
            line1[:36],
            fill="white",
            font=font
        )

        draw.text(
            (x + 10, y + 30),
            line2[:44],
            fill=(230, 230, 230, 255),
            font=font
        )

    label = (
        f"Round {current_round} "
        f"{'(Losers)' if double else '(Winners)'}"
    )

    draw.text(
        (margin_x, 4),
        label,
        fill=(255, 255, 255, 255),
        font=font
    )

    output = BytesIO()
    img.save(output, format="PNG")
    output.seek(0)

    return output

def _find_participant_row_by_name(conn: sqlite3.Connection, tournament_id: int, name_like: str):
    target = _normalize_tournament_name(name_like)
    c = conn.cursor()
    c.execute(
        "SELECT * FROM tournament_participants WHERE tournament_id = ?",
        (int(tournament_id),),
    )
    rows = c.fetchall()
    for row in rows:
        if _normalize_tournament_name(row["display_name"]) == target:
            return row
    return None

def _find_participant_row_by_external_id(conn: sqlite3.Connection, tournament_id: int, external_id: int | str | None):
    ext = str(external_id or "").strip()
    if not ext:
        return None
    c = conn.cursor()
    c.execute(
        "SELECT * FROM tournament_participants WHERE tournament_id = ? AND external_id = ? LIMIT 1",
        (int(tournament_id), ext),
    )
    return c.fetchone()

def _record_local_tournament_loss(slug: str, loser_name: str, loser_user_id: int | None = None):
    setup_tournament_db()
    conn = _tournament_db_connect()
    c = conn.cursor()
    c.execute("SELECT * FROM tournaments WHERE slug = ?", (slug,))
    tourn = c.fetchone()
    if not tourn:
        conn.close()
        return False, "Tournament not found in tournament.db.", None

    loser_row = None
    if loser_user_id is not None:
        loser_row = _find_participant_row_by_external_id(conn, int(tourn["id"]), int(loser_user_id))
    if not loser_row:
        loser_row = _find_participant_row_by_name(conn, int(tourn["id"]), loser_name)
    if not loser_row:
        conn.close()
        return False, "Loser was not found in tournament bracket.", None
    loser_pid = int(loser_row["id"])

    c.execute(
        """
        SELECT *
        FROM tournament_matches
        WHERE tournament_id = ? AND bracket IN ('W', 'L') AND state = 'open'
          AND (player1_participant_id = ? OR player2_participant_id = ?)
        ORDER BY CASE bracket WHEN 'W' THEN 0 ELSE 1 END, round_id ASC, match_order ASC, id ASC
        LIMIT 1
        """,
        (int(tourn["id"]), loser_pid, loser_pid),
    )
    match = c.fetchone()
    if not match:
        conn.close()
        return False, "No open match found for that participant.", None

    resolved_bracket = str(match["bracket"])
    resolved_round = int(match["round_id"])
    winner_pid = match["player2_participant_id"] if int(match["player1_participant_id"] or 0) == loser_pid else match["player1_participant_id"]
    if not winner_pid:
        conn.close()
        return False, "Match opponent is not assigned yet.", None

    tournament_type = str(tourn["tournament_type"] if "tournament_type" in tourn.keys() else "single elimination").strip().lower()
    _advance_match_winner(conn, match, int(winner_pid))
    c.execute("UPDATE tournament_participants SET losses = COALESCE(losses, 0) + 1 WHERE id = ?", (int(loser_pid),))
    c.execute("SELECT losses FROM tournament_participants WHERE id = ?", (int(loser_pid),))
    lrow = c.fetchone()
    losses_now = int((lrow["losses"] if lrow else 1) or 1)
    if tournament_type == "double elimination":
        if losses_now >= 2:
            c.execute(
                "UPDATE tournament_participants SET eliminated = 1, eliminated_round = ? WHERE id = ?",
                (int(match["round_id"]), int(loser_pid)),
            )
        else:
            c.execute("UPDATE tournament_participants SET eliminated = 0 WHERE id = ?", (int(loser_pid),))
    else:
        c.execute(
            "UPDATE tournament_participants SET eliminated = 1, eliminated_round = ? WHERE id = ?",
            (int(match["round_id"]), int(loser_pid)),
        )
    _auto_progress_byes(conn, int(tourn["id"]))

    c.execute(
        """
        SELECT COUNT(*) AS open_count
        FROM tournament_matches
        WHERE tournament_id = ? AND bracket = ? AND round_id = ? AND state = 'open'
        """,
        (int(tourn["id"]), resolved_bracket, resolved_round),
    )
    open_count_row = c.fetchone()
    round_completed = int((open_count_row["open_count"] if open_count_row else 0) or 0) == 0

    c.execute("SELECT status, current_round FROM tournaments WHERE id = ?", (int(tourn["id"]),))
    trow = c.fetchone()
    tournament_status = str(trow["status"] if trow else "ongoing")
    current_round = int((trow["current_round"] if trow else resolved_round) or resolved_round)

    conn.commit()

    c.execute("SELECT display_name FROM tournament_participants WHERE id = ?", (int(winner_pid),))
    wrow = c.fetchone()
    winner_name = wrow["display_name"] if wrow else "Unknown"
    conn.close()
    meta = {
        "slug": slug,
        "tournament_id": int(tourn["id"]),
        "resolved_bracket": resolved_bracket,
        "resolved_round": resolved_round,
        "round_completed": round_completed,
        "tournament_completed": tournament_status == "completed",
        "current_round": current_round,
    }
    return True, f"Bracket updated. Winner: {winner_name}", meta

def _participant_mention_or_name(guild: discord.Guild, participant_row: sqlite3.Row) -> str:
    ext = str(participant_row["external_id"] or "").strip()
    if ext.isdigit():
        try:
            uid = int(ext)
            member = guild.get_member(uid)
            if member:
                return member.mention
            return f"<@{uid}>"
        except Exception:
            pass
    return str(participant_row["display_name"])

def _parse_channel_from_text(guild: discord.Guild, raw: str):
    text = str(raw or "").strip()
    match = re.search(r"<#(\d+)>", text)
    if match:
        cid = int(match.group(1))
    elif text.isdigit():
        cid = int(text)
    else:
        return None
    return guild.get_channel(cid)

async def _create_tournament_threads_from_db(
    guild: discord.Guild,
    target_channel: discord.TextChannel,
    slug: str,
    thread_content: str | None = None,
) -> int:
    row = _db_tournament_row(slug)
    if not row:
        raise ValueError("Tournament not found.")
    participants = _db_tournament_participants(int(row["id"]))
    by_id = {int(p["id"]): p for p in participants}
    open_w = _db_tournament_matches(int(row["id"]), bracket="W", only_open=True)
    open_l = _db_tournament_matches(int(row["id"]), bracket="L", only_open=True)
    created = 0
    for m in (open_w + open_l):
        p1 = by_id.get(int(m["player1_participant_id"] or 0))
        p2 = by_id.get(int(m["player2_participant_id"] or 0))
        if not p1 or not p2:
            continue
        p1_text = _participant_mention_or_name(guild, p1)
        p2_text = _participant_mention_or_name(guild, p2)
        round_label = f"{m['bracket']}{m['round_id']}"
        thread_name = f"[{round_label}] {p1['display_name']} vs {p2['display_name']}"
        thread = await target_channel.create_thread(name=thread_name[:95], type=discord.ChannelType.public_thread)
        await thread.send(f"Match: {p1_text} vs {p2_text}")
        p1_uid = _participant_user_id(p1)
        p2_uid = _participant_user_id(p2)
        tournament_name = str(row["tournament_name"] or "")
        if "instant" not in tournament_name.lower() and "instant" in str(row["name"] or "").lower():
            full_name = str(row["name"] or "")
            if "_instant_" in full_name.lower():
                tournament_name = full_name.split("_instant_", 1)[1]
            else:
                tournament_name = full_name
        is_instant = "instant" in tournament_name.lower()
        if is_instant and p1_uid and p2_uid:
            print("_create_tournament_threads_from_db name", tournament_name)
            print("_create_tournament_threads_from_db slug", slug)
            view = InstantMatchReportView(
                slug=slug,
                tourn_name=tournament_name or "default tournament",
                p1_uid=p1_uid,
                p1_name=str(p1["display_name"]),
                p2_uid=p2_uid,
                p2_name=str(p2["display_name"]),
            )
            await thread.send("Report match result:", view=view)
        if thread_content:
            await thread.send(thread_content)
        created += 1
    return created

async def _create_tournament_posts_from_db(
    guild: discord.Guild,
    forum_channel: discord.ForumChannel,
    slug: str,
    post_content: str | None = None,
) -> int:
    row = _db_tournament_row(slug)
    if not row:
        raise ValueError("Tournament not found.")
    participants = _db_tournament_participants(int(row["id"]))
    by_id = {int(p["id"]): p for p in participants}
    open_w = _db_tournament_matches(int(row["id"]), bracket="W", only_open=True)
    open_l = _db_tournament_matches(int(row["id"]), bracket="L", only_open=True)
    created = 0
    for m in (open_w + open_l):
        p1 = by_id.get(int(m["player1_participant_id"] or 0))
        p2 = by_id.get(int(m["player2_participant_id"] or 0))
        if not p1 or not p2:
            continue
        p1_text = _participant_mention_or_name(guild, p1)
        p2_text = _participant_mention_or_name(guild, p2)
        round_label = f"{m['bracket']}{m['round_id']}"
        title = f"[{round_label}] {p1['display_name']} vs {p2['display_name']}"[:95]
        body = f"{post_content or 'Match details:'}\nMatch: {p1_text} vs {p2_text}"
        await forum_channel.create_thread(name=title, content=body)
        created += 1
    return created

class TournamentDeleteConfirmView(discord.ui.View):
    def __init__(self, slug: str, tourn_name: str):
        super().__init__(timeout=120)
        self.slug = slug
        self.tourn_name = tourn_name

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if not interaction.guild or not _is_tournament_manager_member(interaction.user, interaction.guild):
            await interaction.response.send_message("Tournament manager role required. Use `/tournament manager <role>` first.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="Confirm Delete", style=discord.ButtonStyle.danger)
    async def confirm_delete(self, interaction: discord.Interaction, button: discord.ui.Button):
        conn = _tournament_db_connect()
        c = conn.cursor()
        c.execute("SELECT id FROM tournaments WHERE slug = ?", (self.slug,))
        row = c.fetchone()
        if row:
            tid = int(row["id"])
            c.execute("DELETE FROM tournament_matches WHERE tournament_id = ?", (tid,))
            c.execute("DELETE FROM tournament_participants WHERE tournament_id = ?", (tid,))
            c.execute("DELETE FROM tournaments WHERE id = ?", (tid,))
            conn.commit()
            conn.close()
            await interaction.response.send_message(f"Deleted tournament `{self.tourn_name}` from tournament.db.", ephemeral=True)
        else:
            conn.close()
            await interaction.response.send_message("Tournament already deleted or not found.", ephemeral=True)

    @discord.ui.button(label="Cancel", style=discord.ButtonStyle.secondary)
    async def cancel(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.send_message("Delete cancelled.", ephemeral=True)

class TournamentTargetModal(discord.ui.Modal):
    def __init__(self, action_kind: str, slug: str, tourn_name: str):
        super().__init__(title=f"Tournament {action_kind.title()} Target")
        self.action_kind = action_kind
        self.slug = slug
        self.tourn_name = tourn_name
        self.target = discord.ui.TextInput(
            label="Target Channel",
            placeholder="Enter #channel mention or channel ID",
            required=True,
            max_length=100,
        )
        self.content = discord.ui.TextInput(
            label="Optional Message",
            placeholder="Optional extra text to send in post/thread",
            required=False,
            max_length=300,
        )
        self.add_item(self.target)
        self.add_item(self.content)

    async def on_submit(self, interaction: discord.Interaction):
        if not interaction.guild or not _is_tournament_manager_member(interaction.user, interaction.guild):
            return await interaction.response.send_message("Tournament manager role required. Use `/tournament manager <role>` first.", ephemeral=True)
        target_ch = _parse_channel_from_text(interaction.guild, str(self.target.value))
        if not target_ch:
            return await interaction.response.send_message("Could not parse target channel. Use #mention or channel ID.", ephemeral=True)
        try:
            if self.action_kind == "thread":
                if not isinstance(target_ch, discord.TextChannel):
                    return await interaction.response.send_message("Target must be a text channel for thread creation.", ephemeral=True)
                n = await _create_tournament_threads_from_db(interaction.guild, target_ch, self.slug, str(self.content.value or "").strip() or None)
                await interaction.response.send_message(
                    f"Created {n} thread(s) in {target_ch.mention}.\nYou can also use `/tournament create_threads`.",
                    ephemeral=True,
                )
            else:
                if not isinstance(target_ch, discord.ForumChannel):
                    return await interaction.response.send_message("Target must be a forum channel for post creation.", ephemeral=True)
                n = await _create_tournament_posts_from_db(interaction.guild, target_ch, self.slug, str(self.content.value or "").strip() or None)
                await interaction.response.send_message(
                    f"Created {n} post(s) in {target_ch.mention}.\nYou can also use `/tournament create_posts`.",
                    ephemeral=True,
                )
        except Exception as e:
            await interaction.response.send_message(f"Failed to create {self.action_kind}s: {e}", ephemeral=True)

