async def _maybe_send_tournament_round_actions(
    interaction: discord.Interaction,
    slug: str,
    tourn_name: str,
    meta: dict | None,
):
    if not interaction.guild or not meta:
        return
    if not meta.get("round_completed"):
        return
    role_id = _get_tournament_manager_role_id(interaction.guild.id)
    if not role_id:
        return
    mention = f"<@&{int(role_id)}>"
    resolved_round = int(meta.get("resolved_round", 0) or 0)
    bracket = str(meta.get("resolved_bracket") or "W")
    msg = (
        f"{mention} Round `{bracket}{resolved_round}` is complete for **{tourn_name}**.\n"
        "Manager actions below.\n"
        "You can also run `/tournament create_posts` or `/tournament create_threads` manually."
    )
    await interaction.channel.send(msg, view=TournamentRoundActionView(slug, tourn_name))

INSTANT_TOURNAMENT_SESSIONS = {}

def _resolve_tournament_name_for_log(guild: discord.Guild, tournament: str | None):
    requested = str(tournament or "default tournament").strip()
    if requested.lower() != "instant":
        return requested, None
    setup_tournament_db()
    server_key = re.sub(r"[^a-zA-Z0-9_]", "_", str(guild.name or "").replace(" ", "_").lower())
    conn = _tournament_db_connect()
    try:
        c = conn.cursor()
        c.execute(
            """
            SELECT tournament_name
            FROM tournaments
            WHERE server_name = ? AND tournament_name LIKE 'instant_%'
            ORDER BY
                CASE WHEN status = 'ongoing' THEN 0 ELSE 1 END,
                datetime(updated_at) DESC,
                id DESC
            LIMIT 1
            """,
            (server_key,),
        )
        row = c.fetchone()
    finally:
        conn.close()
    if not row:
        return None, "No instant tournament found for this server."
    return str(row["tournament_name"]), None

def _apply_tournament_log_loss(guild: discord.Guild, loser_id: int, loser_name: str, tourn_name: str):
    server = guild.name
    file_path = os.path.join("register", f"{server}_{tourn_name}.txt")
    lines = []
    parsed = []
    loser_index = None
    loser_team = None
    loser_token = f"<@{int(loser_id)}>"

    try:
        if os.path.exists(file_path):
            with open(file_path, "r", encoding="utf-8") as f:
                lines = f.readlines()

            for idx, line in enumerate(lines):
                text = line.strip()
                mention = text.split("(")[0].strip()
                if mention == loser_token or mention == f"<@!{int(loser_id)}>":
                    loser_index = idx
                m = re.match(r"<@!?(\d+)>(?:\(([^)]+)\))?", text)
                if m:
                    uid_str, team = m.groups()
                    uid = int(uid_str)
                    parsed.append((uid, team))
                    if uid == int(loser_id):
                        loser_team = team
        else:
            # No registration file available; proceed with logging based on loser name only.
            pass
    except Exception as e:
        print(e)

    team_members_same_team = [x for x in parsed if loser_team and x[1] == loser_team]
    loser_key = loser_team if loser_team and len(team_members_same_team) == 1 else str(loser_name)
    safe_tourn_name = re.sub(r"[^a-zA-Z0-9_]", "_", f"{server}_{tourn_name}").replace(" ", "_").lower()
    ok, msg, meta = _record_local_tournament_loss(safe_tourn_name, loser_key, int(loser_id))
    if not ok:
        return False, msg, safe_tourn_name, meta

    if os.path.exists(file_path) and loser_index is not None:
        try:
            eliminated = lines.pop(loser_index).strip()
            with open(file_path, "w", encoding="utf-8") as f:
                f.writelines(lines)

            elim_path = os.path.join("register", f"{server}_{tourn_name}_elim.txt")
            with open(elim_path, "a", encoding="utf-8") as f:
                f.write(f"{eliminated}\n")
        except Exception as e:
            print(e)

    return True, msg, safe_tourn_name, meta
    

def _participant_user_id(row: sqlite3.Row) -> int | None:
    ext = str(row["external_id"] or "").strip()
    if ext.isdigit():
        return int(ext)
    return None

class InstantMatchLossConfirmView(discord.ui.View):
    def __init__(self, slug: str, tourn_name: str, winner_uid: int, winner_name: str, loser_uid: int, loser_name: str):
        super().__init__(timeout=180)
        self.slug = slug
        self.tourn_name = tourn_name
        self.winner_uid = int(winner_uid)
        self.winner_name = str(winner_name)
        self.loser_uid = int(loser_uid)
        self.loser_name = str(loser_name)

    @discord.ui.button(label="Confirm", style=discord.ButtonStyle.success)
    async def confirm(self, interaction: discord.Interaction, button: discord.ui.Button):
        if int(interaction.user.id) != self.loser_uid:
            return await interaction.response.send_message("Only the reported loser can confirm.", ephemeral=True)
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True
        await interaction.response.edit_message(content="Confirmed. Updating records...", view=self)
        ok, msg, safe_slug, meta = _apply_tournament_log_loss(interaction.guild, self.loser_uid, self.loser_name, self.tourn_name)
        if not ok:
            return await interaction.followup.send(msg)
        await interaction.followup.send(f"<@{self.loser_uid}> has confirmed their defeat. {msg}")
        try:
            await _maybe_send_tournament_round_actions(interaction, safe_slug, self.tourn_name, meta)
        except Exception:
            traceback.print_exc()

    @discord.ui.button(label="Decline", style=discord.ButtonStyle.danger)
    async def decline(self, interaction: discord.Interaction, button: discord.ui.Button):
        if int(interaction.user.id) != self.loser_uid:
            return await interaction.response.send_message("Only the reported loser can decline.", ephemeral=True)
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True
        await interaction.response.edit_message(content="Declined. No changes made.", view=self)

    @discord.ui.button(label="Force Log", style=discord.ButtonStyle.blurple)
    async def force_log(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not _is_tournament_manager_member(interaction.user, interaction.guild):
            return await interaction.response.send_message(
                "Tournament manager role required to use Force Log. Use `/tournament manager <role>` first.",
                ephemeral=True,
            )
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True
        await interaction.response.edit_message(content="Force Log. Updating records...", view=self)
        ok, msg, safe_slug, meta = _apply_tournament_log_loss(interaction.guild, self.loser_uid, self.loser_name, self.tourn_name)
        if not ok:
            return await interaction.followup.send(msg)
        await interaction.followup.send(
            f"**{interaction.user.mention}** forced the log of defeat for <@{self.loser_uid}>. {msg}"
        )
        try:
            await _maybe_send_tournament_round_actions(interaction, safe_slug, self.tourn_name, meta)
        except Exception:
            traceback.print_exc()

class InstantMatchWinnerButton(discord.ui.Button):
    def __init__(self, winner_side: int):
        super().__init__(style=discord.ButtonStyle.primary)
        self.winner_side = int(winner_side)

    async def callback(self, interaction: discord.Interaction):
        view = self.view
        if not isinstance(view, InstantMatchReportView):
            return await interaction.response.send_message("Invalid match view.", ephemeral=True)
        await view.on_pick_winner(interaction, self.winner_side)

class InstantMatchReportView(discord.ui.View):
    def __init__(self, slug: str, tourn_name: str, p1_uid: int, p1_name: str, p2_uid: int, p2_name: str):
        super().__init__(timeout=None)
        self.slug = slug
        self.tourn_name = tourn_name
        self.p1_uid = int(p1_uid)
        self.p2_uid = int(p2_uid)
        self.p1_name = str(p1_name)
        self.p2_name = str(p2_name)
        b1 = InstantMatchWinnerButton(1)
        b1.label = f"{self.p1_name} win"
        b2 = InstantMatchWinnerButton(2)
        b2.label = f"{self.p2_name} win"
        self.add_item(b1)
        self.add_item(b2)

    async def on_pick_winner(self, interaction: discord.Interaction, winner_side: int):
        if winner_side == 1:
            winner_uid, winner_name = self.p1_uid, self.p1_name
            loser_uid, loser_name = self.p2_uid, self.p2_name
        else:
            winner_uid, winner_name = self.p2_uid, self.p2_name
            loser_uid, loser_name = self.p1_uid, self.p1_name
        view = InstantMatchLossConfirmView(self.slug, self.tourn_name, winner_uid, winner_name, loser_uid, loser_name)
        await interaction.response.send_message(
            f"<@{loser_uid}>, {interaction.user.mention} reported **{winner_name} win**. Confirm your loss?",
            view=view,
        )

class InstantTournamentJoinView(discord.ui.View):
    def __init__(self, guild_id: int, channel_id: int, host_id: int):
        super().__init__(timeout=30)
        self.guild_id = int(guild_id)
        self.channel_id = int(channel_id)
        self.host_id = int(host_id)
        self.joined_users = {}
        self.message = None

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if not interaction.guild or int(interaction.guild.id) != self.guild_id:
            await interaction.response.send_message("This instant tournament is not for this server.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="Join Instant Tournament", style=discord.ButtonStyle.success)
    async def join_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        user = interaction.user
        if int(user.id) in self.joined_users:
            self.joined_users.pop(int(user.id), None)
            await interaction.response.send_message("You left the instant tournament.", ephemeral=True)
        else:
            self.joined_users[int(user.id)] = {
                "user_id": int(user.id),
                "name": str(getattr(user, "display_name", user.name)),
            }
            await interaction.response.send_message("You joined the instant tournament.", ephemeral=True)

    async def on_timeout(self):
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True
        try:
            if self.message:
                await self.message.edit(view=self)
        except Exception:
            pass

        active_view = INSTANT_TOURNAMENT_SESSIONS.get(self.guild_id)
        if active_view is not self:
            return
        INSTANT_TOURNAMENT_SESSIONS.pop(self.guild_id, None)

        guild = bot.get_guild(self.guild_id)
        channel = bot.get_channel(self.channel_id)
        if channel is None:
            try:
                channel = await bot.fetch_channel(self.channel_id)
            except Exception:
                return
        if guild is None and hasattr(channel, "guild"):
            guild = channel.guild

        asyncio.create_task(self._start_instant_tournament(channel, guild))

    async def _start_instant_tournament(self, channel, guild):
        participants = list(self.joined_users.values())

        """extra_id = 1332728969958527058

        extra = (
            bot.get_user(extra_id)
            or await interaction.client.fetch_user(extra_id)
        )

        participants.append({
            "user_id": extra.id,
            "name": extra.display_name if hasattr(extra, "display_name") else extra.name,
        })"""
        if len(participants) < 2:
            try:
                await channel.send("Instant tournament cancelled: need at least 2 participants.")
            except Exception:
                pass
            return
        used = set()
        normalized = []
        for p in participants:
            base = str(p.get("name") or f"user_{p['user_id']}").strip() or f"user_{p['user_id']}"
            candidate = base
            i = 2
            while candidate.lower() in used:
                candidate = f"{base}-{i}"
                i += 1
            used.add(candidate.lower())
            normalized.append({"name": candidate, "user_id": p["user_id"]})
        safe_tourn_name = re.sub(r"[^a-zA-Z0-9_]", "_", f"{(guild.name if guild else 'server')}_instant_{int(time.time())}")
        print("_start_instant_tournament name", safe_tourn_name)
        try:
            tournament = create_challonge_tournament(safe_tourn_name, normalized, "single elimination")
            slug = str(tournament["url"])
            print("_start_instant_tournament slug", slug)

            # Create a local registration file for instant tournaments so tournament log
            # commands and loss reporting can find and parse the participants.
            register_dir = "register"
            os.makedirs(register_dir, exist_ok=True)
            server_name = guild.name if guild else "server"
            file_path = os.path.join(register_dir, f"{server_name}_{safe_tourn_name}.txt")
            with open(file_path, "w", encoding="utf-8") as f:
                for participant in normalized:
                    f.write(f"<@{participant['user_id']}>\n")

            await channel.send(f"✅ Instant tournament started: `{slug}`")
            image_data = fetch_challonge_data(slug)
            image = await asyncio.to_thread(draw_bracket2, image_data[0], image_data[1], False)
            await channel.send(file=discord.File(image, "instant_bracket.png"))
            if isinstance(channel, discord.TextChannel):
                created = await _create_tournament_threads_from_db(
                    guild=channel.guild,
                    target_channel=channel,
                    slug=slug,
                    thread_content="Instant tournament match thread.",
                )
                await channel.send(f"Created {created} match thread(s) in this channel.")
            else:
                await channel.send("Bracket created. Could not auto-create threads because current channel is not a text channel.")
        except Exception as e:
            try:
                await channel.send(f"Failed to start instant tournament: {e}")
            except Exception:
                pass

