def _build_support_server_view(label: str = "Support Server") -> discord.ui.View:
    view = discord.ui.View()
    view.add_item(discord.ui.Button(label=label, url=SUPPORT_SERVER_INVITE))
    return view

class TournamentFundSelect(discord.ui.Select):
    def __init__(self, guild_id: int):
        self.guild_id = int(guild_id)
        options = [
            discord.SelectOption(label="Amateur", value="amateur", description="5 ARCs per sign up · 32 minimum"),
            discord.SelectOption(label="Standard", value="standard", description="25 ARCs per sign up · 18 minimum"),
            discord.SelectOption(label="Special", value="special", description="Event cosmetics"),
        ]
        super().__init__(placeholder="Choose a prize pool", min_values=1, max_values=1, options=options)

    async def callback(self, interaction: discord.Interaction):
        tier = self.values[0]
        if tier in {"amateur", "standard"} and not _is_oranguru_member(interaction.user.id):
            return await interaction.response.send_message(
                "Only Oranguru Academy members can use Amateur or Standard tournaments.\n"
                "Please apply in the support server and create a ticket.",
                view=_build_support_server_view(),
                ephemeral=True,
            )
        if tier == "special":
            return await interaction.response.send_message(
                "Special tournaments are handled via the support server. Please create a ticket to apply.",
                view=_build_support_server_view(),
                ephemeral=True,
            )
        view = TournamentSignupView(self.guild_id, tier)
        await interaction.response.send_message("Press **Sign Up** to join the tournament pool.", view=view)

class TournamentSignupView(discord.ui.View):
    def __init__(self, guild_id: int, tier: str):
        super().__init__(timeout=300)
        self.add_item(TournamentSignupButton(guild_id, tier))

class TournamentSignupButton(discord.ui.Button):
    def __init__(self, guild_id: int, tier: str):
        super().__init__(label="Sign Up", style=discord.ButtonStyle.success)
        self.guild_id = int(guild_id)
        self.tier = str(tier)

    async def callback(self, interaction: discord.Interaction):
        if not interaction.guild:
            return await interaction.response.send_message("This action must be used in a server.", ephemeral=True)
        if self.tier in {"amateur", "standard"} and not _is_oranguru_member(interaction.user.id):
            return await interaction.response.send_message(
                "Only Oranguru Academy members can sign up for this tournament.\n"
                "Please apply in the support server and create a ticket.",
                view=_build_support_server_view(),
                ephemeral=True,
            )
        remaining = _tournament_user_cooldown_remaining(interaction.user.id)
        if remaining > 0:
            next_ts = int(time.time()) + int(remaining)
            return await interaction.response.send_message(
                f"❌ You can only sign up once every 14 days. Try again <t:{next_ts}:R>.",
                ephemeral=True,
            )
        _record_tournament_signup(self.guild_id, interaction.user.id, self.tier)
        tier_cfg = TOURNAMENT_TIERS.get(self.tier, {})
        min_signups = int(tier_cfg.get("min_signups", 0))
        cutoff = int(time.time()) - TOURNAMENT_SIGNUP_COOLDOWN_SECS
        count = _count_recent_signups(self.guild_id, self.tier, cutoff)
        await interaction.response.send_message(
            f"✅ Signed up for **{self.tier.title()}**.\n"
            f"Current sign-ups: **{count}/{min_signups}**.\n"
            "Select when to assign the prize pool:",
            view=TournamentDelaySelectView(),
            ephemeral=False,
        )
        try:
            msg = await interaction.original_response()
            with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
                c = conn.cursor()
                c.execute(
                    """
                    INSERT OR REPLACE INTO tournament_delay_pending (message_id, user_id, guild_id, tier, created_at)
                    VALUES (?, ?, ?, ?, ?)
                    """,
                    (int(msg.id), int(interaction.user.id), int(self.guild_id), str(self.tier), int(time.time())),
                )
                conn.commit()
        except Exception:
            pass


TOURNAMENT_DELAY_CHOICES = [
    ("1s", 1),
    ("10 min", 10 * 60),
    ("1 hour", 60 * 60),
    ("6 hours", 6 * 60 * 60),
    ("1 day", 24 * 60 * 60),
    ("1 day 12 hours", 36 * 60 * 60),
    ("2 days", 48 * 60 * 60),
    ("2 days 12 hours", 60 * 60 * 60),
    ("3 days", 72 * 60 * 60),
]

class TournamentDelaySelectView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)
        self.add_item(TournamentDelaySelect())

class TournamentDelaySelect(discord.ui.Select):
    def __init__(self):
        options = [
            discord.SelectOption(label=label, value=str(seconds))
            for label, seconds in TOURNAMENT_DELAY_CHOICES
        ]
        super().__init__(
            placeholder="Choose assignment delay",
            min_values=1,
            max_values=1,
            options=options,
            custom_id="tourn_delay_select",
        )

    async def callback(self, interaction: discord.Interaction):
        try:
            with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
                c = conn.cursor()
                c.execute(
                    "SELECT user_id, guild_id, tier FROM tournament_delay_pending WHERE message_id = ?",
                    (int(interaction.message.id),),
                )
                row = c.fetchone()
        except Exception:
            row = None
        if not row:
            return await interaction.response.send_message(
                "This selection has expired. Please sign up again.",
                ephemeral=True,
            )
        user_id, guild_id, tier = int(row[0]), int(row[1]), str(row[2])
        if interaction.user.id != user_id:
            return await interaction.response.send_message("Only the signup user can choose this.", ephemeral=True)
        delay_seconds = int(self.values[0])
        _schedule_prizepool_check_with_delay(guild_id, tier, delay_seconds)
        try:
            with sqlite3.connect(TOURNAMENT_DB_FILE) as conn:
                c = conn.cursor()
                c.execute("DELETE FROM tournament_delay_pending WHERE message_id = ?", (int(interaction.message.id),))
                conn.commit()
        except Exception:
            pass
        await interaction.response.send_message(
            f"✅ Prize pool assignment scheduled in **{delay_seconds} seconds**.",
            ephemeral=True,
        )

