    @app_commands.command(name="log", description="Record a match loss and update bracket.")
    @app_commands.allowed_contexts(guilds=True, dms=False, private_channels=True)
    @app_commands.user_install()
    @app_commands.guild_install()
    async def tourn_log(self, interaction: discord.Interaction, loser: discord.User,  winner: discord.User = None, tournament: str = None):
        loser_name = f'<@{loser.id}>'
        tourn_name, resolve_err = _resolve_tournament_name_for_log(interaction.guild, tournament)
        if resolve_err:
            await interaction.response.send_message(resolve_err, ephemeral=True)
            return
        file_path = os.path.join('register', f'{interaction.guild.name}_{tourn_name}.txt')
        try:
            participants = []
            if os.path.exists(file_path):
                with open(file_path, 'r', encoding='utf-8') as file:
                    participants = [line.strip().split('(')[0] for line in file.readlines()]

            index = None
            for i, p in enumerate(participants):
                if p == loser_name:
                    index = i
                    break

            # If the registration file does not exist or the loser was not found,
            # continue anyway; logging should still work for instant tournaments.
        except Exception as e:
            print(e)

        # Default winner to the user who invoked the command if not provided
        winner = winner or interaction.user

        # Setup buttons
        confirm_button = Button(label="Confirm", style=discord.ButtonStyle.green)
        decline_button = Button(label="Decline", style=discord.ButtonStyle.red)
        force_log_button = Button(label="Force Log", style=discord.ButtonStyle.blurple)

        view = View(timeout=180)
        view.add_item(confirm_button)
        view.add_item(decline_button)
        view.add_item(force_log_button)

        async def confirm_button_callback(button_interaction: discord.Interaction):
            if button_interaction.user != loser:
                await button_interaction.response.send_message("Only the mentioned loser can confirm this action.", ephemeral=True)
                return

            confirm_button.disabled = True
            decline_button.disabled = True
            await button_interaction.response.edit_message(content="Confirmed. Updating records...", view=view)
            ok, msg, safe_tourn_name, meta = _apply_tournament_log_loss(button_interaction.guild, loser.id, loser.name, tourn_name)
            if not ok:
                return await interaction.followup.send(msg)
            await interaction.followup.send(f"{loser.mention} has confirmed their defeat. {msg}")
            try:
                await _maybe_send_tournament_round_actions(button_interaction, safe_tourn_name, tourn_name, meta)
            except Exception:
                traceback.print_exc()

        async def decline_button_callback(button_interaction: discord.Interaction):
            if button_interaction.user != loser:
                await button_interaction.response.send_message("Only the loser can decline.", ephemeral=True)
                return
            confirm_button.disabled = True
            decline_button.disabled = True
            await button_interaction.response.edit_message(content="Declined. No changes made.", view=view)

        async def force_log_button_callback(button_interaction: discord.Interaction):
            if not _is_tournament_manager_member(button_interaction.user, button_interaction.guild):
                await button_interaction.response.send_message("Tournament manager role required to use Force Log. Use `/tournament manager <role>` first.", ephemeral=True)
                return

            confirm_button.disabled = True
            decline_button.disabled = True
            await button_interaction.response.edit_message(content="Force Log. Updating records...", view=view)

            ok, msg, safe_tourn_name, meta = _apply_tournament_log_loss(button_interaction.guild, loser.id, loser.name, tourn_name)
            if not ok:
                return await interaction.followup.send(msg)
            await interaction.followup.send(f"**{button_interaction.user.mention}** has forced the log of defeat for {loser.mention}. {msg}")
            try:
                await _maybe_send_tournament_round_actions(button_interaction, safe_tourn_name, tourn_name, meta)
            except Exception:
                traceback.print_exc()

        # Set callbacks
        confirm_button.callback = confirm_button_callback
        decline_button.callback = decline_button_callback
        force_log_button.callback = force_log_button_callback

        await interaction.response.send_message(
            f"{loser.mention}, do you confirm your defeat in **{tourn_name}**?",
            view=view
        )

    @app_commands.command(name="disqualify", description="Disqualify a person from a tournament by user name")
    @app_commands.allowed_contexts(guilds=True, dms=False, private_channels=True)
    @app_commands.user_install()
    @app_commands.guild_install()
    async def disqualify(self, interaction: discord.Interaction, loser_name: str, tournament: str = None):
        if not interaction.user.guild_permissions.manage_roles:
                await interaction.response.send_message("You must have 'Manage Roles' permission to use this button.", ephemeral=True)
                return
        await interaction.response.defer()
        server = interaction.guild.name
        tourn_name = tournament or 'default tournament'
        file_path = os.path.join('register', f'{server}_{tourn_name}.txt')
        if not os.path.exists(file_path):
            await interaction.response.send_message("Registration file not found for this tournament.", ephemeral=True)
            return

        with open(file_path, 'r') as file:
            participants = [line.strip().split('(')[0] for line in file.readlines()]

        index = None
        for i, p in enumerate(participants):
            if p == loser_name:
                index = i
                break
        try:
            with open(file_path, 'r') as f:
                lines = f.readlines()
                lines.pop(index)
            with open(file_path, 'w') as f:
                f.writelines(lines)
        except Exception as e:
            print(e)

        name = f"{server}_{tourn_name}"
        safe_tourn_name = re.sub(r'[^a-zA-Z0-9_]', '_', name).replace(" ", "_").lower()
        ok, msg, _ = _record_local_tournament_loss(safe_tourn_name, loser_name)
        if ok:
            await interaction.followup.send(f"**{interaction.user.mention}** disqualified {loser_name}. {msg}")
        else:
            await interaction.followup.send(f"**{interaction.user.mention}** disqualified {loser_name}. Register updated ({msg}).")

    @app_commands.command(name="clear_match", description="Clear results for a specific match and re-open it.")
    @app_commands.describe(
        round_id="The round format (e.g., W1, L2)",
        p1_name="Display name of player 1",
        p2_name="Display name of player 2",
        tournament_name="The name of the tournament"
    )
    async def clear_match(
        self, 
        interaction: discord.Interaction, 
        round_id: str, 
        p1_name: str, 
        p2_name: str, 
        tournament_name: str = "default tournament"
    ):
        # 1. Permission Guard
        if not _is_tournament_manager_member(interaction.user, interaction.guild):
            return await interaction.response.send_message("Manager role required.", ephemeral=True)

        bracket = round_id[0].upper()
        round_num = int(round_id[1:])
        
        conn = _tournament_db_connect()
        try:
            c = conn.cursor()
            # Find Tournament ID
            c.execute("SELECT id FROM tournaments WHERE tournament_name = ? AND status = 'ongoing' LIMIT 1", (tournament_name,))
            t_row = c.fetchone()
            if not t_row:
                return await interaction.response.send_message("Tournament not found.", ephemeral=True)
            
            tournament_id = t_row["id"]

            # 2. Locate the Match
            # We look for the match involving both participants in the specified round
            c.execute("""
                SELECT m.* FROM tournament_matches m
                JOIN tournament_participants p1 ON m.player1_participant_id = p1.id
                JOIN tournament_participants p2 ON m.player2_participant_id = p2.id
                WHERE m.tournament_id = ? AND m.bracket = ? AND m.round_id = ?
                AND (p1.display_name = ? OR p1.display_name = ?)
                AND (p2.display_name = ? OR p2.display_name = ?)
            """, (tournament_id, bracket, round_num, p1_name, p2_name, p1_name, p2_name))
            
            match = c.fetchone()
            if not match:
                return await interaction.response.send_message("Match not found.", ephemeral=True)

            # 3. Clear the Match Results
            c.execute("""
                UPDATE tournament_matches 
                SET winner_participant_id = NULL, 
                    loser_participant_id = NULL, 
                    scores_csv = NULL, 
                    state = 'open',
                    updated_at = ?
                WHERE id = ?
            """, (datetime.now(timezone.utc).isoformat(), match["id"]))

            conn.commit()

            # 4. Refresh Tournament State
            _refresh_tournament_round_and_status(conn, tournament_id)
            
            await interaction.response.send_message(f"✅ Match **{round_id}** has been cleared and set to 'open'.")

        except Exception as e:
            await interaction.response.send_message(f"Error: {e}", ephemeral=True)
        finally:
            conn.close()
    

    @app_commands.command(name="clear_round", description="Clear all results for an entire round and reopen all its matches.")
    @app_commands.describe(
        round_id="The round format to clear (e.g., W1, W2, L1, L2)",
        tournament_name="The name of the tournament"
    )
    async def clear_round(
        self, 
        interaction: discord.Interaction, 
        round_id: str, 
        tournament_name: str = "default tournament"
    ):
        # 1. Permission Guard
        if not _is_tournament_manager_member(interaction.user, interaction.guild):
            return await interaction.response.send_message(
                "You do not have the required tournament manager role to use this command.", 
                ephemeral=True
            )

        # 2. Parse Round String (e.g., 'L2' -> bracket='L', round_num=2)
        try:
            bracket = round_id[0].upper()
            round_num = int(round_id[1:])
            if bracket not in ('W', 'L'):
                raise ValueError()
        except Exception:
            return await interaction.response.send_message(
                "Invalid round format. Please use identifiers like 'W1' (winner round 1), 'L3' (loser round 3), etc.", 
                ephemeral=True
            )

        conn = _tournament_db_connect()
        try:
            c = conn.cursor()
            
            # 3. Locate the Active Tournament
            guild_name = interaction.guild.name if interaction.guild else "Unknown Server"
            target_slug = _tournament_slug(guild_name, tournament_name)
            
            c.execute(
                "SELECT id FROM tournaments WHERE slug = ? AND status = 'ongoing' ORDER BY id DESC LIMIT 1", 
                (target_slug,)
            )
            t_row = c.fetchone()
            
            # Fallback scan if slug matching fails (matches original pattern)
            if not t_row:
                c.execute("SELECT id FROM tournaments WHERE status = 'ongoing' ORDER BY id DESC LIMIT 1")
                t_row = c.fetchone()

            if not t_row:
                return await interaction.response.send_message(
                    f"Could not locate an ongoing tournament named `{tournament_name}`.", 
                    ephemeral=True
                )
            
            tournament_id = t_row["id"]

            # 4. Check if any matches exist for this round
            c.execute(
                """
                SELECT COUNT(*) as total FROM tournament_matches 
                WHERE tournament_id = ? AND bracket = ? AND round_id = ?
                """, 
                (tournament_id, bracket, round_num)
            )
            count_row = c.fetchone()
            if not count_row or count_row["total"] == 0:
                return await interaction.response.send_message(
                    f"No match records found for round **{round_id}** in this tournament.", 
                    ephemeral=True
                )

            # 5. Reset all match entries inside this round back to 'open'
            now_iso = datetime.now(timezone.utc).isoformat()
            c.execute(
                """
                UPDATE tournament_matches
                SET winner_participant_id = NULL, 
                    loser_participant_id = NULL, 
                    scores_csv = NULL, 
                    state = 'open', 
                    updated_at = ?
                WHERE tournament_id = ? AND bracket = ? AND round_id = ?
                """,
                (now_iso, tournament_id, bracket, round_num)
            )

            conn.commit()

            # 6. Re-evaluate System Sweeps and round updates
            # This triggers the standard workflow to roll back downstream progressions
            _refresh_tournament_round_and_status(conn, tournament_id)
            
            try:
                _auto_progress_byes(conn, tournament_id)
            except Exception:
                pass

            await interaction.response.send_message(
                f"✅ All matches in round **{round_id}** have been cleared and reopened successfully!"
            )

        except Exception as e:
            conn.rollback()
            await interaction.response.send_message(
                f"An error occurred while updating the database: {str(e)}", 
                ephemeral=True
            )
        finally:
            conn.close()
    @app_commands.command(name="tournament_list", description="List all posted tournaments")
    @app_commands.allowed_contexts(guilds=True, dms=False, private_channels=True)
    @app_commands.guild_install()
    async def tournament_list(self, interaction: discord.Interaction):
        # Define the folder path where tournaments are stored
        folder_path = 'tournaments'
        
        # Check if the folder exists
        if not os.path.exists(folder_path):
            await interaction.response.send_message("No tournaments have been posted yet.")
            return

        # List all files in the 'war' folder
        tournament_files = [f for f in os.listdir(folder_path) if f.endswith('.txt')]

        if not tournament_files:
            await interaction.response.send_message("No tournaments have been posted yet.")
            return

        # Number of tournaments per page
        tournaments_per_page = 5
        pages = []

        # Split the tournament files into pages
        for i in range(0, len(tournament_files), tournaments_per_page):
            page = tournament_files[i:i+tournaments_per_page]
            pages.append(page)

        # Function to generate an embed for a specific page
        def create_embed(page_number):
            page = pages[page_number]
            embed = discord.Embed(title="Posted Tournaments", color=discord.Color.green())
            
            # Loop through each file in the current page and add the details to the embed
            for file_name in page:
                file_path = os.path.join(folder_path, file_name)

                # Read the tournament details from the file
                with open(file_path, 'r') as file:
                    war_details = file.readlines()

                # Extract the details
                server_name = war_details[0].strip()
                war_name = war_details[1].strip()
                format = war_details[2].strip()
                prize = war_details[3].strip()
                start_date = war_details[5].strip()
                invite_link = war_details[4].strip()

                # Add each tournament as a field in the embed
                embed.add_field(
                    name=f"Tournament name: {war_name}",
                    value=f"**Format:** {format}\n**Server:** {server_name}\n**Prize:** {prize}\n**Start Date:** {start_date}\n**Invite Link: **{invite_link}",
                    inline=False
                )
            
            # Add pagination information to the embed
            embed.set_footer(text=f"Page {page_number + 1} of {len(pages)}")
            return embed

        # Create the first page embed
        current_page = 0
        embed = create_embed(current_page)

        # Send the initial embed
        message = await interaction.channel.send(embed=embed)

        # Add reaction emojis for pagination
        if len(pages) > 1:
            await message.add_reaction("⬅️")
            await message.add_reaction("➡️")

            # Define the reaction event listener to handle page navigation
            def check(reaction, user):
                return user != bot.user and reaction.message.id == message.id and str(reaction.emoji) in ["⬅️", "➡️"]

            while True:
                # Wait for a reaction
                reaction, user = await bot.wait_for("reaction_add", check=check)
            
                # Remove the user's reaction so they can use it again
                await message.remove_reaction(reaction, user)

                if str(reaction.emoji) == "➡️" and current_page < len(pages) - 1:
                # Move to the next page
                    current_page += 1
                    embed = create_embed(current_page)
                    await message.edit(embed=embed)
            
                elif str(reaction.emoji) == "⬅️" and current_page > 0:
                    # Move to the previous page
                    current_page -= 1
                    embed = create_embed(current_page)
                    await message.edit(embed=embed)
