class TournamentBracketView(View):
    def __init__(self, server, tourn_name, participants, matches, double=False):
        super().__init__(timeout=600)
        self.server = server
        self.tourn_name = tourn_name
        self.participants = participants
        self.matches = matches
        self.double = double
        self.current_round = None
        self.message = None

        # Determine available rounds
        all_rounds = set(m["round"] for m in matches)
        self.available_rounds = sorted(all_rounds)
        if not self.available_rounds:
            self.current_round = 1
        else:
            open_rounds = [m["round"] for m in matches if str(m.get("state", "")).lower() == "open" and not m.get("winner_id")]
            self.current_round = min(open_rounds) if open_rounds else max(self.available_rounds)

        # Add buttons
        self.prev_button = discord.ui.Button(label="Previous Round", style=discord.ButtonStyle.secondary, disabled=self.current_round <= min(self.available_rounds))
        self.next_button = discord.ui.Button(label="Next Round", style=discord.ButtonStyle.primary, disabled=self.current_round >= max(self.available_rounds))
        self.add_item(self.prev_button)
        self.add_item(self.next_button)

    async def update_bracket(self, interaction: discord.Interaction):
        image = draw_bracket2(self.participants, self.matches, self.double, self.current_round)
        file = discord.File(image, "bracket.png")
        embed = discord.Embed(title=f"{self.tourn_name} - Round {self.current_round} {'(Losers)' if self.double else '(Winners)'}", color=discord.Color.blue() if not self.double else discord.Color.red())
        
        # Update button states
        self.prev_button.disabled = self.current_round <= min(self.available_rounds)
        self.next_button.disabled = self.current_round >= max(self.available_rounds)
        
        await interaction.response.edit_message(embed=embed, attachments=[file], view=self)

    @discord.ui.button(label="Previous Round", style=discord.ButtonStyle.secondary)
    async def prev_round(self, interaction: discord.Interaction, button: discord.Button):
        if self.current_round > min(self.available_rounds):
            self.current_round -= 1
            await self.update_bracket(interaction)

    @discord.ui.button(label="Next Round", style=discord.ButtonStyle.primary)
    async def next_round(self, interaction: discord.Interaction, button: discord.Button):
        if self.current_round < max(self.available_rounds):
            self.current_round += 1
            await self.update_bracket(interaction)

