@bot.tree.command(name="purge", description="purge x number of messages")
@app_commands.allowed_contexts(guilds=True, dms=False, private_channels=True)
@app_commands.guild_install()
async def quick_purge(
    interaction: discord.Interaction,
    amount: int = 100,
):
    if not interaction.channel.permissions_for(interaction.user).manage_messages:
        if not interaction.user.guild_permissions.manage_messages:
            return await interaction.response.send_message("❌ You don't have permission to use this.", ephemeral=True)

    await interaction.response.defer(thinking=True)

    messages = []
    async for msg in interaction.channel.history(limit=amount):
        if not msg.pinned:
            messages.append(msg)

    # Check for messages older than 14 days
    too_old = [
        msg for msg in messages
        if (discord.utils.utcnow() - msg.created_at).days >= 14
    ]

    if too_old:
        return await interaction.channel.send(
            f"⚠️ Stopped: Found {len(too_old)} messages older than 14 days. "
            "Please use /purge",
            delete_after=5
        )

    def check(msg):
        if msg.pinned:
            return False
        return True

    deleted = await interaction.channel.purge(limit=amount, check=check)
    await interaction.channel.send(f"🧹 Deleted {len(deleted)} messages (excluding pinned).", delete_after=5)
    await asyncio.sleep(1)

class QuizTimer():
    def __init__(self, number):
        self.count = 0 
        self.number = number
    def next(self):
        self.count += 1
        return self
    def end(self):
        return self.count == self.number
