class QuizModal(Modal):
    def __init__(self, title, move, folder_name, Qtype):
        super().__init__(title=title)
        self.move = move
        self.folder_name = folder_name
        self.type = Qtype
        if self.type == 1:
            self.pokemon = TextInput(label="Pokemon Name", placeholder="Name of the Pokemon")
            self.add_item(self.pokemon)
        elif self.type == 2:
            self.speed = TextInput(label="Speed", placeholder="speed")
            self.add_item(self.speed)
        elif self.type == 3:
            self.eg = TextInput(label="Egg group", placeholder="no eggs, water1, dragon, etc")
            self.add_item(self.eg)
        elif self.type == 4:
            self.name = TextInput(label="Pokemon Name", placeholder="Name of Pokemon")
            self.add_item(self.name)
        elif self.type == 5:
            self.move_name = TextInput(label="Move Name", placeholder="Name of a move")
            self.add_item(self.move_name)
    async def on_submit(self, interaction: discord.Interaction):
        user_id = interaction.user.id
        value = 0
        if self.type == 1:
            value = does_pokemon_learn_move_by_level(str(self.pokemon).lower(), self.move)
        elif self.type ==2:
            value = 1 if int(str(self.speed)) == int(self.move) else 0
        elif self.type ==3:
            if str(self.eg).lower() == 'field':
                self.eg == 'ground'
            elif str(self.eg).lower() == 'amorphous':
                self.eg == 'indetermine'
            value = 1 if str(self.eg).lower() in self.move else 0
            value = 1 if str(self.eg).capitalize() in self.move else 0
        elif self.type == 4:
            stats, types = get_pokemon_stats(str(self.name).lower())
            if types[0] == self.move[0] or types[0] == self.move[1]:
                if types[1] == self.move[0] or types[1] == self.move[1]:
                    value = 1
        elif self.type == 5:
            _, _, types = get_move_info(str(self.move_name).lower())
            if types:
                effectiveness = get_effectiveness(types, self.move)
                if effectiveness > 1:
                    value = 1
        if value == 1:
            file_path = os.path.join(self.folder_name, f'{user_id}.txt')
            if os.path.exists(file_path):
                with open(file_path, 'r') as file:
                    lines = file.readlines()
                lines = int(lines[0].strip()) + 1
                line = str(lines)
                with open(file_path, 'w') as file:
                    file.write(line)
            else:
                with open(file_path, 'w') as file:
                    file.write(str(1))
            await interaction.response.send_message('Correct', ephemeral = True)
        else:
            await interaction.response.send_message('Incorrect', ephemeral = True)
class Quiz():
    def __init__(self, folder_name, timer):
        self.folder_name = folder_name
        self.timer = timer
        self.deferred = False
    async def question(self, interaction: discord.Interaction):
        if not self.deferred:
            await interaction.response.defer()
            self.deferred = True
        possibility = list(range(1, 100))
        chosen = random.choice(possibility)
        if chosen < 21:
            number = list(range(1, 623))
            index = random.choice(number)
            move = get_move_name(index)
            embed = discord.Embed(title=f'Which Pokemon learns {move} while leveling up?', description='Click on the button to answer\nRemember Primal Kyogre is kyogre-primal', color = discord.Color.green())
            view = QuizView(move, self.folder_name, 1)
            await interaction.followup.send(embed=embed, view=view)
        elif 20 < chosen < 41:
            print('spd')
            number = list(range(1, 1025))
            index = random.choice(number)
            pokemon_name = get_pokemon_name(index)
            stats, types = get_pokemon_stats(pokemon_name)
            embed = discord.Embed(title=f'What is the base speed of {pokemon_name}?', description='Click on the button to answer', color = discord.Color.green())
            view = QuizView(stats[5], self.folder_name, 2)
            await interaction.followup.send(embed=embed, view=view)
        elif 40 < chosen < 61:
            print('egg')
            number = list(range(1, 1025))
            index = random.choice(number)
            pokemon_name = get_pokemon_name(index)
            stats, types = get_pokemon_stats(pokemon_name)
            eg = get_pokemon_egg_groups(pokemon_name)
            embed = discord.Embed(title=f'What is the egg group of {pokemon_name}?', description='Click on the button to answer\nIf None, then write "no eggs"', color = discord.Color.green())
            view = QuizView(eg, self.folder_name, 3)
            await interaction.followup.send(embed=embed, view=view)
        elif 60 < chosen < 81:
            print('name')
            types = []
            type1 = random.choice(GYM_TYPES)
            type2 = random.choice(GYM_TYPES)
            while type1 == type2:
                type2 = random.choice(GYM_TYPES)
            types.append(type1)
            types.append(type2)
            embed = discord.Embed(title=f'Write the name of 1 Pokemon with the following types', description=f'**{types}**', color = discord.Color.green())
            view = QuizView(types, self.folder_name, 4)
            await interaction.followup.send(embed=embed, view=view)
        elif 80 < chosen < 101:
            print('effective')
            number = list(range(1, 1025))
            index = random.choice(number)
            pokemon_name = get_pokemon_name(index)
            stats, types = get_pokemon_stats(pokemon_name)
            embed = discord.Embed(title=f'Write 1 move that is super effective (x2) to the following types', description=f'**{types}**', color = discord.Color.green())
            view = QuizView(types, self.folder_name, 5)
            await interaction.followup.send(embed=embed, view=view)
        else:
            print('moves')
            number = list(range(1, 623))
            index = random.choice(number)
            move = get_move_name(index)
            embed = discord.Embed(title=f'Which Pokemon learns {move} while leveling up?', description='Click on the button to answer', color = discord.Color.green())
            view = QuizView(move.lower(), self.folder_name, 1)
            await interaction.followup.send(embed=embed, view=view)
        await asyncio.sleep(12)
        await self.leaderboard(interaction)
    async def leaderboard(self, interaction: discord.Interaction):
        players = []
        scores = []
        for filename in os.listdir(self.folder_name):
            file_path = os.path.join(self.folder_name, filename)
            if os.path.isfile(file_path):
                players.append(os.path.splitext(filename)[0])
                with open(file_path, 'r') as file:
                    content = file.read()
                    scores.append(content.strip())
        text = ''
        for i in range(0, len(players)):
            text += f'<@{players[i]}>: {scores[i]}\n'
        embed = discord.Embed(title='Leaderboard', description = f'{text}', color = discord.Color.green())
        self.timer.next()
        if self.timer.end():
            shutil.rmtree(self.folder_name)
            embed.add_field(name='Quiz has ended', value='')
        await interaction.followup.send(embed=embed)
        if self.timer.end():
            return
        else:
            await asyncio.sleep(3)
            await self.question(interaction)
    
