@commands.has_permissions(administrator=True)
async def setprefix(ctx, new_prefix: str):
    """Allows an admin to change the bot's prefix for the server."""
    global prefixes
    guild_id = str(ctx.guild.id)  # Convert server ID to string for JSON storage
    # Load existing prefixes
    try:
        with open(PREFIX_FILE, "r") as f:
            prefixes = json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        prefixes = {}  # Create a new dictionary if the file is missing or corrupted
    # Update prefix for this server
    prefixes[guild_id] = new_prefix
    # Save back to the file
    with open(PREFIX_FILE, "w") as f:
        json.dump(prefixes, f, indent=4)
    await ctx.send(f"✅ Prefix changed to `{new_prefix}` for this server.")
