def load_tank_data():
    """Load tank data from tanks.txt with Pokémon, tank names, and multiple stat lines."""
    data = {}
    current_pokemon = None
    current_tank = None

    with open("tanks.txt", "r") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue

            # Pokémon name (doesn't start with digit)
            if not line[0].isdigit():
                current_pokemon = line.lower()
                data[current_pokemon] = []
                current_tank = None
                continue

            # Tank name line (starts with digit + dot)
            if line[0].isdigit() and "." in line:
                parts = line.split(".", 1)
                tank_name = parts[1].strip()
                current_tank = {"name": tank_name, "stats": []}
                data[current_pokemon].append(current_tank)
                continue

            # Stat line: expect three integers
            if current_tank:
                try:
                    hp, deff, spdef = map(int, line.split())
                    current_tank["stats"].append({
                        "hpiv": hp,
                        "defiv": deff,
                        "spdefiv": spdef
                    })
                except ValueError:
                    # Skip lines that are not numbers
                    continue

    return data


# ---------------- Slash Command ----------------
@bot.tree.command(
    name="tank",
    description="Check if a Pokémon tanks based on IVs."
)
@app_commands.describe(
    pokemon="Name of the Pokémon (e.g., Rayquaza)",
    hpiv="Your Pokémon's HP IV (0-31)",
    defiv="Your Pokémon's DEF IV (0-31)",
    spdefiv="Your Pokémon's SPDEF IV (0-31)"
)
async def tank(interaction: discord.Interaction, pokemon: str, hpiv: int, defiv: int, spdefiv: int):
    tanks_data = load_tank_data()
    pokemon_key = pokemon.lower()

    if pokemon_key not in tanks_data:
        await interaction.response.send_message(f"❌ No tank data found for **{pokemon}**.\nPlease use iv analysis for full analysis, come to support server if you need any help (/bot_info)", ephemeral=False)
        return

    results = []

    for tank in tanks_data[pokemon_key]:
        tank_name = tank["name"]
        matched = False

        for stat in tank["stats"]:
            # 0 in file = stat doesn’t matter, otherwise input must be >= file
            hp_match = (stat["hpiv"] == 0 or hpiv >= stat["hpiv"])
            def_match = (stat["defiv"] == 0 or defiv >= stat["defiv"])
            spdef_match = (stat["spdefiv"] == 0 or spdefiv >= stat["spdefiv"])

            if hp_match and def_match and spdef_match:
                matched = True
                break  # matched one stat set, no need to check others

        if matched:
            results.append(f"✅ Tanks {tank_name}")
        else:
            results.append(f"❌ Doesn't Tank {tank_name}")

    msg = (
        f"**Tank Check: {pokemon.title()}**\n"
        f"HP IV: {hpiv} | DEF IV: {defiv} | SPDEF IV: {spdefiv}\n\n"
        + "\n".join(results)
    )

    msg += "\nGoldi AI can make mistakes like tags. Please check /dmg_calc_pokemon if unsure."

    await interaction.response.send_message(msg, ephemeral=False)




