def log_channel(server):
    folder_name = 'log_channel'
    file_path = os.path.join(folder_name, f'{server}.txt')
    if os.path.exists(file_path):
        with open(file_path, 'r') as file:
            lines = file.readlines()
            log_channel = lines[0].strip()
        return log_channel
    else:
        return None
@bot.command()
@commands.has_permissions(administrator=True)
async def gamble_log(ctx, channel: discord.TextChannel = None):
    """Set log channel for gamble log. !gamble_log #channel"""
    server = ctx.guild.id
    if channel:
        folder_name = 'log_channel'
        os.makedirs(folder_name, exist_ok=True)
        file_path = os.path.join(folder_name, f'{server}.txt')
        with open(file_path, 'w') as file:
            file.write(f'{channel.id}')
        await ctx.send(f'✅ Successfully updated log channel to {channel.mention}')
    else:
        folder_name = 'log_channel'
        os.makedirs(folder_name, exist_ok=True)
        file_path = os.path.join(folder_name, f'{server}.txt')
        os.remove(file_path)
        await ctx.send(f'Removed gamble log.\nIf this is unintended, add a #channel after !gamble_log')
