LOG_FOLDER = "log_channel"
os.makedirs(LOG_FOLDER, exist_ok=True)

# Function to get the file path based on guild ID
def get_file_path(guild_id):
    return os.path.join(LOG_FOLDER, f"{guild_id}.json")

# Function to load JSON data (or create file if missing)
def load_data(guild_id):
    try:
        file_path = get_file_path(guild_id)
        with open(file_path, "r") as file:
            return json.load(file)
    except FileNotFoundError:
        return None

# Function to save data to a specific slot
def save_data(ctx, slot, new_data, guild_id=None):
    """Saves data to a specific slot or the whole file.
    If ctx is provided, the guild ID is auto-detected.
    """
    file_path = get_file_path(guild_id)
    if not os.path.exists(file_path):  # Create file if missing
        default_data = {
        "gym_log": None,  # Only store the channel ID for gym log
        "battle_log": None,  # Only store the channel ID for battle log
        "tournament_log": None,  # Only store the channel ID for tournament log
        "war_log": None,
        "war_update": None,  # Store the channel ID for war updates
        }
        with open(file_path, "w") as file:
            json.dump(default_data, file, indent=4)
    data = load_data(guild_id)  # Load existing data

    if slot:
        data[slot] = new_data
    else:  # If no slot is specified, overwrite the entire file
        return

    with open(file_path, "w") as file:
        json.dump(data, file, indent=4)

