class LogButtonView(discord.ui.View):
    def __init__(self, server_id, embed, message_link, channel, gym_win = False, winner = None):
        super().__init__()
        self.clicked = False  # Track if any button is clicked
        self.server_id = server_id
        self.message_link = message_link
        self.embed = embed
        self.channel = channel
        self.gym_win = gym_win
        self.winner = winner

    async def disable_all_buttons(self, interaction: discord.Interaction):
        """Disables all buttons after one is clicked."""
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True  # Disable each button

        await interaction.message.edit(view=self)  # Update the message with disabled buttons

    @discord.ui.button(label="Gym Log", style=discord.ButtonStyle.primary)
    async def gym_log(self, interaction: discord.Interaction, button: discord.ui.Button):
        data = load_data(self.server_id)
        if not data:
            await interaction.response.send_message("No gym log channel found, use `!gym_log #channel` to set up", ephemeral=True)
            return
        channel_id = data.get('gym_log')
        if channel_id:
            modified_embed = discord.Embed(title=self.embed.title, color=self.embed.color)
            gender_emojis = {
                "<:unknown:1207995667788726272>": "<:unknown:1355886105526009990>",
                "<:male:1207734081585152101>": "<:male:1354783083697537075>",
                "<:female:1207734084210532483>": "<:female:1354783558031511663>",
                None: "<a:unknown:1355869316280750161>"
            }
            gmax_emoji = '<:gmax:1355891450058899547>'
            for field in self.embed.fields:
                # Split the field value into lines
                pattern = r"\*{0,2}\s*(<:\w+:\d+>)\s*(<:\w+:\d+>\s*)?L(\d+)(\s*<:\w+:\d+>)?\s*(\d+\.\d+%)\s*([\w\s'-]+?)\s*(<:\w+:\d+>)\s*(\(#\d+\))"
                modified_lines = []
                for line in field.value.splitlines():
                # Apply the regex replacement directly within the loop
                    modified_line = re.sub(pattern, lambda match: (
                    # Get Pokémon name from the match (group 4) and convert it to lowercase for the image URL lookup
                    get_pokemon_emoji(match.group(6))#'<a:pokeball:1355867135636672572>'
                    + ('✨' if match.group(2) else '')  # Optional shiny/other emoji before level
                    + f" L{match.group(3)} "
                    + (gmax_emoji if match.group(4) else '')  # Optional G-Max/other emoji after level
                    + f" {match.group(5)} {match.group(6)} "
                    + f"{gender_emojis.get(match.group(7))} "
                    + f"{match.group(8)}"
                    ), line)
                    modified_lines.append(modified_line)
                modified_value = "\n".join(modified_lines)
                modified_embed.add_field(name=field.name, value=modified_value, inline=field.inline)
            message_link = self.message_link
            target_channel = (bot.get_channel(channel_id) or await bot.fetch_channel(channel_id))
            await target_channel.send(f'<a:crown:1355889489490219026> Gym: {self.channel.name}\n{self.channel.mention}')
            await target_channel.send(embed=modified_embed)
            await interaction.response.send_message("🏋️ Gym Log button clicked!", ephemeral=True)
            await self.disable_all_buttons(interaction)
            prefix = prefixes.get(self.server_id)
            if not prefix:
                prefix = '!'
            if self.gym_win == True:
                await interaction.followup.send(f"Congratulations on successfully defending the gym! +1 win added!\nCheck {str(prefix)}pf or /profile\nCheck /gymstats for leader stats <a:crown:1355889489490219026>")
            else:
                await interaction.followup.send(f"Make sure to use `/award_badge` (no lose/win counted at this stage)!\nCheck {str(prefix)}pf or /profile\nCheck /gymstats for leader stats <a:crown:1355889489490219026>")
            if self.winner:
                conn = get_db_connection()
                cursor = conn.cursor()
                gym_leaders_table = f"gym_leaders_{interaction.guild.id}"
                # Increment the 'wins' column for the leader with the given display_name
                cursor.execute(f"""
                    UPDATE {gym_leaders_table}
                    SET wins = wins + 1
                    WHERE leader_id = ?;
                """, (self.winner.id,))
                conn.commit()
                conn.close()
        else:
            await interaction.response.send_message("No gym log channel found, use `!gym_log #channel` to set up", ephemeral=True)

