    @discord.ui.button(label="⚔️ Detailed 1v1 Analysis", style=discord.ButtonStyle.primary)
    async def detailed_1v1(self, interaction: discord.Interaction, button: discord.ui.Button):
        data = self.load_data()
        if not data:
            return await interaction.response.send_message(
                "This analysis has expired. Please run IV Analysis again.",
                ephemeral=True
            )

        summary = data["summary"]
        await interaction.response.defer()
        try:
            text_lines = []

            for entry in summary:
                missing = ", ".join(entry['missing_wins']) if entry['missing_wins'] else "None"
                never_beat = ", ".join(entry.get('missing_wins_all', [])) if entry.get('missing_wins_all') else "None"

                text_lines.append(
                    f"**{entry['pokemon']}** — Wins: `{entry['wins_current']}/{entry['wins_max']}`\n"
                    f"Missing wins: `{missing}`\n"
                    f"Current mint lose to: `{never_beat}`\n"
                )

            if not text_lines:
                text_lines.append("✅ No 1v1 differences found.")

            chunks = []
            current_chunk = ""

            for line in text_lines:
                if len(current_chunk) + len(line) + 1 > 1900:
                    chunks.append(current_chunk)
                    current_chunk = line
                else:
                    current_chunk += line + "\n"

            if current_chunk:
                chunks.append(current_chunk)

            for idx, c in enumerate(chunks, 1):
                embed = discord.Embed(
                    title=f"⚔️ Detailed 1v1 Analysis (Part {idx})",
                    description=c,
                    color=discord.Color.blue()
                )
                await interaction.followup.send(embed=embed)
            
            proc = psutil.Process(os.getpid())
            before = proc.memory_info().rss / 1024**2
            # load & process
            del data; gc.collect()
            after = proc.memory_info().rss / 1024**2
            print(f"MB before {before:.1f} after {after:.1f}")

        except Exception:
            traceback.print_exc()

