PVP_STATS_FILE = "pvp_poke_stats.json"
def load_pvp_stats():
    if not os.path.exists(PVP_STATS_FILE):
        return {}
    with open(PVP_STATS_FILE, "r") as f:
        return json.load(f)


def save_pvp_stats(data):
    with open(PVP_STATS_FILE, "w") as f:
        json.dump(data, f, indent=2)


def update_pvp_rating(poke_name: str, rating: int, user_id: int):
    data = load_pvp_stats()
    key = poke_name.lower()

    if key not in data:
        data[key] = []

    # ❌ Prevent exact duplicates (same user + same rating)
    for r, uid in data[key]:
        if r == rating and uid == user_id:
            return  # Already exists → do nothing

    # ✅ Add new record
    data[key].append([rating, user_id])
    save_pvp_stats(data)

def get_pvp_ranking(poke_name: str, rating: int, user_id: int):
    data = load_pvp_stats()
    key = poke_name.lower()

    if key not in data:
        return None, None

    # Sort descending by rating
    ranked = sorted(data[key], key=lambda x: x[0], reverse=True)

    # Find rank (1-based)
    for i, (r, uid) in enumerate(ranked, start=1):
        if r == rating and uid == user_id:
            return i, len(ranked)

    return None, len(ranked)

def remove_pvp_entry(poke_name: str, user_id: int):
    data = load_pvp_stats()
    key = poke_name.lower()

    if key not in data:
        return False

    before = len(data[key])
    data[key] = [entry for entry in data[key] if entry[1] != user_id]

    if not data[key]:
        del data[key]

    save_pvp_stats(data)
    return before != len(data.get(key, []))

@bot.tree.command(name="statistics", description="View PvP rating statistics for a Pokémon")
@app_commands.describe(pokemon="Pokemon name (e.g. Pikachu)")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def pokemon_stats(interaction: discord.Interaction, pokemon: str):
    data = load_pvp_stats()
    key = pokemon.lower()

    if key not in data or not data[key]:
        await interaction.response.send_message(
            f"❌ No PvP data found for **{pokemon.title()}**.",
            ephemeral=True
        )
        return

    ratings = [entry[0] for entry in data[key]]
    total = len(ratings)
    max_rating = max(ratings)

    within_5 = sum(1 for r in ratings if max_rating - r <= 5)
    within_10 = sum(1 for r in ratings if max_rating - r <= 10)
    within_20 = sum(1 for r in ratings if max_rating - r <= 20)
    within_40 = sum(1 for r in ratings if max_rating - r <= 40)

    count_max = ratings.count(max_rating)

    embed = discord.Embed(
        title=f"📊 PvP Stats — {pokemon.title()}",
        color=discord.Color.gold()
    )

    embed.add_field(name="🏆 Max Rating", value=str(max_rating), inline=True)
    embed.add_field(name="🥇 With Max Rating", value=str(count_max), inline=True)
    #embed.add_field(name="📈 Total Analyzed", value=str(total), inline=True)

    embed.add_field(name="Within 5 of Max", value=str(within_5), inline=True)
    embed.add_field(name="Within 10 of Max", value=str(within_10), inline=True)
    embed.add_field(name="Within 20 of Max", value=str(within_20), inline=True)
    embed.add_field(name="Within 40 of Max", value=str(within_40), inline=True)

    embed.set_footer(text="Based on recorded PvP ratings")

    await interaction.response.send_message(embed=embed)
