from PIL import ImageFilter

ALLOWED_ROLES = {1333822043103428729, 1333642489487167568}

class UnifiedCompressionModal(Modal):
    def __init__(self, attachment: discord.Attachment):
        super().__init__(title="Compression & Sharpen Settings")
        self.attachment = attachment

        # Field 1: Resample
        self.method_input = TextInput(
            label="Resample Method (lanczos / nearest)", 
            default="lanczos", 
            required=True
        )
        # Field 2: Mode Choice
        self.sharpen_mode_input = TextInput(
            label="Sharpen Mode (none / auto / manual)", 
            default="none", 
            placeholder="If 'manual', fill out the field below.",
            required=True
        )
        # Field 3: Manual Values Override
        self.sharpen_params_input = TextInput(
            label="Manual Sharpening: Radius, Percent, Threshold",
            default="1.5, 50, 4",
            placeholder="Only used if mode is 'manual'",
            required=False
        )
        # Field 4: Size constraints
        self.width_input = TextInput(
            label="Target Width (Leave blank to auto-scale)", 
            required=False
        )
        # Field 5: Size constraints (Total: 5 items)
        self.height_input = TextInput(
            label="Target Height (Leave blank to auto-scale)", 
            required=False
        )

        self.add_item(self.method_input)
        self.add_item(self.sharpen_mode_input)
        self.add_item(self.sharpen_params_input)
        self.add_item(self.width_input)
        self.add_item(self.height_input)

    async def on_submit(self, interaction: discord.Interaction):
        # Acknowledge the single interaction immediately
        await interaction.response.defer(ephemeral=False)

        # 1. Parse core configurations
        method = self.method_input.value.strip().lower()
        sharpen_mode = self.sharpen_mode_input.value.strip().lower()
        w_val = self.width_input.value.strip()
        h_val = self.height_input.value.strip()

        # 2. Parse sharpening values if manual mode is picked
        sharpen_params = None
        if sharpen_mode == "manual":
            try:
                # Splits comma-separated values safely
                raw_params = [p.strip() for p in self.sharpen_params_input.value.split(",")]
                radius = float(raw_params[0])
                percent = int(raw_params[1])
                threshold = int(raw_params[2])
                sharpen_params = (radius, percent, threshold)
            except (ValueError, IndexError):
                return await interaction.followup.send(
                    "❌ Invalid manual sharpening parameters format. Please use format: `radius, percent, threshold` (e.g., `1.5, 50, 4`).", 
                    ephemeral=True
                )

        target_width = int(w_val) if w_val.isdigit() else None
        target_height = int(h_val) if h_val.isdigit() else None

        # 3. Size Calculations
        img_bytes = await self.attachment.read()
        with Image.open(io.BytesIO(img_bytes)) as img:
            orig_width, orig_height = img.size

        if target_width and target_height:
            new_width, new_height = target_width, target_height
        elif target_width:
            new_width = target_width
            new_height = int(orig_height * target_width / orig_width)
        elif target_height:
            new_height = target_height
            new_width = int(orig_width * target_height / orig_height)
        else:
            DEFAULT_TARGET = 140
            if orig_width < orig_height:
                new_width = DEFAULT_TARGET
                new_height = int(orig_height * DEFAULT_TARGET / orig_width)
            else:
                new_height = DEFAULT_TARGET
                new_width = int(orig_width * DEFAULT_TARGET / orig_height)

        # 4. Process and dispatch payload
        await process_and_send_image(
            interaction, self.attachment, method, new_width, new_height, sharpen_mode, sharpen_params
        )


# --- CORE IMAGE PROCESSING ENGINE ---
async def process_and_send_image(interaction, attachment, method, new_width, new_height, sharpen_mode, sharpen_params=None):
    try:
        img_bytes = await attachment.read()
        img = Image.open(io.BytesIO(img_bytes)).convert("RGBA")

        resample = Image.Resampling.NEAREST if method == "nearest" else Image.Resampling.LANCZOS

        # Progressive scale down loop
        while img.width // 2 > new_width:
            img = img.resize((img.width // 2, img.height // 2), Image.Resampling.LANCZOS)

        img = img.resize((new_width, new_height), resample)

        # Conditional sharpening rules
        if sharpen_mode == "auto":
            img = img.filter(ImageFilter.UnsharpMask(radius=1.5, percent=50, threshold=4))
        elif sharpen_mode == "manual" and sharpen_params:
            radius, percent, threshold = sharpen_params
            img = img.filter(ImageFilter.UnsharpMask(radius=radius, percent=percent, threshold=threshold))

        buffer = io.BytesIO()
        img.save(buffer, format="PNG", optimize=True, compress_level=0)
        buffer.seek(0)

        img.close()

        file = discord.File(buffer, filename="compressed.png")
        await interaction.followup.send(
            content=f"✅ Processed! Method: `{method}` | Sharpen Mode: `{sharpen_mode}` | Size: `{new_width}x{new_height}`", 
            file=file
        )
        buffer.close()
        gc.collect()

    except Exception as e:
        await interaction.followup.send(f"❌ Error processing image: {e}", ephemeral=True)


