import io
import asyncio
import discord
from discord.ext import commands
from PIL import Image, ImageFilter

ALLOWED_ROLES = {1333822043103428729, 1333642489487167568}

# Advanced thread worker: resizes in linear light space per channel to preserve color, sharpness, and contrast
def run_linear_compress_pipeline(img_bytes, target_w, target_h):
    with Image.open(io.BytesIO(img_bytes)) as img:
        if img.mode != "RGBA":
            img = img.convert("RGBA")
            
        # 1. Isolate ALL channels independently to avoid cross-channel grayscale conversion
        r, g, b, a = img.split()
        
        # 2. Convert R, G, and B individual channels into 32-bit float linear spaces safely
        r_linear = r.convert("F")
        g_linear = g.convert("F")
        b_linear = b.convert("F")
        
        # 3. Progressive downscaling loop (halving steps) for every single channel
        while r_linear.width // 2 > target_w:
            next_w, next_h = r_linear.width // 2, r_linear.height // 2
            r_linear = r_linear.resize((next_w, next_h), Image.Resampling.LANCZOS)
            g_linear = g_linear.resize((next_w, next_h), Image.Resampling.LANCZOS)
            b_linear = b_linear.resize((next_w, next_h), Image.Resampling.LANCZOS)
            a = a.resize((next_w, next_h), Image.Resampling.LANCZOS)
            
        # Final sizing step for all channels
        r_linear = r_linear.resize((target_w, target_h), Image.Resampling.LANCZOS)
        g_linear = g_linear.resize((target_w, target_h), Image.Resampling.LANCZOS)
        b_linear = b_linear.resize((target_w, target_h), Image.Resampling.LANCZOS)
        a = a.resize((target_w, target_h), Image.Resampling.LANCZOS)
        
        # 4. Convert back to standard 8-bit integers (sRGB channel maps)
        r_final = r_linear.convert("L")
        g_final = g_linear.convert("L")
        b_final = b_linear.convert("F").convert("L") # Double pass ensures clean rounding math
        
        # 5. Recombine RGB channels with the cleanly scaled Alpha channel
        img = Image.merge("RGBA", (r_final, g_final, b_final, a))
        
        # 6. Apply a refined Unsharp Mask to perfectly crisp up edges without halo artifacts
        img = img.filter(ImageFilter.UnsharpMask(radius=0.8, percent=175, threshold=2))
        
        # Save compressed result straight to memory bytes
        buffer = io.BytesIO()
        img.save(buffer, format="PNG", optimize=True, compress_level=3)
        buffer.seek(0)
        return buffer.getvalue()


@bot.command(name="compress2")
async def compress_two_command(ctx):
    # 1. Role Verification
    user_role_ids = {role.id for role in ctx.author.roles}
    if not user_role_ids.intersection(ALLOWED_ROLES):
        return await ctx.send("❌ You do not have the required staff roles to use this command.")

    # 2. Check Attachment
    if not ctx.message.attachments:
        return await ctx.send("❌ Please upload an image to compress.")

    attachment = ctx.message.attachments[0]

    if not attachment.content_type or not attachment.content_type.startswith("image"):
        return await ctx.send("❌ File must be an image.")

    status_msg = await ctx.send("⏳ Executing high-fidelity linear compression... please wait.")

    try:
        img_bytes = await attachment.read()

        # Extract source metadata in-memory
        with Image.open(io.BytesIO(img_bytes)) as img:
            orig_width, orig_height = img.size

        # Aspect Ratio logic: 140 serves as the absolute baseline floor for the smallest side
        if orig_width < orig_height:
            new_width = 140
            new_height = int(orig_height * 140 / orig_width)
        else:
            new_height = 140
            new_width = int(orig_width * 140 / orig_height)

        # Safety Guardrail: Prevent upscaling attempts if the uploaded asset is already tiny
        if new_width > orig_width or new_height > orig_height:
            await status_msg.delete()
            return await ctx.send(f"❌ Image is already smaller than the 140px target minimum constraints (`{orig_width}x{orig_height}`).")

        # Offload structural math to background worker thread
        processed_png_bytes = await asyncio.to_thread(
            run_linear_compress_pipeline, img_bytes, new_width, new_height
        )

        # Transmit the optimized byte stream buffer back to Discord
        buffer = io.BytesIO(processed_png_bytes)
        buffer.seek(0)
        
        clean_file = discord.File(buffer, filename="compressed_hq.png")
        await ctx.send(
            content=f"📉 Imagine the shock (`{new_width}x{new_height}`)!", 
            file=clean_file
        )
        
        await status_msg.delete()
        buffer.close()

    except Exception as e:
        await ctx.send(f"❌ Error during image compression: {e}")

def save_boss_settings():
    with open(BOSS_SETTINGS_FILE, "w") as f:
        json.dump(boss_settings_cache, f, indent=4)

DISABLED_TRANSFORM_FILE = "disabled_transform_servers.json"
disabled_transform_guilds: dict[int, bool] = {}

def load_disabled_transform_guilds():
    global disabled_transform_guilds
    disabled_transform_guilds = {}
    if not os.path.exists(DISABLED_TRANSFORM_FILE):
        return
    try:
        with open(DISABLED_TRANSFORM_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
    except (json.JSONDecodeError, OSError):
        return

    if isinstance(data, dict):
        for guild_id, is_disabled in data.items():
            try:
                gid = int(guild_id)
            except (TypeError, ValueError):
                continue
            if is_disabled:
                disabled_transform_guilds[gid] = True

def save_disabled_transform_guilds():
    payload = {str(guild_id): True for guild_id in disabled_transform_guilds.keys()}
    with open(DISABLED_TRANSFORM_FILE, "w", encoding="utf-8") as f:
        json.dump(payload, f, indent=4)

