@bot.command()
@commands.has_permissions(manage_guild=True)
async def disable(ctx, target: str):
    target = target.lower().strip()
    guild_id = str(ctx.guild.id)

    if target == "boss":
        if guild_id not in boss_settings_cache:
            boss_settings_cache[guild_id] = {
                "redirect_channel": None,
                "disabled": False
            }

        boss_settings_cache[guild_id]["disabled"] = True
        save_boss_settings()
        await ctx.send("⛔ Boss spawning has been disabled for this server.")
        return

    if target == "transform":
        disabled_transform_guilds[ctx.guild.id] = True
        save_disabled_transform_guilds()
        await ctx.send("⛔ Transform behavior has been disabled for this server.")
        return

    await ctx.send("❌ Invalid disable target. Use `!disable boss` or `!disable transform`.")
@bot.command()
@commands.has_permissions(manage_guild=True)
async def enable(ctx, target: str):
    target = target.lower().strip()

    if target == "boss":
        guild_id = str(ctx.guild.id)
        if guild_id in boss_settings_cache:
            boss_settings_cache[guild_id]["disabled"] = False
            save_boss_settings()
        await ctx.send("✅ Boss spawning has been enabled.")
        return

    if target == "transform":
        if ctx.guild.id in disabled_transform_guilds:
            del disabled_transform_guilds[ctx.guild.id]
            save_disabled_transform_guilds()
        await ctx.send("✅ Transform behavior has been enabled for this server.")
        return

    await ctx.send("❌ Invalid enable target. Use `!enable boss` or `!enable transform`.")


