def generate_spell(element, dmg_range, heal_range):
    name = random_spell_name()
    is_damage = random.random() < 0.75

    spell = {
        "name": name,
        "usage": name.lower(),
        "element": element
    }

    if is_damage:
        spell["damage"] = random.randint(*dmg_range)
        spell["heal"] = 0
    else:
        spell["heal"] = random.randint(*heal_range)
        spell["damage"] = 0

    return spell

def give_spell_to_player(user_id, spell):
    conn = sqlite3.connect("magic.db")
    c = conn.cursor()

    # Insert magic if it doesn't exist
    c.execute(
        """
        INSERT OR IGNORE INTO magic
        (name, usage, damage, heal, element, effect, cooldown, mp)
        VALUES (?, ?, ?, ?, ?, NULL, 0, 0)
        """,
        (
            spell["name"],
            spell["usage"],
            spell["damage"],
            spell["heal"],
            spell["element"]
        )
    )

    # Fetch player magic list
    c.execute("SELECT magic FROM players WHERE user_id = ?", (user_id,))
    row = c.fetchone()

    magic_list = json.loads(row[0]) if row and row[0] else []

    if spell["name"] not in magic_list:
        magic_list.append(spell["name"])
        c.execute(
            "UPDATE players SET magic = ? WHERE user_id = ?",
            (json.dumps(magic_list), user_id)
        )

    conn.commit()
    conn.close()

def ensure_chant_magic_exists():
    conn = sqlite3.connect("magic.db")
    c = conn.cursor()
    chant_entries = [
        (CHANT_MAGIC_NAME, CHANT_MAGIC_NAME, 1500, 0, "fire", None),
        (FORCE_OF_NATURE_NAME, FORCE_OF_NATURE_NAME, 1500, 0, "earth", None),
        (CATASTROPHE_MAGIC_NAME, CATASTROPHE_MAGIC_NAME, 1500, 0, "water", None),
        (METEORITE_MAGIC_NAME, METEORITE_MAGIC_NAME, 1500, 0, "wind", None),
        (SILENCE_MAGIC_NAME, SILENCE_MAGIC_NAME, 500, 0, "dark", "clear_chant"),
    ]
    for name, usage, damage, heal, element, effect in chant_entries:
        c.execute(
            """
            INSERT OR IGNORE INTO magic
            (name, usage, damage, heal, element, effect, cooldown, mp)
            VALUES (?, ?, ?, ?, ?, ?, 0, 0)
            """,
            (name, usage, damage, heal, element, effect)
        )
    conn.commit()
    conn.close()

async def grant_chant_magic_task(bot: discord.Client, user_id: int):
    ensure_player2(user_id)
    ensure_chant_magic_exists()
    granted_magic = None
    with sqlite3.connect("magic.db") as conn:
        c = conn.cursor()
        c.execute("SELECT magic FROM players WHERE user_id = ?", (user_id,))
        row = c.fetchone()
        magic_list = json.loads(row[0]) if row and row[0] else []
        available = [m for m in CHANT_DROP_MAGIC if m not in magic_list]
        if not available:
            return
        granted_magic = random.choice(available)
        magic_list.append(granted_magic)
        c.execute(
            "UPDATE players SET magic = ? WHERE user_id = ?",
            (json.dumps(magic_list), user_id)
        )
        conn.commit()

    user = bot.get_user(user_id)
    if not user:
        try:
            user = await bot.fetch_user(user_id)
        except Exception:
            user = None
    if user:
        try:
            await user.send(f"✨ You have learned **{granted_magic}**!")
        except Exception:
            pass

def get_rollable_effect_names(conn):
    c = conn.cursor()
    c.execute("SELECT name FROM effect_dict WHERE special = 0")
    return [r[0] for r in c.fetchall()]


def normalize_effect_name(effect_name):
    """Normalize legacy effect naming so old gear still resolves in effect_dict."""
    if effect_name is None:
        return None
    return str(effect_name).strip().lower().replace("_defense", "_defence")


def normalize_legacy_gear_effects(conn):
    """Migrate old *_defense* entries in player_gear to *_defence*."""
    c = conn.cursor()
    columns = ["primary_effect", "effect2", "effect3", "effect4", "effect5", "effect6", "effect7"]
    for col in columns:
        c.execute(
            f"""
            UPDATE player_gear
            SET {col} = REPLACE(LOWER({col}), '_defense', '_defence')
            WHERE {col} IS NOT NULL AND LOWER({col}) LIKE '%_defense%'
            """
        )
    conn.commit()


def normalize_legacy_gear_names(conn):
    """Fix legacy boss gear typos and normalize IDs/names to match forge gear."""
    c = conn.cursor()
