def roll_random_item(tier: str, force_item: str = None):
    tier = tier.upper()

    # Storm Dragon Armor (A-tier only)
    if force_item == "storm dragon armor":
        return (
            "storm dragon armor",
            "Storm Dragon Armor",
            "frozen_land"
        )
    elif force_item == "phoenix spirit stone":
        return (
            "phoenix spirit stone",
            "Phoenix Spirit Stone",
            "fiery_rebirth"
        )
    elif force_item == "malevolent witch set":
        return (
            "malevolent_witch_set",
            "Malevolent Witch Set",
            "spell_voice"
        )
    elif force_item == "benevolent priest set":
        return (
            "benevolent_priest_set",
            "Benevolent Priest Set",
            "healing_power"
        )
    elif force_item == "guardian knight":
        return (
            "guardian_knight",
            "Guardian Knight",
            "absolute_defence"
        )

    # Normal gear pool
    elements = ["fire", "water", "earth", "wind"]
    gear_types = ["staff", "armor"]

    element = random.choice(elements)
    gear_type = random.choice(gear_types)

    if gear_type == "staff":
        gear_id = f"{element}_staff"
        name = f"{element.title()} Staff"
        primary_effect = f"{element}_buff3"
    else:
        gear_id = f"{element}_armor"
        name = f"{element.title()} Armor"
        primary_effect = f"{element}_defence3"

    return gear_id, name, primary_effect
def give_gear_to_player(conn, user_id: int, tier: str, force_item: str = None):
    c = conn.cursor()

    # Roll which item (or force storm dragon armor)
    gear_id, name, primary_effect = roll_random_item(tier, force_item=force_item)

    # Only roll from NON-special effects
    c.execute("SELECT name FROM effect_dict WHERE special = 0")
    rollable = [r[0] for r in c.fetchall()]

    # Prevent duplicates
    if primary_effect in rollable:
        rollable.remove(primary_effect)

    extra_count = get_extra_effect_count(tier, name)

    extras = []
    if extra_count > 0 and rollable:
        extras = random.sample(rollable, k=min(extra_count, len(rollable)))

    # Fill effect2..effect7
    effect_slots = ["none"] * 6
    for i, eff in enumerate(extras[:6]):
        effect_slots[i] = eff

    c.execute("""
        INSERT INTO player_gear
        (user_id, gear_id, name, primary_effect, effect2, effect3, effect4, effect5, effect6, effect7, equiped)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    """, (
        user_id,
        gear_id,
        name,
        primary_effect,
        effect_slots[0],
        effect_slots[1],
        effect_slots[2],
        effect_slots[3],
        effect_slots[4],
        effect_slots[5],
        "false"
    ))

    conn.commit()

def get_extra_effect_count(tier: str, gear:str) -> int:
    tier = tier.upper()
    gear = str(gear or "").strip().lower()

    if tier == "E":
        return 0

    if tier == "D":
        return 1 if random.random() < 0.50 else 0

    if tier == "C":
        count = 1
        if random.random() < 0.50:
            count += 1
        return count

    if tier == "B":
        if gear == "phoenix spirit stone":
            count = 3
            if random.random() < 0.50:
                count += 1
            if random.random() < 0.30:
                count += 1
            if random.random() < 0.20:
                count += 1
            return count
        count = 2
        if random.random() < 0.10:
            count += 1
        return count

    if tier == "A":
        if gear == "storm dragon armor":
            count = 4
            if random.random() < 0.50:
                count += 1
            if random.random() < 0.50:
                count += 1
            return count
        elif gear == "phoenix spirit stone":
            count = 4
            if random.random() < 0.50:
                count += 1
            if random.random() < 0.50:
                count += 1
            return count
        return 3
    if tier == "S":
        count = 5
        if random.random() < 0.40:
            count += 1
        return count

    return 0
def get_drop_chance(tier: str) -> float:
    tier = tier.upper()
    if tier in ("E", "D"):
        return 0.50
    if tier == "C":
        return 0.60
    if tier == "B":
        return 0.70
    if tier == "A":
        return 0.80
    if tier == "S":
        return 0.90
    return 0.0
async def dm_boss_rewards(bot, guild, user_id: int, coins: int = 0, spell=None, gear_name=None, gear_primary=None, gear_drops=None):
    member = guild.get_member(user_id)
    if not member:
        return

    lines = ["🏆 **Boss Rewards Received!**", ""]

    if coins:
        lines.append(f"💰 Coins gained: **{coins}**")

    if spell:
        # spell can be dict/object depending on your generate_spell()
        # we'll try to display nicely without crashing
        try:
            sname = spell.get("name", "New Spell")
            selement = spell.get("element", "unknown")
            sdmg = spell.get("damage", 0)
            sheal = spell.get("heal", 0)
            lines.append(f"📜 Spell drop: **{sname}** ({selement}) | 💥 {sdmg} | ✨ {sheal}")
        except Exception:
            lines.append("📜 Spell drop: **New Spell**")

    if gear_drops:
        for g_name, g_primary in gear_drops:
            if g_primary:
                lines.append(f"🛡️ Gear drop: **{g_name}** (Primary: **{g_primary}**)")
            else:
                lines.append(f"🛡️ Gear drop: **{g_name}**")
    elif gear_name:
        if gear_primary:
            lines.append(f"🛡️ Gear drop: **{gear_name}** (Primary: **{gear_primary}**)")
        else:
            lines.append(f"🛡️ Gear drop: **{gear_name}**")

    try:
        await member.send("\n".join(lines))
    except Exception:
        pass  # user DMs closed

@tasks.loop(seconds=20)
async def boss_reward_task():
    if not reward_cache:
        return

    for guild_id, data in list(reward_cache.items()):
        guild = bot.get_guild(guild_id)
        if not guild:
            del reward_cache[guild_id]
            continue
        allowed_levels = {"low", "medium", "high", "highest"}
        verification_ok = True  # default allow (for DMs)
        level_name = guild.verification_level.name.lower()
        if level_name not in allowed_levels:
            verification_ok = False
        if not verification_ok:
            del reward_cache[guild_id]
            continue
        boss_name = data["boss"].lower()
        rewards = BOSS_REWARDS.get(boss_name)

        if not rewards:
            del reward_cache[guild_id]
            continue

        tier = data["tier"].upper()
        dm_queue = []

        try:
            with sqlite3.connect("magic.db") as conn_m, connect_poke_db() as conn:
                c = conn.cursor()

                for idx, (user_id, _) in enumerate(data["top5"][:5]):
                    arcs = rewards["arcs"][idx]

                    got_spell = None
                    gear_drops = []

                    # Add coins
                    c.execute(
                        "UPDATE poke SET coins = coins + ? WHERE player_id = ?",
                        (arcs, user_id)
                    )

                    # Spell drop (double rate, capped at 100%)
                    drop_chance = min(1.0, float(rewards.get("drop_chance", 0)))
                    if random.random() < drop_chance:
                        got_spell = generate_spell(
                            rewards["element"],
                            rewards["dmg"],
                            rewards["heal"]
                        )
                        give_spell_to_player(user_id, got_spell)

                    # Gear drop (up to 3 rolls, diminishing chance)
                    base_chance = get_drop_chance(tier)
                    for drop_idx in range(3):
                        drop_chance = base_chance * (0.5 ** drop_idx)
                        if random.random() >= drop_chance:
                            continue
                        force_item = None

                        if tier == "S":
                            force_item = random.choice([
                                "storm dragon armor",
                                "phoenix spirit stone",
                                "malevolent witch set",
                                "benevolent priest set",
                                "guardian knight",
                            ])

                        # A-tier boss can drop storm dragon armor
                        if tier == "A" and random.random() < 0.30:
                            if random.random() < 0.80:
                                force_item = "storm dragon armor"
                            else:
                                force_item = "phoenix spirit stone"
                        if tier == "B" and random.random() < 0.20:
                            force_item = "phoenix spirit stone"
                        if tier == "C" and random.random() < 0.15:
                            force_item = "benevolent priest set"
                        if tier == "D" and random.random() < 0.10:
                            force_item = "guardian knight"

                        gear_id, gear_name, gear_primary = roll_random_item(tier, force_item=force_item)
                        give_gear_to_player(conn_m, user_id, tier, force_item=force_item)
                        gear_drops.append((gear_name, gear_primary))

                    dm_queue.append({
                        "user_id": user_id,
                        "coins": arcs,
                        "spell": got_spell,
                        "gear_drops": gear_drops,
                    })

                # Last hit bonus (coins only)
                if data["last_hit"]:
                    c.execute(
                        "UPDATE poke SET coins = coins + ? WHERE player_id = ?",
                        (rewards["last_hit"], data["last_hit"])
                    )
                    dm_queue.append({
                        "user_id": data["last_hit"],
                        "coins": rewards["last_hit"],
                        "spell": None,
                        "gear_drops": None,
                    })

                conn.commit()
        except Exception:
            traceback.print_exc()
            continue

        for dm in dm_queue:
            await dm_boss_rewards(
                bot=bot,
                guild=guild,
                user_id=dm["user_id"],
                coins=dm["coins"],
                spell=dm["spell"],
                gear_drops=dm.get("gear_drops"),
            )

        del reward_cache[guild_id]
@bot.command()
async def hunt(ctx):
    guild_id = ctx.guild.id
    user_id = ctx.author.id
    now = int(time.time())

    key = (guild_id, user_id)

    # ⏳ One hunt per day per server
    if key in hunt_cache:
        last = hunt_cache[key]
        if now - last < 86400:
            remaining = 86400 - (now - last)
            hours = remaining // 3600
            minutes = (remaining % 3600) // 60
            await ctx.send(
                f"🕒 You must rest before hunting again.\n"
                f"⏱️ {hours}h {minutes}m remaining."
            )
            return

    # Init server cache
    if guild_id not in server_cache:
        server_cache[guild_id] = {}

    guild_data = server_cache[guild_id]

    # Only one boss at a time
    if "boss" in guild_data:
        await ctx.send("⚔️ A boss is already roaming this land!")
        return

    # 🎲 Tier roll (D / E only)
    tier = random.choice(["D", "E"])

    if tier == "D":
        boss = {
            "name": "gmax golem",
            "tier": "D",
            "attribute": "earth",
            "max_hp": 200000,
            "current_hp": 200000,
            "turn_count": 0,
            "leaderboard": [],
            "last_hit": None,
            "attack": {"name": "heavy smash", "damage": 2500, "attribute": "earth"}
        }
    else:
        boss = {
            "name": "armor goblin",
            "tier": "E",
            "attribute": "wind",
            "max_hp": 100000,
            "current_hp": 100000,
            "turn_count": 0,
            "leaderboard": [],
            "last_hit": None,
            "attack": {"name": "slash", "damage": 2000, "attribute": "wind"}
        }

    guild_data["boss"] = boss
    hunt_cache[key] = now

    # 📢 Spawn message
    embed = discord.Embed(
        title="🗺️ Hunt Encounter!",
        description=f"**{boss['name']}** has appeared!\nTier **{tier}**",
        color=discord.Color.orange()
    )
    embed.add_field(name="HP", value=f"{boss['current_hp']:,}")
    embed.set_image(url=f"attachment://{boss['name'].lower().replace(' ', '_')}.jpg")

    file = discord.File(
        f"{boss['name'].lower()}.jpg",
        filename=f"{boss['name'].lower()}.jpg"
    )

    await ctx.send(file=file, embed=embed)
