@bot.command()
@commands.has_permissions(mention_everyone=True)
async def dungeon(ctx):

    guild = ctx.guild

    member_count = guild.member_count

    s_chance = min(
        0.33,
        member_count / 9000
    )

    roll = random.random()

    if roll < s_chance:
        tier = "S"

    elif roll < s_chance + 0.20:
        tier = "A"

    elif roll < s_chance + 0.50:
        tier = "B"

    else:
        tier = "C"

    boss = create_dungeon_boss(tier)

    embed = discord.Embed(
        title="⚔️ Dungeon Boss Appeared",
        description=(
            f"Tier: **{tier}**\n"
            f"Boss: **{boss['name']}**\n"
            f"HP: **{boss['current_hp']:,}**"
        ),
        color=discord.Color.gold()
    )

    await ctx.send(embed=embed)

@bot.command()
async def status(ctx):
    guild_id = ctx.guild.id

    if guild_id not in server_cache or not server_cache[guild_id]:
        await ctx.send("🌱 Nothing stirs in this land yet.")
        return

    guild_data = server_cache[guild_id]

    embed = discord.Embed(
        title="📊 Battle Status",
        color=discord.Color.blue()
    )

    # 🐉 Boss first
    boss = guild_data.get("boss")
    if boss:
        effects = "None"
        if boss.get("effect"):
            effects = ", ".join(boss["effect"])

        embed.add_field(
            name=f"👑 Boss — {boss['name']} (Tier {boss['tier']})",
            value=(
                f"❤️ HP: **{boss['current_hp']:,} / {boss['max_hp']:,}**\n"
                f"🔄 Turn Count: **{boss['turn_count']}**\n"
                f"🧩 Effects: {effects}"
            ),
            inline=False
        )
    else:
        embed.add_field(
            name="👑 Boss",
            value="No boss currently present.",
            inline=False
        )

    # 👥 Players
    for pid, data in guild_data.items():
        if pid == "boss" or pid == "timestamp":
            continue

        user = ctx.guild.get_member(pid)
        if not user:
            continue

        hp = data.get("hp", 0)
        mp = data.get("mp", 0)
        effects = data.get("effect", [])

        effects_text = ", ".join(effects) if effects else "None"

        embed.add_field(
            name=f"🧍 {user.display_name}",
            value=(
                f"❤️ HP: **{max(int(hp), 0)}**\n"
                f"🔮 MP: **{max(int(mp), 0)}**\n"
                f"🧩 Effects: {effects_text}"
            ),
            inline=True
        )

    await ctx.send(embed=embed)


@tasks.loop(minutes=1)
async def cleanup_cache():
    if not bot.is_ready_flag:
        return
    now = int(time.time())

    # Clean player cache
    for user_id in list(player_cache.keys()):
        if now - player_cache[user_id]["timestamp"] > 600:
            del player_cache[user_id]

    # Clean server combat cache
    for guild_id in list(server_cache.keys()): 
        guild_cache = server_cache[guild_id]
        for entity_id in list(guild_cache.keys()):
            entity = guild_cache[entity_id]

            # Skip non-combat entries (boss metadata, etc.)
            if not isinstance(entity, dict):
                continue

            if "timestamp" not in entity:
                continue

            if now - entity["timestamp"] > 600:
                del guild_cache[entity_id]

        # Remove server entry if empty
        if not guild_cache:
            del server_cache[guild_id]
class AddChampionView(discord.ui.View):
    def __init__(self, server_id: str):
        super().__init__(timeout=None)
        self.server_id = server_id

    @discord.ui.button(label="Add Champion 🏆", style=discord.ButtonStyle.success)
    async def add_champion(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message("❌ Only admins can add champions!", ephemeral=True)

        FILE_PATH = "mascot.json"
        CHAMPION_FOLDER = "champions"
        os.makedirs(CHAMPION_FOLDER, exist_ok=True)
        champ_path = os.path.join(CHAMPION_FOLDER, f"{self.server_id}_champion.txt")

        # Load current mascot data
        try:
            with open(FILE_PATH, "r") as f:
                data = json.load(f)
        except (json.JSONDecodeError, FileNotFoundError):
            await interaction.response.send_message("⚠️ Mascot data not found.", ephemeral=True)
            return

        mascot_data = data[self.server_id]
        level = mascot_data.get("battle_level", 1)
        allowed_champs = 1 + level // 5  # 1 slot every 5 levels

        # Load current champions
        champions = []
        if os.path.exists(champ_path):
            with open(champ_path, "r") as f:
                champions = [line.strip() for line in f if line.strip()]

        if len(champions) >= allowed_champs:
            return await interaction.response.send_message(
                f"⚠️ Max champions reached! (Level {level} allows {allowed_champs} champion{'s' if allowed_champs > 1 else ''}).\nYou get one extra champion every 5 levels.",
                ephemeral=True
            )

        await interaction.response.send_message("🏆 Please ping the user to set as champion:", ephemeral=True)

        def check(msg):
            return msg.author == interaction.user and msg.channel == interaction.channel and msg.mentions

        try:
            msg = await bot.wait_for("message", check=check, timeout=30)
            champion_user = msg.mentions[0]

            # Prevent duplicate champions
            for line in champions:
                if str(champion_user.id) in line:
                    await interaction.followup.send(f"⚠️ {champion_user.mention} is already a champion!", ephemeral=True)
                    await msg.delete()
                    return

            # Add champion to file
            with open(champ_path, "a") as f:
                f.write(f"{champion_user.id} {champion_user.name}\n")

            await msg.delete()
            await interaction.followup.send(
                f"✅ {champion_user.mention} has been added as a server champion!",
                ephemeral=True
            )

        except asyncio.TimeoutError:
            await interaction.followup.send("⏰ Time’s up! Champion assignment cancelled.", ephemeral=True)

    @discord.ui.button(label="Remove Champion ❌", style=discord.ButtonStyle.danger)
    async def remove_champion(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message("❌ Only admins can remove champions!", ephemeral=True)

        CHAMPION_FOLDER = "champions"
        champ_path = os.path.join(CHAMPION_FOLDER, f"{self.server_id}_champion.txt")

        if not os.path.exists(champ_path):
            return await interaction.response.send_message("⚠️ No champions found for this server.", ephemeral=True)

        # Load champions
        with open(champ_path, "r") as f:
            champions = [line.strip() for line in f if line.strip()]

        if not champions:
            return await interaction.response.send_message("⚠️ No champions to remove.", ephemeral=True)

        await interaction.response.send_message("❌ Please ping the champion you want to remove:", ephemeral=True)

        def check(msg):
            return msg.author == interaction.user and msg.channel == interaction.channel and msg.mentions

        try:
            msg = await bot.wait_for("message", check=check, timeout=30)
            remove_user = msg.mentions[0]
            new_champs = [line for line in champions if not line.startswith(str(remove_user.id))]

            if len(new_champs) == len(champions):
                await interaction.followup.send(f"⚠️ {remove_user.mention} is not currently a champion.", ephemeral=True)
                await msg.delete()
                return

            # Save updated list
            with open(champ_path, "w") as f:
                f.write("\n".join(new_champs) + ("\n" if new_champs else ""))

            await msg.delete()
            await interaction.followup.send(f"✅ {remove_user.mention} has been removed from champions.", ephemeral=True)

        except asyncio.TimeoutError:
            await interaction.followup.send("⏰ Time’s up! Champion removal cancelled.", ephemeral=True)


class MascotView(discord.ui.View):
    def __init__(self, server_id: str):
        super().__init__(timeout=60)
        self.server_id = server_id
        self.question_asked = False

    async def increment_points(self, interaction: discord.Interaction, action: str, amount: int):
        # Load mascot data
        FILE_PATH = "mascot.json"
        try:
            with open("mascot.json", "r") as f:
                data = json.load(f)
        except (json.JSONDecodeError, FileNotFoundError):
            # Backup the corrupted file before resetting
            try:
                shutil.copy("mascot.json", "mascot.json.bak")
            except Exception:
                pass
            return

        mascot = data[self.server_id]
        mascot["points"] += amount

        # Save back
        
        if data:  # Only write if data is not empty
            with tempfile.NamedTemporaryFile("w", delete=False, dir=os.path.dirname(FILE_PATH), encoding="utf-8") as tf:
                json.dump(data, tf, indent=4)
                tempname = tf.name
            os.replace(tempname, "mascot.json")

        if amount > 0:
            await interaction.followup.send(
                f"💖 You {action} **{mascot['mascot']}**! (+{amount} points)")
        else:
            await interaction.followup.send(
                f"💖 You {action} **{mascot['mascot']}**! **But** it did not work, you got slammed really hard. ({amount} points)")

    @discord.ui.button(label="Cheer 🎉", style=discord.ButtonStyle.success)
    async def cheer(self, interaction: discord.Interaction, button: discord.ui.Button):
        i = random.randint(1,5)
        await interaction.response.send_message("you are cheering very hard!")
        if i < 3:
            await self.increment_points(interaction, "cheered", -1)
        if i > 2:
            await self.increment_points(interaction, "cheered", 1)

    @discord.ui.button(label="Feed 🍎", style=discord.ButtonStyle.primary)
    async def feed(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.question_asked:
            await interaction.response.send_message("Please wait until the current question is answered.", ephemeral=True)
            return

        self.question_asked = True

        # Ask a simple math question
        question_data = random.choice(QUESTION_POOL)
        question = question_data["question"]
        correct_answer = question_data["answer"]

        await interaction.response.send_message(
            f"🍎 To feed the mascot, You must find a something for it to eat.\n**{question}**"
        )

        def check(msg):
            return msg.author == interaction.user and msg.channel == interaction.channel

        try:
            msg = await bot.wait_for("message", check=check, timeout=15)
            if msg.content.strip().capitalize() == correct_answer:
                await self.increment_points(interaction, "fed", 12)
                await msg.delete()
            else:
                await interaction.followup.send("❌ Wrong answer! Feeding failed.")
                await msg.delete()
        except asyncio.TimeoutError:
            await interaction.followup.send("⏰ Time’s up! Feeding failed.")
        finally:
            self.question_asked = False

    @discord.ui.button(label="Play ⚽", style=discord.ButtonStyle.primary)
    async def play(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.question_asked:
            await interaction.response.send_message("Please wait until the current question is answered.", ephemeral=True)
            return

        self.question_asked = True

        a, b = random.randint(1, 100), random.randint(1, 100)
        sign = random.choice(["+", "*"])
        if sign == "+":
            correct_answer = a + b
        elif sign == "*":
            correct_answer = a * b
        await interaction.response.send_message(
            f"⚽Your mascot asked you a question:\n**What is {a} {sign} {b}?**")

        def check(msg):
            return msg.author == interaction.user and msg.channel == interaction.channel

        try:
            msg = await bot.wait_for("message", check=check, timeout=15)
            try:
                if msg.content.strip().isdigit() and int(msg.content.strip()) == correct_answer:
                    await self.increment_points(interaction, "played with", 8)
                    await msg.delete()
                else:
                    await interaction.followup.send("❌ Wrong answer!")
                    await msg.delete()
            except Exception as e:
                print(e)
        except asyncio.TimeoutError:
            await interaction.followup.send("⏰ Time’s up")
        finally:
            self.question_asked = False
    
    @discord.ui.button(label="Change Mascot", style=discord.ButtonStyle.danger)
    async def change_mascot(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message('Only Server Owner can set mascot!')
        await interaction.response.send_message("Please enter the new mascot name:", ephemeral=True)

        def check(msg):
            return msg.author == interaction.user and msg.channel == interaction.channel

        try:
            msg = await bot.wait_for("message", check=check, timeout=30)
            new_name = msg.content.strip()

            try:
                sprite = get_pokemon_normal_sprite(new_name.lower())
            except Exception as e:
                return await interaction.followup.send("Wrong Pokemon Name", ephemeral=True)

            try:
                with open("mascot.json", "r") as f:
                    data = json.load(f)
            except (json.JSONDecodeError, FileNotFoundError):
                # Backup the corrupted file before resetting
                try:
                    shutil.copy("mascot.json", "mascot.json.bak")
                except Exception:
                    pass
                return

            if self.server_id not in data:
                
                if data:  # Only write if data is not empty
                    with tempfile.NamedTemporaryFile("w", delete=False, dir=os.path.dirname("mascot.json"), encoding="utf-8") as tf:
                        json.dump(data, tf, indent=4)
                        tempname = tf.name
                    os.replace(tempname, "mascot.json")
                await interaction.followup.send("⚠️ No mascot found. Use `!mascot` first.", ephemeral=True)
                return

            data[self.server_id]["mascot"] = new_name

            
            if data:  # Only write if data is not empty
                with tempfile.NamedTemporaryFile("w", delete=False, dir=os.path.dirname("mascot.json"), encoding="utf-8") as tf:
                    json.dump(data, tf, indent=4)
                    tempname = tf.name
                os.replace(tempname, "mascot.json")

            await msg.delete()
            await interaction.followup.send(f"✅ Mascot name changed to **{new_name}**!", ephemeral=True)

        except asyncio.TimeoutError:
            await interaction.followup.send("⏰ You took too long! Mascot rename cancelled.", ephemeral=True)


    @discord.ui.button(label="Battle Mode", style=discord.ButtonStyle.secondary)
    async def battle_mode(self, interaction: discord.Interaction, button: discord.ui.Button):
        FILE_PATH = "mascot.json"
        CHAMPION_FOLDER = "champions"
        os.makedirs(CHAMPION_FOLDER, exist_ok=True)

        try:
            with open(FILE_PATH, "r") as f:
                data = json.load(f)
        except (json.JSONDecodeError, FileNotFoundError):
            await interaction.response.send_message("⚠️ Mascot data not found.", ephemeral=True)
            return

        if self.server_id not in data:
            await interaction.response.send_message("⚠️ No mascot found for this server. Use `!mascot` first.", ephemeral=True)
            return

        mascot_data = data[self.server_id]
        mascot_name = mascot_data["mascot"]
        level = mascot_data.get("battle_level", 1)

        # Get shiny sprite URL
        shiny_sprite = get_pokemon_info(mascot_name)[2]

        # Load champions
        champ_path = os.path.join(CHAMPION_FOLDER, f"{self.server_id}_champion.txt")
        champions = []
        if os.path.exists(champ_path):
            with open(champ_path, "r") as f:
                champions = [line.strip() for line in f if line.strip()]

        # Create new embed
        embed = discord.Embed(
            title=f"⚔️ {interaction.guild.name} Battle Mascot",
            description=f"**{mascot_name}** has entered battle mode!",
            color=discord.Color.red()
        )
        embed.add_field(name="Battle Level", value=mascot_data.get("battle_level", 1), inline=True)
        embed.add_field(name="Battle Points", value=mascot_data.get("battle_points", 0), inline=True)

        # Format champions field
        if champions:
            champ_lines = []
            for champ in champions:
                # champ format: "user_id username"
                parts = champ.split(" ", 1)
                if len(parts) == 2:
                    champ_lines.append(f"<@{parts[0]}> ({parts[1]})")
                else:
                    champ_lines.append(champ)
            embed.add_field(name="Server Champions", value="\n".join(champ_lines), inline=False)
        else:
            embed.add_field(name="Server Champions", value="None yet!", inline=False)

        embed.set_image(url=shiny_sprite)
        embed.set_footer(text="Add your champions and dominate the arena! Pro tip: you get battle exp from dueling in the server!")

        # Replace view with AddChampionView
        view = AddChampionView(self.server_id)
        await interaction.response.edit_message(embed=embed, view=view)

    
    @discord.ui.button(label="Add Server", style=discord.ButtonStyle.green)
    async def add_server(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message("❌ Only server admins can use this.", ephemeral=True)

        # Load mascot data
        try:
            with open("mascot.json", "r") as f:
                data = json.load(f)
        except (json.JSONDecodeError, FileNotFoundError):
            # Backup the corrupted file before resetting
            try:
                shutil.copy("mascot.json", "mascot.json.bak")
            except Exception:
                pass
            return

        mascot_data = data.get(self.server_id)
        if not mascot_data or mascot_data["level"] < 10:
            return await interaction.response.send_message(
                "⚠️ Mascot must be at least **level 10** to add this server!", ephemeral=True
            )

        FILE_PATH = "mascot_server.json"
        if os.path.exists(FILE_PATH):
            with open(FILE_PATH, "r") as f:
                try:
                    server_data = json.load(f)
                except json.JSONDecodeError:
                    server_data = {}
        else:
            server_data = {}

        # Check if server is already added
        if self.server_id in server_data:
            # Remove the server
            server_data.pop(self.server_id)
            with open(FILE_PATH, "w") as f:
                json.dump(server_data, f, indent=4)
            await interaction.response.send_message(
                f"⚠️ Server **{interaction.guild.name}** removed from mascot servers. "
                f"Click the button again to add it back.", ephemeral=True
            )
            # Optionally, update button label dynamically
            button.label = "Add Server"
            button.style = discord.ButtonStyle.green
            await interaction.message.edit(view=self)
            return

        # Try to create a permanent invite link
        try:
            invite = await interaction.channel.create_invite(max_age=0, max_uses=0, unique=False)
            invite_link = invite.url
        except Exception:
            await interaction.response.send_message(
                "⚠️ Error getting invite link. Please enter one manually:", ephemeral=True
            )
            await interaction.response.send_modal(AddServerModal(self.server_id))
            return

        # Add server
        server_data[self.server_id] = {
            "name": interaction.guild.name,
            "invite": invite_link,
            "server_id": interaction.guild.id
        }

        with open(FILE_PATH, "w") as f:
            json.dump(server_data, f, indent=4)

        # Change button label dynamically
        button.label = "Remove Server"
        button.style = discord.ButtonStyle.red
        await interaction.message.edit(view=self)

        await interaction.response.send_message(
            f"✅ Server **{interaction.guild.name}** added successfully! "
            f"Click the button again to remove it if needed.", ephemeral=True
        )

    @discord.ui.button(label="Server Quiz 🎓", style=discord.ButtonStyle.success)
    async def quiz(self, interaction: discord.Interaction, button: discord.ui.Button):
        
        await interaction.response.defer(ephemeral=True)
        try:
            # Load categories
            files = [f for f in os.listdir("questions") if f.endswith(".json")]
            if not files:
                return await interaction.followup.send("No quiz data available!", ephemeral=True)

            # Dropdown view
            view = discord.ui.View(timeout=30)
            select = discord.ui.Select(
                placeholder="Choose a quiz category...",
                options=[discord.SelectOption(label=f.replace(".json", "").replace("_", " ").title()) for f in files]
            )
            view.add_item(select)

            initiator_id = interaction.user.id  # save who started it

            async def select_callback(interact: discord.Interaction):
                # Only allow the user who clicked the button to pick
                if interact.user.id != initiator_id:
                    return await interact.followup.send("❌ Only the user who started the quiz can select a category.", ephemeral=True)

                category = select.values[0]
                await interact.response.defer()
                await start_quiz(interact, category, self.server_id)

            select.callback = select_callback
            await interaction.followup.send("Select a quiz category to begin:", view=view)
        except Exception as e:
            print(e)

async def start_quiz(interaction: discord.Interaction, category_name: str, server_id: str):
    file_path = os.path.join("questions", f"{category_name.lower().replace(' ', '_')}.json")
    if not os.path.exists(file_path):
        await interaction.followup.send(f"⚠️ No quiz data found for **{category_name}**.")
        return

    with open(file_path, "r", encoding="utf-8") as f:
        questions = json.load(f)

    quiz_questions = random.sample(questions, k=min(15, len(questions)))
    scores = {}

    await interaction.followup.send(f"🎯 Starting **{category_name}** quiz! Each question lasts **15 seconds**!")

    for i, q in enumerate(quiz_questions, start=1):
        question = q["question"]
        options = q["options"]
        correct = q["correct_answer"]
        random.shuffle(options)

        embed = discord.Embed(
            title=f"Question {i}/15",
            description=question,
            color=discord.Color.blurple()
        )

        view = discord.ui.View()
        start_time = time.perf_counter()
        answered = set()

        for opt in options:
            async def button_callback(inter: discord.Interaction, choice=opt):
                if inter.user.id in answered:
                    await inter.response.send_message("You already answered!", ephemeral=True)
                    return

                elapsed = time.perf_counter() - start_time
                answered.add(inter.user.id)

                if choice == correct:
                    base = 1100
                    penalty = int(elapsed * 30)
                    earned = max(0, base - penalty)
                    scores[inter.user.display_name] = scores.get(inter.user.display_name, 0) + earned
                    await inter.response.send_message(f"✅ Correct! +{earned} pts", ephemeral=True)
                else:
                    await inter.response.send_message(f"❌ Wrong!", ephemeral=True)

            btn = discord.ui.Button(label=opt, style=discord.ButtonStyle.secondary)
            btn.callback = button_callback
            view.add_item(btn)

        msg = await interaction.channel.send(embed=embed, view=view)
        await asyncio.sleep(15)

        for child in view.children:
            child.disabled = True
            if child.label == correct:
                child.style = discord.ButtonStyle.success
        await msg.edit(view=view)

        # Leaderboard
        if scores:
            lb = sorted(scores.items(), key=lambda x: x[1], reverse=True)
            board = "\n".join([f"**#{i+1}** {u}: {int(s)} pts" for i, (u, s) in enumerate(lb[:10])])
        else:
            board = "No one scored yet."
        embed_lb = discord.Embed(title=f"🏆 Leaderboard after Q{i}", description=board, color=discord.Color.gold())
        await interaction.channel.send(embed=embed_lb)
        await asyncio.sleep(3)

    # Final results
    if not scores:
        await interaction.channel.send("No one participated 😅")
        return

    lb = sorted(scores.items(), key=lambda x: x[1], reverse=True)
    winner, top_score = lb[0]
    total_score = sum(s for _, s in lb)
    mascot_bonus = round(total_score / 100)

    embed_final = discord.Embed(
        title="🎉 Final Results!",
        description="\n".join([f"**#{i+1}** {u}: {int(s)} pts" for i, (u, s) in enumerate(lb)]),
        color=discord.Color.green()
    )
    embed_final.set_footer(text=f"Mascot gained +{mascot_bonus} points!")

    await interaction.channel.send(embed=embed_final)

    # Update mascot points
    try:
        with open("mascot.json", "r") as f:
            data = json.load(f)
    except (json.JSONDecodeError, FileNotFoundError):
        # Backup the corrupted file before resetting
        try:
            shutil.copy("mascot.json", "mascot.json.bak")
        except Exception:
            pass
        return
    data[server_id]["points"] += mascot_bonus
    
    if data:  # Only write if data is not empty
        with tempfile.NamedTemporaryFile("w", delete=False, dir=os.path.dirname("mascot.json"), encoding="utf-8") as tf:
            json.dump(data, tf, indent=4)
            tempname = tf.name
        os.replace(tempname, "mascot.json")


