class AddServerModal(discord.ui.Modal, title="Add Server Manually"):
    invite_link = discord.ui.TextInput(
        label="Enter a valid invite link",
        placeholder="https://discord.gg/example",
        required=True
    )

    def __init__(self, server_id):
        super().__init__()
        self.server_id = server_id

    async def on_submit(self, interaction: discord.Interaction):
        FILE_PATH = "mascot_server.json"
        if os.path.exists(FILE_PATH):
            with open(FILE_PATH, "r") as f:
                try:
                    server_data = json.load(f)
                except json.JSONDecodeError:
                    server_data = {}
        else:
            server_data = {}

        server_data[self.server_id] = {
            "name": interaction.guild.name,
            "invite": str(self.invite_link)
        }

        with open(FILE_PATH, "w") as f:
            json.dump(server_data, f, indent=4)

        await interaction.response.send_message("✅ Server successfully added manually!", ephemeral=True)

@bot.command(name="mascot")
async def mascot(ctx):
    server_id = str(ctx.guild.id)

    # Load or create mascot data
    FILE_PATH = "mascot.json"
    if os.path.exists(FILE_PATH):
        with open(FILE_PATH, "r") as f:
            try:
                data = json.load(f)
            except json.JSONDecodeError:
                data = {}
    else:
        data = {}

    if server_id not in data:
        print(f'{ctx.guild.name} created their own mascot')
        data[server_id] = {
            "mascot": random.choice(POKEMON_LIST),
            "points": 0,
            "battle_points": 0,
            "level": 1,
            "battle_level": 1
        }

    mascot = data[server_id]

    # Save back (in case file was empty)
    

    if data:  # Only write if data is not empty
        with tempfile.NamedTemporaryFile("w", delete=False, dir=os.path.dirname(FILE_PATH), encoding="utf-8") as tf:
            json.dump(data, tf, indent=4)
            tempname = tf.name
        os.replace(tempname, "mascot.json")

    # Create the embed
    embed = discord.Embed(
        title=f"<a:yay:1426931130279399638> {ctx.guild.name} Mascot",
        description=f"Meet **{mascot['mascot']}**!",
        color=discord.Color.yellow()
    )
    embed.add_field(name="Level", value=mascot["level"], inline=True)
    embed.add_field(name="Points", value=mascot["points"], inline=True)
    embed.set_image(url=get_pokemon_normal_sprite(mascot["mascot"].lower()))
    embed.set_footer(text="Interact with your mascot below!")

    view = MascotView(server_id)
    await ctx.send(embed=embed, view=view)

@bot.tree.command(name="mascot", description="View Your mascot!")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
@app_commands.describe(server_name="Optional: Server name to look up mascot")
async def mascot_slash(interaction: discord.Interaction, server_name: str = None):
    FILE_PATH = "mascot.json"
    SERVER_FILE = "mascot_server.json"

    # Load mascot data
    if os.path.exists(FILE_PATH):
        with open(FILE_PATH, "r") as f:
            mascot_data_all = json.load(f)
    else:
        await interaction.response.send_message("⚠️ No mascots found yet.", ephemeral=True)
        return

    if server_name:
        # Search by server name in mascot_server.json
        if os.path.exists(SERVER_FILE):
            with open(SERVER_FILE, "r") as f:
                server_data = json.load(f)
        else:
            server_data = {}

        found = None
        for sid, sdata in server_data.items():
            if sdata["name"].lower() == server_name.lower():
                found = sid
                break

        if not found:
            return await interaction.response.send_message(
                f"⚠️ No mascot found for server **{server_name}**.", ephemeral=True
            )

        server_id = found
    else:
        # Default to current server
        server_id = str(interaction.guild.id)

    mascot = mascot_data_all.get(server_id)
    if not mascot:
        return await interaction.response.send_message(
            "⚠️ Mascot not found for this server.", ephemeral=True
        )

    # Build description with invite link if available
    invite_link = None
    if os.path.exists(SERVER_FILE):
        with open(SERVER_FILE, "r") as f:
            server_data = json.load(f)
            if server_id in server_data:
                invite_link = server_data[server_id].get("invite")

    description = f"Meet **{mascot['mascot']}**!"
    if invite_link:
        description += f"\n[Join the server]({invite_link})"

    embed = discord.Embed(
        title=f"<a:yay:1426931130279399638> {server_data.get(server_id, {}).get('name', 'Server')} Mascot",
        description=description,
        color=discord.Color.yellow()
    )
    embed.add_field(name="Level", value=mascot["level"], inline=True)
    embed.add_field(name="Points", value=mascot["points"], inline=True)
    embed.set_image(url=get_pokemon_normal_sprite(mascot["mascot"].lower()))
    embed.set_footer(text=f"Interact with the mascot with !mascot or @{bot.user.name} mascot.")
    await interaction.response.send_message(embed=embed)

