@bot.command(name="mascot_points")
async def mascot_points(ctx, action: str, amount: int):
    """
    Change the mascot's points for this server.
    Usage: !mascot_points <add|remove|set> <amount>
    """
    if ctx.author.id not in owner_ids:
        return await ctx.send("Developer only command")
    server_id = str(ctx.guild.id)
    file = "mascot.json"

    # Load or create mascot data
    if os.path.exists(file):
        with open(file, "r") as f:
            data = json.load(f)
    else:
        data = {}

    if server_id not in data:
        data[server_id] = {
            "mascot": "Pikachu",
            "points": 0,
            "battle_points": 0,
            "level": 1,
            "battle_level": 1
        }

    mascot = data[server_id]["mascot"]
    old_points = data[server_id]["points"]

    # Perform the action
    if action.lower() == "add":
        data[server_id]["points"] += amount
    elif action.lower() == "remove":
        data[server_id]["points"] = max(0, data[server_id]["points"] - amount)
    elif action.lower() == "set":
        data[server_id]["points"] = max(0, amount)
    else:
        return await ctx.send("⚠️ Invalid action! Use `add`, `remove`, or `set`.")

    # Check for level-up (same logic you used before)
    points = data[server_id]["points"]
    level = data[server_id].get("level", 1)

    def get_threshold(level):
        return 10000 if level <= 10 else 10000 + (level - 10) * 10000

    while points >= get_threshold(level):
        level += 1
        await ctx.send(f"🎉 {mascot} leveled up to **Level {level}**!")

    data[server_id]["level"] = level
    data[server_id]["points"] = points

    # Save changes
    with open(file, "w") as f:
        json.dump(data, f, indent=4)

    await ctx.send(
        f"✅ Mascot **{mascot}**'s points updated!\n"
        f"Old Points: `{old_points}` → New Points: `{data[server_id]['points']}` (Level {level})")

def get_next_threshold(current_level: int, base_table: dict):
    """Get threshold dynamically — after 10, each level needs +10,000."""
    if current_level < 10:
        return base_table.get(current_level, 10_000)
    else:
        # For level >10, add 10,000 more per level beyond 10
        base_10 = base_table[10]
        extra = (current_level - 9) * 10_000
        return base_10 + extra
            
