def is_team_fainted(field_value: str) -> bool:
    """
    Returns True if all Pokémon in the field have 0 current HP.
    Works regardless of line breaks or markdown.
    """
    matches = re.findall(r"(\d+(?:\.\d+)?)/(\d+)\s*HP", field_value)
    if not matches:
        return False  # no HP data found
    for current, _ in matches:
        if float(current) > 0.0:
            return False
    return True


@bot.group(name='dm_digest', invoke_without_command=True)
@commands.has_permissions(administrator=True)
async def dmwhitelist(ctx):
    await ctx.send("Usage: `!dm_digest on` or `!dm_digest off`")

@dmwhitelist.command(name='on')
async def add_to_whitelist(ctx):
    global allowed_ids
    member = ctx.author

    if member.id in allowed_ids:
        await ctx.send(f"dm_digest already on for {member.mention}.")
        return

    # Update in-memory set
    allowed_ids.add(member.id)

    # Persist to file
    with open("dm_whitelist.txt", "a") as f:
        f.write(f"{member.id}\n")

    await ctx.send(f"✅ dm_digest toggled on for {member.mention}.")

@dmwhitelist.command(name='off')
async def remove_from_whitelist(ctx):
    global allowed_ids
    member = ctx.author

    if member.id not in allowed_ids:
        await ctx.send(f"dm_digest is off for {member.mention}.")
        return

    # Update in-memory set
    allowed_ids.discard(member.id)

    # Rewrite file without the ID
    with open("dm_whitelist.txt", "w") as f:
        for uid in allowed_ids:
            f.write(f"{uid}\n")

    await ctx.send(f"❌ dm_digest toggled off for {member.mention}.")

def allowed_server():
    folder_name = 'allowed_server'
    file_path = os.path.join(folder_name, 'ASN.txt')
    servers = []
    if os.path.exists:
        with open(file_path, 'r') as file:
            lines = file.readlines()
            for line in lines:
                servers.append(line)
        return servers
    else:
        return None
@bot.tree.command(name="server_add", description="register a server with ASN")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
@commands.is_owner()
async def allow_server(interaction: discord.Interaction):
    folder_name = 'allowed_server'
    os.makedirs(folder_name, exist_ok=True)
    file_path = os.path.join(folder_name, 'ASN.txt')
    if os.path.exists:
        with open(file_path, 'a') as file:
            file.write(f'{interaction.guild.id}\n')
    else:
        with open(file_path, 'w') as file:
            file.write(f'{interaction.guild.id}\n')
    await interaction.response.send_message(f'✅ Successfully registered server {interaction.guild.name} to ASN')

@bot.tree.command(name="update_bal", description="Update bal of a user")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def update_bal(interaction: discord.Interaction, user: discord.User, bal: int):
    if interaction.user.guild_permissions.administrator:
        servers = list(map(int, allowed_server()))
        if interaction.guild.id in servers:
            pass
        else:
            await interaction.response.send_message('Your server is currently not registered with ASN, please register in support server')
            return
        folder_name = 'profile'
        os.makedirs(folder_name, exist_ok=True)
        user_id = user.id
