    @app_commands.command(name="badge", description="Remove a badge from a user")
    @app_commands.guild_install()
    @app_commands.choices(gym_type=badge_choices)
    async def remove_badge(self, interaction: discord.Interaction, member: discord.User, gym_type: str, global_badge: bool = True):
        """Removes a gym badge from a user. Only admins or the gym leader of the type can remove badges."""
        guild_id = interaction.guild.id
        gym_table = f"gym_{guild_id}"
        badge_table = f"badges_{guild_id}"
        gym_leaders_table = f"gym_leaders_{guild_id}"

        conn = get_db_connection()
        cursor = conn.cursor()

        # Fetch gym details
        cursor.execute(f"SELECT gym_id FROM {gym_table} WHERE type = ?", (gym_type,))
        gym = cursor.fetchone()

        if not gym:
            await interaction.response.send_message("❌ Gym type not found.")
            conn.close()
            return

        gym_id = gym[0]

        # Fetch all leader IDs for the gym
        cursor.execute(f"SELECT leader_id FROM {gym_leaders_table} WHERE gym_id = ?", (gym_id,))
        leaders = cursor.fetchall()

        # Check if user is admin or gym leader
        if interaction.user.guild_permissions.administrator or any(leader[0] == interaction.user.id for leader in leaders):
            # Delete badge record
            cursor.execute(f"DELETE FROM {badge_table} WHERE user_id = ? AND gym_id = ?", (member.id, gym_id))

            if global_badge:
                # Optional: Reduce global badge count if leader is verified
                cursor.execute("SELECT 1 FROM certificates WHERE user_id = ? AND achievement = ?", (interaction.user.id, "Verified Gym Leader"))
                verified_leader = cursor.fetchone()
                if verified_leader:
                    cursor.execute("""
                        UPDATE global_badges
                        SET badge_count = badge_count - 1
                        WHERE user_id = ? AND badge_type = ? AND badge_count > 0;
                    """, (member.id, gym_type))

                conn.commit()
            else:
                pass
            await interaction.response.send_message(f"✅ {member.mention}'s {gym_type} Gym badge has been removed.")
        else:
            await interaction.response.send_message("❌ You must be an administrator or the leader of this gym to remove this badge.")
        
        conn.close()

