    @app_commands.command(name="by_id", description="Remove a gym leader by id")
    @app_commands.choices(gym_type=badge_choices)
    async def removebyid(self, interaction: discord.Interaction, gym_type: str, leader_id: str):
        """Removes a gym leader from a specific gym type and adjusts their achievement number."""
        if interaction.user.guild_permissions.manage_roles:
            guild_id = interaction.guild.id
            gym_table = f"gym_{guild_id}"
            gym_leaders_table = f"gym_leaders_{guild_id}"
            server_name = interaction.guild.name
            id = str(leader_id)

            ensure_gym_types(guild_id)  # Ensure gym types exist
            setup_new_badge_tables()
            conn = get_db_connection()
            cursor = conn.cursor()

            # Check if the gym type exists
            cursor.execute(f"SELECT gym_id FROM {gym_table} WHERE type = ?", (gym_type,))
            gym = cursor.fetchone()

            if gym:
                gym_id = gym[0]

                # Remove the leader from the gym_leaders table
                cursor.execute(f"DELETE FROM {gym_leaders_table} WHERE gym_id = ? AND leader_id = ?", (gym_id, id))

                # Fetch the leader's current achievement
                cursor.execute(f"SELECT achievement FROM certificates WHERE user_id = ? AND achievement LIKE 'Gym Leader (%)'", (id,))
                leader_achievement = cursor.fetchone()

                if leader_achievement:
                    # Extract the current achievement number
                    try:
                        current_num = int(leader_achievement[0].split("Gym Leader (")[1].split(")")[0])
                        # If their current achievement is Gym Leader (X), decrement it by 1
                        if current_num > 1:
                            new_achievement = f"Gym Leader ({current_num - 1})"
                            cursor.execute("""
                                UPDATE certificates
                                SET achievement = ?
                                WHERE user_id = ? AND achievement = ?
                            """, (new_achievement, id, leader_achievement[0]))
                        else:
                            # If the leader was on Gym Leader (1), just remove the achievement
                            cursor.execute("""
                                DELETE FROM certificates WHERE user_id = ? AND achievement = ?
                            """, (id, leader_achievement[0]))

                    except Exception as e:
                        cursor.execute("""
                                DELETE FROM certificates WHERE user_id = ? AND achievement = ?
                            """, (id, leader_achievement[0]))

                # Commit the changes
                conn.commit()
                conn.close()

                await interaction.response.send_message(f"✅ {id} (<@{id}>) has been removed as the leader of the {gym_type} Gym and their achievement has been adjusted.")
            else:
                conn.close()
                await interaction.response.send_message(f"❌ Gym type `{gym_type}` not found. Ensure it exists in this server!")
        else:
            await interaction.response.send_message(f"❌ You don't have permission (Manage Roles) to remove leader.")
