async def build_gymstats_embed(interaction: discord.Interaction, leader: discord.User):
    guild_id = interaction.guild.id
    gym_leaders_table = f"gym_leaders_{guild_id}"

    conn = get_db_connection()
    cursor = conn.cursor()

    cursor.execute(f"""
        SELECT display_name, wins, losses
        FROM {gym_leaders_table}
        WHERE leader_id = ?
    """, (leader.id,))
    row = cursor.fetchone()
    conn.close()

    if not row:
        embed = discord.Embed(
            title="Error",
            description=f"{leader.mention} is not a gym leader.",
            color=discord.Color.red()
        )
        return embed

    display_name, wins, losses = row
    total = wins + losses
    win_rate = (wins / total * 100) if total > 0 else 0

    # Custom Pokémon logic (IDENTICAL to your code)
    conn2 = connect_poke_db()
    c2 = conn2.cursor()
    row2 = c2.execute(
        "SELECT custom_pokemon FROM poke WHERE player_id=?",
        (leader.id,)
    ).fetchone()
    conn2.close()

    sprite_url = None
    leader_pokemon_name = None

    if row2 and row2[0]:
        poke_name = row2[0]
        file_path = os.path.join(pokemon_data_folder, f"{poke_name.lower()}.json")

        if os.path.exists(file_path):
            with open(file_path, "r") as f:
                poke_data = json.load(f)

            sprite_url = poke_data["sprites"].get("default_front")
            leader_pokemon_name = poke_data["name"]

    embed = discord.Embed(
        title=f"🏅 Gym Leader Stats - {leader.mention}",
        description=f"Custom Pokemon: {leader_pokemon_name}\nDisplay name: {leader.display_name}",
        color=discord.Color.random()
    )
    embed.add_field(name="📈 Wins", value=str(wins), inline=True)
    embed.add_field(name="📉 Losses", value=str(losses), inline=True)
    embed.add_field(name="🔥 Win Rate", value=f"{win_rate:.2f}%", inline=True)

    if sprite_url:
        embed.set_thumbnail(url=sprite_url)
    else:
        if interaction.guild.icon:
            embed.set_thumbnail(url=interaction.guild.icon.url)

    return embed

