@bot.command()
async def badges(ctx, member: discord.Member = None):
    """Displays all badges a user has earned in a styled embed."""
    if member is None:
        member = ctx.author

    try:
        guild_id = ctx.guild.id
        gym_table = f"gym_{guild_id}"
        badge_table = f"badges_{guild_id}"

        conn = get_db_connection()
        cursor = conn.cursor()

        # Fetch earned badges
        cursor.execute(f'''
            SELECT g.type FROM {badge_table} AS b
            JOIN {gym_table} AS g ON b.gym_id = g.gym_id
            WHERE b.user_id = ?
        ''', (member.id,))
        badges_list = {row[0] for row in cursor.fetchall()}
    except Exception as e:
        badges_list = {}

    # Fetch all possible badges with their emojis
    cursor.execute("SELECT gym_type, emoji FROM badge_emojis")
    all_badges = {row[0]: row[1] for row in cursor.fetchall()}  # Store as dictionary

    conn.close()

    # Define all 18 standard badge types
    standard_types = [
        "Normal", "Fire", "Water", "Electric", "Grass", "Ice",
        "Fighting", "Poison", "Ground", "Flying", "Psychic", "Bug",
        "Rock", "Ghost", "Dragon", "Dark", "Steel", "Fairy"
    ]

    # Prepare badge display
    badge_display = ""
    for badge_type in standard_types:
        emoji = all_badges.get(badge_type, "?")  # Get emoji or default to ❌
        if badge_type in badges_list:
            badge_display += emoji  # User owns the badge
        else:
            badge_display += "❌"  # User is missing the badge
    # Embed styling
    embed = discord.Embed(
        title=f"{member.display_name}'s Gym Badges",
        color=discord.Color.dark_red()
    )
    embed.add_field(name="User ID:", value=f"{member.mention} `{member.id}`", inline=False)
    embed.add_field(name="Server:", value=ctx.guild.name, inline=False)
    embed.add_field(name="Collection", value=badge_display, inline=False)
    rank, total = get_gym_rank(ctx.author.id, ctx.guild.id)
    embed.set_footer(text=f"Rank: {rank}/{total}")

    view = EliteBadgeView(member)

    await ctx.send(embed=embed, view=view)   

class EliteBadgeView(discord.ui.View):
    def __init__(self, member: discord.User):
        super().__init__(timeout=None)  # Persistent if desired
        self.member = member

    @discord.ui.button(label="Show Elite Badges", style=discord.ButtonStyle.red, emoji="🏅")
    async def show_elite_badges(self, interaction: discord.Interaction, button: discord.ui.Button):
        conn = get_db_connection()
        cursor = conn.cursor()

        # Fetch all elite badges for this guild
        cursor.execute("""
            SELECT badge_name, emoji FROM elite_badges
            WHERE guild_id = ?;
        """, (interaction.guild.id,))
        all_badges = cursor.fetchall()  # List of (badge_name, emoji)

        # Fetch badges that the user owns
        cursor.execute("""
            SELECT e.badge_name, e.emoji
            FROM user_elite_badges AS p
            JOIN elite_badges AS e ON p.badge_id = e.id
            WHERE p.guild_id = ? AND p.user_id = ?;
        """, (interaction.guild.id, self.member.id))
        user_badges = cursor.fetchall()  # List of (badge_name, emoji)
        conn.close()

        # Create a dictionary for easy lookup
        user_badge_names = {name for name, _ in user_badges}

        badge_display = ""
        for name, emoji in all_badges:
            if name in user_badge_names:
                badge_display += f"{emoji}"  # user owns it
            else:
                badge_display += "❌"  # missing

        if not all_badges:
            badge_display = "No elite badges exist in this server."
        
        print(badge_display)

        embed = discord.Embed(
            title=f"{self.member.display_name}'s Elite Badges",
            color=discord.Color.gold()
        )
        embed.add_field(name="User ID:", value=f"{self.member.mention} `{self.member.id}`", inline=False)
        embed.add_field(name="Server:", value=interaction.guild.name, inline=False)
        embed.add_field(name="Collection", value=badge_display, inline=False)

        await interaction.message.edit(embed=embed)

