class GlobalBadgePaginationView(discord.ui.View):
    def __init__(self, member: discord.User, data: list):
        super().__init__(timeout=120)
        self.member = member
        self.data = data
        self.page = 0
        self.per_page = 5

    def build_embed(self):
        start = self.page * self.per_page
        end = start + self.per_page

        embed = discord.Embed(
            title=f"{self.member.display_name}'s Badges Across All Gym Servers",
            color=discord.Color.dark_red()
        )

        for server_name, badges in self.data[start:end]:
            embed.add_field(
                name=server_name,
                value=badges,
                inline=False
            )

        max_page = (len(self.data) - 1) // self.per_page + 1
        embed.set_footer(text=f"Page {self.page + 1}/{max_page}")
        return embed

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        return interaction.user.id == self.member.id

    @discord.ui.button(label="◀", style=discord.ButtonStyle.secondary)
    async def previous(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page > 0:
            self.page -= 1
            await interaction.response.edit_message(embed=self.build_embed(), view=self)
        else:
            await interaction.response.defer()

    @discord.ui.button(label="▶", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, button: discord.ui.Button):
        max_page = (len(self.data) - 1) // self.per_page
        if self.page < max_page:
            self.page += 1
            await interaction.response.edit_message(embed=self.build_embed(), view=self)
        else:
            await interaction.response.defer()

@bot.tree.command(name="gym_history", description="Show all your gym badges across all servers")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def gym_history(interaction: discord.Interaction, member: discord.User = None):
    if member is None:
        member = interaction.user

    conn = get_db_connection()
    cursor = conn.cursor()

    # Load badge emoji map
    cursor.execute("SELECT gym_type, emoji FROM badge_emojis")
    badge_emojis = {row[0]: row[1] for row in cursor.fetchall()}

    standard_types = [
        "Normal", "Fire", "Water", "Electric", "Grass", "Ice",
        "Fighting", "Poison", "Ground", "Flying", "Psychic", "Bug",
        "Rock", "Ghost", "Dragon", "Dark", "Steel", "Fairy"
    ]

    server_badges = []

    # Iterate through all guilds the bot is in
    for guild in bot.guilds:
        if guild.get_member(member.id) is None:
            continue
        guild_id = guild.id
        gym_table = f"gym_{guild_id}"
        badge_table = f"badges_{guild_id}"

        try:
            cursor.execute(f"""
                SELECT g.type FROM {badge_table} b
                JOIN {gym_table} g ON b.gym_id = g.gym_id
                WHERE b.user_id = ?
            """, (member.id,))

            owned = {row[0] for row in cursor.fetchall()}
            if not owned:
                continue

            badge_row = ""
            for t in standard_types:
                badge_row += badge_emojis.get(t, "❌") if t in owned else "❌"

            server_badges.append((guild.name, badge_row))

        except Exception:
            continue

    conn.close()

    if not server_badges:
        await interaction.response.send_message(
            "❌ You don’t have any gym badges on any server yet.",
            ephemeral=True
        )
        return

    view = GlobalBadgePaginationView(member, server_badges)
    embed = view.build_embed()

    await interaction.response.send_message(embed=embed, view=view)

