    @discord.ui.button(label="Gamble Profile", style=discord.ButtonStyle.green)
    async def gamble(self, interaction: discord.Interaction, button: discord.ui.Button):
        folder_name = 'profile'
        user_id = self.member.id
        file_path = os.path.join(folder_name, f'{user_id}.txt')
        if os.path.exists(file_path):
            with open(file_path, 'r') as file:
                lines = file.readlines()
                bal = lines[0].strip()
                debt = lines[1].strip()
                win = lines[2].strip()
                total = lines[3].strip()
        else:
            await interaction.response.send_message('Player has not registered with the bot yet\nYour will get a profile once you gambled at least once', ephemeral=True)
        if not bal:
            bal = 0
        if 1000000 > int(bal) > -1:
            ac = 'Novice'
        elif 10000000 > int(bal) > 999999:
            ac = 'Winner of Many Battles'
        elif 100000000 > int(bal) > 9999999:
            ac = 'King of Games'
        elif 1000000000 > int(bal) > 99999999:
            ac = 'God of Cards'
        elif -1000000 < int(bal) < 0:
            ac = 'Unlucky'
        elif -10000000 < int(bal) < -999999:
            ac = 'Loser of Many Battles'
