        member = self.member
        #Code Block for duel profile
        if interaction.guild:
            guild_id = interaction.guild.id
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute("SELECT gym_type, emoji FROM badge_emojis")
