            global_badge_text = " ".join([f"{badge_emojis.get(badge_type, '❔')} x{count}" for badge_type, count in global_badges]) if global_badges else "❌ No global badges"
            server_badge_text = " ".join([f"{badge_emojis.get(badge_type, '❔')} " for badge_type in server_badges]) if server_badges else "❌ No server badges"
