class ProfileView(View):
    def __init__(self, member):
        super().__init__()
        self.member = member
    @discord.ui.button(label="Clan Profile", style=discord.ButtonStyle.green)
    async def clan(self, interaction: discord.Interaction, button: discord.ui.Button):
        conn = get_db_connection(interaction.guild.id)
        c = conn.cursor()
        target = self.member
        user_id = str(target.id)
        # Get profile data and clan name from clan_members
        c.execute("""
            SELECT p.wins, p.losses, p.total, p.win_rate,
                COALESCE(cm.clan_name, 'No Clan') as clan_name
            FROM profile1 p
            LEFT JOIN clan_members cm ON p.user_id = cm.user_id
            WHERE p.user_id = ?
        """, (user_id,))
        row = c.fetchone()

        if not row:
            return await interaction.response.send_message(f"No profile found for <@{user_id}>.", ephemeral=True)

        wins, losses, total, win_rate, clan_name = row

        # Get highest role excluding @everyone
        roles = [role for role in target.roles if role != interaction.guild.default_role]
        highest_role = max(roles, key=lambda r: r.position).mention if roles else "—"

        rank = get_user_rank(int(interaction.guild.id), int(user_id))
        if rank == 'King':
            hex_code = "#CFA109"  
            color = discord.Color(int(hex_code.lstrip("#"), 16))
        elif rank == 'Duke' or rank == 'Marquis':
            hex_code = "#0110B0"  
            color = discord.Color(int(hex_code.lstrip("#"), 16))
        elif rank == 'Count' or rank == 'Viscount':
            hex_code = "#3BF08C"  
            color = discord.Color(int(hex_code.lstrip("#"), 16))
        elif rank == 'Baron' or rank == 'Knight':
            hex_code = "#2BEDED"  
            color = discord.Color(int(hex_code.lstrip("#"), 16))
        else:
            color = discord.Color.orange()
        embed = discord.Embed(
            title=f"Profile Information – {target.display_name}",
            color=color
        )
        embed.set_thumbnail(url=target.display_avatar.url)
        embed.add_field(name="__**Clan**__", value=f"`{clan_name}`", inline=False)
        embed.add_field(name="__**Win Rate**__", value=f"`{win_rate:.2%}`", inline=False)
        embed.add_field(name="__**Server Role**__", value=highest_role, inline=False)
        embed.add_field(name="__**Rank**__", value=get_user_rank(int(interaction.guild.id), int(user_id)), inline=False)
        embed.add_field(
            name="__**General Stats**__",
            value=f"__**Wins**__: `{wins}` | __**Losses**__: `{losses}` | **Total**: `{total}`",
            inline=False
        )
        conn_ach = get_db_connection()
        cursor_ach = conn_ach.cursor()
        cursor_ach.execute("SELECT achievement FROM certificates WHERE user_id = ?", (user_id,))
        achievements = cursor_ach.fetchall()
        conn_ach.close()
        if achievements:
            badge_list = "|".join(get_emoji_for_achievement(ach[0]) for ach in achievements)
        else:
            badge_list = "N/A"
        embed.add_field(name = '__**Achievements:**__', value = badge_list, inline = False)
        await interaction.response.edit_message(embed=embed) 
