def setup_achievement_permissions():
    """Creates the table for storing achievement permissions."""
    conn = get_db_connection()
    cursor = conn.cursor()

    cursor.execute("""
    CREATE TABLE IF NOT EXISTS achievement_permissions (
        granting_achievement TEXT,  -- The achievement that grants permission
        awarded_achievement TEXT     -- The achievement that can be awarded
    );
    """)

    conn.commit()
    conn.close()

setup_achievement_permissions()

@bot.command()
@commands.is_owner()
async def grantpermission(ctx, *, achievements: str):
    """Allows holders of `granter` achievement to award `awarded` achievement."""
    # Split the achievements string into granter and awarded
    try:
        granter, awarded = [achievement.strip() for achievement in achievements.split(',')]
    except ValueError:
        await ctx.send("❌ Please provide both granter and awarded achievements separated by a comma.")
        return

    # Ensure achievements are case-insensitive by converting them to lowercase
    granter_lower = granter.lower()
    awarded_lower = awarded.lower()

    conn = get_db_connection()
    cursor = conn.cursor()

    cursor.execute("""
    INSERT INTO achievement_permissions (granting_achievement, awarded_achievement)
    VALUES (?, ?)
    ON CONFLICT DO NOTHING;
    """, (granter_lower, awarded_lower))

    conn.commit()
    conn.close()

    await ctx.send(f"✅ Holders of **{granter}** can now award **{awarded}**!")
@bot.command()
@commands.is_owner()
async def revokegrant(ctx, *, achievements: str):
    """Revokes permission for holders of a specific achievement to award another achievement."""
    try:
        granter, awarded = [achievement.strip() for achievement in achievements.split(',')]
    except ValueError:
        await ctx.send("❌ Please provide both granter and awarded achievements separated by a comma.")
        return

    granter_lower = granter.lower()
    awarded_lower = awarded.lower()

    conn = get_db_connection()
    cursor = conn.cursor()

    cursor.execute("""
        DELETE FROM achievement_permissions
        WHERE granting_achievement = ? AND awarded_achievement = ?
    """, (granter_lower, awarded_lower))

    conn.commit()
    conn.close()

    await ctx.send(f"❌ Holders of **{granter}** can no longer award **{awarded}**.")

@bot.command()
async def listpermissions(ctx):
    """Lists all achievement permissions."""
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT granting_achievement, awarded_achievement FROM achievement_permissions")
    permissions = cursor.fetchall()
    conn.close()
    if not permissions:
        await ctx.send("📜 No achievement award permissions set.")
        return
    perm_text = "\n".join([f"{get_emoji_for_achievement(grant.title())} **{grant.title()}** → {get_emoji_for_achievement(award.title())} **{award.title()}**" for grant, award in permissions])
    embed = discord.Embed(
        title="🏅 Achievement Award Permissions",
        description=perm_text,
        color=discord.Color.blue()
    )
    await ctx.send(embed=embed)
