def get_number(achievement):
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT COUNT(*) FROM certificates WHERE achievement = ?", (achievement,))
    count = cursor.fetchone()[0]
    conn.close()
    return count

