class AchievementsPaginator(View):
    def __init__(self, pages: list[list[str]]):
        super().__init__(timeout=None)
        self.pages = pages
        self.current_page = 0
        self.message = None

    async def update_page(self, interaction: discord.Interaction):
        embed = discord.Embed(
            title="🏆 All Achievements",
            description="\n".join(self.pages[self.current_page]),
            color=discord.Color.gold()
        )
        embed.set_footer(text=f"Page {self.current_page + 1}/{len(self.pages)}")
        await interaction.response.edit_message(embed=embed, view=self)

    @discord.ui.button(label="⏮️", style=discord.ButtonStyle.secondary)
    async def first(self, interaction: discord.Interaction, button: discord.Button):
        self.current_page = 0
        await self.update_page(interaction)

    @discord.ui.button(label="◀️", style=discord.ButtonStyle.secondary)
    async def previous(self, interaction: discord.Interaction, button: discord.Button):
        self.current_page = max(0, self.current_page - 1)
        await self.update_page(interaction)

    @discord.ui.button(label="▶️", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, button: discord.Button):
        self.current_page = min(len(self.pages) - 1, self.current_page + 1)
        await self.update_page(interaction)

    @discord.ui.button(label="⏭️", style=discord.ButtonStyle.secondary)
    async def last(self, interaction: discord.Interaction, button: discord.Button):
        self.current_page = len(self.pages) - 1
        await self.update_page(interaction)

@bot.tree.command(name="achievement_list", description="List all achievements and how many users have them")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def list_all_achievements(interaction: discord.Interaction):
    await interaction.response.defer()
    achievement_names = ACH_NAMES

    lines = []
    for name in achievement_names:
        emoji = get_emoji_for_achievement(name)  # You must define this
        count = get_number(name)  # You must define this
        lines.append(f"{emoji} **{name}** — `{count}` users")

    # Split into chunks of 20 lines per page
    page_size = 20
    pages = [lines[i:i + page_size] for i in range(0, len(lines), page_size)]

    embed = discord.Embed(
        title="🏆 All Achievements",
        description="\n".join(pages[0]),
        color=discord.Color.gold()
    )
    embed.set_footer(text=f"Page 1/{len(pages)}")

    view = AchievementsPaginator(pages)
    await interaction.followup.send(embed=embed, view=view)

@bot.command()
@commands.has_permissions(administrator=True)  # Restrict this to bot owner only
async def verify_server(ctx, member: discord.Member):
    """Set a host for this server."""
    conn = get_db_connection()
    cursor = conn.cursor()

    # Check if the host is already set for this server
    cursor.execute("SELECT host_id FROM server_hosts WHERE guild_id = ?", (ctx.guild.id,))
    existing_host = cursor.fetchone()

    if existing_host:
        await ctx.send("🚫 This server already has a host.")
    else:
        # Set the host for this server
        cursor.execute("INSERT INTO server_hosts (guild_id, host_id) VALUES (?, ?)", (ctx.guild.id, member.id))
        conn.commit()
        await ctx.send(f"✅ **{member.display_name}** is now set as the host for this server!")

    conn.close()       

@bot.command()
@commands.has_permissions(administrator=True)
async def rach(ctx, member: discord.Member):
    """Resets all achievements for a user."""
    conn = get_db_connection()
    cursor = conn.cursor()

    # Check if the member has any achievements
    cursor.execute("SELECT achievement FROM certificates WHERE user_id = ?", (member.id,))
    achievements = cursor.fetchall()

    if not achievements:
        await ctx.send(f"❌ {member.display_name} does not have any achievements to reset.")
        conn.close()
        return

    # Delete all achievements from the database
    cursor.execute("DELETE FROM certificates WHERE user_id = ?", (member.id,))
    conn.commit()
    conn.close()

    await ctx.send(f"✅ All achievements for {member.display_name} have been reset.") 

@bot.tree.command(name="set_rules", description="Set rules for a gym leader")
@app_commands.guild_install()
@app_commands.choices(gym_type=badge_choices)
async def set_rules(interaction: discord.Interaction, gym_type: str, rules: str):
    """Sets the rules for a gym leader and saves them in a .txt file."""
    # Make sure the 'leader rules' folder exists
    if not os.path.exists('leader rules'):
        os.makedirs('leader rules')

    # Construct the file path using the gym type and leader's ID
    leader_id = interaction.user.id
    file_name = f"leader rules/{gym_type}_{leader_id}.txt"

    # Write the rules to the file, preserving formatting
    with open(file_name, 'w', encoding='utf-8') as file:
        file.write(rules)

    await interaction.response.send_message(f"✅ Rules for the {gym_type} Gym Leader have been set!")

