@bot.command(name="tournament_switch")
@commands.has_permissions(manage_guild=True)
async def tournament_switch(ctx, tournament_slug: str = None):
    setup_tournament_db()
    if not CHALLONGE_API_KEY or not CHALLONGE_USERNAME:
        return await ctx.send("❌ Challonge credentials are not configured.")
    imported = 0
    failed = []
    try:
        if tournament_slug:
            try:
                tid, pcount, mcount = _import_challonge_tournament_to_local(tournament_slug.strip().lower())
                imported += 1
                await ctx.send(f"✅ Imported `{tournament_slug}` -> tournament_id `{tid}` ({pcount} participants, {mcount} matches).")
            except Exception as e:
                await ctx.send(f"❌ Failed to import `{tournament_slug}`: {e}")
            return

        page = 1
        while True:
            res = requests.get(
                "https://api.challonge.com/v1/tournaments.json",
                params={"api_key": CHALLONGE_API_KEY, "page": page},
                auth=(CHALLONGE_API_KEY, CHALLONGE_USERNAME),
                headers={"User-Agent": "Mozilla/5.0"},
                timeout=25,
            )
            res.raise_for_status()
            batch = res.json()
            if not batch:
                break
            for wrapped in batch:
                t = wrapped.get("tournament", wrapped)
                slug = str(t.get("url") or "").strip().lower()
                if not slug:
                    continue
                try:
                    _import_challonge_tournament_to_local(slug)
                    imported += 1
                except Exception as e:
                    failed.append(f"{slug}: {e}")
            page += 1
            if len(batch) < 50:
                break
    except Exception as e:
        return await ctx.send(f"❌ Failed to fetch Challonge tournaments: {e}")

    msg = f"✅ Imported **{imported}** tournament(s) from Challonge into `tournament.db`."
    if failed:
        preview = "\n".join(failed[:5])
        msg += f"\n⚠️ Failed: {len(failed)}\n{preview}"
    await ctx.send(msg)

