### Auction
MIN_BID_INCREMENT = 1000  # Minimum difference between bids
AUCTION_DEFAULT_BASE_PRICE = 1000
AUCTION_DEFAULT_INCREMENT = MIN_BID_INCREMENT
AUCTION_DEFAULT_TIMER_SECS = 60

# --- Database Initialization ---
def init_db(guild_id):
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        db.execute("""
            CREATE TABLE IF NOT EXISTS auctions (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                item TEXT,
                starting_bid INTEGER,
                highest_bid INTEGER,
                highest_bidder TEXT,
                ends_at TEXT,
                ended INTEGER DEFAULT 0,
                image_url TEXT,
                channel_id TEXT
            )
        """)
        db.execute("""
            CREATE TABLE IF NOT EXISTS bids (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                auction_id INTEGER,
                user_id TEXT,
                amount INTEGER,
                bid_time TEXT
            )
        """)
        db.execute("""
            CREATE TABLE IF NOT EXISTS auction_config (
                id INTEGER PRIMARY KEY CHECK (id = 1),
                countdown_reset_seconds INTEGER DEFAULT 20
            )
        """)
        db.execute("INSERT OR IGNORE INTO auction_config (id) VALUES (1)")
        db.commit()
    migrate_auction_db(get_auc_db_file(guild_id), str(guild_id))

def _ensure_column(db, table: str, column: str, definition: str):
    cursor = db.cursor()
    cursor.execute(f"PRAGMA table_info({table})")
    cols = [row[1] for row in cursor.fetchall()]
    if column not in cols:
        cursor.execute(f"ALTER TABLE {table} ADD COLUMN {column} {definition}")
        db.commit()

def migrate_auction_db(db_path: str, guild_id: str = None):
    if not os.path.exists(db_path):
        return
    with sqlite3.connect(db_path) as db:
        # Settings
        db.execute("""
            CREATE TABLE IF NOT EXISTS guild_settings (
                guild_id TEXT PRIMARY KEY,
                sold_log TEXT,
                unsold_log TEXT,
                auction_ch TEXT,
                base_price INTEGER DEFAULT 100,
                increment INTEGER DEFAULT 10,
                timer_secs INTEGER DEFAULT 10,
                prefix TEXT DEFAULT '!',
                wallet_required INTEGER DEFAULT 0
            )
        """)
        _ensure_column(db, "guild_settings", "wallet_required", "INTEGER DEFAULT 0")
        _ensure_column(db, "guild_settings", "prefix", "TEXT DEFAULT '!'")
        _ensure_column(db, "guild_settings", "base_price", "INTEGER DEFAULT 100")
        _ensure_column(db, "guild_settings", "increment", "INTEGER DEFAULT 10")
        _ensure_column(db, "guild_settings", "timer_secs", "INTEGER DEFAULT 10")

        # Auctioneers
        db.execute("""
            CREATE TABLE IF NOT EXISTS auctioneers (
                guild_id TEXT,
                user_id TEXT,
                PRIMARY KEY (guild_id, user_id)
            )
        """)

        # Wallets
        db.execute("""
            CREATE TABLE IF NOT EXISTS wallets (
                guild_id TEXT,
                user_id TEXT,
                balance INTEGER DEFAULT 0,
                PRIMARY KEY (guild_id, user_id)
            )
        """)

        # Inventory
        db.execute("""
            CREATE TABLE IF NOT EXISTS auction_inventory (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                guild_id TEXT,
                user_id TEXT,
                item_name TEXT,
                amount_paid INTEGER,
                won_at TEXT
            )
        """)

        # Auction queue
        db.execute("""
            CREATE TABLE IF NOT EXISTS auction_queue (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                guild_id TEXT,
                item_name TEXT,
                base_price_override INTEGER DEFAULT NULL,
                position INTEGER
            )
        """)

        # Bid log (optional, separate from bids)
        db.execute("""
            CREATE TABLE IF NOT EXISTS bid_log (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                guild_id TEXT,
                auction_id INTEGER,
                user_id TEXT,
                amount INTEGER,
                placed_at TEXT
            )
        """)

        # Ensure guild settings row
        if guild_id:
            prefix = prefixes.get(str(guild_id), "!")
            db.execute("""
                INSERT OR IGNORE INTO guild_settings
                (guild_id, base_price, increment, timer_secs, prefix, wallet_required)
                VALUES (?, ?, ?, ?, ?, 0)
            """, (str(guild_id), AUCTION_DEFAULT_BASE_PRICE, AUCTION_DEFAULT_INCREMENT, AUCTION_DEFAULT_TIMER_SECS, prefix))
        db.commit()

def migrate_all_auction_dbs():
    os.makedirs("auction_data", exist_ok=True)
    for filename in os.listdir("auction_data"):
        if not filename.endswith("_auctions.db"):
            continue
        guild_id = filename.replace("_auctions.db", "")
        db_path = os.path.join("auction_data", filename)
        migrate_auction_db(db_path, guild_id)

def ensure_guild_settings(guild_id: str):
    init_db(guild_id)

def get_guild_settings_sync(guild_id: str) -> dict:
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute("""
            SELECT sold_log, unsold_log, auction_ch, base_price, increment, timer_secs, prefix, wallet_required
            FROM guild_settings WHERE guild_id = ?
        """, (str(guild_id),))
        row = cursor.fetchone()
    if not row:
        return {}
    return {
        "sold_log": row[0],
        "unsold_log": row[1],
        "auction_ch": row[2],
        "base_price": row[3],
        "increment": row[4],
        "timer_secs": row[5],
        "prefix": row[6],
        "wallet_required": int(row[7] or 0),
    }

def set_guild_setting_sync(guild_id: str, field: str, value):
    allowed = {"sold_log", "unsold_log", "auction_ch", "base_price", "increment", "timer_secs", "prefix", "wallet_required"}
    if field not in allowed:
        return False
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        db.execute(f"UPDATE guild_settings SET {field} = ? WHERE guild_id = ?", (value, str(guild_id)))
        db.commit()
    return True

def get_auctioneers_sync(guild_id: str) -> list:
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute("SELECT user_id FROM auctioneers WHERE guild_id = ?", (str(guild_id),))
        rows = cursor.fetchall()
    return [r[0] for r in rows]

def add_auctioneer_sync(guild_id: str, user_id: str):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        db.execute("INSERT OR IGNORE INTO auctioneers (guild_id, user_id) VALUES (?, ?)", (str(guild_id), str(user_id)))
        db.commit()

def remove_auctioneer_sync(guild_id: str, user_id: str):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        db.execute("DELETE FROM auctioneers WHERE guild_id = ? AND user_id = ?", (str(guild_id), str(user_id)))
        db.commit()

def get_balance_sync(guild_id: str, user_id: str) -> int:
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute("SELECT balance FROM wallets WHERE guild_id = ? AND user_id = ?", (str(guild_id), str(user_id)))
        row = cursor.fetchone()
    return int(row[0]) if row else 0

def set_balance_sync(guild_id: str, user_id: str, amount: int):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        db.execute(
            "INSERT OR REPLACE INTO wallets (guild_id, user_id, balance) VALUES (?, ?, ?)",
            (str(guild_id), str(user_id), max(0, int(amount)))
        )
        db.commit()

def add_balance_sync(guild_id: str, user_id: str, amount: int):
    current = get_balance_sync(guild_id, user_id)
    set_balance_sync(guild_id, user_id, current + int(amount))

def remove_balance_sync(guild_id: str, user_id: str, amount: int):
    current = get_balance_sync(guild_id, user_id)
    set_balance_sync(guild_id, user_id, current - int(amount))

def add_to_auction_inventory_sync(guild_id: str, user_id: str, item_name: str, amount_paid: int):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        db.execute(
            "INSERT INTO auction_inventory (guild_id, user_id, item_name, amount_paid, won_at) VALUES (?, ?, ?, ?, ?)",
            (str(guild_id), str(user_id), item_name, int(amount_paid), datetime.now(timezone.utc).isoformat())
        )
        db.commit()

def get_auction_inventory_sync(guild_id: str, user_id: str) -> list:
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute(
            "SELECT item_name, amount_paid, won_at FROM auction_inventory WHERE guild_id = ? AND user_id = ? ORDER BY won_at DESC",
            (str(guild_id), str(user_id))
        )
        rows = cursor.fetchall()
    return rows or []

def add_to_auction_queue_sync(guild_id: str, item_name: str, base_price_override: int = None):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute("SELECT MAX(position) FROM auction_queue WHERE guild_id = ?", (str(guild_id),))
        row = cursor.fetchone()
        next_pos = (row[0] or 0) + 1 if row else 1
        cursor.execute(
            "INSERT INTO auction_queue (guild_id, item_name, base_price_override, position) VALUES (?, ?, ?, ?)",
            (str(guild_id), item_name, base_price_override, next_pos)
        )
        db.commit()

def get_auction_queue_sync(guild_id: str) -> list:
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute(
            "SELECT id, item_name, base_price_override, position FROM auction_queue WHERE guild_id = ? ORDER BY position",
            (str(guild_id),)
        )
        rows = cursor.fetchall()
    return rows or []

def remove_from_auction_queue_sync(guild_id: str, queue_id: int):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute("SELECT position FROM auction_queue WHERE id = ? AND guild_id = ?", (queue_id, str(guild_id)))
        row = cursor.fetchone()
        if not row:
            return
        position = row[0]
        cursor.execute("DELETE FROM auction_queue WHERE id = ? AND guild_id = ?", (queue_id, str(guild_id)))
        cursor.execute(
            "UPDATE auction_queue SET position = position - 1 WHERE guild_id = ? AND position > ?",
            (str(guild_id), position)
        )
        db.commit()

def clear_auction_queue_sync(guild_id: str):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        db.execute("DELETE FROM auction_queue WHERE guild_id = ?", (str(guild_id),))
        db.commit()

def move_auction_queue_item_sync(guild_id: str, from_pos: int, to_pos: int):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute(
            "SELECT id FROM auction_queue WHERE guild_id = ? AND position = ?",
            (str(guild_id), from_pos)
        )
        row = cursor.fetchone()
        if not row:
            return
        item_id = row[0]
        if from_pos < to_pos:
            cursor.execute(
                "UPDATE auction_queue SET position = position - 1 WHERE guild_id = ? AND position > ? AND position <= ?",
                (str(guild_id), from_pos, to_pos)
            )
        else:
            cursor.execute(
                "UPDATE auction_queue SET position = position + 1 WHERE guild_id = ? AND position >= ? AND position < ?",
                (str(guild_id), to_pos, from_pos)
            )
        cursor.execute("UPDATE auction_queue SET position = ? WHERE id = ?", (to_pos, item_id))
        db.commit()

def get_first_auction_queue_item_sync(guild_id: str):
    ensure_guild_settings(guild_id)
    with sqlite3.connect(get_auc_db_file(guild_id)) as db:
        cursor = db.cursor()
        cursor.execute(
            "SELECT id, item_name, base_price_override FROM auction_queue WHERE guild_id = ? ORDER BY position LIMIT 1",
            (str(guild_id),)
        )
        return cursor.fetchone()

async def is_auction_manager_check(ctx):
    if not ctx.guild:
        return False
    if ctx.author.id in owner_ids:
        return True
    if ctx.author.id == ctx.guild.owner_id:
        return True
    if ctx.author.guild_permissions.manage_messages:
        return True
    auctioneers = get_auctioneers_sync(ctx.guild.id)
    return str(ctx.author.id) in auctioneers
        
# --- Auction Commands ---

def get_auc_db_file(guild_id):
    os.makedirs("auction_data", exist_ok=True)
    return f"auction_data/{guild_id}_auctions.db"

@bot.group(invoke_without_command=True)
async def auction(ctx):
    await ctx.send("Available subcommands: !auction config, !auction setup, !auction queue, !auction inventory, !auction start, !auction pause, !auction resume, !auction end, !auction status, !auction history, !bid")

@auction.command(name = 'config', aliases = ['cooldown','set_countdown'])
@commands.check(is_auction_manager_check)
async def setauctioncountdown(ctx, seconds: int):
    init_db(ctx.guild.id)
    if seconds < 5 or seconds > 300:
        return await ctx.send("Please choose a value between 5 and 300 seconds.")

    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        db.execute("UPDATE auction_config SET countdown_reset_seconds = ? WHERE id = 1", (seconds,))
        db.commit()

    await ctx.send(f"Auction countdown reset threshold set to `{seconds}` seconds.")

def get_countdown_reset_seconds(guild_id):
    try:
        with sqlite3.connect(get_auc_db_file(guild_id)) as db:
            cursor = db.cursor()
            cursor.execute("SELECT countdown_reset_seconds FROM auction_config WHERE id = 1")
            row = cursor.fetchone()
            return row[0] if row else 20
    except Exception as e:
        print(e)
        return 20

@auction.command()
@commands.check(is_auction_manager_check)
async def start(ctx, item: str = None, starting_bid: str = None, duration: str = None, image_url: str = None):
    global auction_tasks

    init_db(ctx.guild.id)

    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        cursor = db.cursor()
        cursor.execute("SELECT id FROM auctions WHERE ended = 0 ORDER BY id DESC LIMIT 1")
        active_auction = cursor.fetchone()

    if active_auction:
        return await ctx.send("An auction is already running in this server!")

    settings = get_guild_settings_sync(ctx.guild.id)
    increment = settings.get("increment") or MIN_BID_INCREMENT
    auction_channel_id = settings.get("auction_ch")

    # If no item provided, try queue
    if not item:
        queued = get_first_auction_queue_item_sync(ctx.guild.id)
        if not queued:
            return await ctx.send("No items in the auction queue.")
        queue_id, queued_item, base_override = queued
        item = queued_item
        starting_bid = str(base_override or settings.get("base_price") or AUCTION_DEFAULT_BASE_PRICE)
        duration = f"{settings.get('timer_secs') or AUCTION_DEFAULT_TIMER_SECS}s"
        remove_from_auction_queue_sync(ctx.guild.id, queue_id)

    if not starting_bid or not duration:
        return await ctx.send("Usage: `!auction start <item> <starting_bid> <duration>` or `!auction start` to use the queue.")

    duration = parse_time_string(duration)
    starting_bid = parse_money_string(starting_bid)
    ends_at = datetime.now(timezone.utc) + timedelta(seconds=duration)

    target_channel = ctx.channel
    if auction_channel_id:
        try:
            target_channel = bot.get_channel(int(auction_channel_id)) or await bot.fetch_channel(int(auction_channel_id))
        except Exception:
            target_channel = ctx.channel

    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        cursor = db.cursor()
        cursor.execute("""
            INSERT INTO auctions (item, starting_bid, highest_bid, ends_at, image_url, channel_id)
            VALUES (?, ?, ?, ?, ?, ?)
        """, (item, starting_bid, starting_bid, ends_at.isoformat(), image_url, target_channel.id))
        db.commit()
        auction_id = cursor.lastrowid

    await target_channel.send(
        f"Auction started for **{item}**!\nStarting bid: `{starting_bid}` coins\nEnds in: {duration} Seconds.\nMinimum bid increment: `{increment}` coins."
    )
    auction_task = asyncio.create_task(auction_timer(auction_id, ctx.guild.id))
    auction_tasks[ctx.guild.id] = auction_task
    auction_paused_remaining.pop(ctx.guild.id, None)

@auction.command()
@commands.check(is_auction_manager_check)
async def pause(ctx):
    if ctx.guild.id in auction_paused_remaining:
        return await ctx.send("Auction is already paused.")

    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        cursor = db.cursor()
        cursor.execute("SELECT id, ends_at FROM auctions WHERE ended = 0 ORDER BY id DESC LIMIT 1")
        row = cursor.fetchone()

    if not row:
        return await ctx.send("No auction is currently running.")

    auction_id, ends_at_str = row
    ends_at = datetime.fromisoformat(ends_at_str)
    remaining = (ends_at - datetime.now(timezone.utc)).total_seconds()
    if remaining <= 0:
        return await ctx.send("Auction is already ending.")

    task = auction_tasks.get(ctx.guild.id)
    if task and not task.done():
        task.cancel()
    auction_tasks.pop(ctx.guild.id, None)

    auction_paused_remaining[ctx.guild.id] = remaining
    await ctx.send(f"Auction paused with `{int(remaining)}` seconds remaining.")

@auction.command()
@commands.check(is_auction_manager_check)
async def resume(ctx):
    remaining = auction_paused_remaining.get(ctx.guild.id)
    if remaining is None:
        return await ctx.send("Auction is not paused.")

    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        cursor = db.cursor()
        cursor.execute("SELECT id, channel_id FROM auctions WHERE ended = 0 ORDER BY id DESC LIMIT 1")
        row = cursor.fetchone()

        if not row:
            auction_paused_remaining.pop(ctx.guild.id, None)
            return await ctx.send("No auction is currently running.")

        auction_id, channel_id = row
        new_ends_at = datetime.now(timezone.utc) + timedelta(seconds=remaining)
        cursor.execute("UPDATE auctions SET ends_at = ? WHERE id = ?", (new_ends_at.isoformat(), auction_id))
        db.commit()

    auction_paused_remaining.pop(ctx.guild.id, None)
    task = asyncio.create_task(auction_timer(auction_id, ctx.guild.id))
    auction_tasks[ctx.guild.id] = task
    await ctx.send(f"Auction resumed with `{int(remaining)}` seconds remaining.")

async def auction_timer(auction_id, guild_id):
    db_path = get_auc_db_file(guild_id)
    countdown_reset = get_countdown_reset_seconds(guild_id)
    announced = False
    channel = None

    while True:
        await asyncio.sleep(1)
        with sqlite3.connect(db_path) as db:
            cursor = db.cursor()
            cursor.execute("SELECT ends_at, channel_id, item, ended, image_url FROM auctions WHERE id = ?", (auction_id,))
            row = cursor.fetchone()

        if not row:
            return  # auction deleted or does not exist

        ends_at_str, channel_id, item, ended, image_url = row
        if ended:
            return  # already ended

        ends_at = datetime.fromisoformat(ends_at_str)
        now = datetime.now(timezone.utc)
        remaining = (ends_at - now).total_seconds()

        if remaining <= 0:
            break
        
        count = 0
        if remaining <= countdown_reset:
            # Final countdown
            channel = await bot.fetch_channel(channel_id)
            for i in range(int(remaining), 0, -1):
                await channel.send(f"Auction ending in `{i}` seconds!")
                count += 1
                if count == 5:
                    if image_url:
                        await channel.send(image_url)
                    count = 0
                await asyncio.sleep(1)
            break

        if not announced and remaining <= 60:
            channel = await bot.fetch_channel(channel_id)
            await channel.send(f"Auction ending in `{int(remaining)}` seconds!")
            announced = True

        await asyncio.sleep(min(5, remaining))

    # End auction
    try:
        if channel is None:
            try:
                channel = bot.get_channel(channel_id)
                if channel is None:
                    channel = await bot.fetch_channel(channel_id)
            except Exception:
                channel = None
        if channel is None:
            return
        await end_auction_internal(auction_id, channel)
    except:
        pass

auction_tasks = {}
auction_paused_remaining = {}
@bot.command(name="reset_all_auctions")
@commands.has_permissions(administrator=True)
async def reset_all_auctions(ctx):
    global auction_tasks
    global auction_paused_remaining

    if ctx.author.id not in owner_ids:
        return

    for guild_id, task in list(auction_tasks.items()):
        task.cancel()
    auction_tasks.clear()
    auction_paused_remaining.clear()

    await ctx.send("All auction tasks have been cancelled and current auctions cleared.")
    
@bot.command()
async def bid(ctx, amount: str):
    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        if ctx.guild.id in auction_paused_remaining:
            return await ctx.send("Auction is currently paused. Use `!auction resume` to continue.")
        amount = parse_money_string(amount)
        cursor = db.cursor()
        cursor.execute("""
            SELECT id, highest_bid, ends_at FROM auctions 
            WHERE ended = 0 ORDER BY id DESC LIMIT 1
        """)
        row = cursor.fetchone()
        if not row:
            return await ctx.send("No active auction found.")

        auction_id, highest_bid, ends_at_str = row
        ends_at = datetime.fromisoformat(ends_at_str)
        settings = get_guild_settings_sync(ctx.guild.id)
        increment = settings.get("increment") or MIN_BID_INCREMENT
        min_required = highest_bid + increment
        if amount < min_required:
            return await ctx.send(f"Your bid must be at least `{increment}` more than `{highest_bid}`. Minimum: `{min_required}`.")
        draft_id = get_active_draft(ctx.guild.id)
        if draft_id:
            with get_draft_db() as db:
                cur = db.cursor()
                cur.execute("""
                    SELECT gold_remaining FROM draft_leaders
                    WHERE draft_id = ? AND leader_id = ?
                """, (draft_id, ctx.author.id))
                row = cur.fetchone()

            if not row:
                return await ctx.send("❌ Only leaders may bid in the draft.")

            if amount > row[0]:
                return await ctx.send(
                    f"❌ You only have `{row[0]}` gold remaining."
                )
        else:
            if settings.get("wallet_required"):
                balance = get_balance_sync(ctx.guild.id, ctx.author.id)
                if amount > balance:
                    return await ctx.send(f"❌ Insufficient auction balance. Your balance: `{balance}`.")

        # Check if auction should be extended
        countdown_reset = get_countdown_reset_seconds(ctx.guild.id)
        remaining = (ends_at - datetime.now(timezone.utc)).total_seconds()

        if 0 < remaining <= countdown_reset:
            new_ends_at = datetime.now(timezone.utc) + timedelta(seconds=countdown_reset)
        else:
            new_ends_at = ends_at
        cursor.execute("""
            INSERT INTO bids (auction_id, user_id, amount, bid_time)
            VALUES (?, ?, ?, ?)
        """, (auction_id, str(ctx.author.id), amount, datetime.now(timezone.utc).isoformat()))

        cursor.execute("""
            UPDATE auctions 
            SET highest_bid = ?, highest_bidder = ?, ends_at = ? 
            WHERE id = ?
        """, (amount, str(ctx.author.id), new_ends_at.isoformat(), auction_id))
        db.commit()

        task = auction_tasks.get(ctx.guild.id)
        if task and not task.done():
            task.cancel()

        new_task = asyncio.create_task(auction_timer(auction_id, ctx.guild.id))
        auction_tasks[ctx.guild.id] = new_task

    await ctx.send(f"{ctx.author.mention} placed a bid of `{amount}` coins!")


@auction.command()
@commands.check(is_auction_manager_check)
async def end(ctx):
    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        cursor = db.cursor()
        cursor.execute("SELECT id, channel_id FROM auctions WHERE ended = 0 ORDER BY id DESC LIMIT 1")
        row = cursor.fetchone()

    if not row:
        return await ctx.send("No auction is currently running.")

    auction_id, channel_id = row

    channel = ctx.channel
    try:
        channel = bot.get_channel(channel_id)
        if channel is None:
            channel = await bot.fetch_channel(channel_id)
    except (discord.NotFound, discord.Forbidden):
        pass  # fallback

    # Cancel auction task if running
    task = auction_tasks.get(ctx.guild.id)
    if task and not task.done():
        task.cancel()
    auction_tasks.pop(ctx.guild.id, None)
    auction_paused_remaining.pop(ctx.guild.id, None)

    await end_auction_internal(auction_id, channel)

async def end_auction_internal(auction_id, channel):
    print("called")
    auction_paused_remaining.pop(channel.guild.id, None)
    settings = get_guild_settings_sync(channel.guild.id)
    with sqlite3.connect(get_auc_db_file(channel.guild.id)) as db:
        cursor = db.cursor()
        cursor.execute("UPDATE auctions SET ended = 1 WHERE id = ?", (auction_id,))
        db.commit()

        cursor.execute("SELECT item, highest_bid, highest_bidder FROM auctions WHERE id = ?", (auction_id,))
        row = cursor.fetchone()

    if not row:
        return

    item, highest_bid, highest_bidder = row
    if highest_bidder:
        msg = f"Auction ended! **{item}** sold for `{highest_bid}` coins to <@{highest_bidder}>."
    else:
        msg = f"Auction ended! No valid bids were placed on **{item}**."
    
    await channel.send(msg)

    try:
        draft_id = get_active_draft(channel.guild.id)
    except:
        draft_id = None

    if draft_id:
        with get_draft_db() as db:
            cur = db.cursor()

            # Fetch the current member for this round
            cur.execute("""
                SELECT current_member FROM draft_state
                WHERE draft_id = ?
            """, (draft_id,))
            current_member_row = cur.fetchone()
            if not current_member_row:
                return
            current_member = current_member_row[0]

            # Remove from draft_pool
            cur.execute("""
                DELETE FROM draft_pool
                WHERE draft_id = ? AND member_id = ?
            """, (draft_id, current_member))
            # If there was a winner
            if highest_bidder:
                cur.execute("""
                    UPDATE draft_leaders
                    SET gold_remaining = gold_remaining - ?
                    WHERE draft_id = ? AND leader_id = ?
                """, (highest_bid, draft_id, int(highest_bidder)))

                cur.execute("""
                    INSERT INTO draft_teams
                    (draft_id, guild_id, leader_id, member_id)
                    VALUES (?, ?, ?, ?)
                """, (draft_id, channel.guild.id, int(highest_bidder), current_member))
            # If no bid, move player from draft_pool to draft_unsold
            else:
                cur.execute("""
                    INSERT INTO draft_unsold
                    (draft_id, guild_id, member_id)
                    VALUES (?, ?, ?)
                """, (draft_id, channel.guild.id, current_member))

            # Clear current_member
            cur.execute("""
                UPDATE draft_state SET current_member = NULL
                WHERE draft_id = ?
            """, (draft_id,))

            # Check remaining in pool
            cur.execute("SELECT 1 FROM draft_pool WHERE draft_id = ? LIMIT 1", (draft_id,))
            remaining = cur.fetchone()

            db.commit()

        # Send embed with unsold players if any
        with get_draft_db() as db:
            cur = db.cursor()
            cur.execute("SELECT member_id FROM draft_unsold WHERE draft_id = ?", (draft_id,))
            unsold_members = [r[0] for r in cur.fetchall()]

        if unsold_members:
            embed_unsold = discord.Embed(
                title="❌ Unsold Players",
                color=discord.Color.red()
            )
            embed_unsold.add_field(
                name="Players not picked this round",
                value=", ".join(channel.guild.get_member(m).mention for m in unsold_members),
                inline=False
            )
            await channel.send(embed=embed_unsold)

        # Draft status embed
        with get_draft_db() as db:
            cur = db.cursor()
            cur.execute("""
                SELECT leader_id, gold_remaining
                FROM draft_leaders
                WHERE draft_id = ?
            """, (draft_id,))
            leaders = cur.fetchall()

        embed = discord.Embed(
            title="📊 Draft Status",
            color=discord.Color.gold()
        )

        for leader_id, gold in leaders:
            cur.execute("""
                SELECT member_id FROM draft_teams
                WHERE draft_id = ? AND guild_id = ? AND leader_id = ?
            """, (draft_id, channel.guild.id, leader_id))
            team_ids = [r[0] for r in cur.fetchall()]

            leader = channel.guild.get_member(leader_id)
            team = ", ".join(channel.guild.get_member(m).mention for m in team_ids) or "None"

            embed.add_field(
                name=leader.display_name,
                value=f"💰 Gold: `{gold}`\n👥 Team: {team}",
                inline=False
            )

        await channel.send(embed=embed)

        # Continue draft or start wars
        if remaining:
            await asyncio.sleep(2)  # small buffer for DB consistency
            await start_next_draft_auction(channel.guild, channel)
        else:
            await setup_wars_from_draft(channel.guild, channel, draft_id)
            delete_draft(draft_id)
            await channel.send("✅ Draft completed. Wars have been set up!")
        return

    # Non-draft auction: handle wallet + inventory + logs
    if highest_bidder and settings.get("wallet_required"):
        try:
            remove_balance_sync(channel.guild.id, highest_bidder, highest_bid)
            add_to_auction_inventory_sync(channel.guild.id, highest_bidder, item, highest_bid)
        except Exception as e:
            print(f"[AUCTION] Failed to settle wallet/inventory: {e}")

    sold_log_id = settings.get("sold_log")
    unsold_log_id = settings.get("unsold_log")
    try:
        if highest_bidder and sold_log_id:
            sold_ch = bot.get_channel(int(sold_log_id)) or await bot.fetch_channel(int(sold_log_id))
            await sold_ch.send(f"✅ **{item}** sold to <@{highest_bidder}> for `{highest_bid}`.")
        elif (not highest_bidder) and unsold_log_id:
            unsold_ch = bot.get_channel(int(unsold_log_id)) or await bot.fetch_channel(int(unsold_log_id))
            await unsold_ch.send(f"❌ **{item}** went unsold.")
    except Exception as e:
        print(f"[AUCTION] Failed to send sold/unsold log: {e}")

    # Auto-start next queued item if available
    try:
        next_item = get_first_auction_queue_item_sync(channel.guild.id)
        if next_item:
            await asyncio.sleep(2)
            await channel.send("⏳ Starting next queued item...")
            ctx_for_channel = await bot.get_context(channel.last_message)
            await ctx_for_channel.invoke(
                auction.get_command("start"),
                item=None,
                starting_bid=None,
                duration=None,
                image_url=None
            )
    except Exception as e:
        print(f"[AUCTION] Failed to auto-start next queued item: {e}")

    
def delete_draft(draft_id):
    with get_draft_db() as db:
        cur = db.cursor()

        cur.execute("DELETE FROM draft_leaders WHERE draft_id = ?", (draft_id,))
        cur.execute("DELETE FROM draft_teams WHERE draft_id = ?", (draft_id,))
        cur.execute("DELETE FROM draft_pool WHERE draft_id = ?", (draft_id,))
        cur.execute("DELETE FROM draft_state WHERE draft_id = ?", (draft_id,))
        cur.execute("DELETE FROM draft_wars WHERE id = ?", (draft_id,))

        db.commit()

async def start_next_draft_auction(guild: discord.Guild, channel: discord.TextChannel):
    draft_id = get_active_draft(guild.id)
    if not draft_id:
        return

    with get_draft_db() as db:
        cur = db.cursor()

        cur.execute("""
            SELECT member_id FROM draft_pool
            WHERE draft_id = ? AND guild_id = ?
            ORDER BY position ASC LIMIT 1
        """, (draft_id, guild.id))
        row = cur.fetchone()

        if not row:
            # No members left → setup wars
            await setup_wars_from_draft(guild, channel, draft_id)
            delete_draft(draft_id)
            await channel.send("✅ Draft completed. Wars have been set up!")
            return

        member_id = row[0]

        # Remove from pool
        cur.execute("""
            DELETE FROM draft_pool
            WHERE draft_id = ? AND member_id = ?
        """, (draft_id, member_id))

        # Set current member
        cur.execute("""
            UPDATE draft_state
            SET current_member = ?
            WHERE draft_id = ?
        """, (member_id, draft_id))

        db.commit()

    member = guild.get_member(member_id)
    if not member:
        await start_next_draft_auction(guild, channel)
        return

    await channel.send(f"🎯 **Now auctioning:** {member.mention}\nUse `!bid` to bid")
    ctx_for_channel = await bot.get_context(channel.last_message)
    await ctx_for_channel.invoke(auction.get_command("start"), 
        item=member.display_name,
        starting_bid="0",
        duration="60s",
        image_url=member.display_avatar.url
    )

@auction.command()
async def status(ctx):
    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        cursor = db.cursor()
        cursor.execute("""
            SELECT item, highest_bid, highest_bidder, ends_at, image_url 
            FROM auctions 
            WHERE ended = 0 ORDER BY id DESC LIMIT 1
        """)
        row = cursor.fetchone()

    if not row:
        return await ctx.send("No auction is currently running.")

    item, highest_bid, highest_bidder, ends_at_str, image_url = row
    paused_remaining = auction_paused_remaining.get(ctx.guild.id)
    settings = get_guild_settings_sync(ctx.guild.id)
    increment = settings.get("increment") or MIN_BID_INCREMENT
    if paused_remaining is not None:
        time_left = paused_remaining
        status_line = "**Status**: Paused"
    else:
        ends_at = datetime.fromisoformat(ends_at_str)
        time_left = max(0, (ends_at - datetime.now(timezone.utc)).total_seconds())
        status_line = "**Status**: Live"
    minutes = max(0, round(time_left)/60)
    seconds = max(0, round(time_left))
    bidder = f"<@{highest_bidder}>" if highest_bidder else "None"

    embed = discord.Embed(
        title=f"Auction: {item}",
        description=(
            f"**Current bid**: `{highest_bid}` coins\n"
            f"**Highest bidder**: {bidder}\n"
            f"**Time left**: {minutes} Minutes ({seconds} Seconds)\n"
            f"**Minimum bid increment**: `{increment}` coins\n"
            f"{status_line}"
        ),
        color=discord.Color.gold()
    )
    if image_url:
        embed.set_image(url=image_url)

    await ctx.send(embed=embed)

