    items = get_auction_queue_sync(ctx.guild.id)
    if position > len(items):
        return await ctx.send("Position out of range.")
    queue_id, name, _, _ = items[position - 1]
    remove_from_auction_queue_sync(ctx.guild.id, queue_id)
    await ctx.send(f"✅ Removed **{name}** from position {position}.")

