class AuctionHistoryPaginator(View):
    def __init__(self, pages):
        super().__init__(timeout=60)
        self.pages = pages
        self.index = 0

    async def update_message(self, interaction):
        await interaction.response.edit_message(embed=self.pages[self.index], view=self)

    @discord.ui.button(label="Previous", style=discord.ButtonStyle.secondary)
    async def previous(self, interaction, button):
        self.index = (self.index - 1) % len(self.pages)
        await self.update_message(interaction)

    @discord.ui.button(label="Next", style=discord.ButtonStyle.secondary)
    async def next(self, interaction, button):
        self.index = (self.index + 1) % len(self.pages)
        await self.update_message(interaction)

@auction.command()
async def history(ctx):
    with sqlite3.connect(get_auc_db_file(ctx.guild.id)) as db:
        cursor = db.cursor()
        cursor.execute("""
            SELECT item, highest_bid, highest_bidder FROM auctions
            WHERE ended = 1 ORDER BY id DESC
        """)
        auctions = cursor.fetchall()

    if not auctions:
        return await ctx.send("No past auctions found.")

    pages = []
    for i in range(0, len(auctions), 5):
        embed = discord.Embed(title="Auction History", color=discord.Color.blue())
        for item, bid, bidder in auctions[i:i+5]:
            winner = f"<@{bidder}>" if bidder else "No winner"
            embed.add_field(name=item, value=f"Bid: `{bid}` coins\nWinner: {winner}", inline=False)
        pages.append(embed)

    view = AuctionHistoryPaginator(pages)
    await ctx.send(embed=pages[0], view=view)


