def add_missing_tables_and_columns(conn):
    c = conn.cursor()
    
    # Create new table if not exists
    c.execute("""
        CREATE TABLE IF NOT EXISTS cc (
            id TEXT PRIMARY KEY,
            clan_name_1 TEXT,
            clan_name_2 TEXT,
            players_clan_1 TEXT,
            players_clan_2 TEXT,
            hp_clan_1 TEXT,
            hp_clan_2 TEXT,
            inventory_clan_1 TEXT,
            inventory_clan_2 TEXT
        )
    """)
    c.execute("""
    CREATE TABLE IF NOT EXISTS banners (
    banner_id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id TEXT,
    banner_url TEXT,
    name TEXT
);""")
    
              
    conn.commit()
def setup_database(conn):
    c = conn.cursor()
    add_missing_tables_and_columns(conn)
    c.execute("""
    CREATE TABLE IF NOT EXISTS clans (
        clan_name TEXT PRIMARY KEY,
        leader_id INTEGER,
        emoji TEXT,
        deputy_id INTEGER,
        loss INTEGER DEFAULT 0,
        war_history TEXT DEFAULT ''
    )
    """)
    c.execute("""
    CREATE TABLE IF NOT EXISTS war_duels (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        clan_1 TEXT,
        clan_2 TEXT,
        score_to_win INTEGER,
        status TEXT DEFAULT 'ongoing',
        c1_prio INTEGER DEFAULT 0,
        c2_prio INTEGER DEFAULT 0,
        rare INTEGER DEFAULT 0,
        comm INTEGER DEFAULT 0
    )
    """)
    c.execute("""
    CREATE TABLE IF NOT EXISTS war_members (
        war_id INTEGER,
        clan_name TEXT,
        user_id INTEGER,
        wins INTEGER DEFAULT 0,
        losses INTEGER DEFAULT 0,
        PRIMARY KEY (war_id, user_id)
    )
    """)
    c.execute("""
    CREATE TABLE IF NOT EXISTS war_requests (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        clan_1 TEXT,
        clan_2 TEXT,
        status TEXT DEFAULT 'pending'
    )
    """)
    c.execute("""
    CREATE TABLE IF NOT EXISTS clan_members (
        user_id INTEGER,
        clan_name TEXT,
        joined_at TEXT
        
    )
    """)

    # Battle to the Death
    c.execute("""
        CREATE TABLE IF NOT EXISTS battles (
            id TEXT PRIMARY KEY,
            clan_name_1 TEXT,
            clan_name_2 TEXT,
            players_clan_1 TEXT,
            players_clan_2 TEXT,
            hp_clan_1 TEXT,
            hp_clan_2 TEXT,
            inventory_clan_1 TEXT,
            inventory_clan_2 TEXT
        )
        """)
    # Shop items
    c.execute("""
    CREATE TABLE IF NOT EXISTS shop_items (
        item_name TEXT PRIMARY KEY,
        description TEXT,
        price INTEGER,
        image_url TEXT
    )
    """)
    
    # User coin balance
    c.execute("""
    CREATE TABLE IF NOT EXISTS shop (
        user_id INTEGER PRIMARY KEY,
        coin INTEGER DEFAULT 0
    )
    """)
    c.execute("""
    CREATE TABLE IF NOT EXISTS legendary_event (
    user_id INTEGER PRIMARY KEY,
    points INTEGER DEFAULT 0,
    wins INTEGER DEFAULT 0,
    losses INTEGER DEFAULT 0,
    last_participation TEXT
    )
    """)
    c.execute("""
        CREATE TABLE IF NOT EXISTS track (
            guild_id INTEGER,
            recent_matches TEXT,
            PRIMARY KEY (guild_id)
        )
    """)
    c.execute("""
        CREATE TABLE IF NOT EXISTS profile1 (
            user_id TEXT PRIMARY KEY,
            wins INTEGER DEFAULT 0,
            losses INTEGER DEFAULT 0,
            total INTEGER DEFAULT 0,
            win_rate REAL DEFAULT 0.0
        )
    """)
    # Create roles table
    c.execute('''
        CREATE TABLE IF NOT EXISTS roles (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            role_name TEXT UNIQUE NOT NULL,
            emoji TEXT
        )
    ''')

    # Insert default roles
    c.executemany('''
        INSERT OR IGNORE INTO roles (role_name, emoji)
        VALUES (?, ?)
    ''', [
        ("All Rounder", "<a:metagross:1378671701763821642>"),
        ("Commons Dueler", "<a:primarina:1378671350046261268>"),
        ("Rares Dueler", "<a:Arceus:1378670728127188994>")
    ])

    # Create member_roles table
    c.execute('''
        CREATE TABLE IF NOT EXISTS member_roles (
            user_id INTEGER NOT NULL,
            role_id INTEGER NOT NULL,
            guild_id INTEGER NOT NULL,
            PRIMARY KEY (user_id, guild_id),
            FOREIGN KEY (role_id) REFERENCES roles(id)
        )
    ''')

    c.execute("PRAGMA table_info(clans)")
    existing_columns = [row[1] for row in c.fetchall()]
    if 'war_wins' not in existing_columns:
        c.execute("ALTER TABLE clans ADD COLUMN war_wins INTEGER DEFAULT 0")
    if 'url' not in existing_columns:
        c.execute("ALTER TABLE clans ADD COLUMN url TEXT")
    if 'cumulative_wins' not in existing_columns:
        c.execute("ALTER TABLE clans ADD COLUMN cumulative_wins INTEGER DEFAULT 0")
    if 'loss' not in existing_columns:
        c.execute("ALTER TABLE clans ADD COLUMN loss INTEGER DEFAULT 0")
    if 'war_history' not in existing_columns:
        c.execute("ALTER TABLE clans ADD COLUMN war_history TEXT DEFAULT ''")
    c.execute("PRAGMA table_info(profile1)")
    columns = [col[1] for col in c.fetchall()]
    if 'equipped_banner' not in columns:
        c.execute("ALTER TABLE profile1 ADD COLUMN equipped_banner TEXT DEFAULT NULL")
    if "font_color" not in columns:
        c.execute("ALTER TABLE profile1 ADD COLUMN font_color TEXT DEFAULT white")
    c.execute("PRAGMA table_info(war_duels)")
    existing_columns = [row[1] for row in c.fetchall()]
    if "c1_prio" not in existing_columns:
        c.execute("ALTER TABLE war_duels ADD COLUMN c1_prio INTEGER DEFAULT 0")
    if "c2_prio" not in existing_columns:
        c.execute("ALTER TABLE war_duels ADD COLUMN c2_prio INTEGER DEFAULT 0")
    if "rare" not in existing_columns:
        c.execute("ALTER TABLE war_duels ADD COLUMN rare INTEGER DEFAULT 0")
    if "comm" not in existing_columns:
        c.execute("ALTER TABLE war_duels ADD COLUMN comm INTEGER DEFAULT 0")
   
    conn.commit()

            
def get_db_files():
    folder = "clan_war_dbs"
    if not os.path.exists(folder):
        return []
    return [os.path.join(folder, f) for f in os.listdir(folder) if f.endswith(".db")]

def create_track_table(conn):
    c = conn.cursor()
    c.execute("""
        CREATE TABLE IF NOT EXISTS track (
            guild_id INTEGER PRIMARY KEY,
            recent_matches TEXT,
            war_id INTEGER
        )
    """)
    # Check and add war_id column if not present
    c.execute("PRAGMA table_info(track)")
    columns = [col[1] for col in c.fetchall()]
    if 'war_id' not in columns:
        c.execute("ALTER TABLE track ADD COLUMN war_id INTEGER")
    conn.commit()
    
