from discord.ext.commands import CommandInvokeError
@clan.error
async def clan_error(ctx, error):
    # Check if it's a database locked error
    if isinstance(error, CommandInvokeError) and isinstance(error.original, sqlite3.OperationalError):
        if "database is locked" in str(error.original).lower():
            await ctx.send("⚠️ The database is locked. Try `!unlockdb poke.db` (admin only), then run the command again.")
        else:
            await ctx.send("❌ A database error occurred.")
    else:
        # If not handled, re-raise or log
        raise error 

@bot.command(name="unlockdb")
@commands.has_permissions(administrator=True)
async def unlockdb(ctx, db_name: str = "poke.db"):
    if ctx.author.id not in owner_ids:
        return ctx.send("Bot admin only command, please open a ticket in support server")
    allowed = {"poke.db", "cosmetics.db", "gym.db", "magic.db"}
    db_name = (db_name or "poke.db").strip().lower()

    if db_name not in allowed:
        choices = ", ".join(sorted(allowed))
        return await ctx.send(f"❌ Unsupported database. Choose one of: {choices}")

    ok, detail = await asyncio.to_thread(try_unlock_sqlite_db, db_name)
    if ok:
        await ctx.send(f"✅ Ran recovery on `{db_name}` (checkpoint + optimize).")
    else:
        await ctx.send(f"⚠️ Could not unlock `{db_name}`: {detail}")

