@clan.command(name="resetdb", aliases = ['full_reset', 'wipe'])
async def reset_database(ctx):
    # Check if user is server owner
    if ctx.author.id != ctx.guild.owner_id:
        await ctx.send("❌ Only the **server owner** can use this command.")
        return

    guild_id = ctx.guild.id
    db_file = os.path.join("clan_war_dbs", f"yes_{guild_id}.db")

    if os.path.exists(db_file):
        os.remove(db_file)
        await ctx.send(f"✅ Database for **{ctx.guild.name}** has been reset.")
    else:
        await ctx.send(f"⚠ No database file found for **{ctx.guild.name}**.")


@clan.command()
async def setpos(ctx, member: discord.Member, *, position: str):
    valid_roles = ["All Rounder", "Commons Dueler", "Rares Dueler"]
    position_title = position.title()

    if position_title not in valid_roles:
        return await ctx.send(f"Invalid position. Choose one of: {', '.join(valid_roles)}")

    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()
    inviter_id = ctx.author.id
    # Check if user is a clan leader or deputy
    c.execute("SELECT clan_name, deputy_id FROM clans WHERE leader_id = ?", (inviter_id,))
    result = c.fetchone()
    if not result:
        return await ctx.send("You are not authorized to set positions.")

    clan_name, deputy_id = result
    
    # Get role ID from roles table
    c.execute("SELECT id FROM roles WHERE role_name = ?", (position_title,))
    row = c.fetchone()
    if not row:
        return await ctx.send("Role not found in the database.")
    
    role_id = row[0]

    # Insert or update role for user
    c.execute('''
        INSERT INTO member_roles (user_id, role_id, guild_id)
        VALUES (?, ?, ?)
        ON CONFLICT(user_id, guild_id) DO UPDATE SET role_id = excluded.role_id
    ''', (member.id, role_id, ctx.guild.id))
    conn.commit()

    await ctx.send(f"✅ {member.mention} has been assigned the position **{position_title}**.")
    
# Command to create a clan
@clan.command(name='create', aliases = ['c'])
async def create(ctx, name: str, leader: discord.Member):
    # Check if user has the "Clan" role (strict)
    if not discord.utils.get(ctx.author.roles, name="Clan") and not ctx.author.guild_permissions.administrator:
        return await ctx.send("You need the **Clan** role to use this command. (create a role called `Clan` if it doesn't exist)")

    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    create_track_table(conn)
    c = conn.cursor()

    # Check if the clan already exists
    c.execute("SELECT * FROM clans WHERE clan_name = ?", (name,))
    existing = c.fetchone()
    if existing:
        return await ctx.send(f"A clan named **{name}** already exists.")

    # Insert into database using leader's ID
    c.execute("INSERT INTO clans (clan_name, leader_id) VALUES (?, ?)", (name, leader.id))
    conn.commit()
    conn.close()

    conn_role = get_autorole_db(ctx.guild.id)
    cr = conn_role.cursor()
    cr.execute("SELECT role_id FROM autorole_clan_leader")
    role_rows = cr.fetchall()
    cr.close()

    assigned_roles = []
    for r in role_rows:
        role_id = r[0]
        role = ctx.guild.get_role(role_id)
        if role:
            try:
                await leader.add_roles(role, reason="Autorole: clan leader")
                assigned_roles.append(role.mention)
            except Exception as e:
                print(e)
        else:
            # Remove missing role from DB
            cr = conn_role.cursor()
            cr.execute("DELETE FROM autorole_clan_leader WHERE role_id=?", (role_id,))
            conn_role.commit()
            cr.close()
    conn_role.close()

    await ctx.send(f"Clan **{name}** has been created with **{leader.mention}** as the leader.")
    
class WarStatsView(View):
    def __init__(self, clan_name, war_wins, losses, cumulative_wins, war_history, member_stats):
        super().__init__(timeout=None)
        self.clan_name = clan_name
        self.war_wins = war_wins
        self.losses = losses
        self.cumulative_wins = cumulative_wins
        self.war_history = war_history
        self.member_stats = member_stats

    @discord.ui.button(label="📶", style=discord.ButtonStyle.primary)
    async def view_history(self, interaction: discord.Interaction, button: Button):
        if not self.war_history:
            return await interaction.response.edit_message(
                embed=discord.Embed(
                    title=f"{self.clan_name} — War History",
                    description="> ⚠️ **No war history found.**",
                    color=discord.Color.orange()
                ),
                view=self
            )

        history_entries = self.war_history.split("|")
        formatted = "\n".join(f"> __**{entry.strip()}**__" for entry in history_entries)

        history_embed = discord.Embed(
            title=f"{self.clan_name} — War History",
            description=formatted,
            color=discord.Color.dark_gold()
        )

        self.clear_items()
        self.add_item(Button(label="↻", style=discord.ButtonStyle.secondary, custom_id="back_to_stats"))
        await interaction.response.edit_message(embed=history_embed, view=self)

    @discord.ui.button(label="↻", style=discord.ButtonStyle.secondary, disabled=True)
    async def back_disabled(self, interaction: discord.Interaction, button: Button):
        pass

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.data.get("custom_id") == "back_to_stats":
            total = self.war_wins + (self.losses or 0)
            win_rate = (self.war_wins / total) * 100 if total > 0 else 0.0

            description = (
                f"<a:sword:1378635803680571533> **Total Wars**: **{total}**\n\n"
                f"<a:greendot:1379769519827976282> **Wars Won**: **{self.war_wins}**\n\n"
                f"<a:reddot:1383020181189689387> **Wars Lost**: **{self.losses}**\n\n"
                f"➡ **War WR%**: **{win_rate:.2f}%**\n\n"
                f"➡ **Cumulative Wins**: **{self.cumulative_wins}**\n\n"
                f"➡ **Members**: **{self.member_stats['total']}**"
            )

            for role in self.member_stats["roles"]:
                description += f"\n{role['emoji']} **{role['name']}**: **{role['count']}**"

            embed = discord.Embed(
                title=f"{self.clan_name} — Clan Stats",
                description=description,
                color=discord.Color.blue()
            )

            self.clear_items()
            self.add_item(Button(label="📶", style=discord.ButtonStyle.primary, custom_id="view_history"))
            self.add_item(Button(label="↻", style=discord.ButtonStyle.secondary, disabled=True))

            await interaction.response.edit_message(embed=embed, view=self)
        return True


@clan.command(name="stats")
async def clan_stats(ctx, *, clan_name: str = None):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Get the clan name if not provided
    if not clan_name:
        c.execute("SELECT clan_name FROM clans WHERE leader_id = ?", (ctx.author.id,))
        row = c.fetchone()
        if not row:
            return await ctx.send("You're not a clan leader and no clan name was provided.")
        clan_name = row[0]

    # Fetch clan stats
    c.execute("SELECT cumulative_wins, war_wins, loss, war_history FROM clans WHERE clan_name = ?", (clan_name,))
    row = c.fetchone()
    if not row:
        return await ctx.send("Clan not found.")
    
    cumulative_wins, war_wins, loss, war_history = row
    total = war_wins + (loss or 0)
    win_rate = (war_wins / total) * 100 if total > 0 else 0.0
    rating = cumulative_wins - loss*50 + war_wins*100

    # Fetch member IDs in the clan
    c.execute("SELECT user_id FROM clan_members WHERE clan_name = ?", (clan_name,))
    members = c.fetchall()
    member_ids = [m[0] for m in members]
    total_members = len(member_ids)

    # Prepare placeholders
    placeholders = ','.join('?' for _ in member_ids) if member_ids else 'NULL'

    # Count duelers by role_id for current guild
    c.execute(f'''
        SELECT role_id, COUNT(*) FROM member_roles
        WHERE user_id IN ({placeholders}) AND guild_id = ?
        GROUP BY role_id
    ''', (*member_ids, ctx.guild.id) if member_ids else (ctx.guild.id,))
    role_counts_data = c.fetchall()

    # Get role names and emojis
    c.execute("SELECT id, role_name, emoji FROM roles")
    roles_info = {row[0]: {"name": row[1], "emoji": row[2] or ""} for row in c.fetchall()}

    member_stats = {
        "total": total_members,
        "roles": []
    }

    for role_id, count in role_counts_data:
        role_info = roles_info.get(role_id)
        if role_info:
            member_stats["roles"].append({
                "emoji": role_info["emoji"],
                "name": role_info["name"],
                "count": count
            })

    # Build embed
    description = (
        f"<a:sword:1378635803680571533> **Total Wars**: **{total}**\n\n"
        f"<a:greendot:1379769519827976282> **Wars Won**: **{war_wins}**\n\n"
        f"<a:reddot:1383020181189689387> **Wars Lost**: **{loss}**\n\n"
        f"➡ **War WR%**: **{win_rate:.2f}%**\n\n"
        f"➡ **Cumulative Wins**: **{cumulative_wins}**\n\n"
        f"➡ **Members**: **{total_members}**"
    )

    for role in member_stats["roles"]:
        description += f"\n{role['emoji']} **{role['name']}**: **{role['count']}**"

    embed = discord.Embed(
        title=f"{clan_name}{rank_emoji(rating)} — Clan Stats",
        description=description,
        color=discord.Color.blue()
    )

    view = WarStatsView(clan_name, war_wins, loss, cumulative_wins, war_history, member_stats)
    await ctx.send(embed=embed, view=view)    
    
@clan.command()
@commands.has_permissions(administrator=True)
async def fp(ctx, member: discord.Member, clan: str):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()
    
    clan_name = clan

    # Check if the mentioned member is part of the same clan
    c.execute("SELECT 1 FROM clan_members WHERE clan_name = ? AND user_id = ?", (clan_name, member.id))
    if not c.fetchone():
        return await ctx.send(f"{member.mention} is not a member of {clan_name}.")

    # Button interaction view
    class PromoteView(View):
        def __init__(self):
            super().__init__(timeout=30)

        @discord.ui.button(label="Promote to Leader", style=discord.ButtonStyle.danger)
        async def leader_button(self, interaction: discord.Interaction, button: Button):
            if interaction.user.id != ctx.author.id:
                return await interaction.response.send_message("Only the current clan leader can use this.", ephemeral=True)

            c.execute("UPDATE clans SET leader_id = ? WHERE clan_name = ?", (member.id, clan_name))
            conn.commit()
            await interaction.response.edit_message(content=f"✅ {member.mention} has been promoted to **Leader** of `{clan_name}`.", view=None)

        @discord.ui.button(label="Promote to Deputy", style=discord.ButtonStyle.primary)
        async def deputy_button(self, interaction: discord.Interaction, button: Button):
            if interaction.user.id != ctx.author.id:
                return await interaction.response.send_message("Only the current clan leader can use this.", ephemeral=True)

            c.execute("UPDATE clans SET deputy_id = ? WHERE clan_name = ?", (member.id, clan_name))
            conn.commit()
            await interaction.response.edit_message(content=f"✅ {member.mention} has been promoted to **Deputy** of `{clan_name}`.", view=None)

    await ctx.send(f"Promote {member.mention} in `{clan_name}`:", view=PromoteView())
    
@clan.command()
async def promote(ctx, member: discord.Member):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Check if the command user is a clan leader
    c.execute("SELECT clan_name FROM clans WHERE leader_id = ?", (ctx.author.id,))
    result = c.fetchone()
