    c.execute("SELECT id, role_name, emoji FROM roles")
    roles = {row[0]: {"name": row[1], "emoji": row[2]} for row in c.fetchall()}

    # Fetch role assignments
    c.execute("SELECT user_id, role_id FROM member_roles WHERE guild_id = ?", (ctx.guild.id,))
    member_roles = {user_id: role_id for user_id, role_id in c.fetchall() if user_id in members}

    # Fetch win/loss stats
    c.execute("SELECT user_id, wins, losses FROM profile1")
    stats = {user_id: {"wins": wins, "losses": losses} for user_id, wins, losses in c.fetchall()}

