@clan.command()
async def acceptwar(ctx, your_clan: str, enemy_clan: str, score_to_win: int):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Verify user is leader of their clan
    c.execute("SELECT * FROM clans WHERE clan_name = ? AND leader_id = ?", (your_clan, ctx.author.id))
    if not c.fetchone():
        return await ctx.send("You are not the leader of that clan.")

    # Check for valid war request
    c.execute("SELECT * FROM war_requests WHERE clan_1 = ? AND clan_2 = ? AND status = 'pending'", (enemy_clan, your_clan))
    war = c.fetchone()
    if not war:
        return await ctx.send("No pending war request found.")

    # Accept and delete the request
    c.execute("DELETE FROM war_requests WHERE id = ?", ( war[0],))
    c.execute("INSERT INTO war_duels (clan_1, clan_2, score_to_win) VALUES (?, ?, ?)", (enemy_clan, your_clan, score_to_win))
    conn.commit()

    await ctx.send(f"**{your_clan}** accepted the war against **{enemy_clan}**! First to {score_to_win} wins!")

