def add_conquest_tables(conn):
    try:
        c = conn.cursor()
        c.execute("""
        CREATE TABLE IF NOT EXISTS conquest_members (
            war_id INTEGER,
            clan_name TEXT,
            user_id INTEGER,
            wins INTEGER DEFAULT 0,
            losses INTEGER DEFAULT 0,
            PRIMARY KEY (war_id, user_id)
        )
        """)
        c.execute("""
        CREATE TABLE IF NOT EXISTS conquest (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            clan_1 TEXT,
            clan_2 TEXT,
            score_to_win INTEGER,
            asia TEXT,
            NA TEXT,
            SA TEXT,
            AF TEXT,
            OC TEXT,
            EU TEXT
        )
        """)
    except Exception as e:
        print(e)
    conn.commit()
