async def log_match(ctx, war_id, winner_id, loser_id, conn):
    global league_cache
    c = conn.cursor()

    # update winner + loser war stats
    c.execute("UPDATE war_members SET wins = wins + 1 WHERE war_id = ? AND user_id = ?", (war_id, winner_id))
    c.execute("UPDATE war_members SET losses = losses + 1 WHERE war_id = ? AND user_id = ?", (war_id, loser_id))
    conn.commit()

    # fetch updated stats for both players (from THIS war only)
    c.execute("SELECT wins, losses, clan_name FROM war_members WHERE war_id = ? AND user_id = ?", (war_id, winner_id))
    winner_wins, winner_losses, winner_clan = c.fetchone()
    c.execute("SELECT wins, losses, clan_name FROM war_members WHERE war_id = ? AND user_id = ?", (war_id, loser_id))
    loser_wins, loser_losses, loser_clan = c.fetchone()
    # --- ADD TO LEAGUE CACHE FOR BACKGROUND LOOP ---
    print("inside log_match")
    print((ctx.guild.id, int(winner_id)))
    print((ctx.guild.id, int(loser_id)))
    if (ctx.guild.id, int(winner_id)) not in league_cache["players"]:
        league_cache["players"][(ctx.guild.id, int(winner_id))] = {"wins": 0, "losses": 0, "clan": winner_clan}
    league_cache["players"][(ctx.guild.id, int(winner_id))]["wins"] += 1

    if (ctx.guild.id, int(loser_id)) not in league_cache["players"]:
        league_cache["players"][(ctx.guild.id, int(loser_id))] = {"wins": 0, "losses": 0, "clan": loser_clan}
    league_cache["players"][(ctx.guild.id, int(loser_id))]["losses"] += 1
