@clan.command(name='autolog', aliases=['al'])
async def autolog(ctx, loser: discord.Member):
    winner = ctx.author
    if winner.id == loser.id:
        return await ctx.send("You can't log a match against yourself.")

    print(f"\n[COMMAND] Triggering auto-log pipeline via manual command...")
    print(f"[COMMAND] Guild: {ctx.guild.name} ({ctx.guild.id}) | Winner: {winner.display_name} ({winner.id}) | Loser: {loser.display_name} ({loser.id})")
    
    # Directly invoke your auto-warlog function to test its execution path
    await _auto_warlog_from_battle(
        guild_id=ctx.guild.id,
        winner_id=winner.id,
        loser_id=loser.id,
        channel_id=ctx.channel.id
    )
async def _auto_warlog_from_battle(guild_id, winner_id, loser_id, channel_id=None):
    if guild_id is None:
        return
    winner_int = _safe_int_user_id(winner_id)
    loser_int = _safe_int_user_id(loser_id)
    if winner_int is None or loser_int is None or winner_int == loser_int:
        return

    guild = bot.get_guild(int(guild_id))
    if guild is None:
        return

    conn = None
    try:
        conn = get_db_connection(int(guild_id))
        setup_database(conn)
        c = conn.cursor()

        c.execute("SELECT war_id, clan_name FROM war_members WHERE user_id = ?", (winner_int,))
        winner_row = c.fetchone()
        c.execute("SELECT war_id, clan_name FROM war_members WHERE user_id = ?", (loser_int,))
        loser_row = c.fetchone()
        if not winner_row or not loser_row:
            return

        war_id_w, winner_clan = winner_row
        war_id_l, loser_clan = loser_row
        if war_id_w != war_id_l or not winner_clan or not loser_clan or winner_clan == loser_clan:
            return

        c.execute("SELECT status FROM war_duels WHERE id = ?", (war_id_w,))
        war_state = c.fetchone()
        if not war_state or str(war_state[0]).strip().lower() != "ongoing":
            return

        announce_channel = None
        if channel_id:
            announce_channel = guild.get_channel(int(channel_id))
        if announce_channel is None:
            return

        class _BattleAutoCtx:
            def __init__(self, g, ch):
                self.guild = g
                self.channel = ch
                self.bot = bot

            async def send(self, *args, **kwargs):
                if self.channel:
                    return await self.channel.send(*args, **kwargs)
                return None

        winner_member = guild.get_member(winner_int) or await guild.fetch_member(winner_int)
        loser_member = guild.get_member(loser_int) or await guild.fetch_member(loser_int)
        if not winner_member or not loser_member:
            return

        class _ConfirmLossView(discord.ui.View):
            def __init__(self, target_loser):
                super().__init__(timeout=20)
                self.target_loser = target_loser
                self.result = None
                self.force = False

            @discord.ui.button(label="Yes", style=discord.ButtonStyle.green)
            async def yes(self, interaction: discord.Interaction, button: discord.ui.Button):
                if interaction.user.id != self.target_loser.id:
                    return await interaction.response.send_message("Only the reported loser can confirm.", ephemeral=True)
                self.result = True
                await interaction.response.defer()
                self.stop()

            @discord.ui.button(label="No", style=discord.ButtonStyle.red)
            async def no(self, interaction: discord.Interaction, button: discord.ui.Button):
                if interaction.user.id != self.target_loser.id:
                    return await interaction.response.send_message("Only the reported loser can cancel.", ephemeral=True)
                self.result = False
                await interaction.response.defer()
                self.stop()

            @discord.ui.button(label="Force Log", style=discord.ButtonStyle.grey)
            async def force(self, interaction: discord.Interaction, button: discord.ui.Button):
                if not interaction.user.guild_permissions.administrator:
                    return await interaction.response.send_message("Only admins can force log a match.", ephemeral=True)
                self.force = True
                await interaction.response.defer()
                self.stop()

        view = _ConfirmLossView(loser_member)
        msg = await announce_channel.send(
            f"{loser_member.mention}, do you confirm your loss to {winner_member.mention} in war #{war_id_w}?",
            view=view,
        )
        await view.wait()

        if view.force:
            ctx = _BattleAutoCtx(guild, announce_channel)
            await log_match(ctx, int(war_id_w), winner_int, loser_int, conn)
            await msg.edit(content=f"**Force Logged**: {winner_member.mention} defeated {loser_member.mention}.", view=None)
        elif view.result is True:
            ctx = _BattleAutoCtx(guild, announce_channel)
            await log_match(ctx, int(war_id_w), winner_int, loser_int, conn)
            await msg.edit(content=f"{winner_member.mention} won a match! Score updated.", view=None)
        elif view.result is False:
            await msg.edit(content="Loss not confirmed. Logging cancelled.", view=None)
        else:
            await msg.edit(content="No response from loser. Logging cancelled.", view=None)
    except Exception:
        traceback.print_exc()
    finally:
        if conn is not None:
            try:
                conn.close()
            except Exception:
                pass

@clan.command(name="remove_win")
async def cremove_win(ctx, member: discord.Member, amount: int = 1):
    """Manually add wins to a member in an ongoing war"""
    if not ctx.author.guild_permissions.administrator:
        return await ctx.send("Only admins can run this command.")
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Fetch war info
    c.execute("SELECT war_id FROM war_members WHERE user_id = ?", (member.id,))
    row = c.fetchone()
    if not row:
        return await ctx.send(f"{member.mention} is not part of any ongoing war.")

    war_id = row[0]

    # Update wins
    c.execute("UPDATE war_members SET wins = wins - ? WHERE war_id = ? AND user_id = ?", (amount, war_id, member.id))
    conn.commit()
    c.execute("SELECT wins, losses FROM war_members WHERE war_id = ? AND user_id = ?", (war_id, member.id))
    wins, losses = c.fetchone()
    conn.close()
    if war_log_channel:
        war_log_channel.send(f"{ctx.author.mention} added -{amount} win(s) to {member.mention}. Total: **{wins}W/{losses}L**\n War has not ended for safety purposes, next log will end the war if passed the score needed.")
    await ctx.send(f"✅ Added -{amount} win(s) to {member.mention}. Total: **{wins}W/{losses}L**\n War has not ended for safety purposes, next log will end the war if passed the score needed.")

