async def conquest_log_match(ctx, war_id, winner_id, loser_id, conn):
    c = conn.cursor()

    # Update war-specific win/loss
    c.execute("UPDATE conquest_members SET wins = wins + 1 WHERE war_id = ? AND user_id = ?", (war_id, winner_id))
    c.execute("UPDATE conquest_members SET losses = losses + 1 WHERE war_id = ? AND user_id = ?", (war_id, loser_id))
    conn.commit()

    # Update global profile1 win/loss/total/winrate
    for uid, is_winner in [(winner_id, True), (loser_id, False)]:
        c.execute("SELECT wins, losses FROM profile1 WHERE user_id = ?", (uid,))
        row = c.fetchone()

        if not row:
            wins = 1 if is_winner else 0
            losses = 0 if is_winner else 1
            total = 1
            winrate = wins / total
            c.execute(
                "INSERT INTO profile1 (user_id, wins, losses, total, win_rate) VALUES (?, ?, ?, ?, ?)",
                (uid, wins, losses, total, winrate)
            )
        else:
            wins, losses = row
            wins += 1 if is_winner else 0
            losses += 0 if is_winner else 1
            total = wins + losses
            winrate = wins / total if total > 0 else 0
            c.execute(
                "UPDATE profile1 SET wins = ?, losses = ?, total = ?, win_rate = ? WHERE user_id = ?",
                (wins, losses, total, winrate, uid)
            )
            #Auto win achievements 
            if 1000 > wins > 99:
                setup_new_badge_tables()
                conn_ach = get_db_connection()
                cursor_ach = conn_ach.cursor()
                cursor_ach.execute("""
                INSERT INTO certificates (user_id, achievement)
                VALUES (?, ?)
                ON CONFLICT(user_id, achievement) DO NOTHING;
                """, (uid, 'General'))
                if cursor_ach.rowcount > 0:
                    await ctx.send(f'<@{uid}> has more than 100 wins and earn the **General<:General:1383772088325636189>** achievement')
                conn_ach.commit()
                conn_ach.close()
            elif 10000 > wins > 999:
                setup_new_badge_tables()
                conn_ach = get_db_connection()
                cursor_ach = conn_ach.cursor()
                cursor_ach.execute("""
                INSERT INTO certificates (user_id, achievement)
                VALUES (?, ?)
                ON CONFLICT(user_id, achievement) DO NOTHING;
                """, (uid, 'Warlord'))
                if cursor_ach.rowcount > 0:
                    await ctx.send(f'<@{uid}> has more than 1000 wins and earn the **Warlord<:Warlord:1383779561673588787>** achievement')
                conn_ach.commit()
                conn_ach.close()
            elif wins > 9999:
                setup_new_badge_tables()
                conn_ach = get_db_connection()
                cursor_ach = conn_ach.cursor()
                cursor_ach.execute("""
                INSERT INTO certificates (user_id, achievement)
                VALUES (?, ?)
                ON CONFLICT(user_id, achievement) DO NOTHING;
                """, (uid, 'Hero of 10k Battles'))
                if cursor_ach.rowcount > 0:
                    await ctx.send(f'<@{uid}> has more than 10000 wins and earn the **Hero of 10k Battles<a:HeroOf10KBattles:1383782886725124227>** achievement')
                conn_ach.commit()
                conn_ach.close()
            rand_int = random.randint(0, 100000)
            if rand_int == 1:
                conn_ach = get_db_connection()
                cursor_ach = conn_ach.cursor()
                cursor_ach.execute("""
                INSERT INTO certificates (user_id, achievement)
                VALUES (?, ?)
                ON CONFLICT(user_id, achievement) DO NOTHING;
                """, (uid, 'Herald of Luck'))
                if cursor_ach.rowcount > 0:
                    await ctx.send(f'<@{uid}> is so lucky!!!\nHe has earned the **Herald of Luck<a:HeraldOfLuck:1383837445602283540>** achievement')
                conn_ach.commit()
                conn_ach.close()

    conn.commit()

    # Get clans
    c.execute("SELECT clan_name FROM conquest_members WHERE war_id = ? AND user_id = ?", (war_id, winner_id))
    winner_clan = c.fetchone()[0]
    c.execute("SELECT clan_name FROM conquest_members WHERE war_id = ? AND user_id = ?", (war_id, loser_id))
    loser_clan = c.fetchone()[0]

    # ✅ Increment cumulative_wins for winner's clan
    c.execute("UPDATE clans SET cumulative_wins = cumulative_wins + 1 WHERE clan_name = ?", (winner_clan,))
    conn.commit()

    # Check if a clan won the war
    winner_declared = False
    winning_clan = None
    c.execute("SELECT clan_1, clan_2, score_to_win FROM conquest WHERE id = ?", (war_id,))
    row = c.fetchone()
    c.execute("SELECT asia, NA, SA, AF, EU, OC FROM conquest WHERE id = ?", (war_id,))
    continents = c.fetchone()
    clan_1, clan_2, score_to_win = row
    colors = []
    color_c = []
    color_n = []
    score1 = 0
    score2 = 0
    for continent in continents:
        if continent[2:] == score_to_win:
            if continent[:2] == 'c1':
                colors.append('red')
                color_c.append('red')
                color_n.append(f'{score_to_win}')
                score1 += 1
            elif continent[:2] == 'c2':
                colors.append('green')
                color_c.append('green')
                color_n.append(f'{score_to_win}')
                score2 += 1
        else:
            colors.append('white')
            color_n.append(continent[2:])
            if continent[:2] == 'c1':
                color_c.append('red')
            elif continent[:2] == 'c2':
                color_c.append('green')
    if score1 > 3:
        winner_declared=True
        winning_clan=clan_1
    elif score2 > 3:
        winner_declared=True
        winning_clan=clan_2
    elif score1 == 3 and score2 == 3:
        c.execute("SELECT user_id, clan_name, wins, losses FROM conquest_members WHERE war_id = ?", (war_id,))
        members = c.fetchall()
        clans = {}
        for uid, clan, wins, losses in members:
            clans.setdefault(clan, []).append((uid, wins, losses))
        final_embed = discord.Embed(
            title=f"Conquest #{war_id} Ended!",
            description=f"**{clan_1}** tied with **{clan_2}**!",
            color=discord.Color.blurple(),
            timestamp=discord.utils.utcnow()
        )
        buffer = draw_map(colors[0], colors[1],colors[2], colors[3],colors[4], colors[5],color_c[0], color_c[1],color_c[2],color_c[3],color_c[4], color_c[5],color_n[0], color_n[1],color_n[2],color_n[3],color_n[4], color_n[5])
        filename = "map.png"
        file = discord.File(fp=buffer, filename=filename)
        final_embed.set_image(url=f"attachment://{filename}")
        final_embed.set_footer(text=f"Logged in {ctx.guild.name}")
        for clan_name, players in clans.items():
            value = "\n".join(f"<@{uid}> - **{w}W/{l}L**" for uid, w, l in players)
            final_embed.add_field(name=clan_name, value=value or "No players", inline=False)
        guild_data = load_data(ctx.guild.id)
        war_update_id = guild_data.get("war_update") if guild_data else None
        war_updates_channel = ctx.guild.get_channel(war_update_id) if war_update_id else None
        if not war_updates_channel:
            # Fallback: try to find by name if no channel is configured
            war_updates_channel = discord.utils.get(ctx.guild.text_channels, name="war-updates")
        await war_updates_channel.send(embed=final_embed, file=file)
        c.execute("DELETE FROM conquest_members WHERE war_id = ?", (war_id,))
        c.execute("DELETE FROM conquest WHERE id = ?", (war_id,))
        conn.commit()
        return
    else:
        pass
    if winner_declared:
        c.execute("UPDATE clans SET war_wins = war_wins + 1 WHERE clan_name = ?", (winning_clan,))
        losing_clan = clan_2
        c.execute("UPDATE clans SET loss = loss + 1 WHERE clan_name = ?", (losing_clan,))
        c.execute("SELECT war_history FROM clans WHERE clan_name = ?", (winning_clan,))
