@clan.command(name="ccwarlog", aliases = ['slash', 'attack', 'kill', 'strike', 'beat', 'cclog', 'hit', 'choke', 'ccl', 'cwl'])
async def ccwarlog(ctx, loser: discord.Member):
    winner = ctx.author
    if winner.id == loser.id:
        return await ctx.send("You can't log a match against yourself.")

    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    add_missing_tables_and_columns(conn)
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()

    # Identify ongoing cc war between the two users
    c.execute("SELECT id, hp_clan_1, hp_clan_2 FROM cc")
    wars = c.fetchall()
    active_war_id = None
    for war_id, hp1_json, hp2_json in wars:
        hp1 = json.loads(hp1_json)
        hp2 = json.loads(hp2_json)
        if str(winner.id) in hp1 and str(loser.id) in hp2:
            active_war_id = war_id
            player_side = '1'
            break
        elif str(winner.id) in hp2 and str(loser.id) in hp1:
            active_war_id = war_id
            player_side = '2'
            break

    if not active_war_id:
        return await ctx.send("Both users must be participating in an ongoing CC war against each other.")

    class ConfirmView(discord.ui.View):
        def __init__(self):
            super().__init__(timeout=20)
            self.result = None
            self.force = False

        @discord.ui.button(label="Yes", style=discord.ButtonStyle.green)
        async def confirm(self, interaction: discord.Interaction, button: discord.ui.Button):
            if interaction.user != loser:
                return await interaction.response.send_message("Only the reported loser can confirm.", ephemeral=True)
            self.result = True
            self.stop()

        @discord.ui.button(label="No", style=discord.ButtonStyle.red)
        async def deny(self, interaction: discord.Interaction, button: discord.ui.Button):
            if interaction.user != loser:
                return await interaction.response.send_message("Only the reported loser can cancel.", ephemeral=True)
            self.result = False
            self.stop()

        @discord.ui.button(label="Force Log", style=discord.ButtonStyle.grey)
        async def force_log(self, interaction: discord.Interaction, button: discord.ui.Button):
            if not interaction.user.guild_permissions.administrator:
                return await interaction.response.send_message("Only admins can force log a match.", ephemeral=True)
            self.force = True
            self.stop()

    view = ConfirmView()
    msg = await ctx.send(f"{loser.mention}, do you confirm your loss to {winner.mention} in CC War #{active_war_id}?", view=view)
    await view.wait()

    if view.force:
        confirmed = True
    elif view.result is None:
        return await msg.edit(content="No response from loser. Logging cancelled.", view=None)
    elif not view.result:
        return await msg.edit(content="Loss not confirmed. Logging cancelled.", view=None)
    else:
        confirmed = True

    if confirmed:
        # Load HP data
        active_war_id = str(active_war_id)
        c.execute("SELECT hp_clan_1, hp_clan_2 FROM cc WHERE id = ?", (active_war_id,))
        row = c.fetchone()
        hp1 = json.loads(row[0])
        hp2 = json.loads(row[1])

        winner_str, loser_str = str(winner.id), str(loser.id)
        if player_side == '1':
            hp2[loser_str] = max(0, hp2.get(loser_str, 1) - 1)
        else:
            hp1[loser_str] = max(0, hp1.get(loser_str, 1) - 1)

        # Save updated HP
        c.execute("UPDATE cc SET hp_clan_1 = ?, hp_clan_2 = ? WHERE id = ?", (
            json.dumps(hp1), json.dumps(hp2), active_war_id
        ))

        # Step: Randomly reward item
        file_path = os.path.join('wars', f'{ctx.guild.id}.json')
        if os.path.exists(file_path):
            with open(file_path, 'r') as f:
                data = json.load(f)
            mode = data[f'{active_war_id}']
        else:
            mode = 'classic'
        if mode == 'Adventure':
            cn = random.randint(1, 100)
            if cn < 10:
                rewarded_item = 'high potion'
            elif 9 < cn < 20:
                rewarded_item = 'guided missile'
            elif 19< cn < 30:
                rewarded_item = 'elixir of life'
            elif 29 < cn < 40:
                rewarded_item = 'spice of life'
            elif 39 < cn < 60:
                rewarded_item = 'big bomb'
            elif 59 < cn < 80:
                rewarded_item = 'golden leaf'
            elif 79 < cn < 101:
                rewarded_item = 'emergency potion'

            # Add item to the correct clan inventory
            if player_side == '1':
                c.execute("SELECT inventory_clan_1 FROM cc WHERE id = ?", (active_war_id,))
                inv_json = c.fetchone()[0]
                inventory = json.loads(inv_json)
                inventory.append(rewarded_item)
                c.execute("UPDATE cc SET inventory_clan_1 = ? WHERE id = ?", (json.dumps(inventory), str(active_war_id)))
            else:
                c.execute("SELECT inventory_clan_2 FROM cc WHERE id = ?", (active_war_id,))
                inv_json = c.fetchone()[0]
                inventory = json.loads(inv_json)
                inventory.append(rewarded_item)
                c.execute("UPDATE cc SET inventory_clan_2 = ? WHERE id = ?", (json.dumps(inventory), str(active_war_id)))
            updated_hp = hp2[loser_str] if player_side == '1' else hp1[loser_str]
            message = (
            f"🎁 `{rewarded_item}` has been added to {winner.mention}'s clan inventory!\n"
            f"💔 {loser.mention}'s HP is now **{updated_hp}**.")
        else:
            updated_hp = hp2[loser_str] if player_side == '1' else hp1[loser_str]
            message = (f"💔 {loser.mention}'s HP is now **{updated_hp}**.")

        # Update profile1 stats
        for uid, is_winner in [(winner.id, True), (loser.id, False)]:
            c.execute("SELECT wins, losses FROM profile1 WHERE user_id = ?", (uid,))
            row = c.fetchone()
            if not row:
                wins = 1 if is_winner else 0
                losses = 0 if is_winner else 1
                total = 1
                winrate = wins / total
                c.execute("""
                    INSERT INTO profile1 (user_id, wins, losses, total, win_rate)
                    VALUES (?, ?, ?, ?, ?)
                """, (uid, wins, losses, total, winrate))
            else:
                wins, losses = row
                wins += 1 if is_winner else 0
                losses += 0 if is_winner else 1
                total = wins + losses
                winrate = wins / total if total > 0 else 0
                c.execute("""
                    UPDATE profile1 SET wins = ?, losses = ?, total = ?, win_rate = ?
                    WHERE user_id = ?
                """, (wins, losses, total, winrate, uid))
                #Auto win achievements 
                if 1000 > wins > 99:
                    setup_new_badge_tables()
                    conn_ach = get_db_connection()
                    cursor_ach = conn_ach.cursor()
                    cursor_ach.execute("""
                    INSERT INTO certificates (user_id, achievement)
                    VALUES (?, ?)
                    ON CONFLICT(user_id, achievement) DO NOTHING;
                    """, (uid, 'General'))
                    if cursor_ach.rowcount > 0:
                        await ctx.send(f'<@{uid}> has more than 100 wins and earn the **General<:General:1383772088325636189>** achievement')
                    conn_ach.commit()
                    conn_ach.close()
                elif 10000 > wins > 999:
                    setup_new_badge_tables()
                    conn_ach = get_db_connection()
                    cursor_ach = conn_ach.cursor()
                    cursor_ach.execute("""
                    INSERT INTO certificates (user_id, achievement)
                    VALUES (?, ?)
                    ON CONFLICT(user_id, achievement) DO NOTHING;
                    """, (uid, 'Warlord'))
                    if cursor_ach.rowcount > 0:
                        await ctx.send(f'<@{uid}> has more than 1000 wins and earn the **Warlord<:Warlord:1383779561673588787>** achievement')
                    conn_ach.commit()
                    conn_ach.close()
                elif wins > 9999:
                    setup_new_badge_tables()
                    conn_ach = get_db_connection()
                    cursor_ach = conn_ach.cursor()
                    cursor_ach.execute("""
                    INSERT INTO certificates (user_id, achievement)
                    VALUES (?, ?)
                    ON CONFLICT(user_id, achievement) DO NOTHING;
                    """, (uid, 'Hero of 10k Battles'))
                    if cursor_ach.rowcount > 0:
                        await ctx.send(f'<@{uid}> has more than 10000 wins and earn the **Hero of 10k Battles<a:HeroOf10KBattles:1383782886725124227>** achievement')
                    conn_ach.commit()
                    conn_ach.close()
                rand_int = random.randint(0, 100000)
                if rand_int == 1:
                    conn_ach = get_db_connection()
                    cursor_ach = conn_ach.cursor()
                    cursor_ach.execute("""
                    INSERT INTO certificates (user_id, achievement)
                    VALUES (?, ?)
                    ON CONFLICT(user_id, achievement) DO NOTHING;
                    """, (uid, 'Herald of Luck'))
                    if cursor_ach.rowcount > 0:
                        await ctx.send(f'<@{uid}> is so lucky!!!\nHe has earned the **Herald of Luck<a:HeraldOfLuck:1383837445602283540>** achievement')
                    conn_ach.commit()
                    conn_ach.close()

        conn.commit()

        # Track damage for MVP consideration
        damage_log_file = f'cc_damage/{ctx.guild.id}_{active_war_id}.json'
        os.makedirs('cc_damage', exist_ok=True)
        if os.path.exists(damage_log_file):
            with open(damage_log_file, 'r') as f:
                damage_data = json.load(f)
        else:
            damage_data = {}

        damage_data[str(winner.id)] = damage_data.get(str(winner.id), 0) + 1

        with open(damage_log_file, 'w') as f:
            json.dump(damage_data, f, indent=4)

        # Notify both sides
        await msg.edit(content=f"Logged: {winner.mention} hit {loser.mention}. One HP removed.\n{message}", view=None)
                # Check if war has ended (all HP = 0 on one side)
        all_hp1 = [hp for hp in hp1.values() if hp > 0]
        all_hp2 = [hp for hp in hp2.values() if hp > 0]

        war_ended = False
        winner_clan = None
        c.execute("SELECT clan_name_1, clan_name_2 FROM cc WHERE id = ?", (str(active_war_id),))
        clans = c.fetchall()
        print(clans)
        clan1, clan2 = clans[0]
        total_hp1 = ''
        for hp in all_hp1:
            total_hp1 += f'{hp},'
        total_hp2 = ''
        for hp in all_hp2:
            total_hp2 += f'{hp},'
        if not all_hp1:
            row = c.fetchone()
            winner_clan = clan2
            loser_clan = clan1
            c.execute("UPDATE clans SET war_wins = war_wins + 1 WHERE clan_name = ?", (winner_clan,))
            c.execute("UPDATE clans SET loss = loss + 1 WHERE clan_name = ?", (clan1,))
            war_ended = True
            c.execute("SELECT war_history FROM clans WHERE clan_name = ?", (winner_clan,))
            row = c.fetchone()
            history = row[0] if row and row[0] else ""
            entry = f"{winner_clan} defeated {loser_clan} in Battle to the Death\n{total_hp1}\n{total_hp2}"
            updated_history = (entry + "|" + history).strip("|")
            c.execute("UPDATE clans SET war_history = ? WHERE clan_name = ?", (updated_history, winner_clan))
        elif not all_hp2:
            winner_clan = clan1
            loser_clan = clan2
            c.execute("UPDATE clans SET war_wins = war_wins + 1 WHERE clan_name = ?", (winner_clan,))
            c.execute("UPDATE clans SET loss = loss + 1 WHERE clan_name = ?", (clan2,))
            war_ended = True
            c.execute("SELECT war_history FROM clans WHERE clan_name = ?", (winner_clan,))
            row = c.fetchone()
            history = row[0] if row and row[0] else ""
            entry = f"{winner_clan} defeated {loser_clan} in Battle to the Death\n{total_hp1}\n{total_hp2}"
            updated_history = (entry + "|" + history).strip("|")
            c.execute("UPDATE clans SET war_history = ? WHERE clan_name = ?", (updated_history, winner_clan))
            
        conn.commit()
        

        if war_ended:
            # Load clan names
            print('ended')
            winning_clan = winner_clan
            losing_clan = loser_clan

            # Delete the war from database
            c.execute("DELETE FROM cc WHERE id = ?", (str(active_war_id),))
            conn.commit()

            # MVP from damage data
            mvp_text = "No MVP"
            if os.path.exists(damage_log_file):
                with open(damage_log_file, 'r') as f:
                    damage_data = json.load(f)
                if damage_data:
                    mvp_id = max(damage_data, key=damage_data.get)
                    damage_done = damage_data[mvp_id]
                    mvp_text = f"<@{mvp_id}> dealt the most damage (**{damage_done}** hits) and is the MVP!"

                os.remove(damage_log_file)

            # Send war log to a channel
            warlog_channel = discord.utils.get(ctx.guild.text_channels, name="war-updates")
            if not warlog_channel:
                overwrites = {ctx.guild.default_role: discord.PermissionOverwrite(read_messages=True, send_messages=False)}
                warlog_channel = await ctx.guild.create_text_channel("warlog", overwrites=overwrites)

            if mode == 'Adventure':
                hex_code = "#F64012"
            elif mode == 'classic':
                hex_code = "#7F0000"
            else:
                hex_code = "#470B6D"
            color = discord.Color(int(hex_code.lstrip("#"), 16))
            embed = discord.Embed(
                title=f"CC#{active_war_id} Ended!",
                description=f"**{winning_clan}** has defeated **{losing_clan}** in a Battle to the Death!",
                color=color
            )
            embed.add_field(name="MVP", value=mvp_text, inline=False)
            embed.set_footer(text=f"Logged in {ctx.guild.name}")
            embed.timestamp = discord.utils.utcnow()

            await warlog_channel.send(embed=embed)

@clan.command(name = 'conquestsub', aliases = ['cs'])
async def conquestsub(ctx, old_member: discord.Member, new_member: discord.Member):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()
    inviter_id = ctx.author.id
    # Check if user is a clan leader or deputy
    c.execute("SELECT clan_name, deputy_id FROM clans WHERE leader_id = ?", (inviter_id,))
    result = c.fetchone()
    if not result:
        return await ctx.send("You are not authorized to sub members.")

    # Check if old_member is in an ongoing war
    c.execute("""
        SELECT war_id, clan_name FROM conquest_members 
        WHERE user_id = ? 
        AND war_id IN (SELECT id FROM conquest)
    """, (old_member.id,))
    result = c.fetchone()

    if not result:
        return await ctx.send(f"{old_member.mention} is not in any ongoing war.")
    
    war_id, clan_name = result

    # Check new_member is not already in the war
    c.execute("SELECT 1 FROM conquest_members WHERE war_id = ? AND user_id = ?", (war_id, new_member.id))
    if c.fetchone():
        return await ctx.send(f"{new_member.mention} is already part of the war.")

    # Fetch old_member score
    c.execute("SELECT  wins, losses FROM conquest_members WHERE war_id = ? AND user_id = ?", (war_id, old_member.id))
    score_data = c.fetchone()

    # Delete old member
    c.execute("DELETE FROM conquest_members WHERE war_id = ? AND user_id = ?", (war_id, old_member.id))

    # Add new member with same score data
    c.execute("""
        INSERT INTO conquest_members (war_id, clan_name, user_id, wins, losses) 
        VALUES (?, ?, ?, ?, ?)
    """, (war_id, clan_name, new_member.id, *score_data))
    
    conn.commit()
    await ctx.send(f"Replaced {old_member.mention} with {new_member.mention} in Conquest #{war_id} for **{clan_name}**.")  

