def war_emoji(user_id):
    conn_ach = get_db_connection()
    cursor_ach = conn_ach.cursor()
    cursor_ach.execute("SELECT achievement FROM certificates WHERE user_id = ?", (user_id,))
    achievements = cursor_ach.fetchall()
    conn_ach.close()
    if achievements:
        emoji_priority = [
        ('Special Partner', '⚡'),
        ('Herald of Luck', '📯'),
        ('Devil Himself',  '😈'),
        ('Clan Carrier',  '🔱'),
        ('Tournament Winner',  '🏆'),
        ('Absolute Power', '   🐉'),
        ('King of War', '👑'),
        ('Hero of 10k Battles', '🦸'),
        ('Demolisher', '🕊️'),
        ('Clan Elite', '💎'),
        ('Warlord', '☠️'),
        ('Destroyer', '🔥'),
        ('Veteran', '⚔️'),
        ('General', '🌟')
        ]
        for name, emoji in emoji_priority:
            if any(ach[0] == name for ach in achievements):
                return emoji
    return '🥀'

def get_war_mode(guild_id,cc_id):
    file_path = os.path.join('wars', f'{guild_id}.json')
    if os.path.exists(file_path):
        with open(file_path, 'r') as f:
            data = json.load(f)
        mode = data[f'{cc_id}']
    else:
        mode = 'classic'
    return mode

class ClanPingSelect(discord.ui.Select):
    def __init__(self, embed):
        self.embed = embed
        options = [
            discord.SelectOption(label="Ping Clan 1", description="Mention everyone in the first clan"),
            discord.SelectOption(label="Ping Clan 2", description="Mention everyone in the second clan")
        ]
        super().__init__(placeholder="Select a clan to ping", options=options)

    async def callback(self, interaction: discord.Interaction):
        field_index = 1 if self.values[0] == "Ping Clan 1" else 2
        clan_field = self.embed.fields[field_index]
        clan_name = clan_field.name
        clan_members = clan_field.value

        # Remove markdown and clean up mentions
        message_to_send = f"{clan_members}\n\nPinged by {interaction.user.display_name}"

        await interaction.channel.send(message_to_send)
        await interaction.response.send_message(f"✅ Ping sent for **{clan_name}**.", ephemeral=True)

def get_equipped_banner_url(guild_id: int) -> str | None:
    """Returns public image URL of equipped banner or None"""
    conn = sqlite3.connect(f"clan_war_dbs/yes_{guild_id}.db")
    c = conn.cursor()
    c.execute("""
        SELECT b.image_url
        FROM guild_active_war_banner e
        JOIN war_banners b ON e.banner_id = b.banner_id
        WHERE e.guild_id = ?
    """, (guild_id,))
    row = c.fetchone()
    conn.close()
    
    if row and row[0]:
        url = row[0]
        # If it's still a local path, you can return a placeholder or None
        if url.startswith(("file://", "/")):
            return None  # or "https://example.com/default-banner.png"
        return url
    return None    

def _get_clan_war_db_connection(guild_id: int):
    return sqlite3.connect(f"clan_war_dbs/yes_{guild_id}.db")

