@clan.command(name="warinfo")
async def war_info(ctx, war_id: int):
    """Get detailed information on a specific war by ID"""
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()

    # Fetch war details
    c.execute("SELECT clan_1, clan_2, score_to_win FROM war_duels WHERE id = ?", (war_id,))
    war = c.fetchone()
    if not war:
        await ctx.send(f"❌ War with ID `{war_id}` not found.")
        return

    clan_1, clan_2, score_to_win = war

    # Emojis
    c.execute("SELECT emoji FROM clans WHERE clan_name = ?", (clan_1,))
    emoji1 = c.fetchone()
    emoji1 = emoji1[0] if emoji1 else "⚔️"

    c.execute("SELECT emoji FROM clans WHERE clan_name = ?", (clan_2,))
    emoji2 = c.fetchone()
    emoji2 = emoji2[0] if emoji2 else "⚔️"

    # Scores
    c.execute("SELECT clan_name, SUM(wins) FROM war_members WHERE war_id = ? GROUP BY clan_name", (war_id,))
    scores = {row[0]: row[1] for row in c.fetchall()}
    score1 = scores.get(clan_1, 0)
    score2 = scores.get(clan_2, 0)

    embed = discord.Embed(
        title=f"{emoji1} {clan_1} vs {clan_2} {emoji2}",
        description=f"<a:target:1380066013688758272> **War #{war_id}**\n"
                    f"<a:a_y_trophy:1380066286255476747> First to **{score_to_win}** wins!",
        color=discord.Color.blurple()
    )
    embed.add_field(name="<a:stats:1380065848433053747> Scorecard", value="‎", inline=False)

    # Member stats
    def get_member_stats(clan):
        c.execute("SELECT user_id, wins, losses FROM war_members WHERE war_id = ? AND clan_name = ?", (war_id, clan))
        members = c.fetchall()
        if not members:
            return "_No members added yet._"
        return "\n".join([
            f"{war_emoji(user_id)} <@{user_id}> — `{wins}W / {losses}L`"
            for user_id, wins, losses in members
        ])

    embed.add_field(name=f" **{clan_1}** — `{score1}`", value=get_member_stats(clan_1), inline=False)
    embed.add_field(name=f" **{clan_2}** — `{score2}`", value=get_member_stats(clan_2), inline=False)

    # Recent matches
    c.execute("SELECT recent_matches FROM track WHERE guild_id = ? AND war_id = ?", (ctx.guild.id, war_id))
    track_row = c.fetchone()
    if track_row and track_row[0]:
        match_list = track_row[0].split("|")
        formatted_logs = []

        for entry in match_list:
            if f"#{war_id}" not in entry:
                continue

            clean_entry = entry.strip().replace(f"#{war_id} ", "")
            parts = clean_entry.split(" defeated ")

            if len(parts) == 2:
                winner, loser = parts
                formatted_logs.append(f"🟢 {winner.strip()} 🔴 {loser.strip()}")
            else:
                formatted_logs.append(clean_entry)

            if len(formatted_logs) >= 5:
                break

        while len(formatted_logs) < 5:
            formatted_logs.append("_No recent match._")

        embed.add_field(
            name="<a:sword:1378635803680571533> Recent Logs",
            value="\n".join(formatted_logs),
            inline=False
        )
    else:
        embed.add_field(
            name="<a:sword:1378635803680571533> Recent Logs",
            value="_No recent matches for this war._",
            inline=False
        )

    await ctx.send(embed=embed)
    conn.close()

