class RankSelect(discord.ui.View):
    def __init__(self, ctx, member):
        super().__init__(timeout=60)
        self.ctx = ctx
        self.member = member

        # Create dropdown
        options = [
            discord.SelectOption(label="King", description="King of the Server"),
            discord.SelectOption(label="Duke", description="second highest rank"),
            discord.SelectOption(label="Marquis", description="third highest rank"),
            discord.SelectOption(label="Count", description="fourth highest rank"),
            discord.SelectOption(label="Viscount", description="fifth highest rank"),
            discord.SelectOption(label="Baron", description="lowest rank nobility"),
            discord.SelectOption(label="Knight", description="knighted"),
            discord.SelectOption(label="No Rank", description="knighted")
        ]
        self.add_item(RankDropdown(options, self.ctx, self.member))

class RankDropdown(discord.ui.Select):
    def __init__(self, options, ctx, member):
        super().__init__(placeholder="Select a rank...", min_values=1, max_values=1, options=options)
        self.ctx = ctx
        self.member = member

    async def callback(self, interaction: discord.Interaction):
        if interaction.user != self.ctx.author:
            return await interaction.response.send_message("❌ You can’t change ranks in this menu.", ephemeral=True)

        selected_rank = self.values[0]

        folder_name = 'clan_rank'
        os.makedirs(folder_name, exist_ok=True)
        file_path = os.path.join(folder_name, f"{self.ctx.guild.id}.json")

        # Load or create file
        if os.path.exists(file_path):
            with open(file_path, 'r', encoding='utf-8') as f:
                try:
                    data = json.load(f)
                except json.JSONDecodeError:
                    data = {}
        else:
            data = {}

        # Update rank
        data[str(self.member.id)] = selected_rank

        # Save file
        with open(file_path, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2)

        await interaction.response.edit_message(
            content=f"{self.member.mention} has been promoted to `{selected_rank}`.",
            view=None
        )


