def get_user_bal(guild_id: int, user_id: int):
    file_path = os.path.join("clan_bal", f"{guild_id}.json")
    
    if not os.path.exists(file_path):
        return 0  # No rank data for this guild

    with open(file_path, "r", encoding="utf-8") as f:
        try:
            data = json.load(f)
        except json.JSONDecodeError:
            return 0  # File is empty or corrupted

    return data.get(str(user_id))

@clan.command(name="bal_add", aliases=['give', 'baladd', 'reward'])
@commands.has_permissions(administrator=True)
async def bal_add(ctx, member: discord.Member, amount: str):
    number = parse_money_string(amount)
    folder_name = 'clan_bal'
    os.makedirs(folder_name, exist_ok=True)
    file_path = os.path.join(folder_name, f"{ctx.guild.id}.json")
    if os.path.exists(file_path):
        with open(file_path, 'r', encoding='utf-8') as f:
            try:
                data = json.load(f)
            except json.JSONDecodeError:
                data = {}
    else:
        data = {}
    if data.get(str(member.id), 0):
        new = int(data.get(str(member.id), 0)) + int(number)
    else:
        new = number
    data[str(member.id)] = new
    with open(file_path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2)
    await ctx.send(f'Rewarded {member.mention} with {number} coins')

@clan.command(name="bal_remove", aliases=['take', 'balremove', 'subtract'])
@commands.has_permissions(administrator=True)
async def bal_remove(ctx, member: discord.Member, amount: str):
    number = parse_money_string(amount)
    folder_name = 'clan_bal'
    os.makedirs(folder_name, exist_ok=True)
    file_path = os.path.join(folder_name, f"{ctx.guild.id}.json")
    if os.path.exists(file_path):
        with open(file_path, 'r', encoding='utf-8') as f:
            try:
                data = json.load(f)
            except json.JSONDecodeError:
                data = {}
    else:
        data = {}
    if data.get(str(member.id), 0):
        new = int(data.get(str(member.id), 0)) - int(number)
    else:
        new = -int(number)
    data[str(member.id)] = new
    with open(file_path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2)
    await ctx.send(f'Removed {number} coins from {member.mention}')

