@clan.command(name="clear_inventory", aliases = ['clear', 'clear_inv'])
@commands.has_permissions(administrator=True)
async def clear_inventory(ctx, clan_name: str):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    c.execute("SELECT id, clan_name_1, clan_name_2 FROM cc")
    for row in c.fetchall():
        cc_id, c1, c2 = row
        if clan_name == c1:
            c.execute("UPDATE cc SET inventory_clan_1 = ? WHERE id = ?", (json.dumps([]), cc_id))
            conn.commit()
            return await ctx.send(f"🧹 Cleared inventory for **{clan_name}**.")
        elif clan_name == c2:
            c.execute("UPDATE cc SET inventory_clan_2 = ? WHERE id = ?", (json.dumps([]), cc_id))
            conn.commit()
            return await ctx.send(f"🧹 Cleared inventory for **{clan_name}**.")
    conn.close()
    await ctx.send(f"❌ No ongoing CC war found for **{clan_name}**.")
