@clan.command(name="heal")
@commands.has_permissions(administrator=True)
async def heal(ctx, member: discord.Member):
    user_id = member.id
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    c.execute("SELECT * FROM cc")
    for row in c.fetchall():
        cc_id, _, _, p1_json, p2_json, hp1_json, hp2_json, *_ = row
        players_1 = json.loads(p1_json)
        players_2 = json.loads(p2_json)
        hp_1 = json.loads(hp1_json)
        hp_2 = json.loads(hp2_json)

        if user_id in players_1:
            current_hp = hp_1.get(str(user_id), 0)
            hp_1[str(user_id)] = current_hp + 1
            c.execute("UPDATE cc SET hp_clan_1 = ? WHERE id = ?", (json.dumps(hp_1), cc_id))
            conn.commit()
            conn.close()
            return await ctx.send(f"💉 Healed <@{user_id}> to {current_hp + 1} HP in CC War.")
        elif user_id in players_2:
            current_hp = hp_2.get(str(user_id), 0)
            hp_2[str(user_id)] = current_hp + 1
            c.execute("UPDATE cc SET hp_clan_2 = ? WHERE id = ?", (json.dumps(hp_2), cc_id))
            conn.commit()
            conn.close()
            return await ctx.send(f"💉 Healed <@{user_id}> to {current_hp + 1} HP in CC War.")

    await ctx.send("❌ User is not in any ongoing CC war.")
