@clan.command(name="drop_hp")
async def drop_hp(ctx, member: discord.Member):
    user_id = member.id
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Check if the invoker is an admin
    is_admin = ctx.author.guild_permissions.administrator

    # Get invoker's clan if not admin
    invoker_clan = None
    if not is_admin:
        c.execute("SELECT clan_name FROM clans WHERE leader_id = ? OR deputy_id = ?", (ctx.author.id, ctx.author.id))
        result = c.fetchone()
        if not result:
            return await ctx.send("❌ You must be a clan leader, deputy, or admin to use this command.")
        invoker_clan = result[0]

    # Find which CC war this user is in
    c.execute("SELECT * FROM cc")
    rows = c.fetchall()

    for row in rows:
        (
            cc_id, clan_1, clan_2,
            players_1_json, players_2_json,
            hp_1_json, hp_2_json,
            inv_1_json, inv_2_json
        ) = row

        players_1 = json.loads(players_1_json)
        players_2 = json.loads(players_2_json)
        hp_1 = json.loads(hp_1_json)
        hp_2 = json.loads(hp_2_json)

        # Check if member is in the war
        if user_id in players_1:
            if is_admin or (invoker_clan == clan_1):
                hp_1[str(user_id)] = 0
                c.execute("UPDATE cc SET hp_clan_1 = ? WHERE id = ?", (json.dumps(hp_1), cc_id))
                conn.commit()
                conn.close()
                return await ctx.send(f"💀 {member.mention}'s HP has been set to 0 in **{clan_1}**.")
            else:
                return await ctx.send("❌ You can only drop HP of members in your own clan.")
        elif user_id in players_2:
            if is_admin or (invoker_clan == clan_2):
                hp_2[str(user_id)] = 0
                c.execute("UPDATE cc SET hp_clan_2 = ? WHERE id = ?", (json.dumps(hp_2), cc_id))
                conn.commit()
                conn.close()
                return await ctx.send(f"💀 {member.mention}'s HP has been set to 0 in **{clan_2}**.")
            else:
                return await ctx.send("❌ You can only drop HP of members in your own clan.")

    await ctx.send("❌ User is not part of any ongoing CC war.")


@clan.command()
async def use(ctx, item: str, target: discord.User):
    user_id = ctx.author.id
    target_id = target.id
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Step 1: Fetch all ongoing CC wars
    c.execute("SELECT * FROM cc")
    rows = c.fetchall()

    found = False
    for row in rows:
        (
            cc_id, clan_1, clan_2,
            players_1_json, players_2_json,
            hp_1_json, hp_2_json,
            inv_1_json, inv_2_json
        ) = row

        try:
            players_1 = json.loads(players_1_json)
            players_2 = json.loads(players_2_json)
            hp_1 = json.loads(hp_1_json)
            hp_2 = json.loads(hp_2_json)
            inventory_1 = json.loads(inv_1_json)
            inventory_2 = json.loads(inv_2_json)
        except Exception:
            continue

        if user_id in players_1:
            inventory = inventory_1
            user_hp = hp_1
            opponent_hp = hp_2
            user_players = players_1
            opponent_players = players_2
            user_clan = clan_1
            clan_side = 1
        elif user_id in players_2:
            inventory = inventory_2
            user_hp = hp_2
            opponent_hp = hp_1
            user_players = players_2
            opponent_players = players_1
            user_clan = clan_2
            clan_side = 2
        else:
            continue  # This war doesn't include the user
        found = True
        break

    if not found:
        return await ctx.send("❌ You are not part of any ongoing CC war.")

    # Step 2: Check if item exists in inventory
    if item.lower() not in [i.lower() for i in inventory]:
        return await ctx.send(f'❌ Your clan does not have the item `{item}`\nDo "guided missile" for item with 2 words like guided missile.')

    # Remove first match of item (case-insensitive)
    for i in inventory:
        if i.lower() == item.lower():
            inventory.remove(i)
            break

    # Step 3: Handle item logic
    item = item.lower()
    response = ""
    updated = False

    if item == "guided missile":
        if target_id in opponent_players:
            if str(target_id) in opponent_hp and opponent_hp[str(target_id)] > 0:
                opponent_hp[str(target_id)] -= 1
                response = f"<a:missile:1393595604864864400> **Guided Missile** used by <@{user_id}> on <@{target_id}>! Target lost 1 HP."
                updated = True
            else:
                response = f"⚠️ <@{target_id}> already has 0 HP."
        else:
            response = f"❌ <@{target_id}> is not on the opposing team."
    
    elif item == "rocket launcher":
        if target_id in opponent_players:
            if str(target_id) in opponent_hp and opponent_hp[str(target_id)] > 0:
                user_hp[str(user_id)] -= 1
                opponent_hp[str(target_id)] -= 1
                response = f"<a:missile:1393595604864864400> **Rocket** launched by <@{user_id}> on <@{target_id}>! You and Target both lost 1 HP."
                updated = True
            else:
                response = f"⚠️ <@{target_id}> already has 0 HP."
        else:
            response = f"❌ <@{target_id}> is not on the opposing team."

    elif item == "remove":
        if target_id in user_players:
            if str(target_id) in user_hp and user_hp[str(target_id)] > 0:
                user_hp[str(target_id)] = 0
                response = f"<@{user_id}> removed {target_id}."
                updated = True
            else:
                response = f"⚠️ <@{target_id}> already has 0 HP."
        else:
            response = f"❌ <@{target_id}> is not on the opposing team."

    elif item == "high potion":
        if target_id in user_players:
            current_hp = user_hp.get(str(target_id), 0)
            if 1 < current_hp < 4:
                user_hp[str(target_id)] = current_hp + 2
                response = f"<a:potion:1393595902752591962> **Potion** used on <@{target_id}>! Healed 2 HP (now {user_hp[str(target_id)]} HP)."
                updated = True
            else:
                response = f"⚠️ high potion is not effective for the target (only usable at 3 or below hp)"
        else:
            response = f"❌ <@{target_id}> is not on your team."

    elif item == "emergency potion":
        if target_id in user_players:
            current_hp = user_hp.get(str(target_id), 0)
            if current_hp == 1:
                user_hp[str(target_id)] = current_hp + 1
                response = f"<a:potion:1393595902752591962> **Potion** used on <@{target_id}>! Healed 1 HP (now {user_hp[str(target_id)]} HP)."
                updated = True
            else:
                response = f"⚠️ emergency potion is not effective for the target (only usable at 1 hp)"
        else:
            response = f"❌ <@{target_id}> is not on your team."

    elif item == "elixir of life":
        if target_id in user_players:
            current_hp = user_hp.get(str(target_id), 0)
            if current_hp == 0:
                user_hp[str(target_id)] = current_hp + 1
                response = f"<:exlixir:1393596071036588082> **Elixir Of Life** used on <@{target_id}>! He is now alive."
                updated = True
            else:
                response = f"⚠️ target is still alive ||or more dead than you think||"
        else:
            response = f"❌ <@{target_id}> is not on your team."
    
    elif item == "spice of life":
        if target_id in user_players:
            current_hp = user_hp.get(str(target_id), 0)
            if current_hp > 1:
                user_hp[str(target_id)] = current_hp + 1
                response = f"<a:spice:1393596282651541514> **Spice Of Life** used on <@{target_id}>! Their life has been extended by 1 (now {user_hp[str(target_id)]} HP)."
                updated = True
            else:
                response = f"⚠️ spice of life is not effective for the target (please use emergency potion at 1 hp)"
        else:
            response = f"❌ <@{target_id}> is not on your team."
    
    elif item == "life transfer":
        if target_id in user_players:
            current_hp = user_hp.get(str(target_id), 0)
            user_hp[str(user_id)] = current_hp - 1
            user_hp[str(target_id)] = current_hp + 1
            response = f"<a:spice:1393596282651541514> 1 HP transfered <@{user_id}> to <@{target_id}! Their life has been extended by 1 (now {user_hp[str(target_id)]} HP)."
            updated = True
        else:
            response = f"❌ <@{target_id}> is not on your team."
    
    elif item == "big bomb":
        alive_opponents = [uid for uid in opponent_players if opponent_hp.get(str(uid), 0) > 0]
        if not alive_opponents:
            response = "💣 You launched a **Big Bomb**, but there were no valid targets!"
        else:
            target_id = random.choice(alive_opponents)
            opponent_hp[str(target_id)] -= 1
            response = f"<a:explode:1393595283895750697> **Big Bomb** exploded on <@{target_id}>! They lost 1 HP."
            updated = True

    elif item == "golden leaf":
        alive_team = [uid for uid in user_players if user_hp.get(str(uid), 0) > 0]
        if not alive_team:
            response = "Everyone are dead"
        else:
            target_id = random.choice(alive_team)
            user_hp[str(target_id)] += 1
            response = f"<a:leaf:1393596504199004321> **Golden Leaf**'s miracle happened on <@{target_id}>! They got 1 extra HP."
            updated = True
    else:
        response = f"ℹ️ `{item}` was used by <@{user_id}>. (Effect not implemented yet)"

    # Step 4: Update database if necessary
    if updated:
        if clan_side == 1:
            c.execute("UPDATE cc SET inventory_clan_1 = ?, hp_clan_1 = ?, hp_clan_2 = ? WHERE id = ?", (
                json.dumps(inventory),
                json.dumps(user_hp),
                json.dumps(opponent_hp),
                cc_id
            ))
        else:
            c.execute("UPDATE cc SET inventory_clan_2 = ?, hp_clan_2 = ?, hp_clan_1 = ? WHERE id = ?", (
                json.dumps(inventory),
                json.dumps(user_hp),
                json.dumps(opponent_hp),
                cc_id
            ))
    else:
        if clan_side == 1:
            c.execute("UPDATE cc SET inventory_clan_1 = ? WHERE id = ?", (json.dumps(inventory), cc_id))
        else:
            c.execute("UPDATE cc SET inventory_clan_2 = ? WHERE id = ?", (json.dumps(inventory), cc_id))
    conn.commit()
    conn.close()

    await ctx.send(response)

@clan.command(name="set_score_to_win", aliases = ['set_score', 'modify', 'win_condition'])
@commands.has_permissions(administrator=True)
async def set_score_to_win(ctx, war_id: int, new_score: int):
    war_prem = False
    if os.path.exists('war_premium.txt'):
        with open('war_premium.txt', 'r') as f:
            lines = f.readlines()
        if any(str(ctx.guild.id) == line.strip() for line in lines):
            war_prem = True
    if war_prem == False:
        return await ctx.send("❌ This is a Premium Feature. \nFor more info for Premium, ask on support server (/bot_info)")
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()

    c.execute("SELECT * FROM war_duels WHERE id = ?", (war_id,))
    if c.fetchone() is None:
        await ctx.send(f"❌ No war found with ID {war_id}.")
        conn.close()
        return

    c.execute("UPDATE war_duels SET score_to_win = ? WHERE id = ?", (new_score, war_id))
    conn.commit()
    conn.close()
    await ctx.send(f"✅ Updated score to win for war ID {war_id} to {new_score}.\n If the score has already been reached, do 1 more battle.")
