async def set_score_to_win_error(ctx, error):
    if isinstance(error, commands.MissingPermissions):
        await ctx.send("❌ You must have the **Administrator** permission to use this command.")

@clan.command(name="giveitem")
@commands.has_permissions(administrator=True)
async def giveitem(ctx, clan_name: str, item: str, amount: int = 1):
    if amount < 1:
        return await ctx.send("❌ Amount must be at least 1.")
    war_prem = False
    if os.path.exists('war_premium.txt'):
        with open('war_premium.txt', 'r') as f:
            lines = f.readlines()
        if any(str(ctx.guild.id) == line.strip() for line in lines):
            war_prem = True
    if war_prem == False:
        return await ctx.send("❌ This is a Premium Feature. \nIf you want to remove player, use !clan drop_hp. For raise hp, use !clan heal.\nFor more info for Premium, ask on support server (/bot_info)")

    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Find the CC war involving the given clan
    c.execute("SELECT id, clan_name_1, clan_name_2 FROM cc")
    rows = c.fetchall()

    cc_id = None
    target_column = None

    for row in rows:
        _id, c1, c2 = row
        if clan_name == c1:
            cc_id = _id
            target_column = 'inventory_clan_1'
            break
        elif clan_name == c2:
            cc_id = _id
            target_column = 'inventory_clan_2'
            break

    if not cc_id:
        return await ctx.send(f"❌ No ongoing CC war found for clan `{clan_name}`.")

    # Fetch and update inventory
    c.execute(f"SELECT {target_column} FROM cc WHERE id = ?", (cc_id,))
    inventory_json = c.fetchone()[0]
    inventory = json.loads(inventory_json)
    inventory += [item.lower()] * amount

    c.execute(f"UPDATE cc SET {target_column} = ? WHERE id = ?", (json.dumps(inventory), cc_id))
    conn.commit()
    conn.close()

    await ctx.send(f"✅ Added `{item}` x{amount} to `{clan_name}`'s inventory in CC War #{cc_id}.")
@giveitem.error
async def give_item_error(ctx, error):
    if isinstance(error, commands.MissingPermissions):
        await ctx.send("❌ You must have the **Administrator** permission to use this command.")

@clan.command(name = 'inventory', aliases = ['inv'])
async def inventory(ctx, war:str = None):
    global clan_collection_points_cache
    user_id = ctx.author.id
    g_clan_name, _, g_clan = find_user_global_clan(user_id)
    if g_clan and not war:
        rows = get_global_clan_inventory(g_clan["id"])
        if not rows:
            return await ctx.send(f"🧰 **{g_clan_name}'s Clan Inventory** is currently empty.")
        counted = Counter(
            (
                r["category"],
                r["cosmetic_name"],
                r.get("pokemon_name") or "",
            )
            for r in rows
        )
        lines = []
        current = clan_collection_points_cache.get(user_id, 0)
        for (category, cosmetic_name, pokemon_name), count in counted.items():
            if pokemon_name:
                lines.append(f"• `{category}` `{cosmetic_name}` `{pokemon_name}` x{count}")
            else:
                lines.append(f"• `{category}` `{cosmetic_name}` x{count}")
            current += 42
        clan_collection_points_cache[user_id] = current 
        embed = discord.Embed(
            title=f"🧰 {g_clan_name}'s Global Inventory",
            description="\n".join(lines[:30]),
            color=discord.Color.gold()
        )
        embed.set_footer(text="Use `!clan skins` to make your own clan skins.")
        if len(lines) > 30:
            embed.set_footer(text=f"Showing 30/{len(lines)} items")
        await ctx.send(embed=embed, view=GlobalClanInventoryView(ctx.author.id, rows))
        return

    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    c.execute("SELECT * FROM cc")
    rows = c.fetchall()

    for row in rows:
        (
            cc_id, clan_1, clan_2,
            players_1_json, players_2_json,
            hp_1_json, hp_2_json,
            inv_1_json, inv_2_json
        ) = row

        try:
            players_1 = json.loads(players_1_json)
            players_2 = json.loads(players_2_json)
            inventory_1 = json.loads(inv_1_json)
            inventory_2 = json.loads(inv_2_json)
        except Exception:
            continue

        if user_id in players_1:
            inventory = inventory_1
            clan_name = clan_1
            break
        elif user_id in players_2:
            inventory = inventory_2
            clan_name = clan_2
            break
    else:
        return await ctx.send("❌ You are not part of any ongoing CC war.")

    if not inventory:
        return await ctx.send(f"🧰 **{clan_name}'s Inventory** is currently empty.")

    counted = Counter(inventory)
    item_list = '\n'.join(f"• `{item}` x{count}" for item, count in counted.items())

    embed = discord.Embed(
        title=f"🧰 {clan_name}'s Inventory",
        description=item_list,
        color=discord.Color.blurple()
    )
    await ctx.send(embed=embed)

