@clan.command()
async def leave(ctx):
    user_id = ctx.author.id
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()
    # Check if user is in a clan
    c.execute("SELECT clan_name FROM clan_members WHERE user_id = ?", (user_id,))
    result = c.fetchone()
    if not result:
        conn.close()
        return await ctx.send("You are not in any clan.")

    clan_name = result[0]

    # Check if user is the leader
    c.execute("SELECT leader_id FROM clans WHERE clan_name = ?", (clan_name,))
    leader_result = c.fetchone()
    if leader_result and leader_result[0] == user_id:
        conn.close()
        return await ctx.send("You are the leader of the clan. Please assign a new leader or delete the clan before leaving.")

    view = LeaveClanView(user_id)
    await ctx.send(f"{ctx.author.mention}, are you sure you want to leave **{clan_name}**?", view=view)

    await view.wait()
    if view.value is None:
        conn.close()
        return await ctx.send("Timed out. Leave request cancelled.")

    if view.value:
        c.execute("DELETE FROM clan_members WHERE user_id = ?", (user_id,))
        c.execute("SELECT deputy_id FROM clans WHERE clan_name = ?", (clan_name,))
        deputy = c.fetchone()
        if deputy[0]:
            if int(user_id) == int(deputy[0]):
                c.execute("UPDATE clans SET deputy_id = ? WHERE clan_name = ?", (None, clan_name))
        conn.commit()
        await ctx.send(f"{ctx.author.mention}, you have left **{clan_name}**.")
    else:
        conn.close()
        await ctx.send("Leave request cancelled.")

def get_user_rank(guild_id: int, user_id: int):
    file_path = os.path.join("clan_rank", f"{guild_id}.json")
    
    if not os.path.exists(file_path):
        return 'commoner'  # No rank data for this guild

    with open(file_path, "r", encoding="utf-8") as f:
        try:
            data = json.load(f)
        except json.JSONDecodeError:
            return 'commoner'  # File is empty or corrupted

    return data.get(str(user_id))

