@clan.command()
async def pf2(ctx, member: discord.Member = None):
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()

    # Use command author if no member is mentioned
    target = member or ctx.author
    user_id = str(target.id)

    # Get profile data and clan name from clan_members
    c.execute("""
        SELECT p.wins, p.losses, p.total, p.win_rate,
               COALESCE(cm.clan_name, 'No Clan') as clan_name
        FROM profile1 p
        LEFT JOIN clan_members cm ON p.user_id = cm.user_id
        WHERE p.user_id = ?
    """, (user_id,))
    row = c.fetchone()

    if not row:
        return await ctx.send(f"No profile found for <@{user_id}>.")

    wins, losses, total, win_rate, clan_name = row

    # Get highest role excluding @everyone
    roles = [role for role in target.roles if role != ctx.guild.default_role]
    highest_role = max(roles, key=lambda r: r.position).mention if roles else "—"

    rank = get_user_rank(int(ctx.guild.id), int(target.id))
    if rank == 'King':
        hex_code = "#FBDC14"  
        color = discord.Color(int(hex_code.lstrip("#"), 16))
    elif rank == 'Duke' or rank == 'Marquis':
        hex_code = "#0110B0"  
        color = discord.Color(int(hex_code.lstrip("#"), 16))
    elif rank == 'Count' or rank == 'Viscount':
        hex_code = "#3BF08C"  
        color = discord.Color(int(hex_code.lstrip("#"), 16))
    elif rank == 'Baron' or rank == 'Knight':
        hex_code = "#2BEDED"  
        color = discord.Color(int(hex_code.lstrip("#"), 16))
    else:
        color = discord.Color.orange()
    embed = discord.Embed(
        title=f"Profile Information – {target.display_name}",
        color=color
    )
    embed.set_thumbnail(url=target.display_avatar.url)
    embed.add_field(name="__**Clan**__", value=f"`{clan_name}`", inline=False)
    embed.add_field(name="__**Win Rate**__", value=f"`{win_rate:.2%}`", inline=False)
    embed.add_field(name="__**Rank**__", value=get_user_rank(int(ctx.guild.id), int(target.id)), inline=False)
    embed.add_field(name="__**Server Role**__", value=highest_role, inline=False)
    embed.add_field(
        name="__**General Stats**__",
        value=f"__**Wins**__: `{wins}` | __**Losses**__: `{losses}` | **Total**: `{total}`",
        inline=False
    )
    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute("SELECT achievement FROM certificates WHERE user_id = ?", (user_id,))
    achievements = cursor.fetchall()
    conn.close()
    if achievements:
        badge_list = "|".join(get_emoji_for_achievement(ach[0]) for ach in achievements)
    else:
        badge_list = "N/A"
    embed.add_field(name = '__**Achievements:**__', value = badge_list, inline = False)
    embed.set_footer(text=f'{ctx.guild.name}')
    await ctx.send(embed=embed)    
import copy

# Global cache for the task loop
league_cache = {
    "players": {},       # { (guild_id, user_id): {"wins": 0, "losses": 0, "clan": "name"} }
    "clan_wins": [],     # [ (guild_id, winning_clan, losing_clan) ]
    "streaks": []        # [ (guild_id, user_id, streak_count, clan_name) ]
}

def setup_league_tables(conn):
    c = conn.cursor()
    c.execute("""
        CREATE TABLE IF NOT EXISTS league_table (
            clan_name TEXT PRIMARY KEY,
            points INTEGER DEFAULT 0,
            wins INTEGER DEFAULT 0,
            losses INTEGER DEFAULT 0,
            leader_id INTEGER,
            manual_mode BOOLEAN DEFAULT 0
        )
    """)
    c.execute("""
        CREATE TABLE IF NOT EXISTS league_players (
            user_id INTEGER PRIMARY KEY,
            wins INTEGER DEFAULT 0,
            losses INTEGER DEFAULT 0,
            streak INTEGER DEFAULT 0,
            clan_name TEXT
        )
    """)
    c.execute("""
        CREATE TABLE IF NOT EXISTS league_news (
            guild_id INTEGER PRIMARY KEY,
            total_pool INTEGER DEFAULT 0,
            subscribers TEXT DEFAULT '[]'
        )
    """)
    c.execute("""
        CREATE TABLE IF NOT EXISTS league_matches (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            guild_id INTEGER,
            round_num INTEGER,
            clan_1 TEXT,
            clan_2 TEXT,
            completed BOOLEAN DEFAULT 0
        )
    """)
    conn.commit()

def generate_league_image(data):
    # data: (clan_name, points, wins, losses, leader_name)

    from PIL import Image, ImageDraw, ImageFont
    from io import BytesIO

    width = 1000
    header_height = 70
    row_height = 75

    height = header_height + (len(data) * row_height) + 30


    img = Image.new(
        "RGB",
        (width, height),
        (15, 17, 22)
    )

    draw = ImageDraw.Draw(img)


    try:
        font = _fnt(22, False)
        bold_font = _fnt(23, True)
        header_font = _fnt(24, True)

    except:
        font = bold_font = header_font = ImageFont.load_default()



    # =====================
    # Max values for bars
    # =====================

    max_points = max([x[1] for x in data])

    max_wins = max([x[2] for x in data])

    max_losses = max([x[3] for x in data])



    # =====================
    # Header
    # =====================

    y = 10

    draw.rounded_rectangle(
        (20,y,width-20,y+header_height),
        radius=12,
        fill=(35,40,50),
        outline=(212,175,55),
        width=2
    )


    headers = [
        "#",
        "CLAN",
        "POINTS",
        "WINS",
        "LOSSES",
        "LEADER"
    ]


    x = [
        45,
        120,
        350,
        500,
        630,
        800
    ]


    for i,text in enumerate(headers):
        draw.text(
            (x[i], y+22),
            text,
            fill=(230,230,230),
            font=header_font
        )



    y += header_height



    # =====================
    # Rows
    # =====================

    for idx,row in enumerate(data):

        clan, points, wins, losses, leader = row
        if int(max_points) == 0:
            max_points = 1
        if int(max_wins) == 0:
            max_wins = 1
        if int(max_losses) == 0:
            max_losses = 1


        if idx == 0:
            bg = (70,55,20)
        elif idx % 2:
            bg = (25,29,36)
        else:
            bg = (20,23,29)



        draw.rounded_rectangle(
            (20,y+5,width-20,y+row_height),
            radius=12,
            fill=bg
        )



        # rank circle

        rank_color = (
            (255,215,80)
            if idx == 0
            else
            (150,150,150)
        )


        draw.ellipse(
            (35,y+18,80,y+63),
            fill=rank_color
        )


        draw.text(
            (57,y+40),
            str(idx+1),
            anchor="mm",
            fill=(20,20,20),
            font=bold_font
        )



        # clan name

        draw.text(
            (x[1],y+20),
            clan,
            fill=(255,255,255),
            font=bold_font
        )



        # points

        draw.text(
            (x[2],y+15),
            f"{points:,}",
            fill=(255,215,80),
            font=bold_font
        )


        # points bar

        draw.rounded_rectangle(
            (
                x[2],
                y+48,
                x[2]+110,
                y+56
            ),
            radius=5,
            fill=(50,55,65)
        )


        draw.rounded_rectangle(
            (
                x[2],
                y+48,
                x[2] + (110*(points/max_points)),
                y+56
            ),
            radius=5,
            fill=(255,215,80)
        )



        # wins

        draw.text(
            (x[3],y+15),
            str(wins),
            fill=(90,220,120),
            font=bold_font
        )


        draw.rounded_rectangle(
            (
                x[3],
                y+48,
                x[3]+70,
                y+56
            ),
            radius=5,
            fill=(50,55,65)
        )


        draw.rounded_rectangle(
            (
                x[3],
                y+48,
                x[3]+(70*(wins/max_wins)),
                y+56
            ),
            radius=5,
            fill=(90,220,120)
        )



        # losses

        draw.text(
            (x[4],y+15),
            str(losses),
            fill=(240,90,90),
            font=bold_font
        )


        draw.rounded_rectangle(
            (
                x[4],
                y+48,
                x[4]+70,
                y+56
            ),
            radius=5,
            fill=(50,55,65)
        )


        draw.rounded_rectangle(
            (
                x[4],
                y+48,
                x[4]+(70*(losses/max_losses)),
                y+56
            ),
            radius=5,
            fill=(240,90,90)
        )



        # leader

        draw.text(
            (x[5],y+22),
            leader,
            fill=(220,220,220),
            font=font
        )


        y += row_height



    # bottom gold line

    draw.line(
        (25,height-15,width-25,height-15),
        fill=(212,175,55),
        width=3
    )



    buffer = BytesIO()

    img.save(
        buffer,
        "PNG"
    )

    buffer.seek(0)

    return buffer

class ModifyLeagueModal(discord.ui.Modal, title="Modify Clan Stats"):
    points = discord.ui.TextInput(label="Points", style=discord.TextStyle.short)
    wins = discord.ui.TextInput(label="Wins", style=discord.TextStyle.short)
    losses = discord.ui.TextInput(label="Losses", style=discord.TextStyle.short)

    def __init__(self, clan_name, current_pts, current_wins, current_loss, guild_id):
        super().__init__()
        self.clan_name = clan_name
        self.guild_id = guild_id
        self.points.default = str(current_pts)
        self.wins.default = str(current_wins)
        self.losses.default = str(current_loss)

    async def on_submit(self, interaction: discord.Interaction):
        conn = get_db_connection(self.guild_id)
        c = conn.cursor()
        c.execute("""
            UPDATE league_table 
            SET points = ?, wins = ?, losses = ? 
            WHERE clan_name = ?
        """, (int(self.points.value), int(self.wins.value), int(self.losses.value), self.clan_name))
        conn.commit()
        conn.close()
        await interaction.response.send_message(f"✅ {self.clan_name} updated successfully.", ephemeral=True)

class ModifyClanSelect(discord.ui.Select):
    def __init__(self, clans, guild_id):
        self.guild_id = guild_id
        options = [discord.SelectOption(label=c[0], description=f"Pts: {c[1]}") for c in clans[:25]]
        super().__init__(placeholder="Select clan to modify...", options=options)

    async def callback(self, interaction: discord.Interaction):
        clan_name = self.values[0]
        conn = get_db_connection(self.guild_id)
        c = conn.cursor()
        c.execute("SELECT points, wins, losses FROM league_table WHERE clan_name = ?", (clan_name,))
        stats = c.fetchone()
        conn.close()
        
        modal = ModifyLeagueModal(clan_name, stats[0], stats[1], stats[2], self.guild_id)
        await interaction.response.send_modal(modal)

@tasks.loop(minutes=5.0)
async def process_league_cache():
    global league_cache
    if not league_cache["players"] and not league_cache["clan_wins"]:
        return

    # Create a local copy to process and clear global cache to avoid missing new entries during processing
    cache_to_process = copy.deepcopy(league_cache)
    league_cache["players"].clear()
    league_cache["clan_wins"].clear()
    league_cache["streaks"].clear()
    processed_players = 0

    # Process by guild to handle DB connections safely
    guilds_to_process = set([g_id for g_id, _ in cache_to_process["players"].keys()] + [cw[0] for cw in cache_to_process["clan_wins"]])

    for guild_id in guilds_to_process:
        try:
            conn = get_db_connection(guild_id)
            c = conn.cursor()
            
            # 1. Check League News / Subscribers / Pool
            c.execute("SELECT total_pool, subscribers FROM league_news WHERE guild_id = ?", (guild_id,))
            news_row = c.fetchone()
            total_pool = news_row[0] if news_row else 0
            subscribers = json.loads(news_row[1]) if news_row and news_row[1] else []

            # 2. Process Players
            for (g_id, user_id), stats in cache_to_process["players"].items():
                if g_id != guild_id: continue
                
                c.execute("SELECT wins, losses, streak FROM league_players WHERE user_id = ?", (user_id,))
                p_row = c.fetchone()
                
                w, l, streak = (0, 0, 0) if not p_row else p_row
                new_w = w + stats["wins"]
                new_l = l + stats["losses"]
                new_streak = (streak + stats["wins"]) if stats["losses"] == 0 else 0 # simple streak logic
                
                c.execute("""
                    INSERT INTO league_players (user_id, wins, losses, streak, clan_name) 
                    VALUES (?, ?, ?, ?, ?)
                    ON CONFLICT(user_id) DO UPDATE SET wins=excluded.wins, losses=excluded.losses, streak=excluded.streak
                """, (user_id, new_w, new_l, new_streak, stats["clan"]))

                # Handle player economy + streaks
                for _ in range(stats["wins"]):
                    if total_pool >= 5:
                        total_pool -= 5
                        # ASSUMING you have a modify_coins function:
                        modify_coins(user_id, 5) 

                # Check if hit milestone streak
                if new_streak in [3, 6, 9] and stats["wins"] > 0:
                    for sub_id in subscribers:
                        user = bot.get_user(sub_id)
                        if user:
                            try: await user.send(f"🔥 <@{user_id}> of {stats['clan']} has achieved a win streak of {new_streak}!\n-# You can unsubcribe to clan news by !clan unsubscribe")
                            except: pass
                processed_players += 1
            # 3. Process Clan Wins
            for cw in cache_to_process["clan_wins"]:
                if cw[0] != guild_id: continue
                winner_clan, loser_clan = cw[1], cw[2]

                c.execute("SELECT manual_mode FROM league_table WHERE clan_name = ?", (winner_clan,))
                row = c.fetchone()
                manual_mode = row[0] if row else False

                if not manual_mode:
                    # Update Winner
                    c.execute("UPDATE league_table SET wins = wins + 1, points = points + 100 WHERE clan_name = ?", (winner_clan,))
                    # Update Loser
                    c.execute("UPDATE league_table SET losses = losses + 1 WHERE clan_name = ?", (loser_clan,))
                    
                    # Get ranks for DM
                    c.execute("SELECT clan_name FROM league_table ORDER BY points DESC, wins DESC")
                    rankings = [r[0] for r in c.fetchall()]
                    new_rank = rankings.index(winner_clan) + 1 if winner_clan in rankings else "?"

                    # Economy & DM to clan members
                    c.execute("SELECT user_id FROM clan_members WHERE clan_name = ?", (winner_clan,))
                    for m_row in c.fetchall():
                        modify_coins(m_row[0], 10)
                        u = bot.get_user(m_row[0])
                        if u:
                            try: await u.send(f"🎉 Your clan {winner_clan} just won a war! You earned 10 coins.")
                            except: pass
                    
                    # DM Subscribers
                    for sub_id in subscribers:
                        u = bot.get_user(sub_id)
                        if u:
                            try: await u.send(f"⚔️ **{winner_clan}** has defeated **{loser_clan}**! They are now Rank {new_rank}.\n-# You can unsubcribe to clan news by !clan unsubscribe")
                            except: pass

            # Save pool updates
            c.execute("UPDATE league_news SET total_pool = ? WHERE guild_id = ?", (total_pool, guild_id))
            conn.commit()
            conn.close()
        except Exception:
            traceback.print_exc()
    print(f"process_league_cache: {processed_players}")

class LeagueView(discord.ui.View):
    def __init__(self, ctx, manual_mode, clans_data, current_page=0, current_sort="points"):
        super().__init__(timeout=120)
        self.ctx = ctx
        self.manual_mode = manual_mode
        self.clans_data = clans_data  # Raw/unsorted master array passed from command
        
        self.current_page = current_page
        self.current_sort = current_sort
        self.items_per_page = 5
        
        # 1. Sort master dataset based on the current active sorting rule
        sort_idx = {"points": 1, "wins": 2, "losses": 3}[self.current_sort]
        reverse_sort = self.current_sort != "losses"  # True for points/wins, False for losses
        self.sorted_data = sorted(self.clans_data, key=lambda x: x[sort_idx], reverse=reverse_sort)
        
        # 2. Calculate dynamic page count limits
        self.total_pages = max(1, (len(self.sorted_data) + self.items_per_page - 1) // self.items_per_page)

        # 3. Setup Dropdown Select Menu
        sort_options = [
            discord.SelectOption(label="Sort by Points", value="points", default=(self.current_sort == "points")),
            discord.SelectOption(label="Sort by Wins", value="wins", default=(self.current_sort == "wins")),
            discord.SelectOption(label="Sort by Losses", value="losses", default=(self.current_sort == "losses"))
        ]
        self.select = discord.ui.Select(placeholder="Sort Leaderboard...", options=sort_options, custom_id="sort_select")
        self.select.callback = self.sort_callback
        self.add_item(self.select)

        # 4. Setup Paginator Navigation Buttons
        self.prev_btn = discord.ui.Button(
            label="◀ Previous", 
            style=discord.ButtonStyle.secondary, 
            disabled=(self.current_page == 0)
        )
        self.prev_btn.callback = self.prev_page_callback
        self.add_item(self.prev_btn)

        self.next_btn = discord.ui.Button(
            label="Next ▶", 
            style=discord.ButtonStyle.secondary, 
            disabled=(self.current_page >= self.total_pages - 1)
        )
        self.next_btn.callback = self.next_page_callback
        self.add_item(self.next_btn)

        # 5. Setup Action / Administration Modifiers
        if not manual_mode:
            btn = discord.ui.Button(label="Manual", style=discord.ButtonStyle.danger, custom_id="toggle_manual")
            btn.callback = self.toggle_mode
            self.add_item(btn)
        else:
            mod_btn = discord.ui.Button(label="Modify", style=discord.ButtonStyle.primary, custom_id="mod_btn")
            mod_btn.callback = self.modify_callback
            self.add_item(mod_btn)
            
            auto_btn = discord.ui.Button(label="Auto", style=discord.ButtonStyle.success, custom_id="toggle_auto")
            auto_btn.callback = self.toggle_mode
            self.add_item(auto_btn)

    def get_current_page_slice(self):
        """Helper to safely retrieve the 5 clans allocated to the current page index"""
        start = self.current_page * self.items_per_page
        end = start + self.items_per_page
        return self.sorted_data[start:end]

    async def update_view_message(self, interaction: discord.Interaction):
        """Generates the new page image snippet and updates the interface state layout"""
        sliced_data = self.get_current_page_slice()
        buffer = generate_league_image(sliced_data)
        file = discord.File(fp=buffer, filename="league.png")
        
        # Instantiate updated layout to reconstruct buttons with proper disabled properties
        new_view = LeagueView(
            ctx=self.ctx,
            manual_mode=self.manual_mode,
            clans_data=self.clans_data,
            current_page=self.current_page,
            current_sort=self.current_sort
        )
        
        page_content = f"🏆 **Clan League Leaderboard** (Page {self.current_page + 1}/{new_view.total_pages})"
        await interaction.response.edit_message(content=page_content, attachments=[file], view=new_view)

    async def sort_callback(self, interaction: discord.Interaction):
        self.current_sort = self.select.values[0]
        self.current_page = 0  # Reset pagination to page 1 upon altering filter criteria
        await self.update_view_message(interaction)

    async def prev_page_callback(self, interaction: discord.Interaction):
        if self.current_page > 0:
            self.current_page -= 1
            await self.update_view_message(interaction)

    async def next_page_callback(self, interaction: discord.Interaction):
        if self.current_page < self.total_pages - 1:
            self.current_page += 1
            await self.update_view_message(interaction)

    async def toggle_mode(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message("Admins only.", ephemeral=True)
            
        new_mode = not self.manual_mode
        conn = get_db_connection(self.ctx.guild.id)
        c = conn.cursor()
        c.execute("UPDATE league_table SET manual_mode = ?", (new_mode,))
        conn.commit()
        conn.close()
        
        self.manual_mode = new_mode
        await self.update_view_message(interaction)

    async def modify_callback(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message("Admins only.", ephemeral=True)
        view = discord.ui.View()
        view.add_item(ModifyClanSelect(self.clans_data, self.ctx.guild.id))
        await interaction.response.send_message("Select a clan to modify:", view=view, ephemeral=True)


@clan.command(name="league")
async def clan_league(ctx):
    conn = get_db_connection(ctx.guild.id)
    setup_league_tables(conn)
    c = conn.cursor()

    # Sync and update current leader ids from the main clans table
    c.execute("SELECT clan_name, leader_id FROM clans")
    for clan_name, leader_id in c.fetchall():
        c.execute("""
            INSERT INTO league_table (clan_name, leader_id) VALUES (?, ?)
            ON CONFLICT(clan_name) DO UPDATE SET leader_id = excluded.leader_id
        """, (clan_name, leader_id))
    conn.commit()

    c.execute("SELECT clan_name, points, wins, losses, leader_id, manual_mode FROM league_table")
    rows = c.fetchall()
    
    if not rows:
        conn.close()
        return await ctx.send("No clans exist yet.")

    manual_mode = any(r[5] for r in rows)
    
    # Bulletproof Asynchronous Leader Resolution
    display_data = []
    for r in rows:
        clan_name, points, wins, losses, leader_id, _ = r
        leader_name = "Unknown"
        
        if leader_id:
            # 1. Try local cache
            member = ctx.guild.get_member(leader_id)
            if member:
                leader_name = member.display_name
            else:
                # 2. Try fetching from guild API
                try:
                    member = await ctx.guild.fetch_member(leader_id)
                    leader_name = member.display_name
                except Exception:
                    # 3. Try fetching from global User API
                    try:
                        user = await ctx.bot.fetch_user(leader_id)
                        leader_name = user.name
                    except Exception:
                        leader_name = f"ID: {leader_id}"

        display_data.append((clan_name, points, wins, losses, leader_name))

    conn.close()

    # Pass the initial setup states directly into the View constructor
    view = LeagueView(ctx, manual_mode, display_data, current_page=0, current_sort="points")
    
    # Generate the initial slice (Page 1)
    initial_slice = view.get_current_page_slice()
    buffer = generate_league_image(initial_slice)
    file = discord.File(fp=buffer, filename="league.png")
    
    await ctx.send(
        content=f"🏆 **Clan League Leaderboard** (Page 1/{view.total_pages})", 
        file=file, 
        view=view
    )
