@clan.command(name="restock")
async def clan_restock(ctx, amount: int):
    conn = connect_poke_db()
    c = conn.cursor()
    c.execute(
        "UPDATE poke SET coins = coins - ? WHERE player_id = ? AND coins >= ?",
        (amount, ctx.author.id, amount),
    )
    if c.rowcount == 0:
        conn.close()
        return await ctx.send("❌ Not enough ARCs.")
