@clan.command(name="subscribe")
async def clan_subscribe(ctx):
    conn = get_db_connection(ctx.guild.id)
    setup_league_tables(conn)
    c = conn.cursor()
    c.execute("SELECT subscribers FROM league_news WHERE guild_id = ?", (ctx.guild.id,))
    row = c.fetchone()
    subs = json.loads(row[0]) if row and row[0] else []
    
    if ctx.author.id not in subs:
        subs.append(ctx.author.id)
        c.execute("INSERT INTO league_news (guild_id, subscribers) VALUES (?, ?) ON CONFLICT(guild_id) DO UPDATE SET subscribers = ?", (ctx.guild.id, json.dumps(subs), json.dumps(subs)))
        conn.commit()
        await ctx.send("✅ Subscribed to league news.")
    else:
        await ctx.send("You are already subscribed.")
    conn.close()

@clan.command(name="unsubscribe")
async def clan_unsubscribe(ctx):
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()
    c.execute("SELECT subscribers FROM league_news WHERE guild_id = ?", (ctx.guild.id,))
    row = c.fetchone()
    subs = json.loads(row[0]) if row and row[0] else []
    
    if ctx.author.id in subs:
        subs.remove(ctx.author.id)
        c.execute("UPDATE league_news SET subscribers = ? WHERE guild_id = ?", (json.dumps(subs), ctx.guild.id))
        conn.commit()
        await ctx.send("❌ Unsubscribed from league news.")
    else:
        await ctx.send("You are not subscribed.")
    conn.close()

class RoundsView(discord.ui.View):
    def __init__(self, ctx, current_round=1):
        super().__init__(timeout=300)
        self.ctx = ctx
        self.current_round = current_round

    async def update_display(self, interaction: discord.Interaction):
        conn = get_db_connection(self.ctx.guild.id)
        c = conn.cursor()
        
        # Fetch matches for the targeted round
        c.execute("SELECT clan_1, clan_2, completed FROM league_matches WHERE guild_id = ? AND round_num = ?", (self.ctx.guild.id, self.current_round))
        matches = c.fetchall()
        
        if not matches:
            conn.close()
            return await interaction.response.send_message("❌ This round does not contain any matchups.", ephemeral=True)

        # Determine color status based on completion state
        is_completed = all(m[2] for m in matches)
        color = discord.Color.green() if is_completed else discord.Color.red()
        
        desc = "\n".join([f"⚔️ **{m[0]}** vs **{m[1]}** {' (✅ Completed)' if m[2] else ' (⏳ Pending)'}" for m in matches])
        embed = discord.Embed(title=f"Round {self.current_round} Matchups", description=desc, color=color)
        
        # Update navigation element parameters dynamically
        self.prev_btn.disabled = (self.current_round <= 1)
        self.complete_btn.disabled = is_completed
        self.complete_btn.label = "Completed" if is_completed else "Complete"
        
        conn.close()
        await interaction.response.edit_message(embed=embed, view=self)

    @discord.ui.button(label="Previous Round", style=discord.ButtonStyle.secondary, custom_id="rounds_prev")
    async def prev_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not discord.utils.get(interaction.user.roles, name="Clan"):
            return await interaction.response.send_message("You need the **Clan** role to use this view.", ephemeral=True)
        
        if self.current_round > 1:
            self.current_round -= 1
            await self.update_display(interaction)
        else:
            await interaction.response.send_message("You are on the first round.", ephemeral=True)

    @discord.ui.button(label="Complete", style=discord.ButtonStyle.success, custom_id="rounds_complete")
    async def complete_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not discord.utils.get(interaction.user.roles, name="Clan"):
            return await interaction.response.send_message("You need the **Clan** role to use this view.", ephemeral=True)
            
        conn = get_db_connection(self.ctx.guild.id)
        c = conn.cursor()
        c.execute("UPDATE league_matches SET completed = 1 WHERE guild_id = ? AND round_num = ?", (self.ctx.guild.id, self.current_round))
        conn.commit()
        conn.close()
        
        await self.update_display(interaction)

    @discord.ui.button(label="Next Round", style=discord.ButtonStyle.primary, custom_id="rounds_next")
    async def next_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not discord.utils.get(interaction.user.roles, name="Clan"):
            return await interaction.response.send_message("You need the **Clan** role to use this view.", ephemeral=True)
            
        conn = get_db_connection(self.ctx.guild.id)
        c = conn.cursor()
        
        next_r = self.current_round + 1
        
        # Look ahead in the DB to check if the next round was already generated
        c.execute("SELECT COUNT(*) FROM league_matches WHERE guild_id = ? AND round_num = ?", (self.ctx.guild.id, next_r))
        exists = c.fetchone()[0] > 0
        
        if exists:
            self.current_round = next_r
            conn.close()
            await self.update_display(interaction)
            return

        # If it doesn't exist yet, try to generate a new round layout
        c.execute("SELECT clan_name FROM clans")
        clans = [r[0] for r in c.fetchall()]
        
        if not clans:
            conn.close()
            return await interaction.response.send_message("No clans found to generate matches.", ephemeral=True)
            
        c.execute("SELECT clan_1, clan_2 FROM league_matches WHERE guild_id = ?", (self.ctx.guild.id,))
        past_matches = set(tuple(sorted((r[0], r[1]))) for r in c.fetchall())
        
        new_matchups = generate_round_matchups(clans, past_matches)
        
        if not new_matchups:
            conn.close()
            return await interaction.response.send_message("🏁 All unique round combinations have been exhausted!", ephemeral=True)
            
        for m in new_matchups:
            c.execute("INSERT INTO league_matches (guild_id, round_num, clan_1, clan_2, completed) VALUES (?, ?, ?, ?, 0)", (self.ctx.guild.id, next_r, m[0], m[1]))
        
        conn.commit()
        conn.close()
        
        self.current_round = next_r
        await self.update_display(interaction)

    @discord.ui.button(label="Reset All Rounds", style=discord.ButtonStyle.danger, custom_id="rounds_reset")
    async def reset_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        # Ensure only users with the Clan role or Administrators can reset all metrics
        if not discord.utils.get(interaction.user.roles, name="Clan") and not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message("❌ You need the **Clan** role or Administrator permissions to reset rounds data.", ephemeral=True)
        
        conn = get_db_connection(self.ctx.guild.id)
        c = conn.cursor()
        
        # 1. Clear out all history for this server
        c.execute("DELETE FROM league_matches WHERE guild_id = ?", (self.ctx.guild.id,))
        
        # 2. Re-initialize a fresh Round 1 setup right away
        c.execute("SELECT clan_name FROM clans")
        clans = [r[0] for r in c.fetchall()]
        
        if len(clans) < 2:
            conn.commit()
            conn.close()
            return await interaction.response.send_message("⚠️ All matchups wiped! Cannot auto-generate Round 1 because there are fewer than 2 clans.", ephemeral=True)
            
        new_matchups = generate_round_matchups(clans, set())
        for m in new_matchups:
            c.execute("INSERT INTO league_matches (guild_id, round_num, clan_1, clan_2, completed) VALUES (?, 1, ?, ?, 0)", (self.ctx.guild.id, m[0], m[1]))
            
        conn.commit()
        conn.close()
        
        # 3. Flip view state back to round 1 and refresh the view container safely
        self.current_round = 1
        await self.update_display(interaction)


@clan.command(name="rounds")
async def clan_rounds(ctx):
    if not discord.utils.get(ctx.author.roles, name="Clan") and not ctx.author.guild_permissions.administrator:
        return await ctx.send("You need the **Clan** role to use this command.")
    
    conn = get_db_connection(ctx.guild.id)
    setup_league_tables(conn)
    c = conn.cursor()
    
    # Locate the highest existing round to maintain continuation
    c.execute("SELECT MAX(round_num) FROM league_matches WHERE guild_id = ?", (ctx.guild.id,))
    max_round = c.fetchone()[0]
    
    if not max_round or max_round == 0:
        # Initialize Round 1 instantly if empty
        c.execute("SELECT clan_name FROM clans")
        clans = [r[0] for r in c.fetchall()]
        
        if len(clans) < 2:
            conn.close()
            return await ctx.send("❌ You need at least 2 clans to populate league matching boards.")
            
        new_matchups = generate_round_matchups(clans, set())
        for m in new_matchups:
            c.execute("INSERT INTO league_matches (guild_id, round_num, clan_1, clan_2, completed) VALUES (?, 1, ?, ?, 0)", (ctx.guild.id, m[0], m[1]))
        conn.commit()
        max_round = 1
        
    c.execute("SELECT clan_1, clan_2, completed FROM league_matches WHERE guild_id = ? AND round_num = ?", (ctx.guild.id, max_round))
    matches = c.fetchall()
    
    is_completed = all(m[2] for m in matches)
    color = discord.Color.green() if is_completed else discord.Color.red()
    
    desc = "\n".join([f"⚔️ **{m[0]}** vs **{m[1]}** {' (✅ Completed)' if m[2] else ' (⏳ Pending)'}" for m in matches])
    embed = discord.Embed(title=f"Round {max_round} Matchups", description=desc, color=color)
    
    view = RoundsView(ctx, current_round=max_round)
    view.prev_btn.disabled = (max_round <= 1)
    view.complete_btn.disabled = is_completed
    view.complete_btn.label = "Completed" if is_completed else "Complete"
    
    conn.close()
    await ctx.send(embed=embed, view=view)
def generate_round_matchups(clans, past_matches):
    """
    Generates a list of unique pairs where each clan appears exactly once.
    past_matches: set of tuples (clanA, clanB) sorted alphabetically
    """
    if len(clans) % 2 != 0:
        clans = clans + ["BYE"]
    
    def backtrack(remaining_clans, current_pairs):
        if not remaining_clans:
            return current_pairs
        
        c1 = remaining_clans[0]
        for i in range(1, len(remaining_clans)):
            c2 = remaining_clans[i]
            pair = tuple(sorted((c1, c2)))
            
            if pair not in past_matches:
                new_remaining = remaining_clans[1:i] + remaining_clans[i+1:]
                res = backtrack(new_remaining, current_pairs + [pair])
                if res is not None:
                    return res
        return None

    return backtrack(clans, [])

import asyncio
import aiohttp
from PIL import Image, ImageDraw, ImageFont
from io import BytesIO
import discord

# --- OPTIMIZATION STEP 1: Fast Async Concurrent Prefetching ---
async def _fetch_avatar_bytes(session, url):
    """Asynchronously downloads avatar raw bytes with safe fallbacks."""
    if not url or not url.startswith("http"):
        return None
    try:
        async with session.get(url, timeout=3) as response:
            if response.status == 200:
                return await response.read()
    except Exception:
        pass
    return None

def generate_player_stats_image(data, avatar_bytes_list):
    """
    Generates the leaderboard image quickly using pre-fetched raw bytes.
    avatar_bytes_list mirrors data index arrays.
    """
    width = 1100
    header_height = 60
    row_height = 75
    height = header_height + (len(data) * row_height) + 30

    img = Image.new("RGB", (width, height), (15, 17, 22))
    draw = ImageDraw.Draw(img)

    try:
        header_font = _fnt(22, True)
        font = _fnt(21, False)
        bold_font = _fnt(22, True)
    except Exception:
        header_font = font = bold_font = ImageFont.load_default()

    # Calculate max values safely
    max_worth = max([row[5] for row in data], default=1)
    max_wins = max([row[1] for row in data], default=1)
    max_losses = max([row[2] for row in data], default=1)
    max_total = max([row[3] for row in data], default=1)

    # Header Rendering
    y = 10
    draw.rounded_rectangle(
        (20, y, width - 20, y + header_height),
        radius=12,
        fill=(35, 39, 48),
        outline=(212, 175, 55),
        width=2
    )

    headers = ["#", "PLAYER", "WINS", "LOSSES", "TOTAL", "WORTH"]
    x_positions = [45, 140, 550, 670, 790, 930]

    for i, h in enumerate(headers):
        draw.text((x_positions[i], y + 18), h, fill=(230, 230, 230), font=header_font)

    y += header_height

    # Pre-build a reuseable circular mask to avoid recalculating per-avatar
    mask = Image.new("L", (45, 45), 0)
    mask_draw = ImageDraw.Draw(mask)
    mask_draw.ellipse((0, 0, 45, 45), fill=255)

    # Rows Rendering
    for idx, row in enumerate(data):
        player, wins, losses, total, winrate, worth, _ = row

        bg = (65, 55, 20) if idx == 0 else ((25, 29, 36) if idx % 2 else (20, 23, 29))

        draw.rounded_rectangle((20, y + 5, width - 20, y + row_height), radius=12, fill=bg)

        # Rank Ring
        draw.ellipse((35, y + 18, 75, y + 58), fill=(255, 215, 80) if idx == 0 else (150, 150, 150))
        draw.text((55, y + 38), str(idx + 1), anchor="mm", fill=(20, 20, 20), font=bold_font)

        # Fast Avatar Placement from Prefetched Bytes
        raw_bytes = avatar_bytes_list[idx]
        if raw_bytes:
            try:
                pfp = Image.open(BytesIO(raw_bytes)).convert("RGBA").resize((45, 45))
                img.paste(pfp, (105, y + 15), mask)
            except Exception:
                pass

        # Player Label
        draw.text((160, y + 22), player, fill=(255, 255, 255), font=bold_font)

        # Numeric Metric Stats Grid
        stats = [
            (wins, max_wins, (90, 220, 120), 550),
            (losses, max_losses, (240, 90, 90), 670),
            (total, max_total, (100, 190, 255), 790),
        ]

        bar_y = y + 50
        bar_width = 80

        for value, maximum, color, pos in stats:
            draw.text((pos, y + 15), str(value), fill=color, font=bold_font)
            
            # Base Empty Track Bar
            draw.rounded_rectangle((pos, bar_y, pos + bar_width, bar_y + 7), radius=5, fill=(50, 55, 65))
            
            # Active Performance Scaled Filling Track
            fill_pct = (value / maximum) if maximum > 0 else 0
            if fill_pct > 0:
                draw.rounded_rectangle((pos, bar_y, pos + (bar_width * fill_pct), bar_y + 7), radius=5, fill=color)

        # Worth Indicator Column
        draw.text((930, y + 20), f"{int(worth):,}", fill=(255, 215, 80), font=bold_font)

        worth_bar = 140
        draw.rounded_rectangle((900, y + 52, 900 + worth_bar, y + 59), radius=5, fill=(50, 55, 65))
        
        worth_pct = (worth / max_worth) if max_worth > 0 else 0
        if worth_pct > 0:
            draw.rounded_rectangle((900, y + 52, 900 + (worth_bar * worth_pct), y + 59), radius=5, fill=(255, 215, 80))

        y += row_height

    buffer = BytesIO()
    img.save(buffer, "PNG")
    buffer.seek(0)
    return buffer


class LeagueStatsView(discord.ui.View):
    def __init__(self, raw_players_data, guild, bot, current_page=0, current_sort="worth"):
        super().__init__(timeout=180)
        self.raw_players_data = raw_players_data
        self.guild = guild
        self.bot = bot
        self.current_page = current_page
        self.current_sort = current_sort
        self.items_per_page = 10

        sort_idx = {"wins": 1, "losses": 2, "total": 3, "win_rate": 4, "worth": 5}[self.current_sort]
        reverse_sort = (self.current_sort != "losses")
        self.sorted_data = sorted(self.raw_players_data, key=lambda x: x[sort_idx], reverse=reverse_sort)

        self.total_pages = max(1, (len(self.sorted_data) + self.items_per_page - 1) // self.items_per_page)

        options = [
            discord.SelectOption(label="Sort by Worth", value="worth", description="(W*1000 - L*800) * WinRate", default=(self.current_sort == "worth")),
            discord.SelectOption(label="Sort by Wins", value="wins", description="Most individual wins", default=(self.current_sort == "wins")),
            discord.SelectOption(label="Sort by Losses", value="losses", description="Most individual losses", default=(self.current_sort == "losses")),
            discord.SelectOption(label="Sort by Total", value="total", description="Most total games played", default=(self.current_sort == "total")),
            discord.SelectOption(label="Sort by Win Rate", value="win_rate", description="Highest performance ratio", default=(self.current_sort == "win_rate"))
        ]
        self.select = discord.ui.Select(placeholder="Change leaderboard sorting...", options=options, custom_id="stats_sort_dropdown")
        self.select.callback = self.sort_callback
        self.add_item(self.select)

        self.prev_btn = discord.ui.Button(label="◀ Previous", style=discord.ButtonStyle.secondary, disabled=(self.current_page == 0))
        self.prev_btn.callback = self.prev_page_callback
        self.add_item(self.prev_btn)

        self.next_btn = discord.ui.Button(label="Next ▶", style=discord.ButtonStyle.secondary, disabled=(self.current_page >= self.total_pages - 1))
        self.next_btn.callback = self.next_page_callback
        self.add_item(self.next_btn)

    def get_current_page_slice(self):
        start = self.current_page * self.items_per_page
        end = start + self.items_per_page
        return self.sorted_data[start:end]

    async def update_view_message(self, interaction: discord.Interaction):
        # Acknowledge immediately to avoid UI locking up while asset generates
        await interaction.response.defer()
        
        sliced_data = self.get_current_page_slice()
        
        # Async prefetch exactly the 10 avatars on this page slice concurrently
        async with aiohttp.ClientSession() as session:
            tasks = [_fetch_avatar_bytes(session, row[6]) for row in sliced_data]
            avatar_bytes_list = await asyncio.gather(*tasks)

        buffer = generate_player_stats_image(sliced_data, avatar_bytes_list)
        file = discord.File(fp=buffer, filename="league_stats.png")

        new_view = LeagueStatsView(
            raw_players_data=self.raw_players_data,
            guild=self.guild,
            bot=self.bot,
            current_page=self.current_page,
            current_sort=self.current_sort
        )

        content = f"📊 **League Player Performance Statistics** (Page {self.current_page + 1}/{new_view.total_pages})"
        await interaction.edit_original_response(content=content, attachments=[file], view=new_view)

    async def sort_callback(self, interaction: discord.Interaction):
        self.current_sort = self.select.values[0]
        self.current_page = 0
        await self.update_view_message(interaction)

    async def prev_page_callback(self, interaction: discord.Interaction):
        if self.current_page > 0:
            self.current_page -= 1
            await self.update_view_message(interaction)

    async def next_page_callback(self, interaction: discord.Interaction):
        if self.current_page < self.total_pages - 1:
            self.current_page += 1
            await self.update_view_message(interaction)


@clan.command(name="league_stats", aliases=["ls", "league_statistics"])
async def clan_league_stats(ctx):
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()
    
    c.execute("SELECT user_id, wins, losses FROM league_players")
    rows = c.fetchall()
    conn.close()
    
    if not rows:
        return await ctx.send("❌ No player data available in the league database yet.")
        
    raw_players_data = []
    
    # Static Default URL for completely un-resolvable user avatar entities
    DEFAULT_AVATAR_URL = "https://cdn.discordapp.com/embed/avatars/0.png"
    
    for row in rows:
        user_id, wins, losses = row
        total = wins + losses
        win_rate = wins / total if total > 0 else 0.0
        worth = (wins * 1000 - losses * 800) * win_rate
        
        # User Resolution Core Loop
        member = ctx.guild.get_member(user_id)
        if member:
            player_name = member.display_name
            avatar_url = member.display_avatar.with_format("png").url
        else:
            try:
                member = await ctx.guild.fetch_member(user_id)
                player_name = member.display_name
                avatar_url = member.display_avatar.with_format("png").url
            except Exception:
                try:
                    user = await ctx.bot.fetch_user(user_id)
                    player_name = user.name
                    avatar_url = user.display_avatar.with_format("png").url if user.display_avatar else DEFAULT_AVATAR_URL
                except Exception:
                    player_name = f"ID: {user_id}"
                    avatar_url = DEFAULT_AVATAR_URL
                    
        raw_players_data.append([player_name, wins, losses, total, win_rate, worth, avatar_url])
        
    if not raw_players_data:
        return await ctx.send("❌ Error parsing leaderboard statistics information.")

    # Pass ctx.bot down into the pagination views to handle backend state shifts cleanly
    view = LeagueStatsView(raw_players_data, ctx.guild, ctx.bot, current_page=0, current_sort="worth")
    
    initial_slice = view.get_current_page_slice()
    
    # Run the concurrent prefetch loop for the initialization layout build
    async with aiohttp.ClientSession() as session:
        tasks = [_fetch_avatar_bytes(session, row[6]) for row in initial_slice]
        avatar_bytes_list = await asyncio.gather(*tasks)

    buffer = generate_player_stats_image(initial_slice, avatar_bytes_list)
    file = discord.File(fp=buffer, filename="league_stats.png")
    
    await ctx.send(
        content=f"📊 **League Player Performance Statistics** (Page 1/{view.total_pages})", 
        file=file, 
        view=view
    )
"""
Profile Card System — Circular Avatar + Border Cosmetics
─────────────────────────────────────────────────────────
New in this version:
  • Avatar is circular (masked ellipse)
  • Border cosmetics: transparent PNG overlays sized to exactly
    cover the avatar circle. Uploaded once globally, equipped
    per-user per-guild. Stored in a separate `borders` table
    that syncs to all guild DBs on upload/delete.
  • `border upload <name> [--premium]` — attach transparent PNG
  • `border delete <name>`
  • `border list`
  • Border shown in pf edit menu alongside banners
  • Border drawn ON TOP of the circular avatar at exact position

GIF memory: unchanged zero-RAM streaming model.
─────────────────────────────────────────────────────────
"""

  

import asyncio
import gc
import io
import os
import sqlite3
import tempfile
import uuid

import aiohttp
import discord
from discord.ext import commands
from PIL import Image, ImageDraw, ImageFilter, ImageFont

try:
    import imageio
    import numpy as np
    _IMAGEIO_OK = True
except ImportError:
    _IMAGEIO_OK = False

# ══════════════════════════════════════════════════════════════════
#  GLOBALS
# ══════════════════════════════════════════════════════════════════

_RENDER_SEM   = asyncio.Semaphore(2)
_USER_LOCKS:  dict[str, asyncio.Lock] = {}
_http_session: aiohttp.ClientSession | None = None
_font_cache:   dict[int, ImageFont.FreeTypeFont] = {}

PREMIUM_FILE   = "user_premium.txt"
FONT_PATH      = os.path.join("fonts", "Hm.ttf")
MAX_GIF_FRAMES = 15
GIF_W, GIF_H   = 768, 344
GIF_FPS        = 12

FONT_COLORS: dict[str, str] = {
    "white":  "#FFFFFF",
    "yellow": "#FFD700",
    "cyan":   "#00FFFF",
    "pink":   "#FF69B4",
    "red":    "#FF4444",
    "green":  "#00FF88",
    "orange": "#FFA500",
}

# ── Card (PNG full resolution) ────────────────────────────────────
W, H        = 1536, 687
CORNER_R    = 45

# ── Avatar (circular) ─────────────────────────────────────────────
AV_SIZE     = 400          # diameter of the circle
AV_X, AV_Y = 70, 70       # top-left corner of the bounding box

# Border overlay is exactly AV_SIZE × AV_SIZE, placed at AV_X, AV_Y
# (same bounding box as the avatar circle)
BORDER_SIZE = AV_SIZE      # border PNG rendered at this size

# ── Username ──────────────────────────────────────────────────────
NAME_X = AV_X + AV_SIZE + 50
NAME_Y = AV_Y + AV_SIZE // 2 - 45

# ── Stat block ────────────────────────────────────────────────────
STAT_X     = AV_X
STAT_Y     = AV_Y + AV_SIZE + 20
STAT_SEP_X = STAT_X + 160
STAT_ROW_H = 60

# ── Glow ──────────────────────────────────────────────────────────
GLOW_COLOR  = (140, 90, 255, 255)
GLOW_SPREAD = 25
GLOW_BLUR   = 18


# ══════════════════════════════════════════════════════════════════
#  HELPERS
# ══════════════════════════════════════════════════════════════════

def _get_user_lock(uid: str) -> asyncio.Lock:
    if uid not in _USER_LOCKS:
        _USER_LOCKS[uid] = asyncio.Lock()
    return _USER_LOCKS[uid]


async def _get_session() -> aiohttp.ClientSession:
    global _http_session
    if _http_session is None or _http_session.closed:
        _http_session = aiohttp.ClientSession(
            connector=aiohttp.TCPConnector(limit=8, force_close=True),
            timeout=aiohttp.ClientTimeout(total=15),
        )
    return _http_session


async def _fetch_bytes(url: str) -> bytes:
    s = await _get_session()
    async with s.get(url) as r:
        r.raise_for_status()
        return await r.read()


def _font(size: int) -> ImageFont.FreeTypeFont:
    if size not in _font_cache:
        _font_cache[size] = ImageFont.truetype(FONT_PATH, size)
    return _font_cache[size]


# ══════════════════════════════════════════════════════════════════
#  DB SETUP
# ══════════════════════════════════════════════════════════════════

def ensure_profile_tables(guild_id: str) -> None:
    conn = get_db_connection(guild_id)
    c = conn.cursor()

    # ── Banners table ─────────────────────────────────────────────
    c.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='banners'")
    if c.fetchone():
        c.execute("PRAGMA table_info(banners)")
        if not {"filename", "filetype", "data"}.issubset({r[1] for r in c.fetchall()}):
            c.execute("DROP TABLE banners")
    c.execute("""
        CREATE TABLE IF NOT EXISTS banners (
            id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE,
            filename TEXT NOT NULL, filetype TEXT NOT NULL, data BLOB NOT NULL,
            is_premium INTEGER NOT NULL DEFAULT 0, uploaded_by TEXT NOT NULL,
            uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    """)

    # ── Borders table ─────────────────────────────────────────────
    c.execute("""
        CREATE TABLE IF NOT EXISTS borders (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name        TEXT NOT NULL UNIQUE,
            data        BLOB NOT NULL,
            is_premium  INTEGER NOT NULL DEFAULT 0,
            uploaded_by TEXT NOT NULL,
            uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    """)

    # ── profile1 table ────────────────────────────────────────────
    c.execute("""
        CREATE TABLE IF NOT EXISTS profile1 (
            user_id         TEXT PRIMARY KEY,
            wins            INTEGER DEFAULT 0,
            losses          INTEGER DEFAULT 0,
            total           INTEGER DEFAULT 0,
            win_rate        REAL    DEFAULT 0.0,
            equipped_banner TEXT    DEFAULT NULL,
            font_color      TEXT    DEFAULT 'white',
            equipped_border TEXT    DEFAULT NULL
        )
    """)
    c.execute("PRAGMA table_info(profile1)")
    existing = {r[1] for r in c.fetchall()}
    for col, dflt in (
        ("equipped_banner", "NULL"),
        ("font_color",      "'white'"),
        ("equipped_border", "NULL"),
    ):
        if col not in existing:
            try:
                c.execute(f"ALTER TABLE profile1 ADD COLUMN {col} TEXT DEFAULT {dflt}")
            except sqlite3.OperationalError:
                pass

    conn.commit()
    conn.close()


# ══════════════════════════════════════════════════════════════════
#  PREMIUM
# ══════════════════════════════════════════════════════════════════

def _load_premium_ids() -> list[str]:
    if not os.path.exists(PREMIUM_FILE):
        open(PREMIUM_FILE, "w").close()
        return []
    with open(PREMIUM_FILE) as f:
        return [l.strip() for l in f if l.strip()]

def _save_premium_ids(ids: list[str]) -> None:
    with open(PREMIUM_FILE, "w") as f:
        f.write("\n".join(ids) + ("\n" if ids else ""))

def is_premium_user(uid: str) -> bool:
    return uid in _load_premium_ids()


# ══════════════════════════════════════════════════════════════════
#  BANNER DB  (unchanged, syncs to all guilds)
# ══════════════════════════════════════════════════════════════════

def _sync_table_to_all_guilds(bot_ref, table: str, name: str,
                               row_data: dict | None, delete: bool = False) -> None:
    """Generic sync for both banners and borders tables."""
    for guild in bot_ref.guilds:
        try:
            conn = get_db_connection(str(guild.id))
            c = conn.cursor()
            if table == "banners":
                c.execute("""
                    CREATE TABLE IF NOT EXISTS banners (
                        id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE,
                        filename TEXT NOT NULL, filetype TEXT NOT NULL, data BLOB NOT NULL,
                        is_premium INTEGER NOT NULL DEFAULT 0, uploaded_by TEXT NOT NULL,
                        uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                    )
                """)
                if delete:
                    c.execute("DELETE FROM banners WHERE name=?", (name,))
                else:
                    c.execute(
                        "INSERT INTO banners (name,filename,filetype,data,is_premium,uploaded_by) "
                        "VALUES (:name,:filename,:filetype,:data,:is_premium,:uploaded_by) "
                        "ON CONFLICT(name) DO UPDATE SET "
                        "filename=excluded.filename, filetype=excluded.filetype, "
                        "data=excluded.data, is_premium=excluded.is_premium, "
                        "uploaded_by=excluded.uploaded_by",
                        row_data,
                    )
            elif table == "borders":
                c.execute("""
                    CREATE TABLE IF NOT EXISTS borders (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        name TEXT NOT NULL UNIQUE, data BLOB NOT NULL,
                        is_premium INTEGER NOT NULL DEFAULT 0,
                        uploaded_by TEXT NOT NULL,
                        uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                    )
                """)
                if delete:
                    c.execute("DELETE FROM borders WHERE name=?", (name,))
                else:
                    c.execute(
                        "INSERT INTO borders (name,data,is_premium,uploaded_by) "
                        "VALUES (:name,:data,:is_premium,:uploaded_by) "
                        "ON CONFLICT(name) DO UPDATE SET "
                        "data=excluded.data, is_premium=excluded.is_premium, "
                        "uploaded_by=excluded.uploaded_by",
                        row_data,
                    )
            conn.commit()
            conn.close()
        except Exception:
            pass


# ── Banner helpers ────────────────────────────────────────────────

def db_get_banner_data(guild_id, name) -> tuple[bytes | None, str | None]:
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    c.execute("SELECT data,filetype FROM banners WHERE name=?", (name,))
    row = c.fetchone()
    conn.close()
    return (bytes(row[0]), row[1]) if row else (None, None)


def db_list_banners(guild_id, premium_visible) -> list[tuple]:
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    q = ("SELECT name,filetype,is_premium FROM banners ORDER BY name"
         if premium_visible else
         "SELECT name,filetype,is_premium FROM banners WHERE is_premium=0 ORDER BY name")
    c.execute(q)
    rows = c.fetchall()
    conn.close()
    return rows


def db_insert_banner(bot_ref, guild_id, name, filename, filetype,
                     data, is_premium, uploader_id) -> bool:
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    try:
        c.execute(
            "INSERT INTO banners (name,filename,filetype,data,is_premium,uploaded_by) "
            "VALUES (?,?,?,?,?,?)",
            (name, filename, filetype, data, is_premium, uploader_id),
        )
        conn.commit()
        _sync_table_to_all_guilds(bot_ref, "banners", name, {
            "name": name, "filename": filename, "filetype": filetype,
            "data": data, "is_premium": is_premium, "uploaded_by": uploader_id,
        })
        return True
    except sqlite3.IntegrityError:
        return False
    finally:
        conn.close()
        del data


def db_delete_banner(bot_ref, guild_id, name) -> bool:
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    c.execute("SELECT 1 FROM banners WHERE name=?", (name,))
    if not c.fetchone():
        conn.close()
        return False
    c.execute("DELETE FROM banners WHERE name=?", (name,))
    conn.commit()
    conn.close()
    _sync_table_to_all_guilds(bot_ref, "banners", name, None, delete=True)
    return True


# ── Border helpers ────────────────────────────────────────────────

def db_get_border_data(guild_id, name) -> bytes | None:
    """Returns raw PNG bytes of the border, or None."""
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    c.execute("SELECT data FROM borders WHERE name=?", (name,))
    row = c.fetchone()
    conn.close()
    return bytes(row[0]) if row else None


def db_list_borders(guild_id, premium_visible) -> list[tuple]:
    """Returns list of (name, is_premium)."""
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    q = ("SELECT name,is_premium FROM borders ORDER BY name"
         if premium_visible else
         "SELECT name,is_premium FROM borders WHERE is_premium=0 ORDER BY name")
    c.execute(q)
    rows = c.fetchall()
    conn.close()
    return rows


def db_insert_border(bot_ref, guild_id, name, data, is_premium, uploader_id) -> bool:
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    try:
        c.execute(
            "INSERT INTO borders (name,data,is_premium,uploaded_by) VALUES (?,?,?,?)",
            (name, data, is_premium, uploader_id),
        )
        conn.commit()
        _sync_table_to_all_guilds(bot_ref, "borders", name, {
            "name": name, "data": data,
            "is_premium": is_premium, "uploaded_by": uploader_id,
        })
        return True
    except sqlite3.IntegrityError:
        return False
    finally:
        conn.close()
        del data


def db_delete_border(bot_ref, guild_id, name) -> bool:
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    c.execute("SELECT 1 FROM borders WHERE name=?", (name,))
    if not c.fetchone():
        conn.close()
        return False
    c.execute("DELETE FROM borders WHERE name=?", (name,))
    conn.commit()
    conn.close()
    _sync_table_to_all_guilds(bot_ref, "borders", name, None, delete=True)
    return True


# ── Profile helpers ───────────────────────────────────────────────

def db_set_equipped_banner(guild_id, user_id, v) -> None:
    conn = get_db_connection(guild_id)
    conn.execute("UPDATE profile1 SET equipped_banner=? WHERE user_id=?", (v, user_id))
    conn.commit()
    conn.close()


def db_set_equipped_border(guild_id, user_id, v) -> None:
    conn = get_db_connection(guild_id)
    conn.execute("UPDATE profile1 SET equipped_border=? WHERE user_id=?", (v, user_id))
    conn.commit()
    conn.close()


def db_set_font_color(guild_id, user_id, color) -> None:
    conn = get_db_connection(guild_id)
    conn.execute("UPDATE profile1 SET font_color=? WHERE user_id=?", (color, user_id))
    conn.commit()
    conn.close()


def db_fetch_profile(guild_id, user_id) -> tuple | None:
    conn = get_db_connection(guild_id)
    c = conn.cursor()
    c.execute("""
        SELECT p.wins, p.losses, p.total, p.win_rate,
               COALESCE(cm.clan_name,'No Clan') AS clan_name,
               p.equipped_banner, p.font_color, p.equipped_border
        FROM profile1 p
        LEFT JOIN clan_members cm ON p.user_id = cm.user_id
        WHERE p.user_id = ?
    """, (user_id,))
    row = c.fetchone()
    conn.close()
    return row


def db_fetch_achievements(user_id) -> list:
    conn = get_db_connection()
    c = conn.cursor()
    c.execute("CREATE TABLE IF NOT EXISTS certificates "
              "(user_id TEXT NOT NULL, achievement TEXT NOT NULL)")
    conn.commit()
    c.execute("SELECT achievement FROM certificates WHERE user_id=?", (user_id,))
    rows = c.fetchall()
    conn.close()
    return rows


def resolve_equipped_banner(guild_id, banner_name) -> dict | None:
    if not banner_name:
        return None
    try:
        b = gdb_get_banner_by_name(banner_name)
        if b:
            return b
    except Exception:
        pass
    try:
        data, filetype = db_get_banner_data(guild_id, banner_name)
        if data:
            return {"name": banner_name, "type": filetype, "data": data}
    except Exception:
        pass
    return None


# ══════════════════════════════════════════════════════════════════
#  DRAW HELPERS
# ══════════════════════════════════════════════════════════════════

def _draw_shadowed(draw, x, y, text, font, fill, offset=4, shadow_alpha=180):
    draw.text((x + offset, y + offset), text, font=font,
              fill=(0, 0, 0, shadow_alpha))
    draw.text((x, y), text, font=font, fill=fill)


BORDER_BLEED = 80
def _make_circle_avatar(av_bytes: bytes, size: int) -> Image.Image:
    av   = Image.open(io.BytesIO(av_bytes)).convert("RGBA")
    w, h = av.size
    sq   = min(w, h)
    av   = av.crop(((w - sq) // 2, (h - sq) // 2,
                    (w + sq) // 2, (h + sq) // 2))
    av   = av.resize((size, size), Image.BILINEAR)
    mask = Image.new("L", (size, size), 0)
    ImageDraw.Draw(mask).ellipse((0, 0, size - 1, size - 1), fill=255)
    av.putalpha(mask)
    mask.close()
    return av


def _apply_border(card: Image.Image,
                  border_bytes: bytes | None,
                  av_x: int, av_y: int,
                  av_size: int,
                  cw: int, ch: int) -> None:
    if not border_bytes:
        return
    try:
        bleed  = max(4, int(BORDER_BLEED * ch / H))
        border = Image.open(io.BytesIO(border_bytes)).convert("RGBA")

        # Force square from the full original image (no bbox crop)
        # so positioning is always consistent regardless of source size
        bw, bh = border.size
        if bw != bh:
            sq     = max(bw, bh)
            square = Image.new("RGBA", (sq, sq), (0, 0, 0, 0))
            square.alpha_composite(border, ((sq - bw) // 2, (sq - bh) // 2))
            border.close()
            border = square

        # Always render at av_size + bleed*2, centered over avatar
        render_size = av_size + bleed * 2
        border      = border.resize((render_size, render_size), Image.BILINEAR)

        card.alpha_composite(border, (av_x - bleed, av_y - bleed))
        border.close()
    except Exception:
        pass
    
    
    
def _stamp_frame(card, av_circle, border_bytes,
                 av_x, av_y, av_size,
                 display_name, wins, losses, total,
                 clan_name, font_color, cw, ch):
    sx = cw / W
    sy = ch / H
    def ix(v): return int(v * sx)
    def iy(v): return int(v * sy)

    draw = ImageDraw.Draw(card)

    av_w = av_circle.size[0]
    gs   = max(6, iy(GLOW_SPREAD))

    # ── 1. Glow (bottommost layer) ────────────────────────────────
    glow = Image.new("RGBA", (av_w + gs*2, av_w + gs*2), (0, 0, 0, 0))
    ImageDraw.Draw(glow).ellipse(
        (gs, gs, gs + av_w - 1, gs + av_w - 1), fill=GLOW_COLOR
    )
    glow = glow.filter(ImageFilter.GaussianBlur(max(3, iy(GLOW_BLUR))))
    card.alpha_composite(glow, (av_x - gs, av_y - gs))
    glow.close()

    # ── 2. Avatar first ───────────────────────────────────────────
    card.paste(av_circle, (av_x, av_y), av_circle)

    # ── 3. Border on top (overlaps the avatar edges) ──────────────
    _apply_border(card, border_bytes, av_x, av_y, av_w, cw, ch)

    # ── Username ──────────────────────────────────────────────────
    nf = _font(iy(90))
    _draw_shadowed(draw, ix(NAME_X), iy(NAME_Y),
                   display_name, nf, font_color, offset=iy(4))

    # ── Stats ─────────────────────────────────────────────────────
    inf = _font(iy(50))
    lx  = ix(STAT_X)
    sx2 = ix(STAT_SEP_X)
    by  = iy(STAT_Y)
    rh  = iy(STAT_ROW_H)

    for i, (label, value) in enumerate([
        ("CLAN",   clan_name),
        ("WINS",   str(wins)),
        ("LOSSES", str(losses)),
    ]):
        y = by + i * rh
        _draw_shadowed(draw, lx,  y, label,        inf, font_color, offset=iy(3))
        _draw_shadowed(draw, sx2, y, f"| {value}",  inf, font_color, offset=iy(3))

    # ── Rounded card mask ─────────────────────────────────────────
    mask = Image.new("L", (cw, ch), 0)
    ImageDraw.Draw(mask).rounded_rectangle(
        [(0, 0), (cw, ch)], max(8, iy(CORNER_R)), fill=255
    )
    card.putalpha(mask)
    mask.close()

# ══════════════════════════════════════════════════════════════════
#  PNG RENDER
# ══════════════════════════════════════════════════════════════════

def _render_png(banner_data, av_bytes, border_bytes,
                display_name, wins, losses, total,
                clan_name, font_color) -> bytes:
    card = banner_img = av_circle = None
    try:
        if banner_data:
            banner_img  = Image.open(io.BytesIO(banner_data)).convert("RGBA")
            banner_data = None
            card        = banner_img.resize((W, H), Image.BILINEAR)
            banner_img.close(); banner_img = None
        else:
            card = Image.new("RGBA", (W, H), (30, 30, 30, 255))

        av_circle = _make_circle_avatar(av_bytes, AV_SIZE)
        av_bytes  = None

        _stamp_frame(card, av_circle, border_bytes,
                     AV_X, AV_Y, AV_SIZE,
                     display_name, wins, losses, total,
                     clan_name, font_color, W, H)

        av_circle.close(); av_circle = None
        border_bytes = None

        buf = io.BytesIO()
        card.save(buf, "PNG", optimize=False)
        return buf.getvalue()
    finally:
        for o in (card, banner_img, av_circle):
            try:
                if o: o.close()
            except Exception:
                pass
        gc.collect()


# ══════════════════════════════════════════════════════════════════
#  GIF RENDER — ZERO RAM STREAMING
# ══════════════════════════════════════════════════════════════════

def _count_gif_frames(src: Image.Image) -> int:
    n = 0
    try:
        while True:
            n += 1
            src.seek(src.tell() + 1)
    except EOFError:
        pass
    src.seek(0)
    return n


def _pick_frame_indices(total: int, want: int) -> list[int]:
    if total <= want:
        return list(range(total))
    step = (total - 1) / (want - 1)
    return sorted({round(i * step) for i in range(want)})


def _render_gif_zero_ram(banner_data, av_bytes, border_bytes,
                         display_name, wins, losses, total,
                         clan_name, font_color) -> bytes:
    src = av_circle = None
    tmp_path = None
    try:
        src         = Image.open(io.BytesIO(banner_data))
        banner_data = None

        # Pre-build circular avatar once at GIF scale
        av_size   = int(AV_SIZE * GIF_H / H)
        av_circle = _make_circle_avatar(av_bytes, av_size)
        av_bytes  = None
        ax = int(AV_X * GIF_W / W)
        ay = int(AV_Y * GIF_H / H)

        # Scale border bytes reference size (we'll let _apply_border resize)
        scaled_border_size = av_size

        total_frames   = _count_gif_frames(src)
        target_indices = _pick_frame_indices(total_frames, MAX_GIF_FRAMES)

        tmp_fd, tmp_path = tempfile.mkstemp(suffix=".gif")
        os.close(tmp_fd)

        wrote = 0
        with imageio.get_writer(tmp_path, mode="I", fps=GIF_FPS, loop=0) as writer:
            for idx in target_indices:
                src.seek(idx)
                card = src.copy().convert("RGBA").resize((GIF_W, GIF_H), Image.BILINEAR)

                _stamp_frame(card, av_circle, border_bytes,
                             ax, ay, scaled_border_size,
                             display_name, wins, losses, total,
                             clan_name, font_color, GIF_W, GIF_H)

                arr = np.asarray(card.convert("RGB"), dtype=np.uint8)
                card.close(); del card
                writer.append_data(arr)
                del arr
                wrote += 1

        if wrote == 0:
            dark = np.zeros((GIF_H, GIF_W, 3), dtype=np.uint8)
            dark[:] = 30
            with imageio.get_writer(tmp_path, mode="I", fps=GIF_FPS, loop=0) as w:
                w.append_data(dark)
            del dark

        with open(tmp_path, "rb") as f:
            return f.read()

    finally:
        if src:
            try: src.close()
            except Exception: pass
        if av_circle:
            try: av_circle.close()
            except Exception: pass
        if tmp_path:
            try: os.unlink(tmp_path)
            except Exception: pass
        gc.collect()


def _render_gif_fallback(banner_data, av_bytes, border_bytes,
                         display_name, wins, losses, total,
                         clan_name, font_color) -> bytes:
    FW, FH = 480, 215
    src = av_circle = None
    frames: list[Image.Image] = []
    try:
        src         = Image.open(io.BytesIO(banner_data))
        banner_data = None
        av_size     = int(AV_SIZE * FH / H)
        av_circle   = _make_circle_avatar(av_bytes, av_size)
        av_bytes    = None
        ax = int(AV_X * FW / W)
        ay = int(AV_Y * FH / H)

        total_frames   = _count_gif_frames(src)
        target_indices = _pick_frame_indices(total_frames, MAX_GIF_FRAMES)

        for idx in target_indices:
            src.seek(idx)
            card = src.copy().convert("RGBA").resize((FW, FH), Image.BILINEAR)
            _stamp_frame(card, av_circle, border_bytes,
                         ax, ay, av_size,
                         display_name, wins, losses, total,
                         clan_name, font_color, FW, FH)
            p = card.convert("RGB").quantize(
                colors=64, method=Image.Quantize.MEDIANCUT, dither=0)
            card.close(); del card
            frames.append(p)

        buf = io.BytesIO()
        if frames:
            frames[0].save(buf, format="GIF", save_all=True,
                           append_images=frames[1:], loop=0,
                           duration=int(1000 / GIF_FPS),
                           disposal=2, optimize=True)
        return buf.getvalue()
    finally:
        if src:
            try: src.close()
            except Exception: pass
        if av_circle:
            try: av_circle.close()
            except Exception: pass
        for f in frames:
            try: f.close()
            except Exception: pass
        frames.clear()
        gc.collect()


def _render_gif(banner_data, av_bytes, border_bytes,
                display_name, wins, losses, total,
                clan_name, font_color) -> bytes:
    if _IMAGEIO_OK:
        return _render_gif_zero_ram(banner_data, av_bytes, border_bytes,
                                    display_name, wins, losses, total,
                                    clan_name, font_color)
    return _render_gif_fallback(banner_data, av_bytes, border_bytes,
                                display_name, wins, losses, total,
                                clan_name, font_color)


# ══════════════════════════════════════════════════════════════════
#  EDIT EMBED
# ══════════════════════════════════════════════════════════════════

def _build_edit_embed(target, row, achievements, is_prem) -> discord.Embed:
    wins, losses, total, win_rate, clan_name, equipped_banner, font_color, equipped_border = row
    e = discord.Embed(title=f"✏️ Edit Profile — {target.display_name}",
                      color=discord.Color.blurple())
    e.set_thumbnail(url=target.display_avatar.url)
    e.add_field(name="🏆 Wins",   value=str(wins),                inline=True)
    e.add_field(name="💀 Losses", value=str(losses),              inline=True)
    e.add_field(name="🎮 Total",  value=str(total),               inline=True)
    e.add_field(name="⚔️ Clan",   value=clan_name,                inline=True)
    e.add_field(name="🎨 Font",   value=font_color or "white",    inline=True)
    e.add_field(name="🖼️ Banner", value=equipped_banner or "None", inline=True)
    e.add_field(name="🔮 Border", value=equipped_border or "None", inline=True)
    e.add_field(
        name="🏅 Achievements",
        value=", ".join(
            a[0] if isinstance(a, (list, tuple)) else a for a in achievements[:6]
        ) or "None",
        inline=False,
    )
    if is_prem:
        e.add_field(name="👑 Premium", value="Can equip premium items!", inline=False)
    e.set_footer(text="Use the menus below to customise your profile.")
    return e


