class FontColorSelect(discord.ui.Select):
    def __init__(self, guild_id, user_id, uid):
        self._gid = guild_id; self._uid = user_id
        super().__init__(
            placeholder="🎨 Choose font color…",
            custom_id=f"fc:{user_id}:{uid}",
            options=[discord.SelectOption(label=n.capitalize(), value=v)
                     for n, v in FONT_COLORS.items()])

    async def callback(self, interaction: discord.Interaction):
        chosen = self.values[0]
        db_set_font_color(self._gid, self._uid, chosen)
        label = next(k for k, v in FONT_COLORS.items() if v == chosen)
        await interaction.response.send_message(
            f"✅ Font color → **{label}**.", ephemeral=True)


class BannerSelect2(discord.ui.Select):
    def __init__(self, guild_id, user_id, uid):
        self._gid = guild_id; self._uid = user_id
        options = [discord.SelectOption(
            label="❌ None", value="__none__", description="Default dark card")]
        try:
            guild_banners = db_list_banners(guild_id, True)
        except Exception:
            guild_banners = []
        guild_names: set[str] = set()
        for name, ftype, is_prem in guild_banners:
            guild_names.add(name)
            options.append(discord.SelectOption(
                label=(("👑 " if is_prem else "🏠 ") + name)[:100],
                value=name, description=f"Guild · {ftype.upper()}"))
        try:
            for b in gdb_get_user_banners(user_id):
                if b["name"] not in guild_names:
                    options.append(discord.SelectOption(
                        label=("🎰 " + b["name"])[:100],
                        value=b["name"], description=f"Gacha · {b['type'].upper()}"))
        except Exception:
            pass
        if len(options) == 1:
            options.append(discord.SelectOption(
                label="No banners available yet", value="__no_banners__"))
        super().__init__(placeholder="🖼️ Equip a banner…",
                         custom_id=f"bn:{user_id}:{uid}", options=options[:25])

    async def callback(self, interaction: discord.Interaction):
        chosen = self.values[0]
        if chosen == "__none__":
            db_set_equipped_banner(self._gid, self._uid, None)
            return await interaction.response.send_message("✅ Banner removed.", ephemeral=True)
        if chosen == "__no_banners__":
            return await interaction.response.send_message("❌ No banners yet.", ephemeral=True)
        try:
            gacha_owned = {b["name"] for b in gdb_get_user_banners(self._uid)}
        except Exception:
            gacha_owned = set()
        try:
            conn = get_db_connection(self._gid)
            c = conn.cursor()
            c.execute("SELECT name FROM banners WHERE name=?", (chosen,))
            guild_has = c.fetchone() is not None
            conn.close()
        except Exception:
            guild_has = False
        if not guild_has and chosen not in gacha_owned:
            return await interaction.response.send_message(
                "❌ You don't own that banner.", ephemeral=True)
        db_set_equipped_banner(self._gid, self._uid, chosen)
        await interaction.response.send_message(f"✅ Banner **{chosen}** equipped!", ephemeral=True)


class BorderSelect(discord.ui.Select):
    def __init__(self, guild_id, user_id, uid):
        self._gid = guild_id
        self._uid = user_id

        options = [discord.SelectOption(
            label="❌ None — remove border", value="__none__",
            description="No border on avatar")]

        # Guild-uploaded borders
        try:
            guild_borders = db_list_borders(guild_id, True)
        except Exception:
            guild_borders = []

        guild_names: set[str] = set()
        for name, is_prem in guild_borders:
            guild_names.add(name)
            options.append(discord.SelectOption(
                label=(("👑 " if is_prem else "🔮 ") + name)[:100],
                value=name, description="Guild border"))

        # Gacha-won borders — fetched from gacha_banners.db
        try:
            gacha_borders = gdb_get_user_borders(user_id)
        except Exception:
            gacha_borders = []

        for b in gacha_borders:
            if b["name"] not in guild_names:
                options.append(discord.SelectOption(
                    label=("🎰 " + b["name"])[:100],
                    value=b["name"],
                    description="Gacha border"))

        if len(options) == 1:
            options.append(discord.SelectOption(
                label="No borders available yet", value="__no_borders__"))

        super().__init__(
            placeholder="🔮 Equip a border…",
            custom_id=f"brd:{user_id}:{uid}",
            options=options[:25])

    async def callback(self, interaction: discord.Interaction):
        chosen = self.values[0]

        if chosen == "__none__":
            db_set_equipped_border(self._gid, self._uid, None)
            return await interaction.response.send_message(
                "✅ Border removed.", ephemeral=True)

        if chosen == "__no_borders__":
            return await interaction.response.send_message(
                "❌ No borders yet.", ephemeral=True)

        # Check guild borders table
        try:
            conn = get_db_connection(self._gid)
            c = conn.cursor()
            c.execute("SELECT name FROM borders WHERE name=?", (chosen,))
            guild_has = c.fetchone() is not None
            conn.close()
        except Exception:
            guild_has = False

        # Check gacha-won borders
        try:
            gacha_owned = {b["name"] for b in gdb_get_user_borders(self._uid)}
        except Exception:
            gacha_owned = set()

        if not guild_has and chosen not in gacha_owned:
            return await interaction.response.send_message(
                "❌ You don't own that border.", ephemeral=True)

        db_set_equipped_border(self._gid, self._uid, chosen)
        await interaction.response.send_message(
            f"✅ Border **{chosen}** equipped!", ephemeral=True)

class RemoveBannerButton(discord.ui.Button):
    def __init__(self, guild_id, user_id, uid):
        self._gid = guild_id; self._uid = user_id
        super().__init__(label="❌ Remove Banner", style=discord.ButtonStyle.danger,
                         custom_id=f"rb:{user_id}:{uid}")

    async def callback(self, interaction: discord.Interaction):
        db_set_equipped_banner(self._gid, self._uid, None)
        await interaction.response.send_message("✅ Banner removed.", ephemeral=True)


class ProfileEditView(discord.ui.View):
    def __init__(self, guild_id, user_id, _unused=None):
        super().__init__(timeout=120)
        uid = uuid.uuid4().hex[:8]
        self.add_item(FontColorSelect(guild_id, user_id, uid))
        self.add_item(BannerSelect2(guild_id, user_id, uid))
        self.add_item(BorderSelect(guild_id, user_id, uid))
        self.add_item(RemoveBannerButton(guild_id, user_id, uid))


class ProfileButtons(discord.ui.View):
    def __init__(self, ctx):
        super().__init__(timeout=60)
        self._ctx = ctx
        btn = discord.ui.Button(
            label="✏️ Edit Profile", style=discord.ButtonStyle.primary,
            custom_id=f"ep_{uuid.uuid4().hex[:8]}")
        btn.callback = self.open_edit
        self.add_item(btn)

    async def open_edit(self, interaction: discord.Interaction):
        if interaction.user.id != self._ctx.author.id:
            return await interaction.response.send_message(
                "This isn't your profile!", ephemeral=True)
        await interaction.response.defer(ephemeral=True, thinking=True)
        uid  = str(interaction.user.id)
        gid  = str(interaction.guild.id)
        row  = db_fetch_profile(gid, uid)
        if not row:
            return await interaction.followup.send("No profile found.", ephemeral=True)
        ach     = db_fetch_achievements(uid)
        is_prem = is_premium_user(uid)
        embed   = _build_edit_embed(interaction.user, row, ach, is_prem)
        view    = ProfileEditView(gid, uid)
        await interaction.followup.send(embed=embed, view=view, ephemeral=True)


