def setup_profile_system(bot: commands.Bot, clan: commands.Group):

    @bot.event
    async def on_guild_available(guild: discord.Guild):
        ensure_profile_tables(str(guild.id))

    @bot.event
    async def on_guild_join(guild: discord.Guild):
        ensure_profile_tables(str(guild.id))
        source = next((g for g in bot.guilds if g.id != guild.id), None)
        if not source:
            return
        try:
            sc = get_db_connection(str(source.id))
            banner_rows = sc.execute(
                "SELECT name,filename,filetype,data,is_premium,uploaded_by FROM banners"
            ).fetchall()
            border_rows = sc.execute(
                "SELECT name,data,is_premium,uploaded_by FROM borders"
            ).fetchall()
            sc.close()
            dc = get_db_connection(str(guild.id))
            for row in banner_rows:
                dc.execute(
                    "INSERT INTO banners (name,filename,filetype,data,is_premium,uploaded_by) "
                    "VALUES (?,?,?,?,?,?) ON CONFLICT(name) DO NOTHING", row)
            for row in border_rows:
                dc.execute(
                    "INSERT INTO borders (name,data,is_premium,uploaded_by) "
                    "VALUES (?,?,?,?) ON CONFLICT(name) DO NOTHING", row)
            dc.commit(); dc.close()
        except Exception:
            pass

    # ── clan pf ──────────────────────────────────────────────────

    @clan.command(name="pf")
    async def pf(ctx, member: discord.Member = None):
        target = member or ctx.author
        uid    = str(target.id)
        gid    = str(ctx.guild.id)
        ensure_profile_tables(gid)

        user_lock = _get_user_lock(uid)
        if user_lock.locked():
            return await ctx.send("⏳ Already generating your profile…", delete_after=5)

        async with user_lock, _RENDER_SEM:
            av_bytes = banner_data = border_bytes = out_bytes = None
            try:
                row = db_fetch_profile(gid, uid)
                if not row:
                    return await ctx.send(f"No profile for <@{uid}>.")

                wins, losses, total, win_rate, clan_name, \
                    equipped_banner, font_color, equipped_border = row
                font_color = font_color or "white"

                # Fetch all bytes async before entering thread
                av_bytes = await _fetch_bytes(str(target.display_avatar.url))

                banner_dict = resolve_equipped_banner(gid, equipped_banner)
                is_gif      = banner_dict is not None and banner_dict["type"] == "gif"
                banner_data = banner_dict["data"] if banner_dict else None
                del banner_dict

                # Fetch border blob — names only stored in profile1
                # Fetch border blob — check guild DB first, then gacha DB
                if equipped_border:
                    border_bytes = db_get_border_data(gid, equipped_border)
                    if not border_bytes:
                        try:
                            border_bytes = gdb_get_border_data_for_user(uid, equipped_border)
                        except Exception:
                            border_bytes = None

                if is_gif:
                    out_bytes = await asyncio.to_thread(
                        _render_gif,
                        banner_data, av_bytes, border_bytes,
                        target.display_name, wins, losses, total,
                        clan_name, font_color,
                    )
                    filename = "profile.gif"
                else:
                    out_bytes = await asyncio.to_thread(
                        _render_png,
                        banner_data, av_bytes, border_bytes,
                        target.display_name, wins, losses, total,
                        clan_name, font_color,
                    )
                    filename = "profile.png"

                banner_data = av_bytes = border_bytes = None

                await ctx.send(
                    file=discord.File(io.BytesIO(out_bytes), filename=filename),
                    view=ProfileButtons(ctx),
                )

            except Exception as err:
                import traceback; traceback.print_exc()
                try:
                    await ctx.send(f"⚠️ Something went wrong.\n`{err}`",
                                   view=ProfileButtons(ctx))
                except Exception:
                    pass
            finally:
                banner_data = av_bytes = border_bytes = out_bytes = None
                gc.collect()

    # ── banner admin ─────────────────────────────────────────────

    @bot.group(name="banner", invoke_without_command=True)
    @commands.has_permissions(administrator=True)
    async def banner_grp(ctx):
        await ctx.send(
            "**🖼️ Banner Admin**\n"
            "`banner upload <n> [--premium]` — attach JPG/PNG/GIF\n"
            "`banner delete <n>` | `banner list`")

    @banner_grp.command(name="upload")
    @commands.has_permissions(administrator=True)
    async def banner_upload(ctx, name: str, flag: str = ""):
        gid = str(ctx.guild.id)
        ensure_profile_tables(gid)
        if not ctx.message.attachments:
            return await ctx.send("❌ Attach a JPG, PNG, or GIF.")
        att = ctx.message.attachments[0]
        ext = att.filename.rsplit(".", 1)[-1].lower()
        if ext not in ("jpg", "jpeg", "png", "gif"):
            return await ctx.send("❌ Only JPG, PNG, GIF accepted.")
        filetype = "gif" if ext == "gif" else "png" if ext == "png" else "jpg"
        is_prem  = 1 if flag.strip().lower() == "--premium" else 0
        async with ctx.typing():
            data = await att.read()
            ok   = db_insert_banner(bot, gid, name, att.filename,
                                    filetype, data, is_prem, str(ctx.author.id))
        if ok:
            await ctx.send(f"✅ **{name}** uploaded synced to all guilds.")
        else:
            await ctx.send(f"❌ **{name}** already exists.")

    @banner_grp.command(name="delete")
    @commands.has_permissions(administrator=True)
    async def banner_delete(ctx, name: str):
        if db_delete_banner(bot, str(ctx.guild.id), name):
            await ctx.send(f"✅ **{name}** deleted from all guilds.")
        else:
            await ctx.send(f"❌ No banner named **{name}**.")

    @banner_grp.command(name="list")
    @commands.has_permissions(administrator=True)
    async def banner_list(ctx):
        rows = db_list_banners(str(ctx.guild.id), True)
        if not rows:
            return await ctx.send("No banners uploaded yet.")
        embed = discord.Embed(title="🖼️ Banners", color=discord.Color.blurple())
        for name, ft, is_prem in rows:
            embed.add_field(name=("👑 " if is_prem else "🌐 ") + name,
                            value=f"`{ft.upper()}`", inline=True)
        await ctx.send(embed=embed)

    # ── border admin ─────────────────────────────────────────────

    @bot.group(name="border", invoke_without_command=True)
    @commands.has_permissions(administrator=True)
    async def border_grp(ctx):
        await ctx.send(
            "**🔮 Border Admin**\n"
            "`border upload <n> [--premium]` — attach transparent PNG\n"
            "`border delete <n>` | `border list`\n\n"
            "Border PNG must be square with transparent background "
            "outside the ring. It is placed at exactly the avatar size "
            f"({AV_SIZE}×{AV_SIZE}px reference).")

    @border_grp.command(name="upload")
    @commands.has_permissions(administrator=True)
    async def border_upload(ctx, name: str, flag: str = ""):
        gid = str(ctx.guild.id)
        ensure_profile_tables(gid)
        if not ctx.message.attachments:
            return await ctx.send("❌ Attach a transparent PNG.")
        att = ctx.message.attachments[0]
        if not att.filename.lower().endswith(".png"):
            return await ctx.send("❌ Borders must be PNG (transparent background).")
        if att.size > 4 * 1024 * 1024:
            return await ctx.send("❌ Max 4 MB.")
        is_prem = 1 if flag.strip().lower() == "--premium" else 0
        async with ctx.typing():
            data = await att.read()
            ok   = db_insert_border(bot, gid, name, data, is_prem, str(ctx.author.id))
        if ok:
            label = "👑 Premium" if is_prem else "🔮 Free"
            await ctx.send(f"✅ Border **{name}** [{label}] uploaded and synced to all guilds.")
        else:
            await ctx.send(f"❌ Border **{name}** already exists.")

    @border_grp.command(name="delete")
    @commands.has_permissions(administrator=True)
    async def border_delete(ctx, name: str):
        if db_delete_border(bot, str(ctx.guild.id), name):
            await ctx.send(f"✅ Border **{name}** deleted from all guilds.")
        else:
            await ctx.send(f"❌ No border named **{name}**.")

    @border_grp.command(name="list")
    @commands.has_permissions(administrator=True)
    async def border_list(ctx):
        rows = db_list_borders(str(ctx.guild.id), True)
        if not rows:
            return await ctx.send("No borders uploaded yet.")
        embed = discord.Embed(title="🔮 Avatar Borders", color=discord.Color.purple())
        for name, is_prem in rows:
            embed.add_field(name=("👑 " if is_prem else "🔮 ") + name,
                            value="PNG", inline=True)
        await ctx.send(embed=embed)

    # ── premium ───────────────────────────────────────────────────

    @bot.group(name="pfpremium", invoke_without_command=True)
    @commands.has_permissions(administrator=True)
    async def pf_premium(ctx):
        await ctx.send("Use `pfpremium add/remove/list <user_id>`.")

    @pf_premium.command(name="add")
    @commands.has_permissions(administrator=True)
    async def pf_premium_add(ctx, user_id: str):
        ids = _load_premium_ids()
        if user_id in ids:
            return await ctx.send("ℹ️ Already premium.")
        ids.append(user_id); _save_premium_ids(ids)
        await ctx.send(f"✅ `{user_id}` added.")

    @pf_premium.command(name="remove")
    @commands.has_permissions(administrator=True)
    async def pf_premium_remove(ctx, user_id: str):
        ids = _load_premium_ids()
        if user_id not in ids:
            return await ctx.send("ℹ️ Not in list.")
        ids.remove(user_id); _save_premium_ids(ids)
        await ctx.send(f"✅ `{user_id}` removed.")

    @pf_premium.command(name="list")
    @commands.has_permissions(administrator=True)
    async def pf_premium_list(ctx):
        ids = _load_premium_ids()
        if not ids:
            return await ctx.send("No premium users yet.")
        embed = discord.Embed(title="👑 Premium Users", color=discord.Color.gold())
        embed.description = "\n".join(f"• `{i}`" for i in ids)
        await ctx.send(embed=embed)


