@clan.command()
async def equipbanner(ctx, banner_id: int):
    """Equip a global banner by its ID."""
    user_id = str(ctx.author.id)
    guild_id = ctx.guild.id

    conn = get_db_connection(guild_id)
    c = conn.cursor()

    # ✅ Fetch banner globally (no user_id restriction)
    c.execute("SELECT banner_url, name FROM banners WHERE banner_id=?", (banner_id,))
    result = c.fetchone()
    if not result:
        conn.close()
        return await ctx.send("❌ Banner not found!")

    banner_url, banner_name = result

    # ✅ Update user's equipped banner
    c.execute("UPDATE profile1 SET equipped_banner=? WHERE user_id=?", (banner_url, user_id))
    conn.commit()

    # Fetch profile info
    c.execute("""
        SELECT p.wins, p.losses, p.total, p.win_rate,
               COALESCE(cm.clan_name,'No Clan') as clan_name,
               p.font_color
        FROM profile1 p
        LEFT JOIN clan_members cm ON p.user_id = cm.user_id
        WHERE p.user_id=?
    """, (user_id,))
    row = c.fetchone()
    conn.close()

    if not row:
        return await ctx.send("❌ Could not load your profile after updating banner.")

    wins, losses, total, win_rate, clan_name, font_color = row

    # 🔹 Global DB (achievements)
    conn_global = get_db_connection()
    c_global = conn_global.cursor()
    c_global.execute("SELECT achievement FROM certificates WHERE user_id=?", (user_id,))
    achievements = [ach[0] for ach in c_global.fetchall()]
    conn_global.close()

    # Avatar + Banner
    avatar_img = await fetch_image(ctx.author.display_avatar.url)
    banner_img = await fetch_image(banner_url)
    stats = (wins, losses, total, win_rate)

    # Generate card
    card = await create_profile_card(
        ctx.author, stats, clan_name, achievements,
        avatar_img, banner_img, font_color=font_color or "white"
    )

    # Send profile card
    with io.BytesIO() as image_binary:
        card.save(image_binary, "PNG")
        image_binary.seek(0)
        await ctx.send(
            f"✅ Banner '{banner_name}' equipped successfully!",
            file=discord.File(fp=image_binary, filename="profile.png")
        )



