# ---------------- BannerDropdown ----------------
class BannerDropdown(discord.ui.Select):
    def __init__(self, user, banners):
        self.user = user
        self.banner_map = {}
        options = []
        for i, (url, name) in enumerate(banners):
            str_id = str(i)  # must be <= 100 chars
            self.banner_map[str_id] = url
            options.append(discord.SelectOption(label=name, value=str_id))
        super().__init__(placeholder="Select a banner to equip", min_values=1, max_values=1, options=options)

    async def callback(self, interaction: discord.Interaction):
        banner_url = self.banner_map[self.values[0]]
        user_id = str(interaction.user.id)

        # Update DB
        conn = get_db_connection(interaction.guild.id)
        c = conn.cursor()
        c.execute("UPDATE profile1 SET equipped_banner=? WHERE user_id=?", (banner_url, user_id))
        conn.commit()

        # Fetch user data to re-render profile
        c.execute("""
            SELECT p.wins,p.losses,p.total,p.win_rate,
                   COALESCE(cm.clan_name,'No Clan') as clan_name
            FROM profile1 p
            LEFT JOIN clan_members cm ON p.user_id = cm.user_id
            WHERE p.user_id=?
        """, (user_id,))
        row = c.fetchone()
        c.execute("SELECT achievement FROM certificates WHERE user_id=?", (user_id,))
        achievements = [ach[0] for ach in c.fetchall()]
        conn.close()

        wins, losses, total, win_rate, clan_name = row
        avatar_img = await fetch_image(interaction.user.display_avatar.url)
        banner_img = await fetch_image(banner_url)
        stats = (wins, losses, total, win_rate)

        card = await create_profile_card(interaction.user, stats, clan_name, achievements, avatar_img, banner_img)

        with io.BytesIO() as image_binary:
            card.save(image_binary, "PNG")
            image_binary.seek(0)
            await interaction.response.send_message(
                file=discord.File(fp=image_binary, filename="profile.png"),
                ephemeral=True
            )

    
import discord
from discord.ext import commands
import sqlite3
from PIL import Image, ImageDraw, ImageFont, ImageFont
import aiohttp
from io import BytesIO
import math
import os


# Path to your custom font
FONT_PATH = os.path.join("fonts", "Hm.ttf")  # <-- replace with your font file path


async def create_shop_grid(banners):
    """
    Create a 2x2 grid image with banner images + name + ID.
    """
    # Canvas size
    canvas_width = 512
    canvas_height = 256
    canvas = Image.new("RGBA", (canvas_width, canvas_height), (54,57,63,255))
    
    # Load custom font
    try:
        font = ImageFont.truetype(FONT_PATH, 20)
        id_font = ImageFont.truetype(FONT_PATH, 16)
    except:
        font = ImageFont.load_default()
        id_font = ImageFont.load_default()
    
    draw = ImageDraw.Draw(canvas)
    positions = [(0,0), (256,0), (0,128), (256,128)]

    for i, banner in enumerate(banners):
        if i >= 4:
            break
        banner_id, name, url = banner
        # Load banner image
        async with aiohttp.ClientSession() as session:
            async with session.get(url) as resp:
                if resp.status == 200:
                    data = BytesIO(await resp.read())
                    img = Image.open(data).convert("RGBA").resize((256,128))
                    canvas.paste(img, positions[i])

                    # Draw Name text
                    bbox = draw.textbbox((0,0), name, font=font)
                    text_w = bbox[2]-bbox[0]
                    text_h = bbox[3]-bbox[1]
                    text_x = positions[i][0] + (256 - text_w)//2
                    text_y = positions[i][1] + 5
                    draw.text((text_x, text_y), name, font=font, fill=(255,255,255,255))

                    # Draw ID text instead of Tier
                    id_text = f"ID: {banner_id}"
                    bbox2 = draw.textbbox((0,0), id_text, font=id_font)
                    t_w = bbox2[2]-bbox2[0]
                    t_h = bbox2[3]-bbox2[1]
                    draw.text((positions[i][0]+5, positions[i][1]+128-t_h-5), id_text, font=id_font, fill=(255,255,255,255))

    buffer = BytesIO()
    canvas.save(buffer, format="PNG")
    buffer.seek(0)
    return buffer

@clan.command()
async def banners(ctx):
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()
    c.execute("SELECT banner_id, name, banner_url FROM banners")
    all_banners = c.fetchall()
    conn.close()

    if not all_banners:
        await ctx.send("No banners found!")
        return

    per_page = 4
    pages = math.ceil(len(all_banners)/per_page)
    current_page = 0

    async def send_page(page):
        start = page*per_page
        end = start+per_page
        banners_page = all_banners[start:end]
        merged_image = await create_shop_grid(banners_page)
        file = discord.File(fp=merged_image, filename="shop.png")
        embed = discord.Embed(title="Banners", color=discord.Color.purple())
        embed.set_image(url="attachment://shop.png")
        embed.set_footer(text="To equip use !clan equipbanner (id)`")
        return embed, file

    embed, file = await send_page(current_page)
    message = await ctx.send(embed=embed, file=file)

    if pages>1:
        await message.add_reaction("◀️")
        await message.add_reaction("▶️")

        def check(reaction, user):
            return (
                user==ctx.author and
                reaction.message.id==message.id and
                str(reaction.emoji) in ["◀️","▶️"]
            )

        while True:
            try:
                reaction, user = await bot.wait_for("reaction_add", timeout=120.0, check=check)
                if str(reaction.emoji)=="▶️" and current_page<pages-1:
                    current_page+=1
                elif str(reaction.emoji)=="◀️" and current_page>0:
                    current_page-=1
                else:
                    await message.remove_reaction(reaction,user)
                    continue
                embed, file = await send_page(current_page)
                await message.edit(embed=embed, attachments=[file])
                await message.remove_reaction(reaction,user)
            except:
                break

    
    
@clan.command()
@commands.has_permissions(administrator=True)
async def endcc(ctx, war_id: int):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()
    c.execute("DELETE FROM cc WHERE id = ?", (str(war_id),))
    conn.commit()
    damage_log_file = f'cc_damage/{ctx.guild.id}_{war_id}.json'
    os.makedirs('cc_damage', exist_ok=True)
    if os.path.exists(damage_log_file):
        os.remove(damage_log_file)
    await ctx.send(f"cc#{war_id} and related requests have been reset.")
@endcc.error
async def endcc_error(ctx, error):
    if isinstance(error, commands.MissingPermissions):
        await ctx.send("❌ You must have the **Administrator** permission to use this command.")

@clan.command(name = 'resetconquest', aliases = ['rc'])
@commands.has_permissions(administrator=True)
async def resetconquest(ctx, war_id: int):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Check if war exists
    c.execute("SELECT clan_1, clan_2 FROM conquest WHERE id = ?", (war_id,))
    war = c.fetchone()
    if not war:
        return await ctx.send("War not found.")

    clan_1, clan_2 = war

    # Delete member data
    c.execute("DELETE FROM conquest_members WHERE war_id = ?", (war_id,))
    # Delete war record
    c.execute("DELETE FROM conquest WHERE id = ?", (war_id,))
    conn.commit()
    conn.close()
    
    await ctx.send(f"Conquest #{war_id} and related requests have been reset.")
@resetconquest.error
async def resetconquest_error(ctx, error):
    if isinstance(error, commands.MissingPermissions):
        await ctx.send("❌ You must have the **Administrator** permission to use this command.")

@clan.command(name = 'resetwar', aliases = ['rw'])
@commands.has_permissions(administrator=True)
async def resetwar(ctx, war_id: int):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Check if war exists
    c.execute("SELECT clan_1, clan_2 FROM war_duels WHERE id = ?", (war_id,))
    war = c.fetchone()
    if not war:
        return await ctx.send("War not found.")

    clan_1, clan_2 = war

    # Delete member data
    c.execute("DELETE FROM war_members WHERE war_id = ?", (war_id,))
    # Delete war record
    c.execute("DELETE FROM war_duels WHERE id = ?", (war_id,))
    # Delete any pending war requests involving either clan
    c.execute("""
        DELETE FROM war_requests 
        WHERE (clan_1 = ? AND clan_2 = ?) OR (clan_1 = ? AND clan_2 = ?)
    """, (clan_1, clan_2, clan_2, clan_1))
    conn.commit()
    conn.close()
    

    await ctx.send(f"War #{war_id} and related requests have been reset.")
@resetwar.error
async def resetwar_error(ctx, error):
    if isinstance(error, commands.MissingPermissions):
        await ctx.send("❌ You must have the **Administrator** permission to use this command.")
