@clan.command(name="rankings")
async def rankings(ctx):
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()

    c.execute("SELECT clan_name, leader_id, cumulative_wins, war_wins, loss FROM clans ORDER BY cumulative_wins DESC")
    clans = c.fetchall()
    if not clans:
        return await ctx.send("No clans found in this server.")
    clans = sorted(
    clans,
    key=lambda clan: clan[3] * 100 - clan[4] * 50 + clan[2],
    reverse=True)

    class ClansView(discord.ui.View):
        def __init__(self, ctx, clans):
            super().__init__(timeout=60)
            self.ctx = ctx
            self.clans = clans
            self.page = 0
            self.per_page = 5
            self.max_page = (len(clans) - 1) // self.per_page

        def get_embed(self):
            embed = discord.Embed(
                title=f" Current Clans (Page {self.page + 1}/{self.max_page + 1})",
                color=discord.Color.red()
            )

            start = self.page * self.per_page
            end = start + self.per_page
            description = ""

            for idx, (name, leader_id, cumulative_wins, war_wins, loss) in enumerate(self.clans[start:end], start=start + 1):
                description += (
                    f"**{idx} — {name}**{rank_emoji(100*war_wins - 50*loss + cumulative_wins)} (<@{leader_id}>)\n"
                    f"> **Clan Ratings:** `{100*war_wins - 50*loss + cumulative_wins}`\n"
                    f"> **Clan Accumulative Wins:** `{cumulative_wins}`\n"
                    f"> **Clan War Wins:** `{war_wins}`\n\n"
                )

            embed.description = description
            return embed

        async def update(self, interaction):
            await interaction.response.edit_message(embed=self.get_embed(), view=self)

        def authorized(self, user):
            return user == self.ctx.author or user.guild_permissions.administrator

        @discord.ui.button(label="⋘", style=discord.ButtonStyle.secondary)
        async def first(self, interaction: discord.Interaction, button: discord.ui.Button):
            if not self.authorized(interaction.user):
                return await interaction.response.send_message("You're not allowed to interact with this.", ephemeral=True)
            self.page = 0
            await self.update(interaction)

        @discord.ui.button(label="⪻", style=discord.ButtonStyle.primary)
        async def previous(self, interaction: discord.Interaction, button: discord.ui.Button):
            if not self.authorized(interaction.user):
                return await interaction.response.send_message("You're not allowed to interact with this.", ephemeral=True)
            if self.page > 0:
                self.page -= 1
            await self.update(interaction)

        @discord.ui.button(label="⪼", style=discord.ButtonStyle.primary)
        async def next(self, interaction: discord.Interaction, button: discord.ui.Button):
            if not self.authorized(interaction.user):
                return await interaction.response.send_message("You're not allowed to interact with this.", ephemeral=True)
            if self.page < self.max_page:
                self.page += 1
            await self.update(interaction)

        @discord.ui.button(label="⋙", style=discord.ButtonStyle.secondary)
        async def last(self, interaction: discord.Interaction, button: discord.ui.Button):
            if not self.authorized(interaction.user):
                return await interaction.response.send_message("You're not allowed to interact with this.", ephemeral=True)
            self.page = self.max_page
            await self.update(interaction)

    view = ClansView(ctx, clans)
    await ctx.send(embed=view.get_embed(), view=view)

@clan.command()
async def setclanemoji(ctx, clan_name: str, emoji: str):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Check if user is a clan leader or deputy
    c.execute("SELECT clan_name FROM clans WHERE leader_id = ? OR deputy_id = ?", (ctx.author.id, ctx.author.id))
    result = c.fetchone()
    if not result:
        return await ctx.send("You are not authorized to set an emoji.")

    try:
        c.execute("UPDATE clans SET emoji = ? WHERE clan_name = ?", (emoji, clan_name))
        if c .rowcount == 0:
            return await ctx.send("Clan not found.")
        conn.commit()
        await ctx.send(f"Emoji for **{clan_name}** set to {emoji}")
    except Exception as e:
        await ctx.send("Error updating emoji.")
    
        
