class ShopDropdown(discord.ui.Select):

    def __init__(self):

        super().__init__(
            placeholder="Click to buy",
            options=[

                discord.SelectOption(
                    label="Curse Spirit Primal Kyogre",
                    value="curse_kyogre"
                ),

                discord.SelectOption(
                    label="Godzilla Primal Groudon",
                    value="gozilla_groudon"
                ),

                discord.SelectOption(
                    label="Hollow Yveltal",
                    value="hollow_yveltal"
                )

            ]
        )

        self.prices = {
            "curse_kyogre": ("primal kyogre", "curse spirit", 50000),
            "gozilla_groudon": ("primal groudon", "godzilla", 50000),
            "hollow_yveltal": ("yveltal", "hollow", 50000),
        }

    async def callback(self, interaction: discord.Interaction):

        choice = self.values[0]

        if choice not in self.prices:
            return await interaction.response.send_message(
                "❌ Invalid item.",
                ephemeral=True
            )

        poke, cosmetic, cost = self.prices[choice]

        conn = connect_poke_db()
        ensure_player(conn, interaction.user.id)

        c = conn.cursor()

        # ---------- CHECK + DEDUCT ----------
        c.execute(
            "UPDATE poke SET coins = coins - ? WHERE player_id = ? AND coins >= ?",
            (cost, interaction.user.id, cost),
        )

        if c.rowcount == 0:
            conn.close()
            return await interaction.response.send_message(
                f"❌ Not enough ARCs (need {cost:,}).",
                ephemeral=True
            )

        conn.commit()
        conn.close()
        clan_name, _, clan = find_user_global_clan(interaction.user.id)
        # ---------- ADD TO CLAN INVENTORY ----------
        add_global_clan_inventory_item(
            clan["id"],  # or self.parent_view.clan_id if you have it
            "pokemon",
            cosmetic,
            poke
        )

        await interaction.response.send_message(
            f"✅ Purchased **{cosmetic} {poke}** for `{cost:,} ARCs` and added to clan inventory.",
            ephemeral=True
        )


