@bot.command()
async def buy(ctx, *, item_name):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Get item price and image
    c.execute("SELECT price, image_url FROM shop_items WHERE item_name = ?", (item_name,))
    row = c.fetchone()
    if not row:
        return await ctx.send("Item not found in the shop.")
    price, image_url = row

    # Get user balance
    c.execute("SELECT coin FROM shop WHERE user_id = ?", (ctx.author.id,))
    bal = c.fetchone()
    if not bal or bal[0] < price:
        return await ctx.send("You don't have enough coins to buy this item.")

    # Deduct coins
    c.execute("UPDATE shop SET coin = coin - ? WHERE user_id = ?", (price, ctx.author.id))

    # Create profile_urls table if not exists
    c.execute("""
        CREATE TABLE IF NOT EXISTS profile_urls (
            user_id INTEGER,
            item_name TEXT,
            image_url TEXT,
            PRIMARY KEY(user_id, item_name)
        )
    """)

    # Add image to user's profile_urls
    c.execute("""
        INSERT OR REPLACE INTO profile_urls (user_id, item_name, image_url)
        VALUES (?, ?, ?)
    """, (ctx.author.id, item_name, image_url))

    # Check if user is a clan leader
    c.execute("SELECT clan_name FROM clans WHERE leader_id = ?", (ctx.author.id,))
    leader_clan = c.fetchone()
    if leader_clan:
        c.execute("UPDATE clans SET url = ? WHERE clan_name = ?", (image_url, leader_clan[0]))

    conn.commit()
    conn.close()

    # Send confirmation with item image
    embed = discord.Embed(
        title="Purchase Successful!",
        description=f"You bought **{item_name}** for **{price}** coins!",
        color=discord.Color.green()
    )
    embed.set_image(url=image_url)
    await ctx.send(embed=embed)

