@clan.command()
@commands.has_permissions(administrator=True)
async def globaladd(ctx, item_name: str, price: int, description: str, image_url: str):
    added_to = 0
    for file in os.listdir("clan_war_dbs"):
        match = re.match(r'^yes_(\d+)\.db$', file)
        if match:
            guild_id = int(match.group(1))
            conn = get_db_connection(guild_id)
            c = conn.cursor()
            c.execute("""
            CREATE TABLE IF NOT EXISTS shop_items (
                item_name TEXT PRIMARY KEY,
                description TEXT,
                price INTEGER,
                image_url TEXT
            )
            """)
            c.execute("SELECT 1 FROM shop_items WHERE item_name = ?", (item_name,))
            if not c.fetchone():
                c.execute(
                    "INSERT INTO shop_items (item_name, description, price, image_url) VALUES (?, ?, ?, ?)",
                    (item_name, description, price, image_url)
                )
                added_to += 1
            conn.commit()
            conn.close()

    await ctx.send(f"**{item_name}** added to {added_to} guild shop(s).")
