def _quote_sql_ident(name: str) -> str:
    return '"' + str(name).replace('"', '""') + '"'

def _discover_event_point_sources(conn: sqlite3.Connection):
    achilles_aliases = {"achilles_points", "achilles_point", "achilles", "titan_points", "titan_point", "titan"}
    hero_aliases = {"hero_points", "hero_point", "hero"}
    user_aliases = {"user_id", "member_id", "discord_id", "id"}
    generic_points_aliases = {"amount", "points", "point", "score"}
    achilles_table_aliases = {
        "achilles point",
        "achilles points",
        "achilles_point",
        "achilles_points",
        "titan point",
        "titan points",
        "titan_point",
        "titan_points",
    }
    hero_table_aliases = {"hero point", "hero points", "hero_point", "hero_points"}

    c = conn.cursor()
    c.execute("SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'")
    tables = [row[0] for row in c.fetchall()]

    sources = {"achilles": [], "hero": []}
    for table in tables:
        try:
            c.execute(f"PRAGMA table_info({_quote_sql_ident(table)})")
            cols_raw = [row[1] for row in c.fetchall()]
            cols = {col.lower(): col for col in cols_raw}
        except Exception:
            continue

        user_col = next((cols[k] for k in user_aliases if k in cols), None)
        if not user_col:
            continue

        table_l = table.lower().strip()

        # Explicit table-name mapping for cosmetics.db style tables:
        # "titan point" / "hero point" with amount column.
        if table_l in achilles_table_aliases:
            points_col = next((cols[k] for k in generic_points_aliases if k in cols), None)
            if points_col:
                sources["achilles"].append((table, user_col, points_col))
        if table_l in hero_table_aliases:
            points_col = next((cols[k] for k in generic_points_aliases if k in cols), None)
            if points_col:
                sources["hero"].append((table, user_col, points_col))

        # Legacy/alternate schemas where point columns are mode-specific names.
        titan_col = next((cols[k] for k in achilles_aliases if k in cols), None)
        hero_col = next((cols[k] for k in hero_aliases if k in cols), None)

        if titan_col:
            sources["achilles"].append((table, user_col, titan_col))
        if hero_col:
            sources["hero"].append((table, user_col, hero_col))

    return sources
def _event_lb_rows(conn: sqlite3.Connection, mode: str, limit=None):
    mode = mode.lower()
    if mode == "titan":
        mode = "achilles"
    discovered = _discover_event_point_sources(conn)
    candidates = discovered.get(mode, [])
    if not candidates:
        return []

    best_rows = []
    best_count = -1
    c = conn.cursor()

    for table, user_col, points_col in candidates:
        q_table = _quote_sql_ident(table)
        q_user = _quote_sql_ident(user_col)
        q_points = _quote_sql_ident(points_col)
        try:
            query = f"""
                SELECT {q_user}, {q_points}
                FROM {q_table}
                WHERE {q_points} IS NOT NULL AND {q_points} > 0
                ORDER BY {q_points} DESC
            """
            if limit is not None:
                query += " LIMIT ?"
                c.execute(query, (limit,))
            else:
                c.execute(query)
            rows = c.fetchall()
            if len(rows) > best_count:
                best_count = len(rows)
                best_rows = rows
        except Exception:
            continue

    return best_rows

def _build_event_embed(rows, mode: str, guild: discord.Guild, page: int = 0, per_page: int = 10):
    title_mode = ACHILLES_POINT_NAME if mode in {"achilles", "titan"} else HERO_POINT_NAME
    embed = discord.Embed(
        title=f"{title_mode} Leaderboard",
        color=discord.Color.gold()
    )

    if not rows:
        embed.description = f"No {title_mode.lower()} data found."
        embed.set_footer(text="Page 1/1")
        return embed

    start = page * per_page
    end = start + per_page
    page_rows = rows[start:end]
    lines = []
    for i, (user_id, points) in enumerate(page_rows, start=start + 1):
        member = guild.get_member(int(user_id)) if guild else None
        mention = member.mention if member else f"<@{user_id}>"
        lines.append(f"**{i}.** {mention}: `{points}`")

    embed.description = "\n".join(lines)
    total_pages = max(1, (len(rows) - 1) // per_page + 1)
    embed.set_footer(text=f"Page {page + 1}/{total_pages} | Total: {len(rows)}")
    return embed

class EventLeaderboardView(discord.ui.View):
    def __init__(self, guild_id: int, guild: discord.Guild, per_page: int = 10):
        super().__init__(timeout=180)
        self.guild_id = guild_id
        self.guild = guild
        self.per_page = per_page
        self.mode = "achilles"
        self.current_page = 0
        self.rows = self._fetch_rows(self.mode)
        self._sync_buttons()
    def _fetch_rows(self, mode: str):
        # Primary source: cosmetics.db (where titan/hero point rewards are written).
        try:
            with sqlite3.connect("cosmetics.db") as conn:
                rows = _event_lb_rows(conn, mode=mode, limit=None)
                if rows:
                    return rows
        except Exception:
            pass

        # Fallback: guild-scoped DB for legacy schemas.
        conn = get_db_connection(self.guild_id)
        setup_database(conn)
        rows = _event_lb_rows(conn, mode=mode, limit=None)
        conn.close()
        return rows
    def _max_page(self):
        return max(0, (len(self.rows) - 1) // self.per_page)

    def _sync_buttons(self):
        self.titan_button.style = (
            discord.ButtonStyle.primary if self.mode == "achilles" else discord.ButtonStyle.secondary
        )
        self.hero_button.style = (
            discord.ButtonStyle.primary if self.mode == "hero" else discord.ButtonStyle.secondary
        )
        self.previous_button.disabled = self.current_page <= 0
        self.next_button.disabled = self.current_page >= self._max_page()

    def current_embed(self):
        return _build_event_embed(
            self.rows,
            mode=self.mode,
            guild=self.guild,
            page=self.current_page,
            per_page=self.per_page,
        )

    async def _render(self, interaction: discord.Interaction):
        self._sync_buttons()
        await interaction.response.edit_message(embed=self.current_embed(), view=self)

    async def _show_mode(self, interaction: discord.Interaction, mode: str):
        self.mode = mode
        self.current_page = 0
        self.rows = self._fetch_rows(mode)
        await self._render(interaction)

    @discord.ui.button(label="Scarlet Leaderboard", style=discord.ButtonStyle.primary, row=0)
    async def titan_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._show_mode(interaction, "achilles")

    @discord.ui.button(label="King Leaderboard", style=discord.ButtonStyle.secondary, row=0)
    async def hero_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._show_mode(interaction, "hero")

    @discord.ui.button(label="Previous", style=discord.ButtonStyle.secondary, row = 1)
    async def previous_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.current_page > 0:
            self.current_page -= 1
            await self._render(interaction)
        else:
            await interaction.response.defer()

    @discord.ui.button(label="Next", style=discord.ButtonStyle.secondary, row = 1)
    async def next_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.current_page < self._max_page():
            self.current_page += 1
            await self._render(interaction)
        else:
            await interaction.response.defer()

