@clan.command()
async def cprofile(ctx, member: discord.Member = None):
    member = member or ctx.author
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Fetch legendary stats
    c.execute("SELECT points, wins, losses FROM legendary_event WHERE user_id = ?", (member.id,))
    row = c.fetchone()
    if not row:
        return await ctx.send(f"{member.mention} has no Legendary Month data.")
    points, wins, losses = row
    total = wins + losses
    win_rate = (wins / total * 100) if total > 0 else 0

    # Fetch profile banner (main image)
    c.execute("SELECT image_url FROM profile_urls WHERE user_id = ? ORDER BY rowid DESC LIMIT 1", (member.id,))
    profile_row = c.fetchone()
    profile_url = profile_row[0] if profile_row else None

    # Build profile text
    description = (
        f"**Points →** {points}\n"
        f"──────────────\n"
        f"**Wins →** {wins}\n"
        f"**Losses →** {losses}\n"
        f"──────────────\n"
        f"**Total →** {total}\n"
        f"**Win Rate →** {win_rate:.2f}%"
    )

    # Create embed
    embed = discord.Embed(
        title=f"{member.display_name}'s Legendary Profile",
        description=description,
        color=discord.Color.purple()
    )
    embed.set_thumbnail(url=member.display_avatar.url)
    if profile_url:
        embed.set_image(url=profile_url)

    await ctx.send(embed=embed)    


    
@clan.command()
async def cinco(ctx, loser: discord.Member):
    winner = ctx.author

    if loser.id == winner.id:
        return await ctx.send("You can't log a match against yourself.")

    class ConfirmLog(View):
        def __init__(self):
            super().__init__(timeout=30)

        @discord.ui.button(label="Yes", style=discord.ButtonStyle.success)
        async def yes(self, interaction: discord.Interaction, button: Button):
            if interaction.user != loser:
                return await interaction.response.send_message("Only the mentioned loser can confirm this log.", ephemeral=True)

            conn = get_db_connection(ctx.guild.id)
            c = conn.cursor()
            now = discord.utils.utcnow().isoformat()

            # Ensure tables exist
            c.execute("""
                CREATE TABLE IF NOT EXISTS legendary_event (
                    user_id INTEGER PRIMARY KEY,
                    points INTEGER DEFAULT 0,
                    wins INTEGER DEFAULT 0,
                    losses INTEGER DEFAULT 0,
                    last_participation TEXT
                )
            """)
            c.execute("""
                CREATE TABLE IF NOT EXISTS shop (
                    user_id INTEGER PRIMARY KEY,
                    coin INTEGER DEFAULT 0
                )
            """)

            # Update winner stats
            c.execute("INSERT INTO legendary_event (user_id, points, wins, losses, last_participation) VALUES (?, 1, 1, 0, ?) "
                      "ON CONFLICT(user_id) DO UPDATE SET points = points + 1, wins = wins + 1, last_participation = ?",
                      (winner.id, now, now))

            # Update loser stats
            c.execute("INSERT INTO legendary_event (user_id, points, wins, losses, last_participation) VALUES (?, 0, 0, 1, ?) "
                      "ON CONFLICT(user_id) DO UPDATE SET losses = losses + 1, last_participation = ?",
                      (loser.id, now, now))

            # Award coins
            c.execute("INSERT INTO shop (user_id, coin) VALUES (?, 2) "
                      "ON CONFLICT(user_id) DO UPDATE SET coin = coin + 2", (winner.id,))

            conn.commit()
            await interaction.response.edit_message(
                content=f"{winner.mention} defeated {loser.mention} in a legendary match!\n+1 Legendary Point & +2 Coins awarded to {winner.mention}.",
                view=None
            )

        @discord.ui.button(label="No", style=discord.ButtonStyle.danger)
        async def no(self, interaction: discord.Interaction, button: Button):
            if interaction.user != loser:
                return await interaction.response.send_message("Only the mentioned loser can cancel this.", ephemeral=True)
            await interaction.response.edit_message(content="Legendary log canceled.", view=None)

    await ctx.send(
        f"{loser.mention}, did you lose a legendary match to {winner.mention}?",
        view=ConfirmLog()
    )
    
