@clan.command()
async def removemember(ctx, member: discord.Member):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    c = conn.cursor()

    # Check if author is leader or deputy
    c.execute("SELECT clan_name, leader_id, deputy_id FROM clans WHERE leader_id = ? OR deputy_id = ?", (ctx.author.id, ctx.author.id))
    result = c.fetchone()

    if not result and ctx.author.id != OWNER_ID:
        return await ctx.send("You are not authorized to remove members from war.")

    clan_name = result[0] if result else None

    # Check ongoing war
    c.execute("SELECT id FROM war_duels WHERE status = 'ongoing' AND (clan_1 = ? OR clan_2 = ?)", (clan_name, clan_name))
    war = c.fetchone()
    if not war:
        return await ctx.send("No ongoing war found for your clan.")

    war_id = war[0]

    # Check if member is in the war
    c.execute("SELECT * FROM war_members WHERE war_id = ? AND user_id = ?", (war_id, member.id))
    if not c.fetchone():
        return await ctx.send("This member is not part of the current war.")

    # Remove member
    c.execute("DELETE FROM war_members WHERE war_id = ? AND user_id = ?", (war_id, member.id))
    conn.commit()
    conn.close()

    await ctx.send(f"{member.mention} has been removed from the war for **{clan_name}**.") 


@clan.command(name='conquestremove', aliases=['cr', 'conquest_removemember'])
async def conquestremove(ctx, member: discord.Member):
    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    add_conquest_tables(conn)
    conn = get_db_connection(ctx.guild.id)
    c = conn.cursor()

    # Check if author is leader or deputy
    c.execute("SELECT clan_name, leader_id, deputy_id FROM clans WHERE leader_id = ? OR deputy_id = ?", (ctx.author.id, ctx.author.id))
    result = c.fetchone()

    if not result and ctx.author.id != OWNER_ID:
        return await ctx.send("You are not authorized to remove members from war.")

    clan_name = result[0] if result else None

    # Check ongoing war
    c.execute("SELECT id FROM conquest WHERE (clan_1 = ? OR clan_2 = ?)", (clan_name, clan_name))
    war = c.fetchone()
    if not war:
        return await ctx.send("No ongoing war found for your clan.")

    war_id = war[0]

    # Check if member is in the war
    c.execute("SELECT * FROM conquest_members WHERE war_id = ? AND user_id = ?", (war_id, member.id))
    if not c.fetchone():
        return await ctx.send("This member is not part of the current war.")

    # Remove member
    c.execute("DELETE FROM conquest_members WHERE war_id = ? AND user_id = ?", (war_id, member.id))
    conn.commit()
    conn.close()

    await ctx.send(f"{member.mention} has been removed from the war for **{clan_name}**.") 

from deep_translator import GoogleTranslator

@commands.cooldown(rate=5, per=60, type=commands.BucketType.user)
@bot.command(name="translate", aliases=["ts"])
async def translate(ctx, lang_to: str = None):
    if lang_to:
        lang_to = lang_to
    else:
        lang_to = 'en'
    if ctx.message.reference:
        try:
            # Get the message being replied to
            referenced_message = await ctx.channel.fetch_message(ctx.message.reference.message_id)
            text_to_translate = referenced_message.content

            # Translate with deep-translator (auto-detect source language)
            translated = GoogleTranslator(source='auto', target=lang_to).translate(text_to_translate)
            embed = discord.Embed(title = f"Translated to {lang_to}:", description = f"{translated}", color = discord.Color.random())

            await ctx.reply(embed=embed)
        except Exception as e:
            await ctx.send(f"❌ Error: {e}\nYou can google the 2 letter language code you wish to translate message to")
    else:
        await ctx.send("❗ Please reply to the message you want to translate.")

