from datetime import timezone
from datetime import timedelta

# Async reminder function
async def send_reminder(channel_id, user_id, message, is_dm):
        user = bot.get_user(user_id) or await bot.fetch_user(user_id)

        if is_dm:
            embed = discord.Embed(title = '⏰Reminder', description = f'{message}', color = discord.Color(int("ff4200", 16)))
            embed.add_field(name = 'Channel', value = f'<#{channel_id}>' )
            embed.set_footer(text = 'You can clear all reminders using /clear_reminder')

            with open("reminders.json", "r") as f:
                reminders = json.load(f)

            # Remove the matching one-time reminder (non-recursive)
            reminders = [r for r in reminders if not (
                r["channel_id"] == channel_id and
                r["user_id"] == user_id and
                r["message"] == message and
                r["is_dm"] == is_dm and
                not r.get("recursive", False))]

            with open("reminders.json", "w") as f:
                json.dump(reminders, f, indent=4)

            await user.send(f"⏰ Reminder for {user.mention}", embed=embed)
        else:
            channel = bot.get_channel(channel_id)
            if channel:
                embed = discord.Embed(title = '⏰Reminder', description = f'{message}', color = discord.Color(int("ff4200", 16)))
                embed.set_footer(text = 'You can clear all reminders using /clear_reminder')
                await channel.send(f"⏰ Reminder for {user.mention}:", embed = embed)


# Sync wrapper for scheduler
def run_async_reminder(channel_id, user_id, message, is_dm):
    asyncio.run_coroutine_threadsafe(
        send_reminder(channel_id, user_id, message, is_dm),
        bot.loop)

REMINDERS_FILE = "reminders.json"

def save_reminder(channel_id, user_id, message, is_dm, run_time, recursive, interval=None):
    data = load_reminders()
    data.append({
        "channel_id": channel_id,
        "user_id": user_id,
        "message": message,
        "is_dm": is_dm,
        "run_time": run_time.isoformat(),
        "recursive": recursive,
        "interval": interval
    })
    with open(REMINDERS_FILE, "w") as f:
        json.dump(data, f, indent=4)

def load_reminders():
    try:
        with open(REMINDERS_FILE, "r") as f:
            return json.load(f)
    except FileNotFoundError:
        return []

@bot.tree.command(name="remind", description="Set a reminder")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def remind(interaction: discord.Interaction, time: str, content: str = None, recursive: bool = False):
    seconds = parse_time_string(time)

    if seconds <= 0:
        await interaction.response.send_message("⛔ Invalid time.", ephemeral=True)
        return

    run_time = datetime.now(timezone.utc) + timedelta(seconds=seconds)
    await interaction.response.send_message(f"⏰ Reminder set for {seconds} from now.\nRecursive: {recursive}")
    channel = bot.get_channel(interaction.channel.id)
    if channel is None:
        channel_id = interaction.channel.id
        is_dm = True
    else:
        channel_id = interaction.channel.id
        is_dm = False
    
    if recursive:
        time = seconds
        scheduler.add_job(
        run_async_reminder,
            trigger='interval',
            seconds=time,
            start_date=datetime.now(timezone.utc) + timedelta(seconds=time),
            args=[channel_id, interaction.user.id, content, is_dm],
            replace_existing=True)
        save_reminder(channel_id, interaction.user.id, content, is_dm, datetime.now(timezone.utc) + timedelta(seconds=time), recursive=True, interval=time)
    else:
        scheduler.add_job(
            run_async_reminder,
            trigger='date',
            run_date=run_time,
            args=[channel_id, interaction.user.id, content, is_dm])
        save_reminder(channel_id, interaction.user.id, content, is_dm, run_time, recursive=False)

@bot.tree.command(name="reminders", description="List your scheduled reminders")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def reminders(interaction: discord.Interaction):
    user_id = interaction.user.id
    jobs = scheduler.get_jobs()

    user_jobs = [
        job for job in jobs
        if job.args and len(job.args) >= 2 and job.args[1] == user_id
    ]

    if not user_jobs:
        await interaction.response.send_message("📭 You have no scheduled reminders.", ephemeral=True)
        return

    embed = discord.Embed(
        title="⏰ Your Scheduled Reminders",
        color=discord.Color.green()
    )

    for i, job in enumerate(user_jobs, start=1):
        reminder_time = job.next_run_time.strftime("%Y-%m-%d %H:%M:%S UTC")
        message = job.args[2] if len(job.args) > 2 else "No message"
        embed.add_field(
            name=f"Reminder #{i}",
            value=f"🕒 At: `{reminder_time}`\n📋 Message: {message}",
            inline=False
        )

    await interaction.response.send_message(embed=embed, ephemeral=True)

from apscheduler.jobstores.base import JobLookupError
def delete_reminders_for_user(user_id: int) -> int:
    to_remove = []

    for job in scheduler.get_jobs():
        if len(job.args) >= 2 and job.args[1] == user_id:
            to_remove.append(job)

    for job in to_remove:
        scheduler.remove_job(job.id)

    return len(to_remove)
@bot.tree.command(name="clear_reminders", description="Delete all your reminders")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
async def clear_reminders(interaction: discord.Interaction):
    count = delete_reminders_for_user(interaction.user.id)
    if count:
        await interaction.response.send_message(f"🗑️ Deleted {count} reminder(s).")
    else:
        await interaction.response.send_message("❌ You have no reminders to delete.")

def get_move_priority(move_name: str):
    filepath = _resolve_move_data_filepath(move_name)
    if not filepath:
        print(f"No data found for move: {move_name}")
        return None

    with open(filepath, "r") as f:
        move_data = json.load(f)

    return move_data.get("priority")
def get_move_pec(move_name: str):
    filepath = _resolve_move_data_filepath(move_name)
    if not filepath:
        print(f"No data found for move: {move_name}")
        return None

    with open(filepath, "r") as f:
        move_data = json.load(f)
    effect_description = " ".join(move_data.get("effect_entries", []))
    return move_data.get("priority"), effect_description, move_data.get("category", "unknown")
def get_move_effect(move_name: str):
    filepath = _resolve_move_data_filepath(move_name)
    if not filepath:
        print(f"No data found for move: {move_name}")
        return None, None, None

    with open(filepath, "r") as f:
        move_data = json.load(f)

    # Get effect description
    effect_description = " ".join(move_data.get("effect_entries", []))

    # Extract debuffed stats and amounts
    debuffed_stats = []
    debuff_amounts = []

    # stat_changes is a list of dicts with 'stat' and 'amount' keys; 'stat' and 'amount' can be lists
    for change in move_data.get("stat_changes", []):
        stats = change.get("stat")
        amounts = change.get("amount")

        # Normalize to lists for easy iteration
        if not isinstance(stats, list):
            stats = [stats]
        if not isinstance(amounts, list):
            amounts = [amounts]

        for stat, amount in zip(stats, amounts):
            if amount < 0:
                debuffed_stats.append(stat)
                debuff_amounts.append(amount)

    return effect_description, debuffed_stats, debuff_amounts
def get_ability_effect(ability_name, directory="ability_data"):
    filename = os.path.join(directory, f"{ability_name.lower()}.json")
    
    if not os.path.exists(filename):
        return 'Ability not found or does not exist.'

    with open(filename, "r", encoding="utf-8") as file:
        data = json.load(file)
    
    return data.get("description")

def check_ready(file_path: str) -> bool:
    # load battle data either from file or sqlite
    data = _load_battle(file_path)
    number = data['number']
    p1_ready = all(data.get(f"p1_p{i}") for i in range(1, number + 1))
    p2_ready = all(data.get(f"p2_p{i}") for i in range(1, number + 1))
    return p1_ready and p2_ready

def check_ready_pve(file_path: str) -> bool:
    """Check if the player has selected enough Pokémon and moves for a PvE battle."""
    data = _load_battle(file_path)

    number = data.get("number", 3)  # number of Pokémon required (3v3, 6v6, etc.)

    # Player 1 must have filled Pokémon, moves, stats, and nature for each slot
    for i in range(1, number + 1):
        if not all([
            data.get(f"p1_p{i}"),
            data.get(f"p1_moves{i}"),
            data.get(f"p1_stats{i}"),
            data.get(f"p1_nature{i}")
        ]):
            return False

    return True

# --- battle sqlite helper functions ------------------------------------------------
BATTLE_DB = "battles.db"

# use a factory so we can apply common pragmas and a timeout to each connection

def _get_battle_conn():
    # timeout prevents "database is locked" errors when multiple writers
    conn = sqlite3.connect(BATTLE_DB, timeout=10, isolation_level=None)
    # enable WAL for better concurrency
    conn.execute("PRAGMA journal_mode=WAL;")
    conn.execute("PRAGMA synchronous=NORMAL;")
    return conn


def _init_battle_db():
    conn = _get_battle_conn()
    c = conn.cursor()
    c.execute("""
        CREATE TABLE IF NOT EXISTS battles (
            id INTEGER PRIMARY KEY,
            p1_id INTEGER,
            p2_id INTEGER,
            data TEXT
        )
    """)
    conn.commit()
    conn.close()

# initialize when module loads
_init_battle_db()

def _create_battle(data: dict) -> str:
    conn = _get_battle_conn()
    c = conn.cursor()
    p1 = data.get("p1_id")
    p2 = data.get("p2_id")
    c.execute(
        "INSERT INTO battles (p1_id, p2_id, data) VALUES (?, ?, ?)",
        (p1, p2, json.dumps(data))
    )
    battle_id = c.lastrowid
    conn.commit()
    conn.close()
    return f"db:{battle_id}"

def _load_battle(file_path: str) -> dict:
    if isinstance(file_path, str) and file_path.startswith("db:"):
        battle_id = int(file_path.split(":", 1)[1])
        conn = _get_battle_conn()
        c = conn.cursor()
        c.execute("SELECT data FROM battles WHERE id=?", (battle_id,))
        row = c.fetchone()
        conn.close()
        if not row:
            raise FileNotFoundError(f"Battle record {battle_id} not found")
        return json.loads(row[0])
    else:
        with open(file_path, "r") as f:
            return json.load(f)

def _save_battle(file_path: str, data: dict):
    if isinstance(file_path, str) and file_path.startswith("db:"):
        battle_id = int(file_path.split(":", 1)[1])
        conn = _get_battle_conn()
        c = conn.cursor()
        c.execute("UPDATE battles SET data=? WHERE id=?", (json.dumps(data), battle_id))
        conn.commit()
        conn.close()
    else:
        with open(file_path, "w") as f:
            json.dump(data, f, indent=4)


def _get_round_id(file_path: str) -> int:
    data = _load_battle(file_path)
    try:
        return int(data.get("round_id", 0) or 0)
    except Exception:
        return 0


def _bump_round_id(file_path: str) -> int:
    data = _load_battle(file_path)
    try:
        next_round = int(data.get("round_id", 0) or 0) + 1
    except Exception:
        next_round = 1
    data["round_id"] = next_round
    _save_battle(file_path, data)
    try:
        _clear_selection_alive_for_battle(file_path)
    except Exception:
        pass
    return next_round

# override built-in open to transparently handle battles stored in SQLite
import builtins
import io as _io

_original_open = builtins.open

class _BattleDBFile(_io.StringIO):
    def __init__(self, battle_ref, mode='r', *args, **kwargs):
        self._battle_ref = battle_ref
        self._mode = mode
        # prepare buffer depending on mode
        if 'r' in mode or '+' in mode:
            try:
                data = _load_battle(battle_ref)
            except FileNotFoundError:
                # behave like normal open when file not found
                raise
            except Exception:
                # other errors, fall back to empty dict
                data = {}
            initial = json.dumps(data, indent=4)
            super().__init__(initial)
            if 'a' in mode:
                self.seek(0, _io.SEEK_END)
        else:
            # write-only or other modes start with empty buffer
            super().__init__()

    def close(self):
        # commit buffer back to database when writing
        if any(m in self._mode for m in ['w', 'a', '+']):
            try:
                self.seek(0)
                content = self.read()
                if content.strip():
                    data = json.loads(content)
                else:
                    data = {}
                _save_battle(self._battle_ref, data)
            except Exception:
                pass
        super().close()


def _open_override(file, mode='r', *args, **kwargs):
    if isinstance(file, str) and file.startswith("db:"):
        return _BattleDBFile(file, mode, *args, **kwargs)
    return _original_open(file, mode, *args, **kwargs)

# replace built-in open at runtime
builtins.open = _open_override

def _delete_battle(file_path: str):
    if isinstance(file_path, str) and file_path.startswith("db:"):
        battle_id = int(file_path.split(":", 1)[1])
        conn = _get_battle_conn()
        c = conn.cursor()
        c.execute("DELETE FROM battles WHERE id=?", (battle_id,))
        conn.commit()
        conn.close()
    else:
        try:
            os.remove(file_path)
        except Exception:
            pass

def _cleanup_battle_file(file_path: str):
    # wrapper used when battle might be stored in sqlite or filesystem
    _delete_battle(file_path)


PVE_MODE_CLASSIC = "p2 pve"
