class RaidChallengeButton(discord.ui.Button):
    def __init__(self, user_id: int):
        super().__init__(label="Challenge", style=discord.ButtonStyle.danger)
        self.user_id = int(user_id)

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            return await interaction.response.send_message("This raid panel is not yours.", ephemeral=True)
        try:
            data = _raid_start_battle_data(interaction.user, interaction.channel.id)
            #print(data["p2_order"])
        except ValueError as e:
            return await interaction.response.send_message(str(e), ephemeral=True)
        except Exception:
            traceback.print_exc()
            return await interaction.response.send_message("Failed to start raid battle.", ephemeral=True)
        filepath = _create_battle(data)
        try:
            await _send_team_selection_panel(interaction.user, interaction.user.id, filepath, "p1", "Please select 3 Pokemon for the Global Raid.")
        except Exception:
            traceback.print_exc()
            return await interaction.response.send_message("Could not DM your raid setup panel. Please open your DMs and try again.", ephemeral=True)
        await interaction.response.send_message("Raid challenge started. Please check your DMs to pick 3 Pokemon.", ephemeral=True)


