class RaidExchangeSelect(discord.ui.Select):
    OPTIONS = {
        "arc": (20, "30 ARCs"),
        "coupon": (80, "1 Exchange Coupon"),
        "shiny_coupon": (200, "1 Shiny Exchange Coupon"),
        "cosmetic": (1000, "Storm God Complete Zygarde cosmetics"),
        "trial": (30, "7 day trial Storm God Complete Zygarde"),
    }

    def __init__(self, user_id: int):
        self.user_id = int(user_id)
        super().__init__(
            placeholder="Exchange Storm Tokens",
            min_values=1,
            max_values=1,
            options=[
                discord.SelectOption(label="30 ARCs", value="arc", description="Cost: 20 Storm Tokens"),
                discord.SelectOption(label="1 Exchange Coupon", value="coupon", description="Cost: 80 Storm Tokens"),
                discord.SelectOption(label="1 Shiny Exchange Coupon", value="shiny_coupon", description="Cost: 200 Storm Tokens"),
                discord.SelectOption(label="Storm God Complete Zygarde cosmetics", value="cosmetic", description="Cost: 1000 Storm Tokens"),
                discord.SelectOption(label="7 day trial Storm God Complete Zygarde", value="trial", description="Cost: 30 Storm Tokens"),
            ],
        )

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            return await interaction.response.send_message("This exchange menu is not yours.", ephemeral=True)
        choice = self.values[0]
        cost, label = self.OPTIONS[choice]
        if not _raid_spend_tokens(self.user_id, cost):
            return await interaction.response.send_message(f"Not enough Storm Tokens for **{label}**.", ephemeral=True)
        try:
            if choice == "arc":
                modify_coins(self.user_id, 30)
            elif choice == "coupon":
                with sqlite3.connect("cosmetics.db") as conn:
                    c = conn.cursor()
                    _increment_coupon(c, self.user_id, shiny=False, amount=1)
                    conn.commit()
            elif choice == "shiny_coupon":
                with sqlite3.connect("cosmetics.db") as conn:
                    c = conn.cursor()
                    _increment_coupon(c, self.user_id, shiny=True, amount=1)
                    conn.commit()
            elif choice == "cosmetic":
                with _connect_cosmetics_db() as conn:
                    _grant_cosmetic(conn, self.user_id, "pokemon", RAID_BOSS_COSMETIC, RAID_BOSS_POKEMON)
                    conn.commit()
            elif choice == "trial":
                _grant_trial_skin(self.user_id, RAID_BOSS_POKEMON, RAID_BOSS_COSMETIC, int(time.time()) + 7 * 24 * 60 * 60)
        except Exception:
            with _raid_connect() as conn:
                _raid_add_tokens(conn, self.user_id, cost)
                conn.commit()
            traceback.print_exc()
            return await interaction.response.send_message("Exchange failed, so your Storm Tokens were refunded.", ephemeral=True)
        await interaction.response.send_message(f"Exchanged **{cost} Storm Tokens** for **{label}**.", ephemeral=True)


