def _normalize_stage_list(value):
    if not isinstance(value, list):
        return [0] * 6
    if len(value) < 6:
        return (value + [0] * 6)[:6]
    return value[:6]


def _raid_enraged_atk_boost(current_round: int) -> int:
    try:
        current_round = int(current_round or 0)
    except Exception:
        return 0
    if current_round <= 0:
        return 0
    if current_round == 6:
        return 1
    if current_round == 12:
        return 2
    if current_round in {18, 23, 27, 30}:
        return 3
    if current_round > 30 and ((current_round - 30) % 3 == 0):
        return 3
    return 0


def _is_simplified_banned_pokemon(pokemon_name: str) -> bool:
    name = str(pokemon_name or "").strip().lower()
    if name.startswith("mega ") or name.startswith("primal "):
        return True
    return False


def _is_ranked_common_banned_pokemon(pokemon_name: str) -> bool:
    """Check if pokemon is restricted for ranked common battles (megas and rares)."""
    name = str(pokemon_name or "").strip().lower()
    # Check if it's a mega or has mega in the name
    if "mega" in name:
        return True
    # Check if it's in the rares list
    if any(name == r.lower() for r in rares):
        return True
    # Check if it's in the mega list
    if any(name == m.lower() for m in mega):
        return True
    return False


def _is_crowned_no_item_pokemon(pokemon_name: str) -> bool:
    name = str(pokemon_name or "").strip().lower()
    return name in {"crowned zacian", "crowned zamazenta"}


