def _available_battle_items():
    # Whitelist based on items explicitly handled in battle_round_st/apply_damage_pi/extra_dmg_st.
    base = [
        "none",
        "leftovers", "big root", "muscle band", "wise glasses", "life orb", "expert belt",
        "black belt", "fist plate", "black glasses", "dread plate",
        "charcoal", "flame plate", "dragon fang", "draco plate", "hard stone", "stone plate",
        "magnet", "zap plate", "metal coat", "iron plate", "miracle seed", "meadow plate",
        "mystic water", "splash plate", "never-melt ice", "icicle plate", "poison barb", "toxic plate",
        "sharp beak", "sky plate", "silk scarf", "blank plate", "silver power", "insect plate",
        "soft sand", "earth plate", "spell tag", "spooky plate", "twisted spoon", "mind plate",
        "pixie plate", "assault vest", "focus sash", "air balloon",
        "choice scarf", "choice band", "choice specs", "weakness policy",
        # Needed for primal evolution flow in simplified mode.
        "red orb", "blue orb", "mega stone", "z crystal"
    ]
    tera_orbs = [f"tera orb {t}" for t in POKEMON_TYPES]
    return base + tera_orbs


def _battle_item_effect_text(item_name: str) -> str:
    item = str(item_name or "").strip().lower()
    if not item:
        return "No effect data"
    if item == "none":
        return "No held item."
    if item.startswith("tera orb "):
        tera_type = item.replace("tera orb ", "", 1).strip()
        return f"Allows the holder to terastallize into {tera_type} type."
    if item == "mega stone":
        return "Allows the holder to mega evolve."
    if item == "choice scarf":
        return "Raises Speed by 50%, locks move until switch."
    if item == "choice band":
        return "Raises Attack by 50%, locks move until switch."
    if item == "choice specs":
        return "Raises Sp. Atk by 50%, locks move until switch."

    alias_map = {
        "never-melt ice": "never melt ice",
        "silver power": "silver powder",
        "blank plate": "silk scarf",
    }
    candidates = [item, item.replace("-", " ")]
    mapped = alias_map.get(item)
    if mapped:
        candidates.insert(0, mapped)

    for name in candidates:
        path = os.path.join("items", f"{name}.txt")
        if not os.path.exists(path):
            continue
        try:
            with open(path, "r", encoding="utf-8") as f:
                text = " ".join((f.read() or "").strip().split())
            if text:
                return text
        except Exception:
            continue
    if item == "z crystal":
        return "Allows the holder to use a one-time Z Move."
    return "No effect data"


def _battle_item_select_options(item_names: list[str]) -> list[discord.SelectOption]:
    options = []
    for item in sorted([str(x).strip().lower() for x in item_names if str(x).strip()], key=str.lower):
        desc = _battle_item_effect_text(item)
        if len(desc) > 100:
            desc = desc[:97].rstrip() + "..."
        options.append(discord.SelectOption(label=item.title(), value=item, description=desc))
    return options


def _find_mega_forms_for_base(base_name: str):
    base = str(base_name or "").strip().lower()
    if not base:
        return []
    forms = []
    try:
        for fn in os.listdir("pokemon_data"):
            if not fn.lower().endswith(".json"):
                continue
            name = fn[:-5].strip().lower()
            if name.startswith(f"mega {base}") or name.startswith(f"primal {base}"):
                forms.append(name)
    except Exception:
        pass
    forms = sorted(set(forms))
    return forms


def _can_trigger_mega_with_item(base_name: str, form_name: str, held_item: str):
    base = str(base_name or "").strip().lower()
    form = str(form_name or "").strip().lower()
    item = str(held_item or "").strip().lower()
    if form.startswith("primal "):
        if "kyogre" in base:
            return item == "blue orb"
        if "groudon" in base:
            return item == "red orb"
        return False
    # Generic mega-stone check
    return item == "mega stone"


def _make_special_choice_label(choice: str):
    text = str(choice or "")
    if text.startswith("ZMOVE::"):
        try:
            _, mtype, category = text.split("::", 2)
            return f"Z Move ({mtype.capitalize()} {category.capitalize()})"
        except Exception:
            return "Z Move"
    if text.startswith("MEGA_EVOLVE::"):
        try:
            form = text.split("::", 1)[1]
            return f"Mega Evolve -> {form.title()}"
        except Exception:
            return "Mega Evolve"
    return text


def _compute_zmove_damage(move_choice: str, defender_types):
    try:
        _, z_type, _ = str(move_choice).split("::", 2)
    except Exception:
        return 0
    tm = get_effectiveness(z_type, defender_types)
    if tm is None:
        tm = 1
    return math.floor(150 * tm)


def _generate_rng_iv_set():
    # Exact IV total = 160, with Speed always maxed at 31.
    target_total = 160
    speed_iv = 31
    remaining = target_total - speed_iv  # 117 split across HP/Atk/Def/SpA/SpD
    ivs = []
    for idx in range(5):
        slots_left = 5 - idx
        lo = max(0, remaining - (slots_left - 1) * 31)
        hi = min(31, remaining)
        roll = random.randint(lo, hi)
        ivs.append(roll)
        remaining -= roll
    ivs.append(speed_iv)
    return ivs


def _ensure_rng_iv_pool(data, slot):
    if not _is_p2_rng_mode(data.get("mode", "")):
        return
    key = f"{slot}_rng_ivs"
    number = int(data.get("number", 3) or 3)
    max_iv_mode = bool(data.get("rng_max_iv_mode", False))
    if max_iv_mode:
        data[key] = [[31, 31, 31, 31, 31, 31] for _ in range(number)]
        return

    pool = data.get(key)
    if not isinstance(pool, list):
        pool = []
    # Normalize legacy/invalid rolls so p2 rng is always deterministic to current rules.
    normalized = []
    for ivs in pool[:number]:
        valid = (
            isinstance(ivs, list)
            and len(ivs) == 6
            and all(isinstance(v, int) and 0 <= v <= 31 for v in ivs)
            and ivs[5] == 31
            and sum(ivs) == 160
        )
        normalized.append(ivs if valid else _generate_rng_iv_set())
    pool = normalized
    while len(pool) < number:
        pool.append(_generate_rng_iv_set())
    data[key] = pool[:number]


def _rng_iv_for_index(data, slot, index_1_based):
    if not _is_p2_rng_mode(data.get("mode", "")):
        return None
    _ensure_rng_iv_pool(data, slot)
    pool = data.get(f"{slot}_rng_ivs") or []
    idx = max(1, int(index_1_based)) - 1
    if idx < len(pool):
        ivs = pool[idx]
        if isinstance(ivs, list) and len(ivs) == 6:
            return [int(v) for v in ivs]
    return None


def _next_empty_slot_idx(data, slot):
    number = int(data.get("number", 3) or 3)
    for i in range(1, number + 1):
        if not data.get(f"{slot}_p{i}"):
            return i
    return None


def _apply_rng_secondary_effect(move_name, defender_condition, msg_parts):
    mv = str(move_name or "").strip().lower()
    if not mv:
        return
    roll_dice = random.random()
    if mv == "sacred fire":
        if roll_dice < 0.50 and "burn" not in defender_condition:
            defender_condition.append("burn")
            msg_parts.append("It inflicted burn!")
    elif mv in {"ice burn", "lava plume", "scorching sands", "searing shot", "steam eruption"}:
        if roll_dice < 0.30 and "burn" not in defender_condition:
            defender_condition.append("burn")
            msg_parts.append("It inflicted burn!")
    elif mv in {"sandsear storm", "blue flare"}:
        if roll_dice < 0.20 and "burn" not in defender_condition:
            defender_condition.append("burn")
            msg_parts.append("It inflicted burn!")
    elif mv in {"fire punch", "flamethrower", "pyro ball", "fire blast", "flare blitz", "blaze kick", "fire fang"}:
        if roll_dice < 0.10 and "burn" not in defender_condition:
            defender_condition.append("burn")
            msg_parts.append("It inflicted burn!")
    elif mv in {"poison jab", "sludge bomb"}:
        if roll_dice < 0.30 and "poison" not in defender_condition:
            defender_condition.append("poison")
            msg_parts.append("It poisoned the opponent!")
    elif mv in {"sludge wave"}:
        if roll_dice < 0.10 and "poison" not in defender_condition:
            defender_condition.append("poison")
            msg_parts.append("It poisoned the opponent!")
    elif mv == "will-o-wisp":
        if roll_dice < 0.85 and "burn" not in defender_condition:
            defender_condition.append("burn")
            msg_parts.append("It inflicted burn!")


def _format_rng_iv_line(ivs):
    return f"HP {ivs[0]} / Atk {ivs[1]} / Def {ivs[2]} / SpA {ivs[3]} / SpD {ivs[4]} / Spe {ivs[5]}"


def _build_rng_iv_embed(data, slot):
    if not _is_p2_rng_mode(data.get("mode", "")):
        return None
    _ensure_rng_iv_pool(data, slot)
    number = int(data.get("number", 3) or 3)
    pool = data.get(f"{slot}_rng_ivs") or []
    max_iv_mode = bool(data.get("rng_max_iv_mode", False))
    desc = "These IV rolls are locked to your team slots for this battle.\nTotal IV per slot: 160 | Speed IV: 31"
    if max_iv_mode:
        desc = "Max IV mode is active for this battle.\nAll slots: 31 / 31 / 31 / 31 / 31 / 31"
    embed = discord.Embed(
        title="P2 RNG IV Slots",
        description=desc,
        color=parse_embed_color(data.get("color")),
    )
    for i in range(1, number + 1):
        ivs = pool[i - 1] if i - 1 < len(pool) else [0, 0, 0, 0, 0, 31]
        embed.add_field(
            name=f"Slot {i}",
            value=f"`{_format_rng_iv_line(ivs)}`\nTotal: {sum(ivs)}",
            inline=False,
        )
    return embed


def _set_all_rng_ivs_to_max(data):
    """In p2 rng mode, convert all RNG IV rolls and assigned slot IVs to max IV."""
    if not _is_p2_rng_mode(data.get("mode", "")):
        return False

    number = int(data.get("number", 3) or 3)
    max_ivs = [31, 31, 31, 31, 31, 31]

    data["rng_max_iv_mode"] = True
    for slot in ("p1", "p2"):
        data[f"{slot}_rng_ivs"] = [max_ivs.copy() for _ in range(number)]
        for i in range(1, number + 1):
            pokemon_name = data.get(f"{slot}_p{i}")
            if not pokemon_name:
                continue
            data[f"{slot}_stats{i}"] = max_ivs.copy()
            try:
                base_stats, _ = get_pokemon_stats(pokemon_name)
                hp = math.floor(2 * base_stats[0] + 31 + 5 + 110)
                data[f"{slot}_hp{i}"] = hp
            except Exception:
                continue

    return True


def _randomize_all_rng_ivs(data):
    """In p2 rng mode, convert all RNG IV rolls and assigned slot IVs to random IVs."""
    if not _is_p2_rng_mode(data.get("mode", "")):
        return False

    number = int(data.get("number", 3) or 3)
    data["rng_max_iv_mode"] = False
    for slot in ("p1", "p2"):
        data[f"{slot}_rng_ivs"] = [_generate_rng_iv_set() for _ in range(number)]
        for i in range(1, number + 1):
            pokemon_name = data.get(f"{slot}_p{i}")
            if not pokemon_name:
                continue
            ivs = data[f"{slot}_rng_ivs"][i - 1]
            data[f"{slot}_stats{i}"] = ivs.copy()
            try:
                base_stats, _ = get_pokemon_stats(pokemon_name)
                hp = math.floor(2 * base_stats[0] + ivs[0] + 5 + 110)
                data[f"{slot}_hp{i}"] = hp
            except Exception:
                continue

    return True


async def _send_team_selection_panel(user_obj, player_id, file_path, slot, content_text):
    data = None
    try:
        data = _load_battle(file_path)
    except Exception as e:
        data = None
    if data is None:
        try:
            with open(file_path, "r") as f:
                data = json.load(f)
        except Exception:
            data = {}
    if _is_simplified_mode(data.get("mode", "")):
        view = SimplifiedBattleTeamSelectView(player_id, file_path)
        content_text = (
            "Pick pokemon/team for your battle. \nUse `!premake <pokemon>` to set up your pokemon, then add by clicking "
            "\"Add Premade Pokemon\" button to add with mint,pokemon. \nOr use `!battle_team simplified` to set up team "
            "and add by selecting team using dropdown."
        )
    else:
        view = SelectPokemonView(player_id, file_path)
        if bool(data.get("fake")):
            content_text = (
                f"{content_text}\n"
                "You can create fakemon using !create_pokemon\n"
                "You can find a list of fakemons in /search_pokemon fake: True"
            )
    embed = None
    try:
        if _is_p2_rng_mode(data.get("mode", "")):
            _ensure_rng_iv_pool(data, slot)
            if bool(data.get("rng_max_iv_mode", False)):
                embed = _build_rng_iv_embed(data, slot)
            _save_battle(file_path, data)
    except Exception:
        embed = None

    if embed:
        msg = await user_obj.send(content=content_text, embed=embed, view=view)
    else:
        msg = await user_obj.send(content=content_text, view=view)
    view.message = msg
    return msg, view

    return _choose_pve_reply_fallback(file_path)


def _choose_raid_boss_move(file_path, player_choice):
    data = _load_battle(file_path)
    p2_active = get_active("p2", data)
    p1_active = get_active("p1", data)
    if not p2_active or not p1_active:
        return None
    moves = data.get(f"p2_moves{p2_active}", []) or []
    legal_moves = [m for m in moves if m and not str(m).startswith("Switch to ")]
    if not legal_moves:
        return None

    p2_poke = data[f"p2_p{p2_active}"]
    p2_stats = get_pokemon_stats(p2_poke)[0]
    p2_type = get_pokemon_stats(p2_poke)[1]
    p2_ability = data.get(f"p2_ability{p2_active}") or "ball fetch"
    p2_hi = (data.get(f"p2_hi{p2_active}") or "scope lense").lower()
    p2_status = data.get(f"p2_status{p2_active}", [0] * 6) or [0] * 6
    if len(p2_status) < 6:
        p2_status = (p2_status + [0] * 6)[:6]

    p1_poke = data[f"p1_p{p1_active}"]
    p1_stats = get_pokemon_stats(p1_poke)[0]
    p1_type = get_pokemon_stats(p1_poke)[1]
    p1_ability = data.get(f"p1_ability{p1_active}") or "ball fetch"
    p1_hi = (data.get(f"p1_hi{p1_active}") or "scope lense").lower()
    p1_status = data.get(f"p1_status{p1_active}", [0] * 6) or [0] * 6
    if len(p1_status) < 6:
        p1_status = (p1_status + [0] * 6)[:6]

    weather = str(data.get("weather", "none") or "none").strip().lower()

    def score_move(move_name):
        try:
            dmg, _, _ = apply_damage_pi(
                move_name,
                p2_stats,
                p1_stats,
                p2_type,
                p1_type,
                p2_status,
                p1_status,
                data.get(f"p2_nature{p2_active}") or "hardy",
                data.get(f"p1_nature{p1_active}") or "hardy",
                p2_ability,
                p1_ability,
                p2_hi,
                p1_hi,
                current_hp=data.get(f"p2_hp{p2_active}"),
                max_hp=max(1, math.floor(2 * int(p2_stats[0]) + 31 + 5 + 110)),
            )
        except Exception:
            dmg = -1
        try:
            move_type = str(get_move_info(move_name)[2]).lower()
        except Exception:
            move_type = ""
        if weather == "extremely harsh sunlight" and move_type == "water":
            return -10
        return dmg

    best = max(legal_moves, key=score_move)
    return best

def _choose_pve_reply(mode_value: str, file_path: str, player_choice: str):
    mode = str(mode_value or "").strip().lower()
    if mode == PVE_MODE_RAID:
        try:
            reply = _choose_raid_boss_move(file_path, player_choice)
        except Exception:
            traceback.print_exc()
            reply = None
        if reply:
            return reply
        return _choose_pve_reply_fallback(file_path)
    is_tower = False
    use_advanced_ai = mode == PVE_MODE_KONGFU
    if not use_advanced_ai:
        try:
            b = _load_battle(file_path)
            is_tower = isinstance(b.get("tower_battle"), dict)
            use_advanced_ai = is_tower
        except Exception:
            pass
    
    # Use simplified tower AI for tower battles
    if is_tower:
        try:
            reply = _tower_choose_move_simple(file_path, player_choice)
            if reply:
                return reply
        except Exception:
            traceback.print_exc()
        return _choose_pve_reply_fallback(file_path)
    
    # Use advanced AI for non-tower battles
    if use_advanced_ai:
        try:
            reply = choose_pve_move2(file_path, player_choice, depth=1)
            if reply:
                return reply
        except Exception:
            traceback.print_exc()
        try:
            reply = choose_pve_move(file_path, player_choice)
            if reply:
                return reply
        except Exception:
            traceback.print_exc()
        return _choose_pve_reply_fallback(file_path)
    try:
        reply = choose_pve_move(file_path, player_choice)
        if reply:
            return reply
    except Exception:
        traceback.print_exc()
    return _choose_pve_reply_fallback(file_path)


def _choose_pve_reply_fallback(file_path: str):
    """Emergency fallback so NPC always responds with a legal action."""
    try:
        data = _load_battle(file_path)
        active = get_active("p2", data)
        if active:
            moves = data.get(f"p2_moves{active}", []) or []
            for mv in moves:
                if mv:
                    return mv
            number = int(data.get("number", 6) or 6)
            for i in range(1, number + 1):
                if i == active:
                    continue
                poke = data.get(f"p2_p{i}")
                if poke and data.get(f"p2_hp{i}", 0) > 0:
                    return f"Switch to {poke}"
    except Exception:
        traceback.print_exc()
    return "Surrender"


