def get_pokemon_moves(pokemon_name, allow_fake=False, prefer_fake=False):
    pokemon_data, _, _ = load_pokemon_data_for_lookup(
        pokemon_name,
        allow_fake=allow_fake,
        prefer_fake=prefer_fake,
    )
    if pokemon_data:
        moves = [str(m["move"]).replace("-", " ") for m in pokemon_data.get("moves_via_level_up", [])]
        return sorted(set(moves))
    return ['poke not found']

DUEL_BAN_DB = "duel_ban_config.db"

def setup_duel_ban_db():
    with sqlite3.connect(DUEL_BAN_DB) as conn:
        c = conn.cursor()
        c.execute("""
            CREATE TABLE IF NOT EXISTS duel_bans (
                guild_id INTEGER PRIMARY KEY,
                enable_trending INTEGER DEFAULT 1,
                specific_bans TEXT,
                pokemon_bans TEXT,
                move_bans TEXT
            )
        """)
        conn.commit()

def _duel_default_config():
    return {
        "enable_trending": True,
        "specific_bans": [],
        "pokemon_bans": [],
        "move_bans": [],
    }

_HARD_BANNED_POKEMON = {
    "best1111",
    "grand mountain groudon",
    "gmax ainz",
    "armored mewtwo x",
    "armored mewtwo y",
    "thunder rider calyrex",
    "flame heart koraidon",
    "gmax slaking",
    "detective pikachu",
    "engo"
}

def _normalize_ban_name(value: str) -> str:
    return str(value or "").strip().lower().replace("-", " ")

def _is_hard_banned_pokemon(pokemon_name: str) -> bool:
    return _normalize_ban_name(pokemon_name) in _HARD_BANNED_POKEMON

def _load_duel_ban_config(guild_id: int | None):
    if not guild_id:
        return _duel_default_config()
    setup_duel_ban_db()
    with sqlite3.connect(DUEL_BAN_DB) as conn:
        c = conn.cursor()
        c.execute(
            "SELECT enable_trending, specific_bans, pokemon_bans, move_bans FROM duel_bans WHERE guild_id = ?",
            (int(guild_id),)
        )
        row = c.fetchone()
    if not row:
        return _duel_default_config()

    enable_trending, specific_json, pokemon_json, move_json = row
    try:
        specific_bans = json.loads(specific_json) if specific_json else []
    except Exception:
        specific_bans = []
    try:
        pokemon_bans = json.loads(pokemon_json) if pokemon_json else []
    except Exception:
        pokemon_bans = []
    try:
        move_bans = json.loads(move_json) if move_json else []
    except Exception:
        move_bans = []

    return {
        "enable_trending": bool(enable_trending),
        "specific_bans": specific_bans if isinstance(specific_bans, list) else [],
        "pokemon_bans": pokemon_bans if isinstance(pokemon_bans, list) else [],
        "move_bans": move_bans if isinstance(move_bans, list) else [],
    }

def _save_duel_ban_config(guild_id: int, config: dict):
    setup_duel_ban_db()
    with sqlite3.connect(DUEL_BAN_DB) as conn:
        c = conn.cursor()
        c.execute(
            """
            INSERT INTO duel_bans (guild_id, enable_trending, specific_bans, pokemon_bans, move_bans)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(guild_id)
            DO UPDATE SET
                enable_trending = excluded.enable_trending,
                specific_bans = excluded.specific_bans,
                pokemon_bans = excluded.pokemon_bans,
                move_bans = excluded.move_bans
            """,
            (
                int(guild_id),
                1 if config.get("enable_trending", True) else 0,
                json.dumps(config.get("specific_bans", []), ensure_ascii=True),
                json.dumps(config.get("pokemon_bans", []), ensure_ascii=True),
                json.dumps(config.get("move_bans", []), ensure_ascii=True),
            )
        )
        conn.commit()

def _duel_ban_limit(guild_id: int) -> int:
    return 10 if is_guild_premium(guild_id) else 5

def _get_battle_guild_id(file_path: str):
    try:
        data = _load_battle(file_path)
    except Exception:
        return None
    guild_id = data.get("guild_id")
    if guild_id:
        try:
            return int(guild_id)
        except Exception:
            pass
    channel_id = data.get("channel")
    if channel_id:
        try:
            channel = bot.get_channel(int(channel_id))
        except Exception:
            channel = None
        if channel and getattr(channel, "guild", None):
            return int(channel.guild.id)
    return None

def _duel_is_pokemon_banned(guild_id: int | None, pokemon_name: str) -> bool:
    if not guild_id:
        return _is_hard_banned_pokemon(pokemon_name)
    if _is_hard_banned_pokemon(pokemon_name):
        return True
    config = _load_duel_ban_config(guild_id)
    target = _normalize_ban_name(pokemon_name)
    return target in { _normalize_ban_name(x) for x in config.get("pokemon_bans", []) }

def _duel_is_move_banned(guild_id: int | None, move_name: str) -> bool:
    if not guild_id:
        return False
    config = _load_duel_ban_config(guild_id)
    target = _normalize_ban_name(move_name)
    return target in { _normalize_ban_name(x) for x in config.get("move_bans", []) }

def _duel_is_specific_banned(guild_id: int | None, pokemon_name: str, move_name: str) -> bool:
    if not guild_id:
        return False
    config = _load_duel_ban_config(guild_id)
    p = _normalize_ban_name(pokemon_name)
    m = _normalize_ban_name(move_name)
    for entry in config.get("specific_bans", []):
        if not isinstance(entry, dict):
            continue
        if _normalize_ban_name(entry.get("pokemon")) == p and _normalize_ban_name(entry.get("move")) == m:
            return True
    return False

def _duel_team_ban_violations(guild_id: int | None, members: list):
    if not guild_id:
        return []
    config = _load_duel_ban_config(guild_id)
    pokemon_bans = { _normalize_ban_name(x) for x in config.get("pokemon_bans", []) }
    move_bans = { _normalize_ban_name(x) for x in config.get("move_bans", []) }
    specific_bans = {
        (_normalize_ban_name(e.get("pokemon")), _normalize_ban_name(e.get("move")))
        for e in config.get("specific_bans", [])
        if isinstance(e, dict)
    }
    violations = []
    for p in members:
        name = _normalize_ban_name(p.get("name"))
        if not name:
            continue
        if name in _HARD_BANNED_POKEMON:
            violations.append(f"Pokémon banned: {name}")
            continue
        if name in pokemon_bans:
            violations.append(f"Pokémon banned: {name}")
            continue
        moves = [ _normalize_ban_name(m) for m in (p.get("moves") or []) if str(m).strip() ]
        for mv in moves:
            if not mv or mv == "auto":
                continue
            if mv in move_bans:
                violations.append(f"Move banned: {name} — {mv}")
            elif (name, mv) in specific_bans:
                violations.append(f"Specific ban: {name} — {mv}")
    return violations

# Ranked ban config (global)
RANKED_BAN_CONFIG_FILE = "ranked_ban_config.json"

def _ranked_default_config():
    return {
        "pokemon_bans": [],
        "move_bans": [],
        "specific_bans": [],
    }

def _load_ranked_ban_config():
    if os.path.exists(RANKED_BAN_CONFIG_FILE):
        try:
            with open(RANKED_BAN_CONFIG_FILE, "r", encoding="utf-8") as f:
                config = json.load(f)
            # Ensure all keys exist
            defaults = _ranked_default_config()
            for key, default_value in defaults.items():
                if key not in config:
                    config[key] = default_value
            return config
        except json.JSONDecodeError:
            pass
    return _ranked_default_config()

def _save_ranked_ban_config(config: dict):
    with open(RANKED_BAN_CONFIG_FILE, "w", encoding="utf-8") as f:
        json.dump(config, f, indent=4, ensure_ascii=False)

