def _ranked_common_team_ban_violations(members: list):
    config = _load_ranked_common_ban_config()
    pokemon_bans = { _normalize_ban_name(x) for x in config.get("pokemon_bans", []) }
    move_bans = { _normalize_ban_name(x) for x in config.get("move_bans", []) }
    specific_bans = {
        (_normalize_ban_name(e.get("pokemon")), _normalize_ban_name(e.get("move")))
        for e in config.get("specific_bans", [])
        if isinstance(e, dict)
    }
    violations = []
    for p in members:
        name = _normalize_ban_name(p.get("name"))
        if not name:
            continue
        if name in _HARD_BANNED_POKEMON:
            violations.append(f"Pokémon hard-banned: {name}")
            continue
        if name in pokemon_bans:
            violations.append(f"Pokémon banned: {name}")
            continue
        moves = [ _normalize_ban_name(m) for m in (p.get("moves") or []) if str(m).strip() ]
        for mv in moves:
            if not mv or mv == "auto":
                continue
            if mv in move_bans:
                violations.append(f"Move banned: {name} — {mv}")
            elif (name, mv) in specific_bans:
                violations.append(f"Specific ban: {name} — {mv}")
    return violations

def _build_ranked_common_specific_bans_text() -> str:
    config = _load_ranked_common_ban_config()
    limit = 30
    specific_lines = []
    for entry in config.get("specific_bans", []):
        if isinstance(entry, dict):
            p = str(entry.get("pokemon", "")).strip()
            m = str(entry.get("move", "")).strip()
            if p and m:
                specific_lines.append(f"{get_pokemon_emoji(p)}{p} --- {m}")
    text = "\n".join(specific_lines) if specific_lines else "None"
    return f"**Specific Bans** ({len(specific_lines)}/{limit})\n{text}"

