def _is_ranked_common_banned(pokemon_name: str) -> bool:
    if _is_hard_banned_pokemon(pokemon_name):
        return True
    if _is_ranked_common_banned_pokemon(pokemon_name):
        return True
    return _ranked_common_is_pokemon_banned(pokemon_name)

def _is_move_banned_for_ranked_common(move_name: str) -> bool:
    return _ranked_common_is_move_banned(move_name)

def _is_specific_banned_for_ranked_common(pokemon_name: str, move_name: str) -> bool:
    if _ranked_common_is_specific_banned(pokemon_name, move_name):
        return True
    return _ranked_is_specific_banned(pokemon_name, move_name)

def _ranked_is_pokemon_banned(pokemon_name: str) -> bool:
    if _is_hard_banned_pokemon(pokemon_name):
        return True
    config = _load_ranked_ban_config()
    target = _normalize_ban_name(pokemon_name)
    return target in { _normalize_ban_name(x) for x in config.get("pokemon_bans", []) }

def _ranked_is_move_banned(move_name: str) -> bool:
    config = _load_ranked_ban_config()
    target = _normalize_ban_name(move_name)
    return target in { _normalize_ban_name(x) for x in config.get("move_bans", []) }

def _ranked_is_specific_banned(pokemon_name: str, move_name: str) -> bool:
    config = _load_ranked_ban_config()
    p = _normalize_ban_name(pokemon_name)
    m = _normalize_ban_name(move_name)
    for entry in config.get("specific_bans", []):
        if not isinstance(entry, dict):
            continue
        if _normalize_ban_name(entry.get("pokemon")) == p and _normalize_ban_name(entry.get("move")) == m:
            return True
    return False

def _ranked_team_ban_violations(members: list):
    config = _load_ranked_ban_config()
    pokemon_bans = { _normalize_ban_name(x) for x in config.get("pokemon_bans", []) }
    move_bans = { _normalize_ban_name(x) for x in config.get("move_bans", []) }
    specific_bans = {
        (_normalize_ban_name(e.get("pokemon")), _normalize_ban_name(e.get("move")))
        for e in config.get("specific_bans", [])
        if isinstance(e, dict)
    }
    violations = []
    for p in members:
        name = _normalize_ban_name(p.get("name"))
        if not name:
            continue
        if name in _HARD_BANNED_POKEMON:
            violations.append(f"Pokémon banned: {name}")
            continue
        if name in pokemon_bans:
            violations.append(f"Pokémon banned: {name}")
            continue
        moves = [ _normalize_ban_name(m) for m in (p.get("moves") or []) if str(m).strip() ]
        for mv in moves:
            if not mv or mv == "auto":
                continue
            if mv in move_bans:
                violations.append(f"Move banned: {name} — {mv}")
            elif (name, mv) in specific_bans:
                violations.append(f"Specific ban: {name} — {mv}")
    return violations


def _get_battle_rank_type(file_path: str | None) -> str | None:
    try:
        data = _load_battle(file_path)
        if data.get("rank"):
            return _normalize_ranked_queue_type(data.get("rank_type"))
        else:
            return None
    except Exception:
        traceback.print_exc()
    return None


def _is_pokemon_banned_for_battle(file_path: str | None, guild_id: int | None, pokemon_name: str) -> bool:
    rank_type = _get_battle_rank_type(file_path)
    if rank_type == "ranked common":
        return _is_ranked_common_banned(pokemon_name)
    if rank_type:
        return _ranked_is_pokemon_banned(pokemon_name)
    return _duel_is_pokemon_banned(guild_id, pokemon_name)


def _is_move_banned_for_battle(file_path: str | None, guild_id: int | None, move_name: str) -> bool:
    rank_type = _get_battle_rank_type(file_path)
    if rank_type == "ranked common":
        return _ranked_common_is_move_banned(move_name)
    if rank_type:
        return _ranked_is_move_banned(move_name)
    return _duel_is_move_banned(guild_id, move_name)


def _is_specific_banned_for_battle(file_path: str | None, guild_id: int | None, pokemon_name: str, move_name: str) -> bool:
    rank_type = _get_battle_rank_type(file_path)
    if rank_type == "ranked common":
        return _is_specific_banned_for_ranked_common(pokemon_name, move_name)
    if rank_type:
        return _ranked_is_specific_banned(pokemon_name, move_name)
    return _duel_is_specific_banned(guild_id, pokemon_name, move_name)


def load_player_teams(user_id: int, rarity: str = "rare"):
    suffix = "_common" if str(rarity).lower() == "common" else ""
    prio_path = f"battle_teams/{user_id}_prio{suffix}.json"
    non_prio_path = f"battle_teams/{user_id}_non-prio{suffix}.json"
    trending_path = f"battle_teams/trending{suffix}.json"

    prio_teams = []
    non_prio_teams = []
    trending_teams= []

    if os.path.exists(prio_path):
        with open(prio_path, "r") as f:
            prio_teams = json.load(f).get("teams", [])

    if os.path.exists(non_prio_path):
        with open(non_prio_path, "r") as f:
            non_prio_teams = json.load(f).get("teams", [])
    
    if os.path.exists(trending_path):
        with open(trending_path, "r") as f:
            trending_teams = json.load(f).get("teams", [])

    return prio_teams, non_prio_teams, trending_teams

