class DuelConfigView(discord.ui.LayoutView):
    def __init__(self, guild_id: int):
        super().__init__(timeout=600)
        self.guild_id = int(guild_id)
        self.message = None
        self.refresh_layout()

    def refresh_layout(self):
        self.clear_items()

        container = discord.ui.Container()

        # --- Title ---
        container.add_item(discord.ui.TextDisplay("## Duel Configuration"))

        # --- Trending section ---
        container.add_item(discord.ui.TextDisplay(_build_trending_text(self.guild_id)))
        trending_action_row = discord.ui.ActionRow()
        self.trending_button = DuelTrendingToggleButton(self)
        trending_action_row.add_item(self.trending_button)
        container.add_item(trending_action_row)

        # --- Separator ---
        container.add_item(discord.ui.Separator(spacing=discord.SeparatorSpacing.small))

        # --- Specific bans section ---
        container.add_item(discord.ui.TextDisplay(_build_specific_bans_text(self.guild_id)))
        specific_action_row = discord.ui.ActionRow()
        specific_action_row.add_item(DuelSpecificBanAddButton(self))
        specific_action_row.add_item(DuelSpecificBanRemoveButton(self))
        container.add_item(specific_action_row)

        # --- Separator ---
        container.add_item(discord.ui.Separator(spacing=discord.SeparatorSpacing.small))

        # --- Pokémon bans section ---
        container.add_item(discord.ui.TextDisplay(_build_pokemon_bans_text(self.guild_id)))
        pokemon_action_row = discord.ui.ActionRow()
        pokemon_action_row.add_item(DuelPokemonBanAddButton(self))
        pokemon_action_row.add_item(DuelPokemonBanRemoveButton(self))
        container.add_item(pokemon_action_row)

        # --- Separator ---
        container.add_item(discord.ui.Separator(spacing=discord.SeparatorSpacing.small))

        # --- Move bans section ---
        container.add_item(discord.ui.TextDisplay(_build_move_bans_text(self.guild_id)))
        move_action_row = discord.ui.ActionRow()
        move_action_row.add_item(DuelMoveBanAddButton(self))
        move_action_row.add_item(DuelMoveBanRemoveButton(self))
        container.add_item(move_action_row)

        self.add_item(container)

    async def refresh(self):
        self.refresh_layout()
        if self.message:
            await self.message.edit(view=self)

class DuelTrendingToggleButton(discord.ui.Button):
    def __init__(self, parent_view: DuelConfigView):
        super().__init__(label="Toggle Trending", style=discord.ButtonStyle.primary, row=0)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message("❌ Admins only.", ephemeral=True)
        config = _load_duel_ban_config(self.parent_view.guild_id)
        config["enable_trending"] = not bool(config.get("enable_trending", True))
        _save_duel_ban_config(self.parent_view.guild_id, config)
        await interaction.response.send_message(
            f"✅ Trending teams {'enabled' if config['enable_trending'] else 'disabled'}.",
            ephemeral=True
        )
        await self.parent_view.refresh()

class SpecificBanPokemonModal(discord.ui.Modal, title="Add Specific Ban"):
    pokemon_name = discord.ui.TextInput(
        label="Pokémon Name",
        placeholder="e.g. charizard",
        required=True,
        max_length=32
    )

    def __init__(self, parent_view: DuelConfigView):
        super().__init__()
        self.parent_view = parent_view

    async def on_submit(self, interaction: discord.Interaction):
        pokemon = _normalize_ban_name(self.pokemon_name.value)
        if not pokemon or not get_pokemon_info(pokemon):
            return await interaction.response.send_message("❌ Invalid Pokémon.", ephemeral=True)
        moves = [m for m in get_pokemon_moves(pokemon) if m and m != "poke not found"]
        if not moves:
            return await interaction.response.send_message("❌ No moves found for that Pokémon.", ephemeral=True)
        view = SpecificBanMoveSelectView(self.parent_view, pokemon, moves)
        await interaction.response.send_message("Select a move to ban:", view=view, ephemeral=True)

class SpecificBanMoveSelectView(discord.ui.View):
    def __init__(self, parent_view: DuelConfigView, pokemon_name: str, moves: list):
        super().__init__(timeout=180)
        self.parent_view = parent_view
        self.pokemon_name = _normalize_ban_name(pokemon_name)
        self.moves = sorted({_normalize_ban_name(m) for m in moves if str(m).strip()})
        self.page = 0
        self.max_per_page = 25
        self.dropdown = None
        self.update_dropdown()
        self.add_item(PrevSpecificBanMoveButton(self))
        self.add_item(NextSpecificBanMoveButton(self))

    def update_dropdown(self):
        start = self.page * self.max_per_page
        end = start + self.max_per_page
        options = [discord.SelectOption(label=m) for m in self.moves[start:end]]
        if self.dropdown:
            self.remove_item(self.dropdown)
        self.dropdown = SpecificBanMoveDropdown(self, options)
        self.add_item(self.dropdown)

class SpecificBanMoveDropdown(discord.ui.Select):
    def __init__(self, parent_view: SpecificBanMoveSelectView, options: list):
        super().__init__(placeholder="Select a move", min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        move_name = _normalize_ban_name(self.values[0])
        config = _load_duel_ban_config(self.parent_view.parent_view.guild_id)
        limit = _duel_ban_limit(self.parent_view.parent_view.guild_id)
        current = config.get("specific_bans", [])
        if len(current) >= limit:
            return await interaction.response.send_message("❌ Specific ban limit reached.", ephemeral=True)
        for entry in current:
            if isinstance(entry, dict):
                if _normalize_ban_name(entry.get("pokemon")) == self.parent_view.pokemon_name and _normalize_ban_name(entry.get("move")) == move_name:
                    return await interaction.response.send_message("⚠️ This specific ban already exists.", ephemeral=True)
        current.append({"pokemon": self.parent_view.pokemon_name, "move": move_name})
        config["specific_bans"] = current
        _save_duel_ban_config(self.parent_view.parent_view.guild_id, config)
        await interaction.response.send_message(
            f"✅ Added specific ban: {self.parent_view.pokemon_name} --- {move_name}",
            ephemeral=True
        )
        await self.parent_view.parent_view.refresh()

class PrevSpecificBanMoveButton(discord.ui.Button):
    def __init__(self, parent_view: SpecificBanMoveSelectView):
        super().__init__(label="Prev", style=discord.ButtonStyle.secondary, row=1)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if self.parent_view.page > 0:
            self.parent_view.page -= 1
            self.parent_view.update_dropdown()
            await interaction.response.edit_message(view=self.parent_view)
        else:
            await interaction.response.defer()

class NextSpecificBanMoveButton(discord.ui.Button):
    def __init__(self, parent_view: SpecificBanMoveSelectView):
        super().__init__(label="Next", style=discord.ButtonStyle.secondary, row=1)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        max_page = max(0, (len(self.parent_view.moves) - 1) // self.parent_view.max_per_page)
        if self.parent_view.page < max_page:
            self.parent_view.page += 1
            self.parent_view.update_dropdown()
            await interaction.response.edit_message(view=self.parent_view)
        else:
            await interaction.response.defer()

