class DuelSpecificBanRemoveButton(discord.ui.Button):
    def __init__(self, parent_view: DuelConfigView):
        super().__init__(label="Remove Specific Ban", style=discord.ButtonStyle.danger, row=1)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.administrator:
            return await interaction.response.send_message("❌ Admins only.", ephemeral=True)
        config = _load_duel_ban_config(self.parent_view.guild_id)
        entries = config.get("specific_bans", [])
        if not entries:
            return await interaction.response.send_message("⚠️ No specific bans to remove.", ephemeral=True)
        options = []
        for i, entry in enumerate(entries):
            if not isinstance(entry, dict):
                continue
            p = str(entry.get("pokemon", "")).strip()
            m = str(entry.get("move", "")).strip()
            label = f"{p} --- {m}"[:100]
            options.append(discord.SelectOption(label=label, value=str(i)))
        view = SpecificBanRemoveSelectView(self.parent_view, entries, options)
        await interaction.response.send_message("Select a specific ban to remove:", view=view, ephemeral=True)

class SpecificBanRemoveSelectView(discord.ui.View):
    def __init__(self, parent_view: DuelConfigView, entries: list, options: list):
        super().__init__(timeout=120)
        self.parent_view = parent_view
        self.entries = entries
        self.add_item(SpecificBanRemoveDropdown(self, options))

class SpecificBanRemoveDropdown(discord.ui.Select):
    def __init__(self, parent_view: SpecificBanRemoveSelectView, options: list):
        super().__init__(placeholder="Select a ban to remove", min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        idx = int(self.values[0])
        config = _load_duel_ban_config(self.parent_view.parent_view.guild_id)
        if idx < 0 or idx >= len(config.get("specific_bans", [])):
            return await interaction.response.send_message("❌ Ban not found.", ephemeral=True)
        removed = config["specific_bans"].pop(idx)
        _save_duel_ban_config(self.parent_view.parent_view.guild_id, config)
        await interaction.response.send_message("✅ Removed specific ban.", ephemeral=True)
        await self.parent_view.parent_view.refresh()

