class RankedConfigView(discord.ui.LayoutView):
    def __init__(self):
        super().__init__(timeout=600)
        self.message = None
        self.refresh_layout()

    def refresh_layout(self):
        self.clear_items()

        container = discord.ui.Container()

        # --- Title ---
        container.add_item(discord.ui.TextDisplay("## Ranked Rare Configuration"))

        # --- Separator ---
        container.add_item(discord.ui.Separator(spacing=discord.SeparatorSpacing.small))

        # --- Specific bans section ---
        container.add_item(discord.ui.TextDisplay(_build_ranked_specific_bans_text()))
        specific_action_row = discord.ui.ActionRow()
        specific_action_row.add_item(RankedSpecificBanAddButton(self))
        specific_action_row.add_item(RankedSpecificBanRemoveButton(self))
        container.add_item(specific_action_row)

        # --- Separator ---
        container.add_item(discord.ui.Separator(spacing=discord.SeparatorSpacing.small))

        # --- Pokémon bans section ---
        container.add_item(discord.ui.TextDisplay(_build_ranked_pokemon_bans_text()))
        pokemon_action_row = discord.ui.ActionRow()
        pokemon_action_row.add_item(RankedPokemonBanAddButton(self))
        pokemon_action_row.add_item(RankedPokemonBanRemoveButton(self))
        container.add_item(pokemon_action_row)

        # --- Separator ---
        container.add_item(discord.ui.Separator(spacing=discord.SeparatorSpacing.small))

        # --- Move bans section ---
        container.add_item(discord.ui.TextDisplay(_build_ranked_move_bans_text()))
        move_action_row = discord.ui.ActionRow()
        move_action_row.add_item(RankedMoveBanAddButton(self))
        move_action_row.add_item(RankedMoveBanRemoveButton(self))
        container.add_item(move_action_row)

        self.add_item(container)

    async def refresh(self):
        self.refresh_layout()
        if self.message:
            await self.message.edit(view=self)


