class RankedSpecificBanMoveSelectView(discord.ui.View):
    def __init__(self, parent_view: RankedConfigView, pokemon_name: str, moves: list):
        super().__init__(timeout=180)
        self.parent_view = parent_view
        self.pokemon_name = _normalize_ban_name(pokemon_name)
        self.moves = sorted({_normalize_ban_name(m) for m in moves if str(m).strip()})
        self.page = 0
        self.max_per_page = 25
        self.dropdown = None
        self.update_dropdown()
        self.add_item(RankedPrevSpecificBanMoveButton(self))
        self.add_item(RankedNextSpecificBanMoveButton(self))

    def update_dropdown(self):
        start = self.page * self.max_per_page
        end = start + self.max_per_page
        options = [discord.SelectOption(label=m) for m in self.moves[start:end]]
        if self.dropdown:
            self.remove_item(self.dropdown)
        self.dropdown = RankedSpecificBanMoveDropdown(self, options)
        self.add_item(self.dropdown)


class RankedSpecificBanMoveDropdown(discord.ui.Select):
    def __init__(self, parent_view: RankedSpecificBanMoveSelectView, options: list):
        super().__init__(placeholder="Select a move", min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        move_name = _normalize_ban_name(self.values[0])
        config = _load_ranked_ban_config()
        limit = 30
        current = config.get("specific_bans", [])
        if len(current) >= limit:
            return await interaction.response.send_message("❌ Specific ban limit reached.", ephemeral=True)
        for entry in current:
            if isinstance(entry, dict):
                if _normalize_ban_name(entry.get("pokemon")) == self.parent_view.pokemon_name and _normalize_ban_name(entry.get("move")) == move_name:
                    return await interaction.response.send_message("⚠️ This specific ban already exists.", ephemeral=True)
        current.append({"pokemon": self.parent_view.pokemon_name, "move": move_name})
        config["specific_bans"] = current
        _save_ranked_ban_config(config)
        await interaction.response.send_message(
            f"✅ Added ranked specific ban: {self.parent_view.pokemon_name} --- {move_name}",
            ephemeral=True
        )
        await self.parent_view.parent_view.refresh()


class RankedPrevSpecificBanMoveButton(discord.ui.Button):
    def __init__(self, parent_view: RankedSpecificBanMoveSelectView):
        super().__init__(label="Prev", style=discord.ButtonStyle.secondary, row=1)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if self.parent_view.page > 0:
            self.parent_view.page -= 1
            self.parent_view.update_dropdown()
            await interaction.response.edit_message(view=self.parent_view)
        else:
            await interaction.response.defer()


class RankedNextSpecificBanMoveButton(discord.ui.Button):
    def __init__(self, parent_view: RankedSpecificBanMoveSelectView):
        super().__init__(label="Next", style=discord.ButtonStyle.secondary, row=1)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        max_page = max(0, (len(self.parent_view.moves) - 1) // self.parent_view.max_per_page)
        if self.parent_view.page < max_page:
            self.parent_view.page += 1
            self.parent_view.update_dropdown()
            await interaction.response.edit_message(view=self.parent_view)
        else:
            await interaction.response.defer()


class RankedSpecificBanRemoveButton(discord.ui.Button):
    def __init__(self, parent_view: RankedConfigView):
        super().__init__(label="Remove Specific Ban", style=discord.ButtonStyle.danger, row=1)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id not in owner_ids:
            return await interaction.response.send_message("❌ Bot owners only.", ephemeral=True)
        config = _load_ranked_ban_config()
        entries = config.get("specific_bans", [])
        if not entries:
            return await interaction.response.send_message("⚠️ No specific bans to remove.", ephemeral=True)
        options = []
        for i, entry in enumerate(entries):
            if not isinstance(entry, dict):
                continue
            p = str(entry.get("pokemon", "")).strip()
            m = str(entry.get("move", "")).strip()
            label = f"{p} --- {m}"[:100]
            options.append(discord.SelectOption(label=label, value=str(i)))
        view = RankedSpecificBanRemoveSelectView(self.parent_view, entries, options)
        await interaction.response.send_message("Select a specific ban to remove:", view=view, ephemeral=True)


