SIMPLIFIED_TEAM_DB = "battle_teams/simplified_teams.db"
PREMAKE_DB = "premade.db"


def _ensure_simplified_team_db():
    os.makedirs("battle_teams", exist_ok=True)
    with sqlite3.connect(SIMPLIFIED_TEAM_DB) as conn:
        c = conn.cursor()
        c.execute(
            """
            CREATE TABLE IF NOT EXISTS simplified_teams (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                rarity TEXT NOT NULL DEFAULT 'rare',
                team_json TEXT NOT NULL,
                created_at INTEGER NOT NULL
            )
            """
        )
        conn.commit()

def _ensure_premake_db():
    with sqlite3.connect(PREMAKE_DB) as conn:
        c = conn.cursor()
        c.execute(
            """
            CREATE TABLE IF NOT EXISTS premake (
                user_id INTEGER NOT NULL,
                pokemon TEXT NOT NULL,
                moves_json TEXT NOT NULL,
                ability TEXT,
                item TEXT,
                updated_at INTEGER NOT NULL,
                PRIMARY KEY (user_id, pokemon)
            )
            """
        )
        conn.commit()

def load_premake(user_id: int, pokemon_name: str):
    _ensure_premake_db()
    with sqlite3.connect(PREMAKE_DB) as conn:
        c = conn.cursor()
        c.execute(
            """
            SELECT moves_json, ability, item
            FROM premake
            WHERE user_id = ? AND pokemon = ?
            """,
            (int(user_id), str(pokemon_name or "").strip().lower()),
        )
        row = c.fetchone()
    if not row:
        return None
    moves_json, ability, item = row
    try:
        moves = json.loads(moves_json) if moves_json else []
    except Exception:
        moves = []
    return {
        "moves": moves,
        "ability": str(ability or "").strip().lower() or None,
        "item": str(item or "").strip().lower() or None,
    }

def save_premake(user_id: int, pokemon_name: str, moves: list, ability: str, item: str | None):
    _ensure_premake_db()
    with sqlite3.connect(PREMAKE_DB) as conn:
        c = conn.cursor()
        c.execute(
            """
            INSERT OR REPLACE INTO premake (user_id, pokemon, moves_json, ability, item, updated_at)
            VALUES (?, ?, ?, ?, ?, ?)
            """,
            (
                int(user_id),
                str(pokemon_name or "").strip().lower(),
                json.dumps(moves or [], ensure_ascii=True),
                str(ability or "").strip().lower() or None,
                str(item or "").strip().lower() or None,
                int(time.time()),
            ),
        )
        conn.commit()


def load_simplified_teams(user_id: int, rarity: str = "rare"):
    _ensure_simplified_team_db()
    rows = []
    with sqlite3.connect(SIMPLIFIED_TEAM_DB) as conn:
        c = conn.cursor()
        c.execute(
            """
            SELECT id, team_json
            FROM simplified_teams
            WHERE user_id = ? AND rarity = ?
            ORDER BY id ASC
            """,
            (int(user_id), str(rarity or "rare").strip().lower()),
        )
        rows = c.fetchall()
    teams = []
    for tid, team_json in rows:
        try:
            team = json.loads(team_json)
            if isinstance(team, list):
                teams.append({"id": int(tid), "members": team})
        except Exception:
            continue
    return teams


def save_simplified_team(user_id: int, members: list, rarity: str = "rare"):
    _ensure_simplified_team_db()
    with sqlite3.connect(SIMPLIFIED_TEAM_DB) as conn:
        c = conn.cursor()
        c.execute(
            """
            INSERT INTO simplified_teams (user_id, rarity, team_json, created_at)
            VALUES (?, ?, ?, ?)
            """,
            (
                int(user_id),
                str(rarity or "rare").strip().lower(),
                json.dumps(members, ensure_ascii=True),
                int(time.time()),
            ),
        )
        conn.commit()
        return int(c.lastrowid)


def update_simplified_team(team_id: int, members: list):
    _ensure_simplified_team_db()
    with sqlite3.connect(SIMPLIFIED_TEAM_DB) as conn:
        c = conn.cursor()
        c.execute(
            "UPDATE simplified_teams SET team_json = ? WHERE id = ?",
            (json.dumps(members, ensure_ascii=True), int(team_id)),
        )
        conn.commit()

class TeamDropdown(discord.ui.Select):
    def __init__(self, label, teams, player_id, file_path, disabled=False):
        self.teams = teams
        self.player_id = player_id
        self.file_path = file_path
        #print(teams)

        # Use the index + 1 as the team_id
        options = [
            discord.SelectOption(
                label=f"Team {i+1}",
                description=", ".join(p["name"] for p in t.values())[:100] if t else "No Pokémon",
                value=str(i)  # store index as value
            )
            for i, t in enumerate(teams)
        ]

        super().__init__(
            placeholder=label,
            options=options or [
                discord.SelectOption(label="No teams available", value="none")
            ],
            disabled=disabled or not options
        )

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.player_id:
            return await interaction.response.send_message(
                "Not your selection!",
                ephemeral=True
            )

        idx = int(self.values[0])
        team = self.teams[idx]
        guild_id = _get_battle_guild_id(self.file_path)
        team_members = list(team.values())
        
        # Check if this is a ranked battle
        data = _load_battle(self.file_path)
        rank_type = _normalize_ranked_queue_type(data.get("rank_type"))
        
        # Check for ranked common restrictions
        if rank_type == "ranked common":
            for member in team_members:
                if _is_ranked_common_banned_pokemon(member.get("name", "")):
                    return await interaction.response.send_message(
                        "❌ This team contains mega or rare Pokémon, which are not allowed in ranked common battles.",
                        ephemeral=True
                    )
        
        violations = []
        if rank_type == "ranked common":
            violations.extend(_ranked_common_team_ban_violations(team_members))
        elif rank_type == "ranked rare":
            violations = _ranked_team_ban_violations(team_members)
        else:
            violations = _duel_team_ban_violations(guild_id, team_members)
        
        if violations:
            msg = "❌ This team contains banned selections:\n" + "\n".join(violations[:5]) + "\nPlease select another team."
            return await interaction.response.send_message(msg, ephemeral=True)

        if rank_type:
            pokemon_names = [p["name"].lower() for p in team_members]
            if len(set(pokemon_names)) != len(pokemon_names):
                return await interaction.response.send_message("This team contains duplicate Pokémon.", ephemeral=True)

        TEAM_PICK_CACHE[self.player_id] = {
            "pokemon": [
                {
                    "name": p["name"].lower(),
                    "moves": p["moves"][:],
                    "nature": p.get("nature", "hardy")
                }
                for p in team.values()
            ]
        }

        embed = build_team_embed(TEAM_PICK_CACHE[self.player_id]["pokemon"])

        await interaction.response.send_message(
            embed=embed,
            view=TeamConfirmView(self.player_id, self.file_path),
            ephemeral=True
        )


async def _apply_simplified_team_to_battle(player_id: int, file_path: str, members: list):
    data = _load_battle(file_path)
    guild_id = _get_battle_guild_id(file_path)
    
    # Check if this is a ranked battle
    rank_type = _normalize_ranked_queue_type(data.get("rank_type"))
    
    # Check for ranked common restrictions
    if rank_type == "ranked common":
        for member in members:
            if _is_ranked_common_banned(member.get("name", "")):
                raise ValueError(f"{member.get('name', '')} is not allowed in ranked common battles.")
        violations = _ranked_common_team_ban_violations(members)
        if violations:
            raise ValueError("Team contains banned selections. Please choose another team.")
    elif rank_type == "ranked rare":
        violations = _ranked_team_ban_violations(members)
    else:
        violations = _duel_team_ban_violations(guild_id, members)
        for member in members:
            if member in ["gmax ainz", "best1111"]:
                raise ValueError("Team contains banned selections. Please choose another team.")
    
    if violations:
        raise ValueError("Team contains banned selections. Please choose another team.")
    
    if rank_type:
        pokemon_names = [m.get("name", "").lower() for m in members]
        if len(set(pokemon_names)) != len(pokemon_names):
            raise ValueError("Team contains duplicate Pokémon.")
    
    if data.get("mode") == TOWER_MODE_SIMPLIFIED:
        tb = data.get("tower_battle")
        if tb.get("tower_id") in [4, 5]:
            pokemon_names = [m.get("name", "").lower() for m in members]
            for pokemon_name in pokemon_names:
                if pokemon_name.title() in rares or pokemon_name.title() in mega:
                    raise ValueError("❌ This pokemon cannot enter this tower. Try common pokemons instead.")
                    break
    
    with open(file_path, "r+") as f:
        data = json.load(f)
        slot = "p1" if data["p1_id"] == player_id else "p2"
        number = int(data.get("number", 6) or 6)
        for i, m in enumerate(members[:number], start=1):
            name = str(m.get("name", "")).strip().lower()
            if not name:
                continue
            if _is_simplified_banned_pokemon(name):
                raise ValueError(f"{name} is not allowed in simplified mode.")
            nature = str(m.get("nature", "hardy")).strip().lower()
            moves = [str(x).strip() for x in (m.get("moves") or []) if str(x).strip()][:4]
            ability = str(m.get("ability", "")).strip().lower() or None
            item = str(m.get("item", "")).strip().lower() or None
            if _is_crowned_no_item_pokemon(name):
                item = None

            data[f"{slot}_p{i}"] = name
            data[f"{slot}_cosmetic{i}"] = get_equipped_pokemon_cosmetic(player_id, name)
            data[f"{slot}_nature{i}"] = nature if nature in VALID_NATURES else "hardy"
            data[f"{slot}_moves{i}"] = moves
            data[f"{slot}_ability{i}"] = ability
            data[f"{slot}_hi{i}"] = item
            data[f"{slot}_stats{i}"] = [31, 31, 31, 31, 31, 31]
            data[f"{slot}_ev{i}"] = _simplified_default_evs()
            base_stats = get_pokemon_stats(name)
            hp = math.floor(2 * base_stats[0][0] + 31 + data[f"{slot}_ev{i}"][0] // 4 + 110)
            data[f"{slot}_hp{i}"] = hp
        data[f"{slot}_order"] = [data.get(f"{slot}_p{i}") for i in range(1, number + 1)]
        f.seek(0)
        json.dump(data, f, indent=4)
        f.truncate()
    await _maybe_start_battle_after_setup(file_path)


class SimplifiedTeamDropdown(discord.ui.Select):
    def __init__(self, label, teams, player_id, file_path, parent_view=None, disabled=False):
        self.teams = teams
        self.player_id = player_id
        self.file_path = file_path
        self.parent_view = parent_view
        options = []
        for i, t in enumerate(teams):
            members = t.get("members", [])
            desc = ", ".join((m.get("name", "") or "").title() for m in members[:6])[:100] or "No Pokémon"
            options.append(
                discord.SelectOption(
                    label=f"Team {i+1}",
                    description=desc,
                    value=str(i),
                )
            )
        super().__init__(
            placeholder=label,
            options=options or [discord.SelectOption(label="No teams available", value="none")],
            disabled=disabled or not options
        )

    async def callback(self, interaction: discord.Interaction):
        # 1. Acknowledge the interaction immediately to prevent timeouts
        await interaction.response.defer(ephemeral=True)
        
        # 2. Check permissions using followups (since we deferred, response is consumed)
        if interaction.user.id != self.player_id:
            return await interaction.followup.send("Not your selection!", ephemeral=True)
            
        if self.values[0] == "none":
            return await interaction.followup.send("No team available.", ephemeral=True)
            
        idx = int(self.values[0])
        team_row = self.teams[idx]
        
        try:
            await _apply_simplified_team_to_battle(self.player_id, self.file_path, team_row.get("members", []))
        except Exception as e:
            return await interaction.followup.send(f"❌ Failed to apply team: {e}", ephemeral=True)
        
        # 3. Modify your view instance properties
        if self.parent_view:
            await self.parent_view.disable_all()

            # 4. FIXED: Use edit_original_response instead of followup.edit without an ID
            await interaction.edit_original_response(view=self.parent_view)

        # 5. Send confirmation to the interacting user
        await interaction.followup.send(
            "✅ Simplified preset team applied.",
            ephemeral=True
        )

class TeamRarityToggleButton(discord.ui.Button):
    def __init__(self, parent_view: "SelectPokemonView"):
        self.parent_view = parent_view
        super().__init__(label="Show Common Team", style=discord.ButtonStyle.secondary, row=4)

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.parent_view.player_id:
            return await interaction.response.send_message("Not your selection!", ephemeral=True)

        if self.parent_view.current_team_rarity == "rare":
            self.parent_view.current_team_rarity = "common"
            self.label = "Show Rare Team"
        else:
            self.parent_view.current_team_rarity = "rare"
            self.label = "Show Common Team"

        if getattr(self.parent_view, "enable_simplified_team_dropdowns", False):
            self.parent_view.refresh_simplified_team_dropdowns()
        else:
            self.parent_view.refresh_team_dropdowns()
        await interaction.response.edit_message(view=self.parent_view)


def _load_battle_team_file(path: str) -> dict:
    if os.path.exists(path):
        try:
            with open(path, "r") as f:
                data = json.load(f)
        except Exception:
            data = {"teams": []}
    else:
        data = {"teams": []}
    if "teams" not in data:
        data["teams"] = []
    return data


def _save_battle_team_file(path: str, data: dict):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w") as f:
        json.dump(data, f, indent=4)


def _team_summary_line(team: dict) -> str:
    names = []
    for p in team.values():
        name = str(p.get("name", "")).strip()
        if name:
            names.append(name.capitalize())
    return ", ".join(names)[:100] if names else "No Pokémon"


class BattleTeamReplaceView(discord.ui.View):
    def __init__(self, player_id: int, path: str, new_team: dict, max_teams: int = 20):
        super().__init__(timeout=180)
        self.player_id = int(player_id)
        self.path = path
        self.new_team = new_team
        self.max_teams = max_teams
        data = _load_battle_team_file(self.path)
        teams = data.get("teams", [])
        options = []
        for i, t in enumerate(teams):
            options.append(
                discord.SelectOption(
                    label=f"Team {i+1}",
                    description=_team_summary_line(t),
                    value=str(i),
                )
            )
        self.add_item(BattleTeamReplaceSelect(self, options))


class BattleTeamReplaceSelect(discord.ui.Select):
    def __init__(self, parent: "BattleTeamReplaceView", options: list):
        super().__init__(
            placeholder="Select a team to replace",
            min_values=1,
            max_values=1,
            options=options or [discord.SelectOption(label="No teams available", value="none")],
            disabled=not options
        )
        self.parent = parent

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.parent.player_id:
            return await interaction.response.send_message("Not your selection!", ephemeral=True)
        if self.values[0] == "none":
            return await interaction.response.send_message("No teams to replace.", ephemeral=True)
        idx = int(self.values[0])
        data = _load_battle_team_file(self.parent.path)
        if idx < 0 or idx >= len(data.get("teams", [])):
            return await interaction.response.send_message("Team not found.", ephemeral=True)
        data["teams"][idx] = self.parent.new_team
        _save_battle_team_file(self.parent.path, data)
        for item in self.parent.children:
            if isinstance(item, discord.ui.Select):
                item.disabled = True
        await interaction.response.edit_message(
            content="✅ Team replaced.",
            view=self.parent
        )


class SaveBattleTeamPromptView(discord.ui.View):
    def __init__(self, player_id: int, team_payload: dict):
        super().__init__(timeout=180)
        self.player_id = int(player_id)
        self.team_payload = team_payload
        self.max_teams = 25

    async def _disable_with_message(self, interaction: discord.Interaction, message: str):
        for item in self.children:
            if isinstance(item, discord.ui.Button):
                item.disabled = True
        await interaction.response.edit_message(content=message, view=self)

    async def _handle_save(self, interaction: discord.Interaction, team_type: str, rarity: str):
        if interaction.user.id != self.player_id:
            return await interaction.response.send_message("Not your selection!", ephemeral=True)
        path = _battle_team_path(self.player_id, team_type, rarity)
        data = _load_battle_team_file(path)
        if len(data.get("teams", [])) >= self.max_teams:
            replace_view = BattleTeamReplaceView(self.player_id, path, self.team_payload, self.max_teams)
            await self._disable_with_message(interaction, "Choose a team to replace from the dropdown.")
            await interaction.followup.send(
                "No empty slots. Select a team to replace:",
                view=replace_view,
                ephemeral=True
            )
            return
        data["teams"].append(self.team_payload)
        _save_battle_team_file(path, data)
        await self._disable_with_message(
            interaction,
            f"✅ Team saved to {rarity} {team_type}."
        )

    @discord.ui.button(label="Rare Prio", style=discord.ButtonStyle.success)
    async def rare_prio(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._handle_save(interaction, "prio", "rare")

    @discord.ui.button(label="Rare Non Prio", style=discord.ButtonStyle.success)
    async def rare_non_prio(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._handle_save(interaction, "non-prio", "rare")

    @discord.ui.button(label="Comm Prio", style=discord.ButtonStyle.primary)
    async def comm_prio(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._handle_save(interaction, "prio", "common")

    @discord.ui.button(label="Comm Non Prio", style=discord.ButtonStyle.primary)
    async def comm_non_prio(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._handle_save(interaction, "non-prio", "common")

    @discord.ui.button(label="No", style=discord.ButtonStyle.secondary)
    async def no_save(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.player_id:
            return await interaction.response.send_message("Not your selection!", ephemeral=True)
        await self._disable_with_message(interaction, "Okay, not saving this team.")

def build_team_embed(pokemon):
    embed = discord.Embed(title="Selected Team")

    for i, p in enumerate(pokemon, 1):
        embed.add_field(
            name=f"Pokémon {i}",
            value=(
                f"**{p['name'].capitalize()}**\n"
                f"Nature: `{p['nature']}`\n"
                f"Moves: {', '.join(p['moves'])}"
            ),
            inline=False
        )

    return embed
