async def finalize_team_from_cache(player_id, file_path):
    cache = TEAM_PICK_CACHE.get(player_id)
    if not cache:
        return ("Team not found")

    # Use locking for duo setup files to prevent concurrent modifications
    if _is_duo_setup_file_path(file_path):
        link = _duo_resolve_setup_link(file_path)
        duo_file = link["duo_file"] if link else None
        lock = _duo_lock_for(duo_file) if duo_file else None
        should_start_after = False
        if lock:
            async with lock:
                with open(file_path, "r+") as f:
                    data = json.load(f)
                    slot = "p1" if data["p1_id"] == player_id else "p2"
                    is_rng_mode = _is_p2_rng_mode(data.get("mode", ""))
                    if is_rng_mode:
                        _ensure_rng_iv_pool(data, slot)

                    for i, p in enumerate(cache["pokemon"], 1):
                        data[f"{slot}_p{i}"] = p["name"]
                        data[f"{slot}_cosmetic{i}"] = get_equipped_pokemon_cosmetic(player_id, p["name"])
                        data[f"{slot}_moves{i}"] = p["moves"]
                        data[f"{slot}_nature{i}"] = p["nature"]
                        if is_rng_mode:
                            data[f"{slot}_stats{i}"] = _rng_iv_for_index(data, slot, i) or [31] * 6
                        else:
                            data[f"{slot}_stats{i}"] = [31] * 6
                        base_stats = get_pokemon_stats(p["name"])
                        hp = math.floor(2 * base_stats[0][0] + data[f"{slot}_stats{i}"][0] + 5 + 110)
                        data[f"{slot}_hp{i}"] = hp

                    data[f"{slot}_order"] = [data[f"{slot}_p{i}"] for i in range(1, 4)]

                    f.seek(0)
                    json.dump(data, f, indent=4)
                    f.truncate()

                del TEAM_PICK_CACHE[player_id]
                should_start_after = True

        if should_start_after:
            await _maybe_start_battle_after_setup(file_path)
            return ("Battle started")
    else:
        with open(file_path, "r+") as f:
            data = json.load(f)
            slot = "p1" if data["p1_id"] == player_id else "p2"

            if _normalize_ranked_queue_type(data.get("mode", "")) is not None:
                team_names = [p["name"].lower() for p in cache["pokemon"]]

                duplicates = {
                    name for name in team_names
                    if team_names.count(name) > 1
                }

                if duplicates:
                    return (
                        "❌ Ranked battles do not allow duplicate Pokémon.\n"
                        f"Duplicates found: {', '.join(sorted(duplicates))}"
                    )
            is_rng_mode = _is_p2_rng_mode(data.get("mode", ""))
            if is_rng_mode:
                _ensure_rng_iv_pool(data, slot)

            for i, p in enumerate(cache["pokemon"], 1):
                data[f"{slot}_p{i}"] = p["name"]
                data[f"{slot}_cosmetic{i}"] = get_equipped_pokemon_cosmetic(player_id, p["name"])
                data[f"{slot}_moves{i}"] = p["moves"]
                data[f"{slot}_nature{i}"] = p["nature"]
                if is_rng_mode:
                    data[f"{slot}_stats{i}"] = _rng_iv_for_index(data, slot, i) or [31] * 6
                else:
                    data[f"{slot}_stats{i}"] = [31] * 6
                base_stats = get_pokemon_stats(p["name"])
                hp = math.floor(2 * base_stats[0][0] + data[f"{slot}_stats{i}"][0] + 5 + 110)
                data[f"{slot}_hp{i}"] = hp

            data[f"{slot}_order"] = [data[f"{slot}_p{i}"] for i in range(1, 4)]

            f.seek(0)
            json.dump(data, f, indent=4)
            f.truncate()

        del TEAM_PICK_CACHE[player_id]
        # Duo setup files rely on _maybe_start_battle_after_setup to import the
        # temporary p1_* picks into the main duo battle file.
        if _is_duo_setup_file_path(file_path):
            await _maybe_start_battle_after_setup(file_path)
            return ("Battle started")

    if _is_pve_mode(data.get("mode", "")):
        if check_ready_pve(file_path):
            try:
                if str(data.get("mode", "")).strip().lower() != PVE_MODE_RAID:
                    add_pve_pokemon(file_path, data.get("rarity", "rare"))
                await _send_battle_status_with_retry(file_path)
                round_id = _bump_round_id(file_path)
                counter = 0
                view1 = BattleMoveSelectView(data["p1_id"], file_path, counter, round_id=round_id)
                player = bot.get_user(data["p1_id"])
                await send_battle_move_view(player, view1, "Battle ready! Select a move:")
            except Exception as e:
                traceback.print_exc()
    else:
        # Normal PvP ready check
        if check_ready(file_path):
            asyncio.create_task(_send_battle_views_with_retry(data, file_path))
    return True
async def _send_battle_views_with_retry(data, file_path, max_retries=5, p1_dmg = None, p2_dmg = None):
    for attempt in range(1, max_retries + 1):
        try:
            await send_battle_status(file_path, p1_dmg, p2_dmg)

            round_id = _bump_round_id(file_path)
            counter = 0

            view1 = BattleMoveSelectView(data["p1_id"], file_path, counter, round_id=round_id)
            if data["p1_id"] == data["p2_id"]:
                counter = 1
            view2 = BattleMoveSelectView(data["p2_id"], file_path, counter, round_id=round_id)

            p1 = bot.get_user(data["p1_id"])
            p2 = bot.get_user(data["p2_id"])

            await send_battle_move_view(p1, view1, "Select a move for player 1")
            await send_battle_move_view(p2, view2, "Select a move for player 2")

            return  # ✅ success → stop retrying

        except Exception as e:
            print(f"[Retry {attempt}/{max_retries}] Failed to send battle views:", e)
            traceback.print_exc()

            if attempt >= max_retries:
                print("❌ Max retries reached. Giving up.")
                return

            await asyncio.sleep(2 * attempt)  # simple backoff

async def _send_battle_status_with_retry(file_path, max_retries=5, p1_dmg=None, p2_dmg=None):
    for attempt in range(1, max_retries + 1):
        try:
            await send_battle_status(file_path, p1_dmg, p2_dmg)
            return
        except Exception as e:
            print(f"[Retry {attempt}/{max_retries}] Failed to send battle views:", e)
            traceback.print_exc()

            if attempt >= max_retries:
                print("❌ Max retries reached. Giving up.")
                return

            await asyncio.sleep(2 * attempt)  # simple backoff
class MintModal(discord.ui.Modal, title="Modify Pokémon Mint"):
    mint_input = discord.ui.TextInput(
        label="New Mint",
        placeholder="e.g. timid",
        required=True,
        max_length=20
    )

    def __init__(self, player_id, index):
        super().__init__()
        self.player_id = player_id
        self.index = index  # which Pokémon in the cached team

    async def on_submit(self, interaction: discord.Interaction):
        new_mint = self.mint_input.value.strip().lower()
        if new_mint not in VALID_NATURES:
            return await interaction.response.send_message(
                f"❌ Invalid mint. Must be one of: {', '.join(VALID_NATURES)}",
                ephemeral=True
            )

        # Update cached team
        try:
            TEAM_PICK_CACHE[self.player_id]["pokemon"][self.index]["nature"] = new_mint
        except Exception:
            return await interaction.response.send_message(
                "❌ Could not update mint (cache missing).",
                ephemeral=True
            )

        # Rebuild the embed
        updated_team = TEAM_PICK_CACHE[self.player_id]["pokemon"]
        embed = build_team_embed(updated_team)

        # Edit the original message with the updated embed
        try:
            await interaction.response.edit_message(embed=embed)
        except discord.errors.InteractionResponded:
            # fallback: send ephemeral if the original was already responded
            await interaction.followup.send("✅ Mint updated.", ephemeral=True)

TEAM_PICK_CACHE = {}
PENDING_POKEMON_SELECTIONS = {}
QUICK_ADD_SESSIONS = {}
QUICK_ADD_TTL_SECONDS = 180
SAVE_TEAM_PROMPTED = set()
ACTIVE_BATTLE_SELECTIONS = {}
ACTIVE_BATTLE_ROUND_EXECUTIONS = set()
ACTIVE_BATTLE_WINNER_ANNOUNCEMENTS = {}
BASE_BATTLE_TIMER_SECONDS = 180
BATTLE_SELECTION_INCREMENT_SECONDS = 30
NPC_BATTLE_TIMER_SECONDS = 100000
FAKE_BASE_BATTLE_TIMER_SECONDS = 360
FAKE_BATTLE_SELECTION_INCREMENT_SECONDS = 30

def _battle_base_timer_seconds(data: dict) -> int:
    if bool((data or {}).get("fake")):
        return FAKE_BASE_BATTLE_TIMER_SECONDS
    return BASE_BATTLE_TIMER_SECONDS

def _battle_selection_increment_seconds(data: dict) -> int:
    if bool((data or {}).get("fake")):
        return FAKE_BATTLE_SELECTION_INCREMENT_SECONDS
    return BATTLE_SELECTION_INCREMENT_SECONDS

def _pending_key(player_id: int, file_path: str) -> str:
    return f"{int(player_id)}:{str(file_path)}"

def _get_pending_selection(player_id: int, file_path: str):
    return PENDING_POKEMON_SELECTIONS.get(_pending_key(player_id, file_path))

def _set_pending_selection(player_id: int, file_path: str, pending: dict):
    PENDING_POKEMON_SELECTIONS[_pending_key(player_id, file_path)] = pending

def _clear_pending_selection(player_id: int, file_path: str):
    PENDING_POKEMON_SELECTIONS.pop(_pending_key(player_id, file_path), None)

def _is_quick_add_active(player_id: int) -> bool:
    session = QUICK_ADD_SESSIONS.get(int(player_id))
    if not session:
        return False
    started_at = float(session.get("started_at", 0))
    if time.time() - started_at > QUICK_ADD_TTL_SECONDS:
        QUICK_ADD_SESSIONS.pop(int(player_id), None)
        return False
    return True

def _start_quick_add_session(player_id: int, file_path: str):
    QUICK_ADD_SESSIONS[int(player_id)] = {
        "file_path": str(file_path),
        "started_at": time.time(),
    }

def _clear_quick_add_session(player_id: int):
    QUICK_ADD_SESSIONS.pop(int(player_id), None)


def _battle_selection_key(file_path: str, round_id: int | None, player_id: int, counter: int) -> str:
    rid = int(round_id or 0)
    return f"{str(file_path)}:{rid}:{int(player_id)}:{int(counter)}"


def _is_selection_alive(file_path: str, round_id: int | None, player_id: int, counter: int) -> bool:
    return _battle_selection_key(file_path, round_id, player_id, counter) in ACTIVE_BATTLE_SELECTIONS


def _register_selection_alive(file_path: str, round_id: int | None, player_id: int, counter: int, message_id: int | None):
    key = _battle_selection_key(file_path, round_id, player_id, counter)
    ACTIVE_BATTLE_SELECTIONS[key] = {
        "created_at": time.time(),
        "message_id": int(message_id) if message_id else None,
    }


def _clear_selection_alive(file_path: str, round_id: int | None, player_id: int, counter: int):
    ACTIVE_BATTLE_SELECTIONS.pop(_battle_selection_key(file_path, round_id, player_id, counter), None)


def _clear_selection_alive_for_battle(file_path: str):
    prefix = f"{str(file_path)}:"
    stale = [k for k in ACTIVE_BATTLE_SELECTIONS.keys() if k.startswith(prefix)]
    for k in stale:
        ACTIVE_BATTLE_SELECTIONS.pop(k, None)


def _battle_round_execution_key(file_path: str, data: dict | None = None) -> str:
    if data is None:
        data = _load_battle(file_path)
    round_id = int(data.get("round_id", 0) or 0)
    return f"{str(file_path)}::{round_id}"


def _claim_battle_round_execution(file_path: str, data: dict | None = None) -> str | None:
    if data is None:
        data = _load_battle(file_path)
    if not data.get("p1_choice") or not data.get("p2_choice"):
        return None
    key = _battle_round_execution_key(file_path, data)
    if key in ACTIVE_BATTLE_ROUND_EXECUTIONS:
        return None
    ACTIVE_BATTLE_ROUND_EXECUTIONS.add(key)
    return key


def _release_battle_round_execution(key: str | None):
    if not key:
        return
    ACTIVE_BATTLE_ROUND_EXECUTIONS.discard(key)


async def _dispatch_battle_round_if_ready(file_path: str, data: dict | None = None) -> bool:
    try:
        key = _claim_battle_round_execution(file_path, data=data)
    except Exception:
        return False
    if not key:
        return False
    try:
        if data is None:
            data = _load_battle(file_path)
        if not _is_standard_like_mode(data.get("mode")):
            await battle_round(file_path)
        else:
            await battle_round_st(file_path)
        return True
    finally:
        _release_battle_round_execution(key)


def _ensure_battle_timers_initialized(data: dict):
    now_ts = int(time.time())
    p2_is_npc = _safe_int_user_id(data.get("p2_id")) is None
    default_player_seconds = _battle_base_timer_seconds(data)
    for slot in ("p1", "p2"):
        legacy_ts_key = f"{slot}_timestart"
        legacy_te_key = f"{slot}_timeend"
        left_key = f"{slot}_time_left"
        tick_key = f"{slot}_clock_started_at"
        default_seconds = NPC_BATTLE_TIMER_SECONDS if (slot == "p2" and p2_is_npc) else default_player_seconds
        legacy_ts = data.get(legacy_ts_key)
        legacy_te = data.get(legacy_te_key)

        if data.get(left_key) is None:
            left_seconds = default_seconds
            try:
                if legacy_te is not None:
                    if legacy_ts is not None:
                        left_seconds = int(legacy_te) - int(legacy_ts)
                    else:
                        left_seconds = int(legacy_te) - now_ts
            except Exception:
                left_seconds = default_seconds
            data[left_key] = max(1, int(left_seconds))

        if data.get(tick_key) is None:
            data[tick_key] = None

        try:
            left_seconds = max(1, int(data.get(left_key, default_seconds)))
        except Exception:
            left_seconds = default_seconds
        data[legacy_ts_key] = now_ts
        data[legacy_te_key] = now_ts + left_seconds


def _refresh_player_time_left(data: dict, slot: str) -> int:
    _ensure_battle_timers_initialized(data)
    now_ts = int(time.time())
    left_key = f"{slot}_time_left"
    tick_key = f"{slot}_clock_started_at"
    legacy_ts_key = f"{slot}_timestart"
    legacy_te_key = f"{slot}_timeend"
    try:
        left_seconds = int(data.get(left_key, 1) or 1)
    except Exception:
        left_seconds = 1
    started_at = data.get(tick_key)
    if started_at is not None:
        try:
            elapsed = max(0, now_ts - int(started_at))
        except Exception:
            elapsed = 0
        left_seconds = max(0, left_seconds - elapsed)
        data[left_key] = left_seconds
        data[tick_key] = now_ts
    else:
        data[left_key] = max(0, left_seconds)
    data[legacy_ts_key] = now_ts
    data[legacy_te_key] = now_ts + int(data.get(left_key, 0) or 0)
    return int(data.get(left_key, 0) or 0)


def _selection_timeout_seconds(data: dict, slot: str) -> int:
    if slot == "p2" and _safe_int_user_id(data.get("p2_id")) is None:
        return NPC_BATTLE_TIMER_SECONDS
    left_seconds = _refresh_player_time_left(data, slot)
    return max(1, int(left_seconds))


def _begin_player_selection_timer(data: dict, slot: str) -> int:
    if slot == "p2" and _safe_int_user_id(data.get("p2_id")) is None:
        now_ts = int(time.time())
        data["p2_clock_started_at"] = now_ts
        data["p2_time_left"] = NPC_BATTLE_TIMER_SECONDS
        data["p2_timestart"] = now_ts
        data["p2_timeend"] = now_ts + NPC_BATTLE_TIMER_SECONDS
        return NPC_BATTLE_TIMER_SECONDS
    _ensure_battle_timers_initialized(data)
    now_ts = int(time.time())
    left_key = f"{slot}_time_left"
    tick_key = f"{slot}_clock_started_at"

    left_seconds = _refresh_player_time_left(data, slot)
    if left_seconds <= 0:
        left_seconds = 1
        data[left_key] = left_seconds
    data[tick_key] = now_ts
    data[f"{slot}_timestart"] = now_ts
    data[f"{slot}_timeend"] = now_ts + left_seconds
    return max(1, int(left_seconds))


def _finalize_player_selection_timer(data: dict, slot: str, increment: int = 0):
    _ensure_battle_timers_initialized(data)
    now_ts = int(time.time())
    left_key = f"{slot}_time_left"
    tick_key = f"{slot}_clock_started_at"
    left_seconds = _refresh_player_time_left(data, slot)
    left_seconds = max(0, int(left_seconds) + int(increment or 0))
    data[left_key] = left_seconds
    data[tick_key] = None
    data[f"{slot}_timestart"] = now_ts
    data[f"{slot}_timeend"] = now_ts + left_seconds


def _extend_player_timeend(data: dict, slot: str, increment: int = None):
    if increment is None:
        increment = _battle_selection_increment_seconds(data)
    _finalize_player_selection_timer(data, slot, increment=int(increment))


def _stop_player_selection_timer(data: dict, slot: str):
    _finalize_player_selection_timer(data, slot, increment=0)

def _legacy_selection_time_remaining(data: dict, slot: str) -> int:
    now_ts = int(time.time())
    try:
        end_ts = int(data.get(f"{slot}_timeend", now_ts) or now_ts)
    except Exception:
        end_ts = now_ts
    return max(0, end_ts - now_ts)

def _prepare_pending_selection(player_id: int, file_path: str, pokemon_name: str, source: str):
    try:
        with open(file_path, "r") as f:
            data = json.load(f)
    except Exception:
        return None, "Could not open battle data."

    slot = "p1" if data.get("p1_id") == player_id else "p2"
    number = int(data.get("number", 3) or 3)
    if data.get("p1_id") == data.get("p2_id"):
        filled = sum(1 for i in range(1, 7) if data.get(f"p1_moves{i}"))
        if filled >= number:
            slot = "p2"

    assigned_index = None
    for i in range(1, number + 1):
        if not data.get(f"{slot}_p{i}"):
            assigned_index = i
            break

    if assigned_index is None:
        return None, "No empty slots available for this battle."

    pending = {
        "player_id": int(player_id),
        "file_path": str(file_path),
        "pokemon_name": str(pokemon_name or "").strip().lower(),
        "slot": slot,
        "assigned_index": int(assigned_index),
        "moves": None,
        "ability": None,
        "item": None,
        "item_selected": False,
        "nature": None,
        "ivs": None,
        "evs": None,
        "source": str(source or ""),
        "created_at": time.time(),
    }
    _set_pending_selection(player_id, file_path, pending)
    return pending, None

def _commit_pending_selection(player_id: int, file_path: str):
    pending = _get_pending_selection(player_id, file_path)
    if not pending:
        return False, "No pending selection found. Please start again."

    guild_id = _get_battle_guild_id(file_path)
    pokemon_name = pending.get("pokemon_name", "")
    if _is_pokemon_banned_for_battle(file_path, guild_id, pokemon_name):
        return False, "❌ This Pokémon is banned for this battle. Please choose another."
    for mv in pending.get("moves") or []:
        if not mv or str(mv).strip().lower() == "auto":
            continue
        if _is_move_banned_for_battle(file_path, guild_id, mv) or _is_specific_banned_for_battle(file_path, guild_id, pokemon_name, mv):
            return False, "❌ This Pokémon has banned moves for this battle. Please choose different moves."

    try:
        with open(file_path, "r+") as f:
            data = json.load(f)
            mode = str(data.get("mode", "")).strip().lower()
            slot = "p1" if data.get("p1_id") == player_id else "p2"
            if data.get("p1_id") == data.get("p2_id"):
                slot = pending.get("slot") or slot
            number = int(data.get("number", 3) or 3)

            if not pending.get("moves"):
                return False, "Moves not selected yet."
            if _is_simplified_mode(mode) and not pending.get("ability"):
                return False, "Ability not selected yet."
            if "p2" not in mode and not _is_simplified_mode(mode) and not pending.get("ability"):
                return False, "Ability not selected yet."
            if _is_simplified_mode(mode) and not pending.get("item_selected"):
                return False, "Item not selected yet."
            if _is_standard_like_mode(mode) and not pending.get("evs"):
                return False, "EVs not selected yet."

            target_index = pending.get("assigned_index")
            if not target_index or not (1 <= int(target_index) <= int(number)) or data.get(f"{slot}_p{target_index}"):
                target_index = None
                for i in range(1, number + 1):
                    if not data.get(f"{slot}_p{i}"):
                        target_index = i
                        break
            if target_index is None:
                return False, "No empty slots available for this battle."

            is_rng_mode = _is_p2_rng_mode(mode)
            if is_rng_mode:
                _ensure_rng_iv_pool(data, slot)

            pokemon_name = pending.get("pokemon_name")
            moves = pending.get("moves") or []
            ability = pending.get("ability")
            item = pending.get("item")
            nature = pending.get("nature") or "hardy"
            evs = pending.get("evs")
            if _is_simplified_mode(mode):
                if not evs:
                    evs = _simplified_default_evs()
            elif _is_standard_like_mode(mode):
                if not evs:
                    evs = [0, 0, 0, 0, 0, 0]

            iv_list = pending.get("ivs") or [31, 31, 31, 31, 31, 31]
            if is_rng_mode:
                iv_list = _rng_iv_for_index(data, slot, target_index) or iv_list

            if _is_crowned_no_item_pokemon(pokemon_name):
                item = None

            data[f"{slot}_p{target_index}"] = pokemon_name
            data[f"{slot}_cosmetic{target_index}"] = get_equipped_pokemon_cosmetic(player_id, pokemon_name)
            data[f"{slot}_moves{target_index}"] = moves
            data[f"{slot}_nature{target_index}"] = nature
            data[f"{slot}_stats{target_index}"] = iv_list
            if ability is not None:
                data[f"{slot}_ability{target_index}"] = ability
            if pending.get("item_selected") or (item is not None):
                data[f"{slot}_hi{target_index}"] = item
            if evs is not None:
                data[f"{slot}_ev{target_index}"] = evs

            base_stats = get_pokemon_stats(pokemon_name)
            if _is_simplified_mode(mode) or _is_standard_like_mode(mode):
                hp = math.floor(2 * base_stats[0][0] + iv_list[0] + evs[0] // 4 + 110)
            else:
                hp = math.floor(2 * base_stats[0][0] + iv_list[0] + 5 + 110)
            data[f"{slot}_hp{target_index}"] = hp

            data["p1_order"] = [data.get(f"p1_p{i}") for i in range(1, number + 1)]
            data["p2_order"] = [data.get(f"p2_p{i}") for i in range(1, number + 1)]

            f.seek(0)
            json.dump(data, f, indent=4)
            f.truncate()
    except Exception:
        traceback.print_exc()
        return False, "Failed to save battle data."

    _clear_pending_selection(player_id, file_path)
    if pending.get("source") == "quick_add":
        _clear_quick_add_session(player_id)
    # Duo setup imports must not rely on per-callback follow-up code paths.
    # Trigger import immediately after successful commit so duel_duo is updated
    # even if a caller forgets to invoke _maybe_start_battle_after_setup.
    if _is_duo_setup_file_path(file_path):
        try:
            loop = asyncio.get_running_loop()
            loop.create_task(_duo_import_setup_team(file_path))
        except Exception:
            traceback.print_exc()
    return True, None


def _save_team_prompt_key(player_id: int, file_path: str, slot: str) -> str:
    return f"{int(player_id)}:{str(file_path)}:{str(slot)}"


def _battle_team_path(user_id: int, team_type: str, rarity: str) -> str:
    team_type = str(team_type or "").strip().lower()
    rarity = str(rarity or "").strip().lower()
    suffix = "_common" if rarity == "common" else ""
    return f"battle_teams/{int(user_id)}_{team_type}{suffix}.json"


def _extract_battle_team_payload(data: dict, slot: str, number: int = 3) -> dict:
    team = {}
    for i in range(1, int(number) + 1):
        name = str(data.get(f"{slot}_p{i}") or "").strip().lower()
        if not name:
            continue
        entry = {
            "name": name,
            "nature": str(data.get(f"{slot}_nature{i}") or "hardy").strip().lower(),
            "moves": [str(m).strip() for m in (data.get(f"{slot}_moves{i}") or []) if str(m).strip()],
        }
        ivs = data.get(f"{slot}_stats{i}")
        if ivs is not None:
            entry["ivs"] = ivs
        ability = data.get(f"{slot}_ability{i}")
        if ability is not None:
            entry["ability"] = ability
        item = data.get(f"{slot}_hi{i}")
        if item is not None:
            entry["item"] = item
        evs = data.get(f"{slot}_ev{i}")
        if evs is not None:
            entry["evs"] = evs
        cosmetic = data.get(f"{slot}_cosmetic{i}")
        if cosmetic:
            entry["cosmetic"] = cosmetic
        team[f"p{i}"] = entry
    return team


async def _maybe_prompt_save_battle_team(player_id: int, file_path: str, slot: str, source: str):
    if str(source or "").strip().lower() not in {"quick_add", "select_pokemon"}:
        return
    try:
        data = _load_battle(file_path)
    except Exception:
        return
    mode = str(data.get("mode", "")).strip().lower()
    if mode not in {"p2", PVP_MODE_RNG}:
        return
    number = int(data.get("number", 3) or 3)
    if number != 3:
        return
    if not slot:
        slot = "p1" if int(data.get("p1_id", 0) or 0) == int(player_id) else "p2"
    if not all(data.get(f"{slot}_p{i}") for i in range(1, number + 1)):
        return
    prompt_key = _save_team_prompt_key(player_id, file_path, slot)
    if prompt_key in SAVE_TEAM_PROMPTED:
        return
    team_payload = _extract_battle_team_payload(data, slot, number)
    if len(team_payload) < 3:
        return
    user = await _get_user_cached_or_fetch(player_id)
    if user is None:
        return
    view = SaveBattleTeamPromptView(player_id, team_payload)
    content = "You just completed a full 3 Pokémon team. Add it to your battle teams?"
    try:
        await user.send(content, view=view)
        SAVE_TEAM_PROMPTED.add(prompt_key)
    except Exception:
        return


class RngMaxIvApprovalView(discord.ui.View):
    def __init__(self, file_path: str, requester_id: int, approver_id: int):
        super().__init__(timeout=120)
        self.file_path = file_path
        self.requester_id = int(requester_id)
        self.approver_id = int(approver_id)

    async def _disable_and_edit(self, interaction: discord.Interaction, content: str):
        for item in self.children:
            if isinstance(item, discord.ui.Button):
                item.disabled = True
        await interaction.response.edit_message(content=content, view=self)

    @discord.ui.button(label="Agree", style=discord.ButtonStyle.success)
    async def agree(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.approver_id:
            return await interaction.response.send_message("Only the requested opponent can respond.", ephemeral=True)

        try:
            with open(self.file_path, "r+", encoding="utf-8") as f:
                data = json.load(f)
                if not _is_p2_rng_mode(data.get("mode", "")):
                    return await self._disable_and_edit(interaction, "This battle is no longer in p2 rng mode.")

                changed = _randomize_all_rng_ivs(data)
                if changed:
                    f.seek(0)
                    json.dump(data, f, indent=4)
                    f.truncate()
        except Exception:
            return await self._disable_and_edit(interaction, "Failed to update IVs. The battle file may be unavailable.")

        await self._disable_and_edit(interaction, "✅ Approved. All RNG IVs were randomized.")
        requester = interaction.client.get_user(self.requester_id)
        if requester is None:
            try:
                requester = await interaction.client.fetch_user(self.requester_id)
            except Exception:
                requester = None
        if requester is not None:
            try:
                await requester.send(f"{interaction.user.display_name} approved your request. All RNG IVs were randomized.")
            except Exception:
                pass
        try:
            p1_id = int(data.get("p1_id", 0) or 0)
            approver_slot = "p1" if self.approver_id == p1_id else "p2"
            requester_slot = "p1" if self.requester_id == p1_id else "p2"
            approver_embed = _build_rng_iv_embed(data, approver_slot)
            if approver_embed:
                await interaction.followup.send(embed=approver_embed, ephemeral=True)
            if requester is not None:
                requester_embed = _build_rng_iv_embed(data, requester_slot)
                if requester_embed:
                    await requester.send(embed=requester_embed)
        except Exception:
            pass

    @discord.ui.button(label="Decline", style=discord.ButtonStyle.danger)
    async def decline(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.approver_id:
            return await interaction.response.send_message("Only the requested opponent can respond.", ephemeral=True)

        await self._disable_and_edit(interaction, "❌ Declined. RNG IVs were not randomized.")
        requester = interaction.client.get_user(self.requester_id)
        if requester is None:
            try:
                requester = await interaction.client.fetch_user(self.requester_id)
            except Exception:
                requester = None
        if requester is not None:
            try:
                await requester.send(f"{interaction.user.display_name} declined your randomize IV request.")
            except Exception:
                pass


class ChangeToMaxIvButton(discord.ui.Button):
    def __init__(self, file_path: str, player_id: int):
        super().__init__(label="Randomize IVs", style=discord.ButtonStyle.secondary, row=4)
        self.file_path = file_path
        self.player_id = int(player_id)

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.player_id:
            return await interaction.response.send_message("Not your selection!", ephemeral=True)

        try:
            with open(self.file_path, "r", encoding="utf-8") as f:
                data = json.load(f)
        except Exception:
            return await interaction.response.send_message("Could not open battle data.", ephemeral=True)

        if not _is_p2_rng_mode(data.get("mode", "")):
            return await interaction.response.send_message("This is not a p2 rng battle.", ephemeral=True)

        p1_id = int(data.get("p1_id", 0) or 0)
        p2_id = int(data.get("p2_id", 0) or 0)
        if interaction.user.id not in {p1_id, p2_id}:
            return await interaction.response.send_message("You are not part of this battle.", ephemeral=True)

        opponent_id = p2_id if interaction.user.id == p1_id else p1_id

        # Single-player battle flow: apply instantly.
        if opponent_id == interaction.user.id:
            try:
                with open(self.file_path, "r+", encoding="utf-8") as f:
                    data = json.load(f)
                    if _randomize_all_rng_ivs(data):
                        f.seek(0)
                        json.dump(data, f, indent=4)
                        f.truncate()
            except Exception:
                return await interaction.response.send_message("Failed to update IVs.", ephemeral=True)
            embed = _build_rng_iv_embed(data, "p1")
            return await interaction.response.send_message(
                "✅ All RNG IVs were randomized.",
                embed=embed,
                ephemeral=True
            )

        opponent = interaction.client.get_user(opponent_id)
        if opponent is None:
            try:
                opponent = await interaction.client.fetch_user(opponent_id)
            except Exception:
                opponent = None
        if opponent is None:
            return await interaction.response.send_message("Could not find your opponent.", ephemeral=True)

        approval_view = RngMaxIvApprovalView(self.file_path, interaction.user.id, opponent_id)
        try:
            await opponent.send(
                f"{interaction.user.display_name} requested to randomize all RNG IVs for this p2 rng battle. Do you agree?",
                view=approval_view,
            )
        except Exception:
            return await interaction.response.send_message("I couldn't DM your opponent for approval.", ephemeral=True)

        await interaction.response.send_message("Request sent. Waiting for opponent approval.", ephemeral=True)

# ---- Simplified selection panel (premade + team) ----
async def _simplified_premade_add(interaction: discord.Interaction, player_id: int, file_path: str):
    if interaction.user.id != player_id:
        return await interaction.response.send_message("Not your selection!", ephemeral=True)

    await interaction.response.defer(ephemeral=True)
    await interaction.followup.send(
        "Please type your mint with Pokémon name separate by comma only (e.g. `timid,abomasnow`).",
        ephemeral=True
    )

    def check(msg: discord.Message):
        return msg.author.id == player_id and msg.channel == interaction.channel

    try:
        msg = await interaction.client.wait_for("message", check=check, timeout=30)
    except Exception:
        return await interaction.followup.send("Timeout or error. Try again.", ephemeral=True)

    parts = msg.content.lower().split(",")
    if len(parts) != 2:
        return await interaction.followup.send("❌ Please use the format `nature,pokemon`.", ephemeral=True)
    nature, pokemon_name = parts[0].strip(), parts[1].strip()
    if nature not in VALID_NATURES:
        return await interaction.followup.send("❌ Invalid mint.", ephemeral=True)
    if pokemon_name in ["gmax ainz", "best1111"]:
        return await interaction.followup.send("❌ Invalid Pokemon.", ephemeral=True)
    if not get_pokemon_info(pokemon_name):
        return await interaction.followup.send("Invalid Pokémon. Try again.", ephemeral=True)

    with open(file_path, "r") as f:
        quick_mode_data = json.load(f)
    if not _is_simplified_mode(quick_mode_data.get("mode")):
        return await interaction.followup.send("This panel is only for simplified mode.", ephemeral=True)
    if _is_simplified_banned_pokemon(pokemon_name):
        return await interaction.followup.send(
            "❌ Mega and primal Pokémon are not allowed in simplified mode.",
            ephemeral=True
        )
    if quick_mode_data.get("mode") == TOWER_MODE_SIMPLIFIED:
        tb = quick_mode_data.get("tower_battle")
        if tb.get("tower_id") in [4, 5]:
            if pokemon_name.title() in rares or pokemon_name.title() in mega:
                return await interaction.followup.send(
                    "❌ This pokemon cannot enter this tower. Try common pokemons instead.",
                    ephemeral=True
                )

    premade = load_premake(player_id, pokemon_name)
    if not premade:
        return await interaction.followup.send(
            "No premade found for this pokemon. Use `!premake <pokemon>` first.",
            ephemeral=True
        )
    selected_moves = [str(m).strip().lower() for m in (premade.get("moves") or []) if str(m).strip()]
    if len(selected_moves) < 4:
        return await interaction.followup.send(
            "Premade data is missing moves. Please run `!premake <pokemon>` again.",
            ephemeral=True
        )
    selected_moves = selected_moves[:4]
    selected_ability = str(premade.get("ability") or "ball fetch").strip().lower()
    selected_item = str(premade.get("item") or "").strip().lower() or None
    if _is_crowned_no_item_pokemon(pokemon_name):
        selected_item = None

    # Assign Pokémon to first open slot.
    with open(file_path, "r+") as f:
        data = json.load(f)
        slot = "p1" if data["p1_id"] == player_id else "p2"
        is_rng_mode = _is_p2_rng_mode(data.get("mode", ""))
        if is_rng_mode:
            _ensure_rng_iv_pool(data, slot)
        number = int(data.get("number", 3) or 3)
        if data["p1_id"] == data["p2_id"]:
            filled = sum(1 for i in range(1, 7) if data.get(f"p1_moves{i}"))
            if filled >= number:
                slot = "p2"
        assigned_index = None
        for i in range(1, number + 1):
            key = f"{slot}_p{i}"
            if not data.get(key):
                data[key] = pokemon_name
                data[f"{slot}_cosmetic{i}"] = get_equipped_pokemon_cosmetic(player_id, pokemon_name)
                assigned_index = i
                break
        if assigned_index is None:
            return await interaction.followup.send("No empty slots available for this battle.", ephemeral=True)
        f.seek(0)
        json.dump(data, f, indent=4)
        f.truncate()

    with open(file_path, "r+") as f:
        data = json.load(f)
        slot = "p1" if data["p1_id"] == player_id else "p2"
        is_rng_mode = _is_p2_rng_mode(data.get("mode", ""))
        if is_rng_mode:
            _ensure_rng_iv_pool(data, slot)
        number = int(data.get("number", 3) or 3)
        if data["p1_id"] == data["p2_id"]:
            filled = sum(1 for i in range(1, 7) if data.get(f"p1_moves{i}"))
            if filled >= number:
                slot = "p2"
        if assigned_index and 1 <= int(assigned_index) <= int(number):
            data[f"{slot}_moves{int(assigned_index)}"] = selected_moves
            data[f"{slot}_ability{int(assigned_index)}"] = selected_ability
            data[f"{slot}_hi{int(assigned_index)}"] = selected_item
        else:
            for i in range(1, number + 1):
                key = f"{slot}_moves{i}"
                if not data.get(key):
                    data[key] = selected_moves
                    break
            for i in range(1, number + 1):
                key = f"{slot}_ability{i}"
                if not data.get(key):
                    data[key] = selected_ability
                    break
            for i in range(1, number + 1):
                key = f"{slot}_hi{i}"
                if not data.get(key):
                    data[key] = selected_item
                    break

        if is_rng_mode:
            iv_list = _rng_iv_for_index(data, slot, assigned_index or 1) or [31, 31, 31, 31, 31, 31]
        else:
            iv_list = [31, 31, 31, 31, 31, 31]

        if data["p1_id"] == data["p2_id"]:
            filled = sum(1 for i in range(1, 7) if data.get(f"p1_nature{i}"))
            if filled >= number:
                slot = "p2"
        if assigned_index and 1 <= int(assigned_index) <= int(number):
            data[f"{slot}_stats{int(assigned_index)}"] = iv_list
            data[f"{slot}_nature{int(assigned_index)}"] = nature
            data[f"{slot}_ev{int(assigned_index)}"] = _simplified_default_evs()
        else:
            for i in range(1, number + 1):
                key = f"{slot}_stats{i}"
                if not data.get(key):
                    data[key] = iv_list
                    break
            for i in range(1, number + 1):
                key = f"{slot}_nature{i}"
                if not data.get(key):
                    data[key] = nature
                    break
            for i in range(1, number + 1):
                key = f"{slot}_ev{i}"
                if not data.get(key):
                    data[key] = _simplified_default_evs()
                    break

        try:
            data["p1_order"] = [data[f"p1_p{i}"] for i in range(1, number + 1)]
            data["p2_order"] = [data[f"p2_p{i}"] for i in range(1, number + 1)]
        except Exception:
            pass

        base_stats = get_pokemon_stats(pokemon_name)
        hp = math.floor(2 * base_stats[0][0] + iv_list[0] + 20 // 4 + 110)
        poke_index = assigned_index if assigned_index and 1 <= int(assigned_index) <= int(number) else 1
        data[f"{slot}_hp{poke_index}"] = hp
        f.seek(0)
        json.dump(data, f, indent=4)
        f.truncate()

    await interaction.followup.send("✅ Premade Pokémon added.", ephemeral=True)
    await _maybe_start_battle_after_setup(file_path)


class SimplifiedPremadeAddButton(discord.ui.Button):
    def __init__(self, player_id: int, file_path: str):
        super().__init__(label="Add Premade Pokemon", style=discord.ButtonStyle.primary, row=1)
        self.player_id = int(player_id)
        self.file_path = file_path

    async def callback(self, interaction: discord.Interaction):
        await _simplified_premade_add(interaction, self.player_id, self.file_path)


class SimplifiedBattleTeamSelectView(discord.ui.View):
    def __init__(self, player_id: int, file_path: str):
        super().__init__(timeout=300)
        self.player_id = int(player_id)
        self.file_path = file_path
        rarity = "rare"
        try:
            with open(self.file_path, "r") as f:
                data = json.load(f)
            if str(data.get("rarity", "")).lower() in {"rare", "common"}:
                rarity = str(data.get("rarity")).lower()
        except Exception:
            rarity = "rare"
        saved = load_simplified_teams(self.player_id, rarity)
        self.add_item(
            SimplifiedTeamDropdown(
                label="Choose Team",
                teams=saved,
                player_id=self.player_id,
                file_path=self.file_path,
                parent_view=self
            )
        )
        self.add_item(SimplifiedPremadeAddButton(self.player_id, self.file_path))
    async def disable_all(self):
        for item in self.children:
            item.disabled = True

    async def on_timeout(self):
        await self.disable_all()

        # If the message exists, update it
        if hasattr(self, "message") and self.message:
            await self.message.edit(view=self)

