    def _tower_resolve_moves(name: str, forced_moves: list[str] | None = None):
        if forced_moves:
            return forced_moves[:4]
        moves_path = os.path.join("moves", f"{name.capitalize()}_moves.txt")
        if os.path.exists(moves_path):
            with open(moves_path, "r", encoding="utf-8") as mfile:
                content = mfile.read().strip()
                npc_moves = [m.strip().lower() for m in content.split("/") if m.strip()]
                if npc_moves:
                    return npc_moves[:4]
        return ["tackle", "growl", "protect", "hyper beam"]

    def _tower_resolve_ability(name: str, ability: str | None = None):
        ability = str(ability or "").strip().lower()
        if ability:
            return ability
        abilities = []
        try:
            with open(f"pokemon_data/{name}.json", "r", encoding="utf-8") as f:
                pdata = json.load(f)
                abilities = [str(a).strip().lower() for a in (pdata.get("abilities") or []) if str(a).strip()]
        except Exception:
            abilities = []
        if not abilities:
            return "ball fetch"
        return random.choice(abilities)

    def _tower_resolve_item(name: str, item: str | None = None):
        item = str(item or "").strip().lower()
        if item:
            return item
        if name == "arceus":
            return "silk scarf"
        if name == "yveltal":
            return random.choice(["big root", "sharp beak"])
        if name == "mega rayquaza":
            return "choice scarf"
        if name == "primal groudon":
            return "choice band"
        if name == "primal kyogre":
            return "choice scarf"
        if name == "crowned zacian":
            return "rusted sword"
        if name == "shadow rider calyrex":
            return "choice specs"
        if name == "miraidon":
            return "life orb"
        if name == "world guardian mega rayquaza":
            return "life orb"
        if name == "mirror shield origin dialga":
            return "choice specs"
        if name == "arachnid origin giratina":
            return "life orb"
        if name == "wonder bidoof":
            return "life orb"
        if name == "wolf king zacian":
            return "assault vest"
        if name == "mega metagross":
            return "assault vest"
        if name == "scorpion king metagross":
            return "assault vest"
        if name == "mega garchomp z":
            return "choice specs"
        if name == "garchomp":
            return "choice scarf"
        if name == "denjiman garchomp":
            return "focus sash"
        if name == "primarina":
            return "choice specs"
        if name == "golisopod":
            return "leftovers"
        if name == "mega golisopod":
            return "leftovers"
        if name == "mega salamence":
            return "life orb"
        if name == "mega pyroar":
            return "choice specs"
        if name == "mega malamar":
            return "choice scarf"
        if name == "mega dragonite":
            return "choice scarf"
        if name == "dragonite":
            return "choice scarf"
        return "scope lense"

    def _tower_write_slot(slot_idx: int, entry: dict):
        npc_name = str(entry.get("name") or "").strip().lower()
        if not npc_name:
            return None
        npc_nature = random.choice(entry.get("natures") or ["hardy"]).lower()
        npc_iv = [31, 31, 31, 31, 31, 31]
        npc_moves = _tower_resolve_moves(npc_name, entry.get("moves"))
        base_stats = get_pokemon_stats(npc_name)
        if not isinstance(base_stats, tuple) and not isinstance(base_stats, list):
            return None
        if not isinstance(base_stats[0], list):
            return None
        hp = math.floor(2 * base_stats[0][0] + npc_iv[0] + 5 + 110)
        data[f"p2_p{slot_idx}"] = npc_name
        data[f"p2_nature{slot_idx}"] = npc_nature
        data[f"p2_stats{slot_idx}"] = npc_iv
        data[f"p2_moves{slot_idx}"] = npc_moves
        data[f"p2_hp{slot_idx}"] = hp
        data[f"p2_status{slot_idx}"] = [0] * 6
        data[f"p2_condition{slot_idx}"] = []
        data[f"p2_hi{slot_idx}"] = _tower_resolve_item(npc_name, entry.get("item"))
        data[f"p2_ability{slot_idx}"] = _tower_resolve_ability(npc_name, entry.get("ability"))
        return npc_name

    def _load_kongfu_trending_teams():
        try:
            is_common = str(rarity).lower() == "common"
            default_path = "battle_teams/trending_common.json" if is_common else "battle_teams/trending.json"
            path = globals().get("TRENDING_COMMON_PATH" if is_common else "TRENDING_PATH", default_path)
            if not os.path.exists(path):
                return []
            with open(path, "r", encoding="utf-8") as f:
                return (json.load(f) or {}).get("teams", []) or []
        except Exception:
            return []

    def _kongfu_pick_nature(poke_name, original_nature):
        name = str(poke_name or "").strip().lower()
        base = str(original_nature or "hardy").strip().lower()
        if name == "arceus":
            return random.choice(["rash", "modest", "timid"])

        physical_pool = {"jolly", "adamant", "impish"}
        special_pool = {"timid", "modest", "bold", "calm"}
        if base in physical_pool and random.random() < 0.60:
            return random.choice(list(physical_pool))
        if base in special_pool and random.random() < 0.60:
            return random.choice(list(special_pool))
        return base

    if rarity == "rare":
        npc_pool = {
            "arceus": ["rash", "timid", "modest"],
            "primal groudon": ["timid", "calm"],
            "primal kyogre": ["modest", "timid"],
            "mega rayquaza": ["adamant", "jolly"],
            "yveltal": ["brave", "jolly"],
            "marshadow": ["jolly"],
            "origin dialga": ["timid", "modest"],
            "origin palkia": ["timid", "modest"],
            "koraidon": ["jolly"],
            "miraidon": ["timid", "modest"],
            "zacian": ["timid", "modest"],
            "magearna": ["calm", "modest", "sassy"],
            "mega metagross": ["adamant"],
            "regigigas": ["adamant", "jolly"],
            "giratina": ["sassy", "brave"]
        }
    else:
        npc_pool = {
            "primarina": ["bold", "timid", "modest"],
            "braviary": ["impish", "jolly"],
            "pyroar": ["modest", "timid"],
            "dragonite": ["adamant", "jolly"],
            "dragapult": ["adamant", "jolly"],
            "metagross": ["adamant", "jolly"],
            "golisopod": ["impish", "adamant","jolly"],
            "rhyperior": ["adamant", "impish"],
            "sneasler": ["jolly", "adamant"],
            "salamence": ["jolly", "adamant"],
            "garchomp": ["adamant", "jolly", "impish"],
            "kommo-o": ["adamant", "jolly"],
            "staraptor": ["adamant", "jolly"],
            "basculegion": ["adamant", "jolly"]
        }

    with open(file_path, "r") as f:
        data = json.load(f)

    number = data.get("number", 3)
    is_kongfu_mode = str(data.get("mode", "")).strip().lower() == PVE_MODE_KONGFU
    prev_poke = []

    tower_meta = data.get("tower_battle")
    if isinstance(tower_meta, dict):
        try:
            tower_id = int(tower_meta.get("tower_id") or 1)
        except Exception:
            tower_id = 1
        is_boss = bool(tower_meta.get("is_boss"))
        if is_boss:
            boss_entry = _tower_boss_for(tower_id)
            name_written = _tower_write_slot(1, boss_entry)
            if name_written:
                prev_poke.append(name_written)
            fill_pool = [e for e in _tower_pool_for(tower_id) if str(e.get("name")) != str(boss_entry.get("name"))]
            random.shuffle(fill_pool)
            slot_idx = 2
            for entry in fill_pool:
                if slot_idx > number:
                    break
                name_written = _tower_write_slot(slot_idx, entry)
                if name_written and name_written not in prev_poke:
                    prev_poke.append(name_written)
                    slot_idx += 1
        else:
            pool = _tower_pool_for(tower_id)
            random.shuffle(pool)
            number = 3
            chosen = pool[:number]
            while len(chosen) < number and pool:
                chosen.append(random.choice(pool))
            for i, entry in enumerate(chosen[:number], start=1):
                name_written = _tower_write_slot(i, entry)
                if name_written:
                    prev_poke.append(name_written)
        data["p2_order"] = prev_poke
        with open(file_path, "w") as f:
            json.dump(data, f, indent=4)
        return

    if is_kongfu_mode:
        trending_teams = _load_kongfu_trending_teams()
        selected_entries = []
        used_names = set()
        tries = 0
        while len(selected_entries) < number and tries < 120:
            tries += 1
            if not trending_teams:
                break
            team = random.choice(trending_teams)
            for key in sorted(team.keys()):
                entry = team.get(key) or {}
                poke_name = str(entry.get("name", "")).strip().lower()
                if not poke_name or poke_name in used_names:
                    continue
                selected_entries.append(entry)
                used_names.add(poke_name)
                if len(selected_entries) >= number:
                    break

        # Fallback: if trending teams are missing/insufficient, fill from existing random pool.
        while len(selected_entries) < number:
            npc_name = random.choice(list(npc_pool.keys()))
            if npc_name in used_names:
                continue
            selected_entries.append({"name": npc_name, "nature": random.choice(npc_pool[npc_name]), "moves": []})
            used_names.add(npc_name)

        for i, entry in enumerate(selected_entries[:number], start=1):
            npc_name = str(entry.get("name", "")).strip().lower()
            if not npc_name:
                continue
            prev_poke.append(npc_name)
            npc_nature = _kongfu_pick_nature(npc_name, entry.get("nature"))
            npc_iv = [31, 31, 31, 31, 31, 31]

            npc_moves = [m for m in (entry.get("moves") or []) if m][:4]
            if not npc_moves:
                moves_path = os.path.join("moves", f"{npc_name.capitalize()}_moves.txt")
                if os.path.exists(moves_path):
                    with open(moves_path, "r", encoding="utf-8") as mfile:
                        content = mfile.read().strip()
                        npc_moves = content.split("/")
                        if len(npc_moves) > 4:
                            npc_moves = npc_moves[:4]
                else:
                    npc_moves = ["Tackle", "Growl", "Protect", "Hyper Beam"]

            base_stats = get_pokemon_stats(npc_name)
            hp = math.floor(2 * base_stats[0][0] + npc_iv[0] + 5 + 110)

            data[f"p2_p{i}"] = npc_name
            data[f"p2_nature{i}"] = npc_nature
            data[f"p2_stats{i}"] = npc_iv
            data[f"p2_moves{i}"] = npc_moves
            data[f"p2_hp{i}"] = hp

        data["p2_order"] = prev_poke
        with open(file_path, "w") as f:
            json.dump(data, f, indent=4)
        return

    for i in range(1, number + 1):
        npc_name = random.choice(list(npc_pool.keys()))
        while npc_name in prev_poke:
            npc_name = random.choice(list(npc_pool.keys()))
        prev_poke.append(npc_name)

        npc_nature = random.choice(npc_pool[npc_name])
        npc_iv = [31,31,31,31,31,31]

        # Get moves
        moves_path = os.path.join("moves", f"{npc_name.capitalize()}_moves.txt")
        if os.path.exists(moves_path):
            with open(moves_path, "r", encoding="utf-8") as mfile:
                content = mfile.read().strip()
                npc_moves = content.split("/")
                if len(npc_moves) > 4:
                    npc_moves = npc_moves[:4]
        else:
            npc_moves = ["Tackle", "Growl", "Protect", "Hyper Beam"]

        # Get base stats to calculate HP
        base_stats = get_pokemon_stats(npc_name)
        hp = math.floor(2 * base_stats[0][0] + npc_iv[0] + 5 + 110)

        # Save to p2
        data[f"p2_p{i}"] = npc_name
        data[f"p2_nature{i}"] = npc_nature
        data[f"p2_stats{i}"] = npc_iv
        data[f"p2_moves{i}"] = npc_moves
        data[f"p2_hp{i}"] = hp

    data[f"p2_order"] = prev_poke

    with open(file_path, "w") as f:
        json.dump(data, f, indent=4)


