def _lru_get(cache: OrderedDict, key):
    value = cache.get(key)
    if value is None:
        return None
    cache.move_to_end(key)
    return value


def _lru_put(cache: OrderedDict, key, value, max_size: int):
    if max_size <= 0:
        try:
            value.close()
        except Exception:
            pass
        return
    cache[key] = value
    cache.move_to_end(key)
    while len(cache) > max_size:
        _, old_value = cache.popitem(last=False)
        try:
            old_value.close()
        except Exception:
            pass

def get_pokemon_sprite(pokemon_name, shiny=True):
    """Fetch and cache Pokemon sprite images."""
    if not pokemon_name:
        return None

    key = (pokemon_name.lower(), bool(shiny))
    cached = _lru_get(_POKEMON_SPRITE_CACHE, key)
    if cached is not None:
        return cached.copy()

    filename = f"{pokemon_name.lower()}.json"
    pokemon_filepath = os.path.join(pokemon_data_folder, filename)
    pokemon_data = None
    try:
        pokemon_data = load_json_data(pokemon_filepath)
    except FileNotFoundError:
        pass
    except Exception:
        pass

    if not pokemon_data:
        fakemon_filepath = os.path.join(fakemon_data_folder, filename)
        try:
            pokemon_data = load_json_data(fakemon_filepath)
        except FileNotFoundError:
            pass
        except Exception:
            pass

    if not pokemon_data:
        return None

    url = pokemon_data["sprites"]["shiny_front"] if shiny else pokemon_data["sprites"]["default_front"]
    try:
        resp = requests.get(url, timeout=10)
        if resp.status_code != 200:
            return None
        sprite = Image.open(BytesIO(resp.content)).convert("RGBA")
        _lru_put(_POKEMON_SPRITE_CACHE, key, sprite, _MAX_POKEMON_SPRITE_CACHE)
        return sprite.copy()
    except (requests.Timeout, requests.ConnectionError, Exception) as e:
        logging.warning(f"Failed to fetch sprite for {pokemon_name}: {e}")
        return None

