def _get_cached_battle_background(background_name: str):
    name = (background_name or "arena").strip().lower()
    if name not in _BATTLE_BG_PATHS:
        name = "arena"

    cached = _lru_get(_BATTLE_BACKGROUND_CACHE, name)
    if cached is not None:
        return cached.copy()

    bg_path = _BATTLE_BG_PATHS[name]
    bg = Image.open(bg_path).convert("RGBA").resize(_BATTLE_IMAGE_SIZE, Image.LANCZOS)
    _lru_put(_BATTLE_BACKGROUND_CACHE, name, bg, _MAX_BACKGROUND_CACHE)
    return bg.copy()


def _get_cached_special_sprite(url: str):
    cached = _lru_get(_BATTLE_SPECIAL_SPRITE_CACHE, url)
    if cached is not None:
        return cached.copy()

    try:
        resp = requests.get(url, timeout=10)
        if resp.status_code != 200:
            return None
        sprite = Image.open(BytesIO(resp.content)).convert("RGBA")
        _lru_put(_BATTLE_SPECIAL_SPRITE_CACHE, url, sprite, _MAX_SPECIAL_SPRITE_CACHE)
    except (requests.Timeout, requests.ConnectionError, Exception) as e:
        logging.warning(f"Failed to fetch special sprite from {url}: {e}")
        return None
    return sprite.copy()


def _get_cached_claw(size):
    key = (int(size[0]), int(size[1]))
    cached = _lru_get(_BATTLE_CLAW_CACHE, key)
    if cached is not None:
        return cached.copy()
    claw = Image.open("claw.png").convert("RGBA")
    claw = claw.resize(key, Image.LANCZOS).rotate(90, expand=True)
    _lru_put(_BATTLE_CLAW_CACHE, key, claw, _MAX_CLAW_CACHE)
    return claw.copy()


def _get_cached_battle_pokeball(state: str, size=(15, 15)):
    state_key = "alive" if str(state).strip().lower() != "fainted" else "fainted"
    key = (state_key, int(size[0]), int(size[1]))
    cached = _lru_get(_BATTLE_POKEBALL_CACHE, key)
    if cached is not None:
        return cached.copy()

    path = _BATTLE_POKEBALL_PATHS.get(state_key, _BATTLE_POKEBALL_PATHS["alive"])
    try:
        icon = Image.open(path).convert("RGBA")
    except Exception:
        icon = Image.new("RGBA", (int(size[0]), int(size[1])), (0, 0, 0, 0))
        draw = ImageDraw.Draw(icon)
        fill = (225, 0, 0, 255) if state_key == "fainted" else (255, 255, 255, 255)
        draw.ellipse([1, 1, icon.width - 2, icon.height - 2], fill=fill, outline=(0, 0, 0, 255), width=2)

    _lru_put(_BATTLE_POKEBALL_CACHE, key, icon, _MAX_BATTLE_POKEBALL_CACHE)
    return icon.copy()

