def parse_embed_color(color_name: str):
    color_map = {
        "red": 0xFF3B30,
        "dark blue": 0x1F3A93,
        "blue": 0x3498DB,
        "green": 0x1C9903,
        "pink": 0xFF9CE3,
        "purple": 0x9B59B6,
        "cyan": 0x00BCD4,
        "golden": 0xF1C40F,
        "yellow": 0xF1C40F,
        "light": 0xFFFF00,
        "dark": 0x000000,
        "crimson": 0x8B0000,
        "default": 0x9CFFA9,
        "black":0x5C170F,
        "sky blue":0x4DE2FF,
    }
    value = color_map.get((color_name or "").strip().lower())
    return discord.Color(value) if value is not None else discord.Color.green()
def get_active(slot, data):
    number = data['number']
    for i in range(1,number+1):
        hp_val = data.get(f"{slot}_hp{i}")
        try:
            if float(hp_val or 0) > 0:
                return i
        except Exception:
            pass
    return None

def _battle_perf_print(label: str, wall_start: float, cpu_start: float):
    wall = max(1e-9, time.perf_counter() - wall_start)
    cpu = max(0.0, time.process_time() - cpu_start)
    one_core_pct = (cpu / wall) * 100.0
    print(f"[battle-perf] {label} wall={wall:.4f}s cpu={cpu:.4f}s one_core_est={one_core_pct:.1f}%")

