class MegaFormDropdown(discord.ui.Select):
    def __init__(self, player_id, file_path, counter, forms):
        self.player_id = player_id
        self.file_path = file_path
        self.counter = counter
        options = [discord.SelectOption(label=f.title(), value=f) for f in forms[:25]]
        super().__init__(placeholder="Choose mega/primal form", min_values=1, max_values=1, options=options)

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.player_id:
            return await interaction.response.send_message("Not your selection!", ephemeral=True)
        origin_message = getattr(self.view, "origin_message", None)
        await _apply_mega_evolution_now(
            interaction,
            self.player_id,
            self.file_path,
            self.counter,
            self.values[0],
            origin_message,
        )


