class TerastallizeButton(discord.ui.Button):
    def __init__(self, player_id, file_path, counter):
        super().__init__(label="Terastrallize", style=discord.ButtonStyle.primary, row=2)
        self.player_id = player_id
        self.file_path = file_path
        self.counter = counter

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.player_id:
            return await interaction.response.send_message("Not your selection!", ephemeral=True)
        try:
            with open(self.file_path, "r") as f:
                data = json.load(f)
            mode_now = str(data.get("mode", "")).strip().lower()
            if not (_is_simplified_mode(mode_now) or mode_now == "standard"):
                return await interaction.response.send_message("Terastallization is not available in this mode.", ephemeral=True)
            slot = _resolve_battle_slot(data, self.player_id, self.counter)
            active = get_active(slot, data)
            if not active:
                return await interaction.response.send_message("No active pokemon found.", ephemeral=True)
            held_item = str(data.get(f"{slot}_hi{active}") or "").strip().lower()
            if not held_item.startswith("tera orb "):
                return await interaction.response.send_message("You need a `tera orb <type>` held item to terastallize.", ephemeral=True)
            tera_type = held_item.replace("tera orb ", "", 1).strip().lower()
            if not tera_type:
                return await interaction.response.send_message("Invalid tera orb type.", ephemeral=True)
            cond_key = f"{slot}_condition{active}"
            conditions = data.get(cond_key)
            if not isinstance(conditions, list):
                conditions = []
            if any(isinstance(c, str) and c.lower().startswith("tera:") for c in conditions):
                return await interaction.response.send_message("This pokemon is already terastallized.", ephemeral=True)
            conditions.append(f"tera: {tera_type}")
            data[cond_key] = conditions
            with open(self.file_path, "w") as f:
                json.dump(data, f, indent=4)
            await interaction.response.send_message(
                f"✅ Terastallized into {tera_type.title()} type.",
                ephemeral=True
            )
        except Exception:
            traceback.print_exc()
            await interaction.response.send_message("Failed to process terastallization.", ephemeral=True)


