def _resolve_battle_slot(data, player_id, counter):
    slot = "p1" if data["p1_id"] == player_id else "p2"
    if data["p1_id"] == data["p2_id"]:
        slot = "p1" if counter == 0 else "p2"
    return slot


def _battle_move_deadline_unix(timeout_seconds=120):
    return int(time.time() + timeout_seconds)


def _battle_move_prompt_text(prefix_text: str, timeout_seconds=120):
    deadline = _battle_move_deadline_unix(timeout_seconds)
    return f"{prefix_text}\nAuto-surrender <t:{deadline}:R>."

def _build_switch_options_for_slot(data, slot, active_index):
    switch_options = []
    number = int(data.get("number", 0) or 0)
    for i in range(1, number + 1):
        if i == active_index:
            continue
        if data.get(f"{slot}_hp{i}", 0) <= 0:
            continue
        switch_name = data.get(f"{slot}_p{i}")
        if not switch_name:
            continue

        types_emojis = "❔"
        base_stats = [0, 0, 0, 0, 0, 0]
        try:
            base_stats, poke_types = get_pokemon_stats(switch_name)
            type_icons = [DESCRIPTION_TYPE_EMOJIS.get(str(t).lower(), "❔") for t in (poke_types or [])[:2]]
            if type_icons:
                types_emojis = "".join(type_icons)
        except Exception:
            pass

        ivs = data.get(f"{slot}_stats{i}") or [31] * 6
        try:
            hp_iv = int(ivs[0])
        except Exception:
            hp_iv = 31

        current_hp = int(data.get(f"{slot}_hp{i}", 0) or 0)
        try:
            max_hp = int(math.floor(2 * int(base_stats[0]) + hp_iv + 5 + 110))
        except Exception:
            max_hp = current_hp

        status = data.get(f"{slot}_status{i}") or [0] * 6
        has_debuff = any(isinstance(v, (int, float)) and v < 0 for v in status)
        debuff_text = "debuff" if has_debuff else ""

        description = f"{types_emojis} | {current_hp}/{max_hp}"
        if debuff_text:
            description += f" | {debuff_text}"

        switch_options.append(
            {
                "name": switch_name,
                "description": description[:100]
            }
        )
    return switch_options


def _parse_switch_target(choice: str) -> str | None:
    """Return the plain Pokémon name for a `Switch to ...` choice.

    This handles values that may include a uniqueness suffix (e.g. "Switch to Pikachu||2").
    """
    if not choice or not isinstance(choice, str) or not choice.startswith("Switch to "):
        return None
    target = choice.replace("Switch to ", "", 1)
    # strip uniqueness suffix if present
    if "||" in target:
        target = target.split("||", 1)[0]
    return target


def _is_choice_item(item_name: str) -> bool:
    return str(item_name or "").strip().lower() in {"choice scarf", "choice band", "choice specs"}


async def send_battle_move_view(user, view, prefix_text):
    if not user:
        return None
    round_id = getattr(view, "round_id", None)
    player_id = int(getattr(view, "player_id", 0) or 0)
    counter = int(getattr(view, "counter", 0) or 0)
    file_path = str(getattr(view, "file_path", "") or "")
    if file_path and player_id and _is_selection_alive(file_path, round_id, player_id, counter):
        return None

    timeout_seconds = int(view.timeout or 180)
    if file_path and player_id:
        try:
            data = _load_battle(file_path)
            slot = _resolve_battle_slot(data, player_id, counter)
            timeout_seconds = _begin_player_selection_timer(data, slot)
            _save_battle(file_path, data)
            view.timeout = timeout_seconds
        except Exception:
            timeout_seconds = int(view.timeout or 180)

    msg = await user.send(_battle_move_prompt_text(prefix_text, timeout_seconds), view=view)
    view.message = msg
    if file_path and player_id:
        _register_selection_alive(file_path, round_id, player_id, counter, getattr(msg, "id", None))
    return msg


async def send_battle_move_with_retry(user, view, prefix_text, max_retries=2):
    """Send battle move view with smart retry logic. Only retries on transient errors."""
    if not user:
        print(f"User is None/invalid - skipping send")
        return False
    for attempt in range(max_retries):
        try:
            await send_battle_move_view(user, view, prefix_text)
            return True
        except discord.NotFound:
            print(f"User {user.id} not found (404) - skipping retry")
            return False
        except discord.Forbidden:
            print(f"Cannot DM {user.id} (403) - user may have blocked bot or DMs closed")
            return False
        except discord.HTTPException as e:
            # Retry on rate limits or server errors
            if e.status == 429:
                retry_after = float(e.response.headers.get('Retry-After', 1))
                print(f"Rate limited. Waiting {retry_after}s before retry...")
                if attempt < max_retries - 1:
                    await asyncio.sleep(retry_after)
            elif 500 <= e.status < 600:  # Server errors
                if attempt < max_retries - 1:
                    await asyncio.sleep(0.5 * (2 ** attempt))
            else:
                return False
        except asyncio.TimeoutError:
            if attempt < max_retries - 1:
                await asyncio.sleep(0.5 * (2 ** attempt))
        except Exception as e:
            print(f"Unexpected error sending to {user.id}: {e}")
            return False
    return False


async def finalize_pivot_choice(interaction, player_id, file_path, counter, move_name, target_name):
    perf_wall_start = time.perf_counter()
    perf_cpu_start = time.process_time()
    if not interaction.response.is_done():
        await interaction.response.defer(ephemeral=True)

    if interaction.user.id != player_id:
        return await interaction.followup.send("Not your selection!", ephemeral=True)

    try:
        data = _load_battle(file_path)
        data.setdefault("mega_used", False)
        data.setdefault("z_move_used", False)

        slot = _resolve_battle_slot(data, player_id, counter)
        other_slot = "p2" if slot == "p2" else "p1"

        active = get_active(slot, data)
        if not active:
            return await interaction.followup.send("No active pokemon found.", ephemeral=True)

        held_item = str(data.get(f"{slot}_hi{active}") or "").strip().lower()
        if _is_choice_item(held_item):
            lock_move = data.get(f"{slot}_choice_lock_move")
            lock_name = data.get(f"{slot}_choice_lock_name")
            active_name = str(data.get(f"{slot}_p{active}") or "").strip().lower()
            if lock_move and lock_name == active_name and str(move_name or "") != lock_move:
                return await interaction.followup.send(
                    f"Choice item locked: you must use `{lock_move}` or switch out.",
                    ephemeral=True
                )

        # Normalize target name (may include uniqueness suffix)
        tname = _parse_switch_target(target_name) or target_name
        cond_key = f"{slot}_condition{active}"
        conditions = data.get(cond_key)
        if not isinstance(conditions, list):
            conditions = []
        conditions = [c for c in conditions if not (isinstance(c, str) and c.lower().startswith("switch::"))]
        conditions.append(f"switch::{tname}")
        data[cond_key] = conditions
        data[f"{slot}_choice"] = move_name
        _finalize_player_selection_timer(
            data,
            slot,
            increment=_battle_selection_increment_seconds(data),
        )
        print(cond_key, conditions)

        if _is_pve_mode(data.get("mode", "")):
            data["p2_choice"] = _choose_pve_reply(data.get("mode", ""), file_path, move_name)

        _save_battle(file_path, data)
        _clear_selection_alive(file_path, data.get("round_id"), player_id, counter)

        if not data.get(f"{other_slot}_choice"):
            await interaction.followup.send("Waiting for your opponent...", ephemeral=True)
            return

    except Exception as e:
        print(e)
        traceback.print_exc()
        return

    await interaction.followup.send(
        f"You selected: {_make_special_choice_label(move_name)} → switch to {tname}",
        ephemeral=True
    )

    await _dispatch_battle_round_if_ready(file_path, data)
    _battle_perf_print("finalize_pivot_choice_total", perf_wall_start, perf_cpu_start)


async def process_battle_choice(interaction, player_id, file_path, counter, choice, battle_view=None, battle_message=None):
    perf_wall_start = time.perf_counter()
    perf_cpu_start = time.process_time()
    if not interaction.response.is_done():
        await interaction.response.defer(ephemeral=True)

    if interaction.user.id != player_id:
        return await interaction.followup.send("Not your selection!", ephemeral=True)

    if battle_view is not None and battle_message is not None:
        for item in battle_view.children:
            item.disabled = True
        try:
            await battle_message.edit(view=battle_view)
        except Exception:
            pass

    try:
        # load and update data via sqlite/file wrapper
        data = _load_battle(file_path)
        data.setdefault("mega_used", False)
        data.setdefault("z_move_used", False)

        if battle_view is not None:
            current_round = int(data.get("round_id", 0) or 0)
            view_round = int(getattr(battle_view, "round_id", 0) or 0)
            if view_round != current_round:
                return await interaction.followup.send(
                    "That selection panel is stale. Please use the newest DM prompt.",
                    ephemeral=True
                )
            if not _is_selection_alive(file_path, view_round, player_id, counter):
                return await interaction.followup.send(
                    "That selection panel already expired. Please use the newest DM prompt.",
                    ephemeral=True
                )

        slot = _resolve_battle_slot(data, player_id, counter)
        other_slot = "p2" if slot == "p1" else "p1"

        if str(choice).startswith("MEGA_EVOLVE::") and data.get("mega_used"):
            return await interaction.followup.send("Mega evolution has already been used in this game.", ephemeral=True)
        if str(choice).startswith("ZMOVE::") and data.get("z_move_used"):
            return await interaction.followup.send("Z move has already been used in this game.", ephemeral=True)
        if str(choice).startswith("ZMOVE::"):
            active = get_active(slot, data)
            if not active:
                return await interaction.followup.send("No active pokemon found.", ephemeral=True)
            held_item = str(data.get(f"{slot}_hi{active}") or "").strip().lower()
            if held_item != "z crystal":
                return await interaction.followup.send(
                    "Only pokemon holding `z crystal` can use Z Move.",
                    ephemeral=True
                )

        active = get_active(slot, data)
        if active:
            held_item = str(data.get(f"{slot}_hi{active}") or "").strip().lower()
            if _is_choice_item(held_item):
                choice_text = str(choice or "")
                if choice_text.startswith("Switch to "):
                    data[f"{slot}_choice_lock_move"] = None
                    data[f"{slot}_choice_lock_name"] = None
                elif (
                    choice_text
                    and not choice_text.startswith("MEGA_EVOLVE::")
                    and not choice_text.startswith("ZMOVE::")
                    and choice_text != "Surrender"
                ):
                    lock_move = data.get(f"{slot}_choice_lock_move")
                    lock_name = data.get(f"{slot}_choice_lock_name")
                    active_name = str(data.get(f"{slot}_p{active}") or "").strip().lower()
                    if lock_move and lock_name == active_name and choice_text != lock_move:
                        return await interaction.followup.send(
                            f"Choice item locked: you must use `{lock_move}` or switch out.",
                            ephemeral=True
                        )

        if _is_standard_like_mode(data.get("mode")):
            choice_text = str(choice or "").strip().lower()
            choice_norm = choice_text.replace("-", " ")
            if choice_norm in {"u turn", "volt switch", "flip turn", "parting shot", "baton pass"}:
                if not active:
                    return await interaction.followup.send("No active pokemon found.", ephemeral=True)
                switch_options = _build_switch_options_for_slot(data, slot, active)
                if switch_options:
                    view = PivotSwitchSelectView(player_id, file_path, counter, switch_options, str(choice))
                    await interaction.followup.send(
                        f"Choose a Pokémon to switch to after using **{_make_special_choice_label(choice)}**.",
                        view=view,
                        ephemeral=True
                    )
                    return

        data[f"{slot}_choice"] = choice
        if str(choice) != "Surrender":
            _finalize_player_selection_timer(
                data,
                slot,
                increment=_battle_selection_increment_seconds(data),
            )
        else:
            _stop_player_selection_timer(data, slot)

        if _is_pve_mode(data.get("mode", "")):
            data["p2_choice"] = _choose_pve_reply(data.get("mode", ""), file_path, choice)

        _save_battle(file_path, data)
        if battle_view is not None:
            _clear_selection_alive(file_path, getattr(battle_view, "round_id", None), player_id, counter)
        if battle_view is not None:
            battle_view.stop()

        data = _load_battle(file_path)

        if not data.get(f"{other_slot}_choice"):
            await interaction.followup.send("Waiting for your opponent...", ephemeral=True)
            return

    except Exception as e:
        print(e)
        traceback.print_exc()
        return

    await interaction.followup.send(f"You selected: {_make_special_choice_label(choice)}", ephemeral=True)

    await _dispatch_battle_round_if_ready(file_path, data)
    _battle_perf_print("process_battle_choice_total", perf_wall_start, perf_cpu_start)

def choose_pve_move2(file_path, player_move, depth=1):
    import copy
    perf_wall_start = time.perf_counter()
    perf_cpu_start = time.process_time()
    base_data = _load_battle(file_path)

    p1_slot, p2_slot = "p1", "p2"
    number = int(base_data.get("number", 6))
    base_data["p1_choice"] = player_move

    if not get_active(p1_slot, base_data) or not get_active(p2_slot, base_data):
        _battle_perf_print("choose_pve_move2", perf_wall_start, perf_cpu_start)
        return None

    stat_index = {"HP": 0, "Attack": 1, "Defense": 2, "Special Attack": 3, "Special Defense": 4, "Speed": 5}
    draining_moves = {
        "giga drain", "leech life", "draining kiss", "horn leech", "mega drain",
        "absorb", "dream eater", "parabolic charge", "drain punch", "oblivion wing"
    }
    start_time = time.perf_counter()
    time_budget = 0.18
    base_stats_cache = {}
    max_hp_cache = {}
    mon_cache = {}
    dmg_cache = {}
    eval_cache = {}
    move_effect_cache = {}

    def _clone_state(state):
        return copy.deepcopy(state)

    def _stage_mult(stage):
        if stage < 0:
            return 2 / (2 - stage)
        return 1 + 0.5 * stage

    def _max_hp(base_hp, hp_iv):
        return max(1, math.floor(2 * base_hp + hp_iv + 5 + 110))

    def _scaled_stat(base_stat, iv, stage, nature_mult):
        return max(1, math.floor((2 * base_stat + iv + 5 + 5) * _stage_mult(stage) * nature_mult))

    def _mint_mods(nature_name):
        return get_mint_modifiers((nature_name or "hardy").lower())

    def _build_mon(slot, idx, state):
        poke_name = state.get(f"{slot}_p{idx}")
        if not poke_name:
            return None
        cache_key = (
            slot,
            idx,
            poke_name,
            state.get(f"{slot}_hp{idx}", 0),
            tuple(state.get(f"{slot}_stats{idx}", [31] * 6) or [31] * 6),
            tuple(state.get(f"{slot}_status{idx}", [0] * 6) or [0] * 6),
            (state.get(f"{slot}_nature{idx}") or "hardy").lower(),
            (state.get(f"{slot}_ability{idx}") or "ball fetch").lower(),
            (state.get(f"{slot}_hi{idx}") or "scope lense").lower(),
        )
        cached = mon_cache.get(cache_key)
        if cached is not None:
            return cached
        if poke_name not in base_stats_cache:
            base_stats_cache[poke_name] = get_pokemon_stats(poke_name)
        base_stats, types = base_stats_cache[poke_name]
        ivs = state.get(f"{slot}_stats{idx}", [31] * 6) or [31] * 6
        while len(ivs) < 6:
            ivs.append(31)
        stages = state.get(f"{slot}_status{idx}", [0] * 6) or [0] * 6
        while len(stages) < 6:
            stages.append(0)
        nature = (state.get(f"{slot}_nature{idx}") or "hardy").lower()
        mods = _mint_mods(nature)
        hp_key = (poke_name, ivs[0])
        if hp_key not in max_hp_cache:
            max_hp_cache[hp_key] = _max_hp(base_stats[0], ivs[0])
        hp_max = max_hp_cache[hp_key]
        speed_stage = max(-6, min(6, stages[5]))
        speed = _scaled_stat(base_stats[5], ivs[5], speed_stage, mods.get("spd", 1))
        mon = {
            "slot": slot,
            "idx": idx,
            "name": poke_name,
            "base": base_stats,
            "types": types,
            "ivs": ivs,
            "stages": stages,
            "nature": nature,
            "mods": mods,
            "ability": (state.get(f"{slot}_ability{idx}") or "ball fetch").lower(),
            "item": (state.get(f"{slot}_hi{idx}") or "scope lense").lower(),
            "moves": state.get(f"{slot}_moves{idx}", []) or [],
            "condition": state.get(f"{slot}_condition{idx}", []) or [],
            "hp": max(0, state.get(f"{slot}_hp{idx}", 0)),
            "hp_max": hp_max,
            "speed": speed,
        }
        mon_cache[cache_key] = mon
        return mon

    def _switch(slot, choice, state):
        if not choice or not isinstance(choice, str) or not choice.startswith("Switch to "):
            return
        target_name = _parse_switch_target(choice)
        order_key = f"{slot}_order"
        original_order = state.get(order_key, [])
        if target_name not in original_order:
            return

        active_idx = get_active(slot, state)
        if active_idx:
            active_mon = _build_mon(slot, active_idx, state)
            if active_mon and active_mon["ability"] == "regenerator":
                healed = math.floor(active_mon["hp_max"] * 0.33)
                state[f"{slot}_hp{active_idx}"] = min(active_mon["hp_max"], active_mon["hp"] + healed)

        new_order = [target_name] + [n for n in original_order if n != target_name]
        keys = ["p", "hp", "stats", "nature", "moves", "status", "ability", "hi", "condition", "charge"]
        name_to_fields = {
            state.get(f"{slot}_p{i}"): {k: state.get(f"{slot}_{k}{i}") for k in keys}
            for i in range(1, number + 1)
            if state.get(f"{slot}_p{i}")
        }
        for i, name in enumerate(new_order, start=1):
            fields = name_to_fields.get(name)
            if not fields:
                continue
            for k in keys:
                state[f"{slot}_{k}{i}"] = fields.get(k)
        state[order_key] = new_order

    def _legal_actions(slot, state):
        active = get_active(slot, state)
        if not active:
            return []
        actions = [mv for mv in (state.get(f"{slot}_moves{active}", []) or []) if mv]
        for i in range(1, number + 1):
            poke = state.get(f"{slot}_p{i}")
            if not poke or i == active:
                continue
            if state.get(f"{slot}_hp{i}", 0) > 0:
                actions.append(f"Switch to {poke}")
        return actions

    def _apply_stage_effects(move_name, attacker_slot, defender_slot, state, fixed_active):
        if not move_name or move_name.startswith("Switch to "):
            return
        try:
            effect_text = get_move_effect(move_name)[0]
            self_changes = parse_stat_changes(effect_text) or {}
            target_changes = parse_target_stat_changes(effect_text) or {}
        except Exception:
            return

        atk_idx = fixed_active.get(attacker_slot)
        def_idx = fixed_active.get(defender_slot)
        if not atk_idx or not def_idx:
            return

        atk_status = state.get(f"{attacker_slot}_status{atk_idx}", [0] * 6) or [0] * 6
        def_status = state.get(f"{defender_slot}_status{def_idx}", [0] * 6) or [0] * 6

        for key, delta in self_changes.items():
            if key in stat_index and delta:
                sidx = stat_index[key]
                atk_status[sidx] = max(-6, min(6, atk_status[sidx] + int(delta)))
        for key, delta in target_changes.items():
            if key in stat_index and delta:
                sidx = stat_index[key]
                def_status[sidx] = max(-6, min(6, def_status[sidx] + int(delta)))

        state[f"{attacker_slot}_status{atk_idx}"] = atk_status
        state[f"{defender_slot}_status{def_idx}"] = def_status

    def _estimate_damage(attacker, defender, move_name):
        if not move_name:
            return 0, 0
        cache_key = (
            move_name,
            attacker["name"],
            defender["name"],
            tuple(attacker["ivs"]),
            tuple(defender["ivs"]),
            tuple(attacker["stages"]),
            tuple(defender["stages"]),
            attacker["nature"],
            defender["nature"],
            attacker["ability"],
            defender["ability"],
            attacker["item"],
            defender["item"],
        )
        if cache_key in dmg_cache:
            return dmg_cache[cache_key]
        try:
            dmg, heal = apply_damage_pi(
                move_name,
                attacker["base"], defender["base"],
                attacker["types"], defender["types"],
                attacker["stages"], defender["stages"],
                attacker["nature"], defender["nature"],
                attacker["ability"], defender["ability"],
                attacker["item"], defender["item"],
            )
        except Exception:
            return 0, 0

        dmg = max(0, dmg)
        heal = max(0, heal)
        move_info = get_move_info(move_name)
        category = move_info[1] if move_info else "status"

        if category in ("physical", "special"):
            if category == "physical":
                atk_key, def_key = 1, 2
                atk_nature = attacker["mods"].get("atk", 1)
                def_nature = defender["mods"].get("def", 1)
            else:
                atk_key, def_key = 3, 4
                atk_nature = attacker["mods"].get("spatk", 1)
                def_nature = defender["mods"].get("spdef", 1)

            assumed_atk = _scaled_stat(attacker["base"][atk_key], 31, attacker["stages"][atk_key], atk_nature)
            true_atk = _scaled_stat(attacker["base"][atk_key], attacker["ivs"][atk_key], attacker["stages"][atk_key], atk_nature)
            assumed_def = _scaled_stat(defender["base"][def_key], 31, defender["stages"][def_key], def_nature)
            true_def = _scaled_stat(defender["base"][def_key], defender["ivs"][def_key], defender["stages"][def_key], def_nature)

            scale = (true_atk / max(1, assumed_atk)) * (assumed_def / max(1, true_def))
            dmg = max(0, math.floor(dmg * scale))
            if move_name.lower() in draining_moves:
                heal = max(0, math.floor(heal * scale))

        dmg_cache[cache_key] = (dmg, heal)
        return dmg, heal

    def _apply_attack(attacker_slot, move_name, state, fixed_active, p1_action, p2_action):
        if not move_name or move_name.startswith("Switch to "):
            return
        defender_slot = p1_slot if attacker_slot == p2_slot else p2_slot
        atk_idx = fixed_active.get(attacker_slot)
        def_idx = fixed_active.get(defender_slot)
        if not atk_idx or not def_idx:
            return

        atk_mon = _build_mon(attacker_slot, atk_idx, state)
        def_mon = _build_mon(defender_slot, def_idx, state)
        if not atk_mon or not def_mon:
            return
        if atk_mon["hp"] <= 0 or def_mon["hp"] <= 0:
            return

        if move_name.lower() == "sucker punch":
            opp_action = p1_action if attacker_slot == p2_slot else p2_action
            if not opp_action or opp_action.startswith("Switch to "):
                return

        if "invinsible" in (def_mon["condition"] or []):
            dmg, heal = 0, 0
        else:
            dmg, heal = _estimate_damage(atk_mon, def_mon, move_name)

        if def_mon["ability"] == "multiscale" and def_mon["hp"] == def_mon["hp_max"]:
            dmg = math.floor(dmg / 2)

        if (def_mon["item"] == "focus sash" or def_mon["ability"] == "sturdy") and def_mon["hp"] == def_mon["hp_max"] and dmg >= def_mon["hp"]:
            new_def_hp = 1
        else:
            new_def_hp = max(0, def_mon["hp"] - dmg)

        new_atk_hp = min(atk_mon["hp_max"], atk_mon["hp"] + heal)
        state[f"{defender_slot}_hp{def_idx}"] = new_def_hp
        state[f"{attacker_slot}_hp{atk_idx}"] = new_atk_hp
        _apply_stage_effects(move_name, attacker_slot, defender_slot, state, fixed_active)

    def _simulate_turn(state, p2_action, p1_action):
        sim = _clone_state(state)
        _switch(p1_slot, p1_action, sim)
        _switch(p2_slot, p2_action, sim)

        p1_active = get_active(p1_slot, sim)
        p2_active = get_active(p2_slot, sim)
        if not p1_active or not p2_active:
            return sim
        fixed_active = {p1_slot: p1_active, p2_slot: p2_active}

        p1_mon = _build_mon(p1_slot, p1_active, sim)
        p2_mon = _build_mon(p2_slot, p2_active, sim)
        p1_attack = None if (not p1_action or p1_action.startswith("Switch to ")) else p1_action
        p2_attack = None if (not p2_action or p2_action.startswith("Switch to ")) else p2_action

        try:
            p1_pri = get_move_priority(p1_attack) if p1_attack else 0
        except Exception:
            p1_pri = 0
        try:
            p2_pri = get_move_priority(p2_attack) if p2_attack else 0
        except Exception:
            p2_pri = 0
        if not p1_pri:
            p1_pri = 0
        if not p2_pri:
            p2_pri = 0
        if p2_pri > p1_pri:
            order = [(p2_slot, p2_attack), (p1_slot, p1_attack)]
        elif p1_pri > p2_pri:
            order = [(p1_slot, p1_attack), (p2_slot, p2_attack)]
        elif (p2_mon["speed"] if p2_mon else 0) > (p1_mon["speed"] if p1_mon else 0):
            order = [(p2_slot, p2_attack), (p1_slot, p1_attack)]
        else:
            order = [(p1_slot, p1_attack), (p2_slot, p2_attack)]

        _apply_attack(order[0][0], order[0][1], sim, fixed_active, p1_action, p2_action)
        _apply_attack(order[1][0], order[1][1], sim, fixed_active, p1_action, p2_action)
        return sim

    def _team_state_value(slot, state):
        total = 0.0
        alive = 0
        for i in range(1, number + 1):
            poke = state.get(f"{slot}_p{i}")
            if not poke:
                continue
            if poke not in base_stats_cache:
                base_stats_cache[poke] = get_pokemon_stats(poke)
            base_stats = base_stats_cache[poke][0]
            ivs = state.get(f"{slot}_stats{i}", [31] * 6) or [31] * 6
            hp_now = max(0, state.get(f"{slot}_hp{i}", 0))
            hp_key = (poke, ivs[0] if ivs else 31)
            if hp_key not in max_hp_cache:
                max_hp_cache[hp_key] = _max_hp(base_stats[0], hp_key[1])
            hp_max = max_hp_cache[hp_key]
            total += hp_now / max(1, hp_max)
            if hp_now > 0:
                alive += 1
        return total, alive

    def _best_damage(attacker_slot, defender_slot, state):
        atk_idx = get_active(attacker_slot, state)
        def_idx = get_active(defender_slot, state)
        if not atk_idx or not def_idx:
            return 0
        atk_mon = _build_mon(attacker_slot, atk_idx, state)
        def_mon = _build_mon(defender_slot, def_idx, state)
        if not atk_mon or not def_mon:
            return 0
        best = 0
        for mv in atk_mon["moves"]:
            dmg, _ = _estimate_damage(atk_mon, def_mon, mv)
            if dmg > best:
                best = dmg
        return best

    def _turns_to_ko(attacker_slot, defender_slot, state):
        atk_idx = get_active(attacker_slot, state)
        def_idx = get_active(defender_slot, state)
        if not atk_idx or not def_idx:
            return 99
        defender = _build_mon(defender_slot, def_idx, state)
        if not defender:
            return 99
        best = _best_damage(attacker_slot, defender_slot, state)
        if best <= 0:
            return 99
        return int(math.ceil(defender["hp"] / max(1, best)))

    def _team_attack_potential(attacker_slot, defender_slot, state):
        def_idx = get_active(defender_slot, state)
        if not def_idx:
            return 0.0
        defender = _build_mon(defender_slot, def_idx, state)
        if not defender:
            return 0.0
        total = 0.0
        for i in range(1, number + 1):
            if state.get(f"{attacker_slot}_hp{i}", 0) <= 0:
                continue
            mon = _build_mon(attacker_slot, i, state)
            if not mon:
                continue
            local_best = 0
            for mv in mon["moves"]:
                dmg, _ = _estimate_damage(mon, defender, mv)
                if dmg > local_best:
                    local_best = dmg
            total += local_best / max(1, defender["hp_max"])
        return total

    def _switch_kill_potential(action, state):
        if not action or not action.startswith("Switch to "):
            return 0.0
        t_npc = _turns_to_ko(p2_slot, p1_slot, state)
        t_enemy = _turns_to_ko(p1_slot, p2_slot, state)
        if t_npc >= 99:
            return -450.0
        if t_enemy >= 99:
            return 260.0
        return (t_enemy - t_npc) * 140.0

    def _evaluate(state):
        eval_key = (
            tuple((state.get(f"p1_hp{i}", 0), state.get(f"p2_hp{i}", 0)) for i in range(1, number + 1)),
            tuple(tuple(state.get(f"p1_status{i}", [0] * 6) or [0] * 6) for i in range(1, number + 1)),
            tuple(tuple(state.get(f"p2_status{i}", [0] * 6) or [0] * 6) for i in range(1, number + 1)),
            tuple(state.get("p1_order", [])),
            tuple(state.get("p2_order", [])),
        )
        cached = eval_cache.get(eval_key)
        if cached is not None:
            return cached
        if not get_active(p1_slot, state):
            return 1_000_000
        if not get_active(p2_slot, state):
            return -1_000_000

        p2_ratio, p2_alive = _team_state_value(p2_slot, state)
        p1_ratio, p1_alive = _team_state_value(p1_slot, state)
        active_pressure = _best_damage(p2_slot, p1_slot, state) - _best_damage(p1_slot, p2_slot, state)
        p2_team_potential = _team_attack_potential(p2_slot, p1_slot, state)
        p1_team_potential = _team_attack_potential(p1_slot, p2_slot, state)

        p1_active = get_active(p1_slot, state)
        p2_active = get_active(p2_slot, state)
        p1_speed = _build_mon(p1_slot, p1_active, state)["speed"] if p1_active else 0
        p2_speed = _build_mon(p2_slot, p2_active, state)["speed"] if p2_active else 0
        speed_edge = p2_speed - p1_speed
        score = (
            (p2_ratio - p1_ratio) * 3200
            + (p2_alive - p1_alive) * 900
            + active_pressure * 2.0
            + (p2_team_potential - p1_team_potential) * 550
            + speed_edge * 0.35
        )
        eval_cache[eval_key] = score
        return score

    def _move_stage_changes(move_name):
        if not move_name or move_name.startswith("Switch to "):
            return {}, {}
        cached = move_effect_cache.get(move_name)
        if cached is not None:
            return cached
        try:
            effect_text = get_move_effect(move_name)[0]
            self_changes = parse_stat_changes(effect_text) or {}
            target_changes = parse_target_stat_changes(effect_text) or {}
        except Exception:
            self_changes, target_changes = {}, {}
        move_effect_cache[move_name] = (self_changes, target_changes)
        return self_changes, target_changes

    def _is_stat_utility_move(move_name):
        self_changes, target_changes = _move_stage_changes(move_name)
        if not self_changes and not target_changes:
            return False
        for v in self_changes.values():
            if v:
                return True
        for v in target_changes.values():
            if v:
                return True
        return False

    def _best_damage_for_mon(attacker_mon, defender_mon, category=None):
        best = 0
        for mv in attacker_mon["moves"]:
            try:
                info = get_move_info(mv)
                if category and info and info[1] != category:
                    continue
            except Exception:
                if category:
                    continue
            dmg, _ = _estimate_damage(attacker_mon, defender_mon, mv)
            if dmg > best:
                best = dmg
        return best

    def _quick_action_score(slot, action, state):
        if not action:
            return -1e9
        if action.startswith("Switch to "):
            return -120.0
        atk_idx = get_active(slot, state)
        def_idx = get_active(p1_slot if slot == p2_slot else p2_slot, state)
        if not atk_idx or not def_idx:
            return -1e9
        atk_mon = _build_mon(slot, atk_idx, state)
        def_mon = _build_mon(p1_slot if slot == p2_slot else p2_slot, def_idx, state)
        if not atk_mon or not def_mon:
            return -1e9
        dmg, heal = _estimate_damage(atk_mon, def_mon, action)
        score = dmg + heal * 0.5

        self_changes, target_changes = _move_stage_changes(action)
        if self_changes or target_changes:
            # Combo value: reward moves that improve follow-up damage.
            cur_phys = _best_damage_for_mon(atk_mon, def_mon, "physical")
            cur_spec = _best_damage_for_mon(atk_mon, def_mon, "special")

            atk_old = atk_mon["stages"][1]
            def_old = def_mon["stages"][2]
            spa_old = atk_mon["stages"][3]
            spd_old = def_mon["stages"][4]

            atk_new = max(-6, min(6, atk_old + int(self_changes.get("Attack", 0))))
            def_new = max(-6, min(6, def_old + int(target_changes.get("Defense", 0))))
            spa_new = max(-6, min(6, spa_old + int(self_changes.get("Special Attack", 0))))
            spd_new = max(-6, min(6, spd_old + int(target_changes.get("Special Defense", 0))))

            phys_ratio = (_stage_mult(atk_new) / max(1e-6, _stage_mult(atk_old))) * (_stage_mult(def_old) / max(1e-6, _stage_mult(def_new)))
            spec_ratio = (_stage_mult(spa_new) / max(1e-6, _stage_mult(spa_old))) * (_stage_mult(spd_old) / max(1e-6, _stage_mult(spd_new)))

            combo_gain = max(0.0, cur_phys * (phys_ratio - 1.0), cur_spec * (spec_ratio - 1.0))
            score += combo_gain * 0.8

            # Survival value: reward lowering opponent offenses / speed or raising own defenses.
            opp_phys = _best_damage_for_mon(def_mon, atk_mon, "physical")
            opp_spec = _best_damage_for_mon(def_mon, atk_mon, "special")
            incoming_now = max(opp_phys, opp_spec)

            opp_atk_old = def_mon["stages"][1]
            opp_spa_old = def_mon["stages"][3]
            my_def_old = atk_mon["stages"][2]
            my_spd_old = atk_mon["stages"][4]

            opp_atk_new = max(-6, min(6, opp_atk_old + int(target_changes.get("Attack", 0))))
            opp_spa_new = max(-6, min(6, opp_spa_old + int(target_changes.get("Special Attack", 0))))
            my_def_new = max(-6, min(6, my_def_old + int(self_changes.get("Defense", 0))))
            my_spd_new = max(-6, min(6, my_spd_old + int(self_changes.get("Special Defense", 0))))

            phys_in_ratio = (_stage_mult(opp_atk_new) / max(1e-6, _stage_mult(opp_atk_old))) * (_stage_mult(my_def_old) / max(1e-6, _stage_mult(my_def_new)))
            spec_in_ratio = (_stage_mult(opp_spa_new) / max(1e-6, _stage_mult(opp_spa_old))) * (_stage_mult(my_spd_old) / max(1e-6, _stage_mult(my_spd_new)))
            incoming_after = max(opp_phys * phys_in_ratio, opp_spec * spec_in_ratio)
            score += max(0.0, incoming_now - incoming_after) * 1.0

            # Speed control value: if a speed change flips order, value it.
            my_spd_stage_old = atk_mon["stages"][5]
            opp_spd_stage_old = def_mon["stages"][5]
            my_spd_stage_new = max(-6, min(6, my_spd_stage_old + int(self_changes.get("Speed", 0))))
            opp_spd_stage_new = max(-6, min(6, opp_spd_stage_old + int(target_changes.get("Speed", 0))))
            my_speed_new = atk_mon["speed"] * (_stage_mult(my_spd_stage_new) / max(1e-6, _stage_mult(my_spd_stage_old)))
            opp_speed_new = def_mon["speed"] * (_stage_mult(opp_spd_stage_new) / max(1e-6, _stage_mult(opp_spd_stage_old)))
            if atk_mon["speed"] <= def_mon["speed"] and my_speed_new > opp_speed_new:
                score += 120.0 + incoming_now * 0.2

        return score

    def _top_actions(slot, state, limit=4):
        actions = _legal_actions(slot, state)
        if len(actions) <= limit:
            return actions
        scored = [(a, _quick_action_score(slot, a, state)) for a in actions]
        scored.sort(key=lambda x: x[1], reverse=True)
        top = [a for a, _ in scored[:limit]]
        # Always keep one switch candidate if any exists.
        if not any(a.startswith("Switch to ") for a in top):
            for a, _ in scored:
                if isinstance(a, str) and a.startswith("Switch to "):
                    top[-1] = a
                    break
        # Keep at least one utility/setup move so combo/debuff lines are searchable.
        if not any(_is_stat_utility_move(a) for a in top if not a.startswith("Switch to ")):
            for a, _ in scored:
                if isinstance(a, str) and (not a.startswith("Switch to ")) and _is_stat_utility_move(a):
                    top[-1] = a
                    break
        return top

    def _future_value(state, plies_left, alpha=-float("inf"), beta=float("inf")):
        if time.perf_counter() - start_time > time_budget:
            return _evaluate(state)
        if plies_left <= 0:
            return _evaluate(state)
        if not get_active(p1_slot, state) or not get_active(p2_slot, state):
            return _evaluate(state)

        p2_actions = _top_actions(p2_slot, state, limit=3)
        p1_actions = _top_actions(p1_slot, state, limit=2)
        if not p2_actions or not p1_actions:
            return _evaluate(state)

        best_for_npc = -float("inf")
        for npc_action in p2_actions:
            worst_case = float("inf")
            for pl_action in p1_actions:
                next_state = _simulate_turn(state, npc_action, pl_action)
                score = _future_value(next_state, plies_left - 1, alpha, beta)
                if score < worst_case:
                    worst_case = score
                beta = min(beta, worst_case)
                if beta <= alpha:
                    break
            if worst_case > best_for_npc:
                best_for_npc = worst_case
            alpha = max(alpha, best_for_npc)
            if beta <= alpha:
                break
        return best_for_npc

    root_state = _clone_state(base_data)
    npc_actions = _top_actions(p2_slot, root_state, limit=3)
    if not npc_actions:
        _battle_perf_print("choose_pve_move2", perf_wall_start, perf_cpu_start)
        return None
    if time.perf_counter() - start_time > time_budget:
        legal = _legal_actions(p2_slot, root_state)
        if legal:
            choice = max(legal, key=lambda a: _quick_action_score(p2_slot, a, root_state))
            _battle_perf_print("choose_pve_move2", perf_wall_start, perf_cpu_start)
            return choice

    effective_player_move = player_move
    if isinstance(player_move, str) and player_move.startswith("Switch to ") and random.random() < 0.15:
        p1_idx = get_active(p1_slot, root_state)
        p2_idx = get_active(p2_slot, root_state)
        if p1_idx and p2_idx:
            p1_mon = _build_mon(p1_slot, p1_idx, root_state)
            p2_mon = _build_mon(p2_slot, p2_idx, root_state)
            if p1_mon and p2_mon:
                best_player_attack = None
                best_player_dmg = -1
                for mv in p1_mon.get("moves", []) or []:
                    if not mv or str(mv).startswith("Switch to "):
                        continue
                    dmg, _ = _estimate_damage(p1_mon, p2_mon, mv)
                    if dmg > best_player_dmg:
                        best_player_dmg = dmg
                        best_player_attack = mv
                if best_player_attack:
                    effective_player_move = best_player_attack

    forced_switch_action = None
    p1_idx = get_active(p1_slot, root_state)
    p2_idx = get_active(p2_slot, root_state)
    if p1_idx and p2_idx:
        p1_mon = _build_mon(p1_slot, p1_idx, root_state)
        p2_mon = _build_mon(p2_slot, p2_idx, root_state)
        if p1_mon and p2_mon:
            current_best_dmg = 0
            for mv in p2_mon.get("moves", []) or []:
                if not mv or str(mv).startswith("Switch to "):
                    continue
                dmg, _ = _estimate_damage(p2_mon, p1_mon, mv)
                if dmg > current_best_dmg:
                    current_best_dmg = dmg
            if current_best_dmg < (p1_mon["hp_max"] * 0.33):
                best_switch_name = None
                best_switch_score = -float("inf")
                player_best_damage_cache = {}

                def _player_best_into(mon_name, mon_obj):
                    cached = player_best_damage_cache.get(mon_name)
                    if cached is not None:
                        return cached
                    best = 0
                    for pmv in p1_mon.get("moves", []) or []:
                        if not pmv or str(pmv).startswith("Switch to "):
                            continue
                        pdmg, _ = _estimate_damage(p1_mon, mon_obj, pmv)
                        if pdmg > best:
                            best = pdmg
                    player_best_damage_cache[mon_name] = best
                    return best

                for i in range(1, number + 1):
                    if i == p2_idx:
                        continue
                    if int(root_state.get(f"{p2_slot}_hp{i}") or 0) <= 0:
                        continue
                    candidate = _build_mon(p2_slot, i, root_state)
                    if not candidate:
                        continue
                    candidate_best_dmg = 0
                    for mv in candidate.get("moves", []) or []:
                        if not mv or str(mv).startswith("Switch to "):
                            continue
                        dmg, _ = _estimate_damage(candidate, p1_mon, mv)
                        if dmg > candidate_best_dmg:
                            candidate_best_dmg = dmg
                    if candidate_best_dmg <= 0:
                        continue
                    candidate_turns = int(math.ceil(max(1, p1_mon["hp"]) / max(1, candidate_best_dmg)))
                    player_best_dmg = _player_best_into(candidate["name"], candidate)
                    if player_best_dmg <= 0:
                        player_turns = 99
                    else:
                        player_turns = int(math.ceil(max(1, candidate["hp"]) / max(1, player_best_dmg)))
                    if candidate_turns < player_turns:
                        score = (player_turns - candidate_turns) * 220.0 + candidate_best_dmg
                        if score > best_switch_score:
                            best_switch_score = score
                            best_switch_name = candidate["name"]
                if best_switch_name:
                    forced_switch_action = f"Switch to {best_switch_name}"

    best_action = None
    best_score = -float("inf")
    best_move_action = None
    best_move_score = -float("inf")
    best_switch_action = None
    best_switch_score = -float("inf")
    lookahead = max(1, int(depth))
    for npc_action in npc_actions:
        first_state = _simulate_turn(root_state, npc_action, effective_player_move)
        score = _evaluate(first_state)
        score += _switch_kill_potential(npc_action, first_state)
        if lookahead > 1:
            score = score * 0.35 + _future_value(first_state, lookahead - 1) * 0.65
        if isinstance(npc_action, str) and npc_action.startswith("Switch to "):
            score -= 220.0
            if score > best_switch_score:
                best_switch_score = score
                best_switch_action = npc_action
        else:
            if score > best_move_score:
                best_move_score = score
                best_move_action = npc_action
        if score > best_score:
            best_score = score
            best_action = npc_action

    # Conservative switch policy: only switch when it clearly outperforms best attacking line.
    switch_margin = 260.0
    if forced_switch_action and forced_switch_action in _legal_actions(p2_slot, root_state):
        choice = forced_switch_action
    elif best_switch_action and best_switch_score > (best_move_score + switch_margin):
        choice = best_switch_action
    elif best_move_action:
        choice = best_move_action
    else:
        choice = best_action if best_action else npc_actions[0]
    _battle_perf_print("choose_pve_move2", perf_wall_start, perf_cpu_start)
    return choice
        
def choose_pve_move(file_path, player_move):
    perf_wall_start = time.perf_counter()
    perf_cpu_start = time.process_time()

    with open(file_path, "r") as f:
        data = json.load(f)

    p2_slot = "p2"  # NPC
    p1_slot = "p1"  # Player
    p2_active = get_active(p2_slot, data)
    p1_active = get_active(p1_slot, data)

    if not p2_active or not p1_active:
        return None  # battle over

    moves = data.get(f"{p2_slot}_moves{p2_active}", [])
    if not moves:
        return None
    
    data['p1_choice'] = player_move

    # NPC stats
    p2_pokemon = data[f"{p2_slot}_p{p2_active}"]
    p2_stats = get_pokemon_stats(p2_pokemon)[0]
    p2_speed = p2_stats[5]
    p2_ability = data.get(f"{p2_slot}_ability{p2_active}") or 'ball fetch'
    p2_hi = (data.get(f"{p2_slot}_hi{p2_active}") or 'scope lense').lower()
    p2_debuff = data.get(f"{p2_slot}_status{p2_active}", [0]*6)
    p2_hp = data.get(f"{p2_slot}_hp{p2_active}", 100)
    p2_condition = data.get(f"{p2_slot}_condition{p2_active}", [])

    # Player stats
    p1_pokemon = data[f"{p1_slot}_p{p1_active}"]
    p1_stats = get_pokemon_stats(p1_pokemon)[0]
    p1_speed = p1_stats[5]
    p1_ability = data.get(f"{p1_slot}_ability{p1_active}") or 'ball fetch'
    p1_hi = (data.get(f"{p1_slot}_hi{p1_active}") or 'scope lense').lower()
    p1_debuff = data.get(f"{p1_slot}_status{p1_active}", [0]*6)
    p1_hp = data.get(f"{p1_slot}_hp{p1_active}", 100)
    p1_condition = data.get(f"{p1_slot}_condition{p1_active}", [])

    # Check if player is switching
    if "Switch to" in data['p1_choice']:
        choice=data['p1_choice']
        target_name = _parse_switch_target(choice)
        number = data['number']
        order_key = f"p1_order"
        original_order = data[order_key]
        if target_name not in original_order:
            return  # Pokémon not found or already front
        new_order = [target_name] + [n for n in original_order if n != target_name]
        # Map current Pokémon name to their fields
        keys = ["p", "hp", "stats", "nature", "moves", "status", "ability", "hi", "cosmetic", "condition", "charge"]
        name_to_fields = {
            data[f"p1_p{i}"]: {k: data[f"p1_{k}{i}"] for k in keys}
            for i in range(1, number + 1)
        }
        # Reassign fields according to new order
        fields = name_to_fields[new_order[0]]
        p1_pokemon = fields['p']
        p1_stats = get_pokemon_stats(fields['p'])[0]
        p1_speed = p1_stats[5]
        p1_ability = fields['ability'] or 'ball fetch'
        p1_hi = (fields['hi'] or 'scope lense').lower()
        p1_debuff = fields['status']
        p1_hp = fields['hp']

    # Helper: simulate multi-turn battle
    def simulate_battle(npc_poke, npc_stats, npc_hp, npc_moves, npc_ability, npc_hi,
                    player_poke, player_stats, player_hp, player_move, player_ability, player_hi):
        """
        Returns True if NPC can eventually win the 1v1, else False.
        """
        npc_cur_hp = npc_hp
        player_cur_hp = player_hp

        for _ in range(20):  # turn limit
            # Determine who attacks first
            npc_faster = npc_stats[5] >= player_stats[5]

            # Player attacks
            if not npc_faster:
                dmg, heal, tm = apply_damage(player_move, "p1", "p2", data, p1_condition)
                npc_cur_hp -= dmg
                npc_cur_hp += heal
                if npc_cur_hp <= 0:
                    return False

            # NPC attacks
            best_move = None
            best_dmg = -float('inf')
            for mv in npc_moves:
                dmg, _, _ = apply_damage(mv, "p2", "p1", data, p2_condition)
                if dmg > best_dmg:
                    best_dmg = dmg
                    best_move = mv

            player_cur_hp -= best_dmg
            if player_cur_hp <= 0:
                return True

            # Player second if slower
            if npc_faster:
                dmg, heal, tm = apply_damage(player_move, "p1", "p2", data, p1_condition)
                npc_cur_hp -= dmg
                npc_cur_hp += heal
                if npc_cur_hp <= 0:
                    return False

        # Decide by remaining HP ratio if both alive
        return npc_cur_hp > player_cur_hp

    can_current_win = simulate_battle(
        p2_pokemon, p2_stats, p2_hp, moves, p2_ability, p2_hi,
        p1_pokemon, p1_stats, p1_hp,
        data.get(f"{p1_slot}_moves", moves[0]), p1_ability, p1_hi
    )

    switch_options = []
    if not can_current_win:
        for idx in range(1, 7):
            poke_name = data.get(f"{p2_slot}_p{idx}")
            if not poke_name or idx == p2_active:
                continue
            if data.get(f"{p2_slot}_hp{idx}", 0) <= 0:
                continue  # skip fainted

            poke_stats, types = get_pokemon_stats(poke_name)
            poke_ability= data.get(f"{p2_slot}_ability{idx}")
            poke_moves= data.get(f"{p2_slot}_moves{idx}")
            poke_hi = data.get(f"{p2_slot}_hi{idx}")
            poke_hp = data.get(f"{p2_slot}_hp{idx}", 100)
            p1_attack = data[p1_slot+"_choice"] if p1_active and "Switch to" not in data[p1_slot+"_choice"] else None
            if p1_attack:
                taken_dmg, taken_heal, tm = apply_damage(p1_attack, p1_slot, p2_slot, data, p1_condition)
            else:
                taken_dmg = 0

            if simulate_battle(poke_name, poke_stats, poke_hp, poke_moves, poke_ability, poke_hi,
                            p1_pokemon, p1_stats, p1_hp,
                            data.get(f"{p1_slot}_moves", moves[0]), p1_ability, p1_hi):
                switch_options.append(poke_name)

    if switch_options:
        # Pick Pokémon with highest HP or most favorable matchup
        best_switch = max(switch_options, key=lambda x: data.get(f"{p2_slot}_hp{x[0]}", 0))
        return f"Switch to {best_switch}"


    # Otherwise, pick best move
    best_move = None
    best_score = -float('inf')
    best_priority_move = None
    highest_priority_dmg = -float('inf')
    highest_dmg = -float('inf')
    highest_dmg_move = None

    for mv in moves:
        effect_text = get_move_effect(mv)[0]

        # Parse stat changes
        target_stat_changes = parse_target_stat_changes(effect_text) or {}
        self_stat_changes = parse_stat_changes(effect_text) or {}

        # Score debuffs on player
        debuff_score = sum(-v for v in target_stat_changes.values() if v < 0)
        # Score buffs on NPC
        buff_score = sum(-v for v in self_stat_changes.values() if v < 0)

        # Simulate damage (p2 attacking p1)
        dmg, heal, tm = apply_damage(mv, p2_slot, p1_slot, data, p2_condition)
        priority = get_move_priority(mv)

        score = dmg + (debuff_score + buff_score) * 10

        if priority and dmg > highest_priority_dmg:
            highest_priority_dmg = dmg
            best_priority_move = mv

        if score > best_score:
            best_score = score
            best_move = mv

        if dmg > highest_dmg:
            highest_dmg = dmg
            highest_dmg_move = mv
        

    if highest_priority_dmg >= p1_hp and best_priority_move:
        return best_priority_move

    if highest_dmg >= p1_hp and highest_dmg_move:
        return highest_dmg_move

    _battle_perf_print("choose_pve_move", perf_wall_start, perf_cpu_start)
    return best_move


def _tower_choose_move_simple(file_path: str, player_move: str) -> str | None:
    """
    Simplified tower AI using the following logic:
    1. Check opponent's move
    2. Calculate damage considering weather, terrain, abilities, held items
    3. If opponent buffs, check if highest damage move can deal half HP
    4. If not, check other pokemon to switch
    5. If no buff, use highest damage move
    """
    try:
        data = _load_battle(file_path)
        data["p1_choice"] = player_move
        
        p1_slot, p2_slot = "p1", "p2"
        p1_active = get_active(p1_slot, data)
        p2_active = get_active(p2_slot, data)
        
        if not p1_active or not p2_active:
            return None
        
        p2_moves = data.get(f"{p2_slot}_moves{p2_active}", []) or []
        if not p2_moves:
            return None
        
        # Get current active pokemon stats
        p1_poke = data.get(f"{p1_slot}_p{p1_active}")
        p2_poke = data.get(f"{p2_slot}_p{p2_active}")
        p1_stats = get_pokemon_stats(p1_poke)[0] if p1_poke else [1]*6
        p2_stats = get_pokemon_stats(p2_poke)[0] if p2_poke else [1]*6
        
        p1_hp = data.get(f"{p1_slot}_hp{p1_active}", 1)
        p2_hp = data.get(f"{p2_slot}_hp{p2_active}", 1)
        
        # Step 1: Check what move player chose
        player_move_normalized = player_move.lower() if isinstance(player_move, str) else ""
        is_player_switch = "switch to" in player_move_normalized
        
        # Step 2: Calculate damage of possible moves, accounting for weather, terrain, abilities, items
        best_damage = 0
        best_move = p2_moves[0] if p2_moves else "Struggle"
        
        for move in p2_moves:
            try:
                dmg, _, _ = apply_damage(move, p2_slot, p1_slot, data, data.get(f"{p2_slot}_condition{p2_active}", []))
                if dmg > best_damage:
                    best_damage = dmg
                    best_move = move
            except Exception:
                pass
        
        # Step 3: Check if opponent's move buffs their stats
        opponent_buffs = False
        if not is_player_switch:
            try:
                move_effect = get_move_effect(player_move)[0]
                self_changes = parse_stat_changes(move_effect) or {}
                opponent_buffs = any(v > 0 for v in self_changes.values())
            except Exception:
                pass
        
        # If opponent buffs, check if our highest damage can deal half HP
        if opponent_buffs:
            half_p1_hp = math.ceil(p1_hp * 0.5)
            if best_damage >= half_p1_hp:
                # We can deal half, just attack
                return best_move
            else:
                # Check if we should switch
                number = int(data.get("number", 3) or 3)
                for i in range(1, number + 1):
                    if i == p2_active or data.get(f"{p2_slot}_hp{i}", 0) <= 0:
                        continue
                    
                    switch_poke = data.get(f"{p2_slot}_p{i}")
                    if not switch_poke:
                        continue
                    
                    switch_stats = get_pokemon_stats(switch_poke)[0]
                    switch_hp = data.get(f"{p2_slot}_hp{i}", 1)
                    switch_moves = data.get(f"{p2_slot}_moves{i}", []) or []
                    
                    # Check if this pokemon can defeat opponent
                    for mv in switch_moves:
                        try:
                            dmg, _, _ = apply_damage(mv, p2_slot, p1_slot, data, data.get(f"{p2_slot}_condition{i}", []))
                            # Consider speed to check who moves first after switch
                            opponent_is_faster = (p1_stats[5] if p1_stats else 0) >= (switch_stats[5] if switch_stats else 0)
                            if opponent_is_faster:
                                # Opponent moves first - they'd have buffs already, so damage threshold is higher
                                if dmg >= p1_hp * 0.5:
                                    return f"Switch to {switch_poke}"
                            else:
                                # We move first after switch - can KO
                                if dmg >= p1_hp:
                                    return f"Switch to {switch_poke}"
                        except Exception:
                            pass
        
        # Step 4: If no buff or no good switch, just use highest damage move
        return best_move
    
    except Exception:
        traceback.print_exc()
        return None


async def wait_for_both_choices(file_path):
    """Wait until both players have made their choices."""
    while True:
        data = _load_battle(file_path)
        if data.get("p1_choice") and data.get("p2_choice"):
            return data
        await asyncio.sleep(1)

def placeholder_circle(size=(175, 175)):
    """Return a black circle image as a placeholder."""
    circle = Image.new("RGBA", size, (0, 0, 0, 0))
    draw = ImageDraw.Draw(circle)
    radius = min(size) // 2
    center = (size[0] // 2, size[1] // 2)
    draw.ellipse(
        (center[0] - radius, center[1] - radius,
         center[0] + radius, center[1] + radius),
        fill=(0, 0, 0, 255)
    )
    return circle
import time
import math
from io import BytesIO
from PIL import Image, ImageDraw, ImageFont
def recolor_sprite(sprite: Image.Image, target_color: tuple, threshold=30):
    sprite = sprite.convert("RGBA")
    pixels = sprite.load()
    w, h = sprite.size

    tr, tg, tb = target_color

    for y in range(h):
        for x in range(w):
            r, g, b, a = pixels[x, y]

            if a == 0:
                continue

            if (r > g + threshold and r > b + threshold) or \
               (g > r + threshold and g > b + threshold) or \
               (b > r + threshold and b > g + threshold):

                pixels[x, y] = (tr, tg, tb, a)

    return sprite

def recolor_sprite2(sprite: Image.Image, target_color: tuple, threshold=40, tolerance = 50):
    sprite = sprite.convert("RGBA")
    pixels = sprite.load()
    w, h = sprite.size

    tr, tg, tb = target_color

    white_count = 0
    black_count = 0

    # Pass 1: count
    for y in range(h):
        for x in range(w):
            r, g, b, a = pixels[x, y]
            if a == 0:
                continue

            avg = (r + g + b) // 3
            spread = max(r, g, b) - min(r, g, b)

            if avg > 180 and spread < tolerance:
                white_count += 1
            elif avg < 85 and spread < tolerance:
                black_count += 1

    recolor_white = white_count >= black_count

    # Pass 2: recolor dominant group
    for y in range(h):
        for x in range(w):
            r, g, b, a = pixels[x, y]
            if a == 0:
                continue

            avg = (r + g + b) // 3
            spread = max(r, g, b) - min(r, g, b)

            if recolor_white:
                if avg > 180 and spread < tolerance:
                    pixels[x, y] = (tr, tg, tb, a)
            else:
                if avg < 85 and spread < tolerance:
                    pixels[x, y] = (tr, tg, tb, a)

    return sprite

def add_color_outline(sprite, color=(255, 0, 0), thickness=4):
    """Add a colored outline around a sprite."""
    if sprite.mode != "RGBA":
        sprite = sprite.convert("RGBA")

    alpha = sprite.split()[3]

    outline = Image.new("RGBA", sprite.size, (0, 0, 0, 0))

    for x in range(-thickness, thickness + 1):
        for y in range(-thickness, thickness + 1):
            outline.paste((int(color[0]), int(color[1]), int(color[2]), 255), (x, y), alpha)

    outline.paste(sprite, (0, 0), sprite)
    return outline

def add_red_outline(sprite, thickness=4):
    return add_color_outline(sprite, color=(255, 0, 0), thickness=thickness)

_TYPE_ICON_CACHE = {}

def _get_type_icon(type_name):
    if not type_name:
        return None

    key = str(type_name).lower().strip()

    if key not in _TYPE_ICON_CACHE:
        path = os.path.join("type_emojis", f"{key}.png")

        if not os.path.exists(path):
            return None

        _TYPE_ICON_CACHE[key] = Image.open(path).convert("RGBA")

    return _TYPE_ICON_CACHE[key]
