    def apply_color_mask(sprite, color, intensity=0.3):
        if sprite.mode != "RGBA":
            sprite = sprite.convert("RGBA")
        color_layer = Image.new("RGBA", sprite.size, color + (0,))
        alpha = sprite.split()[3]
        color_layer.putalpha(alpha)
        return Image.blend(sprite, color_layer, intensity)
    def draw_shard_name(layer, text, hp_top_left, fill_inside=None, shard="♦", player_name=False):
        fill_inside = None
        font = _fnt(18, True)
        if not text:
            return
        
        draw = ImageDraw.Draw(layer)
        x, y = hp_top_left
        if player_name:
            y -= 10
            
        full_text = f"{shard} {text}"
        max_width = hp_bar_width

        # =========================
        # Multiline word wrap if too wide
        # =========================
        bbox = draw.textbbox((0, 0), full_text, font=font)
        if bbox[2] - bbox[0] > max_width and " " in full_text:
            parts = full_text.split(" ")
            midpoint = len(parts) // 2
            
            # Adjust midpoint if it makes string lengths more balanced
            line1 = " ".join(parts[:midpoint])
            line2 = " ".join(parts[midpoint:])
            full_text = line1 + "\n" + line2

        # Split into individual lines for processing
        lines = full_text.split("\n")
        
        # Get font height metrics for uniform spacing
        ascent, descent = font.getmetrics()
        line_step = ascent + descent

        # Calculate exact total multiline bounding box height
        m_bbox = draw.multiline_textbbox((0, 0), full_text, font=font, spacing=0)
        text_h = m_bbox[3] - m_bbox[1]
        base_ty = y - text_h - 3

        # Pre-compute layout positions for each line to ensure perfect centering
        line_layouts = []
        for i, line in enumerate(lines):
            l_bbox = draw.textbbox((0, 0), line, font=font)
            lw = l_bbox[2] - l_bbox[0]
            
            tx_line = x + (hp_bar_width - lw) // 2
            ty_line = base_ty + (i * line_step)
            line_layouts.append((line, tx_line, ty_line))

        # =========================
        # Tier gradients color configuration
        # =========================
        if "(H)" in text:
            colors = [(80, 255, 80), (0, 160, 40)]
        elif "(Li+)" in text:
            colors = [(100, 255, 255), (0, 150, 220)]
        elif "(Na+)" in text:
            colors = [(100, 180, 255), (0, 60, 255)]
        elif "(K+)" in text:
            colors = [(220, 120, 255), (90, 0, 180)]
        elif "(Rb+)" in text or player_name:
            colors = [(255, 255, 120), (255, 180, 0), (180, 100, 0)]
        elif "(Fr+)" in text:
            colors = [(255, 0, 0), (255, 120, 0), (255, 255, 0), (0, 255, 0), (0, 180, 255), (80, 0, 255)]
        else:
            colors = [fill_inside or (255, 255, 255), (150, 150, 150)]

        # =========================
        # PASS 1: Draw All Shadows (Bottom Layer)
        # =========================
        for line, tx, ty in line_layouts:
            draw.text(
                (tx + 2, ty + 2),
                line,
                font=font,
                fill=(0, 0, 0),
                stroke_width=4,
                stroke_fill=(0, 0, 0)
            )

        # =========================
        # PASS 2: Gradient Fill (Middle Layer)
        # =========================
        for line, tx, ty in line_layouts:
            # Create a precise localized mask for this line
            line_mask = Image.new("L", layer.size, 0)
            lm_draw = ImageDraw.Draw(line_mask)
            lm_draw.text((tx, ty), line, font=font, fill=255)
            
            # Find exact pixel bounding boundaries for this line's placement
            bx1, by1, bx2, by2 = lm_draw.textbbox((tx, ty), line, font=font)
            elw = max(1, bx2 - bx1)
            elh = max(1, by2 - by1)
            
            # Build a localized horizontal gradient matching this row's width
            grad_slice = Image.new("RGBA", (elw, elh))
            gs_load = grad_slice.load()
            for xx in range(elw):
                progress = xx / max(1, elw - 1)
                pos = progress * (len(colors) - 1)
                idx = int(pos)
                if idx >= len(colors) - 1:
                    idx = len(colors) - 2
                frac = pos - idx
                c1 = colors[idx]
                c2 = colors[idx + 1]
                col = (
                    int(c1[0] * (1 - frac) + c2[0] * frac),
                    int(c1[1] * (1 - frac) + c2[1] * frac),
                    int(c1[2] * (1 - frac) + c2[2] * frac),
                    255
                )
                for yy in range(elh):
                    gs_load[xx, yy] = col
            
            # Project slice back onto global sizing canvas and apply through mask
            gradient_canvas = Image.new("RGBA", layer.size, (0, 0, 0, 0))
            gradient_canvas.paste(grad_slice, (bx1, by1))
            layer.paste(gradient_canvas, (0, 0), line_mask)

        # =========================
        # PASS 3: White Outlines (Top Layer)
        # =========================
        outline = Image.new("RGBA", layer.size, (0, 0, 0, 0))
        outline_draw = ImageDraw.Draw(outline)
        for line, tx, ty in line_layouts:
            outline_draw.text(
                (tx, ty),
                line,
                font=font,
                fill=(0, 0, 0, 0),
                stroke_width=2,
                stroke_fill=(255, 255, 255)
            )
        layer.alpha_composite(outline)
    def resize_or_placeholder(sprite, scale=1.0):
        if sprite is None:
            sprite = placeholder_circle(size=(125, 125))

        w, h = sprite.size
        mean = (w+h)/2
        new_w = int(w * scale * 125 / mean)
        new_h = int(h * scale * 125 / mean)

        return sprite.resize((new_w, new_h), Image.LANCZOS)
    
