    p2_center = (p2_pos[0] + p2_sprite.width // 2, p2_pos[1] + p2_sprite.height // 2)

    #font_path = os.path.join("font", "Arial.ttf")
    #try:
    #    name_font = ImageFont.truetype(font_path, 18)
    #    print("Loaded custom font")
    #except Exception as e:
    #    print("Font failed:", e)
    #    name_font = ImageFont.truetype("arial.ttf", 18)
    name_font = _fnt(18, True)
    hp_bar_width = 120
    hp_bar_height = 14
    def draw_hp_bar(draw, current_hp, max_hp, top_left, type: str = "normal"):
        bar_width = hp_bar_width
        bar_height = hp_bar_height

        x, y = top_left

        ratio = max(
            0,
            min(1, current_hp / max(1, max_hp))
        )

        hp_width = int(bar_width * ratio)


        # =====================
        # outer shadow
        # =====================

        draw.rounded_rectangle(
            [
                x-3,
                y-3,
                x+bar_width+3,
                y+bar_height+3
            ],
            radius=6,
            fill=(0,0,0)
        )


        # =====================
        # outer border
        # =====================

        draw.rounded_rectangle(
            [
                x-1,
                y-1,
                x+bar_width+1,
                y+bar_height+1
            ],
            radius=5,
            fill=(180,180,180)
        )


        # =====================
        # empty background
        # =====================

        # Toggle background to white if type is cosmic
        bg_fill = (255, 255, 255) if type == "cosmic" else (45, 45, 45)

        draw.rounded_rectangle(
            [
                x,
                y,
                x+bar_width,
                y+bar_height
            ],
            radius=4,
            fill=bg_fill
        )


        # =====================
        # plant-like object on the right
        # =====================
        if type == "cosmic":
            orb_radius = max(8, bar_height)
            orb_cx = x + bar_width + orb_radius
            orb_cy = y + bar_height // 2
            
            draw.ellipse(
                [orb_cx - orb_radius, orb_cy - orb_radius, orb_cx + orb_radius, orb_cy + orb_radius], 
                fill=(255, 0, 0) 
            )
            draw.ellipse(
                [orb_cx - orb_radius + 3, orb_cy - orb_radius + 3, orb_cx + orb_radius - 3, orb_cy + orb_radius - 3], 
                fill=(255, 243, 0)  
            )


        if hp_width <= 0:
            return

        # =====================
        # hp gradient
        # =====================

        if type != "cosmic":
            if ratio > 0.5:
                c1 = (80,255,80)
                c2 = (0,150,0)

            elif ratio > 0.2:
                c1 = (255,240,80)
                c2 = (220,130,0)

            else:
                c1 = (255,80,80)
                c2 = (180,0,0)



        hp_layer = Image.new(
            "RGBA",
            (
                hp_width,
                bar_height
            ),
            (0,0,0,0)
        )


        pixels = hp_layer.load()


        for xx in range(hp_width):

            t = xx / max(1, hp_width-1)

            if type == "cosmic":
                # Smooth 3-way interpolation spanning Blue -> Purple -> Violet
                if t < 0.5:
                    t2 = t * 2
                    # Interpolating from Deep Blue (0, 100, 255) to Royal Purple (130, 0, 255)
                    r = int(0 * (1 - t2) + 130 * t2)
                    g = int(100 * (1 - t2) + 0 * t2)
                    b = int(255 * (1 - t2) + 255 * t2)
                else:
                    t2 = (t - 0.5) * 2
                    # Interpolating from Royal Purple (130, 0, 255) to Cosmic Violet (238, 130, 238)
                    r = int(130 * (1 - t2) + 238 * t2)
                    g = int(0 * (1 - t2) + 130 * t2)
                    b = int(255 * (1 - t2) + 238 * t2)
                
                color = (r, g, b, 255)
            else:
                color = (
                    int(c1[0]*(1-t)+c2[0]*t),
                    int(c1[1]*(1-t)+c2[1]*t),
                    int(c1[2]*(1-t)+c2[2]*t),
                    255
                )

            for yy in range(bar_height):
                pixels[xx,yy] = color



        # =====================
        # paste rounded hp
        # =====================

        hp_mask = Image.new(
            "L",
            hp_layer.size,
            0
        )

        ImageDraw.Draw(hp_mask).rounded_rectangle(
            [
                0,
                0,
                hp_width,
                bar_height
            ],
            radius=4,
            fill=255
        )


        draw._image.paste(
            hp_layer,
            (
                x,
                y
            ),
            hp_mask
        )

        draw.text(
            (x+bar_width//2+30,y),
            f"{round(current_hp/max_hp*100)}%",
            font=_fnt(12, True),
            fill=(255,255,255),
            stroke_width=2,
            stroke_fill=(0,0,0)
        )


    def shorten_name(text, draw):
        if not text:
            return None
        txt = str(text)
        bar_width = 200
        while len(txt) > 1:
            bbox = draw.textbbox((0, 0), txt, font=name_font)
            if (bbox[2] - bbox[0]) <= bar_width:
                break
            if len(txt) <= 4:
                txt = txt[:1]
                break
            txt = txt[:-4] + "..."
        return txt

