    def draw_name(draw, text, hp_top_left, fill_inside = (255, 255, 255)):
        if not text:
            return
        x, y = hp_top_left
        bbox = draw.textbbox((0, 0), text, font=name_font)
        text_w = bbox[2] - bbox[0]
        text_h = bbox[3] - bbox[1]
        tx = x + max(0, (hp_bar_width - text_w) // 2)
        ty = y - text_h - 3
        draw.text((tx + 1, ty + 1), text, fill=(0, 0, 0), font=name_font)
        draw.text((tx, ty), text, fill=fill_inside, font=name_font)
    def gradient_text(
        layer,
        position,
        text,
        font,
        colors
    ):
        mask = Image.new(
            "L",
            layer.size
        )

        md = ImageDraw.Draw(mask)

        md.text(
            position,
            text,
            font=font,
            fill=255,
            stroke_width=0
        )


        grad = Image.new(
            "RGBA",
            layer.size
        )

        px = grad.load()

        for y in range(layer.height):
            t = y / layer.height

            r = int(colors[0][0]*(1-t)+colors[1][0]*t)
            g = int(colors[0][1]*(1-t)+colors[1][1]*t)
            b = int(colors[0][2]*(1-t)+colors[1][2]*t)

            for x in range(layer.width):
                px[x,y]=(r,g,b,255)


        layer.paste(
            grad,
            (0,0),
            mask
        )

    def draw_pokeball_row(layer: Image.Image, hp_top_left, states):
        if not states:
            return
        x, y = hp_top_left
        start_x = int(x)
        start_y = int(y + hp_bar_height + 4)
        for i, is_alive in enumerate(states):
            icon = _get_cached_battle_pokeball("alive" if is_alive else "fainted", size=(15, 15))
            layer.paste(icon, (start_x + i * 17, start_y), icon)

