    player2_msg_parts = []

    if isinstance(data.get("raid_battle"), dict) and str(data.get("mode", "")).strip().lower() == PVE_MODE_RAID:
        current_round = int(data.get("round_id", 0) or 0)
        atk_boost = _raid_enraged_atk_boost(current_round)
        if atk_boost:
            stages = _normalize_stage_list(data.get(f"p2_status{p2_active}") or [0] * 6)
            stages[1] = int(stages[1] or 0) + atk_boost
            if stages[1] < 0:
                stages[1] = 0
                atk_boost = atk_boost + 1
            data[f"p2_status{p2_active}"] = stages
            player2_msg_parts.append(f"Boss is enraged, attack increased by {atk_boost}")

    # Handle switches
    def switch_pokemon(slot, choice):
        if not choice.startswith("Switch to "):
            return

        target_name = _parse_switch_target(choice)
        number = data['number']

        # Get original order
        order_key = f"{slot}_order"
        original_order = data.get(order_key)
        if not isinstance(original_order, list) or not original_order:
            original_order = [data.get(f"{slot}_p{i}") for i in range(1, number + 1)]
            data[order_key] = original_order

        if target_name not in original_order:
            return  # Pokémon not found or already front

        # Handle Regenerator for the Pokémon currently in front
        active_idx = get_active(slot, data)
        active_name = data[f"{slot}_p{active_idx}"]
        ability = data.get(f'{slot}_ability{active_idx}')
        stats, types = get_pokemon_stats(active_name)
        ev = data[f"{slot}_ev{active_idx}"]
        max_hp = (2 * stats[0] + 31 + ev[0]//4 + 110)
        heal = math.floor(max_hp * 0.33)
        if ability == 'regenerator':
            data[f"{slot}_hp{active_idx}"] = min(
                data[f"{slot}_hp{active_idx}"] + heal,
                max_hp
            )
            if slot == "p1":
                player_msg_parts.append(f'Regenerated {heal} HP by Regenerator')
            elif slot == "p2":
                player2_msg_parts.append(f'Regenerated {heal} HP by Regenerator')
        if "spiked" in data[f'{slot}_condition{active_idx}']:
            data[f'{slot}_condition{active_idx}'].remove("spiked")
        if "tspiked" in data[f'{slot}_condition{active_idx}']:
            data[f'{slot}_condition{active_idx}'].remove("tspiked")
        if "rock" in data[f'{slot}_condition{active_idx}']:
            data[f'{slot}_condition{active_idx}'].remove("rock")
        if "sticked" in data[f'{slot}_condition{active_idx}']:
            data[f'{slot}_condition{active_idx}'].remove("sticked")
        data[f"{slot}_status{active_idx}"] = [0]*6

        # Create new order: switched-in Pokémon goes first
        new_order = [target_name] + [n for n in original_order if n != target_name]

        # Map current Pokémon name to their fields
        keys = ["p", "hp", "stats", "nature", "moves", "status", "ability", "hi", "cosmetic", "condition", "charge"]
        name_to_fields = {
            data[f"{slot}_p{i}"]: {k: data[f"{slot}_{k}{i}"] for k in keys}
            for i in range(1, number + 1)
        }

        # Reassign fields according to new order
        for i, name in enumerate(new_order, start=1):
            fields = name_to_fields[name]
            for k in keys:
                data[f"{slot}_{k}{i}"] = fields[k]
        data[f"{slot}_choice_lock_move"] = None
        data[f"{slot}_choice_lock_name"] = None
        active_idx = get_active(slot, data)
        active_name = data[f"{slot}_p{active_idx}"]
        ability = data.get(f'{slot}_ability{active_idx}')
        stats, types = get_pokemon_stats(active_name)
        ev = data[f"{slot}_ev{active_idx}"]
        max_hp = (2 * stats[0] + 31 + ev[0]//4 + 110)
        field = data[f'{slot}_field'] or []
        spikes_count = min(field.count("spikes"), 3)
        if "stealth rock" in field:
            eff = get_effectiveness("rock", types)
            data[f"{slot}_hp{active_idx}"] -= max_hp/8*eff
            data[f"{slot}_condition{active_idx}"].append('rock')
            if slot == "p1":
                player_msg_parts.append('Taken damage from stealth rock')
            elif slot == "p2":
                player2_msg_parts.append('Taken damage from stealth rock')
        if "flying" not in types:
            if "spikes" in field:
                data[f"{slot}_hp{active_idx}"] -= max_hp/8*(1+ (spikes_count-1)/3)
                data[f"{slot}_condition{active_idx}"].append('spiked')
                if slot == "p1":
                    player_msg_parts.append(f'Taken damage from {spikes_count} spikes')
                elif slot == "p2":
                    player2_msg_parts.append(f'Taken damage from {spikes_count} spikes')
        if "toxic spikes" in field:
            data[f"{slot}_condition{active_idx}"].append('poison')
            data[f"{slot}_condition{active_idx}"].append('tspiked')
            if slot == "p1":
                player_msg_parts.append('Poisoned by toxic spikes')
            elif slot == "p2":
                player2_msg_parts.append('Poisoned by toxic spikes')
        if simplified_mode and "sticky web" in field:
            stages = data.get(f"{slot}_status{active_idx}") or [0] * 6
            data[f"{slot}_condition{active_idx}"].append('sticked')
            if len(stages) < 6:
                stages = (stages + [0] * 6)[:6]
            stages[5] = max(-6, int(stages[5]) - 1)
            data[f"{slot}_status{active_idx}"] = stages
            if slot == "p1":
                player_msg_parts.append('Speed fell by 1 from Sticky Web')
            elif slot == "p2":
                player2_msg_parts.append('Speed fell by 1 from Sticky Web')

