        def _has_tag(cond_list: list, tag: str) -> bool:
            return any(str(x).strip().lower() == str(tag).strip().lower() for x in (cond_list or []))

        def _remove_tag(cond_list: list, tag: str) -> list:
            lower_tag = str(tag).strip().lower()
            return [x for x in (cond_list or []) if str(x).strip().lower() != lower_tag]

