        def _consume_lock(condition_list, current_attack):
            if current_attack is None:
                return current_attack, False
            for lock_move in ("outrage", "raging fury"):
                lock_tag = f"lock::{lock_move}"
                if lock_tag in condition_list:
                    condition_list.remove(lock_tag)
                    return lock_move, True
                if lock_move in condition_list:
                    condition_list.remove(lock_move)
                    return lock_move, True
            return current_attack, False

        def _trigger_defensive_abilities(attacker_move, defender_slot, defender_active, defender_ability, actual_dmg, msg_parts):
            if actual_dmg <= 0 or not defender_ability:
                return
            defender_ability = str(defender_ability).strip().lower()
            try:
                stages = data.get(f"{defender_slot}_status{defender_active}") or [0] * 6
                if len(stages) < 6:
                    stages = (stages + [0] * 6)[:6]
            except Exception:
                stages = [0] * 6
            move_type = ""
            if isinstance(attacker_move, str) and attacker_move.startswith("ZMOVE::"):
                try:
                    _, move_type, _ = attacker_move.split("::", 2)
                except Exception:
                    move_type = ""
            elif attacker_move:
                try:
                    move_type = str(get_move_info(attacker_move)[2] or "").lower()
                except Exception:
                    move_type = ""
            if defender_ability == "stamina":
                stages[2] = min(6, int(stages[2]) + 1)
                data[f"{defender_slot}_status{defender_active}"] = stages
                msg_parts.append("Increased Defense stage by 1 through Stamina")
            if defender_ability == "justified" and move_type == "dark":
                stages[1] = min(6, int(stages[1]) + 1)
                data[f"{defender_slot}_status{defender_active}"] = stages
                msg_parts.append("Increased Attack stage by 1 through Justified")

        p1_attack, p1_forced_lock = _consume_lock(p1_condition, p1_attack)
        p2_attack, p2_forced_lock = _consume_lock(p2_condition, p2_attack)

