                    if tm1 >= 2 and dmg1 > 0 and p2_hi == "weakness policy" and "policy_active" not in data[f"{p2_slot}_condition{p2_active}"]:
                        data[f"{p2_slot}_status{p2_active}"][1] += 2
                        data[f"{p2_slot}_status{p2_active}"][3] += 2
