VOTES_DB_PATH = "cosmetics.db"   # ← DB containing vote_progress table
ELO_DB_PATH   = "elo.db"   # ← DB containing elo/rating table

_ELO_TIERS = [
    (1700, 21),
    (1600, 18),
    (1500, 15),
    (1400,  12),
    (1300,  9),
    (1200,  6),
    (1100,  3),
]


def _get_dynamic_ticket_limit(user_id: int) -> tuple[int, int, int, int]:
    """
    Returns (total_limit, wins_bonus, elo_bonus, votes_bonus).
    Base : 10
    Wins : +5 per 100 wins (uncapped)
    ELO  : +2/3/5/7/10/14/19 at 1.1k/1.2k/1.3k/1.4k/1.5k/1.6k/1.7k+
    Votes: +1/+2/+3 at 100/200/300+ votes (capped at +3)
    """
    base = 10
    wins_bonus = elo_bonus = votes_bonus = 0

    try:
        # Get wins from both ranked queue types
        _, ranked_rare_wins, _ = get_ranked_stats(user_id, "ranked rare")
        _, ranked_common_wins, _ = get_ranked_stats(user_id, "ranked common")
        total_ranked_wins = ranked_rare_wins + ranked_common_wins
        if total_ranked_wins:
            wins_bonus = (total_ranked_wins // 100) * 5
    except Exception:
        traceback.print_exc()

    try:
        conn = sqlite3.connect(ELO_DB_PATH)
        c = conn.cursor()
        c.execute("SELECT MAX(rating) FROM ranked_elo WHERE user_id = ?", (user_id,))
        row = c.fetchone()
        if row and row[0]:
            rating = int(row[0])
            # Sum every tier the player has reached
            elo_bonus = sum(
                bonus for threshold, bonus in _ELO_TIERS if rating >= threshold
            )
        conn.close()
    except Exception:
        traceback.print_exc()
        

    try:
        conn = sqlite3.connect(VOTES_DB_PATH)
        c = conn.cursor()
        c.execute("SELECT total_votes FROM vote_progress WHERE user_id = ?", (user_id,))
        row = c.fetchone()
        if row and row[0]:
            votes_bonus = 0
            if row[0] > 100:
                votes_bonus += 3
            if row[0] > 200:
                votes_bonus += 4
            if row[0] > 300:
                votes_bonus += 5
            if row[0] > 400:
                votes = int(row[0]) - 400
                votes_bonus += 5 * vote // 100
        conn.close()
        print(votes_bonus)
    except Exception:
        traceback.print_exc()

    return base + wins_bonus + elo_bonus + votes_bonus, wins_bonus, elo_bonus, votes_bonus

def process_event_ticket_reward(user_id: int) -> tuple[bool, int, int]:
    """
    Grants 1 event ticket to user_id if under their dynamic daily limit.
    Returns (granted, daily_count_after, limit).
    """
    import datetime
    today = datetime.datetime.utcnow().date().isoformat()
    limit, _, _, _ = _get_dynamic_ticket_limit(user_id)

    conn = sqlite3.connect("cosmetics.db")
    c = conn.cursor()
    _ensure_event_ticket_table(c)

    c.execute(
        'INSERT OR IGNORE INTO "event ticket" (user_id, amount, daily_count, daily_date) '
        'VALUES (?, 0, 0, ?)', (user_id, today)
    )
    c.execute(
        'SELECT amount, daily_count, daily_date FROM "event ticket" WHERE user_id = ?',
        (user_id,)
    )
    row = c.fetchone() or (0, 0, today)
    cur_amount  = int(row[0] or 0)
    daily_count = int(row[1] or 0)
    daily_date  = row[2] or ""

    if daily_date != today:
        daily_count = 0
        daily_date  = today

    granted = False
    amount = 0
    if daily_count < limit:
        if random.random() < (limit-daily_count)/10:
            amount = 2
        else:
            amount = 1
        cur_amount  += amount
        daily_count += amount
        granted      = True
        c.execute(
            'UPDATE "event ticket" SET amount = ?, daily_count = ?, daily_date = ? '
            'WHERE user_id = ?',
            (cur_amount, daily_count, daily_date, user_id)
        )
    else:
        c.execute(
            'UPDATE "event ticket" SET daily_count = ?, daily_date = ? WHERE user_id = ?',
            (daily_count, daily_date, user_id)
        )

    conn.commit()
    conn.close()
    return granted, daily_count, limit, amount


