HERO_LEADERBOARD_LOCKED = False

VERIFICATION_MAP = {
    "none": discord.VerificationLevel.none,
    "low": discord.VerificationLevel.low,
    "medium": discord.VerificationLevel.medium,
    "high": discord.VerificationLevel.high,
    "highest": discord.VerificationLevel.highest
}

@bot.command()
@commands.has_permissions(manage_guild=True)
async def set_verification(ctx, level: str = None):
    if level is None:
        await ctx.send(
            "Usage: !set_verification <none|low|medium|high|highest>"
        )
        return

    level = level.lower()

    if level not in VERIFICATION_MAP:
        await ctx.send("Invalid level. Choose: none, low, medium, high, highest")
        return

    try:
        await ctx.guild.edit(verification_level=VERIFICATION_MAP[level])
        await ctx.send(f"✅ Verification level set to **{level}**")
    except discord.Forbidden:
        await ctx.send("❌ I don't have permission to change this.")
    except Exception as e:
        await ctx.send(f"Error: {e}")
def _safe_int_user_id(value):
    try:
        return int(value)
    except (TypeError, ValueError):
        return None


def _normalize_battle_pair_key(p1_id, p2_id):
    p1 = _safe_int_user_id(p1_id)
    p2 = _safe_int_user_id(p2_id)
    if p1 is None or p2 is None or p1 == p2:
        return None
    low_id, high_id = sorted((p1, p2))
    return f"{low_id}:{high_id}"


def _init_battle_reward_tables(cursor):
    cursor.execute(
        "SELECT name FROM sqlite_master WHERE type='table' AND name='titan point'"
    )
    has_titan = cursor.fetchone() is not None
    cursor.execute(
        "SELECT name FROM sqlite_master WHERE type='table' AND name='achilles point'"
    )
    has_achilles = cursor.fetchone() is not None
    if has_titan and not has_achilles:
        cursor.execute('ALTER TABLE "titan point" RENAME TO "achilles point"')
    cursor.execute(
        """
        CREATE TABLE IF NOT EXISTS "achilles point" (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0
        )
        """
    )
    cursor.execute(
        """
        CREATE TABLE IF NOT EXISTS "hero point" (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0
        )
        """
    )
    cursor.execute(
        """
        CREATE TABLE IF NOT EXISTS battle_reward_winners (
            reward_type TEXT,
            user_id INTEGER,
            UNIQUE(reward_type, user_id)
        )
        """
    )
    cursor.execute(
        """
        CREATE TABLE IF NOT EXISTS embed_color (
            user_id INTEGER PRIMARY KEY,
            available_colors TEXT
        )
        """
    )
    cursor.execute(
        """
        CREATE TABLE IF NOT EXISTS "exchange coupon" (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0
        )
        """
    )
    cursor.execute(
        """
        CREATE TABLE IF NOT EXISTS battle_reward_meta (
            key TEXT PRIMARY KEY,
            value TEXT NOT NULL
        )
        """
    )
    cursor.execute(
        "INSERT OR IGNORE INTO battle_reward_meta (key, value) VALUES ('titan_enabled', '1')"
    )
    cursor.execute(
        "INSERT OR IGNORE INTO battle_reward_meta (key, value) VALUES ('achilles_enabled', '1')"
    )
    cursor.execute(
        "INSERT OR IGNORE INTO battle_reward_meta (key, value) VALUES ('achilles_started', '0')"
    )
    cursor.execute(
        "INSERT OR IGNORE INTO battle_reward_meta (key, value) VALUES ('hero_enabled', '1')"
    )


def _init_arc_limit_tables(cursor):
    cursor.execute(
        """
        CREATE TABLE IF NOT EXISTS arc_daily_limit (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0,
            last_reset REAL DEFAULT 0
        )
        """
    )


def _meta_flag(cursor, key, default=True):
    cursor.execute("SELECT value FROM battle_reward_meta WHERE key = ?", (key,))
    row = cursor.fetchone()
    if not row:
        return default
    return str(row[0]).strip() == "1"


def _set_meta_flag(cursor, key, enabled):
    cursor.execute(
        """
        INSERT INTO battle_reward_meta (key, value) VALUES (?, ?)
        ON CONFLICT(key) DO UPDATE SET value = excluded.value
        """,
        (key, "1" if enabled else "0"),
    )


def _start_achilles_event_if_needed(cursor) -> bool:
    titan_enabled_flag = _meta_flag(cursor, "titan_enabled", default=True)
    achilles_started = _meta_flag(cursor, "achilles_started", default=False)
    if not achilles_started and not titan_enabled_flag:
        cursor.execute(
            "DELETE FROM battle_reward_winners WHERE reward_type IN ('achilles','titan')"
        )
        _set_meta_flag(cursor, "achilles_enabled", True)
        _set_meta_flag(cursor, "achilles_started", True)
        return True
    return False


def _consume_pair_reward_slot(p1_id, p2_id):
    pair_key = _normalize_battle_pair_key(p1_id, p2_id)
    if not pair_key:
        return False, 0

    now = time.time()
    window = int(now // BATTLE_PAIR_TRACK_TTL_SECONDS)

    entry = battle_pair_tracker.get(pair_key)

    # reset if new window
    if not entry or entry.get("window") != window:
        entry = {"count": 0, "window": window}

    current = int(entry.get("count", 0))

    if current >= BATTLE_REWARD_LIMIT_PER_PAIR:
        battle_pair_tracker[pair_key] = entry
        return False, current

    entry["count"] = current + 1
    battle_pair_tracker[pair_key] = entry

    return True, int(entry["count"])


def _append_battle_reward(cache, user_id, reward_name, amount, reason="battle"):
    if user_id is None:
        return
    cache[user_id].append(
        {"reward": reward_name, "amount": int(amount), "reason": reason}
    )


battle_reward_cache = defaultdict(list)
battle_reward_lock = asyncio.Lock()
battle_pair_tracker = {}


@tasks.loop(minutes=1)
async def reset_rank_rare_counter():
    global RANK_RARE_NUMBER
    RANK_RARE_NUMBER = 0

@tasks.loop(minutes=30)
async def cleanup_battle_pair_tracker():
    now = time.time()
    async with battle_reward_lock:
        if not battle_pair_tracker:
            return
        stale_keys = [
            key
            for key, value in battle_pair_tracker.items()
            if now - float((value or {}).get("last_seen", 0)) > BATTLE_PAIR_TRACK_TTL_SECONDS
        ]
        for key in stale_keys:
            battle_pair_tracker.pop(key, None)


@tasks.loop(seconds=15)
async def reward_processor():
    async with battle_reward_lock:
        pending_rewards = dict(battle_reward_cache)
        battle_reward_cache.clear()

    dm_lines = defaultdict(list)

    try:
        with connect_poke_db(timeout=30) as poke_conn, \
             sqlite3.connect("cosmetics.db", timeout=30) as cosmetics_conn, \
             sqlite3.connect("limit.db", timeout=30) as limit_conn:
             
            poke_cursor = poke_conn.cursor()
            cosmetics_cursor = cosmetics_conn.cursor()
            limit_cursor = limit_conn.cursor()
            
            _init_battle_reward_tables(cosmetics_cursor)
            _init_arc_limit_tables(limit_cursor)

            if not pending_rewards:
                cosmetics_conn.commit()
                limit_conn.commit()
                poke_conn.commit()
                return

            # --- PROCESS INCOMING POINTS ---
            for user_id, rewards in pending_rewards.items():
                total_coins = sum(int(r.get("amount", 0)) for r in rewards if r.get("reward") == "coins")
                total_achilles = sum(int(r.get("amount", 0)) for r in rewards if r.get("reward") == "achilles point")
                total_hero = sum(int(r.get("amount", 0)) for r in rewards if r.get("reward") == "hero point")
                total_tickets = sum(int(r.get("amount", 0)) for r in rewards if r.get("reward") == "event_ticket")

                # Daily ARC Coin Cap processing
                now = time.time()
                limit_cursor.execute("SELECT amount, last_reset FROM arc_daily_limit WHERE user_id = ?", (user_id,))
                row = limit_cursor.fetchone()
                limit_amount = int(row[0]) if row and row[0] is not None else 0
                last_reset = float(row[1]) if row and row[1] is not None else 0
                if now - last_reset >= ARC_DAILY_RESET_SECONDS:
                    limit_amount = 0
                    last_reset = now

                remaining = ARC_DAILY_CAP - limit_amount
                if remaining <= 0:
                    if total_coins > 0:
                        dm_lines[user_id].append("Daily ARC limit reached. ARCs were not granted.")
                    total_coins = 0
                elif total_coins > 0:
                    allowed_coins = min(total_coins, remaining)
                    if allowed_coins <= 0:
                        dm_lines[user_id].append("Daily ARC limit reached. ARCs were not granted.")
                        total_coins = 0
                    else:
                        if allowed_coins < total_coins:
                            dm_lines[user_id].append(f"Daily ARC limit reached. +{allowed_coins} coins granted (cap {ARC_DAILY_CAP}/day).")
                        total_coins = allowed_coins
                        limit_amount += allowed_coins
                        limit_cursor.execute(
                            """
                            INSERT INTO arc_daily_limit (user_id, amount, last_reset)
                            VALUES (?, ?, ?)
                            ON CONFLICT(user_id) DO UPDATE SET amount = excluded.amount, last_reset = excluded.last_reset
                            """,
                            (user_id, limit_amount, last_reset),
                        )

                # Grant Coins
                if total_coins > 0:
                    poke_cursor.execute("UPDATE poke SET coins = coins + ? WHERE player_id = ?", (total_coins, user_id))
                    dm_lines[user_id].append(f"+{total_coins} coins")

                # Grant Achilles Points
                if total_achilles > 0:
                    cosmetics_cursor.execute(
                        """
                        INSERT INTO "achilles point" (user_id, amount)
                        VALUES (?, ?)
                        ON CONFLICT(user_id) DO UPDATE SET amount = amount + excluded.amount
                        """,
                        (user_id, total_achilles),
                    )
                    dm_lines[user_id].append(f"+{total_achilles} {ACHILLES_POINT_NAME}")

                # Grant Hero Points
                if total_hero > 0:
                    cosmetics_cursor.execute(
                        """
                        INSERT INTO "hero point" (user_id, amount)
                        VALUES (?, ?)
                        ON CONFLICT(user_id) DO UPDATE SET amount = amount + excluded.amount
                        """,
                        (user_id, total_hero),
                    )
                    dm_lines[user_id].append(f"+{total_hero} {HERO_POINT_NAME}")

                # Grant event tickets
                if total_tickets > 0:
                    granted = _grant_event_ticket_for_win(user_id, total_tickets, cursor=cosmetics_cursor, conn=cosmetics_conn)
                    if granted > 0:
                        dm_lines[user_id].append(f"+{granted} event ticket")
                    else:
                        dm_lines[user_id].append("Event ticket daily cap reached. No tickets granted.")

            # --- BREAKPOINT CHECK: ACHILLES ---
            cosmetics_cursor.execute(
                'SELECT user_id FROM "achilles point" WHERE amount >= ? ORDER BY amount DESC',
                (ACHILLES_POINT_MILESTONE,),
            )
            eligible_achilles = [r[0] for r in cosmetics_cursor.fetchall() if r and r[0] is not None]

            for user_id in eligible_achilles:
                # Reset points immediately so they don't get trapped in this query block on the next execution loop
                cosmetics_cursor.execute('UPDATE "achilles point" SET amount = 0 WHERE user_id = ?', (user_id,))
                
                # Check allocation caps right now
                cosmetics_cursor.execute("SELECT COUNT(*) FROM battle_reward_winners WHERE reward_type = 'achilles'")
                achilles_winners = int(cosmetics_cursor.fetchone()[0] or 0)
                
                if achilles_winners < SPECIAL_REWARD_WINNER_CAP:
                    cosmetics_cursor.execute(
                        "SELECT 1 FROM battle_reward_winners WHERE user_id = ? AND reward_type = 'achilles'",
                        (user_id,),
                    )
                    if cosmetics_cursor.fetchone() is None:
                        cosmetics_cursor.execute(
                            "INSERT INTO battle_reward_winners (reward_type, user_id) VALUES ('achilles', ?)",
                            (user_id,),
                        )
                        _append_pokemon_cosmetic(
                            cosmetics_cursor, user_id, ACHILLES_PRIZE["pokemon"], ACHILLES_PRIZE["cosmetic"]
                        )
                        dm_lines[user_id].append(
                            f"🎉 You reached the Milestone! Unlocked cosmetic: {ACHILLES_PRIZE['pokemon']} [{ACHILLES_PRIZE['cosmetic']}]"
                        )
                else:
                    dm_lines[user_id].append(
                        f"ℹ️ You hit the {ACHILLES_POINT_NAME} breakpoint, but all {SPECIAL_REWARD_WINNER_CAP} reward slots have been claimed!"
                    )

            # --- BREAKPOINT CHECK: HERO ---
            cosmetics_cursor.execute(
                'SELECT user_id FROM "hero point" WHERE amount >= ? ORDER BY amount DESC',
                (HERO_POINT_MILESTONE,),
            )
            eligible_hero = [r[0] for r in cosmetics_cursor.fetchall() if r and r[0] is not None]

            for user_id in eligible_hero:
                # Reset points immediately
                cosmetics_cursor.execute('UPDATE "hero point" SET amount = 0 WHERE user_id = ?', (user_id,))
                
                # Check allocation caps right now
                cosmetics_cursor.execute("SELECT COUNT(*) FROM battle_reward_winners WHERE reward_type = 'hero'")
                hero_winners = int(cosmetics_cursor.fetchone()[0] or 0)
                
                if hero_winners < SPECIAL_REWARD_WINNER_CAP:
                    cosmetics_cursor.execute(
                        "SELECT 1 FROM battle_reward_winners WHERE user_id = ? AND reward_type = 'hero'",
                        (user_id,),
                    )
                    if cosmetics_cursor.fetchone() is None:
                        cosmetics_cursor.execute(
                            "INSERT INTO battle_reward_winners (reward_type, user_id) VALUES ('hero', ?)",
                            (user_id,),
                        )
                        _append_pokemon_cosmetic(
                            cosmetics_cursor, user_id, HERO_PRIZE["pokemon"], HERO_PRIZE["cosmetic"]
                        )
                        dm_lines[user_id].append(
                            f"🎉 You reached the Milestone! Unlocked cosmetic: {HERO_PRIZE['pokemon']} [{HERO_PRIZE['cosmetic']}]"
                        )
                else:
                    dm_lines[user_id].append(
                        f"ℹ️ You hit the {HERO_POINT_NAME} breakpoint, but all {SPECIAL_REWARD_WINNER_CAP} reward slots have been claimed!"
                    )

            poke_conn.commit()
            cosmetics_conn.commit()
            limit_conn.commit()

    except Exception as e:
        print(f"Error in reward_processor: {e}")
        import traceback
        traceback.print_exc()
        async with battle_reward_lock:
            for user_id, rewards in pending_rewards.items():
                battle_reward_cache[user_id].extend(rewards)
        return

    # Notification Dispatches
    for user_id, lines in dm_lines.items():
        if not lines:
            continue
        user = bot.get_user(user_id)
        if user is None:
            try:
                user = await bot.fetch_user(user_id)
            except Exception:
                user = None
        if user is None:
            continue
        try:
            msg = "Battle rewards processed:\n" + "\n".join(f"- {line}" for line in lines)
            await user.send(msg)
        except Exception:
            continue

