formats = ['3v3', '6v6', '1v1', '2v2','4v4','5v5']
modes = ['p2', 'p2 rng', 'p∞ (p2 + ability + item)', 'standard', 'simplified']


def _existing_pair_battle_file(user1_id: int, user2_id: int):
    # first look in sqlite database
    conn = _get_battle_conn()
    c = conn.cursor()
    c.execute(
        "SELECT id, data FROM battles WHERE (p1_id=? AND p2_id=?) OR (p1_id=? AND p2_id=?)",
        (user1_id, user2_id, user2_id, user1_id)
    )
    row = c.fetchone()
    conn.close()
    if row:
        battle_id, data_text = row
        try:
            data = json.loads(data_text)
            ids = {int(data.get("p1_id")), int(data.get("p2_id"))}
            if ids == {int(user1_id), int(user2_id)}:
                return f"db:{battle_id}"
        except Exception:
            pass
    # fallback to filesystem for legacy battles
    folder = "duel"
    p1 = os.path.join(folder, f"{user1_id}_{user2_id}.json")
    p2 = os.path.join(folder, f"{user2_id}_{user1_id}.json")

    for candidate in (p1, p2):
        if not os.path.exists(candidate):
            continue
        try:
            with open(candidate, "r") as f:
                data = json.load(f)
            ids = {int(data.get("p1_id")), int(data.get("p2_id"))}
            if ids == {int(user1_id), int(user2_id)}:
                return candidate
        except Exception:
            continue
    return None


async def _get_user_cached_or_fetch(user_id: int):
    user = bot.get_user(user_id)
    if user:
        return user
    try:
        return await bot.fetch_user(user_id)
    except Exception:
        return None


async def _send_existing_battle_move_selection(file_path: str):
    data = _load_battle(file_path)
    if _is_pve_mode(data.get("mode", "")):
        return False

    if not check_ready(file_path):
        return False

    current_round = int(data.get("round_id", 0) or 0)
    if current_round <= 0:
        current_round = _bump_round_id(file_path)

    p1_id = int(data.get("p1_id", 0) or 0)
    p2_id = int(data.get("p2_id", 0) or 0)
    total_id = p1_id + p2_id
    if total_id in ACTIVE_BATTLES:
        return False
    p1_counter = 0
    p2_counter = 1 if p1_id == p2_id else 0
    p1_alive = _is_selection_alive(file_path, current_round, p1_id, p1_counter)
    p2_alive = _is_selection_alive(file_path, current_round, p2_id, p2_counter)
    if p1_alive and p2_alive:
        return True

    p1 = await _get_user_cached_or_fetch(p1_id)
    p2 = await _get_user_cached_or_fetch(p2_id)

    if not p1_alive:
        view1 = BattleMoveSelectView(p1_id, file_path, p1_counter, round_id=current_round)
        await send_battle_move_view(p1, view1, "Select a move for player 1")
    if not p2_alive:
        view2 = BattleMoveSelectView(p2_id, file_path, p2_counter, round_id=current_round)
        await send_battle_move_view(p2, view2, "Select a move for player 2")
    return True


async def _reset_battle_file_for_team_setup(file_path: str):
    """Reset an existing battle file back to fresh team selection state (same flow as /battle)."""
    try:
        old = _load_battle(file_path)
    except Exception:
        return False

    number = int(old.get("number", 3))
    mode = old.get("mode", "p2")
    p1_id = int(old.get("p1_id"))
    p2_id = int(old.get("p2_id"))
    channel_id = old.get("channel")

    p1_equipped = get_equipped_battle_cosmetics(p1_id)
    p2_equipped = get_equipped_battle_cosmetics(p2_id)

    data = {
        "mode": mode,
        "fake": bool(old.get("fake")),
        "weather": None,
        "weather_turns": 0,
        "terrain": None,
        "terrain_turns": 0,
        "number": number,
        "channel": channel_id,
        "p1_order": None,
        "p2_order": None,
        "background": p1_equipped["background"] or get_battle_background(p1_id),
        "color": p1_equipped["color"],
        "p1_pokeball": p1_equipped["pokeball"],
        "p2_pokeball": p2_equipped["pokeball"],
        "p2_color": p2_equipped["color"],
        "p2_background": p2_equipped["background"] or get_battle_background(p2_id),
        "p1_status_cosmetic": p1_equipped["status"] or "ninja",
        "p2_status_cosmetic": p2_equipped["status"] or "ninja",
        "graphics": p1_equipped["graphics"] or "animated",
        "p1_graphics": p1_equipped["graphics"] or "animated",
        "p2_graphics": p2_equipped["graphics"] or "animated",
        "p1_id": p1_id,
        "p2_id": p2_id,
        "p1_choice": None,
        "p2_choice": None,
        "p1_field": [],
        "p2_field": [],
        "trick_room_turns": 0,
        "p1_light_screen_turns": 0,
        "p2_light_screen_turns": 0,
        "p1_reflect_turns": 0,
        "p2_reflect_turns": 0,
        "mega_used": False,
        "z_move_used": False,
    }

    for p in ("p1", "p2"):
        for i in range(1, 7):
            data.update({
                f"{p}_p{i}": None,
                f"{p}_stats{i}": None,
                f"{p}_hp{i}": None,
                f"{p}_ev{i}": None,
                f"{p}_nature{i}": None,
                f"{p}_moves{i}": None,
                f"{p}_status{i}": None,
                f"{p}_ability{i}": None,
                f"{p}_hi{i}": None,
                f"{p}_cosmetic{i}": None,
                f"{p}_condition{i}": [],
                f"{p}_charge{i}": None,
            })

    _clear_selection_alive_for_battle(file_path)
    _save_battle(file_path, data)

    p1 = await _get_user_cached_or_fetch(p1_id)
    p2 = await _get_user_cached_or_fetch(p2_id)
    if not p1 or not p2:
        return False

    await _send_team_selection_panel(p1, p1_id, file_path, "p1", "Please select your pokemon")
    await _send_team_selection_panel(p2, p2_id, file_path, "p2", "Please select your pokemon")
    return True

class ExistingBattleResolveView(discord.ui.View):
    def __init__(self, file_path: str):
        super().__init__(timeout=180)
        self.file_path = file_path
        self.resolved = False

        data = _load_battle(file_path)
        self.p1_id = int(data["p1_id"])
        self.p2_id = int(data["p2_id"])

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id not in {self.p1_id, self.p2_id}:
            await interaction.response.send_message("This prompt is only for the two battlers.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="I Surrender", style=discord.ButtonStyle.danger)
    async def surrender(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.resolved:
            return await interaction.response.send_message("Already resolved.", ephemeral=True)

        self.resolved = True
        for item in self.children:
            item.disabled = True

        surrender_slot = "p1" if interaction.user.id == self.p1_id else "p2"
        winner_slot = "p2" if surrender_slot == "p1" else "p1"

        await interaction.response.edit_message(
            content=f"{interaction.user.mention} surrendered. Ending battle...",
            view=self
        )
        await announce_winner(self.file_path, winner_slot)
    @discord.ui.button(label="Keep Battling", style=discord.ButtonStyle.success)
    async def keep_battling(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.resolved:
            return await interaction.response.send_message("Already resolved.", ephemeral=True)

        self.resolved = True
        for item in self.children:
            item.disabled = True

        try:
            data = _load_battle(self.file_path)
            number = int(data.get("number", 3))
            p1_number = 0
            p2_number = 0
            for i in range(1, number + 1):
                if data.get(f"p1_p{i}"):
                    p1_number += 1
            for i in range(1, number + 1):
                if data.get(f"p2_p{i}"):
                    p2_number += 1
        except Exception:
            number = 0
            p1_number = 0
            p2_number = 0

        if p1_number < number or p2_number < number:
            ok = await _reset_battle_file_for_team_setup(self.file_path)
            if ok:
                return await interaction.response.edit_message(
                    content="Battle file was reset because one side had no Pokemon selected. Fresh team setup was sent in DMs.",
                    view=self
                )
            return await interaction.response.edit_message(
                content="Could not reset battle setup automatically. Please run /battle again.",
                view=self
            )

        ready = await _send_existing_battle_move_selection(self.file_path)
        if ready:
            await interaction.response.edit_message(
                content="Battle resumed. Move selection sent in DMs.",
                view=self
            )
        else:
            await interaction.response.edit_message(
                content="Battle already exists. Check DMs.",
                view=self
            )

@bot.tree.command(name="battle", description="Do a mock battle")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
@app_commands.describe(fakemon="Allow selecting fakemon from fakemon_data")
@app_commands.choices(
    format=[app_commands.Choice(name=t.capitalize(), value=t) for t in formats], 
    mode=[app_commands.Choice(name=t.capitalize(), value=t) for t in modes])
async def battle(interaction: discord.Interaction, opponent: discord.User, format: str = '3v3', mode: str = 'p2', fakemon: bool = False):
    await interaction.response.defer()
    player1 = interaction.user
    player2 = opponent
