@bot.command(name="battle")
async def battle_prefix(
    ctx: commands.Context,
    arg1: str = None,
    arg2: str = None,
    arg3: str = None,
    _force_fake: bool = False
):
    # Resolve arg1 to a Member/User before the suspension check
    target = None
    if arg1:
        try:
            target = await commands.MemberConverter().convert(ctx, arg1)
        except commands.BadArgument:
            try:
                target = await commands.UserConverter().convert(ctx, arg1)
            except commands.BadArgument:
                pass

    if target and await check_user_suspended(target, ctx):
        return

   
    def _format_to_team_size(fmt: str) -> int:
        if fmt == "3v3":
            return 3
        if fmt == "6v6":
            return 6
        if fmt == "2v2":
            return 2
        if fmt == "4v4":
            return 4
        if fmt == "5v5":
            return 5
        if fmt == "1v1":
            return 1
        return 3

    def _collect_active_pvp_battles_for_user(user_id: int):
        hits = []
        # first check sqlite database for battles involving this user
        conn = _get_battle_conn()
        c = conn.cursor()
        c.execute(
            "SELECT id, p1_id, p2_id FROM battles WHERE p1_id=? OR p2_id=?",
            (user_id, user_id)
        )
        for battle_id, p1_id, p2_id in c.fetchall():
            hits.append((f"db:{battle_id}", p1_id, p2_id))
        conn.close()

        # then fallback to legacy json files on disk
        folder = "duel"
        if not os.path.isdir(folder):
            return hits
        for entry in os.scandir(folder):
            if not entry.is_file() or not entry.name.endswith(".json"):
                continue
            try:
                with open(entry.path, "r") as f:
                    duel_data = json.load(f)
                p1_id = _safe_int_user_id(duel_data.get("p1_id"))
                p2_id = _safe_int_user_id(duel_data.get("p2_id"))
                if p2_id is None:
                    continue
                if user_id in {p1_id, p2_id}:
                    hits.append((entry.path, p1_id, p2_id))
            except Exception:
                continue
        return hits

    async def _start_prefix_pvp_battle(player1: discord.abc.User, player2: discord.abc.User, battle_format: str, battle_mode: str):
        number = _format_to_team_size(battle_format)
        channel_id = ctx.channel.id
        p1_equipped = get_equipped_battle_cosmetics(player1.id)
        p2_equipped = get_equipped_battle_cosmetics(player2.id)

        data = {
            "mode": battle_mode,
            "fake": bool(_force_fake),
            "weather": None,
            "weather_turns": 0,
            "terrain": None,
            "terrain_turns": 0,
            "number": number,
            "channel": channel_id,
            "guild_id": ctx.guild.id if ctx.guild else None,
            "p1_order": None,
            "p2_order": None,
            "background": p1_equipped["background"] or get_battle_background(player1.id),
            "color": p1_equipped["color"],
            "p1_pokeball": p1_equipped["pokeball"],
            "p2_pokeball": p2_equipped["pokeball"],
            "p2_color": p2_equipped["color"],
            "p2_background": p2_equipped["background"] or get_battle_background(player2.id),
            "p1_status_cosmetic": p1_equipped["status"] or "ninja",
            "p2_status_cosmetic": p2_equipped["status"] or "ninja",
            "graphics": p1_equipped["graphics"] or "animated",
            "p1_graphics": p1_equipped["graphics"] or "animated",
            "p2_graphics": p2_equipped["graphics"] or "animated",
            "p1_id": player1.id,
            "p2_id": player2.id,
            "p1_choice": None,
            "p2_choice": None,
            "p1_field": [],
            "p2_field": [],
            "trick_room_turns": 0,
            "p1_light_screen_turns": 0,
            "p2_light_screen_turns": 0,
            "p1_reflect_turns": 0,
            "p2_reflect_turns": 0,
            "mega_used": False,
            "z_move_used": False,
        }
        if str(battle_mode).strip().lower() == PVP_MODE_RNG:
            data["rng_max_iv_mode"] = True

        for p in ("p1", "p2"):
            for i in range(1, 7):
                data.update({
                    f"{p}_p{i}": None,
                    f"{p}_stats{i}": None,
                    f"{p}_hp{i}": None,
                    f"{p}_ev{i}": None,
                    f"{p}_nature{i}": None,
                    f"{p}_moves{i}": None,
                    f"{p}_status{i}": None,
                    f"{p}_ability{i}": None,
                    f"{p}_hi{i}": None,
                    f"{p}_cosmetic{i}": None,
                    f"{p}_condition{i}": [],
                    f"{p}_charge{i}": None,
                })

        # store the PvP battle in sqlite rather than a file
        filepath = _create_battle(data)

        await _send_team_selection_panel(player1, player1.id, filepath, "p1", "Please select your pokemon")
        await _send_team_selection_panel(player2, player2.id, filepath, "p2", "Please select your pokemon")

    class BattleChallengeConfirmView(discord.ui.View):
        def __init__(self, challenger: discord.Member, opponent: discord.Member, timeout: float = 60):
            super().__init__(timeout=timeout)
            self.challenger = challenger
            self.opponent = opponent
            self.result = None

        async def interaction_check(self, interaction: discord.Interaction) -> bool:
            if interaction.user.id != self.opponent.id:
                await interaction.response.send_message("Only the challenged player can respond.", ephemeral=True)
                return False
            return True

        async def _resolve(self, interaction: discord.Interaction, result: str):
            self.result = result
            for child in self.children:
                if isinstance(child, discord.ui.Button):
                    child.disabled = True
            await interaction.response.edit_message(view=self)
            self.stop()

        @discord.ui.button(label="Accept", style=discord.ButtonStyle.success)
        async def accept(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._resolve(interaction, "accepted")

        @discord.ui.button(label="Decline", style=discord.ButtonStyle.danger)
        async def decline(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._resolve(interaction, "declined")

    class BattleModeSelectView(discord.ui.View):
        def __init__(self, challenger: discord.Member, opponent: discord.Member, battle_format: str, timeout: float = 90):
            super().__init__(timeout=timeout)
            self.challenger = challenger
            self.opponent = opponent
            self.battle_format = battle_format
            self.done = False
            self.message = None

        async def interaction_check(self, interaction: discord.Interaction) -> bool:
            if interaction.user.id not in {self.challenger.id, self.opponent.id}:
                await interaction.response.send_message("Only the two battlers can pick the mode.", ephemeral=True)
                return False
            return True

        async def on_timeout(self):
            for child in self.children:
                if isinstance(child, discord.ui.Button):
                    child.disabled = True
            if self.message:
                try:
                    await self.message.edit(content="Battle mode selection timed out.", view=self)
                except Exception:
                    pass

        async def _pick_mode(self, interaction: discord.Interaction, mode_name: str):
            if self.done:
                return await interaction.response.send_message("Mode already selected.", ephemeral=True)
            self.done = True
            for child in self.children:
                if isinstance(child, discord.ui.Button):
                    child.disabled = True

            await _start_prefix_pvp_battle(self.challenger, self.opponent, self.battle_format, mode_name)
            await interaction.response.edit_message(
                content=f"Mode selected: **{mode_name}**.",
                view=self
            )
            await interaction.followup.send(
                f"<@{self.challenger.id}> and <@{self.opponent.id}> 📬 **Please check your DMs to select Pokémon.**"
            )

        @discord.ui.button(label="p2", style=discord.ButtonStyle.primary)
        async def mode_p2(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._pick_mode(interaction, "p2")

        @discord.ui.button(label="p2 rng", style=discord.ButtonStyle.secondary)
        async def mode_p2_rng(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._pick_mode(interaction, "p2 rng")

        @discord.ui.button(label="p∞", style=discord.ButtonStyle.success)
        async def mode_pinf(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._pick_mode(interaction, "p∞ (p2 + ability + item)")

        @discord.ui.button(label="standard", style=discord.ButtonStyle.danger)
        async def mode_standard(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._pick_mode(interaction, "standard")

        @discord.ui.button(label="simplified", style=discord.ButtonStyle.primary)
        async def mode_simplified(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._pick_mode(interaction, "simplified")
            #await interaction.response.send_message("Under Development")

    class BattleMassSurrenderConfirmView(discord.ui.View):
        def __init__(self, author: discord.Member, battle_entries: list[tuple[str, int, int]], timeout: float = 45):
            super().__init__(timeout=timeout)
            self.author = author
            self.battle_entries = battle_entries

        async def interaction_check(self, interaction: discord.Interaction) -> bool:
            if interaction.user.id != self.author.id:
                await interaction.response.send_message("This confirmation is only for the command user.", ephemeral=True)
                return False
            return True

        async def _disable(self):
            for child in self.children:
                if isinstance(child, discord.ui.Button):
                    child.disabled = True

        @discord.ui.button(label="Confirm Surrender All", style=discord.ButtonStyle.danger)
        async def confirm(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._disable()
            surrendered = 0
            for file_path, p1_id, p2_id in list(self.battle_entries):
                if self.author.id not in {p1_id, p2_id}:
                    continue
                winner_slot = "p2" if self.author.id == p1_id else "p1"
                try:
                    await announce_winner(file_path, winner_slot)
                    surrendered += 1
                except Exception:
                    continue
            await interaction.response.edit_message(
                content=f"Surrender complete. You surrendered in **{surrendered}** active battle(s).",
                view=self
            )

        @discord.ui.button(label="Cancel", style=discord.ButtonStyle.secondary)
        async def cancel(self, interaction: discord.Interaction, button: discord.ui.Button):
            await self._disable()
            await interaction.response.edit_message(content="Mass surrender cancelled.", view=self)

    if not arg1:
        return await ctx.send("Usage: `!battle @player [3v3|6v6|1v1|2v2|4v4|5v5] [mode]` or `!battle x`.")

    if arg1.lower() in {"x", "cancel", "stop"}:
        active_entries = _collect_active_pvp_battles_for_user(ctx.author.id)
        if not active_entries:
            return await ctx.send("You have no active battles to surrender.")
        view = BattleMassSurrenderConfirmView(ctx.author, active_entries)
        return await ctx.send(
            f"{ctx.author.mention}, surrender in **all {len(active_entries)}** of your active battles?",
            view=view
        )

    try:
        opponent = await commands.MemberConverter().convert(ctx, arg1)
    except commands.MemberNotFound:
        return await ctx.send("Couldn't find that player.")

    battle_format = "3v3"
    mode_lookup = {m.lower(): m for m in modes}
    mode_alias = {
        "pinf": "p∞ (p2 + ability + item)",
        "p-infinity": "p∞ (p2 + ability + item)",
        "infinity": "p∞ (p2 + ability + item)",
    }
    mode_arg_used = False

    for token in [arg2, arg3]:
        if not token:
            continue
        lowered = token.lower()
        if lowered in formats:
            battle_format = lowered
            continue
        if lowered in mode_lookup:
            mode_arg_used = True
            continue
        if lowered in mode_alias:
            mode_arg_used = True
            continue
        return await ctx.send(f"❌ Invalid argument: `{token}`")

    number = _format_to_team_size(battle_format)
    player1 = ctx.author
    player2 = opponent
    channel_id = ctx.channel.id

    if player2.bot:
        p1_equipped = get_equipped_battle_cosmetics(player1.id)
        data = {
            "mode": PVE_MODE_KONGFU,
            "fake": bool(_force_fake),
            "rarity": "rare",
            "weather": None,
            "weather_turns": 0,
            "terrain": None,
            "terrain_turns": 0,
            "number": number,
            "channel": channel_id,
            "p1_order": None,
            "p2_order": None,
            "p1_id": player1.id,
            "p2_id": "NPC",
            "p1_name": player1.display_name,
            "p2_name": "Kongfu Panda",
            "background": p1_equipped["background"] or get_battle_background(player1.id),
            "color": p1_equipped["color"],
            "p1_pokeball": p1_equipped["pokeball"],
            "p2_pokeball": None,
            "p2_color": None,
            "p2_background": None,
            "p1_status_cosmetic": p1_equipped["status"] or "ninja",
            "p2_status_cosmetic": "ninja",
            "graphics": p1_equipped["graphics"] or "animated",
            "p1_graphics": p1_equipped["graphics"] or "animated",
            "p2_graphics": "animated",
            "p1_choice": None,
            "p2_choice": None,
            "p1_field": [],
            "p2_field": [],
            "trick_room_turns": 0,
            "p1_light_screen_turns": 0,
            "p2_light_screen_turns": 0,
            "p1_reflect_turns": 0,
            "p2_reflect_turns": 0,
            "mega_used": False,
            "z_move_used": False,
        }
        for prefix in ("p1", "p2"):
            for i in range(1, 7):
                data[f"{prefix}_p{i}"] = None
                data[f"{prefix}_stats{i}"] = None
                data[f"{prefix}_ev{i}"] = None
                data[f"{prefix}_nature{i}"] = None
                data[f"{prefix}_moves{i}"] = None
                data[f"{prefix}_hp{i}"] = None
                data[f"{prefix}_status{i}"] = None
                data[f"{prefix}_ability{i}"] = None
                data[f"{prefix}_hi{i}"] = None
                data[f"{prefix}_cosmetic{i}"] = None
                data[f"{prefix}_condition{i}"] = []
                data[f"{prefix}_charge{i}"] = None

        # instead of writing to a json file, store the battle in sqlite
        filepath = _create_battle(data)

        await _send_team_selection_panel(player1, player1.id, filepath, "p1", "Please select your Pokémon for the PvE battle.")
        return await ctx.send(f"<@{player1.id}> 📬 **Please check your DMs to set up your PvE battle vs Kongfu Panda.**")

    existing_path = _existing_pair_battle_file(player1.id, player2.id)
    if existing_path:
        view = ExistingBattleResolveView(existing_path)
        await ctx.send(
            f"<@{player1.id}> <@{player2.id}> You are already in a battle. "
            "Click a button: surrender now, or keep battling and pick a move.",
            view=view
        )
        return

    confirm_view = BattleChallengeConfirmView(player1, player2)
    challenge_message = await ctx.send(
        f"{player2.mention}, **{player1.mention}** challenged you to a battle ({battle_format}). Do you accept?",
        view=confirm_view
    )
    await confirm_view.wait()

    if confirm_view.result != "accepted":
        for child in confirm_view.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True
        if confirm_view.result == "declined":
            return await challenge_message.edit(content=f"{player2.mention} declined the battle request.", view=confirm_view)
        return await challenge_message.edit(content=f"Battle request to {player2.mention} timed out.", view=confirm_view)

    if _existing_pair_battle_file(player1.id, player2.id):
        return await challenge_message.edit(
            content="One of you is already in this battle now. Request cancelled.",
            view=None
        )

    mode_view = BattleModeSelectView(player1, player2, battle_format)
    mode_prompt = f"{player1.mention} {player2.mention}, select a battle mode for this duel:"
    if mode_arg_used:
        mode_prompt += "\n-# Mode is now selected with buttons."
    mode_message = await ctx.send(mode_prompt, view=mode_view)
    mode_view.message = mode_message
    await challenge_message.edit(content=f"{player2.mention} accepted the battle challenge.", view=None)

@bot.command(name="fbattle")
async def fbattle_prefix(
    ctx: commands.Context,
    arg1: str = None,
    arg2: str = None,
    arg3: str = None
):
    await battle_prefix(ctx, arg1, arg2, arg3, _force_fake=True)

DUO_BATTLE_FOLDER = "duel_duo"
DUO_BATTLE_LOCKS: dict[str, asyncio.Lock] = {}
DUO_SLOTS = ("p11", "p12", "p21", "p22")
DUO_SIDES = {"p11": "p1", "p12": "p1", "p21": "p2", "p22": "p2"}
DUO_SETUP_FOLDER = "duel_duo_setup"
DUO_SETUP_LINKS: dict[str, dict] = {}
DUO_MOVE_TIMEOUT_SECONDS = 180


def _duo_parse_setup_file_path(setup_file: str) -> dict | None:
    """Recover duo link info from a setup filename.

    Expected filename:
      <duo-battle-json>.{slot}.{user_id}.json
    Example:
      1_2_3_4.json.p12.222.json
    """
    base = os.path.basename(str(setup_file or ""))
    m = re.match(r"^(?P<duo>.+\.json)\.(?P<slot>p11|p12|p21|p22)\.(?P<uid>\d+)\.json$", base)
    if not m:
        return None
    return {
        "duo_file": os.path.join(DUO_BATTLE_FOLDER, m.group("duo")),
        "slot": m.group("slot"),
        "user_id": int(m.group("uid")),
    }


def _duo_resolve_setup_link(setup_file: str) -> dict | None:
    link = DUO_SETUP_LINKS.get(setup_file)
    if link:
        return link
    parsed = _duo_parse_setup_file_path(setup_file)
    if not parsed:
        return None
    return parsed


def _is_duo_setup_file_path(file_path: str) -> bool:
    if file_path in DUO_SETUP_LINKS:
        return True
    return _duo_parse_setup_file_path(file_path) is not None


def _duo_lock_for(file_path: str) -> asyncio.Lock:
    lock = DUO_BATTLE_LOCKS.get(file_path)
    if lock is None:
        lock = asyncio.Lock()
        DUO_BATTLE_LOCKS[file_path] = lock
    return lock


def _duo_battle_path(ids: list[int]) -> str:
    os.makedirs(DUO_BATTLE_FOLDER, exist_ok=True)
    canon = "_".join(str(i) for i in sorted(ids))
    return os.path.join(DUO_BATTLE_FOLDER, f"{canon}.json")


def _duo_load(file_path: str) -> dict:
    with open(file_path, "r", encoding="utf-8") as f:
        return json.load(f)


def _duo_save(file_path: str, data: dict):
    with open(file_path, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=4)


def _duo_slot_for_user(data: dict, user_id: int) -> str | None:
    for slot in DUO_SLOTS:
        if int(data.get(f"{slot}_id", 0) or 0) == int(user_id):
            return slot
    return None


def _duo_opponents(slot: str) -> list[str]:
    return ["p21", "p22"] if slot.startswith("p1") else ["p11", "p12"]


def _duo_max_hp_for(poke_name: str) -> int:
    base_stats = get_pokemon_stats(poke_name)[0]
    return max(1, math.floor(2 * int(base_stats[0]) + 31 + 5 + 110))


def _duo_active_idx(data: dict, slot: str) -> int | None:
    team = data.get(f"{slot}_team") or []
    hps = data.get(f"{slot}_hps") or []
    start = int(data.get(f"{slot}_active", 0) or 0)
    if start < 0:
        start = 0
    for i in range(start, len(team)):
        if i < len(hps) and int(hps[i] or 0) > 0:
            data[f"{slot}_active"] = i
            return i
    for i in range(0, start):
        if i < len(hps) and int(hps[i] or 0) > 0:
            data[f"{slot}_active"] = i
            return i
    return None


def _duo_slot_alive(data: dict, slot: str) -> bool:
    if data.get(f"{slot}_surrendered", False):
        return False
    return _duo_active_idx(data, slot) is not None


def _duo_side_alive(data: dict, side: str) -> bool:
    slots = ["p11", "p12"] if side == "p1" else ["p21", "p22"]
    return any(_duo_slot_alive(data, s) for s in slots)


def _duo_choice_ready(data: dict) -> bool:
    for slot in DUO_SLOTS:
        if not _duo_slot_alive(data, slot):
            continue
        if not data.get(f"{slot}_choice"):
            return False
    return True


def _duo_teams_complete(data: dict) -> bool:
    for slot in DUO_SLOTS:
        team = data.get(f"{slot}_team")
        if not isinstance(team, list) or len(team) < 3:
            return False
    return True


def _duo_slot_team_member(data: dict, slot: str, idx: int) -> dict | None:
    team = data.get(f"{slot}_team") or []
    if idx < 0 or idx >= len(team):
        return None
    return team[idx]


def _duo_slot_speed(data: dict, slot: str) -> int:
    idx = _duo_active_idx(data, slot)
    member = _duo_slot_team_member(data, slot, idx if idx is not None else -1)
    if idx is None or not member:
        return 0
    name = str(member.get("name") or "").strip().lower()
    stats = get_pokemon_stats(name)[0]
    nature = str(member.get("nature") or "hardy").strip().lower()
    statuses = data.get(f"{slot}_statuses") or []
    stage = 0
    if idx < len(statuses) and isinstance(statuses[idx], list) and len(statuses[idx]) >= 6:
        try:
            stage = int(statuses[idx][5])
        except Exception:
            stage = 0
    if nature in {"jolly", "timid", "naive", "hasty"}:
        nature_mult = 1.1
    elif nature in {"brave", "quiet", "sassy", "relaxed"}:
        nature_mult = 0.9
    else:
        nature_mult = 1.0
    raw = (2 * int(stats[5]) + 31 + 5 + 5) * nature_mult
    if stage < 0:
        raw *= (2 / (2 - stage))
    else:
        raw *= ((2 + stage) / 2)
    return int(max(1, math.floor(raw)))


def _duo_team_options_for_user(user_id: int) -> dict[str, list[dict]]:
    prio_rare, non_rare, _ = load_player_teams(user_id, "rare")
    prio_common, non_common, _ = load_player_teams(user_id, "common")
    out = {}
    if prio_rare:
        out["rare_prio"] = prio_rare
    if non_rare:
        out["rare_nonprio"] = non_rare
    if prio_common:
        out["common_prio"] = prio_common
    if non_common:
        out["common_nonprio"] = non_common
    return out


def _duo_normalize_team(team_dict: dict) -> list[dict]:
    items = []
    for key in sorted(team_dict.keys()):
        p = team_dict[key] or {}
        name = str(p.get("name") or "").strip().lower()
        if not name:
            continue
        moves = [str(m).strip().lower() for m in (p.get("moves") or []) if str(m).strip()][:4]
        if not moves:
            pm = [m for m in get_pokemon_moves(name) if m and m != "poke not found"][:4]
            if not pm:
                pm = [m for m in get_default_moves(name) if m][:4]
            moves = pm
        if not moves:
            moves = ["struggle"]
        items.append(
            {
                "name": name,
                "moves": moves,
                "nature": str(p.get("nature") or "hardy").strip().lower(),
                "ability": str(p.get("ability") or "").strip().lower() or None,
                "item": str(p.get("item") or "").strip().lower() or None,
                "cosmetic": str(p.get("cosmetic") or "").strip().lower() or None,
                "max_hp": _duo_max_hp_for(name),
            }
        )
        if len(items) >= 3:
            break
    return items


async def _duo_render_gif(data: dict) -> BytesIO:
    bg_name = str(data.get("background") or "arena").strip().lower()
    bg = _get_cached_battle_background(bg_name).convert("RGBA")
    bg = bg.resize((900, 450), Image.Resampling.LANCZOS)

    try:
        name_font = ImageFont.truetype("arial.ttf", 20)
    except Exception:
        name_font = ImageFont.load_default()

    def resize_or_placeholder(sprite, scale=1.0):
        if sprite is None:
            sprite = placeholder_circle((125, 125))
        else:
            sprite = sprite.convert("RGBA")
        w, h = sprite.size
        mean = max(1, (w + h) / 2)
        new_w = max(1, int(w * scale * 180 / mean))
        new_h = max(1, int(h * scale * 180 / mean))
        return sprite.resize((new_w, new_h), Image.Resampling.LANCZOS)

    hp_bar_width = 240
    hp_bar_height = 14

    def draw_hp_bar(draw_ctx, current_hp, max_hp, top_left):
        bar_width = hp_bar_width
        bar_height = hp_bar_height
        x, y = top_left
        draw_ctx.rectangle([x - 2, y - 2, x + bar_width + 2, y + bar_height + 2], fill=(0, 0, 0))
        draw_ctx.rectangle([x, y, x + bar_width, y + bar_height], fill=(70, 70, 70))
        ratio = max(0.0, min(1.0, current_hp / max(1, max_hp)))
        hp_width = int(bar_width * ratio)
        if ratio > 0.5:
            color = (0, 220, 0)
        elif ratio > 0.2:
            color = (240, 200, 0)
        else:
            color = (220, 0, 0)
        draw_ctx.rectangle([x, y, x + hp_width, y + bar_height], fill=color)

    def shorten_name(text, draw_ctx):
        if not text:
            return None
        txt = str(text)
        bar_width = 240
        while len(txt) > 1:
            bbox = draw_ctx.textbbox((0, 0), txt, font=name_font)
            if (bbox[2] - bbox[0]) <= bar_width:
                break
            if len(txt) <= 4:
                txt = txt[:1]
                break
            txt = txt[:-4] + "..."
        return txt

    def draw_name(draw_ctx, text, hp_top_left):
        if not text:
            return
        x, y = hp_top_left
        bbox = draw_ctx.textbbox((0, 0), text, font=name_font)
        text_w = bbox[2] - bbox[0]
        text_h = bbox[3] - bbox[1]
        tx = x + max(0, (hp_bar_width - text_w) // 2)
        ty = y - text_h - 4
        draw_ctx.text((tx + 1, ty + 1), text, fill=(0, 0, 0), font=name_font)
        draw_ctx.text((tx, ty), text, fill=(255, 255, 255), font=name_font)

    def draw_pokeball_row(layer: Image.Image, hp_top_left, states):
        if not states:
            return
        x, y = hp_top_left
        start_x = int(x)
        start_y = int(y + hp_bar_height + 4)
        for i, is_alive in enumerate(states):
            icon = _get_cached_battle_pokeball("alive" if is_alive else "fainted", size=(30, 30))
            layer.paste(icon, (start_x + i * 32, start_y), icon)

    positions = {
        "p11": (int(bg.width * 0.2), int(bg.height * 0.74)),
        "p12": (int(bg.width * 0.2), int(bg.height * 0.30)),
        "p21": (int(bg.width * 0.8), int(bg.height * 0.30)),
        "p22": (int(bg.width * 0.8), int(bg.height * 0.74)),
    }
    draw = ImageDraw.Draw(bg)

    for slot in DUO_SLOTS:
        idx = _duo_active_idx(data, slot)
        hp_text = "0/0"
        sprite = None
        sprite_mask = None
        label_name = "Fainted"
        current_hp = 0
        max_hp = 1

        if idx is not None:
            member = _duo_slot_team_member(data, slot, idx)
            if member:
                label_name = str(member.get("name") or "").title()
                current_hp = int((data.get(f"{slot}_hps") or [0])[idx] or 0)
                max_hp = int(member.get("max_hp") or 1)
                hp_text = f"{current_hp}/{max_hp}"
                cosmetic = str(member.get("cosmetic") or "").strip().lower() or None
                sprite, sprite_mask = resolve_special_sprite(member["name"], cosmetic)
                sprite = _apply_preview_mask(sprite, sprite_mask)

        scale = 1.2 if str(sprite_mask or "").strip().lower() == "dynamax" else 1.0
        sprite = resize_or_placeholder(sprite, scale)
        x, y = positions[slot]
        sprite_pos = (x - sprite.width // 2, y - sprite.height // 2)
        hp_pos = (sprite_pos[0], max(5, sprite_pos[1] - 26))
        team = data.get(f"{slot}_team") or []
        hps = data.get(f"{slot}_hps") or []
        ball_states = [int(hps[i] if i < len(hps) else 0) > 0 for i in range(len(team))]

        draw_hp_bar(draw, current_hp, max_hp, hp_pos)
        draw_pokeball_row(bg, hp_pos, ball_states)
        display_text = f"{slot.upper()} {label_name} {hp_text}"
        display_text = shorten_name(display_text, draw) or display_text
        draw_name(draw, display_text, hp_pos)
        bg.paste(sprite, sprite_pos, sprite)

    out = BytesIO()
    bg.save(out, format="PNG")
    out.seek(0)
    return out


async def _duo_send_status(channel: discord.abc.Messageable, file_path: str, title: str = "Battle Duo Status"):
    if not os.path.exists(file_path):
        return
    data = _duo_load(file_path)
    gif = await _duo_render_gif(data)
    channel_id = data.get("channel")
    channel_ref = f"<#{channel_id}>" if channel_id else "Unknown"
    embed = discord.Embed(
        title=title,
        description=f"Mode: **{data.get('mode', 'p2')}** | Round: **{int(data.get('round', 1) or 1)}**\nChannel: {channel_ref}",
        color=discord.Color.blurple(),
    )

    users = {}
    for slot in DUO_SLOTS:
        uid = int(data.get(f"{slot}_id") or 0)
        user = bot.get_user(uid)
        if not user:
            try:
                user = await bot.fetch_user(uid)
            except Exception:
                user = None
        users[slot] = user

    for slot in DUO_SLOTS:
        team = data.get(f"{slot}_team") or []
        hps = data.get(f"{slot}_hps") or []
        active_idx = _duo_active_idx(data, slot)
        user = users.get(slot)
        display_name = user.display_name if user else slot.upper()
        lines = []
        for i, member in enumerate(team):
            poke_name = str(member.get("name") or "").strip().lower()
            if not poke_name:
                continue
            hp = int(hps[i] if i < len(hps) else 0)
            max_hp = int(member.get("max_hp") or _duo_max_hp_for(poke_name))
            cosmetic = str(member.get("cosmetic") or "").strip().lower()
            cosmetic_emoji = _get_cosmetic_emoji(cosmetic, "") if cosmetic else ""
            line = f"{get_pokemon_emoji(poke_name)} {poke_name.title()}{cosmetic_emoji} - {hp}/{max_hp} HP"
            if i == active_idx:
                lines.append(f"<a:green_dot:1383016833040515142> **{line}**")
            elif hp > 0:
                lines.append(f"{DEFAULT_POKEBALL_EMOJI} {line}")
            else:
                lines.append(f"<a:red_dot:1383016307355553903> {line}")
        if not lines:
            lines = ["No team selected."]
        embed.add_field(
            name=f"{_get_status_emoji_for_slot('p1' if slot.startswith('p1') else 'p2', data)} {slot.upper()} • {display_name}",
            value="\n".join(lines),
            inline=True,
        )

    embed.set_image(url="attachment://battle_duo.png")
    await channel.send(embed=embed, file=discord.File(gif, filename="battle_duo.png"))

    # Also send status to all 4 player DMs.
    for slot in DUO_SLOTS:
        user = users.get(slot)
        if not user:
            continue
        try:
            gif.seek(0)
            await user.send(embed=embed, file=discord.File(gif, filename="battle_duo.png"))
        except Exception:
            pass


def _duo_target_options(data: dict, slot: str) -> list[discord.SelectOption]:
    opts = []
    for enemy in _duo_opponents(slot):
        if not _duo_slot_alive(data, enemy):
            continue
        idx = _duo_active_idx(data, enemy)
        member = _duo_slot_team_member(data, enemy, idx if idx is not None else -1)
        if idx is None or not member:
            continue
        hp = int((data.get(f"{enemy}_hps") or [0])[idx] or 0)
        opts.append(discord.SelectOption(label=f"{enemy.upper()} - {member['name'].title()} ({hp} HP)", value=enemy))
    return opts


async def _duo_maybe_start_after_team_setup(file_path: str):
    print("dmsats")
    lock = _duo_lock_for(file_path)
    should_start = False
    channel = None
    try:
        async with lock:
            try:
                data = _duo_load(file_path)
            except Exception:
                return
            print("data loaded")
            print(_duo_teams_complete(data))
            if _duo_teams_complete(data):
                data["setup_complete"] = True
                _duo_save(file_path, data)
                should_start = True
                cid = int(data.get("channel") or 0)
                try:
                    channel = bot.get_channel(cid) or await bot.fetch_channel(cid)
                except Exception:
                    channel = None
                print(cid)
    except Exception:
        traceback.print_exc()
    if should_start and channel:
        await channel.send("All 4 players have selected teams. Battle is starting.")
        await _duo_send_status(channel, file_path, "Battle Duo Started")
        await _duo_prompt_moves(file_path, channel)


async def _duo_recover_pending_setup_files():
    """Recover and import any completed duo setup files left on disk."""
    if not os.path.isdir(DUO_SETUP_FOLDER):
        return
    imported = 0
    scanned = 0
    try:
        names = sorted(os.listdir(DUO_SETUP_FOLDER))
    except Exception:
        return

    for name in names:
        setup_file = os.path.join(DUO_SETUP_FOLDER, name)
        if not os.path.isfile(setup_file):
            continue
        if not _duo_parse_setup_file_path(setup_file):
            continue
        scanned += 1
        try:
            if await _duo_import_setup_team(setup_file):
                imported += 1
        except Exception:
            traceback.print_exc()

    if scanned:
        print(f"[DUO] Setup recovery scanned={scanned}, imported={imported}")


@tasks.loop(seconds=30)
async def duo_setup_recovery_task():
    await _duo_recover_pending_setup_files()


@duo_setup_recovery_task.before_loop
async def _before_duo_setup_recovery_task():
    await bot.wait_until_ready()


def _duo_setup_file_path(duo_file: str, slot: str, user_id: int) -> str:
    os.makedirs(DUO_SETUP_FOLDER, exist_ok=True)
    base = os.path.basename(str(duo_file or "duo"))
    return os.path.join(DUO_SETUP_FOLDER, f"{base}.{slot}.{int(user_id)}.json")


def _duo_create_setup_file(duo_file: str, slot: str, user_id: int, mode: str) -> str:
    setup_file = _duo_setup_file_path(duo_file, slot, user_id)
    data = {
        "mode": mode,
        "number": 3,
        "channel": None,
        "guild_id": None,
        "p1_id": int(user_id),
        "p2_id": -1,
        "p1_order": None,
        "p2_order": None,
        "background": "arena",
        "color": "default",
        "p1_choice": None,
        "p2_choice": None,
        "p1_field": [],
        "p2_field": [],
        "trick_room_turns": 0,
        "p1_light_screen_turns": 0,
        "p2_light_screen_turns": 0,
        "p1_reflect_turns": 0,
        "p2_reflect_turns": 0,
    }
    for prefix in ("p1", "p2"):
        for i in range(1, 7):
            data[f"{prefix}_p{i}"] = None
            data[f"{prefix}_stats{i}"] = None
            data[f"{prefix}_ev{i}"] = None
            data[f"{prefix}_nature{i}"] = None
            data[f"{prefix}_moves{i}"] = None
            data[f"{prefix}_hp{i}"] = None
            data[f"{prefix}_status{i}"] = None
            data[f"{prefix}_ability{i}"] = None
            data[f"{prefix}_hi{i}"] = None
            data[f"{prefix}_cosmetic{i}"] = None
            data[f"{prefix}_condition{i}"] = []
            data[f"{prefix}_charge{i}"] = None
    try:
        _save_battle(setup_file, data)
        # Only add to links after successful save
        DUO_SETUP_LINKS[setup_file] = {"duo_file": duo_file, "slot": slot, "user_id": int(user_id)}
    except Exception:
        # If save fails, don't add to links
        return setup_file
    return setup_file


async def _duo_import_setup_team(setup_file: str) -> bool:
    print("dist")
    link = _duo_resolve_setup_link(setup_file)
    if not link:
        return False
    duo_file = link["duo_file"]
    slot = link["slot"]
    user_id = int(link["user_id"])
    lock = _duo_lock_for(duo_file)
    print("bp1")
    try:
        async with lock:
            # Check both files exist within lock protection
            if not os.path.exists(setup_file) or not os.path.exists(duo_file):
                DUO_SETUP_LINKS.pop(setup_file, None)
                print(DUO_SETUP_LINKS)
                return False
            try:
                sdata = _load_battle(setup_file)
            except Exception:
                DUO_SETUP_LINKS.pop(setup_file, None)
                traceback.print_exc()
                return False
            if not all(sdata.get(f"p1_p{i}") for i in range(1, 4)):
                print("sdata")
                return False
            team_payload = _extract_battle_team_payload(sdata, "p1", 3)
            picked = _duo_normalize_team(team_payload)
            if len(picked) < 3:
                print(picked)
                return False
            data = _duo_load(duo_file)
            if int(data.get(f"{slot}_id", 0) or 0) != user_id:
                print(data, "slot id")
                DUO_SETUP_LINKS.pop(setup_file, None)
                return False
            print("bp2")
            data[f"{slot}_team"] = picked
            data[f"{slot}_hps"] = [int(p["max_hp"]) for p in picked]
            data[f"{slot}_statuses"] = [[0, 0, 0, 0, 0, 0] for _ in picked]
            data[f"{slot}_active"] = 0
            data[f"{slot}_surrendered"] = False
            _duo_save(duo_file, data)
            print("bp3")
            # Clean up setup file within lock to prevent race conditions
            DUO_SETUP_LINKS.pop(setup_file, None)
            try:
                os.remove(setup_file)
            except Exception:
                traceback.print_exc()
    except Exception:
        traceback.print_exc()
    await _duo_maybe_start_after_team_setup(duo_file)
    return True


class DuoTeamSelectView(SelectPokemonView):
    def __init__(self, file_path: str, slot: str, user_id: int, mode: str):
        setup_file = _duo_create_setup_file(file_path, slot, user_id, mode)
        self.duo_file = file_path
        self.duo_slot = slot
        self.setup_file = setup_file
        super().__init__(int(user_id), setup_file)


class DuoTargetDropdown(discord.ui.Select):
    def __init__(self, file_path: str, slot: str, user_id: int, move_name: str):
        self.file_path = file_path
        self.slot = slot
        self.user_id = int(user_id)
        self.move_name = move_name
        data = _duo_load(file_path)
        options = _duo_target_options(data, slot)
        if not options:
            options = [discord.SelectOption(label="No valid target", value="none")]
        super().__init__(placeholder="Choose target (enemy slot)", min_values=1, max_values=1, options=options[:25])

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            return await interaction.response.send_message("Not your selection.", ephemeral=True)
        target = self.values[0]
        if target == "none":
            return await interaction.response.send_message("No valid target.", ephemeral=True)
        ready = await _duo_lock_choice(self.file_path, self.slot, {"move": self.move_name, "target": target})
        await interaction.response.edit_message(content=f"Locked in: **{self.move_name}** -> **{target.upper()}**", view=None)
        if self.view:
            self.view.stop()
        if ready:
            await _duo_resolve_round(self.file_path)


class DuoTargetView(discord.ui.View):
    def __init__(self, file_path: str, slot: str, user_id: int, move_name: str):
        super().__init__(timeout=DUO_MOVE_TIMEOUT_SECONDS)
        self.add_item(DuoTargetDropdown(file_path, slot, user_id, move_name))


class DuoMoveDropdown(discord.ui.Select):
    def __init__(self, file_path: str, slot: str, user_id: int):
        self.file_path = file_path
        self.slot = slot
        self.user_id = int(user_id)
        data = _duo_load(file_path)
        idx = _duo_active_idx(data, slot)
        member = _duo_slot_team_member(data, slot, idx if idx is not None else -1)
        moves = (member or {}).get("moves") or ["struggle"]
        options = [discord.SelectOption(label=m, value=m) for m in moves[:25]]
        super().__init__(placeholder=f"Choose move for {slot.upper()}", min_values=1, max_values=1, options=options)

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            return await interaction.response.send_message("Not your selection.", ephemeral=True)
        move_name = self.values[0]
        await interaction.response.edit_message(content=f"Move selected: **{move_name}**. Choose target.", view=DuoTargetView(self.file_path, self.slot, self.user_id, move_name))
        if self.view:
            self.view.stop()


class DuoMoveView(discord.ui.View):
    def __init__(self, file_path: str, slot: str, user_id: int):
        super().__init__(timeout=DUO_MOVE_TIMEOUT_SECONDS)
        self.file_path = file_path
        self.slot = slot
        self.user_id = int(user_id)
        self.add_item(DuoMoveDropdown(file_path, slot, user_id))
        self.add_item(DuoSwitchDropdown(file_path, slot, user_id))

    @discord.ui.button(label="Surrender", style=discord.ButtonStyle.danger, row=1)
    async def surrender(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            return await interaction.response.send_message("Not your selection.", ephemeral=True)
        ready = await _duo_lock_choice(self.file_path, self.slot, {"surrender": True})
        await interaction.response.edit_message(content="Surrender selected. Your full team will forfeit this battle.", view=None)
        if ready:
            await _duo_resolve_round(self.file_path)

    async def on_timeout(self):
        # Match BattleMoveSelectView behavior: timeout implies surrender for that slot.
        try:
            ready = await _duo_lock_choice(self.file_path, self.slot, {"surrender": True}, only_if_missing=True)
            if ready:
                await _duo_resolve_round(self.file_path)
        except Exception:
            traceback.print_exc()


async def _duo_prompt_moves(file_path: str, channel: discord.abc.Messageable):
    if not os.path.exists(file_path):
        return
    data = _duo_load(file_path)

    def _format_timeout(seconds: int) -> str:
        if seconds % 60 == 0:
            mins = seconds // 60
            return f"{mins} minute{'s' if mins != 1 else ''}"
        mins = seconds // 60
        secs = seconds % 60
        if mins:
            return f"{mins} minute{'s' if mins != 1 else ''} {secs} second{'s' if secs != 1 else ''}"
        return f"{secs} second{'s' if secs != 1 else ''}"

    timeout_text = _format_timeout(DUO_MOVE_TIMEOUT_SECONDS)

    for slot in DUO_SLOTS:
        if not _duo_slot_alive(data, slot):
            continue
        uid = int(data.get(f"{slot}_id") or 0)
        user = bot.get_user(uid)
        if not user:
            try:
                user = await bot.fetch_user(uid)
            except Exception:
                user = None
        view = DuoMoveView(file_path, slot, uid)
        sent = False
        if user:
            try:
                await user.send(
                    f"Choose your action for **{slot.upper()}**.\n"
                    f"You have **{timeout_text}** to select; if you do not choose in time, your team will auto-surrender.",
                    view=view,
                )
                sent = True
            except Exception:
                sent = False
        if not sent:
            await channel.send(
                f"<@{uid}> choose your action for **{slot.upper()}**.\n"
                f"You have **{timeout_text}** to select; if you do not choose in time, your team will auto-surrender.",
                view=view,
            )


class DuoSwitchDropdown(discord.ui.Select):
    def __init__(self, file_path: str, slot: str, user_id: int):
        self.file_path = file_path
        self.slot = slot
        self.user_id = int(user_id)
        data = _duo_load(file_path) if os.path.exists(file_path) else {}
        team = data.get(f"{slot}_team") or []
        hps = data.get(f"{slot}_hps") or []
        active_idx = _duo_active_idx(data, slot) if data else None
        options = []
        for i, member in enumerate(team):
            if i == active_idx:
                continue
            hp = int(hps[i] if i < len(hps) else 0)
            if hp <= 0:
                continue
            name = str(member.get("name") or "").strip().lower()
            if not name:
                continue
            max_hp = int(member.get("max_hp") or _duo_max_hp_for(name))
            options.append(
                discord.SelectOption(
                    label=f"Switch to {name.title()}",
                    value=name,
                    description=f"{hp}/{max_hp} HP",
                )
            )
        if not options:
            options = [discord.SelectOption(label="No switch targets", value="none")]
        super().__init__(
            placeholder=f"Switch for {slot.upper()}",
            min_values=1,
            max_values=1,
            options=options[:25],
        )

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            return await interaction.response.send_message("Not your selection.", ephemeral=True)
        target_name = self.values[0]
        if target_name == "none":
            return await interaction.response.send_message("No valid switch target.", ephemeral=True)
        ready = await _duo_lock_choice(self.file_path, self.slot, {"switch": target_name})
        await interaction.response.edit_message(content=f"Locked in: **Switch to {target_name.title()}**", view=None)
        if ready:
            await _duo_resolve_round(self.file_path)


async def _duo_lock_choice(file_path: str, slot: str, choice: dict, only_if_missing: bool = False) -> bool:
    ready = False
    if not os.path.exists(file_path):
        return False
    lock = _duo_lock_for(file_path)
    async with lock:
        if not os.path.exists(file_path):
            return False
        data = _duo_load(file_path)
        if only_if_missing and data.get(f"{slot}_choice"):
            return False
        if not _duo_slot_alive(data, slot):
            return False
        if (choice or {}).get("surrender"):
            side_slots = ("p11", "p12") if slot.startswith("p1") else ("p21", "p22")
            for s in side_slots:
                data[f"{s}_choice"] = {"surrender": True}
            ready = not data.get("resolving", False)
            if ready:
                data["resolving"] = True
            _duo_save(file_path, data)
            return ready
        data[f"{slot}_choice"] = choice
        ready = _duo_choice_ready(data) and not data.get("resolving", False)
        if ready:
            data["resolving"] = True
        _duo_save(file_path, data)
    return ready


def _duo_apply_switch(data: dict, slot: str, target_name: str) -> bool:
    team = data.get(f"{slot}_team") or []
    hps = data.get(f"{slot}_hps") or []
    statuses = data.get(f"{slot}_statuses") or []
    if not team:
        return False
    target_name = str(target_name or "").strip().lower()
    current_idx = _duo_active_idx(data, slot)
    if current_idx is None:
        return False
    target_idx = None
    for i, member in enumerate(team):
        name = str((member or {}).get("name") or "").strip().lower()
        if name == target_name:
            target_idx = i
            break
    if target_idx is None or target_idx == current_idx:
        return False
    if target_idx >= len(hps) or int(hps[target_idx] or 0) <= 0:
        return False

    def _swap(lst):
        if not isinstance(lst, list) or current_idx >= len(lst) or target_idx >= len(lst):
            return lst
        out = list(lst)
        out[current_idx], out[target_idx] = out[target_idx], out[current_idx]
        return out

    data[f"{slot}_team"] = _swap(team)
    data[f"{slot}_hps"] = _swap(hps)
    data[f"{slot}_statuses"] = _swap(statuses)
    data[f"{slot}_active"] = current_idx
    return True


def _duo_apply_stat_changes(data: dict, atk_slot: str, def_slot: str, move_name: str):
    try:
        eff = get_move_effect(move_name)[0] or ""
    except Exception:
        eff = ""
    self_changes = parse_stat_changes(eff) if eff else {}
    target_changes = parse_target_stat_changes(eff) if eff else {}
    stat_order = ["HP", "Attack", "Defense", "Special Attack", "Special Defense", "Speed"]
    aidx = _duo_active_idx(data, atk_slot)
    didx = _duo_active_idx(data, def_slot)
    if aidx is None or didx is None:
        return
    a_statuses = data.get(f"{atk_slot}_statuses") or []
    d_statuses = data.get(f"{def_slot}_statuses") or []
    if aidx >= len(a_statuses) or didx >= len(d_statuses):
        return
    for i, stat in enumerate(stat_order):
        a_statuses[aidx][i] = max(-6, min(6, int(a_statuses[aidx][i]) + int(self_changes.get(stat, 0))))
        d_statuses[didx][i] = max(-6, min(6, int(d_statuses[didx][i]) + int(target_changes.get(stat, 0))))


async def _duo_resolve_round(file_path: str):
    lock = _duo_lock_for(file_path)
    channel = None
    round_embed = None
    winner_side = None
    data = None
    if not os.path.exists(file_path):
        return
    async with lock:
        if not os.path.exists(file_path):
            return
        data = _duo_load(file_path)
        cid = int(data.get("channel") or 0)
        try:
            channel = bot.get_channel(cid) or await bot.fetch_channel(cid)
        except Exception:
            channel = None

        round_logs = {slot: "No action." for slot in DUO_SLOTS}
        action_order = []

        # If any slot surrendered, its whole side forfeits immediately.
        surrendered_sides = set()
        for slot in DUO_SLOTS:
            if not _duo_slot_alive(data, slot):
                continue
            choice = data.get(f"{slot}_choice") or {}
            if choice.get("surrender"):
                surrendered_sides.add("p1" if slot.startswith("p1") else "p2")

        for side in surrendered_sides:
            for slot in ("p11", "p12") if side == "p1" else ("p21", "p22"):
                hps = data.get(f"{slot}_hps") or []
                data[f"{slot}_hps"] = [0 for _ in hps]
                data[f"{slot}_surrendered"] = True
                round_logs[slot] = "Surrendered. Team forfeited."

        # Apply switches first (same idea as battle_round switch phase).
        for slot in DUO_SLOTS:
            if not _duo_slot_alive(data, slot):
                continue
            choice = data.get(f"{slot}_choice") or {}
            target_switch = choice.get("switch")
            if target_switch:
                if _duo_apply_switch(data, slot, target_switch):
                    round_logs[slot] = f"Switched to **{str(target_switch).title()}**."
                else:
                    round_logs[slot] = f"Switch to **{str(target_switch).title()}** failed."

        # Build action queue for all 4 battlers.
        actions = []
        for slot in DUO_SLOTS:
            if not _duo_slot_alive(data, slot):
                continue
            choice = data.get(f"{slot}_choice") or {}
            if choice.get("switch"):
                continue
            move = choice.get("move")
            target = choice.get("target")
            if not move:
                round_logs[slot] = "No move selected."
                continue
            pri = get_move_priority(move)
            pri = 0 if pri is None else int(pri)
            spd = _duo_slot_speed(data, slot)
            slot_active = data.get(f"{slot}_active")
            actions.append((pri, spd, random.random(), slot, target, move, slot_active))

        actions.sort(key=lambda t: (-t[0], -t[1], t[2]))
        for _, _, _, slot, target_slot, move, original_active_idx in actions:
            action_order.append(slot)
            hps = data.get(f"{slot}_hps") or []
            if original_active_idx is None or original_active_idx >= len(hps) or int(hps[original_active_idx] or 0) <= 0:
                round_logs[slot] = f"Tried **{move}**, but fainted before moving."
                continue

            # If selected target is gone, retarget to an alive opponent.
            if not target_slot or not _duo_slot_alive(data, target_slot):
                alive_targets = [s for s in _duo_opponents(slot) if _duo_slot_alive(data, s)]
                if not alive_targets:
                    round_logs[slot] = f"Used **{move}**, but no valid target remained."
                    continue
                target_slot = alive_targets[0]

            aidx = _duo_active_idx(data, slot)
            didx = _duo_active_idx(data, target_slot)
            am = _duo_slot_team_member(data, slot, aidx if aidx is not None else -1)
            dm = _duo_slot_team_member(data, target_slot, didx if didx is not None else -1)
            if aidx is None or didx is None or not am or not dm:
                round_logs[slot] = f"Used **{move}**, but matchup state was invalid."
                continue

            a_name = am["name"]
            d_name = dm["name"]
            atk_stats, atk_types = get_pokemon_stats(a_name)
            def_stats, def_types = get_pokemon_stats(d_name)
            a_status = data.get(f"{slot}_statuses")[aidx]
            d_status = data.get(f"{target_slot}_statuses")[didx]

            try:
                dmg, heal, _ = apply_damage_pi(
                    move,
                    atk_stats,
                    def_stats,
                    atk_types,
                    def_types,
                    a_status,
                    d_status,
                    str(am.get("nature") or "hardy").strip().lower(),
                    str(dm.get("nature") or "hardy").strip().lower(),
                    am.get("ability") or "ball fetch",
                    dm.get("ability") or "ball fetch",
                    am.get("item"),
                    dm.get("item"),
                )
            except Exception:
                round_logs[slot] = f"Failed to use **{move}**."
                continue

            dmg = int(max(0, dmg or 0))
            heal = int(max(0, heal or 0))
            prev_target_hp = int(data[f"{target_slot}_hps"][didx] or 0)
            data[f"{target_slot}_hps"][didx] = max(0, prev_target_hp - dmg)
            data[f"{slot}_hps"][aidx] = min(int(am.get("max_hp") or 1), int(data[f"{slot}_hps"][aidx] or 0) + heal)
            _duo_apply_stat_changes(data, slot, target_slot, move)

            attacker_label = f"{str(a_name).title()} ({slot.upper()})"
            defender_label = f"{str(d_name).title()} ({target_slot.upper()})"
            faint_note = ""
            if prev_target_hp > 0 and int(data[f"{target_slot}_hps"][didx] or 0) <= 0:
                faint_note = f" {defender_label} fainted."
            round_logs[slot] = (
                f"{attacker_label} used **{move}** and inflicted **{dmg}** damage on {defender_label}"
                + (f", healed **{heal}**." if heal else ".")
                + faint_note
            )

        for slot in DUO_SLOTS:
            data[f"{slot}_choice"] = None
            _duo_active_idx(data, slot)

        p1_alive = _duo_side_alive(data, "p1")
        p2_alive = _duo_side_alive(data, "p2")
        if not p1_alive or not p2_alive:
            winner_side = "p1" if p1_alive else "p2"

        data["round"] = int(data.get("round", 1) or 1) + 1
        data["resolving"] = False
        _duo_save(file_path, data)

        # Round embed with one field per battler (battle_round style, but 4 slots).
        round_embed = discord.Embed(
            title="⚔️ Duo Round Results ⚔️",
            color=parse_embed_color(data.get("color")),
        )
        users = {}
        for slot in DUO_SLOTS:
            uid = int(data.get(f"{slot}_id") or 0)
            user = bot.get_user(uid)
            if not user:
                try:
                    user = await bot.fetch_user(uid)
                except Exception:
                    user = None
            users[slot] = user

        order_for_embed = action_order + [s for s in DUO_SLOTS if s not in action_order]
        for slot in order_for_embed:
            user = users.get(slot)
            member_name = user.display_name if user else slot.upper()
            aidx = _duo_active_idx(data, slot)
            member = _duo_slot_team_member(data, slot, aidx if aidx is not None else -1) if aidx is not None else None
            move_title = f"{slot.upper()} • {member_name}"
            if member:
                move_title += f" ({get_pokemon_emoji(member.get('name'))} {str(member.get('name') or '').title()})"
            round_embed.add_field(name=move_title, value=round_logs.get(slot, "No action."), inline=False)

    if not channel:
        return

    if round_embed:
        await channel.send(embed=round_embed)
        for slot in DUO_SLOTS:
            uid = int(data.get(f"{slot}_id") or 0)
            if not uid:
                continue
            user = bot.get_user(uid)
            if not user:
                try:
                    user = await bot.fetch_user(uid)
                except Exception:
                    user = None
            if user:
                try:
                    await user.send(embed=round_embed)
                except Exception:
                    pass

    if winner_side:
        await duo_announce_winner(file_path, winner_side)
        return
    await _duo_send_status(channel, file_path)
    await _duo_prompt_moves(file_path, channel)


async def duo_announce_winner(file_path: str, winner_side: str):
    if not os.path.exists(file_path):
        return
    data = _duo_load(file_path)
    winner_slots = ("p11", "p12") if winner_side == "p1" else ("p21", "p22")
    winner_mentions = [f"<@{int(data.get(f'{s}_id') or 0)}>" for s in winner_slots if int(data.get(f"{s}_id") or 0)]

    embed = discord.Embed(
        title="🏆 Battle Duo Ended",
        description=f"Winner Team: **{winner_side.upper()}** ({' + '.join(winner_mentions)})",
        color=discord.Color.gold(),
    )

    users = {}
    for slot in DUO_SLOTS:
        uid = int(data.get(f"{slot}_id") or 0)
        user = bot.get_user(uid)
        if not user:
            try:
                user = await bot.fetch_user(uid)
            except Exception:
                user = None
        users[slot] = user

    for slot in DUO_SLOTS:
        user = users.get(slot)
        display_name = user.display_name if user else slot.upper()
        team = data.get(f"{slot}_team") or []
        hps = data.get(f"{slot}_hps") or []
        lines = []
        for i, member in enumerate(team):
            poke_name = str(member.get("name") or "").strip().lower()
            if not poke_name:
                continue
            hp = int(hps[i] if i < len(hps) else 0)
            max_hp = int(member.get("max_hp") or _duo_max_hp_for(poke_name))
            moves = ", ".join(str(m).title() for m in (member.get("moves") or [])[:4]) or "None"
            nature = str(member.get("nature") or "hardy").strip().lower()
            ability = str(member.get("ability") or "None")
            item = str(member.get("item") or "None")
            lines.append(
                f"{get_pokemon_emoji(poke_name)} **{poke_name.title()}** ({nature}) {hp}/{max_hp} HP\n"
                f"⚔️ {moves}\n"
                f"Ability: {ability}\n"
                f"Held Item: {item}"
            )
        embed.add_field(
            name=f"{slot.upper()} • {display_name}",
            value="\n".join(lines) if lines else "No team data.",
            inline=False,
        )

    all_ids = [int(data.get(f"{slot}_id") or 0) for slot in DUO_SLOTS]
    all_ids = [uid for uid in all_ids if uid]
    any_pokemon_added = False
    damaged_pokemon_count = 0

    for slot in DUO_SLOTS:
        team = data.get(f"{slot}_team") or []
        hps = data.get(f"{slot}_hps") or []
        for i, member in enumerate(team):
            poke_name = str(member.get("name") or "").strip().lower()
            if not poke_name:
                continue
            any_pokemon_added = True
            max_hp = int(member.get("max_hp") or _duo_max_hp_for(poke_name))
            current_hp = int(hps[i] if i < len(hps) else 0)
            if current_hp < max_hp:
                damaged_pokemon_count += 1

    rewards_granted = False
    trainer_primarina_winners = []
    if any_pokemon_added and damaged_pokemon_count >= 7 and len(set(all_ids)) == 4:
        guild_id = _get_battle_guild_id(file_path)
        verification_ok = True
        guild = None
        if guild_id:
            guild = bot.get_guild(guild_id)
        if guild is not None:
            level_name = guild.verification_level.name.lower()
            if level_name not in {"low", "medium", "high", "highest"}:
                verification_ok = False

        if verification_ok:
            async with battle_reward_lock:
                for uid in all_ids:
                    _append_battle_reward(battle_reward_cache, uid, "coins", 10)
                    _append_battle_reward(battle_reward_cache, uid, "hero point", 1)
                for slot in winner_slots:
                    wid = int(data.get(f"{slot}_id") or 0)
                    if wid:
                        _append_battle_reward(battle_reward_cache, wid, "achilles point", 1)
                        _append_battle_reward(battle_reward_cache, wid, "event ticket", 1)
                rewards_granted = True

                for uid in all_ids:
                    if random.randint(1, 500) == 1:
                        trainer_primarina_winners.append(uid)

    if rewards_granted:
        reward_message = "Duo rewards queued: all 4 players might receive a mystery OU cosmetics."
    elif not any_pokemon_added:
        reward_message = "No rewards granted: no pokemon were added."
    elif damaged_pokemon_count < 7:
        reward_message = "No rewards granted: fewer than 7 pokemon took damage."
    else:
        reward_message = "No rewards granted for this duo battle."

    channel_fallback_notifications = []
    for slot in DUO_SLOTS:
        user = users.get(slot)
        if not user:
            continue
        try:
            await user.send(embed=embed)
            await user.send(reward_message)
            if user.id in trainer_primarina_winners:
                try:
                    with sqlite3.connect("cosmetics.db", timeout=30) as cosmetics_conn:
                        cos_cursor = cosmetics_conn.cursor()
                        _append_pokemon_cosmetic(cos_cursor, user.id, "primarina", "trainer")
                        cosmetics_conn.commit()
                    await user.send("🎉 Congratulations! You unlocked Trainer Primarina cosmetic for your Primarina.")
                except Exception:
                    channel_fallback_notifications.append(
                        f"<@{user.id}> almost got a mystery cosmetic!"
                    )
        except Exception:
            if user.id in trainer_primarina_winners:
                channel_fallback_notifications.append(
                    f"<@{user.id}> almost got a mystery cosmetic!"
                )

    channel_id = data.get("channel")
    channel = None
    if channel_id:
        try:
            channel = bot.get_channel(channel_id) or await bot.fetch_channel(channel_id)
        except Exception:
            channel = None
    if channel:
        await channel.send(embed=embed)
        await channel.send(reward_message)
        if channel_fallback_notifications:
            for notice in channel_fallback_notifications:
                await channel.send(notice)

    try:
        os.remove(file_path)
    except Exception:
        pass
    DUO_BATTLE_LOCKS.pop(file_path, None)


class DuoChallengeView(discord.ui.View):
    def __init__(self, inviter: discord.abc.User, invited: list[discord.abc.User], timeout: float = 90):
        super().__init__(timeout=timeout)
        self.inviter = inviter
        self.invited = {int(u.id) for u in invited}
        self.accepted = set()
        self.declined_by = None
        self.ready = False

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        uid = int(interaction.user.id)
        if uid not in self.invited:
            await interaction.response.send_message("Only invited players can answer this duo request.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="Accept", style=discord.ButtonStyle.success)
    async def accept(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.accepted.add(int(interaction.user.id))
        pending = [f"<@{uid}>" for uid in self.invited if uid not in self.accepted]
        if not pending:
            self.ready = True
            for child in self.children:
                child.disabled = True
            await interaction.response.edit_message(content="All invited players accepted the duo challenge.", view=self)
            self.stop()
            return
        await interaction.response.send_message(f"Accepted. Waiting for: {', '.join(pending)}", ephemeral=True)

    @discord.ui.button(label="Decline", style=discord.ButtonStyle.danger)
    async def decline(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.declined_by = int(interaction.user.id)
        for child in self.children:
            child.disabled = True
        await interaction.response.edit_message(content=f"<@{self.declined_by}> declined the duo challenge.", view=self)
        self.stop()


class DuoModeSelectView(discord.ui.View):
    def __init__(self, allowed_ids: set[int], timeout: float = 120):
        super().__init__(timeout=timeout)
        self.allowed_ids = allowed_ids
        self.selected_mode = None

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if int(interaction.user.id) not in self.allowed_ids:
            await interaction.response.send_message("Only the 4 battlers can select mode.", ephemeral=True)
            return False
        return True

    async def _pick(self, interaction: discord.Interaction, mode_name: str):
        if self.selected_mode is not None:
            return await interaction.response.send_message("Mode already selected.", ephemeral=True)
        self.selected_mode = mode_name
        for child in self.children:
            child.disabled = True
        await interaction.response.edit_message(content=f"Mode selected: **{mode_name}**", view=self)
        self.stop()

    @discord.ui.button(label="p2", style=discord.ButtonStyle.primary)
    async def p2(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._pick(interaction, "p2")

    @discord.ui.button(label="p2 rng", style=discord.ButtonStyle.secondary)
    async def p2_rng(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._pick(interaction, "p2 rng")

    @discord.ui.button(label="p∞", style=discord.ButtonStyle.success)
    async def pinf(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._pick(interaction, "p∞ (p2 + ability + item)")

    @discord.ui.button(label="standard", style=discord.ButtonStyle.danger)
    async def standard(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._pick(interaction, "standard")

    @discord.ui.button(label="simplified", style=discord.ButtonStyle.primary)
    async def simplified(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._pick(interaction, "simplified")


def _duo_validate_players(author_id: int, teammate1: discord.abc.User, opponent1: discord.abc.User, opponent2: discord.abc.User, test_mode: bool = False) -> str | None:
    if not test_mode:
        ids = [author_id, teammate1.id, opponent1.id, opponent2.id]
        if len(set(ids)) != 4:
            return "All 4 slots must be different users."
        if teammate1.bot or opponent1.bot or opponent2.bot:
            return "Bots are not allowed in `battle_duo`."
    return None


async def _duo_send_team_selection_dms(file_path: str, users_by_slot: dict[str, discord.abc.User], fallback_channel: discord.abc.Messageable, test_mode: bool = False):
    data = _duo_load(file_path)
    mode = str(data.get("mode") or "p2")
    for slot, user in users_by_slot.items():
        view = DuoTeamSelectView(file_path, slot, int(user.id), mode)
        text = (
            f"Mode: **{mode}**\n"
            f"You are **{slot.upper()}**.\n"
            "Select your 3-pokemon team for battle_duo."
        )
        try:
            await user.send(text, view=view)
        except Exception:
            await fallback_channel.send(f"<@{user.id}> {text}", view=view)


async def _start_duo_battle_flow(
    channel: discord.abc.Messageable,
    author: discord.abc.User,
    teammate1: discord.abc.User,
    opponent1: discord.abc.User,
    opponent2: discord.abc.User,
    test_mode: bool = False,
):
    if channel is None:
        return
    err = _duo_validate_players(author.id, teammate1, opponent1, opponent2, test_mode)
    if err:
        return await channel.send(err)

    participant_ids = [author.id, teammate1.id, opponent1.id, opponent2.id]
    file_path = _duo_battle_path(participant_ids)
    if os.path.exists(file_path):
        return await channel.send("A battle_duo already exists for these participants.")

    if not test_mode:
        challenge = DuoChallengeView(author, [teammate1, opponent1, opponent2])
        challenge_msg = await channel.send(
            f"{teammate1.mention} {opponent1.mention} {opponent2.mention}\n"
            f"{author.mention} challenged you to **battle_duo**.\nAccept or decline:",
            view=challenge,
        )
        await challenge.wait()
        if not challenge.ready:
            if challenge.declined_by is None:
                await challenge_msg.edit(content="Duo challenge timed out.", view=challenge)
            return

        all_ids = {int(author.id), int(teammate1.id), int(opponent1.id), int(opponent2.id)}
        mode_view = DuoModeSelectView(all_ids)
        mode_msg = await channel.send(
            f"{author.mention} {teammate1.mention} {opponent1.mention} {opponent2.mention}\nChoose the duo battle mode:",
            view=mode_view,
        )
        await mode_view.wait()
        if not mode_view.selected_mode:
            await mode_msg.edit(content="Mode selection timed out.", view=mode_view)
            return

        selected_mode = mode_view.selected_mode
    else:
        selected_mode = "p2"

    data = {
        "channel": getattr(channel, "id", None),
        "guild_id": getattr(getattr(channel, "guild", None), "id", None),
        "round": 1,
        "resolving": False,
        "setup_complete": False,
        "mode": selected_mode,
        "background": get_battle_background(int(author.id)),
        "p11_id": int(author.id),
        "p12_id": int(teammate1.id),
        "p21_id": int(opponent1.id),
        "p22_id": int(opponent2.id),
    }
    for slot in DUO_SLOTS:
        data[f"{slot}_team"] = []
        data[f"{slot}_hps"] = []
        data[f"{slot}_statuses"] = []
        data[f"{slot}_active"] = 0
        data[f"{slot}_choice"] = None
        data[f"{slot}_surrendered"] = False
    _duo_save(file_path, data)

    if not test_mode:
        await channel.send(
            "Accepted and mode selected.\n"
            f"Team p1: {author.mention} (**p11**) + {teammate1.mention} (**p12**)\n"
            f"Team p2: {opponent1.mention} (**p21**) + {opponent2.mention} (**p22**)\n"
            "Team selection has been sent in DM to all 4 players."
        )
        await _duo_send_team_selection_dms(
            file_path,
            {"p11": author, "p12": teammate1, "p21": opponent1, "p22": opponent2},
            channel,
        )
    else:
        await channel.send(
            "Test battle_duo started.\n"
            f"Team p1: {author.mention} (**p11**) + Arceus/Yveltal/Marshadow (**p12**)\n"
            f"Team p2: Primal Groudon/Mega Metagross/Primal Kyogre (**p21**) + Primal Groudon/Mega Metagross/Primal Kyogre (**p22**)\n"
            "Team selection has been sent in DM to you."
        )
        await _duo_send_team_selection_dms(
            file_path,
            {"p11": author},
            channel,
            test_mode=True,
        )
        # Set pre-selected teams
        teammate_team = _duo_normalize_team({
            "p1": {"name": "arceus"},
            "p2": {"name": "yveltal"},
            "p3": {"name": "marshadow"}
        })
        opponent_team = _duo_normalize_team({
            "p1": {"name": "primal groudon"},
            "p2": {"name": "mega metagross"},
            "p3": {"name": "primal kyogre"}
        })
        for slot in ["p12", "p21", "p22"]:
            team = teammate_team if slot == "p12" else opponent_team
            data[f"{slot}_team"] = team
            data[f"{slot}_hps"] = [p["max_hp"] for p in team]
            data[f"{slot}_statuses"] = [[0, 0, 0, 0, 0, 0] for _ in team]
            data[f"{slot}_active"] = 0
            data[f"{slot}_choice"] = None
            data[f"{slot}_surrendered"] = False
        data["setup_complete"] = True
        _duo_save(file_path, data)
        #await channel.send("All teams selected. Battle is starting.")
        #await _duo_send_status(channel, file_path, "Battle Duo Started")
        #await _duo_prompt_moves(file_path, channel)


def _duo_find_battle_for_user(user_id: int) -> tuple[str | None, str | None]:
    try:
        files = os.listdir(DUO_BATTLE_FOLDER)
    except Exception:
        return None, None
    for name in files:
        path = os.path.join(DUO_BATTLE_FOLDER, name)
        if not os.path.isfile(path):
            continue
        try:
            data = _duo_load(path)
        except Exception:
            continue
        for slot in DUO_SLOTS:
            if int(data.get(f"{slot}_id", 0) or 0) == int(user_id):
                return path, slot
    return None, None


async def _duo_force_surrender_for_user(user_id: int) -> tuple[bool, str]:
    file_path, slot = _duo_find_battle_for_user(int(user_id))
    if not file_path or not slot:
        return False, "You are not in an active duo battle."

    side = "p1" if slot.startswith("p1") else "p2"
    side_slots = ("p11", "p12") if side == "p1" else ("p21", "p22")
    winner_side = "p2" if side == "p1" else "p1"
    lock = _duo_lock_for(file_path)
    async with lock:
        data = _duo_load(file_path)
        for s in side_slots:
            hps = data.get(f"{s}_hps") or []
            data[f"{s}_hps"] = [0 for _ in hps]
            data[f"{s}_surrendered"] = True
            data[f"{s}_choice"] = {"surrender": True}
        data["resolving"] = False
        _duo_save(file_path, data)
    await duo_announce_winner(file_path, winner_side)
    return True, "Your duo team surrendered."


@bot.command(name="battle_duo")
async def battle_duo_prefix(
    ctx: commands.Context,
    *args,
):
    if len(args) == 1 and str(args[0]).strip().lower() in {"x", "surrender"}:
        ok, msg = await _duo_force_surrender_for_user(ctx.author.id)
        return await ctx.send(msg)

    if len(args) == 1 and str(args[0]).strip().lower() == "test":
        await _start_duo_battle_flow(ctx.channel, ctx.author, ctx.author, ctx.author, ctx.author, test_mode=True)
        return

    if len(args) != 3:
        return await ctx.send("Usage: `!battle_duo <teammate1> <opponent1> <opponent2>`")
    converter = commands.MemberConverter()
    try:
        teammate1 = await converter.convert(ctx, str(args[0]))
        opponent1 = await converter.convert(ctx, str(args[1]))
        opponent2 = await converter.convert(ctx, str(args[2]))
    except Exception:
        return await ctx.send("Could not parse players. Use mentions: `!battle_duo @ally @opp1 @opp2`.")
    await _start_duo_battle_flow(ctx.channel, ctx.author, teammate1, opponent1, opponent2)


@bot.tree.command(name="battle_duo", description="Start a 2v2 duo battle.")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
@app_commands.choices(action=[
    app_commands.Choice(name="start", value="start"),
    app_commands.Choice(name="x (surrender my team)", value="x"),
])
async def battle_duo_slash(
    interaction: discord.Interaction,
    action: str = "start",
    teammate1: discord.User = None,
    opponent1: discord.User = None,
    opponent2: discord.User = None,
):
    await interaction.response.defer(ephemeral=True if action == "x" else False)
    if action == "x":
        _, msg = await _duo_force_surrender_for_user(interaction.user.id)
        return await interaction.followup.send(msg, ephemeral=True)
    if not teammate1 or not opponent1 or not opponent2:
        return await interaction.followup.send(
            "For `start`, provide teammate1, opponent1, and opponent2.",
            ephemeral=True,
        )
    await _start_duo_battle_flow(interaction.channel, interaction.user, teammate1, opponent1, opponent2)


def _build_tower_battle_data(player1: discord.User, channel_id: int, tower_id: int, floor_value: int, guild_id: int | None = None) -> dict:
    p1_equipped = get_equipped_battle_cosmetics(player1.id)
    required_wins = _tower_required_wins(tower_id)
    is_boss = int(floor_value) >= int(required_wins)
    data = {
        "mode": TOWER_MODE_SIMPLIFIED,
        "rarity": "tower",
        "tower_battle": {
            "tower_id": int(tower_id),
            "is_boss": bool(is_boss),
            "floor_before": int(floor_value),
            "required_wins": int(required_wins),
        },
        "weather": None,
        "weather_turns": 0,
        "terrain": None,
        "terrain_turns": 0,
        "number": 3,
        "channel": channel_id,
        "guild_id": guild_id,
        "p1_order": None,
        "p2_order": None,
        "p1_id": player1.id,
        "p2_id": "NPC",
        "p1_name": player1.display_name,
        "p2_name": f"{TOWER_TEXT.get(int(tower_id), 'Tower')} Guardian",
        "background": p1_equipped["background"] or get_battle_background(player1.id),
        "color": p1_equipped["color"],
        "p1_pokeball": p1_equipped["pokeball"],
        "p2_pokeball": None,
        "p2_color": None,
        "p2_background": None,
        "p1_status_cosmetic": p1_equipped["status"] or "ninja",
        "p2_status_cosmetic": "ninja",
        "graphics": p1_equipped["graphics"] or "animated",
        "p1_graphics": p1_equipped["graphics"] or "animated",
        "p2_graphics": "animated",
        "p1_choice": None,
        "p2_choice": None,
        "p1_field": [],
        "p2_field": [],
        "trick_room_turns": 0,
        "p1_light_screen_turns": 0,
        "p2_light_screen_turns": 0,
        "p1_reflect_turns": 0,
        "p2_reflect_turns": 0,
        "mega_used": False,
        "z_move_used": False,
    }
    for prefix in ("p1", "p2"):
        for i in range(1, 7):
            data[f"{prefix}_p{i}"] = None
            data[f"{prefix}_stats{i}"] = None
            data[f"{prefix}_ev{i}"] = None
            data[f"{prefix}_nature{i}"] = None
            data[f"{prefix}_moves{i}"] = None
            data[f"{prefix}_hp{i}"] = None
            data[f"{prefix}_status{i}"] = None
            data[f"{prefix}_ability{i}"] = None
            data[f"{prefix}_hi{i}"] = None
            data[f"{prefix}_cosmetic{i}"] = None
            data[f"{prefix}_condition{i}"] = []
            data[f"{prefix}_charge{i}"] = None
    return data


class TowerChallengeSelect(discord.ui.Select):
    def __init__(self, panel_view: "TowerPanelView"):
        self.panel_view = panel_view
        progress = panel_view.progress
        unlocked = _tower_unlocked_level(progress)
        options = []
        for tower_id in (1, 2, 3, 4, 5):
            if tower_id > unlocked:
                continue
            row = progress.get(f"tower{tower_id}")
            floor_value = int((row or {}).get("tower_floor") or 0)
            required = _tower_required_wins(tower_id)
            boss_tag = "Boss Floor" if floor_value >= required else f"Floor {_tower_display_floor(floor_value)}"
            options.append(
                discord.SelectOption(
                    label=TOWER_TEXT[tower_id],
                    value=str(tower_id),
                    description=boss_tag[:100],
                )
            )
        super().__init__(
            placeholder="Choose a tower to challenge...",
            min_values=1,
            max_values=1,
            options=options or [discord.SelectOption(label="No towers unlocked", value="0", description="Complete previous tower first")],
            disabled=not bool(options),
        )

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.panel_view.user_id:
            return await interaction.response.send_message("This tower panel is not yours.", ephemeral=True)
        if self.values[0] == "0":
            return await interaction.response.send_message("No available tower to challenge.", ephemeral=True)

        await interaction.response.defer(ephemeral=True)
        tower_id = int(self.values[0])
        progress = _tower_user_progress(self.panel_view.user_id)
        if tower_id > _tower_unlocked_level(progress):
            return await interaction.followup.send("That tower is still locked.", ephemeral=True)

        row = progress.get(f"tower{tower_id}") or {}
        floor_value = int(row.get("tower_floor") or 0)
        not_limit = _tower_increment_daily_challenge(interaction.user.id)
        if not_limit:
            data = _build_tower_battle_data(
                interaction.user,
                interaction.channel.id,
                tower_id=tower_id,
                floor_value=floor_value,
                guild_id=interaction.guild.id if interaction.guild else None,
            )
            filepath = _create_battle(data)
            await _send_team_selection_panel(
                interaction.user,
                interaction.user.id,
                filepath,
                "p1",
                f"Prepare your team for **{TOWER_TEXT.get(tower_id, 'Tower')}**.",
            )
            await interaction.followup.send(
                f"Tower challenge started: **{TOWER_TEXT.get(tower_id, 'Tower')}**. Check your DMs to select your team.",
                ephemeral=True,
            )
        else:
            await interaction.followup.send(
                f"Please wait for limit reset tomorrow",
                ephemeral=True,
            )


