class TowerPanelView(LayoutView):
    def __init__(self, user: discord.User, guild: discord.Guild | None):
        super().__init__(timeout=300)
        self.user_id = int(user.id)
        self.guild = guild
        self.progress = _tower_user_progress(self.user_id)
        self._refresh()

    def _refresh(self):
        self.clear_items()
        self.progress = _tower_user_progress(self.user_id)
        row2 = self.progress.get("tower2") or {}
        row3 = self.progress.get("tower3") or {}
        row4 = self.progress.get("tower4") or {}
        row5 = self.progress.get("tower5") or {}
        dragon_scale = int(row2.get("dragon_scale") or 0)
        fantasy_gem = int(row3.get("fantasy_gem") or 0)
        chainsaw = int(row4.get("chainsaw") or 0)
        liquid_of_life = int(row5.get("liquid_of_life") or 0)
        unlocked = _tower_unlocked_level(self.progress)

        container = discord.ui.Container()
        container.add_item(discord.ui.TextDisplay("# Tower of Heavens"))
        container.add_item(discord.ui.TextDisplay(f"Your highest unlocked tower: **{TOWER_TEXT.get(unlocked, 'Standard Tower')}**"))
        container.add_item(discord.ui.TextDisplay(_tower_floor_status_line(1, self.progress.get("tower1"))))
        container.add_item(discord.ui.TextDisplay(_tower_floor_status_line(2, self.progress.get("tower2"))))
        container.add_item(discord.ui.TextDisplay(_tower_floor_status_line(3, self.progress.get("tower3"))))
        container.add_item(discord.ui.TextDisplay(_tower_floor_status_line(4, self.progress.get("tower4"))))
        container.add_item(discord.ui.TextDisplay(_tower_floor_status_line(5, self.progress.get("tower5"))))
        coins, ss, ec, sec, et = _get_gacha_balances(self.user_id)
        container.add_item(discord.ui.TextDisplay(f"Dragon Scale: **{dragon_scale}**  |  Fantasy Gem: **{fantasy_gem}**\nChainsaw: **{chainsaw}**  |  Liquid of Life: **{liquid_of_life}**"))

        select_row = discord.ui.ActionRow()
        select_row.add_item(TowerChallengeSelect(self))
        container.add_item(select_row)

        exchange_row = discord.ui.ActionRow()
        exchange_row.add_item(TowerExchangeSelect(self))
        container.add_item(exchange_row)

        remaining, daily_count, last_reset = _tower_daily_challenges_remaining(self.user_id)
        reset_time = datetime.fromtimestamp(last_reset, timezone.utc) + timedelta(seconds=TOWER_DAILY_RESET_SECONDS)
        container.add_item(discord.ui.TextDisplay(
            f"Daily Tower Challenges: **{daily_count}/60** (resets <t:{int(reset_time.timestamp())}:R>)"
        ))
        container.add_item(discord.ui.TextDisplay(
            f"Weekly exchange reset: **{_tower_time_until_next_reset()}**"
        ))

        """guild_id = self.guild.id if self.guild else None
        if guild_id:
            bg_url = get_war_background_url(guild_id)
            if bg_url:
                try:
                    container.add_item(discord.ui.MediaGallery(
                        discord.ui.MediaGalleryItem(media=bg_url)
                    ))
                except Exception:
                    pass"""

        container.add_item(discord.ui.TextDisplay(
            "Simplified mode is used for tower battles. "
            "Get to a certain floor on each tower to fight a boss and progress."
        ))
        self.add_item(container)


