def _find_tower_entry_by_name(name: str, tower_id: int = 1) -> dict | None:
    """Finds a tower entry by pokemon name."""
    name_normalized = str(name or "").strip().lower()
    pool = _get_tower_pool_entries(tower_id)
    for entry in pool:
        if entry.get("name") == name_normalized:
            return entry
    return None


@bot.command(name="test_tower")
async def test_tower(ctx: commands.Context, poke1: str, poke2: str, poke3: str):
    """
    Owner-only command to test tower battle with 3 specified NPC pokemon from tower entries.
    User will select their own team, then battle proceeds normally.
    Usage: !test_tower pokemon1 pokemon2 pokemon3
    """
    if ctx.author.id not in owner_ids:
        return await ctx.send("❌ Owner only command.")
    
    try:
        # Get tower entries for the 3 pokemon
        tower_id = 1
        poke_entries = []
        poke_names = [poke1.lower(), poke2.lower(), poke3.lower()]
        
        for poke_name in poke_names:
            entry = _find_tower_entry_by_name(poke_name, tower_id)
            if not entry:
                return await ctx.send(f"❌ Pokemon not found in tower entries: {poke_name}")
            poke_entries.append(entry)
        
        # Build battle data with tower settings (same as regular tower)
        data = _build_tower_battle_data(
            ctx.author,
            ctx.channel.id,
            tower_id=tower_id,
            floor_value=0,
            guild_id=ctx.guild.id if ctx.guild else None,
        )
        
        # Populate p2 (NPC) team with tower entries
        for idx, entry in enumerate(poke_entries, start=1):
            poke_name = entry.get("name")
            base_stats, _ = get_pokemon_stats(poke_name)
            
            # Calculate max HP
            max_hp = max(1, int(2 * int(base_stats[0]) + 31 + 5 + 110))
            
            # Resolve moves from entry or from file
            moves = entry.get("moves") or []
            if not moves:
                moves_path = os.path.join("moves", f"{poke_name.capitalize()}_moves.txt")
                if os.path.exists(moves_path):
                    try:
                        with open(moves_path, "r", encoding="utf-8") as mfile:
                            content = mfile.read().strip()
                            npc_moves = [m.strip().lower() for m in content.split("/") if m.strip()]
                            if npc_moves:
                                moves = npc_moves[:4]
                    except Exception:
                        pass
            if not moves:
                moves = ["tackle", "growl", "protect", "hyper beam"]
            
            # Pick a random nature from the entry's natures
            natures = entry.get("natures") or ["hardy"]
            chosen_nature = random.choice(natures)
            
            # Get ability from entry
            ability = entry.get("ability") or "ball fetch"
            
            # Resolve held item
            item_map = {
                "arceus": "silk scarf",
                "yveltal": "sharp beak",
                "mega rayquaza": "choice scarf",
                "primal groudon": "choice band",
                "primal kyogre": "choice scarf",
                "crowned zacian": "rusted sword",
                "shadow rider calyrex": "choice specs",
                "miraidon": "life orb",
                "world guardian mega rayquaza": "life orb",
                "mirror shield origin dialga": "choice specs",
                "arachnid origin giratina": "life orb",
                "wonder bidoof": "life orb",
                "wolf king zacian": "assault vest",
                "mega pyroar": "life orb",
                "mega metagross": "assault vest",
                "mega salamence": "choice band",
                "mega golisopod": "leftovers", 
                "mega malamar": "leftovers",
                "mega garchomp z": "choice specs",  
                "golisopod": "leftovers", 
                "garchomp": "life orb", 
                "primarina": "choice specs", 
                "dragapult": "life orb", 
                "dragonite": "choice scarf", 
            }
            held_item = item_map.get(poke_name, "scope lense")
            
            # Set NPC pokemon data
            data[f"p2_p{idx}"] = poke_name
            data[f"p2_hp{idx}"] = max_hp
            data[f"p2_stats{idx}"] = [31, 31, 31, 31, 31, 31]
            data[f"p2_nature{idx}"] = chosen_nature
            data[f"p2_moves{idx}"] = moves
            data[f"p2_ability{idx}"] = ability
            data[f"p2_hi{idx}"] = held_item
            data[f"p2_condition{idx}"] = []
            data[f"p2_cosmetic{idx}"] = None
            data[f"p2_status{idx}"] = [0, 0, 0, 0, 0, 0]
            data[f"p2_ev{idx}"] = [0, 0, 0, 0, 0, 0]
            data[f"p2_charge{idx}"] = 0
        
        data["p2_order"] = poke_names
        
        # Create battle in database
        filepath = _create_battle(data)
        
        # Send team selection panel (user selects their team)
        await _send_team_selection_panel(
            ctx.author,
            ctx.author.id,
            filepath,
            "p1",
            f"Prepare your team for **Tower Test Battle** against {', '.join(p.title() for p in poke_names)}.",
        )
        
        await ctx.send(
            f"✅ Test tower battle started with opponents: **{', '.join(p.title() for p in poke_names)}**. Check your DMs to select your team.",
            ephemeral=False,
        )
        
    except Exception as e:
        await ctx.send(f"❌ Error: {e}")
        traceback.print_exc()


