import discord
import sqlite3



# ─────────────────────────────────────────────────────────────────────────────
#  HELPERS
# ─────────────────────────────────────────────────────────────────────────────

def _filter_listed(user_id: int, category: str, cosmetics: list, pokemon_name: str = None) -> tuple[list, list]:
    """
    Split cosmetics into (available, blocked).
    'blocked' = currently active on the market → cannot be equipped.
    """
    available, blocked = [], []
    for c in cosmetics:
        if is_cosmetic_listed(user_id, category, c.strip(), pokemon_name):
            blocked.append(c.strip())
        else:
            available.append(c.strip())
    return available, blocked


def _listed_warning(blocked: list) -> str:
    """Inline footer note shown when some cosmetics are hidden due to market listing."""
    names = ", ".join(f"**{b}**" for b in blocked[:5])
    extra = f" (+{len(blocked)-5} more)" if len(blocked) > 5 else ""
    return (
        f"\n\n🔒 {names}{extra} "
        f"{'is' if len(blocked)==1 else 'are'} listed on the market and hidden. "
        f"Use `market remove <id>` to delist."
    )

def is_cosmetic_listed(user_id, category, cosmetic, pokemon_name=None):
    with _connect_cosmetics_db() as db:
        row = db.execute(
            """SELECT 1 FROM market
               WHERE seller_id=? AND category=? AND cosmetic=?
               AND (pokemon_name IS ? OR (pokemon_name IS NULL AND ? IS NULL))
               AND status='active'""",
            (user_id, category, cosmetic, pokemon_name, pokemon_name)
        ).fetchone()
    return row is not None


def _global_clan_available_cosmetics(user_id: int, category: str, pokemon_name: str | None = None) -> list[str]:
    _, _, clan = find_user_global_clan(int(user_id))
    if not clan:
        return []
    rows = get_global_clan_inventory(clan["id"], category)
    values = []
    for row in rows:
        if pokemon_name and _normalize_name(row.get("pokemon_name")) != _normalize_name(pokemon_name):
            continue
        values.append(_normalize_name(row.get("cosmetic_name")))
    return sorted(set(v for v in values if v))
# ─────────────────────────────────────────────────────────────────────────────
#  CATEGORY PICKER
# ─────────────────────────────────────────────────────────────────────────────

class EquipCategoryView(discord.ui.View):
    def __init__(self, user_id):
        super().__init__(timeout=60)
        self.user_id = user_id

    async def interaction_check(self, interaction: discord.Interaction):
        return interaction.user.id == self.user_id

    @discord.ui.select(
        placeholder="Choose category...",
        options=[
            discord.SelectOption(label="Pokemon"),
            discord.SelectOption(label="Pokeball"),
            discord.SelectOption(label="Status"),
            discord.SelectOption(label="Graphics"),
            discord.SelectOption(label="Animation"),
            discord.SelectOption(label="Background"),
            discord.SelectOption(label="Embed Color"),
        ],
    )
    async def select_callback(self, interaction: discord.Interaction, select: discord.ui.Select):
        choice = select.values[0].lower()
        if choice == "pokemon":
            await interaction.response.send_modal(PokemonNameModal(self.user_id))
        else:
            if choice == "animation":
                choice = "graphics"
            await handle_simple_category(interaction, self.user_id, choice)


# ─────────────────────────────────────────────────────────────────────────────
#  POKEMON FLOW
# ─────────────────────────────────────────────────────────────────────────────

class PokemonNameModal(discord.ui.Modal, title="Enter Pokemon Name"):
    name = discord.ui.TextInput(label="Pokemon Name")

    def __init__(self, user_id):
        super().__init__()
        self.user_id = user_id

    async def on_submit(self, interaction: discord.Interaction):
        pokemon_name = self.name.value.lower()

        with sqlite3.connect("cosmetics.db") as db:
            cursor = db.cursor()
            cursor.execute(
                "SELECT available_cosmetics FROM pokemon WHERE user_id=? AND pokemon_name=?",
                (self.user_id, pokemon_name)
            )
            row = cursor.fetchone()

        clan_cosmetics = _global_clan_available_cosmetics(self.user_id, "pokemon", pokemon_name)

        if not row and not clan_cosmetics:
            await interaction.response.send_message(
                "You don't own cosmetics for that Pokémon.",
                ephemeral=True
            )
            return

        all_cosmetics = [c for c in (row[0].split(",") if row and row[0] else []) if c.strip()]
        all_cosmetics.extend(clan_cosmetics)
        all_cosmetics.extend(_get_trial_cosmetics_for_pokemon(self.user_id, pokemon_name))
        all_cosmetics = sorted(set(c.strip().lower() for c in all_cosmetics if c and c.strip()))
        available, blocked = _filter_listed(self.user_id, "pokemon", all_cosmetics, pokemon_name)

        if not available:
            # Every cosmetic for this pokemon is on the market
            msg = f"You have no equippable cosmetics for **{pokemon_name}**."
            if blocked:
                msg += _listed_warning(blocked)
            await interaction.response.send_message(msg, ephemeral=True)
            return

        suffix = _listed_warning(blocked) if blocked else ""
        view = PokemonCosmeticView(self.user_id, pokemon_name, available)
        await interaction.response.send_message(
            f"Choose cosmetic for **{pokemon_name}**:{suffix}",
            view=view,
            ephemeral=True
        )


class PokemonCosmeticView(discord.ui.View):
    def __init__(self, user_id, pokemon_name, cosmetics):
        super().__init__(timeout=60)
        self.user_id = user_id
        self.pokemon_name = pokemon_name

        options = [discord.SelectOption(label=c) for c in cosmetics]
        self.add_item(PokemonCosmeticSelect(user_id, pokemon_name, options))


class PokemonCosmeticSelect(discord.ui.Select):
    def __init__(self, user_id, pokemon_name, options):
        super().__init__(placeholder="Select cosmetic...", options=options)
        self.user_id = user_id
        self.pokemon_name = pokemon_name

    async def callback(self, interaction: discord.Interaction):
        cosmetic = self.values[0]

        # ── Guard: ownership/race-condition checks
        if not _user_can_equip_cosmetic(self.user_id, "pokemon", cosmetic, self.pokemon_name):
            await interaction.response.send_message(
                f"⚠️ You no longer own **{cosmetic}** for {self.pokemon_name}.",
                ephemeral=True
            )
            return

        if is_cosmetic_listed(self.user_id, "pokemon", cosmetic, self.pokemon_name):
            await interaction.response.send_message(
                f"🔒 **{cosmetic}** is listed on the market and cannot be equipped.\n"
                f"Use `market remove <id>` to delist it first.",
                ephemeral=True
            )
            return

        with sqlite3.connect("cosmetics.db") as db:
            db.execute(
                "INSERT OR REPLACE INTO equipped (user_id, category, pokemon_name, cosmetic) "
                "VALUES (?, 'pokemon', ?, ?)",
                (self.user_id, self.pokemon_name, cosmetic)
            )
            db.commit()

        await interaction.response.send_message(
            f"✅ Equipped **{cosmetic}** to {self.pokemon_name}!",
            ephemeral=True
        )


# ─────────────────────────────────────────────────────────────────────────────
#  SIMPLE CATEGORY FLOW
# ─────────────────────────────────────────────────────────────────────────────

# Maps normalized category name → (table, column, default cosmetics)
_CATEGORY_MAP = {
    "pokeball":    ("pokeball",    "available_pokeballs", {"pokeball"}),
    "status":      ("status",      "available_status",    {"ninja"}),
    "graphics":    ("graphics",    "available_graphics",  {"animated", "stationary"}),
    "embed color": ("embed_color", "available_colors",    {"default"}),
    "background":  ("background",  "available_backgrounds", {"arena", "volcano", "grassland"}),
}

# Maps the normalized UI category name → the key used in is_cosmetic_listed / market table
_CATEGORY_KEY = {
    "pokeball":    "pokeball",
    "status":      "status",
    "graphics":    "graphics",
    "embed color": "embed_color",
    "background":  "background",
}


async def handle_simple_category(interaction: discord.Interaction, user_id: int, category: str):
    category = category.replace("_", " ")
    if category == "animation":
        category = "graphics"

    if category not in _CATEGORY_MAP:
        return await interaction.response.send_message("Invalid category.", ephemeral=True)

    table, column, defaults = _CATEGORY_MAP[category]
    market_category = _CATEGORY_KEY[category]

    with sqlite3.connect("cosmetics.db") as db:
        cursor = db.cursor()
        cursor.execute(f"SELECT {column} FROM {table} WHERE user_id=?", (user_id,))
        row = cursor.fetchone()

    owned = set(row[0].split(",")) if (row and row[0]) else set()
    owned |= set(_global_clan_available_cosmetics(user_id, market_category))
    all_cosmetics = list(owned | defaults)       # merge owned + defaults

    available, blocked = _filter_listed(user_id, market_category, all_cosmetics)

    if not available:
        msg = f"You have no equippable cosmetics for **{category}**."
        if blocked:
            msg += _listed_warning(blocked)
        return await interaction.response.send_message(msg, ephemeral=True)

    suffix = _listed_warning(blocked) if blocked else ""
    view = SimpleEquipView(user_id, category, market_category, available)
    await interaction.response.send_message(
        f"Choose **{category}** cosmetic:{suffix}",
        view=view,
        ephemeral=True
    )


class SimpleEquipView(discord.ui.View):
    def __init__(self, user_id, category, market_category, cosmetics):
        super().__init__(timeout=60)
        options = [discord.SelectOption(label=c) for c in cosmetics]
        self.add_item(SimpleEquipSelect(user_id, category, market_category, options))


class SimpleEquipSelect(discord.ui.Select):
    def __init__(self, user_id, category, market_category, options):
        super().__init__(placeholder="Select cosmetic...", options=options)
        self.user_id = user_id
        self.category = category
        self.market_category = market_category  # key used in market table

    async def callback(self, interaction: discord.Interaction):
        cosmetic = self.values[0]

        # ── Guard: ownership/race-condition check
        if not _user_can_equip_cosmetic(self.user_id, self.market_category, cosmetic):
            await interaction.response.send_message(
                f"⚠️ You no longer own **{cosmetic}** for {self.category}.",
                ephemeral=True
            )
            return

        if is_cosmetic_listed(self.user_id, self.market_category, cosmetic):
            await interaction.response.send_message(
                f"🔒 **{cosmetic}** is listed on the market and cannot be equipped.\n"
                f"Use `market remove <id>` to delist it first.",
                ephemeral=True
            )
            return

        db_category = self.market_category   # store with underscore form in equipped table

        with sqlite3.connect("cosmetics.db") as db:
            db.execute(
                "INSERT OR REPLACE INTO equipped (user_id, category, pokemon_name, cosmetic) "
                "VALUES (?, ?, NULL, ?)",
                (self.user_id, db_category, cosmetic)
            )
            db.commit()

        await interaction.response.send_message(
            f"✅ Equipped **{cosmetic}** as your {self.category}!",
            ephemeral=True
        )
async def setup_cosmetics_db():
    with sqlite3.connect("cosmetics.db") as db:

        # Pokemon cosmetics table
        db.execute("""
        CREATE TABLE IF NOT EXISTS pokemon (
            user_id INTEGER,
            pokemon_name TEXT,
            available_cosmetics TEXT,
            UNIQUE(user_id, pokemon_name)
        )
        """)

        # Pokeball cosmetics
        db.execute("""
        CREATE TABLE IF NOT EXISTS pokeball (
            user_id INTEGER PRIMARY KEY,
            available_pokeballs TEXT
        )
        """)

        # Status cosmetics
        db.execute("""
        CREATE TABLE IF NOT EXISTS status (
            user_id INTEGER PRIMARY KEY,
            available_status TEXT
        )
        """)

        # Graphics settings
        db.execute("""
        CREATE TABLE IF NOT EXISTS graphics (
            user_id INTEGER PRIMARY KEY,
            available_graphics TEXT
        )
        """)

        # Embed color cosmetics
        db.execute("""
        CREATE TABLE IF NOT EXISTS embed_color (
            user_id INTEGER PRIMARY KEY,
            available_colors TEXT
        )
        """)

        # Background cosmetics
        db.execute("""
        CREATE TABLE IF NOT EXISTS background (
            user_id INTEGER PRIMARY KEY,
            available_backgrounds TEXT
        )
        """)

        # Equipped cosmetics
        db.execute("""
        CREATE TABLE IF NOT EXISTS equipped (
            user_id INTEGER,
            category TEXT,
            pokemon_name TEXT,
            cosmetic TEXT,
            UNIQUE(user_id, category, pokemon_name)
        )
        """)
        db.execute("""
        CREATE TABLE IF NOT EXISTS showcase (
            user_id INTEGER,
            slot INTEGER,
            pokemon_name TEXT,
            cosmetic TEXT,
            UNIQUE(user_id, slot)
        )
        """)
        db.execute("""
        CREATE TABLE IF NOT EXISTS vote_progress (
            user_id INTEGER PRIMARY KEY,
            total_votes INTEGER DEFAULT 0,
            last_topgg_claim INTEGER DEFAULT 0,
            last_dbl_claim INTEGER DEFAULT 0
        )
        """)

        # Shiny-star currency
        db.execute("""
        CREATE TABLE IF NOT EXISTS "shiny star" (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0
        )
        """)
        db.execute("""
        CREATE TABLE IF NOT EXISTS "exchange coupon" (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0
        )
        """)
        db.execute("""
        CREATE TABLE IF NOT EXISTS "shiny exchange coupon" (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0
        )
        """)
        db.execute("""
        CREATE TABLE IF NOT EXISTS prefix_launch_notice (
            user_id INTEGER PRIMARY KEY,
            seen_at TEXT DEFAULT CURRENT_TIMESTAMP
        )
        """)

        # Battle reward point tables
        cursor = db.cursor()
        cursor.execute(
        "SELECT name FROM sqlite_master WHERE type='table' AND name='titan point'"
        )
        has_titan = cursor.fetchone() is not None
        cursor.execute(
        "SELECT name FROM sqlite_master WHERE type='table' AND name='achilles point'"
        )
        has_achilles = cursor.fetchone() is not None
        if has_titan and not has_achilles:
            cursor.execute('ALTER TABLE "titan point" RENAME TO "achilles point"')
        db.execute("""
        CREATE TABLE IF NOT EXISTS "achilles point" (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0
        )
        """)
        db.execute("""
        CREATE TABLE IF NOT EXISTS "hero point" (
            user_id INTEGER PRIMARY KEY,
            amount INTEGER DEFAULT 0
        )
        """)
        db.execute("""
        CREATE TABLE IF NOT EXISTS battle_reward_winners (
            reward_type TEXT,
            user_id INTEGER,
            UNIQUE(reward_type, user_id)
        )
        """)
        db.execute("""
        CREATE TABLE IF NOT EXISTS battle_reward_meta (
            key TEXT PRIMARY KEY,
            value TEXT NOT NULL
        )
        """)
        db.execute(
            "INSERT OR IGNORE INTO battle_reward_meta (key, value) VALUES ('titan_enabled', '1')"
        )
        db.execute(
            "INSERT OR IGNORE INTO battle_reward_meta (key, value) VALUES ('achilles_enabled', '1')"
        )
        db.execute(
            "INSERT OR IGNORE INTO battle_reward_meta (key, value) VALUES ('achilles_started', '0')"
        )
        db.execute(
            "INSERT OR IGNORE INTO battle_reward_meta (key, value) VALUES ('hero_enabled', '1')"
        )


        db.commit()

    print("Cosmetics database setup complete.")


