def _parse_csv_list(value: str):
    return [x.strip().lower() for x in (value or "").split(",") if x.strip()]


def _cosmetic_emoji_text(cosmetics_csv: str):
    cosmetics = _parse_csv_list(cosmetics_csv)
    if not cosmetics:
        return ""
    return " ".join(_get_cosmetic_emoji(c, fallback=f"`{c}`") for c in cosmetics)


def _get_cosmetic_emoji(cosmetic_name: str, fallback: str = "") -> str:
    name = str(cosmetic_name or "").strip().lower()
    if not name:
        return fallback
    if "clan" in name:
        return "<a:clan:1497715786599497758>"
    return COSMETIC_EMOJIS.get(name, fallback)


HUE_RARITY = {"red", "blue", "green", "golden", "purple", "cyan"}
PREMIUM_RARITY = {"dark", "light", "dynamax", "plate", "aura", "crimson"}
SHINY_RARITY = {"shiny"}
LIMITED_RARITY = set()
SPECIAL_RARITY = set()
