def _cosmetic_rarity_label(cosmetic_name: str) -> str:
    cosmetic = str(cosmetic_name or "").strip().lower()
    if cosmetic in HUE_RARITY:
        return "Hue"
    if cosmetic in PREMIUM_RARITY:
        return "Premium"
    if cosmetic in SHINY_RARITY:
        return "Shiny"
    if cosmetic in LIMITED_RARITY:
        return "Limited"
    if cosmetic in SPECIAL_RARITY:
        return "Special"
    return "Events"


def _pokemon_cosmetic_owners(pokemon_name: str, cosmetic_name: str):
    pokemon = str(pokemon_name or "").strip().lower()
    cosmetic = str(cosmetic_name or "").strip().lower()
    owners = []
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            "SELECT rowid, user_id, available_cosmetics FROM pokemon WHERE LOWER(pokemon_name) = ?",
            (pokemon,)
        )
        for rowid, user_id, cosmetics_csv in c.fetchall():
            cosmetics = _parse_csv_list(cosmetics_csv)
            if cosmetic in cosmetics:
                owners.append((rowid, int(user_id)))
    owners.sort(key=lambda x: x[0])
    return [uid for _, uid in owners]


def _showcase_get_entries(user_id: int):
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            """
            SELECT slot, pokemon_name, cosmetic
            FROM showcase
            WHERE user_id = ?
            ORDER BY slot ASC
            """,
            (user_id,),
        )
        return c.fetchall()


def _showcase_owned_cosmetics(user_id: int, pokemon_name: str):
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            "SELECT available_cosmetics FROM pokemon WHERE user_id = ? AND pokemon_name = ?",
            (user_id, pokemon_name),
        )
        row = c.fetchone()
    if not row or not row[0]:
        return set()
    return set(_parse_csv_list(row[0]))


def _showcase_add_entry(user_id: int, pokemon_name: str, cosmetic: str):
    pokemon_name = str(pokemon_name or "").strip().lower()
    cosmetic = str(cosmetic or "").strip().lower()
    if not pokemon_name or not cosmetic:
        return False, "Pokemon name and cosmetic are required."

    owned = _showcase_owned_cosmetics(user_id, pokemon_name)
    if cosmetic not in owned:
        return False, "You do not own that cosmetic for this pokemon."

    existing = _showcase_get_entries(user_id)
    if len(existing) >= 6:
        return False, "Showcase is full (max 6 pokemon)."
    if any((p == pokemon_name and c == cosmetic) for _, p, c in existing):
        return False, "That pokemon + cosmetic is already in your showcase."

    used_slots = {int(slot) for slot, _, _ in existing}
    slot = next((idx for idx in range(1, 7) if idx not in used_slots), None)
    if slot is None:
        return False, "No empty showcase slot is available."

    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            "INSERT OR REPLACE INTO showcase (user_id, slot, pokemon_name, cosmetic) VALUES (?, ?, ?, ?)",
            (user_id, slot, pokemon_name, cosmetic),
        )
        conn.commit()
    return True, f"Added **{pokemon_name.title()}** with **{cosmetic}** to slot {slot}."


def _showcase_remove_slot(user_id: int, slot: int):
    if slot < 1 or slot > 6:
        return False, "Slot must be between 1 and 6."
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            "SELECT pokemon_name, cosmetic FROM showcase WHERE user_id = ? AND slot = ?",
            (user_id, slot),
        )
        row = c.fetchone()
        if not row:
            return False, "That slot is already empty."
        c.execute("DELETE FROM showcase WHERE user_id = ? AND slot = ?", (user_id, slot))
        conn.commit()
    return True, f"Removed slot {slot}: **{row[0].title()}** --- **{row[1]}**."


def _build_showcase_embed(target: discord.User):
    rows = _showcase_get_entries(target.id)
    if rows:
        lines = []
        for slot, pokemon_name, cosmetic in rows:
            emoji = COSMETIC_EMOJIS.get((cosmetic or "").lower(), f"`{cosmetic}`")
            lines.append(f"**{slot}.** {str(pokemon_name).title()} --- {cosmetic} {emoji}")
        description = "\n".join(lines)
    else:
        description = "No pokemon in showcase."
    return discord.Embed(
        title=f"{target.display_name}'s Showcase",
        description=description,
        color=discord.Color.blurple(),
    )

