@bot.command(name='upload_event')
async def upload_event(ctx, cosmetics_name, pokemon):
    global SPECIAL_POKEMON_LIST, SPECIAL_COSMETICS_LIST
    # Update in-memory set
    if ctx.author.id not in owner_ids:
        return
    SPECIAL_COSMETICS_LIST.add(cosmetics_name)
    SPECIAL_POKEMON_LIST.add(pokemon)

    # Persist to file
    with open("event_pokemon.txt", "a") as f:
        f.write(f"{pokemon}\n")
    with open("event_cosmetics.txt", "a") as f:
        f.write(f"{cosmetics_name}\n")

    await ctx.send(f"✅ Event cosmetics {cosmetics_name} {pokemon} added")


def resolve_special_sprite(poke, cosmetic_name):
    url = _SPECIAL_COSMETIC_SPRITE_URLS.get(cosmetic_name)
    if url:
        return _get_cached_special_sprite(url), None
    if poke.lower() in SPECIAL_POKEMON_LIST and cosmetic_name in SPECIAL_COSMETICS_LIST:
        poke_name = poke.replace(" ", "_")
        cos = cosmetic_name.replace(" ", "_")
        return _get_cached_special_sprite(f"https://raw.githubusercontent.com/Best1111-dev/Sprites/main/{cos}_{poke_name}.png"), None
    mask = None
    if cosmetic_name in _BATTLE_MASK_COLORS or cosmetic_name in ["dark", "light", "dynamax", "plate", "aura", "crimson"]:
        mask = cosmetic_name
    if cosmetic_name == "shiny":
        return get_pokemon_sprite(poke, shiny=True), None
    return get_pokemon_sprite(poke, shiny=False), mask


def get_transform_avatar_url(pokemon_name: str, cosmetic_name: str | None = None):
    cosmetic = str(cosmetic_name or "").strip().lower()
    special_url = _SPECIAL_COSMETIC_SPRITE_URLS.get(cosmetic)
    if special_url:
        return special_url
    if cosmetic == "shiny":
        return get_pokemon_info(pokemon_name, True)[2]
    return get_pokemon_info(pokemon_name, True)[2]

def _resolve_showcase_sprite(pokemon_name: str, cosmetic_name: str):
    cosmetic = (cosmetic_name or "").strip().lower()
    poke = (pokemon_name or "").strip().lower()
    mask = None
    return resolve_special_sprite(pokemon_name, cosmetic_name)
    
    


def _preview_split_args(raw_text: str):
    text = str(raw_text or "").strip()
    if not text:
        return None, None
    tokens = text.split()
    if len(tokens) < 2:
        return None, None

    best = None
    for i in range(1, len(tokens)):
        cosmetic = " ".join(tokens[:i]).strip().lower()
        pokemon = " ".join(tokens[i:]).strip().lower()
        if not cosmetic or not pokemon:
            continue
        pokemon_path = os.path.join(pokemon_data_folder, f"{pokemon}.json")
        if os.path.exists(pokemon_path):
            pokemon_word_count = len(tokens) - i
            if best is None or pokemon_word_count > best[0]:
                best = (pokemon_word_count, cosmetic, pokemon)

    if best:
        return best[1], best[2]

    # Fallback: assume final token is pokemon.
    return " ".join(tokens[:-1]).strip().lower(), tokens[-1].strip().lower()


def _preview_owned_cosmetics(user_id: int, pokemon_name: str):
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            "SELECT available_cosmetics FROM pokemon WHERE user_id = ? AND pokemon_name = ?",
            (user_id, str(pokemon_name or "").strip().lower()),
        )
        row = c.fetchone()
    return _parse_csv_list(row[0] if row and row[0] else "")


def _apply_preview_mask(sprite: Image.Image, mask: str):
    if sprite is None:
        return None
    if not mask:
        return sprite

    mask_name = str(mask).strip().lower()
    sprite = sprite.convert("RGBA")

    if mask_name in ("dark", "light"):
        pixels = sprite.load()
        w, h = sprite.size
        target_color = (0, 0, 0) if mask_name == "dark" else (255, 255, 255)
        tr, tg, tb = target_color
        threshold = 30
        for y in range(h):
            for x in range(w):
                r, g, b, a = pixels[x, y]
                if a == 0:
                    continue
                if (r > g + threshold and r > b + threshold) or (g > r + threshold and g > b + threshold) or (b > r + threshold and b > g + threshold):
                    pixels[x, y] = (tr, tg, tb, a)
        return sprite
    if mask_name in ("plate", "aura", "crimson"):
        sprite = sprite.convert("RGBA")
        pixels = sprite.load()
        w, h = sprite.size
        threshold = 60
        tolerance = 50

        if mask_name == "plate":
            target_color = (255, 255, 0)
        if mask_name == "crimson":
            target_color = (139, 0, 0)
        if mask_name == "aura":
            target_color = (173, 216, 230)
        tr, tg, tb = target_color

        white_count = 0
        black_count = 0

        # Pass 1: count
        for y in range(h):
            for x in range(w):
                r, g, b, a = pixels[x, y]
                if a == 0:
                    continue

                avg = (r + g + b) // 3
                spread = max(r, g, b) - min(r, g, b)

                if avg > 180 and spread < tolerance:
                    white_count += 1
                elif avg < 85 and spread < tolerance:
                    black_count += 1

        recolor_white = white_count >= black_count

        # Pass 2: recolor dominant group
        for y in range(h):
            for x in range(w):
                r, g, b, a = pixels[x, y]
                if a == 0:
                    continue

                avg = (r + g + b) // 3
                spread = max(r, g, b) - min(r, g, b)

                if recolor_white:
                    if avg > 180 and spread < tolerance:
                        pixels[x, y] = (tr, tg, tb, a)
                else:
                    if avg < 85 and spread < tolerance:
                        pixels[x, y] = (tr, tg, tb, a)

        return sprite

    if mask_name == "dynamax":
        alpha = sprite.split()[3]
        outline = Image.new("RGBA", sprite.size, (0, 0, 0, 0))
        for x in range(-4, 5):
            for y in range(-4, 5):
                outline.paste((255, 0, 0, 255), (x, y), alpha)
        outline.paste(sprite, (0, 0), sprite)
        return outline

    if mask_name in _BATTLE_MASK_COLORS:
        color_layer = Image.new("RGBA", sprite.size, _BATTLE_MASK_COLORS[mask_name] + (0,))
        alpha = sprite.split()[3]
        color_layer.putalpha(alpha.point(lambda p: int(p * 0.45)))
        return Image.alpha_composite(sprite, color_layer)

    return sprite


def _render_cosmetic_preview_image(user_id: int, pokemon_name: str, cosmetic_name: str):
    poke = str(pokemon_name or "").strip().lower()
    cosmetic = str(cosmetic_name or "").strip().lower()
    sprite, mask = _resolve_showcase_sprite(poke, cosmetic)
    if sprite is None:
        return None

    equipped = get_equipped_battle_cosmetics(user_id)
    bg = resolve_special_background(cosmetic_name, "nothing")
    if bg:
        canvas = bg.convert("RGBA")
    else:
        bg_name = equipped.get("background") or get_battle_background(user_id)
        canvas = _get_cached_battle_background(bg_name).convert("RGBA")

    mask_name = mask
    scale = 1.45 if mask_name == "dynamax" else 1.20
    base = int(min(canvas.size) * 0.60)
    side = max(64, int(base * scale))
    w, h = sprite.size
    mean = (w+h)/2
    sprite = sprite.resize((int(w*side/mean), int(h*side/mean)), Image.LANCZOS)
    sprite = _apply_preview_mask(sprite, mask_name)

    x = canvas.width // 2 - sprite.width // 2
    y = canvas.height // 2 - sprite.height // 2
    canvas.paste(sprite, (x, y), sprite)

    return canvas

def _showcase_layout_positions(count: int, width: int, height: int):
    cx = width // 2
    cy = height // 2
    if count <= 1:
        return [(cx, cy)], 210
    if count == 2:
        return [(int(width * 0.33), cy), (int(width * 0.67), cy)], 185
    if count == 3:
        return [(cx, int(height * 0.30)), (int(width * 0.34), int(height * 0.70)), (int(width * 0.66), int(height * 0.70))], 165
    if count == 4:
        return [
            (int(width * 0.30), int(height * 0.34)),
            (int(width * 0.70), int(height * 0.34)),
            (int(width * 0.30), int(height * 0.70)),
            (int(width * 0.70), int(height * 0.70)),
        ], 150
    if count == 5:
        return [
            (int(width * 0.20), int(height * 0.32)),
            (int(width * 0.50), int(height * 0.28)),
            (int(width * 0.80), int(height * 0.32)),
            (int(width * 0.35), int(height * 0.72)),
            (int(width * 0.65), int(height * 0.72)),
        ], 136
    return [
        (int(width * 0.20), int(height * 0.30)),
        (int(width * 0.50), int(height * 0.30)),
        (int(width * 0.80), int(height * 0.30)),
        (int(width * 0.20), int(height * 0.72)),
        (int(width * 0.50), int(height * 0.72)),
        (int(width * 0.80), int(height * 0.72)),
    ], 122


def _render_showcase_image(user_id: int):
    entries = _showcase_get_entries(user_id)
    if not entries:
        return None

    equipped = get_equipped_battle_cosmetics(user_id)
    bg_name = equipped.get("background") or get_battle_background(user_id)
    canvas = _get_cached_battle_background(bg_name).convert("RGBA")
    width, height = canvas.size

    positions, size = _showcase_layout_positions(len(entries), width, height)

    def recolor_sprite(sprite: Image.Image, target_color: tuple, threshold=30):
        sprite = sprite.convert("RGBA")
        pixels = sprite.load()
        w, h = sprite.size

        tr, tg, tb = target_color

        for y in range(h):
            for x in range(w):
                r, g, b, a = pixels[x, y]

                if a == 0:
                    continue

                if (r > g + threshold and r > b + threshold) or \
                (g > r + threshold and g > b + threshold) or \
                (b > r + threshold and b > g + threshold):

                    pixels[x, y] = (tr, tg, tb, a)

        return sprite

    def add_red_outline(sprite, thickness=4):
        alpha = sprite.split()[3]
        outline = Image.new("RGBA", sprite.size, (0, 0, 0, 0))
        for x in range(-thickness, thickness + 1):
            for y in range(-thickness, thickness + 1):
                outline.paste((255, 0, 0, 255), (x, y), alpha)
        outline.paste(sprite, (0, 0), sprite)
        return outline

    for i, (_, pokemon_name, cosmetic) in enumerate(entries):
        sprite, mask = _resolve_showcase_sprite(pokemon_name, cosmetic)
        if sprite is None:
            continue
        if mask:
            mask = mask.lower()
        scale = 1.5 if mask == "dynamax" else 1.0
        w, h = sprite.size
        mean = (w+h)/2
        sprite = sprite.convert("RGBA").resize((int(w * scale*125/mean), int(h * scale*125/mean)), Image.LANCZOS)

        if mask == "dark":
            sprite = recolor_sprite(sprite, (0, 0, 0))

        elif mask == "light":
            sprite = recolor_sprite(sprite, (255, 255, 255))
        
        elif mask == "crimson":
            sprite = recolor_sprite2(sprite, (139, 0, 0))

        elif mask == "plate":
            sprite = recolor_sprite2(sprite, (255, 255, 0))

        elif mask == "aura":
            sprite = recolor_sprite2(sprite, (173, 216, 230))

        elif mask == "dynamax":
            sprite = add_red_outline(sprite)

        elif mask and mask in _BATTLE_MASK_COLORS:
            color_layer = Image.new("RGBA", sprite.size, _BATTLE_MASK_COLORS[mask] + (0,))
            alpha = sprite.split()[3]
            color_layer.putalpha(alpha.point(lambda p: int(p * 0.45)))
            sprite = Image.alpha_composite(sprite, color_layer)

        px, py = positions[i]
        x = px - sprite.width // 2
        y = py - sprite.height // 2

        canvas.paste(sprite, (x, y), sprite)

    return canvas


class ShowcaseAddModal(discord.ui.Modal, title="Add To Showcase"):
    pokemon_name = discord.ui.TextInput(label="Pokemon name", placeholder="e.g. charizard", required=True, max_length=64)
    cosmetic_name = discord.ui.TextInput(label="Cosmetic name", placeholder="e.g. shiny / red / true titan", required=True, max_length=64)

    def __init__(self, view_ref):
        super().__init__()
        self.view_ref = view_ref

    async def on_submit(self, interaction: discord.Interaction):
        if interaction.user.id != self.view_ref.invoker_id:
            return await interaction.response.send_message("This showcase panel is not for you.", ephemeral=True)
        if interaction.user.id != self.view_ref.target.id:
            return await interaction.response.send_message("You can only edit your own showcase.", ephemeral=True)
        ok, msg = _showcase_add_entry(interaction.user.id, self.pokemon_name.value, self.cosmetic_name.value)
        await interaction.response.edit_message(embed=self.view_ref.build_embed(), view=self.view_ref)
        await interaction.followup.send(("✅ " if ok else "❌ ") + msg, ephemeral=True)


class ShowcaseRemoveModal(discord.ui.Modal, title="Remove From Showcase"):
    slot = discord.ui.TextInput(label="Slot number (1-6)", placeholder="e.g. 3", required=True, max_length=1)

    def __init__(self, view_ref):
        super().__init__()
        self.view_ref = view_ref

    async def on_submit(self, interaction: discord.Interaction):
        if interaction.user.id != self.view_ref.invoker_id:
            return await interaction.response.send_message("This showcase panel is not for you.", ephemeral=True)
        if interaction.user.id != self.view_ref.target.id:
            return await interaction.response.send_message("You can only edit your own showcase.", ephemeral=True)
        try:
            slot = int(self.slot.value.strip())
        except Exception:
            return await interaction.response.send_message("❌ Invalid slot number.", ephemeral=True)
        ok, msg = _showcase_remove_slot(interaction.user.id, slot)
        await interaction.response.edit_message(embed=self.view_ref.build_embed(), view=self.view_ref)
        await interaction.followup.send(("✅ " if ok else "❌ ") + msg, ephemeral=True)


class ShowcaseView(discord.ui.View):
    def __init__(self, invoker_id: int, target: discord.User):
        super().__init__(timeout=300)
        self.invoker_id = invoker_id
        self.target = target

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.invoker_id:
            await interaction.response.send_message("This showcase panel is not for you.", ephemeral=True)
            return False
        return True

    def build_embed(self):
        return _build_showcase_embed(self.target)

    @discord.ui.button(label="Add", style=discord.ButtonStyle.success)
    async def add_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.target.id:
            return await interaction.response.send_message("You can only edit your own showcase.", ephemeral=True)
        await interaction.response.send_modal(ShowcaseAddModal(self))

    @discord.ui.button(label="Remove", style=discord.ButtonStyle.danger)
    async def remove_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.target.id:
            return await interaction.response.send_message("You can only edit your own showcase.", ephemeral=True)
        await interaction.response.send_modal(ShowcaseRemoveModal(self))

    @discord.ui.button(label="Preview", style=discord.ButtonStyle.primary)
    async def preview_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        image = _render_showcase_image(self.target.id)
        if image is None:
            return await interaction.response.send_message("No pokemon in showcase to preview.", ephemeral=True)
        output = BytesIO()
        image.save(output, format="PNG")
        output.seek(0)
        equipped = get_equipped_battle_cosmetics(self.target.id)
        embed = discord.Embed(
            title=f"{self.target.display_name}'s Showcase Preview",
            color=parse_embed_color(equipped.get("color")),
        )
        embed.set_image(url="attachment://showcase.png")
        file = discord.File(output, filename="showcase.png")
        await interaction.response.send_message(embed=embed, file=file)

class CollectionFilterDropdown(discord.ui.Select):
    def __init__(self, paginator: "CollectionPaginator", cosmetics: list[str]):
        self.paginator = paginator

        options = [discord.SelectOption(label="All Cosmetics", value="all")]

        for c in cosmetics[:24]:
            label = c.title()
            if c == "special":
                emoji = "✨"
            else:
                emoji = COSMETIC_EMOJIS.get(c)

            options.append(
                discord.SelectOption(
                    label=label[:100],
                    value=c,
                    emoji=emoji if emoji else None,
                )
            )

        super().__init__(
            placeholder="Filter by cosmetic",
            min_values=1,
            max_values=1,
            options=options,
        )

    async def callback(self, interaction: discord.Interaction):
        value = self.values[0]

        self.paginator.apply_filter(None if value == "all" else value)
        self.paginator.refresh_layout()

        await interaction.response.edit_message(
            view=self.paginator,
        )


