class CollectionPaginator(LayoutView):
    def __init__(
        self,
        invoker_id: int,
        target: discord.User,
        entries: list[dict],
        cosmetics: list[str],
        points : int,
        per_page: int = 12,
    ):
        super().__init__(timeout=180)

        self.invoker_id = invoker_id
        self.target = target
        self.entries = entries
        self.cosmetics = cosmetics
        self.points = points
        print(points)

        self.all_lines = [e["line"] for e in entries]
        self.lines = self.all_lines[:]

        self.per_page = per_page
        self.page = 0
        self.max_page = max(0, (len(self.lines) - 1) // per_page)
        self.refresh_layout()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.invoker_id:
            await interaction.response.send_message(
                "This pagination is not for you.", ephemeral=True
            )
            return False
        return True

    def build_title_text(self):
        return f"# {self.target.display_name}'s Pokemon Collection\n## Points: {self.points}"

    def build_body_text(self):
        start = self.page * self.per_page
        end = start + self.per_page

        chunk = self.lines[start:end]
        desc = "\n".join(chunk) if chunk else "No cosmetics found."

        footer = f"Page {self.page + 1}/{self.max_page + 1} • Total: {len(self.lines)}"
        return f"{desc}\n\n{footer}"

    def apply_filter(self, cosmetic: str | None):
        allowed = {
            "cosmic",
            "shiny",
            "dark",
            "light",
            "crimson",
            "aura",
            "plate",
            "red",
            "blue",
            "green",
            "dynamax",
            "cyan",
            "golden",
            "purple",
        }

        if cosmetic is None:
            self.lines = self.all_lines[:]
        elif cosmetic == "special":
            filtered = []
            for e in self.entries:
                cosmetics = [str(c).strip().lower() for c in e.get("cosmetics", [])]
                if any(c and c not in allowed for c in cosmetics):
                    filtered.append(e["line"])
            self.lines = filtered
        elif cosmetic in allowed:
            filtered = []
            for e in self.entries:
                cosmetics = [str(c).strip().lower() for c in e.get("cosmetics", [])]
                if cosmetic in cosmetics:
                    filtered.append(e["line"])
            self.lines = filtered
        else:
            self.lines = self.all_lines[:]

        self.page = 0
        self.max_page = max(0, (len(self.lines) - 1) // self.per_page)

    def refresh_layout(self):
        self.clear_items()
        container = Container()

        container.add_item(TextDisplay(self.build_title_text()))

        if self.cosmetics:
            filter_row = ActionRow()
            filter_row.add_item(CollectionFilterDropdown(self, self.cosmetics))
            container.add_item(filter_row)

        container.add_item(TextDisplay(self.build_body_text()))

        nav_row = ActionRow()
        nav_row.add_item(CollectionPrevButton(self))
        nav_row.add_item(CollectionShowcaseButton(self))
        nav_row.add_item(CollectionNextButton(self))
        container.add_item(nav_row)

        self.add_item(container)

collection_points_cache = {}
clan_collection_points_cache = {}

def _build_collection_entries(target_id: int):
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            """
            SELECT pokemon_name, available_cosmetics
            FROM pokemon
            WHERE user_id = ?
            ORDER BY pokemon_name COLLATE NOCASE
            """,
            (target_id,),
        )
        rows = c.fetchall()

    entries = []
    cosmetics_set = set()
    allowed_filters = {
        "cosmic",
        "shiny",
        "dark",
        "light",
        "crimson",
        "aura",
        "plate",
        "red",
        "blue",
        "green",
        "dynamax",
        "cyan",
        "golden",
        "purple",
    }
    points = 0
    H = 0
    Li = 0
    K = 0
    NA = 0
    RB = 0
    FR = 0
    for pokemon_name, cosmetics_csv in rows:
        cosmetics = _parse_csv_list(cosmetics_csv)

        if not cosmetics:
            continue

        for cosmetic in cosmetics:
            try:
                p1_tier = _cosmetic_emoji_text(cosmetic)
                if p1_tier in ["🔴","🔵","🟢","🟣","🩵","🟡"]:
                    points += 1
                    H+=1
                elif p1_tier in ["🌑","☀️","<:gmax:1355891450058899547>","🛡️","🩸","🌠"]:
                    points += 2
                    Li+=1
                elif p1_tier in ["<a:leaf:1393596504199004321>","✨"]:
                    points += 18
                    NA += 1
                elif p1_tier in ["<a:clan:1497715786599497758>","<:titan:1506914927498235924>","🌃", "<a:Tower:1509953499591348244>"]:
                    points += 42
                    K += 1
                elif p1_tier in ["<a:BlueFire:1380598160170422302>","<a:custom:1492970288512630974>","<a:Shiny:1492825491894177882>","<:beserk_mega_metagross:1490124321081917500>","<:achilles_gmax_rapid_strike_urshi:1487488654195822754>","<a:vote:1499164555987910798>","<:heroofathousandbattles:1471542644818837741>","<:truetitan:1471542625575243797>"]:
                    points += 104
                    RB += 1
                elif p1_tier in ["<:bluephoenixhooh:1508874679199465503>","<a:custom:1492970288512630974>","<:merciless_marshadow:1479841986570621018>","<a:tournament:1520072005100241078>"]:
                    points += 184
                    FR += 1
                else:
                    points += 0
            except Exception as e:
                traceback.print_exc()

        emoji_text = _cosmetic_emoji_text(cosmetics_csv)

        if not emoji_text:
            continue

        line = f"**{str(pokemon_name).title()}** {emoji_text}"

        entries.append(
            {
                "name": str(pokemon_name).lower(),
                "cosmetics": cosmetics,
                "line": line,
            }
        )

        cosmetics_set.update(str(c).strip().lower() for c in cosmetics if str(c).strip())
        
    #print(f"{H},{Li},{NA},{K},{RB},{FR}")
    cosmetics_list = sorted(cosmetics_set & allowed_filters, key=str.lower)
    cosmetics_list = ["special"] + [c for c in cosmetics_list if c != "special"]

    return entries, cosmetics_list, points


@bot.tree.command(name="collection", description="Show Pokemon cosmetic collection")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
@app_commands.describe(member="Whose collection to view")
async def collection(interaction: discord.Interaction, member: discord.User = None):
    global collection_points_cache
    target = member or interaction.user
    entries, cosmetics_list, points = _build_collection_entries(target.id)

    view = CollectionPaginator(
        interaction.user.id,
        target,
        entries,
        cosmetics_list,
        points
    )

    collection_points_cache[target.id] = points

    await interaction.response.send_message(view=view)


