@bot.command(name="search")
async def search_pokemon_cosmetics(ctx: commands.Context, *, pokemon_name: str = None):
    if not pokemon_name or not str(pokemon_name).strip():
        return await ctx.send("Usage: `!search <pokemon name>`")

    name = str(pokemon_name).strip().lower()
    cosmetics_set = set()

    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            "SELECT available_cosmetics FROM pokemon WHERE user_id = ? AND lower(pokemon_name) = ?",
            (int(ctx.author.id), name),
        )
        rows = c.fetchall()

    for (cosmetics_csv,) in rows:
        cosmetics_set.update(_parse_csv_list(cosmetics_csv))

    if not cosmetics_set:
        return await ctx.send(f"❌ No cosmetics found for **{name.title()}** in your inventory.")

    cosmetics = sorted(cosmetics_set, key=str.lower)
    lines = [f"• `{c}` {COSMETIC_EMOJIS.get(c, '')}".rstrip() for c in cosmetics]
    embed = discord.Embed(
        title=f"🎨 {name.title()} Cosmetics",
        description="\n".join(lines[:50]),
        color=discord.Color.blurple(),
    )
    if len(lines) > 50:
        embed.set_footer(text=f"Showing 50 of {len(lines)} cosmetics.")
    await ctx.send(embed=embed)


@bot.command(name="preview")
async def preview_prefix(ctx: commands.Context, *, payload: str = None):
    if not payload or not payload.strip():
        return await ctx.send(
            "Usage:\n"
            "`!preview <cosmetic name> <pokemon>`\n"
            "`!preview cosmetics <pokemon>`"
        )

    cosmetic_name, pokemon_name = _preview_split_args(payload)
    if not cosmetic_name or not pokemon_name:
        return await ctx.send("❌ Could not parse input. Try `!preview red pikachu`.")

    pokemon_path = os.path.join(pokemon_data_folder, f"{pokemon_name}.json")
    if not os.path.exists(pokemon_path):
        return await ctx.send(f"❌ Pokémon not found: `{pokemon_name}`.")

    if cosmetic_name in {"cosmetics", "cosmetic"}:
        owned = _preview_owned_cosmetics(ctx.author.id, pokemon_name)
        if not owned:
            return await ctx.send(f"❌ You do not own any cosmetics for **{pokemon_name.title()}**.")

        lines = []
        footer_parts = []
        for cosmetic in owned:
            emoji = COSMETIC_EMOJIS.get(cosmetic, "")
            lines.append(f"• `{cosmetic}` {emoji}".rstrip())
            footer_parts.append(f"{pokemon_name.title()} [{cosmetic}] {emoji}".rstrip())

        embed = discord.Embed(
            title=f"🎰 Cosmetic Footer Preview — {pokemon_name.title()}",
            description="\n".join(lines[:30]),
            color=discord.Color.gold(),
        )
        footer_text = " | ".join(footer_parts)
        if len(footer_text) > 2048:
            footer_text = footer_text[:2045] + "..."
        embed.set_footer(text=footer_text)
        return await ctx.send(embed=embed)

    image = _render_cosmetic_preview_image(ctx.author.id, pokemon_name, cosmetic_name)
    if image is None:
        return await ctx.send("❌ Could not render preview for that pokemon/cosmetic.")

    emoji = COSMETIC_EMOJIS.get(cosmetic_name, "")
    gacha_footer = f"{pokemon_name.title()} [{cosmetic_name}] {emoji}".rstrip()
    embed = discord.Embed(
        title=f"Preview: {pokemon_name.title()} [{cosmetic_name}]",
        color=discord.Color.blurple(),
    )
    embed.set_footer(text=gacha_footer)

    buffer = BytesIO()
    image.save(buffer, format="PNG")
    buffer.seek(0)
    file = discord.File(fp=buffer, filename="preview.png")
    embed.set_image(url="attachment://preview.png")
    await ctx.send(embed=embed, file=file)


def _format_owner_display(guild: discord.Guild | None, user_id: int) -> str:
    member = guild.get_member(user_id) if guild else None
    return member.mention if member else f"<@{user_id}>"


def _build_cosmetic_stats_embed(user_id: int, guild: discord.Guild | None, pokemon_name: str, cosmetic_name: str):
    pokemon = str(pokemon_name or "").strip().lower()
    cosmetic = str(cosmetic_name or "").strip().lower()
    owners = _pokemon_cosmetic_owners(pokemon, cosmetic)

    rarity = _cosmetic_rarity_label(cosmetic)
    p1_tier = _get_cosmetic_emoji(cosmetic) if cosmetic else ""
    if p1_tier in ["🔴","🔵","🟢","🟣","🩵","🟡"]:
        p1_tier = "H"
        p1_txt_color = (68, 255, 87)
    elif p1_tier in ["🌑","☀️","<:gmax:1355891450058899547>","🛡️","🩸","🌠"]:
        p1_tier = "Li+"
        p1_txt_color = (68, 255, 250)
    elif p1_tier in ["<a:leaf:1393596504199004321>","✨"]:
        p1_tier = "Na+"
        p1_txt_color = (0, 128, 255)
    elif p1_tier in ["<a:clan:1497715786599497758>","<:titan:1506914927498235924>","🌃", "<a:Tower:1509953499591348244>"]:
        p1_tier = "K+"
        p1_txt_color = (85, 0, 255)
    elif p1_tier in ["<a:BlueFire:1380598160170422302>","<a:custom:1492970288512630974>","<a:Shiny:1492825491894177882>","<:beserk_mega_metagross:1490124321081917500>","<:achilles_gmax_rapid_strike_urshi:1487488654195822754>","<a:vote:1499164555987910798>","<:heroofathousandbattles:1471542644818837741>","<:truetitan:1471542625575243797>"]:
        p1_tier = "Rb+"
        p1_txt_color = (255, 222, 0)
    elif p1_tier in ["<:bluephoenixhooh:1508874679199465503>","<a:custom:1492970288512630974>","<:merciless_marshadow:1479841986570621018>","<a:tournament:1520072005100241078>"]:
        p1_tier = "Fr+"
        p1_txt_color = (255, 102, 0)
    else:
        p1_tier = ""
    has_it = user_id in owners
    first_five = owners[:5]
    if first_five:
        first_text = "\n".join(_format_owner_display(guild, uid) for uid in first_five)
    else:
        first_text = "None"

    embed = discord.Embed(
        title=f"Cosmetic Stats — {pokemon.title()} [{cosmetic}]",
        color=discord.Color.gold(),
    )
    embed.add_field(name="Rarity", value=f"Type: {rarity}\nRarity tier: {p1_tier}", inline=True)
    embed.add_field(name="Owners", value=str(len(owners)), inline=True)
    embed.add_field(name="You Own It", value="Yes" if has_it else "No", inline=True)
    embed.add_field(name="First 5 Owners", value=first_text, inline=False)
    return embed, owners


class CosmeticOwnersView(discord.ui.View):
    def __init__(self, requester_id: int, owners: list[int], guild: discord.Guild | None, pokemon_name: str, cosmetic_name: str):
        super().__init__(timeout=120)
        self.requester_id = int(requester_id)
        self.owners = owners
        self.guild = guild
        self.pokemon_name = pokemon_name
        self.cosmetic_name = cosmetic_name
        self.page = 0

    def build_embed(self):
        per_page = 10
        total_pages = max(1, math.ceil(len(self.owners) / per_page))
        self.page = max(0, min(self.page, total_pages - 1))
        start = self.page * per_page
        end = start + per_page
        chunk = self.owners[start:end]
        lines = [
            f"{start + idx + 1}. {_format_owner_display(self.guild, uid)}"
            for idx, uid in enumerate(chunk)
        ]
        desc = "\n".join(lines) if lines else "No owners found."
        embed = discord.Embed(
            title=f"Owners — {self.pokemon_name.title()} [{self.cosmetic_name}]",
            description=desc,
            color=discord.Color.blurple(),
        )
        embed.set_footer(text=f"Page {self.page + 1}/{total_pages}")
        return embed

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        return interaction.user.id == self.requester_id

    @discord.ui.button(label="⬅ Prev", style=discord.ButtonStyle.secondary)
    async def prev(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.page = max(0, self.page - 1)
        await interaction.response.edit_message(embed=self.build_embed(), view=self)

    @discord.ui.button(label="Next ➡", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, button: discord.ui.Button):
        max_page = max(0, math.ceil(len(self.owners) / 10) - 1)
        self.page = min(max_page, self.page + 1)
        await interaction.response.edit_message(embed=self.build_embed(), view=self)


class CosmeticStatsView(discord.ui.View):
    def __init__(self, requester_id: int, owners: list[int], guild: discord.Guild | None, pokemon_name: str, cosmetic_name: str):
        super().__init__(timeout=120)
        self.requester_id = int(requester_id)
        self.owners = owners
        self.guild = guild
        self.pokemon_name = pokemon_name
        self.cosmetic_name = cosmetic_name

        if len(owners) < 50:
            self.add_item(self.OwnersButton(self))

    class OwnersButton(discord.ui.Button):
        def __init__(self, p):
            super().__init__(label="Owners", style=discord.ButtonStyle.primary)
            self.p = p

        async def callback(self, interaction: discord.Interaction):
            if interaction.user.id != self.p.requester_id:
                return await interaction.response.send_message("Not your selection!", ephemeral=True)
            view = CosmeticOwnersView(
                self.p.requester_id,
                self.p.owners,
                self.p.guild,
                self.p.pokemon_name,
                self.p.cosmetic_name,
            )
            await interaction.response.edit_message(embed=view.build_embed(), view=view)


