    embed, owners = _build_cosmetic_stats_embed(ctx.author.id, ctx.guild, pokemon_name, cosmetic_name)
    view = CosmeticStatsView(ctx.author.id, owners, ctx.guild, pokemon_name, cosmetic_name) if owners is not None else None
    await ctx.send(embed=embed, view=view)


