def _ensure_ritual_db():
    with sqlite3.connect(RITUAL_DB_PATH) as conn:
        c = conn.cursor()
        c.execute(
            """
            CREATE TABLE IF NOT EXISTS ritual_pulls (
                user_id INTEGER,
                collection_key TEXT,
                pulled_at INTEGER,
                PRIMARY KEY (user_id, collection_key)
            )
            """
        )
        c.execute(
            """
            CREATE TABLE IF NOT EXISTS ritual_prizes (
                user_id INTEGER,
                prize_key TEXT,
                granted_at INTEGER,
                PRIMARY KEY (user_id, prize_key)
            )
            """
        )
        conn.commit()


_ensure_ritual_db()


def _ritual_collection_key(collection: str, cosmetic: str) -> str:
    return f"{collection.strip().lower()}|{cosmetic.strip().lower()}"


def _ritual_reward_key(reward: dict) -> str:
    reward_type = str(reward.get("type") or "").strip().lower()
    if reward_type == "pokemon_cosmetic":
        pokemon_name = str(reward.get("pokemon") or "").strip().lower()
        cosmetic = str(reward.get("cosmetic") or "").strip().lower()
        return f"pokemon|{pokemon_name}|{cosmetic}"
    if reward_type == "graphics":
        value = str(reward.get("value") or "").strip().lower()
        return f"graphics|{value}"
    return f"unknown|{str(reward).strip().lower()}"


def _ritual_load_user_cosmetics(user_id: int) -> dict[str, set[str]]:
    owned: dict[str, set[str]] = {}
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            "SELECT pokemon_name, available_cosmetics FROM pokemon WHERE user_id = ?",
            (user_id,),
        )
        rows = c.fetchall()
    for pokemon_name, cosmetics_csv in rows:
        pokemon_key = str(pokemon_name).strip().lower()
        cosmetics = set(_parse_csv_list(cosmetics_csv))
        owned[pokemon_key] = cosmetics
    return owned


def _ritual_collection_complete(owned: dict[str, set[str]], pokemon_list: list[str], cosmetic: str) -> bool:
    cosmetic = str(cosmetic).strip().lower()
    for pokemon in pokemon_list:
        pokemon_key = str(pokemon).strip().lower()
        if cosmetic not in owned.get(pokemon_key, set()):
            return False
    return True


def _ritual_build_collection_entries(user_id: int):
    owned = _ritual_load_user_cosmetics(user_id)
    entries = []

    with sqlite3.connect(RITUAL_DB_PATH) as conn:
        c = conn.cursor()

        for cosmetic in RITUAL_COSMETICS:
            cosmetic_emoji = _get_cosmetic_emoji(cosmetic, "")

            for collection_name, pokemon_list in RITUAL_COLLECTIONS.items():

                complete = _ritual_collection_complete(
                    owned,
                    pokemon_list,
                    cosmetic
                )

                collection_key = _ritual_collection_key(
                    collection_name,
                    cosmetic
                )

                if complete:
                    c.execute(
                        """
                        SELECT pulled_at
                        FROM ritual_pulls
                        WHERE user_id = ?
                        AND collection_key = ?
                        """,
                        (user_id, collection_key)
                    )

                    row = c.fetchone()

                    if row:
                        tick = f"<t:{row[0]}:R>"   # pull timestamp
                    else:
                        tick = "✅"                # completed but not pulled
                else:
                    tick = "❌"

                pokemon_emojis = " ".join(
                    get_pokemon_emoji(p)
                    for p in pokemon_list
                )

                line = (
                    f"{tick} "
                    f"{cosmetic_emoji}{collection_name} "
                    f"({cosmetic}): "
                    f"{pokemon_emojis}"
                )

                entries.append({
                    "collection": collection_name,
                    "cosmetic": cosmetic,
                    "complete": complete,
                    "line": line.strip(),
                })

    return entries


