def _ritual_resolve_reward(base_reward: dict) -> dict:
    if base_reward.get("type") == "popular_shiny":
        pokemon = random.choice(RITUAL_POPULAR_SHINY_POKEMON)
        return {
            "type": "pokemon_cosmetic",
            "pokemon": pokemon,
            "cosmetic": "shiny",
            "label": f"Popular Shiny Skin — {pokemon.title()}",
        }
    return base_reward


def _ritual_user_has_reward(
    cos_cursor: sqlite3.Cursor,
    ritual_cursor: sqlite3.Cursor,
    user_id: int,
    reward: dict,
) -> bool:
    prize_key = _ritual_reward_key(reward)
    ritual_cursor.execute(
        "SELECT 1 FROM ritual_prizes WHERE user_id = ? AND prize_key = ?",
        (user_id, prize_key),
    )
    if ritual_cursor.fetchone():
        return True
    reward_type = str(reward.get("type") or "").strip().lower()
    if reward_type == "pokemon_cosmetic":
        return _has_pokemon_cosmetic(cos_cursor, user_id, reward["pokemon"], reward["cosmetic"])
    if reward_type == "graphics":
        return _has_owned_value(cos_cursor, "graphics", "available_graphics", user_id, reward.get("value", ""))
    return False


def _ritual_sacrifice_collection(user_id: int, pokemon_list: list[str], cosmetic: str) -> list[str]:
    num_to_sacrifice = random.randint(2, 7)
    sacrificed = random.sample(pokemon_list, min(num_to_sacrifice, len(pokemon_list)))
    with sqlite3.connect("cosmetics.db") as conn:
        conn.isolation_level = None
        cursor = conn.cursor()
        for pokemon in sacrificed:
            _remove_pokemon_cosmetic(cursor, user_id, pokemon, cosmetic)
    return sacrificed


def _ritual_grant_reward(user_id: int) -> dict | None:
    try:
        with sqlite3.connect("cosmetics.db") as cos_conn, sqlite3.connect(RITUAL_DB_PATH) as ritual_conn:
            cos_conn.isolation_level = None  # Autocommit mode
            ritual_conn.isolation_level = None
            cos_cursor = cos_conn.cursor()
            ritual_cursor = ritual_conn.cursor()

            for _ in range(100):
                base_reward = random.choices(RITUAL_PRIZE_POOL, weights=RITUAL_PRIZE_WEIGHTS, k=1)[0]
                reward = _ritual_resolve_reward(base_reward)
                if _ritual_user_has_reward(cos_cursor, ritual_cursor, user_id, reward):
                    continue

                try:
                    # Insert prize record FIRST to reserve it
                    prize_key = _ritual_reward_key(reward)
                    ritual_cursor.execute(
                        "INSERT OR IGNORE INTO ritual_prizes (user_id, prize_key, granted_at) VALUES (?, ?, ?)",
                        (user_id, prize_key, int(time.time())),
                    )
                    # If we got here, prize was inserted. Now add the cosmetic.
                    reward_type = str(reward.get("type") or "").strip().lower()
                    if reward_type == "pokemon_cosmetic":
                        _append_pokemon_cosmetic(cos_cursor, user_id, reward["pokemon"], reward["cosmetic"])
                    elif reward_type == "graphics":
                        _append_owned_value(cos_cursor, "graphics", "available_graphics", user_id, reward.get("value", ""))
                    else:
                        continue
                    return reward
                except Exception as e:
                    # If anything fails, skip this reward and try the next one
                    print(f"Error granting reward to {user_id}: {e}")
                    continue
        return None
    except Exception as e:
        print(f"Critical error in _ritual_grant_reward for {user_id}: {e}")
        return None


class RitualCollectionView(discord.ui.View):
    def __init__(self, user_id: int, entries: list[dict]):
        super().__init__(timeout=300)
        self.user_id = int(user_id)
        self.entries = entries
        self.page = 0
        self.per_page = 5

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("This ritual panel is not for you.", ephemeral=True)
            return False
        return True

    def build_embed(self) -> discord.Embed:
        embed = _ritual_rules_embed()
        total_pages = max(1, math.ceil(len(self.entries) / self.per_page))
        self.page = max(0, min(self.page, total_pages - 1))
        start = self.page * self.per_page
        end = start + self.per_page
        lines = [entry["line"] for entry in self.entries[start:end]]
        embed.description = "\n".join(lines) if lines else "No collections available."
        embed.set_footer(text=f"Page {self.page + 1}/{total_pages}")
        return embed

    @discord.ui.button(label="⬅ Prev", style=discord.ButtonStyle.secondary, row=0)
    async def prev_page(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.page = max(0, self.page - 1)
        await interaction.response.edit_message(embed=self.build_embed(), view=self)

    @discord.ui.button(label="Next ➡", style=discord.ButtonStyle.secondary, row=0)
    async def next_page(self, interaction: discord.Interaction, button: discord.ui.Button):
        max_page = max(0, math.ceil(len(self.entries) / self.per_page) - 1)
        self.page = min(max_page, self.page + 1)
        await interaction.response.edit_message(embed=self.build_embed(), view=self)

    @discord.ui.button(label="Grand Prize", style=discord.ButtonStyle.primary, row=1)
    async def grand_prize(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.send_message(embed=_ritual_grand_prize_embed(), ephemeral=True)

    @discord.ui.button(label="Pull", style=discord.ButtonStyle.success, row=1)
    async def pull(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.send_modal(RitualPullModal(interaction.user.id))


class RitualPullModal(discord.ui.Modal, title="Ritual Pull"):
    cosmetic = discord.ui.TextInput(
        label="Cosmetic (dark/light/dynamax/...)",
        placeholder="e.g. dark",
        required=True,
        max_length=32,
    )
    collection = discord.ui.TextInput(
        label="Collection (ou rare/ou comm/cute)",
        placeholder="e.g. ou rare",
        required=True,
        max_length=32,
    )

    def __init__(self, user_id: int):
        super().__init__()
        self.user_id = int(user_id)

    async def on_submit(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            return await interaction.response.send_message("This pull is not for you.", ephemeral=True)

        cosmetic = str(self.cosmetic.value or "").strip().lower()
        collection_raw = str(self.collection.value or "").strip().lower()
        collection = RITUAL_COLLECTION_ALIASES.get(collection_raw)

        rare_rating, _, _, _ = get_ranked_stats_with_highest(interaction.user.id, "ranked rare")
        if (rare_rating or 0) <= 1100:
            return await interaction.response.send_message(
                "❌ Your current ranked rare rating must be above 1100 to pull.",
                ephemeral=True,
            )

        if cosmetic not in RITUAL_COSMETICS:
            return await interaction.response.send_message("❌ Invalid cosmetic type.", ephemeral=True)
        if not collection or collection not in RITUAL_COLLECTIONS:
            return await interaction.response.send_message("❌ Invalid collection name.", ephemeral=True)

        owned = _ritual_load_user_cosmetics(interaction.user.id)
        if not _ritual_collection_complete(owned, RITUAL_COLLECTIONS[collection], cosmetic):
            return await interaction.response.send_message(
                "❌ You haven't completed that collection yet.",
                ephemeral=True,
            )

        collection_key = _ritual_collection_key(collection, cosmetic)
        try:
            with sqlite3.connect(RITUAL_DB_PATH) as conn:
                conn.isolation_level = None  # Autocommit mode to prevent locks
                c = conn.cursor()
                c.execute(
                    "SELECT 1 FROM ritual_pulls WHERE user_id = ? AND collection_key = ?",
                    (interaction.user.id, collection_key),
                )
                if c.fetchone():
                    return await interaction.response.send_message(
                        "❌ You already pulled from this collection.",
                        ephemeral=True,
                    )

            reward = _ritual_grant_reward(interaction.user.id)
            if not reward:
                return await interaction.response.send_message(
                    "❌ No available rewards left. Contact an admin.",
                    ephemeral=True,
                )

            sacrificed = _ritual_sacrifice_collection(interaction.user.id, RITUAL_COLLECTIONS[collection], cosmetic)
            
            # Record the pull after successfully granting the reward and performing the sacrifice
            with sqlite3.connect(RITUAL_DB_PATH) as conn:
                conn.isolation_level = None
                c = conn.cursor()
                c.execute(
                    "INSERT OR IGNORE INTO ritual_pulls (user_id, collection_key, pulled_at) VALUES (?, ?, ?)",
                    (interaction.user.id, collection_key, int(time.time())),
                )
        except Exception as e:
            print(f"Error in ritual pull for {interaction.user.id}: {e}")
            return await interaction.response.send_message(
                f"⚠️ An error occurred during the ritual. Please contact an admin. (Error: {str(e)[:50]})",
                ephemeral=True,
            )

        reward_type = str(reward.get("type") or "").strip().lower()
        if reward_type == "graphics":
            gfx_name = str(reward.get("value") or "").strip().lower()
            reward_text = f"Animation [{gfx_name}] {_get_cosmetic_emoji(gfx_name, '')}".strip()
        else:
            cosmetic_emoji = _get_cosmetic_emoji(reward["cosmetic"], "")
            pokemon_emoji = get_pokemon_emoji(reward["pokemon"])
            reward_text = f"{pokemon_emoji} {reward['pokemon'].title()} [{reward['cosmetic']}] {cosmetic_emoji}".strip()
        embed = discord.Embed(
            title="Ritual Pull",
            description=f"🎁 You pulled **{reward_text}**\nYou sacrificed to the void.",
            color=discord.Color.green(),
        )
        if sacrificed:
            sacrificed_text = "\n".join(f"{get_pokemon_emoji(p)} {p.title()}" for p in sacrificed)
            embed.add_field(name="Sacrificed Pokemon", value=sacrificed_text, inline=False)
        else:
            embed.add_field(name="Sacrificed Pokemon", value="None this time.", inline=False)
        await interaction.response.send_message(embed=embed)


class RitualConvergenceModal(discord.ui.Modal, title="Soul Convergence Sacrifice"):
    shiny_pokemon = discord.ui.TextInput(
        label="Shiny Pokemon (5 names, comma-separated)",
        placeholder="e.g. mega rayquaza, zacian, yveltal, arceus, giratina",
        required=True,
        style=discord.TextStyle.paragraph,
        max_length=256,
    )
    shiny_mega_rare = discord.ui.TextInput(
        label="Shiny Mega Rare",
        placeholder="e.g. primal groudon",
        required=True,
        max_length=64,
    )

    def __init__(self, user_id: int):
        super().__init__()
        self.user_id = int(user_id)

    async def on_submit(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            return await interaction.response.send_message("This ritual is not for you.", ephemeral=True)

        raw_pokemon = str(self.shiny_pokemon.value or "")
        selected = [p.strip().lower() for p in re.split(r"[\n,;]+", raw_pokemon) if p.strip()]
        mega_rare = str(self.shiny_mega_rare.value or "").strip().lower()

        if len(selected) != 5:
            return await interaction.response.send_message(
                "❌ Please enter exactly 5 shiny pokemon in the first field.",
                ephemeral=True,
            )
        if not mega_rare:
            return await interaction.response.send_message(
                "❌ Please enter a shiny mega rare.",
                ephemeral=True,
            )
        if mega_rare in selected:
            return await interaction.response.send_message(
                "❌ Your shiny mega rare must be different from the other 5 shiny pokemon.",
                ephemeral=True,
            )
        if mega_rare not in RITUAL_SHINY_MEGA_RARES:
            return await interaction.response.send_message(
                "❌ Invalid shiny mega rare.",
                ephemeral=True,
            )

        normalized = selected + [mega_rare]

        with sqlite3.connect("cosmetics.db") as conn:
            c = conn.cursor()
            missing = []
            for pokemon in normalized:
                c.execute(
                    "SELECT available_cosmetics FROM pokemon WHERE user_id = ? AND lower(pokemon_name) = ?",
                    (interaction.user.id, pokemon),
                )
                row = c.fetchone()
                if not row or "shiny" not in (row[0] or ""):
                    missing.append(pokemon)

            c.execute(
                "SELECT available_cosmetics FROM pokemon WHERE user_id = ? AND lower(pokemon_name) = ?",
                (interaction.user.id, "mega rayquaza"),
            )
            row = c.fetchone()
            if not row or "rocket" not in (row[0] or ""):
                missing_rocket = True
            else:
                missing_rocket = False

            if missing:
                return await interaction.response.send_message(
                    f"❌ Missing shiny cosmetic for: {', '.join(missing)}",
                    ephemeral=True,
                )
            if missing_rocket:
                return await interaction.response.send_message(
                    "❌ You need a rocket rayquaza to complete the ritual.",
                    ephemeral=True,
                )

            for pokemon in normalized:
                _remove_pokemon_cosmetic(c, interaction.user.id, pokemon, "shiny")
            _remove_pokemon_cosmetic(c, interaction.user.id, "mega rayquaza", "rocket")
            _append_pokemon_cosmetic(c, interaction.user.id, "mega rayquaza", "shiny rocket")
            conn.commit()

        embed = discord.Embed(
            title="Soul Convergence Complete",
            description="✨ You obtained **Shiny Rocket Rayquaza**.",
            color=discord.Color.gold(),
        )
        await interaction.response.send_message(embed=embed)


