@bot.command(name="admin_give_cosmetic")
async def admin_give_cosmetic(
    ctx: commands.Context,
    member: discord.User,
    category: str,
    *,
    payload: str = None,
):
    if ctx.author.id not in owner_ids:
        return await ctx.send("You do not have permission to use this command.")

    if not payload or not payload.strip():
        return await ctx.send(
            "Usage:\n"
            "`!admin_give_cosmetic @user pokemon \"pokemon_name\" \"cosmetic_name\"`\n"
            "`!admin_give_cosmetic @user pokeball/background/color/status/graphics \"cosmetic_name\"`"
        )

    category_key = category.strip().lower()
    if category_key == "embed color":
        category_key = "color"
    if category_key == "animation":
        category_key = "graphics"

    simple_category_map = {
        "pokeball": ("pokeball", "available_pokeballs"),
        "background": ("background", "available_backgrounds"),
        "color": ("embed_color", "available_colors"),
        "embed_color": ("embed_color", "available_colors"),
        "status": ("status", "available_status"),
        "graphics": ("graphics", "available_graphics"),
    }

    try:
        parts = shlex.split(payload.strip())
    except ValueError:
        return await ctx.send(
            "Invalid format. If names contain spaces, wrap them in quotes."
        )

    with sqlite3.connect("cosmetics.db") as conn:
        cursor = conn.cursor()

        if category_key == "pokemon":
            if len(parts) < 2:
                return await ctx.send(
                    "Usage: `!admin_give_cosmetic @user pokemon \"pokemon_name\" \"cosmetic_name\"`"
                )

            pokemon_name = parts[0].strip().lower()
            cosmetic_name = " ".join(parts[1:]).strip().lower()
            if not pokemon_name or not cosmetic_name:
                return await ctx.send("Pokemon name and cosmetic name are required.")

            _append_pokemon_cosmetic(cursor, member.id, pokemon_name, cosmetic_name)
            conn.commit()
            return await ctx.send(
                f"Added pokemon cosmetic `{cosmetic_name}` for `{pokemon_name}` to {member.mention}."
            )

        table_info = simple_category_map.get(category_key)
        if not table_info:
            return await ctx.send(
                "Invalid category. Use: `pokemon`, `pokeball`, `background`, `color`, `status`, or `graphics`."
            )

        cosmetic_name = " ".join(parts).strip().lower()
        if not cosmetic_name:
            return await ctx.send("Cosmetic name is required.")

        table, column = table_info
        _append_owned_value(cursor, table, column, member.id, cosmetic_name)
        conn.commit()

    await ctx.send(
        f"Added `{cosmetic_name}` to `{category_key}` cosmetics for {member.mention}."
    )


@bot.command(name="admin_remove_cosmetics")
async def admin_remove_cosmetics(
    ctx: commands.Context,
    mode: str = None,
    user_id: int = None,
    cosmetic_type: str = None,
    *,
    rest: str = None
):
    print("called")
    if ctx.author.id not in owner_ids:
        return await ctx.send("❌ You must be a bot owner to use this command.")

    if not mode or user_id is None or not cosmetic_type:
        return await ctx.send(
            "Usage: `!admin_remove_cosmetics <equip|inv> <user id> <cosmetic type> <cosmetic name> <extra>`\n"
            "Example: `!admin_remove_cosmetics equip 123 pokemon dark mega rayquaza`"
        )

    mode_key = str(mode).strip().lower()
    if mode_key not in {"equip", "inv"}:
        return await ctx.send("Mode must be `equip` or `inv`.")

    type_key = _normalize_cosmetic_type(cosmetic_type)
    if not type_key:
        return await ctx.send("Invalid cosmetic type. Use pokemon/pokeball/background/color/status/graphics.")

    payload = str(rest or "").strip()
    if not payload:
        return await ctx.send("Please provide cosmetic name (and pokemon name for pokemon cosmetics).")

    removed = False
    with sqlite3.connect("cosmetics.db") as conn:
        cursor = conn.cursor()
        if type_key == "pokemon":
            cosmetic_name, pokemon_name = _split_pokemon_cosmetic_payload(payload)
            if not cosmetic_name or not pokemon_name:
                return await ctx.send("Usage: `!admin_remove_cosmetics <equip|inv> <user id> pokemon <cosmetic> <pokemon>`")
            if mode_key == "equip":
                _remove_equipped_cosmetic(cursor, user_id, "pokemon", cosmetic_name, pokemon_name=pokemon_name)
                removed = cursor.rowcount > 0
            else:
                removed = _remove_pokemon_cosmetic(cursor, user_id, pokemon_name, cosmetic_name)
                if removed:
                    _remove_equipped_cosmetic(cursor, user_id, "pokemon", cosmetic_name, pokemon_name=pokemon_name)
        else:
            cosmetic_name = payload.strip().lower()
            table, column = _COSMETIC_TABLES.get(type_key, (None, None))
            if not table:
                return await ctx.send("Invalid cosmetic type.")
            if mode_key == "equip":
                _remove_equipped_cosmetic(cursor, user_id, type_key, cosmetic_name)
                removed = cursor.rowcount > 0
            else:
                removed = _remove_owned_value(cursor, table, column, user_id, cosmetic_name)
                if removed:
                    _remove_equipped_cosmetic(cursor, user_id, type_key, cosmetic_name)
        conn.commit()

    if removed:
        await ctx.send("✅ Cosmetic removed.")
    else:
        await ctx.send("⚠️ Cosmetic not found or already removed.")


@bot.command(name="move_to_trial")
async def move_to_trial(ctx: commands.Context, *, payload: str = None):
    if ctx.author.id not in owner_ids:
        return await ctx.send("❌ You must be a bot owner to use this command.")

    if not payload or not payload.strip():
        return await ctx.send(
            "Usage:\n"
            "`!move_to_trial <pokemon> <cosmetic> <duration_days> <refund_currency> <refund_amount>`\n"
            "Example: `!move_to_trial \"mega rayquaza\" \"world guardian\" 7 dragon_scale 100`"
        )

    try:
        parts = shlex.split(payload.strip())
    except ValueError:
        return await ctx.send("Invalid format. Wrap multi-word values in quotes.")

    if len(parts) < 5:
        return await ctx.send(
            "Usage: `!move_to_trial <pokemon> <cosmetic> <duration_days> <refund_currency> <refund_amount>`"
        )

    pokemon_name = parts[0].strip().lower()
    cosmetic_name = parts[1].strip().lower()
    try:
        duration_days = int(parts[2])
        refund_amount = int(parts[4])
    except ValueError:
        return await ctx.send("Duration and refund amount must be integers.")

    refund_currency_raw = parts[3].strip().lower()
    refund_currency_map = {
        "dragon_scale": "dragon_scale",
        "dragon scale": "dragon_scale",
        "fantasy_gem": "fantasy_gem",
        "fantasy gem": "fantasy_gem",
        "fairy_gem": "fantasy_gem",
        "fairy gem": "fantasy_gem",
    }
    refund_currency = refund_currency_map.get(refund_currency_raw)
    if not refund_currency:
        return await ctx.send("Refund currency must be `dragon_scale` or `fantasy_gem` / `fairy gem`.")

    if not pokemon_name or not cosmetic_name:
        return await ctx.send("Pokemon name and cosmetic name are required.")
    if duration_days <= 0:
        return await ctx.send("Duration must be a positive number of days.")
    if refund_amount < 0:
        return await ctx.send("Refund amount must be zero or positive.")

    with sqlite3.connect(COSMETICS_DB) as conn:
        cursor = conn.cursor()
        cursor.execute(
            "SELECT user_id, available_cosmetics FROM pokemon WHERE lower(pokemon_name)=?",
            (pokemon_name,)
        )
        rows = cursor.fetchall()
        owners = []
        for user_id, available_cosmetics in rows:
            if cosmetic_name in _parse_csv_list(available_cosmetics):
                owners.append(int(user_id))
        owners = sorted(set(owners))

        if not owners:
            return await ctx.send(
                f"No users own `{cosmetic_name}` for `{pokemon_name}`."
            )

        expiry = int(time.time()) + duration_days * 86400
        for owner_id in owners:
            _remove_cosmetic(cursor, owner_id, "pokemon", cosmetic_name, pokemon_name=pokemon_name)
            _remove_equipped_cosmetic(cursor, owner_id, "pokemon", cosmetic_name, pokemon_name=pokemon_name)
            cursor.execute(
                "DELETE FROM market WHERE seller_id=? AND category='pokemon' AND lower(pokemon_name)=? AND lower(cosmetic)=? AND status='active'",
                (owner_id, pokemon_name, cosmetic_name)
            )
            _grant_trial_skin(owner_id, pokemon_name, cosmetic_name, expiry)
            if refund_amount:
                _tower_add_currency(owner_id, refund_currency, refund_amount)
        conn.commit()

    refund_name = "Dragon Scale" if refund_currency == "dragon_scale" else "Fantasy Gem"
    user_count = len(owners)
    dm_text = (
        f"Your `{cosmetic_name}` cosmetic for `{pokemon_name}` has been moved to trial "
        f"for {duration_days} day(s).\n"
        f"You have been refunded {refund_amount} {refund_name}.\n"
        "Use `!trial` to view your active trial skins."
    )

    for owner_id in owners:
        try:
            user = bot.get_user(owner_id) or await bot.fetch_user(owner_id)
            if user:
                await user.send(dm_text)
        except Exception:
            pass

    await ctx.send(
        f"Moved `{cosmetic_name}` for `{pokemon_name}` to trial for {user_count} user(s). "
        f"Refunded {refund_amount} {refund_name} each."
    )


@bot.command(name="trial")
async def trial_command(ctx: commands.Context):
    trial_rows = _get_active_trial_skins(ctx.author.id)
    if not trial_rows:
        return await ctx.send("You have no active trial skins.")

    lines = []
    for row in trial_rows:
        expires_at = int(row["expires_at"])
        pokemon_text = str(row["pokemon_name"]).title()
        cosmetic_text = str(row["cosmetic"])
        lines.append(
            f"• **{pokemon_text}** — {cosmetic_text} — expires <t:{expires_at}:F> (<t:{expires_at}:R>)"
        )

    embed = discord.Embed(
        title="Active Trial Skins",
        description="\n".join(lines),
        color=discord.Color.blurple(),
    )
    await ctx.send(embed=embed)


@bot.command(name="reset_hero_points")
async def reset_hero_points(ctx: commands.Context, member: discord.User):
    if ctx.author.id not in owner_ids:
        return await ctx.send("You do not have permission to use this command.")

    with sqlite3.connect("cosmetics.db") as conn:
        cursor = conn.cursor()
        _init_battle_reward_tables(cursor)
        cursor.execute(
            'INSERT OR IGNORE INTO "hero point" (user_id, amount) VALUES (?, 0)',
            (member.id,),
        )
        cursor.execute(
            'UPDATE "hero point" SET amount = 0 WHERE user_id = ?',
            (member.id,),
        )
        cursor.execute(
            "DELETE FROM battle_reward_winners WHERE reward_type = 'hero' AND user_id = ?",
            (member.id,),
        )
        removed_winner = cursor.rowcount > 0
        removed_cosmetic = _remove_pokemon_cosmetic(
            cursor, member.id, "zacian", "hero of a thousand battles"
        )
        cursor.execute(
            "SELECT COUNT(*) FROM battle_reward_winners WHERE reward_type = 'hero'"
        )
        hero_winners = int(cursor.fetchone()[0] or 0)
        if hero_winners < SPECIAL_REWARD_WINNER_CAP:
            _set_meta_flag(cursor, "hero_enabled", True)
        conn.commit()

    parts = [f"Reset hero points for {member.mention}."]
    if removed_cosmetic:
        parts.append("Removed Zacian [hero of a thousand battles] cosmetic.")
    if removed_winner:
        parts.append("Removed hero winner entry.")
    parts.append(f"Hero winners: {hero_winners}/{SPECIAL_REWARD_WINNER_CAP}.")
    await ctx.send(" ".join(parts))


