GACHA_BANNERS_DB = "gacha_banners.db"

def _gacha_banner_conn(): return sqlite3.connect(GACHA_BANNERS_DB)

def ensure_gacha_banner_tables():
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("""CREATE TABLE IF NOT EXISTS gacha_banner_pool (
        id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE,
        filename TEXT NOT NULL, filetype TEXT NOT NULL CHECK(filetype IN ('png','jpg','gif')),
        data BLOB NOT NULL, is_premium INTEGER NOT NULL DEFAULT 0,
        uploaded_by TEXT NOT NULL, uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)""")
    c.execute("""CREATE TABLE IF NOT EXISTS gacha_border_pool (
        id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE,
        data BLOB NOT NULL, is_premium INTEGER NOT NULL DEFAULT 0,
        uploaded_by TEXT NOT NULL, uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)""")
    c.execute("""CREATE TABLE IF NOT EXISTS user_banners (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL,
        banner_name TEXT NOT NULL, won_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        UNIQUE(user_id, banner_name))""")
    c.execute("""CREATE TABLE IF NOT EXISTS user_borders (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id TEXT NOT NULL,
        border_name TEXT NOT NULL, won_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        UNIQUE(user_id, border_name))""")
    conn.commit(); conn.close()

# ═════════════════════════════════════════════════════════════════════════════
#  BANNER / BORDER POOL HELPERS (unchanged)
# ═════════════════════════════════════════════════════════════════════════════

def gdb_insert_banner(name, data, filetype, is_premium, uploader_id):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("INSERT INTO gacha_banner_pool (name,filename,filetype,data,is_premium,uploaded_by) VALUES (?,?,?,?,?,?)",
              (name, f"{name}.{filetype}", filetype, data, int(is_premium), uploader_id))
    conn.commit(); bid = c.lastrowid; conn.close(); return bid

def gdb_get_banner_by_name(name):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT id,name,filetype,data,is_premium FROM gacha_banner_pool WHERE name=?", (name,))
    row = c.fetchone(); conn.close()
    if not row: return None
    return {"id":row[0],"name":row[1],"type":row[2],"data":bytes(row[3]),"premium":bool(row[4])}

def gdb_get_banner_by_id(banner_id):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT id,name,filetype,data,is_premium FROM gacha_banner_pool WHERE id=?", (banner_id,))
    row = c.fetchone(); conn.close()
    if not row: return None
    return {"id":row[0],"name":row[1],"type":row[2],"data":bytes(row[3]),"premium":bool(row[4])}

def gdb_list_banners(include_premium=True):
    conn = _gacha_banner_conn(); c = conn.cursor()
    q = "SELECT id,name,filetype,is_premium FROM gacha_banner_pool ORDER BY is_premium,name"
    if not include_premium: q = q.replace("ORDER","WHERE is_premium=0 ORDER")
    c.execute(q); rows = c.fetchall(); conn.close()
    return [{"id":r[0],"name":r[1],"type":r[2],"premium":bool(r[3])} for r in rows]

def gdb_delete_banner(banner_id):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT name FROM gacha_banner_pool WHERE id=?", (banner_id,))
    row = c.fetchone()
    if not row: conn.close(); return None
    c.execute("DELETE FROM gacha_banner_pool WHERE id=?", (banner_id,))
    conn.commit(); conn.close(); return row[0]

def gdb_insert_border(name, data, is_premium, uploader_id):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("INSERT INTO gacha_border_pool (name,data,is_premium,uploaded_by) VALUES (?,?,?,?)",
              (name, data, int(is_premium), uploader_id))
    conn.commit(); bid = c.lastrowid; conn.close(); return bid

def gdb_get_border_by_id(border_id):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT id,name,data,is_premium FROM gacha_border_pool WHERE id=?", (border_id,))
    row = c.fetchone(); conn.close()
    if not row: return None
    return {"id":row[0],"name":row[1],"data":bytes(row[2]),"premium":bool(row[3])}

def gdb_list_borders(include_premium=True):
    conn = _gacha_banner_conn(); c = conn.cursor()
    q = "SELECT id,name,is_premium FROM gacha_border_pool ORDER BY is_premium,name"
    if not include_premium: q = q.replace("ORDER","WHERE is_premium=0 ORDER")
    c.execute(q); rows = c.fetchall(); conn.close()
    return [{"id":r[0],"name":r[1],"premium":bool(r[2])} for r in rows]

def gdb_delete_border(border_id):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT name FROM gacha_border_pool WHERE id=?", (border_id,))
    row = c.fetchone()
    if not row: conn.close(); return None
    c.execute("DELETE FROM gacha_border_pool WHERE id=?", (border_id,))
    conn.commit(); conn.close(); return row[0]

def gdb_grant_banner_to_user(user_id, banner_name):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT 1 FROM user_banners WHERE user_id=? AND banner_name=?", (user_id, banner_name))
    if c.fetchone(): conn.close(); return False
    c.execute("INSERT INTO user_banners (user_id,banner_name) VALUES (?,?)", (user_id, banner_name))
    conn.commit(); conn.close(); return True

def gdb_grant_border_to_user(user_id, border_name):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT 1 FROM user_borders WHERE user_id=? AND border_name=?", (user_id, border_name))
    if c.fetchone(): conn.close(); return False
    c.execute("INSERT INTO user_borders (user_id,border_name) VALUES (?,?)", (user_id, border_name))
    conn.commit(); conn.close(); return True

def gdb_get_user_banners(user_id):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("""SELECT gbp.name,gbp.filetype,gbp.is_premium FROM user_banners ub
        JOIN gacha_banner_pool gbp ON ub.banner_name=gbp.name
        WHERE ub.user_id=? ORDER BY gbp.is_premium,gbp.name""", (user_id,))
    rows = c.fetchall(); conn.close()
    return [{"name":r[0],"type":r[1],"premium":bool(r[2])} for r in rows]

def gdb_get_user_borders(user_id):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("""SELECT gbp.name,gbp.is_premium FROM user_borders ub
        JOIN gacha_border_pool gbp ON ub.border_name=gbp.name
        WHERE ub.user_id=? ORDER BY gbp.is_premium,gbp.name""", (user_id,))
    rows = c.fetchall(); conn.close()
    return [{"name":r[0],"premium":bool(r[1])} for r in rows]

def gdb_get_border_data_for_user(user_id, border_name):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT 1 FROM user_borders WHERE user_id=? AND border_name=?", (user_id, border_name))
    if not c.fetchone(): conn.close(); return None
    c.execute("SELECT data FROM gacha_border_pool WHERE name=?", (border_name,))
    row = c.fetchone(); conn.close()
    return bytes(row[0]) if row else None

# ═════════════════════════════════════════════════════════════════════════════
#  WEIGHTED ROLL
# ═════════════════════════════════════════════════════════════════════════════

_KIND_GIF = "gif_banner"; _KIND_STATIC = "static_banner"; _KIND_BORDER = "border"

def _pick_gacha_reward(exclude_banners=None, exclude_borders=None):
    conn = _gacha_banner_conn(); c = conn.cursor()
    c.execute("SELECT name,filetype FROM gacha_banner_pool WHERE is_premium=0"); banner_rows = c.fetchall()
    c.execute("SELECT name FROM gacha_border_pool WHERE is_premium=0"); border_rows = c.fetchall(); conn.close()
    gif_names    = [r[0] for r in banner_rows if r[1]=="gif"]
    static_names = [r[0] for r in banner_rows if r[1]!="gif"]
    border_names = [r[0] for r in border_rows]
    if exclude_banners:
        gif_names    = [n for n in gif_names    if n not in exclude_banners]
        static_names = [n for n in static_names if n not in exclude_banners]
    if exclude_borders: border_names = [n for n in border_names if n not in exclude_borders]
    pool = []
    if gif_names:    pool.append((5.0,  _KIND_GIF))
    if static_names: pool.append((50.0, _KIND_STATIC))
    if border_names: pool.append((45.0, _KIND_BORDER))
    if not pool: return None
    total = sum(w for w,_ in pool); r = random.random()*total; chosen = pool[-1][1]; cum = 0.0
    for w,k in pool:
        cum += w
        if r < cum: chosen = k; break
    if chosen == _KIND_GIF:    return (_KIND_GIF,    random.choice(gif_names))
    if chosen == _KIND_STATIC: return (_KIND_STATIC, random.choice(static_names))
    return (_KIND_BORDER, random.choice(border_names))

def grant_random_gacha_reward(user_id):
    result = _pick_gacha_reward()
    if not result: return None, None, False
    kind, name = result
    is_new = gdb_grant_banner_to_user(user_id, name) if kind in (_KIND_GIF,_KIND_STATIC) else gdb_grant_border_to_user(user_id, name)
    return kind, name, is_new

def grant_random_gacha_banner(user_id):
    kind, name, is_new = grant_random_gacha_reward(user_id)
    return (name, is_new) if kind in (_KIND_GIF,_KIND_STATIC) else (None, False)

def _format_reward_line(kind, name, is_new):
    if not name: return "❌ No items in prize pool yet — contact an admin."
    is_banner = kind in (_KIND_GIF,_KIND_STATIC); emoji = "🖼️" if is_banner else "🔮"
    label = "Profile Banner" if is_banner else "Avatar Border"; gif_tag = " 🎞️ *animated*" if kind==_KIND_GIF else ""
    return (f"{emoji} **{label}** won: **{name}**{gif_tag} — equip with `pf edit`!" if is_new
            else f"{emoji} ~~{name}~~ — duplicate {label}")

