#  ANIME COUPON PITY — 1/50 random OR guaranteed at 50th pull
# ═════════════════════════════════════════════════════════════════════════════

def _ensure_anime_coupon_pity_table(c):
    c.execute("""CREATE TABLE IF NOT EXISTS anime_coupon_pity (
        user_id INTEGER PRIMARY KEY, pulls_since_last INTEGER DEFAULT 0)""")

def _check_anime_coupon_pity(user_id):
    conn = sqlite3.connect("cosmetics.db"); c = conn.cursor()
    _ensure_anime_coupon_pity_table(c)
    c.execute("INSERT OR IGNORE INTO anime_coupon_pity (user_id,pulls_since_last) VALUES (?,0)", (user_id,))
    c.execute("SELECT pulls_since_last FROM anime_coupon_pity WHERE user_id=?", (user_id,))
    row = c.fetchone(); pulls = (row[0] if row else 0) + 1
    was_pity = pulls >= 50; random_hit = (not was_pity) and (random.randint(1,50)==1)
    granted = was_pity or random_hit
    if granted:
        c.execute("UPDATE anime_coupon_pity SET pulls_since_last=0 WHERE user_id=?", (user_id,))
        conn.commit(); conn.close(); _upsert_coupon(user_id, 1)
    else:
        c.execute("UPDATE anime_coupon_pity SET pulls_since_last=? WHERE user_id=?", (pulls, user_id))
        conn.commit(); conn.close()
    return granted, was_pity

