NORMAL_COSMETICS = {"red","blue","green","cyan","purple","golden","dark","light","crimson","aura","plate","dynamax"}

class GachaExchangeModal(discord.ui.Modal, title="Exchange Cosmetic (10c/20c)"):
    pokemon_name  = discord.ui.TextInput(label="Pokemon Name",  placeholder="e.g. regigigas", required=True, max_length=60)
    cosmetic_name = discord.ui.TextInput(label="Cosmetic Name", placeholder="e.g. red / dark / shiny", required=True, max_length=80)

    def __init__(self, source_view=None):
        super().__init__(); self.source_view = source_view

    async def on_submit(self, interaction: discord.Interaction):
        user_id = interaction.user.id; pokemon = self.pokemon_name.value.strip().lower(); cosmetic = self.cosmetic_name.value.strip().lower()
        special = {"true titan","hero of a thousand battles","hero of a thousand battle","president","merciless","achilles"}
        shiny_like = cosmetic == "shiny" or cosmetic in special
        if not shiny_like and cosmetic not in NORMAL_COSMETICS:
            return await interaction.response.send_message("❌ This cosmetic is not available via normal exchange coupons.", ephemeral=True)
        table_name = "shiny exchange coupon" if shiny_like else "exchange coupon"
        required = 20 if cosmetic in {"dark","light","dynamax","plate","crimson","aura"} else 10
        poke_info = get_pokemon_info(pokemon)
        if not poke_info: return await interaction.response.send_message("❌ Invalid pokemon name.", ephemeral=True)
        conn = sqlite3.connect("cosmetics.db"); c = conn.cursor(); _ensure_exchange_coupon_tables(c)
        c.execute(f'INSERT OR IGNORE INTO "{table_name}" (user_id,amount) VALUES (?,0)', (user_id,))
        c.execute(f'SELECT amount FROM "{table_name}" WHERE user_id=?', (user_id,)); row = c.fetchone()
        current = int(row[0] if row and row[0] is not None else 0)
        if current < required:
            conn.close(); lbl = "shiny exchange coupon(s)" if shiny_like else "exchange coupon(s)"
            return await interaction.response.send_message(f"❌ You need {required-current} more {lbl}.", ephemeral=True)
        if _has_pokemon_cosmetic(c, user_id, pokemon, cosmetic):
            conn.close(); return await interaction.response.send_message("❌ You already have this pokemon cosmetic.", ephemeral=True)
        c.execute(f'UPDATE "{table_name}" SET amount=amount-? WHERE user_id=?', (required, user_id))
        _append_pokemon_cosmetic(c, user_id, pokemon, cosmetic); conn.commit(); conn.close()
        em = COSMETIC_EMOJIS.get(cosmetic,""); display = f"{pokemon.title()} [{cosmetic}]" + (f" {em}" if em else "")
        await interaction.response.send_message(f"✅ Exchanged {required} {'shiny ' if shiny_like else ''}exchange coupon(s) for {display}.", ephemeral=True)
        try:
            if self.source_view and interaction.message:
                await interaction.message.edit(embed=_build_gacha_embed(self.source_view.page, user_id), view=self.source_view)
        except Exception: pass

# ═════════════════════════════════════════════════════════════════════════════
#  BANNER INSURANCE VIEW
# ═════════════════════════════════════════════════════════════════════════════

def _add_arcs(user_id, amount):
    conn = connect_poke_db(); ensure_player(conn, user_id); cp = conn.cursor()
    cp.execute("UPDATE poke SET coins=coins+? WHERE player_id=?", (amount, user_id)); conn.commit(); conn.close()

class BannerInsuranceView(discord.ui.View):
    INSURANCE_COST = 250
    def __init__(self, user_id, parent_view, gacha_message):
        super().__init__(timeout=60); self.user_id=user_id; self.parent_view=parent_view; self.gacha_message=gacha_message
    async def interaction_check(self, interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("This isn't for you.", ephemeral=True); return False
        return True
    async def _execute(self, interaction, insurance):
        banner = GACHA_BANNERS[self.parent_view.page]; user_id = interaction.user.id; uid = str(user_id)
        ok, spend_msg, _ = _spend_gacha_cost(user_id, banner, 1)
        if not ok: return await interaction.response.edit_message(content=spend_msg, view=None)
        if insurance:
            conn = connect_poke_db(); ensure_player(conn, user_id); cp = conn.cursor()
            cp.execute("UPDATE poke SET coins=coins-? WHERE player_id=? AND coins>=?", (self.INSURANCE_COST, user_id, self.INSURANCE_COST))
            if cp.rowcount == 0:
                cp.execute("UPDATE poke SET coins=coins+? WHERE player_id=?", (banner["cost"], user_id)); conn.commit(); conn.close()
                return await interaction.response.edit_message(content=f"❌ Can't afford {self.INSURANCE_COST} ARC insurance. Pull refunded.", view=None)
            conn.commit(); conn.close()
        total = banner["cost"] + (self.INSURANCE_COST if insurance else 0); result_msg = ""
        if insurance:
            if random.random() < 0.70:
                ob={b["name"] for b in gdb_get_user_banners(uid)}; ors={b["name"] for b in gdb_get_user_borders(uid)}
                result = _pick_gacha_reward(exclude_banners=ob, exclude_borders=ors)
                if result:
                    kind, name = result
                    if kind in (_KIND_GIF,_KIND_STATIC): gdb_grant_banner_to_user(uid,name); emoji="🖼️"; label="Profile Banner"; tag=" 🎞️" if kind==_KIND_GIF else ""
                    else: gdb_grant_border_to_user(uid,name); emoji="🔮"; label="Avatar Border"; tag=""
                    result_msg = f"✅ Spent **{total} ARCs**.\n🛡️ **No duplicate guaranteed!**\n{emoji} **{label}** won: **{name}**{tag} — equip with `pf edit`."
                else:
                    _add_arcs(user_id,200); result_msg = f"✅ Spent **{total} ARCs**.\n🛡️ You own every item in the pool!\nCompensation: **+200 ARCs**."
            else:
                kind, name, is_new = grant_random_gacha_reward(uid)
                if not name: result_msg = "❌ No items in prize pool yet."
                elif is_new: result_msg = f"✅ Spent **{total} ARCs**.\n" + _format_reward_line(kind, name, True)
                else:
                    _add_arcs(user_id,200); emoji="🖼️" if kind in (_KIND_GIF,_KIND_STATIC) else "🔮"; label="banner" if kind in (_KIND_GIF,_KIND_STATIC) else "border"
                    result_msg = f"✅ Spent **{total} ARCs**.\n{emoji} Rolled **{name}** — duplicate {label}.\n🛡️ Insurance: **+200 ARCs** added."
        else:
            kind, name, is_new = grant_random_gacha_reward(uid)
            if not name: result_msg = "❌ No items in prize pool yet."
            elif is_new: result_msg = f"✅ Spent **{banner['cost']} ARCs**.\n" + _format_reward_line(kind, name, True)
            else:
                emoji="🖼️" if kind in (_KIND_GIF,_KIND_STATIC) else "🔮"; label="banner" if kind in (_KIND_GIF,_KIND_STATIC) else "border"
                result_msg = f"✅ Spent **{banner['cost']} ARCs**.\n{emoji} Rolled **{name}** — duplicate {label}.\n⚠️ No insurance, no refund. 😔"
        await interaction.response.edit_message(content=result_msg, view=None)
        try:
            if self.gacha_message:
                await self.gacha_message.edit(embed=_build_gacha_embed(self.parent_view.page, user_id), view=self.parent_view)
        except Exception: pass
    @discord.ui.button(label="🛡️ With Insurance  (+250 ARCs)", style=discord.ButtonStyle.green)
    async def with_insurance(self, interaction, button): await self._execute(interaction, True)
    @discord.ui.button(label="🎲 No Insurance", style=discord.ButtonStyle.red)
    async def no_insurance(self, interaction, button): await self._execute(interaction, False)

# ═════════════════════════════════════════════════════════════════════════════
#  EVENT GACHA WHEEL — display + animation
# ═════════════════════════════════════════════════════════════════════════════

_EVENT_WHEEL_DISPLAY = [
    ("<:titan:1506914927498235924>", "Anime Event"),
    ("🌟", "Shiny Exchange Coupon"),
    ("✨", "Shiny Cosmetic"),
    ("🎟️", "Exchange Coupon ×2"),
    ("🎟️", "Exchange Coupon ×1"),
    ("💎", "Premium Cosmetic"),
    ("🎨", "Hue Cosmetic"),
    ("💰", "ARCs +25"),
    ("💰", "ARCs +50"),
    ("🎫", "Anime Coupon"),
]
_N_EVENT_SLOTS = len(_EVENT_WHEEL_DISPLAY)

# Blink pool — random symbols flashed during draw-10 scan
_BLINK_POOL = ["🌌","🌟","✨","🎟️","🖼️","💎","🎨","💰","🎫","⚡","💫","🌀","❓","🎰","🔮","🎴"]

def _reward_to_wheel_idx(reward):
    r_type = reward.get("type")
    if r_type == "pokemon_cosmetic":
        cos = reward.get("cosmetic","")
        if cos in _COSMIC_COSMETICS: return 0
        if cos == "shiny":           return 2
        if cos in {"dark","light","crimson","plate","aura"}: return 6
        return 7
    if r_type == "exchange_coupon":
        if reward.get("shiny"): return 1
        return 3 if reward.get("amount",1) >= 2 else 4
    if r_type == "arc": return 7 if reward.get("amount",0) <= 25 else 8
    if r_type == "arc": return 8 if reward.get("amount",0) <= 50 else 9
    return 7

# ── Delay tables ──────────────────────────────────────────────────────────────
# Draw 1: 32 frames, smooth deceleration (circular reel feel)
_WHEEL_DELAYS_FULL  = [0.05]*5 + [0.08]*6 + [0.12]*5 + [0.18]*5 + [0.28]*4 + [0.42]*4 + [0.65]*3

# Draw 10: 12 frames of fast blink per pull
_WHEEL_DELAYS_BLINK = [0.07]*4 + [0.10]*4 + [0.15]*2 + [0.22]*2

def _build_spin_sequence(winning_idx, n_labels, n_frames):
    if n_frames <= 1: return [winning_idx]
    start = random.randint(0, n_labels - 1)
    steps_to_winner = (winning_idx - start) % n_labels or n_labels
    total_steps = 3 * n_labels + steps_to_winner
    seq = [round(total_steps * f / (n_frames - 1)) for f in range(n_frames)]
    result = [(start + s) % n_labels for s in seq]
    result[-1] = winning_idx
    return result

# ── DRAW 1: Circular reel embed ───────────────────────────────────────────────
# Shows 5 items in a slot-reel window. The active slot is bolded with ▶◀.
# Items above scroll ↑, items below scroll ↓ — clear sense of rotation.

def _wheel_reel_embed(current_idx, frame, pull_n, total_pulls):
    n = _N_EVENT_SLOTS
    total_frames = len(_WHEEL_DELAYS_FULL)

    # Speed indicator: red early → green late
    progress = frame / max(total_frames, 1)
    if   progress < 0.25: speed = "🔴🔴🔴 Fast"
    elif progress < 0.50: speed = "🟠🟠🔴 Medium"
    elif progress < 0.75: speed = "🟡🟡🟠 Slowing…"
    else:                 speed = "🟢🟢🟡 Almost…"

    # 5-slot window: offsets -2 -1 0 +1 +2
    lines = ""
    for offset in range(-2, 3):
        idx = (current_idx + offset) % n
        emoji, label = _EVENT_WHEEL_DISPLAY[idx]
        if offset == -2:
            lines += f"⬆️  {emoji}  {label}\n"
        elif offset == -1:
            lines += f"↑   {emoji}  {label}\n"
        elif offset == 0:
            lines += f"**▶  {emoji}  {label}  ◀**\n"   # active slot
        elif offset == 1:
            lines += f"↓   {emoji}  {label}\n"
        elif offset == 2:
            lines += f"⬇️  {emoji}  {label}\n"

    title = "🎡 Spinning…" if total_pulls == 1 else f"🎡 Spinning ({pull_n}/{total_pulls})…"
    embed = discord.Embed(title=title, description=lines, color=discord.Color.yellow())
    embed.set_footer(text=speed)
    return embed

# ── DRAW 10: Blink scan embed ─────────────────────────────────────────────────
# Rapid random symbols flash across the screen, giving a high-energy scan feel.
# Color and text alternate each frame to create the "eye blink" effect.

_BLINK_STATES = [
    (discord.Color.from_rgb(255,200,0),   "⚡ **S C A N N I N G** ⚡"),
    (discord.Color.from_rgb(200,50,255),  "🌀 **R O L L I N G** 🌀"),
    (discord.Color.from_rgb(0,200,255),   "✨ **S P I N N I N G** ✨"),
    (discord.Color.from_rgb(255,80,80),   "🎰 **L O A D I N G** 🎰"),
]

def _wheel_blink_embed(frame, pull_n, total_pulls):
    state_idx   = frame % len(_BLINK_STATES)
    color, text = _BLINK_STATES[state_idx]
    symbols     = "  ".join(random.choice(_BLINK_POOL) for _ in range(7))
    lines = f"{text}\n\n{symbols}"
    return discord.Embed(
        title=f"🎰 Pull {pull_n}/{total_pulls}",
        description=lines,
        color=color,
    )

# ── Landing embed (shared by both modes) ──────────────────────────────────────

def _wheel_land_embed(winning_idx, pull_n, total_pulls):
    lines = ""
    for i, (emoji, label) in enumerate(_EVENT_WHEEL_DISPLAY):
        if i == winning_idx:
            lines += f"## ✨ {emoji} **{label}** ✨\n"
        else:
            lines += f"　　{emoji} {label}\n"
    title = "🎡 Landed!" if total_pulls == 1 else f"🎡 Pull {pull_n}/{total_pulls} — Landed!"
    return discord.Embed(title=title, description=lines, color=discord.Color.green())

def _format_event_reward_detail(reward, anime_granted, was_pity):
    r_type = reward.get("type",""); lines = []
    if r_type == "pokemon_cosmetic":
        cos = reward.get("cosmetic",""); poke = reward.get("pokemon","").title()
        em  = COSMETIC_EMOJIS.get(cos,"")
        tier = ("🌌 **Cosmic Event**" if cos in _COSMIC_COSMETICS
                else "✨ **Shiny**" if cos=="shiny"
                else "💎 **Premium**" if cos in {"dark","light","crimson","plate","aura"}
                else "🎨 **Hue**")
        lines.append(f"{tier} — **{poke}** `[{cos}]`" + (f" {em}" if em else ""))
    elif r_type == "exchange_coupon":
        amt = reward.get("amount",1)
        lines.append(f"🌟 **Shiny Exchange Coupon** ×{amt}" if reward.get("shiny") else f"🎟️ **Exchange Coupon** ×{amt}")
    elif r_type == "arc": lines.append(f"💰 **ARCs +{reward.get('amount',0)}**")
    elif r_type == "background": lines.append(f"🖼️ **Background** — {reward.get('value','').title()}")
    elif r_type == "status":
        em = COSMETIC_EMOJIS.get(reward.get('value',''),"")
        lines.append(f"🎯 **Status** — {reward.get('value','').title()}" + (f" {em}" if em else ""))
    elif r_type == "embed_color": lines.append(f"🎨 **Embed Color** — {reward.get('value','').title()}")
    elif r_type == "graphics": lines.append(f"✨ **Animation** — {reward.get('value','').title()}")
    else: lines.append(f"🎁 {reward.get('text','Unknown reward')}")
    if anime_granted:
        lines.append(f"　🎫 **+1 Anime Coupon**" + (" *(pity — 50th pull!)*" if was_pity else ""))
    return "\n".join(lines)

# ── Animation runners ─────────────────────────────────────────────────────────

async def _run_reel_animation(msg, winning_idx, pull_n, total_pulls):
    """Draw 1 — circular reel with smooth deceleration."""
    seq = _build_spin_sequence(winning_idx, _N_EVENT_SLOTS, len(_WHEEL_DELAYS_FULL))
    for frame, (delay, slot) in enumerate(zip(_WHEEL_DELAYS_FULL, seq), 1):
        await asyncio.sleep(delay)
        await msg.edit(embed=_wheel_reel_embed(slot, frame, pull_n, total_pulls))
    await asyncio.sleep(0.25)
    await msg.edit(embed=_wheel_land_embed(winning_idx, pull_n, total_pulls))
    await asyncio.sleep(1.0)

async def _run_blink_animation(msg, winning_idx, pull_n, total_pulls):
    """Draw 10 — rapid blink scan then land."""
    for frame, delay in enumerate(_WHEEL_DELAYS_BLINK, 1):
        await asyncio.sleep(delay)
        await msg.edit(embed=_wheel_blink_embed(frame, pull_n, total_pulls))
    await asyncio.sleep(0.15)
    await msg.edit(embed=_wheel_land_embed(winning_idx, pull_n, total_pulls))
    await asyncio.sleep(0.6)

# ═════════════════════════════════════════════════════════════════════════════
#  GACHA VIEW
# ═════════════════════════════════════════════════════════════════════════════

class CosmeticGachaView(discord.ui.View):
    def __init__(self, user_id):
        super().__init__(timeout=300); self.user_id = user_id; self.page = 0

    async def interaction_check(self, interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("This gacha panel is not for you.", ephemeral=True); return False
        return True

    async def _do_pull(self, interaction, pulls):
        banner = GACHA_BANNERS[self.page]

        # ── SPOT 7: Banner & Border ────────────────────────────────────────
        if banner.get("banner_only") and pulls == 1:
            ins = BannerInsuranceView(interaction.user.id, self, interaction.message)
            await interaction.response.send_message(
                "🖼️🔮 **Profile Banner & Border Gacha**\n\n"
                "**Weights:** 5% 🎞️ GIF banner · 50% 🖼️ static banner · 45% 🔮 avatar border\n\n"
                "**🎲 No Insurance** — 500 ARCs. Duplicate = nothing.\n\n"
                "**🛡️ With Insurance** — 750 ARCs.\n"
                "• 70% — guaranteed no duplicate.\n• 30% — normal roll; duplicate → **+200 ARCs**.",
                view=ins, ephemeral=True); return

        if banner.get("banner_only") and pulls == 10:
            ok, spend_msg, _ = _spend_gacha_cost(interaction.user.id, banner, 10)
            if not ok: return await interaction.response.send_message(spend_msg, ephemeral=True)
            uid = str(interaction.user.id); lines = []
            for _ in range(10):
                kind, name, is_new = grant_random_gacha_reward(uid)
                lines.append(_format_reward_line(kind, name, is_new) if name else "❌ No items in pool.")
            await interaction.response.send_message(f"✅ {spend_msg}\n🎁 Pulls:\n" + "\n".join(lines))
            try:
                if interaction.message:
                    await interaction.message.edit(embed=_build_gacha_embed(self.page, interaction.user.id), view=self)
            except Exception: pass
            return

        # ── SPOT 8: Event Gacha ────────────────────────────────────────────
        if banner.get("event_only"):
            ok, spend_msg, _ = _spend_gacha_cost(interaction.user.id, banner, pulls)
            if not ok: return await interaction.response.send_message(spend_msg, ephemeral=True)

            await interaction.response.defer()

            all_rewards  = []
            pull_results = []
            anim_msg     = None
            is_draw_10   = (pulls > 1)

            # Draw 10: send a placeholder now so we can edit it with results later
            if is_draw_10:
                anim_msg = await interaction.followup.send(embed=discord.Embed(
                    title="🎰 Rolling…",
                    description="Processing all 10 pulls…",
                    color=discord.Color.blurple(),
                ))

            # Robust pull loop: reroll duplicates (check DB and current batch) and
            # protect with exception handling so tickets are refunded on error.
            try:
                conn = sqlite3.connect("cosmetics.db")
                c = conn.cursor()

                for pull_n in range(1, pulls + 1):
                    # generate non-duplicate reward (check DB and current batch)
                    reward = None
                    for _try in range(80):
                        candidate = _roll_gacha_reward(banner, interaction.user.id)
                        if candidate.get("type") == "error":
                            reward = candidate
                            break
                        # check DB duplicates
                        if _event_reward_is_duplicate(c, interaction.user.id, candidate):
                            continue
                        # check duplicates within same multi-pull batch
                        dup_in_batch = False
                        for ar in all_rewards:
                            if ar.get("type") == candidate.get("type") == "pokemon_cosmetic":
                                if ar.get("pokemon") == candidate.get("pokemon") and ar.get("cosmetic") == candidate.get("cosmetic"):
                                    dup_in_batch = True; break
                            if ar.get("type") in ("background","embed_color","status","graphics","pokeball"):
                                if ar.get("value") == candidate.get("value"):
                                    dup_in_batch = True; break
                        if dup_in_batch: continue
                        reward = candidate
                        break

                    # fallback if nothing found
                    if reward is None:
                        reward = {"type":"error","text":"No event rewards available."}

                    anime_granted, was_pity = _check_anime_coupon_pity(interaction.user.id)
                    winning_idx = _reward_to_wheel_idx(reward)
                    all_rewards.append(reward)

                    if not is_draw_10:
                        init_embed = _wheel_reel_embed(0, 0, pull_n, pulls)
                        if anim_msg is None:
                            anim_msg = await interaction.followup.send(embed=init_embed)
                        else:
                            await anim_msg.edit(embed=init_embed)
                        await _run_reel_animation(anim_msg, winning_idx, pull_n, pulls)

                    pull_results.append(_format_event_reward_detail(reward, anime_granted, was_pity))

                # Grant all rewards
                _grant_gacha_rewards(interaction.user.id, all_rewards)
            except Exception as e:
                try:
                    # refund event tickets if we spent them
                    if banner.get("currency") == "event_ticket":
                        try:
                            rc = sqlite3.connect("cosmetics.db"); rc_cursor = rc.cursor()
                            _ensure_event_ticket_table(rc_cursor)
                            rc_cursor.execute('INSERT OR IGNORE INTO "event ticket" (user_id,amount,daily_count,daily_date) VALUES (?,0,0,"")', (interaction.user.id,))
                            rc_cursor.execute('UPDATE "event ticket" SET amount = amount + ? WHERE user_id = ?', (pulls, interaction.user.id))
                            rc.commit(); rc.close()
                        except Exception:
                            pass
                except Exception:
                    pass
                # send an error message so user isn't left hanging
                try:
                    await interaction.followup.send(f"❌ An error occurred while processing the gacha: {e}")
                except Exception:
                    try:
                        await interaction.response.send_message(f"❌ An error occurred while processing the gacha: {e}")
                    except Exception:
                        pass
                return

            # Final result embed
            if pulls == 1:
                result_embed = discord.Embed(
                    title="🎡 Result",
                    description=f"✅ {spend_msg}\n\n{pull_results[0]}",
                    color=discord.Color.green(),
                )
            else:
                numbered = "\n\n".join(f"**Pull {i+1}**\n{r}" for i, r in enumerate(pull_results))
                result_embed = discord.Embed(
                    title=f"🎡 Results — {pulls} Pulls",
                    description=f"✅ {spend_msg}\n\n{numbered}",
                    color=discord.Color.green(),
                )
            await anim_msg.edit(embed=result_embed)

            try:
                if interaction.message:
                    await interaction.message.edit(embed=_build_gacha_embed(self.page, interaction.user.id), view=self)
            except Exception: pass
            return

        # ── All other gachas ───────────────────────────────────────────────
        ok, msg, _ = _spend_gacha_cost(interaction.user.id, banner, pulls)
        if not ok: return await interaction.response.send_message(msg, ephemeral=True)
        rewards = [_roll_gacha_reward(banner, interaction.user.id) for _ in range(pulls)]
        _grant_gacha_rewards(interaction.user.id, rewards)
        lines = []
        for r in rewards:
            if r.get("type") == "profile_banner":
                kind, name, is_new = grant_random_gacha_reward(str(interaction.user.id))
                lines.append(_format_reward_line(kind, name, is_new) if name else "❌ No items in pool.")
            else: lines.append(r.get("text","Unknown reward"))
        preview = "\n".join(lines[:20]); extra = f"\n... and {len(lines)-20} more" if len(lines)>20 else ""
        await interaction.response.send_message(f"✅ {msg}\n🎁 Rewards:\n{preview}{extra}")
        try:
            if interaction.message:
                await interaction.message.edit(embed=_build_gacha_embed(self.page, interaction.user.id), view=self)
        except Exception: pass

    @discord.ui.button(label="Draw 1",   style=discord.ButtonStyle.green,    row=0)
    async def draw_one(self, i, b):  await self._do_pull(i, 1)
    @discord.ui.button(label="Draw 10",  style=discord.ButtonStyle.blurple,  row=0)
    async def draw_ten(self, i, b):  await self._do_pull(i, 10)
    @discord.ui.button(label="Exchange", style=discord.ButtonStyle.gray,     row=0)
    async def exchange(self, i, b):  await i.response.send_modal(GachaExchangeModal(self))
    @discord.ui.button(label="⬅️",       style=discord.ButtonStyle.secondary, row=1)
    async def left(self, i, b):
        self.page = (self.page - 1) % len(GACHA_BANNERS)
        await i.response.edit_message(embed=_build_gacha_embed(self.page, self.user_id), view=self)
    @discord.ui.button(label="➡️",       style=discord.ButtonStyle.secondary, row=1)
    async def right(self, i, b):
        self.page = (self.page + 1) % len(GACHA_BANNERS)
        await i.response.edit_message(embed=_build_gacha_embed(self.page, self.user_id), view=self)

