@bot.command(name="giveticket", aliases=["gt"])
@commands.has_permissions(administrator=True)
async def give_event_ticket(ctx, member: discord.Member, amount: int = 1):
    if ctx.author.id not in owner_ids:
        return await ctx.reply("Only Bot Administrator can distribute tickets through this methods./n Try to duel for tickets")
    if amount <= 0:
        await ctx.reply("❌ Amount must be at least 1.", mention_author=False)
        return
    conn = sqlite3.connect("cosmetics.db")
    c = conn.cursor()
    _ensure_event_ticket_table(c)
    c.execute("""
        INSERT INTO "event ticket" (user_id, amount) VALUES (?, ?)
        ON CONFLICT(user_id) DO UPDATE SET amount = amount + excluded.amount
    """, (member.id, amount))
    conn.commit()
    c.execute('SELECT amount FROM "event ticket" WHERE user_id = ?', (member.id,))
    row = c.fetchone()
    new_total = row[0] if row else amount
    conn.close()
    await ctx.reply(
        f"✅ Gave **{amount} event ticket(s)** to {member.mention}.\n"
        f"🎫 Their new balance: **{new_total}**",
        mention_author=False
    )

@give_event_ticket.error
async def give_event_ticket_error(ctx, error):
    if isinstance(error, commands.MissingPermissions):
        await ctx.reply("❌ You need administrator permission to use this.", mention_author=False)
    elif isinstance(error, commands.MemberNotFound):
        await ctx.reply("❌ Member not found.", mention_author=False)
    elif isinstance(error, commands.MissingRequiredArgument):
        await ctx.reply("❌ Usage: `!giveticket @user <amount>`", mention_author=False)


