def _ensure_vote_tables(cursor):
    cursor.execute(
        """
        CREATE TABLE IF NOT EXISTS vote_progress (
            user_id INTEGER PRIMARY KEY,
            total_votes INTEGER DEFAULT 0,
            last_topgg_claim INTEGER DEFAULT 0,
            last_dbl_claim INTEGER DEFAULT 0
        )
        """
    )


def _get_vote_progress_row(user_id: int):
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        _ensure_vote_tables(c)
        c.execute(
            "INSERT OR IGNORE INTO vote_progress (user_id, total_votes, last_topgg_claim, last_dbl_claim) VALUES (?, 0, 0, 0)",
            (user_id,),
        )
        c.execute(
            "SELECT total_votes, last_topgg_claim, last_dbl_claim FROM vote_progress WHERE user_id = ?",
            (user_id,),
        )
        row = c.fetchone() or (0, 0, 0)
        conn.commit()
    total_votes = int(row[0] or 0)
    last_topgg_claim = _normalize_vote_ts(row[1])
    last_dbl_claim = _normalize_vote_ts(row[2])

    # Persist normalized timestamps so old/bad values stop breaking cooldown checks.
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        c.execute(
            "UPDATE vote_progress SET last_topgg_claim = ?, last_dbl_claim = ? WHERE user_id = ?",
            (last_topgg_claim, last_dbl_claim, user_id),
        )
        conn.commit()

    return total_votes, last_topgg_claim, last_dbl_claim
def post_server_count(guild_count):
    url = f"https://top.gg/api/bots/{VOTE_TOPGG_BOT_ID}/stats"
    headers = {
        "Authorization": VOTE_TOPGG_TOKEN,
        "Content-Type": "application/json"
    }
    data = {
        "server_count": guild_count
    }

    response = requests.post(url, json=data, headers=headers)
    
    if response.status_code == 200:
        print("Posted server count successfully")
    else:
        print(f"Failed: {response.status_code} | {response.text}")

def _normalize_vote_ts(value) -> int:
    """Normalize persisted claim timestamps to unix seconds."""
    try:
        ts = int(value or 0)
    except Exception:
        return 0
    if ts <= 0:
        return 0
    # Convert millisecond epoch (13 digits) to seconds.
    if ts > 10_000_000_000:
        ts //= 1000
    now = int(time.time())
    # If timestamp is unrealistically in the future, reset to 0.
    if ts > now + 300:
        return 0
    return ts


def _add_arcs(user_id: int, amount: int):
    if amount <= 0:
        return
    conn = connect_poke_db()
    ensure_player(conn, user_id)
    c = conn.cursor()
    c.execute("UPDATE poke SET coins = coins + ? WHERE player_id = ?", (int(amount), user_id))
    conn.commit()
    conn.close()


def _schedule_vote_claim_reminder(user_id: int, source_label: str):
    run_time = datetime.now(timezone.utc) + timedelta(hours=12)
    message = (
        f"Reminder: you claimed your {source_label} vote reward 12 hours ago. "
        "Don't forget to vote again!"
    )
    job_id = f"vote_reminder_{user_id}_{source_label.lower().replace(' ', '_').replace('.', '')}_{int(time.time())}"
    try:
        scheduler.add_job(
            run_async_reminder,
            trigger="date",
            run_date=run_time,
            args=[0, user_id, message, True],
            id=job_id,
            replace_existing=False,
        )
    except Exception:
        pass


def _grant_vote_random_reward(user_id: int):
    if random.random() < 0.5:
        amount = random.randint(30, 80)
        _add_arcs(user_id, amount)
        return [f"💰 Random reward: **{amount} ARCs**"]

    pokemon_pool = _get_all_pokemon_names()
    if not pokemon_pool:
        amount = random.randint(30, 80)
        _add_arcs(user_id, amount)
        return [f"💰 Random reward fallback: **{amount} ARCs**"]

    pokemon_name = random.choice(pokemon_pool)
    if random.random() > 0.03:
        cosmetic = random.choice(VOTE_COLOR_POOL)
    else:
        cosmetic = "shiny"
    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        _ensure_exchange_coupon_tables(c)
        if _has_pokemon_cosmetic(c, user_id, pokemon_name, cosmetic):
            _increment_coupon(c, user_id, shiny=False, amount=1)
            conn.commit()
            return [f"🎟️ Random reward: duplicate **{pokemon_name.title()} [{cosmetic}]**, granted **1 exchange coupon**"]
        _append_pokemon_cosmetic(c, user_id, pokemon_name, cosmetic)
        conn.commit()
    emoji = COSMETIC_EMOJIS.get(cosmetic, "")
    return [f"🎨 Random reward: **{pokemon_name.title()} [{cosmetic}]** {emoji}".strip()]


