async def _check_topgg_vote(user_id: int):
    url = f"https://top.gg/api/bots/{VOTE_TOPGG_BOT_ID}/check?userId={user_id}"
    headers = {"Authorization": VOTE_TOPGG_TOKEN}
    timeout = aiohttp.ClientTimeout(total=10)
    async with aiohttp.ClientSession(timeout=timeout) as session:
        async with session.get(url, headers=headers) as resp:
            if resp.status != 200:
                text = await resp.text()
                return False, f"Top.gg API error ({resp.status}): {text[:120]}"
            data = await resp.json(content_type=None)
    voted = data.get("voted")
    return str(voted).lower() in {"1", "true", "yes"}, None


async def _check_dbl_vote(user_id: int):
    # Discord Bot List check endpoint is the upvotes list endpoint.
    url = f"https://discordbotlist.com/api/v1/bots/{VOTE_DBL_BOT_ID}/upvotes"
    headers = {"Authorization": VOTE_DBL_TOKEN}
    timeout = aiohttp.ClientTimeout(total=10)
    async with aiohttp.ClientSession(timeout=timeout) as session:
        async with session.get(url, headers=headers) as resp:
            if resp.status != 200:
                text = await resp.text()
                return False, f"Discord Bot List API error ({resp.status}): {text[:120]}"
            data = await resp.json(content_type=None)
    votes = data.get("upvotes", [])
    uid = str(user_id)
    voted = any(str(v.get("user_id")) == uid for v in votes if isinstance(v, dict))
    return voted, None


def _format_time_left(seconds_left: int):
    seconds_left = max(0, int(seconds_left))
    h = seconds_left // 3600
    m = (seconds_left % 3600) // 60
    return f"{h}h {m}m"


async def _claim_vote_reward(user_id: int, source: str):
    total_votes, last_topgg_claim, last_dbl_claim = _get_vote_progress_row(user_id)
    now = int(time.time())

    if source == "topgg":
        voted, api_err = await _check_topgg_vote(user_id)
        last_claim = last_topgg_claim
        source_label = "Top.gg"
    else:
        voted, api_err = await _check_dbl_vote(user_id)
        last_claim = last_dbl_claim
        source_label = "Discord Bot List"

    if api_err:
        return False, [f"❌ {api_err}"], total_votes
    if not voted:
        return False, [f"❌ No recent vote detected on {source_label}. Please vote first using the link button."], total_votes

    if last_claim > 0 and (now - last_claim) < VOTE_COOLDOWN_SECONDS:
        remain = VOTE_COOLDOWN_SECONDS - (now - last_claim)
        return False, [f"⏳ You already claimed this source recently. Try again in **{_format_time_left(remain)}**."], total_votes

    reward_lines = []
    base_bonus = 30
    _add_arcs(user_id, base_bonus)
    reward_lines.append(f"🎉 Vote bonus: **{base_bonus} ARCs**")
    reward_lines.extend(_grant_vote_random_reward(user_id))

    with sqlite3.connect("cosmetics.db") as conn:
        c = conn.cursor()
        _ensure_vote_tables(c)
        c.execute(
            "INSERT OR IGNORE INTO vote_progress (user_id, total_votes, last_topgg_claim, last_dbl_claim) VALUES (?, 0, 0, 0)",
            (user_id,),
        )
        if source == "topgg":
            c.execute(
                "UPDATE vote_progress SET total_votes = total_votes + 1, last_topgg_claim = ? WHERE user_id = ?",
                (now, user_id),
            )
        else:
            c.execute(
                "UPDATE vote_progress SET total_votes = total_votes + 1, last_dbl_claim = ? WHERE user_id = ?",
                (now, user_id),
            )
        c.execute("SELECT total_votes FROM vote_progress WHERE user_id = ?", (user_id,))
        row = c.fetchone()
        new_total = int(row[0] if row and row[0] is not None else total_votes + 1)
        conn.commit()

    reward_lines.extend(_grant_vote_breakpoint_rewards(user_id, new_total))
    _schedule_vote_claim_reminder(user_id, source_label)
    reward_lines.append(f"📈 Total vote claims: **{new_total}**")
    return True, reward_lines, new_total


