ALLOWED_BACKGROUNDS = {"arena", "tundra", "volcano", "grassland", "space"}

@bot.command(name="battle_background")
async def battle_background(ctx, name: str):
    name = name.lower()

    if name not in ALLOWED_BACKGROUNDS:
        allowed = ", ".join(sorted(ALLOWED_BACKGROUNDS))
        return await ctx.send(
            f"❌ Invalid background.\nAllowed backgrounds: **{allowed}**"
        )

    folder = "battle_backgrounds"
    os.makedirs(folder, exist_ok=True)

    filepath = os.path.join(folder, f"{ctx.author.id}_background.txt")

    with open(filepath, "w") as f:
        f.write(name)

    await ctx.send(f"✅ Battle background set to **{name.capitalize()}**")

def get_battle_background(player_id: int):
    folder = "battle_backgrounds"
    filepath = os.path.join(folder, f"{player_id}_background.txt")

    if not os.path.exists(filepath):
        return "arena"

    with open(filepath, "r") as f:
        return f.read().strip()


def get_equipped_battle_cosmetics(user_id: int):
    equipped = {
        "pokeball": None,
        "background": None,
        "color": None,
        "status": None,
        "graphics": None,
    }

    try:
        with sqlite3.connect("cosmetics.db") as conn:
            c = conn.cursor()
            c.execute(
                """
                SELECT category, cosmetic
                FROM equipped
                WHERE user_id = ? AND pokemon_name IS NULL
                """,
                (user_id,),
            )
            for category, cosmetic in c.fetchall():
                cat = str(category).strip().lower()
                value = str(cosmetic).strip().lower() if cosmetic else None
                if not value:
                    continue
                if cat == "pokeball":
                    equipped["pokeball"] = value
                elif cat == "background":
                    equipped["background"] = value
                elif cat == "embed color":
                    equipped["color"] = value
                elif cat == "status":
                    equipped["status"] = value
                elif cat == "graphics":
                    equipped["graphics"] = value
    except Exception:
        pass

    return equipped


def _get_status_cosmetic_for_slot(slot: str, data: dict):
    value = data.get(f"{slot}_status_cosmetic")
    value = str(value).strip().lower() if value else ""
    return value if value else "ninja"


def _get_status_emoji_for_slot(slot: str, data: dict):
    cosmetic = _get_status_cosmetic_for_slot(slot, data)
    return COSMETIC_EMOJIS.get(cosmetic, "🥷")


def _get_status_emoji_for_user(user_id: int):
    try:
        equipped = get_equipped_battle_cosmetics(int(user_id))
        cosmetic = (equipped.get("status") or "").strip().lower()
        if not cosmetic:
            cosmetic = "ninja"
        return COSMETIC_EMOJIS.get(cosmetic, "🥷")
    except Exception:
        return "🥷"


def get_equipped_pokemon_cosmetic(user_id: int, pokemon_name: str):
    if not pokemon_name:
        return None
    try:
        with sqlite3.connect("cosmetics.db") as conn:
            c = conn.cursor()
            c.execute(
                """
                SELECT cosmetic
                FROM equipped
                WHERE user_id = ? AND category = 'pokemon' AND lower(pokemon_name) = ?
                ORDER BY rowid DESC
                LIMIT 1
                """,
                (user_id, str(pokemon_name).strip().lower()),
            )
            row = c.fetchone()
            if row and row[0]:
                return str(row[0]).strip().lower()
    except Exception:
        pass
    return None

