@bot.tree.command(name="battle_team", description="Manage your battle teams")
@app_commands.choices(
    type=[
        app_commands.Choice(name="prio", value="prio"),
        app_commands.Choice(name="non-prio", value="non-prio"),
        app_commands.Choice(name="simplified", value="simplified"),
    ],
    rarity=[
        app_commands.Choice(name="rare", value="rare"),
        app_commands.Choice(name="common", value="common")
    ],
)
async def battle_team(
    interaction: discord.Interaction,
    type: app_commands.Choice[str],
    rarity: app_commands.Choice[str] = None
):
    user_id = interaction.user.id
    rarity_value = rarity.value if rarity else "rare"
    if type.value == "simplified":
        view = SimplifiedTeamEditorView(interaction.user.id, rarity_value)
        embed = view.make_embed()
        await interaction.response.send_message(embed=embed, view=view)
        msg = await interaction.original_response()
        view.message = msg
        return
    suffix = "_common" if rarity_value == "common" else ""
    path = f"battle_teams/{user_id}_{type.value}{suffix}.json"

    if not os.path.exists(path):
        await interaction.response.send_message(
            "You don't have any teams yet. Let's create one!\n"
            "Send **3 Pokémon names**, one per message. Type `done` when finished."
        )
        await create_initial_team(interaction, path)
        return

    with open(path) as f:
        data = json.load(f)

    if not data.get("teams"):
        await interaction.response.send_message(
            "No teams found. Let's create one!"
        )
        await create_initial_team(interaction, path)
        return

    view = TeamView(interaction.user.id, path)
    embed = view.make_embed()
    await interaction.response.send_message(embed=embed, view=view)
    msg = await interaction.original_response()
    view.message = msg


