class SimplifiedModifyFieldView(discord.ui.View):
    def __init__(self, parent: SimplifiedTeamEditorView, slot: int):
        super().__init__(timeout=180)
        self.parent = parent
        self.slot = slot

    def _get_members(self):
        self.parent._reload()
        row = self.parent.teams[self.parent.index]
        members = row.get("members", [])
        while len(members) < 6:
            members.append({
                "name": "",
                "nature": "hardy",
                "moves": [],
                "ability": "ball fetch",
                "item": None,
                "ivs": [31, 31, 31, 31, 31, 31],
                "evs": _simplified_default_evs(),
            })
        return row["id"], members

    async def _persist(self, members):
        row_id = self.parent.teams[self.parent.index]["id"]
        update_simplified_team(row_id, members)
        self.parent._reload()
        await self.parent._refresh_message()

    @discord.ui.button(label="Pokemon", style=discord.ButtonStyle.secondary)
    async def pokemon(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.parent.user_id:
            return await interaction.response.send_message("Not your panel.", ephemeral=True)
        await interaction.response.send_message(f"Type new pokemon name for slot {self.slot}:", ephemeral=True)
        try:
            msg = await _wait_owner_message(interaction.client, self.parent.user_id, interaction.channel, timeout=60)
        except asyncio.TimeoutError:
            return await interaction.followup.send("⏰ Timed out.", ephemeral=True)
        pokemon = msg.content.strip().lower()
        if not get_pokemon_info(pokemon):
            return await interaction.followup.send("❌ Invalid pokemon.", ephemeral=True)
        if _is_simplified_banned_pokemon(pokemon):
            return await interaction.followup.send("❌ Mega/primal are not allowed in simplified.", ephemeral=True)
        _, members = self._get_members()
        slot_idx = self.slot - 1
        members[slot_idx]["name"] = pokemon
        members[slot_idx]["item"] = None if _is_crowned_no_item_pokemon(pokemon) else members[slot_idx].get("item")
        if not members[slot_idx].get("moves"):
            members[slot_idx]["moves"] = get_default_moves(pokemon)[:4]
        await self._persist(members)
        await interaction.followup.send("✅ Pokémon updated.", ephemeral=True)

    @discord.ui.button(label="Mint", style=discord.ButtonStyle.secondary)
    async def mint(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.parent.user_id:
            return await interaction.response.send_message("Not your panel.", ephemeral=True)
        await interaction.response.send_message(f"Type new mint for slot {self.slot}:", ephemeral=True)
        try:
            msg = await _wait_owner_message(interaction.client, self.parent.user_id, interaction.channel, timeout=60)
        except asyncio.TimeoutError:
            return await interaction.followup.send("⏰ Timed out.", ephemeral=True)
        mint = msg.content.strip().lower()
        if mint not in VALID_NATURES:
            return await interaction.followup.send("❌ Invalid mint.", ephemeral=True)
        _, members = self._get_members()
        members[self.slot - 1]["nature"] = mint
        await self._persist(members)
        await interaction.followup.send("✅ Mint updated.", ephemeral=True)

    @discord.ui.button(label="Moves", style=discord.ButtonStyle.secondary)
    async def moves(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.parent.user_id:
            return await interaction.response.send_message("Not your panel.", ephemeral=True)
        _, members = self._get_members()
        poke = str(members[self.slot - 1].get("name", "")).strip().lower()
        if not poke:
            return await interaction.response.send_message("Set pokemon first.", ephemeral=True)
        moves = get_pokemon_moves(poke) or get_default_moves(poke)
        moves = [m for m in moves if m][:60]
        if len(moves) < 4:
            return await interaction.response.send_message("Not enough moves available.", ephemeral=True)
        view = _AwaitMovesView(self.parent.user_id, moves)
        await interaction.response.send_message("Select 4 moves:", view=view, ephemeral=True)
        try:
            await asyncio.wait_for(view.done.wait(), timeout=180)
        except asyncio.TimeoutError:
            return await interaction.followup.send("⏰ Timed out.", ephemeral=True)
        members[self.slot - 1]["moves"] = view.selected
        await self._persist(members)
        await interaction.followup.send("✅ Moves updated.", ephemeral=True)

    @discord.ui.button(label="Ability", style=discord.ButtonStyle.secondary)
    async def ability(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.parent.user_id:
            return await interaction.response.send_message("Not your panel.", ephemeral=True)
        _, members = self._get_members()
        poke = str(members[self.slot - 1].get("name", "")).strip().lower()
        if not poke:
            return await interaction.response.send_message("Set pokemon first.", ephemeral=True)
        abilities = []
        try:
            with open(f"pokemon_data/{poke}.json", "r", encoding="utf-8") as f:
                pdata = json.load(f)
                abilities = [str(a).strip().lower() for a in (pdata.get("abilities") or []) if str(a).strip()]
        except Exception:
            abilities = []
        if not abilities:
            abilities = ["ball fetch"]
        view = _AwaitSingleChoiceView(self.parent.user_id, abilities, "Select ability")
        await interaction.response.send_message("Select ability:", view=view, ephemeral=True)
        try:
            await asyncio.wait_for(view.done.wait(), timeout=180)
        except asyncio.TimeoutError:
            return await interaction.followup.send("⏰ Timed out.", ephemeral=True)
        members[self.slot - 1]["ability"] = (view.selected or "ball fetch").strip().lower()
        await self._persist(members)
        await interaction.followup.send("✅ Ability updated.", ephemeral=True)

    @discord.ui.button(label="Battle Item", style=discord.ButtonStyle.secondary)
    async def item(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.parent.user_id:
            return await interaction.response.send_message("Not your panel.", ephemeral=True)
        _, members = self._get_members()
        poke = str(members[self.slot - 1].get("name", "")).strip().lower()
        if not poke:
            return await interaction.response.send_message("Set pokemon first.", ephemeral=True)
        item_choices = sorted(_available_battle_items(), key=str.lower)
        view = _AwaitSingleChoiceView(
            self.parent.user_id,
            item_choices,
            "Select held item",
            select_options=_battle_item_select_options(item_choices)
        )
        await interaction.response.send_message("Select held item:", view=view, ephemeral=True)
        try:
            await asyncio.wait_for(view.done.wait(), timeout=180)
        except asyncio.TimeoutError:
            return await interaction.followup.send("⏰ Timed out.", ephemeral=True)
        selected = (view.selected or "none").strip().lower()
        if selected == "none" or _is_crowned_no_item_pokemon(poke):
            selected = None
        members[self.slot - 1]["item"] = selected
        await self._persist(members)
        await interaction.followup.send("✅ Item updated.", ephemeral=True)


def get_mint_modifiers(mint_name: str):
    mint_name = mint_name.lower()
    # default multipliers
    modifiers = {"atk": 1, "def": 1, "spatk": 1, "spdef": 1, "spd": 1}

    nature_effects = {
        "adamant":   ("atk", "spatk"),
        "brave":     ("atk", "spd"),
        "lonely":    ("atk", "def"),
        "naughty":   ("atk", "spdef"),
        "jolly":     ("spd", "spatk"),
        "timid":     ("spd", "atk"),
        "naive":     ("spd", "spdef"),
        "hasty":     ("spd", "def"),
        "bold":      ("def", "atk"),
        "impish":    ("def", "spatk"),
        "lax":       ("def", "spdef"),
        "relaxed":   ("def", "spd"),
        "modest":    ("spatk", "atk"),
        "mild":      ("spatk", "def"),
        "rash":      ("spatk", "spdef"),
        "quiet":     ("spatk", "spd"),
        "calm":      ("spdef", "atk"),
        "gentle":    ("spdef", "def"),
        "careful":   ("spdef", "spatk"),
        "sassy":     ("spdef", "spd"),
        "hardy":     (None, None),  # neutral
        "docile":    (None, None),
        "serious":   (None, None),
        "bashful":   (None, None),
        "quirky":    (None, None),
    }

    if mint_name in nature_effects:
        inc, dec = nature_effects[mint_name]
        if inc:
            modifiers[inc] = 1.1
        if dec:
            modifiers[dec] = 0.9

    return modifiers

class LogButtonViewBattle(discord.ui.View):
    def __init__(self, server_id, embed, message_link, channel, gym_win = False, winner_user = None):
        super().__init__()
        self.clicked = False  # Track if any button is clicked
        self.server_id = server_id
        self.message_link = message_link
        self.embed = embed
        self.channel = channel
        self.gym_win = gym_win
        self.winner = winner_user

    async def disable_all_buttons(self, interaction: discord.Interaction):
        """Disables all buttons after one is clicked."""
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True  # Disable each button

        await interaction.message.edit(view=self)  # Update the message with disabled buttons

    @discord.ui.button(label="Gym Log", style=discord.ButtonStyle.primary)
    async def gym_log(self, interaction: discord.Interaction, button: discord.ui.Button):
        data = load_data(self.server_id)
        if not data:
            await interaction.response.send_message("No gym log channel found, use `!gym_log #channel` to set up", ephemeral=True)
            return
        channel_id = data.get('gym_log')
        if channel_id:
            message_link = self.message_link
            target_channel = (bot.get_channel(channel_id) or await bot.fetch_channel(channel_id))
            await target_channel.send(f'<a:crown:1355889489490219026> Gym: {self.channel.name}\n{self.channel.mention}')
            await target_channel.send(embed=self.embed)
            await interaction.response.send_message("🏋️ Gym Log button clicked!", ephemeral=True)
            await self.disable_all_buttons(interaction)
            prefix = prefixes.get(self.server_id)
            if not prefix:
                prefix = '!'
            if self.gym_win == True:
                await interaction.followup.send(f"Congratulations on successfully defending the gym! +1 win added!\nCheck {str(prefix)}pf or /profile <a:crown:1355889489490219026>")
            else:
                await interaction.followup.send(f"Make sure to use `/award_badge`!\nCheck {str(prefix)}pf or /profile <a:crown:1355889489490219026>")
            if self.winner:
                conn = get_db_connection()
                cursor = conn.cursor()
                gym_leaders_table = f"gym_leaders_{interaction.guild.id}"
                # Increment the 'wins' column for the leader with the given display_name
                cursor.execute(f"""
                    UPDATE {gym_leaders_table}
                    SET wins = wins + 1
                    WHERE leader_id = ?;
                """, (self.winner.id,))
                conn.commit()
                conn.close()
        else:
            await interaction.response.send_message("No gym log channel found, use `!gym_log #channel` to set up", ephemeral=True)

