import difflib

def ensure_gw_config_folder():
    os.makedirs("gw_config", exist_ok=True)
def create_server_database(guild_id):
    ensure_gw_config_folder()
    db_path = f"gw_config/{guild_id}.db"
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    # Create table if not exists
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS role_entries (
            role_id INTEGER PRIMARY KEY,
            entry_count INTEGER DEFAULT 1,
            staff INTEGER DEFAULT 0
        )
    """)
    cursor.execute("PRAGMA table_info(role_entries)")
    existing_columns = [row[1] for row in cursor.fetchall()]
    if 'staff' not in existing_columns:
        cursor.execute("ALTER TABLE role_entries ADD COLUMN staff INTEGER DEFAULT 0")
    conn.commit()
    conn.close()

