class RoleSearchModal(discord.ui.Modal, title="Search for a Role"):
    def __init__(self, roles, action, message):
        super().__init__()
        self.roles = roles  # Store the actual Role objects
        self.role_names = [role.name for role in roles]
        self.action = action
        self.message = message
        self.role_input = discord.ui.TextInput(label="Enter role name (partial allowed)")
        self.add_item(self.role_input)

    async def on_submit(self, interaction: discord.Interaction):
        input_text = self.role_input.value
        matches = difflib.get_close_matches(input_text, self.role_names, n=5, cutoff=0.5)

        if not matches:
            await interaction.response.send_message("❌ No matching roles found.", ephemeral=True)
            return

        # Get the actual discord.Role objects that match
        matched_roles = [role for role in self.roles if role.name in matches]

        view = RoleSelectView(matched_roles, self.action, self.message)
        await interaction.response.send_message("Select a role from below:", view=view, ephemeral=True)
class RoleSelect(discord.ui.Select):
    def __init__(self, roles: list[discord.Role], action, message):
        options = [
            discord.SelectOption(label=role.name, value=str(role.id))
            for role in roles]

        super().__init__(
            placeholder="Choose a role...",
            min_values=1,
            max_values=1,  # Change this if you want multiple selections
            options=options
        )
        self.action = action
        self.message = message

    async def callback(self, interaction: discord.Interaction):
        selected_role_id = int(self.values[0])
        role = interaction.guild.get_role(selected_role_id)
        if self.action == 'entries':
            modal = ExtraEntry(role)
            await interaction.response.send_modal(modal)
        elif self.action == 'block':
            guild_id = interaction.guild.id
            create_server_database(interaction.guild.id)
            db_path = f"gw_config/{guild_id}.db"
            conn = sqlite3.connect(db_path)
            cursor = conn.cursor()
            amount = 0
            role_id = role.id

            cursor.execute("""
            INSERT INTO role_entries (role_id, entry_count)
            VALUES (?, ?)
            ON CONFLICT(role_id)
            DO UPDATE SET entry_count = ?
            """, (role_id, amount, amount))

            conn.commit()
            conn.close()
            embed = gwconfigeditor(interaction)
            await self.message.edit(embed = embed)
            await interaction.response.send_message(f'{role.name} has been blocked from giveaways', ephemeral=True)
        elif self.action == 'staff':
            guild_id = interaction.guild.id
            create_server_database(interaction.guild.id)
            db_path = f"gw_config/{guild_id}.db"
            conn = sqlite3.connect(db_path)
            cursor = conn.cursor()
            amount = 1
            role_id = role.id

            cursor.execute("""
            INSERT INTO role_entries (role_id, entry_count, staff)
            VALUES (?, 1, ?)
            ON CONFLICT(role_id)
            DO UPDATE SET staff = ?
            """, (role_id, amount, amount))

            conn.commit()
            conn.close()
            try:
                embed = gwconfigeditor(interaction)
                await self.message.edit(embed = embed)
            except Exception as e:
                print(e)
            await interaction.response.send_message(f'{role.name} has been added as staff role', ephemeral=True)
        elif self.action == 'remove':
            guild_id = interaction.guild.id
            create_server_database(guild_id)
            db_path = f"gw_config/{guild_id}.db"
            conn = sqlite3.connect(db_path)
            cursor = conn.cursor()

            cursor.execute("DELETE FROM role_entries WHERE role_id = ?", (role.id,))
            conn.commit()
            conn.close()
            embed = gwconfigeditor(interaction)
            await self.message.edit(embed = embed)
            await interaction.response.send_message(f'{role.name} has been removed from giveaway role settings.', ephemeral=True)

def gwconfigeditor(interaction):
    roles = [role for role in interaction.guild.roles if role.name != "@everyone"]
    role_names = [role.name for role in roles]
    guild = interaction.guild
    create_server_database(guild.id)
    db_path = f"gw_config/{guild.id}.db"
    
    # Connect and fetch roles
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()
    cursor.execute("SELECT role_id, entry_count, staff FROM role_entries")
    rows = cursor.fetchall()
    conn.close()

    # Separate into two lists
    non_zero_roles = []
    zero_roles = []
    manage_roles = []

    for role_id, count, staff in rows:
        if count > 1:
            non_zero_roles.append((role_id, count, staff))
        elif count == 0:
            zero_roles.append((role_id, count, staff))
        else:
            pass
        if staff>0:
            manage_roles.append((role_id, count, staff))

    # Format output
    extra_text = ""
    for role_id, count, staff in non_zero_roles:
        role = guild.get_role(role_id)
        name = role.mention if role else f"<@&{role_id}> (deleted)"
        extra_text += f"{name}: {count}\n"

    zero_text = ""
    for role_id, count, staff in zero_roles:
        role = guild.get_role(role_id)
        name = role.mention if role else f"<@&{role_id}> (deleted)"
        zero_text += f"{name}: {count}\n"

    manage_text = ""
    for role_id, count, staff in manage_roles:
        role = guild.get_role(role_id)
        name = role.mention if role else f"<@&{role_id}> (deleted)"
        manage_text += f"{name}: {count}\n"
    embed = discord.Embed(title = 'Giveaway Configurations', description='Click on buttons for configurations', color = discord.Color.random())
    embed.add_field(name = '🎯 Extra Entries Roles', value = extra_text)
    embed.add_field(name = '🚫 No Entries Roles', value = zero_text)
    embed.add_field(name = '<a:gw_host:1380597876379484310> Manager Roles', value = manage_text)
    return embed

