class ExtraEntry(Modal, title = 'Input number of extra entries'):
    def __init__(self, role):
        super().__init__()
        self.role = role
        self.entries = discord.ui.TextInput(label=f"Number of entries for {role}")
        self.add_item(self.entries)
    async def on_submit(self, interaction: discord.Interaction):
        if isinstance(int(self.entries.value), int):
            guild_id = interaction.guild.id
            create_server_database(interaction.guild.id)
            db_path = f"gw_config/{guild_id}.db"
            conn = sqlite3.connect(db_path)
            cursor = conn.cursor()
            amount = self.entries.value
            role_id = self.role.id

            cursor.execute("""
            INSERT INTO role_entries (role_id, entry_count)
            VALUES (?, ?)
            ON CONFLICT(role_id)
            DO UPDATE SET entry_count = entry_count + ?
            """, (role_id, amount, amount))

            conn.commit()
            conn.close()
            await interaction.response.send_message(f'{self.role.name} has been added with {self.entries.value} entries', ephemeral=True)
        else:
            await interaction.response.send_message(f'Please input an integer', ephemeral = True)

class ConfigGroup(app_commands.Group):
    def __init__(self):
        super().__init__(name="config", description="Set configurations for gw, invite and tickets")
    
    @app_commands.command(name="duel", description="configuration for server duels")
    @app_commands.checks.has_permissions(administrator=True)
    async def duel_config(self, interaction: discord.Interaction, view: bool = False):
        """Configure duel system and roles"""

        # Load existing config if exists
        config_path = os.path.join("duel_log_config", f"{interaction.guild.id}_config.json")
        if os.path.exists(config_path):
            with open(config_path, "r", encoding="utf-8") as f:
                config = json.load(f)
        else:
            config = {"system": "relative", "roles": {}}

        if view:
            system = config.get("system", "Not set")
            roles = config.get("roles", {})

            # Build roles string
            if roles:
                role_lines = []
                # Sort by points
                for points in sorted(roles, key=lambda x: int(x)):
                    role_id = int(roles[points])
                    role = interaction.guild.get_role(role_id)
                    if role:
                        role_lines.append(f"**{points} points:** {role.mention}")
                    else:
                        role_lines.append(f"**{points} points:** Role not found")
                roles_text = "\n".join(role_lines)
            else:
                roles_text = "No roles configured"

            embed = discord.Embed(
                title=f"🏆 Duel Configuration for {interaction.guild.name}",
                color=discord.Color.red()
            )
            embed.add_field(name="System", value=system, inline=False)
            embed.add_field(name="Roles / Point Thresholds", value=roles_text, inline=False)
            await interaction.response.send_message(embed=embed)
            return

        # Ask for system type
        system_options = ["flat (100 win, 100 lose)", "flat (100 win, 50 lose)", "diminishing", "relative"]
        options_str = "\n".join(f"{i+1}. {s}" for i, s in enumerate(system_options))
        await interaction.response.send_message(
            f"Current duel system: **{config['system']}**\n"
            f"Select a new system by typing the number:\n{options_str}\nType 0 to keep current."
        )

        def check(m):
            return m.author.id == interaction.user.id and m.channel == interaction.channel

        try:
            msg = await interaction.client.wait_for("message", check=check, timeout=120)
        except asyncio.TimeoutError:
            return await interaction.followup.send("⏰ Timeout. Duel configuration cancelled.")

        choice = msg.content.strip()
        if choice.isdigit():
            choice = int(choice)
            if 0 < choice <= len(system_options):
                config["system"] = system_options[choice-1]

        # Ask for roles configuration
        war_prem = None
        if os.path.exists('war_premium.txt'):
            with open('war_premium.txt', 'r') as f:
                lines = f.readlines()
            war_prem = any(str(interaction.guild.id) == line.strip() for line in lines)
        if war_prem:
            await interaction.followup.send(
                "Now configure roles for point thresholds.\n"
                "Send messages in the format:\n`<points> <@role>`\n"
                "For example:\n`100 @Novice`\n`200 @Intermediate`\nType `done` when finished."
            )
        else:
            os.makedirs("duel_log_config", exist_ok=True)
            with open(config_path, "w", encoding="utf-8") as f:
                json.dump(config, f, indent=4)
            await interaction.followup.send("✅ Duel system configuration saved successfully!")
            await interaction.followup.send('Get Goldi War Premium to auto assign roles based on points (check support server in /bot_info for more info)')
            return 

        while True:
            try:
                msg = await interaction.client.wait_for("message", check=check, timeout=300)
            except asyncio.TimeoutError:
                return await interaction.followup.send("⏰ Timeout. Duel role configuration cancelled.")

            content = msg.content.strip()
            if content.lower() == "done":
                break

            parts = content.split()
            if len(parts) != 2:
                await interaction.followup.send("Invalid format. Use `<points> <@role>`.")
                continue

            points_str, role_mention = parts
            if not points_str.isdigit():
                await interaction.followup.send("Points must be a number.")
                continue

            points = int(points_str)
            role_id = int(role_mention.strip("<@&>"))
            config["roles"][str(points)] = str(role_id)
            await interaction.followup.send(f"✅ Added role {role_mention} for {points} points.")

        # Save config
        os.makedirs("duel_log_config", exist_ok=True)
        with open(config_path, "w", encoding="utf-8") as f:
            json.dump(config, f, indent=4)

        await interaction.followup.send("✅ Duel system and roles configuration saved successfully!")


