def parse_time_string(time_str):
    time_str = time_str.lower().replace(",", "").strip()
    
    # Regex to find number + unit combinations (like 1m, 2s, 3 hours, etc.)
    matches = re.findall(r'(\d+)\s*(s|sec|secs|second|seconds|m|min|mins|minute|minutes|h|hr|hrs|hour|hours|d|day|days)', time_str)

    if not matches:
        return None  # Invalid format

    total_seconds = 0
    unit_multipliers = {
        's': 1, 'sec': 1, 'secs': 1, 'second': 1, 'seconds': 1,
        'm': 60, 'min': 60, 'mins': 60, 'minute': 60, 'minutes': 60,
        'h': 3600, 'hr': 3600, 'hrs': 3600, 'hour': 3600, 'hours': 3600,
        'd': 86400, 'day': 86400, 'days': 86400
    }

    for value, unit in matches:
        total_seconds += int(value) * unit_multipliers[unit]

    return total_seconds

import re

def parse_money_string(money_str):
    money_str = money_str.lower().replace(",", "").strip()

    unit_multipliers = {
        'k': 1_000,
        'thousand': 1_000,
        'm': 1_000_000,
        'mil': 1_000_000,
        'million': 1_000_000,
        'b': 1_000_000_000,
        'bil': 1_000_000_000,
        'billion': 1_000_000_000,
        'sh': 38_000,
        'shiny': 38_000,
        'shinies': 38_000,
        'rare sh': 5_000_000_000,
        'rare shiny': 5_000_000_000,
        'rare shinies': 5_000_000_000
    }

    # Pattern: decimal or int followed by a known unit
    pattern = r'(\d+(?:\.\d+)?)(k|thousand|m|mil|million|b|bil|billion|sh|shiny|shinies)'
    matches = re.findall(pattern, money_str)

    total_money = 0

    if matches:
        for number, unit in matches:
            multiplier = unit_multipliers[unit.lower()]
            total_money += float(number) * multiplier

        # Check for leftover digits after removing matched parts
        cleaned = re.sub(pattern, '', money_str)
        if cleaned and cleaned.isdigit():
            total_money += int(cleaned)

    else:
        # If no unit matches, check if the string is a plain valid number
        if money_str.isdigit():
            return int(money_str)
        else:
            return 0

    return int(total_money)

class GwClose(View):
    def __init__(self, channel, users, prize, host):
        super().__init__(timeout=None)
        self.channel = channel
        self.users = users
        self.prize = prize
        self.host = host
    @discord.ui.button(label="Close Ticket", style=discord.ButtonStyle.danger, custom_id = f"gw_close")
    async def close(self, interaction: discord.Interaction, button: discord.ui.Button):
        data = load_data2(interaction.guild.id)
        if data:
            log_channel_id = data.get('giveaway')
        else:
            log_channel_id = None
        
        if log_channel_id:
            channel_id = self.channel.id
            target_channel = bot.get_channel(channel_id) or await bot.fetch_channel(channel_id)
            log_channel = bot.get_channel(log_channel_id) or await bot.fetch_channel(log_channel_id)

            # Send archive start message first
            archive_msg = await log_channel.send(f"Archiving messages from ticket: {self.channel.name}")

            # Create unique thread under that message
            thread = await create_unique_thread(log_channel, base_name=f"archive-{self.channel.name}", message=archive_msg)

            # Get all messages, oldest first
            messages = [msg async for msg in target_channel.history(limit=None, oldest_first=True)]

            # Skip the first two messages
            for msg in messages[2:]:
                timestamp = msg.created_at.strftime("%Y-%m-%d %H:%M:%S")
                content = f"**{msg.author.display_name}** ({timestamp}) said:\n{msg.content}"
                await thread.send(content)
        await self.channel.delete()
        remove_persistent_gw_view(self.channel.id)

    @discord.ui.button(label="Reroll Winner", style=discord.ButtonStyle.danger, custom_id=f"gw_reroll")
    async def reroll(self, interaction: discord.Interaction, button: discord.ui.Button):
        try:
            new_winner = random.choice(self.users)
            self.users = [user for user in self.users if user != new_winner]
            prize = self.prize
            host = self.host
            channel_name = f"{prize}-{host.name}-{new_winner}-1"
            category = discord.utils.get(interaction.guild.categories, name="giveaway")
            existing_channel = discord.utils.get(category.channels, name=channel_name)
            match = re.search(r"-(\d+)$", channel_name)
            if match:
                channel_id = int(match.group(1)) + 1
                channel_name = re.sub(r"-(\d+)$", f"-{channel_id}", channel_name)
            else:
                channel_name = f"{channel_name}-1"
            guild = interaction.guild
            overwrites = {
                guild.default_role: discord.PermissionOverwrite(read_messages=False), # @everyone cannot see
                guild.me: discord.PermissionOverwrite(read_messages=True, send_messages=True), # Bot can always see
                new_winner: discord.PermissionOverwrite(read_messages=True, send_messages=True), # Winner can see and send
                host: discord.PermissionOverwrite(read_messages=True, send_messages=True) # Host can see and send
            }
            create_server_database(guild.id)
            db_path = f"gw_config/{guild.id}.db"
            conn = sqlite3.connect(db_path)
            cursor = conn.cursor()
            cursor.execute("SELECT role_id, entry_count, staff FROM role_entries")
            rows = cursor.fetchall()
            conn.close()
            staff_roles = []
            for role_id, count, staff in rows:
                if staff > 0:
                    role_obj = interaction.guild.get_role(role_id)
                    if role_obj:
                        staff_roles.append(role_obj)

            for role in staff_roles:
                overwrites[role] = discord.PermissionOverwrite(
                    read_messages=True,
                    send_messages=True
                )
            new_channel = await interaction.guild.create_text_channel(channel_name, category=category, overwrites=overwrites)
            view = GwClose(new_channel, self.users, self.prize, self.host)
            await new_channel.send(f"<a:giveaway:1380539377167634542> Congratulations {new_winner.mention}! You won the giveaway ({prize})!\nYou can claim your prize here")
            msg = await new_channel.send(f'{host.mention}, please pay out {prize}', view = view)
            await self.channel.delete()
            remove_persistent_gw_view(self.channel.id)
            save_persistent_gw_view(msg.id, self.users, new_channel.id, prize, host.id)
        except Exception as e:
            await self.channel.send(f"Error in rerolling: {e}\nCheck /bot_info for invite to support server for help.")

async def pick_winners(guild_id: int, message_id: int, channel_id: int, winners_count: int, prize: str, host: int, template: bool):
    host = await bot.fetch_user(host)
    guild = bot.get_guild(guild_id)
    if not guild:
        return
    channel = guild.get_channel(channel_id)
    if not channel:
        return
    try:
        message = await channel.fetch_message(message_id)
    except:
        return

    reaction_emoji = EMOJI
    reaction = discord.utils.get(message.reactions, emoji=reaction_emoji)
    if not reaction:
        await channel.send("No one reacted to the giveaway.")
        return

    users = [user async for user in reaction.users()]
    users = [user for user in users if not user.bot]

    if not users:
        await channel.send("No valid participants in the giveaway.")
        return

    db_path = f"gw_config/{guild_id}.db"
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()
    cursor.execute("SELECT role_id, entry_count FROM role_entries")
    role_entries = dict(cursor.fetchall())
    conn.close()

    weighted_pairs = []
    for user in users:
        member = guild.get_member(user.id)
        if not member:
            continue
        total_entries = 1
        if template:
            for role in member.roles:
                if role.id in role_entries and role_entries[role.id] > 0:
                    total_entries += role_entries[role.id]
        weighted_pairs.append((user, max(1, total_entries)))

    if not weighted_pairs:
        weighted_pairs = [(u, 1) for u in users]

    pick_count = min(winners_count, len(weighted_pairs))
    winners = []
    pool_users = [u for u, _ in weighted_pairs]
    pool_weights = [w for _, w in weighted_pairs]
    for _ in range(pick_count):
        if not pool_users:
            break
        winner = random.choices(pool_users, weights=pool_weights, k=1)[0]
        winners.append(winner)
        idx = pool_users.index(winner)
        pool_users.pop(idx)
        pool_weights.pop(idx)

    non_winners = [u for u in users if u not in winners]

    winners_mentions = ", ".join(winner.mention for winner in winners)
    await channel.send(f"<a:giveaway:1380539377167634542> Congratulations {winners_mentions}! You won the giveaway ({prize})!")

    category = discord.utils.get(guild.categories, name="giveaway")
    if category is None:
        category = await guild.create_category("giveaway")

    for winner in winners:
        channel_name = f"{prize}-{host.name}-{winner}-1"
        existing_channel = discord.utils.get(category.channels, name=channel_name)
        if existing_channel:
            channel_id = int(channel_name[-1]) + 1
            channel_name = channel_name[:-1] + str(channel_id)
        overwrites = {
            guild.default_role: discord.PermissionOverwrite(read_messages=False), # @everyone cannot see
            guild.me: discord.PermissionOverwrite(read_messages=True, send_messages=True), # Bot can always see
            winner: discord.PermissionOverwrite(read_messages=True, send_messages=True), # Winner can see and send
            host: discord.PermissionOverwrite(read_messages=True, send_messages=True) # Host can see and send
        }
        db_path = f"gw_config/{guild.id}.db"
        conn = sqlite3.connect(db_path)
        cursor = conn.cursor()
        cursor.execute("SELECT role_id, entry_count, staff FROM role_entries")
        rows = cursor.fetchall()
        conn.close()
        staff_roles = []
        for role_id, count, staff in rows:
            if staff>0:
                staff_roles.append((role_id, count, staff))
        for role_id, _, _ in staff_roles:
            role_obj = guild.get_role(role_id)
            if role_obj:
                overwrites[role_obj] = discord.PermissionOverwrite(read_messages=True, send_messages=True)
        new_channel = await guild.create_text_channel(channel_name, category=category, overwrites=overwrites)
        view = GwClose(new_channel, non_winners, prize, host)
        await new_channel.send(f"<a:giveaway:1380539377167634542> Congratulations {winner.mention}! You won the giveaway ({prize})!\nYou can claim your prize here")
        msg = await new_channel.send(f"{host.mention}, please pay out {prize}", view=view)
        weighted_id = [i.id for i in non_winners]
        save_persistent_gw_view(msg.id, weighted_id, new_channel.id, prize, host.id)
        await winner.send(
        f"<a:giveaway:1380539377167634542> Congratulations! You’ve won the giveaway!\n"
        f"A private channel has been created for you to claim your prize.\n"
        f"Channel: {new_channel.mention} (ID: `{new_channel.id}`)")

def save_persistent_gw_view(message_id, weighted_users, channel_id, prize, host_id):
    filepath = "persistent_gw_views.json"
    data = []
    if os.path.exists(filepath):
        with open(filepath, "r") as f:
            try:
                data = json.load(f)
            except json.JSONDecodeError:
                data = []
    data.append({
        "message_id": message_id,
        "weighted_users": weighted_users,
        "channel_id": channel_id,
        "prize": prize,
        "host_id": host_id
    })
    with open(filepath, "w") as f:
        json.dump(data, f, indent=4)

def remove_persistent_gw_view(channel_id):
    filepath = "persistent_gw_views.json"
    if not os.path.exists(filepath):
        return
    with open(filepath, "r") as f:
        try:
            data = json.load(f)
        except json.JSONDecodeError:
            data = []
    data = [entry for entry in data if entry["channel_id"] != channel_id]
    with open(filepath, "w") as f:
        json.dump(data, f, indent=4)

def update_giveaway_count(server_id: int, amount: int):
    # Step 1: Ensure the folder exists
    folder = "giveaway_data"
    os.makedirs(folder, exist_ok=True)

    # Step 2: Build the file path
    file_path = os.path.join(folder, f"{server_id}.txt")

    # Step 3: Check if file exists and read/update value
    if os.path.exists(file_path):
        with open(file_path, "r") as f:
            try:
                current_value = int(f.read())
            except ValueError:
                current_value = 0
    else:
        current_value = 0

    # Step 4: Update the value and write back
    new_value = current_value + amount
    with open(file_path, "w") as f:
        f.write(str(new_value))

    return new_value

def update_last_gw(server_id: int, last_gw_value: int):
    folder = "last_gw"
    os.makedirs(folder, exist_ok=True)

    file_path = os.path.join(folder, f"{server_id}.json")

    # Check if file exists
    if not os.path.exists(file_path):
        return  # Do nothing if file doesn't exist

    # If file exists, replace the contents
    new_data = {
        "last_gw": last_gw_value,
        "timestamp": datetime.now(timezone.utc).isoformat()
    }

    with open(file_path, "w") as f:
        json.dump(new_data, f, indent=2)
@bot.tree.command(name="giveaway", description="Create a giveaway")
async def giveaway(interaction: discord.Interaction, prize: str, time: str, winners: int, host: discord.User = None, template: bool = True):
    guild = interaction.guild
    create_server_database(guild.id)
    db_path = f"gw_config/{guild.id}.db"
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()
    try:
        cursor.execute("SELECT role_id, entry_count, staff FROM role_entries")
        rows = cursor.fetchall()
    except Exception as e:
        await interaction.response.send_message('No staff role selected. You can set up giveaway staff by using `/config gw`.')
        return
    conn.close()
    if not interaction.user.guild_permissions.mention_everyone:
        staff_roles = []
        for role_id, count, staff in rows:
            if staff > 0:
                staff_roles.append((role_id, count, staff))
        staff_role_ids = [role_id for role_id, _, _ in staff_roles]

        member = guild.get_member(interaction.user.id)  # <-- get Member from Interaction
        confirmed = False
        if any(role.id in staff_role_ids for role in member.roles):
            confirmed = True

        if not confirmed:
            await interaction.response.send_message(
                'You need either mention everyone permission or staff role (set this in /gw_config) to host a giveaway',
                ephemeral=True
            )
            return
    
    if not host:
        host = interaction.user

    if parse_time_string(time):
        seconds = parse_time_string(time)
        future_time = datetime.now(timezone.utc) + timedelta(seconds=seconds)
        unix_timestamp = int(future_time.timestamp())
        discord_timestamp = f"<t:{unix_timestamp}:R>"

        embed = discord.Embed(title=f'{prize}', description=f'{winners} winners\nReact on {EMOJI} to join', color=discord.Color.random())

        non_zero_roles = []
        zero_roles = []
        for role_id, count, staff in rows:
            if count > 1:
                non_zero_roles.append((role_id, count, staff))
            elif count == 0:
                zero_roles.append((role_id, count, staff))
            else:
                pass
        extra_text = ""
