def ticket_channels(ctx, slot, new_data, guild_id=None):
    file_path = get_file_path2(guild_id)
    if not os.path.exists(file_path):  # Create file if missing
        default_data = {
        "giveaway": None,  
        "invite": None,  
        "others": None,
        "premium": None
        }
        with open(file_path, "w") as file:
            json.dump(default_data, file, indent=4)
    data = load_data2(guild_id)  # Load existing data

    if slot:  # If a specific slot is provided, update only that slot
        if slot in data:
            data[slot] = new_data
        else:
            print("❌ Invalid slot!")
            return
    else:  # If no slot is specified, overwrite the entire file
        data = new_data

    with open(file_path, "w") as file:
        json.dump(data, file, indent=4)

async def create_unique_thread(channel: discord.TextChannel, base_name: str, **kwargs):
    existing_names = {thread.name for thread in channel.threads}

    archived_threads = [thread async for thread in channel.archived_threads()]
    existing_names.update(thread.name for thread in archived_threads)

    if base_name not in existing_names:
        return await channel.create_thread(name=base_name, **kwargs)

    pattern = re.compile(re.escape(base_name) + r" \((\d+)\)$")
    used_numbers = []
    for name in existing_names:
        match = pattern.match(name)
        if match:
            used_numbers.append(int(match.group(1)))

    n = 1
    while n in used_numbers:
        n += 1

    new_name = f"{base_name} ({n})"
    return await channel.create_thread(name=new_name, **kwargs)

