def init_default_invite_config(guild_id):
    conn = sqlite3.connect("invite_config.db")
    cursor = conn.cursor()

    cursor.execute("SELECT * FROM invite_config WHERE guild_id = ?", (guild_id,))
    exists = cursor.fetchone()

    if not exists:
        cursor.execute("""
            INSERT INTO invite_config (
                guild_id,
                checker_role_id,
                require_verified_email,
                min_account_age_days,
                invites_lost_on_rejoin,
                invites_lost_on_leave,
                invites_lost_on_fake,
                roles_needed,
                event_message
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (
            guild_id,
            0,          # checker_role_id default (none)
            False,      # require_verified_email
            0,          # min_account_age_days
            0,          # invites_lost_on_rejoin
            0,          # invites_lost_on_leave
            0,           # invites_lost_on_fake
            0,
            'N/A'
        ))
        conn.commit()

    conn.close()

def get_invite_config(guild_id):
    conn = sqlite3.connect("invite_config.db")
    cursor = conn.cursor()

    cursor.execute("SELECT * FROM invite_config WHERE guild_id = ?", (guild_id,))
    result = cursor.fetchone()
    conn.close()

    if result is None:
        return None  # or return default values if preferred

    (
        guild_id,
        checker_role_id,
        require_verified_email,
        min_account_age_days,
        invites_lost_on_rejoin,
        invites_lost_on_leave,
        invites_lost_on_fake,
        roles_needed,
        event_message
    ) = result

    return {
        "guild_id": guild_id,
        "checker_role_id": checker_role_id,
        "require_verified_email": require_verified_email,
        "min_account_age_days": min_account_age_days,
        "invites_lost_on_rejoin": invites_lost_on_rejoin,
        "invites_lost_on_leave": invites_lost_on_leave,
        "invites_lost_on_fake": invites_lost_on_fake,
        "roles_needed": roles_needed,
        "event_message": event_message
    }

def get_min_account_age(guild_id: int) -> int:
    conn = sqlite3.connect("invite_config.db")
    cursor = conn.cursor()

    cursor.execute("SELECT min_account_age_days FROM invite_config WHERE guild_id = ?", (guild_id,))
    row = cursor.fetchone()
    conn.close()

    return row[0] if row else 0  # Default to 0 if not set

def setup_invite_db():
    conn = sqlite3.connect('invite_stats.db')
    cursor = conn.cursor()

    cursor.execute("""
    CREATE TABLE IF NOT EXISTS invite_stats (
        guild_id INTEGER,
        inviter_id INTEGER,
        invites TEXT DEFAULT '[]',
        rejoin TEXT DEFAULT '[]',
        fake TEXT DEFAULT '[]',
        leave TEXT DEFAULT '[]',
        PRIMARY KEY (guild_id, inviter_id)
    )
    """)
    conn.commit()
    conn.close()

def add_invited_user(guild_id: int, inviter_id: int, user_id: int, category: str):
    if category not in ['invites', 'rejoin', 'fake', 'leave']:
        raise ValueError("Invalid category")

    conn = sqlite3.connect('invite_stats.db')
    cursor = conn.cursor()

    cursor.execute("""
        INSERT OR IGNORE INTO invite_stats (guild_id, inviter_id) VALUES (?, ?)
    """, (guild_id, inviter_id))

    current_list = get_list_column(cursor, guild_id, inviter_id, category)
    
    if user_id not in current_list:
        current_list.append(user_id)
        save_list_column(cursor, guild_id, inviter_id, category, current_list)

    conn.commit()
    conn.close()
def get_list_column(cursor, guild_id, inviter_id, column):
    cursor.execute(f"""
        SELECT {column} FROM invite_stats WHERE guild_id = ? AND inviter_id = ?
    """, (guild_id, inviter_id))
    row = cursor.fetchone()
    if row is None:
        return []
    try:
        return json.loads(row[0])
    except Exception:
        return []
def save_list_column(cursor, guild_id, inviter_id, column, data_list):
    json_data = json.dumps(data_list)
    cursor.execute(f"""
        UPDATE invite_stats SET {column} = ? WHERE guild_id = ? AND inviter_id = ?
    """, (json_data, guild_id, inviter_id))

async def get_inviter_id(member: discord.Member) -> int | None:
    guild_id = member.guild.id
    try:
        invites = await member.guild.invites()
    except discord.Forbidden:
        return None  # bot lacks permission

    for invite in invites:
        if invite.uses > 0:  # any used invite
            inviter_id = get_inviter_from_code(guild_id, invite.code)
            if inviter_id:
                return inviter_id
    return None
def get_inviter_from_code(guild_id: int, code: str) -> int | None:
    conn = sqlite3.connect("invite_codes.db")
    cursor = conn.cursor()
    cursor.execute("SELECT inviter_id FROM invite_codes WHERE guild_id = ? AND code = ?", (guild_id, code))
    row = cursor.fetchone()
    conn.close()
    return row[0] if row else None

INVITE_DATA_FOLDER = "./invite_joined_ids/"

if not os.path.exists(INVITE_DATA_FOLDER):
    os.makedirs(INVITE_DATA_FOLDER)

def get_joined_file_path(guild_id):
    return os.path.join(INVITE_DATA_FOLDER, f"{guild_id}.txt")

def is_rejoin(guild_id, user_id):
    path = get_joined_file_path(guild_id)
    if not os.path.exists(path):
        return False
    with open(path, "r") as f:
        joined_ids = set(line.strip() for line in f.readlines())
    return str(user_id) in joined_ids

def add_to_joined_file(guild_id, user_id):
    path = get_joined_file_path(guild_id)
    if os.path.exists(path):
        with open(path, "a") as f:
            f.write(f"{user_id}\n")
    else:
        with open(path, "w") as f:
            now = time.time()
            f.write(f"{now}\n")
        with open(path, "a") as f:
            f.write(f"{user_id}\n")
