def check_invites(guild_id, user_id):
    # --- Invite stats database ---
    conn_stats = sqlite3.connect('invite_stats.db')
    cursor_stats = conn_stats.cursor()

    invites = get_list_column(cursor_stats, guild_id, user_id, 'invites')
    fakes = get_list_column(cursor_stats, guild_id, user_id, 'fake')
    rejoins = get_list_column(cursor_stats, guild_id, user_id, 'rejoin')
    leave = get_list_column(cursor_stats, guild_id, user_id, 'leave')

    conn_stats.close()

    # --- Config database ---
    conn_config = sqlite3.connect(f'invite_config.db')
    cursor_config = conn_config.cursor()

    cursor_config.execute("SELECT invites_lost_on_fake, invites_lost_on_rejoin, invites_lost_on_leave FROM invite_config WHERE guild_id = ?", (guild_id,))
    row = cursor_config.fetchone()
    conn_config.close()

    # Default penalties if not configured
    fake_penalty = row[0] if row else 1
    rejoin_penalty = row[1] if row else 1
    leave_penalty = row[1] if row else 1

    total_valid = len(invites)
    total_fake = len(fakes)
    total_rejoin = len(rejoins)
    total_leave = len(leave)

    # Apply penalties
    total_penalty = (total_fake * fake_penalty) + (total_rejoin * rejoin_penalty) + (total_leave * leave_penalty)
    effective_total = max(0, total_valid - total_penalty)

    return {
        "valid": total_valid,
        "fake": total_fake,
        "rejoin": total_rejoin,
        "leave": total_leave,
        "total": effective_total,
        "fake_penalty": fake_penalty,
        "rejoin_penalty": rejoin_penalty,
        "leave_penalty": leave_penalty
    }

