def get_checker_role_id(guild_id):
    conn = sqlite3.connect("invite_config.db")
    cursor = conn.cursor()
    cursor.execute("SELECT checker_role_id FROM invite_config WHERE guild_id = ?", (guild_id,))
    row = cursor.fetchone()
    conn.close()
    return row[0] if row else None

# Function to reset invite data
def reset_invite_data(guild_id, user_id):
    conn = sqlite3.connect("invite_stats.db")
    cursor = conn.cursor()
    cursor.execute(f"""
        DELETE FROM invite_stats 
        WHERE guild_id = ? AND inviter_id = ?
    """, (guild_id, user_id))
    conn.commit()
    conn.close()
