class TicketButton(View):
    def __init__(self):
            super().__init__()
    @discord.ui.button(label="Invite Ticket", style=discord.ButtonStyle.success)
    async def invt(self, interaction: discord.Interaction, button: Button):
        await interaction.response.defer()
        category = discord.utils.get(interaction.guild.categories, name="invite tickets")
        if category is None:
            category = await interaction.guild.create_category("invite tickets")
        guild_id = interaction.guild.id
        user = interaction.user
        if user:
            user_id = user.id
        else:
            user_id = interaction.user.id
        conn_stats = sqlite3.connect('invite_stats.db')
        cursor_stats = conn_stats.cursor()
        invites = get_list_column(cursor_stats, guild_id, user_id, 'invites')
        conn_config = sqlite3.connect(f'invite_config.db')
        cursor_config = conn_config.cursor()
        cursor_config.execute("SELECT checker_role_id, roles_needed, event_message FROM invite_config WHERE guild_id = ?", (guild_id,))
        checker, needed, msg = cursor_config.fetchone()
        conn_config.close()
        role_missing = 0
        invited_list = ''
        for i in range(0, len(invites)):
            member = await interaction.guild.fetch_member(invites[i])
            invited_list += f'<@{member.id}>\n'
            if len([role for role in member.roles if role.name != "@everyone"]) < needed:
                role_missing += 1
        stats = check_invites(guild_id, user_id)
        guild = interaction.guild
        current = stats['total'] - role_missing
        if role_missing > 0:
            channel_name = f"{current}-pending-role"
            overwrites = {
                guild.default_role: discord.PermissionOverwrite(read_messages=False), # @everyone cannot see
                guild.me: discord.PermissionOverwrite(read_messages=True, send_messages=True), # Bot can always see
                checker: discord.PermissionOverwrite(read_messages=True, send_messages=True)}
            new_channel = await interaction.guild.create_text_channel(channel_name, category=category, overwrites=overwrites)
            view = InvClose(new_channel, user_id)
            save_invite_view("InvClose", new_channel.id, new_channel.guild.id, user_id=user_id)
            embed = discord.Embed(title = 'Invited list', description = invited_list, color = discord.Color.random())
            await new_channel.send(msg)
            await new_channel.send(f"<@{user_id}> You have {current}/{stats['total']} effective invites, please make sure everyone you invite has at least {needed} self-roles\nOnce you are ready, click on re-check", embed=embed, view = view)
        else:
            channel_name = f"{current}-valid"
            overwrites = {
                guild.default_role: discord.PermissionOverwrite(read_messages=False), # @everyone cannot see
                guild.me: discord.PermissionOverwrite(read_messages=True, send_messages=True), # Bot can always see
                checker: discord.PermissionOverwrite(read_messages=True, send_messages=True)}
            new_channel = await interaction.guild.create_text_channel(channel_name, category=category, overwrites=overwrites)
            view = InvClose(new_channel, user_id)
            save_invite_view("InvClose", new_channel.id, new_channel.guild.id, user_id=user_id)
            embed = discord.Embed(title = 'Invited list', description = invited_list, color = discord.Color.random())
            await new_channel.send(msg)
            await new_channel.send(f"<@{user_id}> You have {current} effective invites, please provide info required by invite event here", embed = embed, view = view)
            view2 = InvConfirm(new_channel, current, checker)
            save_invite_view("InvConfirm", new_channel.id, new_channel.guild.id, number=current, checker_role=checker)
            await new_channel.send(f'<@&{checker}> Please check the info provided\nOnce ready, click on button below', view=view2)

class InvClose(View):
    def __init__(self, channel, user_id):
            super().__init__(timeout = None)
            self.channel = channel
            self.user_id = user_id
    @discord.ui.button(label="Close Ticket", style=discord.ButtonStyle.danger)
    async def close(self, interaction: discord.Interaction, button: discord.ui.Button):
        data = load_data2(interaction.guild.id)
        log_channel_id = data.get('invite')
        
        if log_channel_id:
            channel_id = self.channel.id
            target_channel = bot.get_channel(channel_id) or await bot.fetch_channel(channel_id)
            log_channel = bot.get_channel(log_channel_id) or await bot.fetch_channel(log_channel_id)

            # Send archive start message first
            archive_msg = await log_channel.send(f"Archiving messages from ticket: {self.channel.name}")

            # Create unique thread under that message
            thread = await create_unique_thread(log_channel, base_name=f"archive-{self.channel.name}", message=archive_msg)

            # Get all messages, oldest first
            messages = [msg async for msg in target_channel.history(limit=None, oldest_first=True)]

            # Skip the first two messages
            for msg in messages[2:]:
                timestamp = msg.created_at.strftime("%Y-%m-%d %H:%M:%S")
                content = f"**{msg.author.display_name}** ({timestamp}) said:\n{msg.content}"
                await thread.send(content)
        await self.channel.delete()
        remove_invite_view(self.channel.id)
