        checker, needed = cursor_config.fetchone()
        conn_config.close()
        role_missing = 0
        invited_list = ''
        for i in range(0, len(invites)):
            member = await interaction.guild.fetch_member(invites[i])
            invited_list += f'<@{member.id}>\n'
            if len([role for role in member.roles if role.name != "@everyone"]) < needed:
                role_missing += 1
        stats = check_invites(guild_id, user_id)
