class InvConfirm(View):
    def __init__(self, channel, number, checker_role):
            super().__init__(timeout = None)
            self.channel = channel
            self.number = number
            self.checker_role = checker_role
    @discord.ui.button(label="Confirm", style=discord.ButtonStyle.success)
    async def confirm(self, interaction: discord.Interaction, button: discord.ui.Button):
        checker = interaction.user
        if any(role.id == self.checker_role for role in checker.roles):
            await self.channel.edit(name=f"{self.number}-confirmed")
            conn = sqlite3.connect("ticket_lb.db")
            cursor = conn.cursor()
            new_ticket_count = 0 
            try:
                cursor.execute(
                    """
                    UPDATE ticket_lb
                    SET number = number + 1
                    WHERE guild_id = ? AND user_id = ?;
                    """,
                    (interaction.guild.id, interaction.user.id)
                )
                if cursor.rowcount == 0:
                    cursor.execute(
                        """
                        INSERT INTO ticket_lb (guild_id, user_id, number)
                        VALUES (?, ?, 1);
                        """,
                        (interaction.guild.id, interaction.user.id)
                    )
                
                conn.commit() 
                cursor.execute(
                    """
                    SELECT number
                    FROM ticket_lb
                    WHERE guild_id = ? AND user_id = ?;
                    """,
                    (interaction.guild.id, interaction.user.id)
                )
                result = cursor.fetchone()
                if result:
                    new_ticket_count = result[0] # Assign the fetched number
            except sqlite3.Error as e:
                print(f"Database error: {e}")
                conn.rollback() # Rollback changes if an error occurs
                await interaction.response.send_message(
                    "An error occurred while updating your ticket points. Please try again later.", 
                    ephemeral=True
                )
                return 
            finally:
                conn.close()
            await interaction.response.send_message(
                f'Thanks for your work!\nYou now have **{new_ticket_count}** ticket points.', 
                ephemeral=True
            )
        else:
            await interaction.response.send_message(
                f'You do not have the required role to confirm (<@&{self.checker_role}>).',
                ephemeral=True
            )

INV_FILE = "invite_views.json"

def save_invite_view(view_type, channel_id, guild_id, user_id=None, number=None, checker_role=None):
    entry = {
        "type": view_type,
        "channel_id": channel_id,
        "guild_id": guild_id,
        "user_id": user_id,
        "number": number,
        "checker_role": checker_role,
    }

    data = []
    if os.path.exists(INV_FILE):
        with open(INV_FILE, "r") as f:
            try:
                data = json.load(f)
            except json.JSONDecodeError:
                data = []

    data.append(entry)

    with open(INV_FILE, "w") as f:
        json.dump(data, f, indent=4)

def remove_invite_view(channel_id):
    if not os.path.exists(INV_FILE):
        return

    with open(INV_FILE, "r") as f:
        try:
            data = json.load(f)
        except json.JSONDecodeError:
            data = []

    data = [entry for entry in data if entry["channel_id"] != channel_id]

    with open(INV_FILE, "w") as f:
        json.dump(data, f, indent=4)

def load_invite_views():
    if not os.path.exists(INV_FILE):
        return []

    with open(INV_FILE, "r") as f:
        try:
            return json.load(f)
        except json.JSONDecodeError:
            return []
def setup_ticket_lb_db():
    conn = sqlite3.connect("ticket_lb.db")
    cursor = conn.cursor()

    cursor.execute("""
        CREATE TABLE IF NOT EXISTS ticket_lb (
            guild_id INTEGER NOT NULL,
            user_id INTEGER NOT NULL,
            number INTEGER DEFAULT 0,
            PRIMARY KEY (guild_id, user_id)
        );
    """)
    conn.commit()
    conn.close()
