class ConfirmClaimView(discord.ui.View):
    def __init__(self, bot, checker: discord.User, guild_id: int):
        super().__init__(timeout=60)
        self.bot = bot
        self.checker = checker
        self.guild_id = guild_id
        self.message: discord.Message | None = None  # set right after we send it

    async def on_timeout(self) -> None:
        # Disable buttons when the view times out
        if self.message:
            for child in self.children:
                child.disabled = True
            try:
                await self.message.edit(content="⌛ Ticket claim confirmation timed out.", view=self)
            except Exception:
                pass

    @discord.ui.button(label="Confirm", style=discord.ButtonStyle.green)
    async def confirm(self, interaction: discord.Interaction, button: discord.ui.Button):
        # The checker cannot confirm their own claim
        if interaction.user.id == self.checker.id:
            return await interaction.response.send_message(
                "❌ You can't confirm your own ticket claim.", ephemeral=True
            )

        # Update DB
        new_ticket_count = 0
        conn = sqlite3.connect("ticket_lb.db")
        cursor = conn.cursor()
        try:
            cursor.execute(
                """
                UPDATE ticket_lb
                SET number = number + 1
                WHERE guild_id = ? AND user_id = ?;
                """,
                (self.guild_id, self.checker.id)
            )
            if cursor.rowcount == 0:
                cursor.execute(
                    """
                    INSERT INTO ticket_lb (guild_id, user_id, number)
                    VALUES (?, ?, 1);
                    """,
                    (self.guild_id, self.checker.id)
                )
            conn.commit()

            cursor.execute(
                """
                SELECT number
                FROM ticket_lb
                WHERE guild_id = ? AND user_id = ?;
                """,
                (self.guild_id, self.checker.id)
            )
            result = cursor.fetchone()
            if result:
                new_ticket_count = result[0]
        except sqlite3.Error as e:
            print(f"Database error: {e}")
            conn.rollback()
            return await interaction.response.send_message(
                "❌ DB error while updating ticket points. Try again later.",
                ephemeral=True
            )
        finally:
            conn.close()

        # Disable the button(s) and edit the original message
        for child in self.children:
            child.disabled = True

        await interaction.response.edit_message(
            content=(
                f"✅ {interaction.user.mention} confirmed the claim for {self.checker.mention}!\n"
                f"They now have **{new_ticket_count}** ticket points."
            ),
            view=self
        )

