def get_ticket_lb_data(guild_id: int, limit: int = 10) -> list[tuple[int, int]]:
    conn = sqlite3.connect("ticket_lb.db")
    cursor = conn.cursor()
    try:
        cursor.execute(
            """
            SELECT user_id, number
            FROM ticket_lb
            WHERE guild_id = ?
            ORDER BY number DESC, user_id ASC  -- Order by count (desc), then user_id (asc) for tie-breaking
            LIMIT ?;
            """,
            (guild_id, limit)
        )
        leaderboard_data = cursor.fetchall()
        return leaderboard_data
    except sqlite3.Error as e:
        print(f"Database error when fetching leaderboard: {e}")
        return []
    finally:
        conn.close()
def get_invite_lb_data(guild_id: int, limit: int = 10) -> list[tuple[int, int]]:
    """
    Generates a leaderboard for invite counts for a specific guild.
    Returns a list of (inviter_id, effective_total_invites) tuples,
    sorted by effective_total_invites DESC.
    """
    conn_stats = sqlite3.connect('invite_stats.db')
    cursor_stats = conn_stats.cursor()

    leaderboard_entries = []

    try:
        # Get all unique inviter_ids for the given guild
        cursor_stats.execute("SELECT DISTINCT inviter_id FROM invite_stats WHERE guild_id = ?", (guild_id,))
        inviter_ids = [row[0] for row in cursor_stats.fetchall()]

        for inviter_id in inviter_ids:
            # For each inviter, calculate their effective invite total using check_invites
            stats = check_invites(guild_id, inviter_id)
            effective_total = stats['total']
            leaderboard_entries.append((inviter_id, effective_total))
        
        # Sort the entries by effective_total in descending order.
        # For ties, sort by inviter_id for consistent ordering.
        leaderboard_entries.sort(key=lambda x: (x[1], x[0]), reverse=True) # Sort by total DESC, then inviter_id DESC

        # Apply the limit
        return leaderboard_entries[:limit]

    except sqlite3.Error as e:
        print(f"Database error when generating invite leaderboard: {e}")
        return []
    finally:
        conn_stats.close()

def get_dueller_leaderboard(global_scope: bool, guild: discord.Guild = None):
    import sqlite3
    from collections import defaultdict

    db_path = "gym.db"  # Or wherever you store your certificates
    score_dict = defaultdict(int)

    with sqlite3.connect(db_path) as conn:
        c = conn.cursor()

        # Fetch all certificate data
        c.execute("SELECT user_id, achievement FROM certificates")
        all_rows = c.fetchall()

        for user_id, achievement in all_rows:
            if global_scope:
                score_dict[user_id] += 1
            else:
                # Only include users from this guild
                if guild and guild.get_member(user_id):
                    score_dict[user_id] += 1

    # Sort by score descending
    sorted_scores = sorted(score_dict.items(), key=lambda x: x[1], reverse=True)
    return sorted_scores
def get_global_points_lb(limit: int = 100):
    """Return a list of (user_id, points, wins, loses) sorted by points descending."""
    conn = get_queue_db()
    c = conn.cursor()

    # Get points
    c.execute("SELECT user_id, points FROM queue_points ORDER BY points DESC LIMIT ?", (limit,))
    points_data = c.fetchall()  # [(user_id, points), ...]

    leaderboard = []
    for user_id, points in points_data:
        # Optional: also fetch wins/loses for display
        c.execute("SELECT COUNT(*) FROM queue_logs WHERE winner_id=?", (user_id,))
        wins = c.fetchone()[0]
        c.execute("SELECT COUNT(*) FROM queue_logs WHERE loser_id=?", (user_id,))
        loses = c.fetchone()[0]
        leaderboard.append((user_id, wins, loses, points))

    conn.close()
    return leaderboard


def get_server_point_leaderboard(column: str, limit: int = 100) -> list[tuple[int, int]]:
    if column not in {"monthly_points", "total_points"}:
        return []
    with connect_server_point_db() as conn:
        c = conn.cursor()
        c.execute(
            f"""
            SELECT server_id, {column}
            FROM server_points
            WHERE COALESCE({column}, 0) > 0
            ORDER BY {column} DESC, server_id ASC
            LIMIT ?
            """,
            (int(limit),),
        )
        rows = c.fetchall()
    return [(int(row["server_id"]), int(row[column] or 0)) for row in rows]

def get_collection_points_lb(limit: int = 100):
    conn = connect_user_point_db()
    c = conn.cursor()

    c.execute("""
        SELECT
            user_id,
            COALESCE(collection_points, 0) +
            COALESCE(clan_collection_points, 0)
            AS total_points
        FROM user_points
        WHERE
            COALESCE(collection_points, 0) +
            COALESCE(clan_collection_points, 0) > 0
        ORDER BY total_points DESC, user_id ASC
        LIMIT ?
    """, (limit,))

    rows = c.fetchall()
    conn.close()

    return [
        (int(row["user_id"]), int(row["total_points"]))
        for row in rows
    ]

# Helper View for pagination
class LeaderboardView(discord.ui.View):
    def __init__(self, interaction, entries, title, per_page=20, poke =False, is_guild_id=False, gym=False):
        super().__init__(timeout=180)
        self.interaction = interaction
        self.entries = entries
        self.title = title
        self.per_page = per_page
        self.current_page = 0
        self.total_pages = (len(entries) - 1) // per_page + 1
        self.is_guild_id = is_guild_id  # If True, entries have guild_id instead of name
        self.poke = poke
        self.gym = gym

    def format_page(self):
        start = self.current_page * self.per_page
        end = start + self.per_page
        page_entries = self.entries[start:end]

        lines = []
        for i, d in enumerate(page_entries, start=start + 1):
            if self.is_guild_id:
                # d is (guild_id, value)
                guild = self.interaction.client.get_guild(d[0])
                name = guild.name if guild else f"Unknown ({d[0]})"
                val = d[1]
                lines.append(f"**{i}. {name}:** {val}")
            else:
                # d is (user_id, value)
                if len(d) == 4:
                    user_id, wins, loses, points = d
                    if self.gym:
                        lines.append(f"**{i}.** <@{user_id}>: {points} ({wins}W/{loses}L)")
                    else:
                        lines.append(f"**{i}.** {elo_emoji(points)}<@{user_id}>: {points} ({wins}W/{loses}L)")
                elif self.poke:
                    user_id = d[0]
                    val = d[1]
                    lines.append(f"**{i}.** {user_id}: {val}")
                else:
                    user_id = d[0]
                    val = d[1]
                    lines.append(f"**{i}.** <@{user_id}>: {val}")

        desc = "\n".join(lines) if lines else "No data found."
        footer = f"Page {self.current_page + 1}/{self.total_pages}"
        return desc, footer

    async def update_message(self, interaction):
        desc, footer = self.format_page()
        embed = discord.Embed(title=self.title, description=desc, color=discord.Color.gold())
        embed.set_footer(text=footer)
        await interaction.response.edit_message(embed=embed, view=self)

    @discord.ui.button(label="Previous", style=discord.ButtonStyle.secondary)
    async def previous(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.current_page > 0:
            self.current_page -= 1
            await self.update_message(interaction)
        else:
            await interaction.response.defer()

    @discord.ui.button(label="Next", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.current_page < self.total_pages - 1:
            self.current_page += 1
            await self.update_message(interaction)
        else:
            await interaction.response.defer()


class ServerInviteActionSelect(discord.ui.Select):
    def __init__(self):
        options = [
            discord.SelectOption(label="Add Server Invite", value="add", description="Create or refresh this server's saved invite."),
            discord.SelectOption(label="Remove Server Invite", value="remove", description="Delete this server's saved invite from the database."),
        ]
        super().__init__(placeholder="Server invite action", min_values=1, max_values=1, options=options, row=1)

    async def callback(self, interaction: discord.Interaction):
        guild = interaction.guild
        if guild is None:
            return await interaction.response.send_message("This action only works inside a server.", ephemeral=True)
        if interaction.user is None or (interaction.user != guild.owner and not interaction.user.guild_permissions.administrator):
            return await interaction.response.send_message("Only the server owner or an admin can manage the server invite.", ephemeral=True)

        if self.values[0] == "add":
            invite_link = await create_permanent_server_invite(guild)
            if not invite_link:
                return await interaction.response.send_message("I could not create a permanent invite for this server.", ephemeral=True)
            set_server_point_invite(guild.id, invite_link)
            return await interaction.response.send_message(f"Saved server invite: {invite_link}", ephemeral=True)

        set_server_point_invite(guild.id, None)
        await interaction.response.send_message("Removed this server's saved invite.", ephemeral=True)


class ServerInviteLookupSelect(discord.ui.Select):
    def __init__(self, server_ids: list[int], client: discord.Client):
        options = []
        for server_id in server_ids[:25]:
            guild = client.get_guild(int(server_id))
            label = guild.name if guild else f"Server {server_id}"
            options.append(discord.SelectOption(label=label[:100], value=str(server_id)))
        if not options:
            options = [discord.SelectOption(label="No servers available", value="0")]
        super().__init__(placeholder="View a saved server invite", min_values=1, max_values=1, options=options, row=2)

    async def callback(self, interaction: discord.Interaction):
        server_id = int(self.values[0])
        if server_id == 0:
            return await interaction.response.send_message("No server invite data is available.", ephemeral=True)
        server_row = get_server_point_row(server_id)
        guild = interaction.client.get_guild(server_id)
        guild_name = guild.name if guild else f"Server {server_id}"
        invite_link = server_row.get("server_invite")
        if not invite_link:
            return await interaction.response.send_message(f"{guild_name} does not have a saved server invite.", ephemeral=True)
        await interaction.response.send_message(f"{guild_name} invite: {invite_link}", ephemeral=True)


class ServerPointLeaderboardView(LeaderboardView):
    def __init__(self, interaction, entries, title, per_page=20):
        super().__init__(interaction, entries, title, per_page=per_page, is_guild_id=True)
        server_ids = [entry[0] for entry in entries]
        self.add_item(ServerInviteActionSelect())
        self.add_item(ServerInviteLookupSelect(server_ids, interaction.client))

