class FakemonUsageLeaderboardView(discord.ui.View):
    def __init__(self, owner_id: int, rows: list[tuple], per_page: int = 10):
        super().__init__(timeout=180)
        self.owner_id = int(owner_id)
        self.rows = rows or []
        self.per_page = max(1, int(per_page))
        self.page = 0
        self.max_page = max(0, (len(self.rows) - 1) // self.per_page)
        self.message: discord.Message | None = None
        self._sync_buttons()

    def _sync_buttons(self):
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                if child.custom_id == "fk_lb_prev":
                    child.disabled = self.page <= 0
                elif child.custom_id == "fk_lb_next":
                    child.disabled = self.page >= self.max_page

    def build_embed(self) -> discord.Embed:
        start = self.page * self.per_page
        end = start + self.per_page
        lines = []
        for rank, row in enumerate(self.rows[start:end], start=start + 1):
            pokemon_name, creator_id, usage_count = row
            creator_text = f"<@{int(creator_id)}>" if creator_id else "Unknown"
            lines.append(f"**{rank}.** {str(pokemon_name).title()} (created by: {creator_text}) — `{usage_count}`")
        desc = "\n".join(lines) if lines else "No data found."
        embed = discord.Embed(
            title="Fakemon Usage Leaderboard",
            description=desc,
            color=discord.Color.purple(),
        )
        embed.set_footer(text=f"Page {self.page + 1}/{self.max_page + 1}")
        return embed

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.owner_id:
            await interaction.response.send_message("This leaderboard isn't for you.", ephemeral=True)
            return False
        return True

    async def _update(self, interaction: discord.Interaction):
        self._sync_buttons()
        await interaction.response.edit_message(embed=self.build_embed(), view=self)

    @discord.ui.button(label="Prev", style=discord.ButtonStyle.secondary, custom_id="fk_lb_prev")
    async def prev(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page > 0:
            self.page -= 1
        await self._update(interaction)

    @discord.ui.button(label="Next", style=discord.ButtonStyle.secondary, custom_id="fk_lb_next")
    async def next(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page < self.max_page:
            self.page += 1
        await self._update(interaction)

@bot.command(name="leaderboard")
async def leaderboard_prefix(ctx: commands.Context, *, mode: str = None):
    if not mode:
        return await ctx.send("Usage: `!leaderboard ranked rare`, `!leaderboard ranked common`, or `!leaderboard fakemon`")
    if str(mode).strip().lower() == "fakemon":
        rows = _fetch_fakemon_usage_leaderboard()
        if not rows:
            return await ctx.send("No fakemon usage data found.")
        view = FakemonUsageLeaderboardView(ctx.author.id, rows, per_page=10)
        embed = view.build_embed()
        message = await ctx.send(embed=embed, view=view)
        view.message = message
        return
    queue_type = _normalize_ranked_queue_type(mode)
    if not queue_type:
        return await ctx.send("Usage: `!leaderboard ranked rare`, `!leaderboard ranked common`, or `!leaderboard fakemon`")
    data = get_ranked_leaderboard(queue_type, limit=20)
    if not data:
        return await ctx.send("No ranked data found.")
    lines = []
    for i, (user_id, wins, losses, rating) in enumerate(data, start=1):
        lines.append(f"**{i}.** {elo_emoji(rating)}<@{user_id}>: {rating} ({wins}W/{losses}L)")
    desc = "\n".join(lines) if lines else "No data found."
    title = f"🏆 {queue_type.title()} Leaderboard"
    embed = discord.Embed(title=title, description=desc, color=discord.Color.gold())
    embed.set_footer(text="For full leaderboard, check /leaderboard ranked rare/common")
    await ctx.send(embed=embed)


@bot.tree.command(name="reset_lb", description="Reset all ticket checker or invites")
@app_commands.choices(category= [app_commands.Choice(name = 'Invites', value = 'invite'),app_commands.Choice(name = 'Tickets', value = 'ticket')])
async def reset_invite_leaderboard(interaction: discord.Interaction, guild_id: int, category:str):
    if category == 'ticket':
        conn = sqlite3.connect('ticket_lb.db')
        cursor = conn.cursor()
        cursor.execute("DELETE FROM ticket_lb WHERE guild_id = ?", (guild_id,))
        conn.commit()
        await interaction.response.send_message(f"Ticket leaderboard reset for guild ID: {guild_id}")
    elif category == 'invite':
        conn = sqlite3.connect('invite_stats.db')
        cursor = conn.cursor()
        cursor.execute("DELETE FROM invite_stats WHERE guild_id = ?", (guild_id,))
        conn.commit()
        await interaction.response.send_message(f"Invite leaderboard reset for guild ID: {guild_id}")

