CLEANUP_EXCLUSION_FILE = "cleanup_excluded_guilds.txt"

def _read_excluded_guild_ids() -> set[int]:
    """Reads all excluded guild IDs from the text file into a set."""
    if not os.path.exists(CLEANUP_EXCLUSION_FILE):
        return set()
    
    with open(CLEANUP_EXCLUSION_FILE, "r") as f:
        # Read lines, strip whitespace, and convert to int
        # Use a set to handle potential duplicates and for fast lookups
        return {int(line.strip()) for line in f if line.strip().isdigit()}
    
def _write_excluded_guild_ids(guild_ids: set[int]):
    """Writes the set of excluded guild IDs back to the text file."""
    with open(CLEANUP_EXCLUSION_FILE, "w") as f:
        for guild_id in sorted(list(guild_ids)): # Write in sorted order for consistency
            f.write(f"{guild_id}\n")

def add_guild_to_cleanup_exclusion(guild_id: int) -> bool:
    """Adds a guild ID to the cleanup exclusion list. Returns True if added, False if already present."""
    excluded_ids = _read_excluded_guild_ids()
    if guild_id in excluded_ids:
        return False # Already present
    
    excluded_ids.add(guild_id)
    _write_excluded_guild_ids(excluded_ids)
    return True

def remove_guild_from_cleanup_exclusion(guild_id: int) -> bool:
    """Removes a guild ID from the cleanup exclusion list. Returns True if removed, False if not found."""
    excluded_ids = _read_excluded_guild_ids()
    if guild_id not in excluded_ids:
        return False # Not found
    
    excluded_ids.remove(guild_id)
    _write_excluded_guild_ids(excluded_ids)
    return True

def get_excluded_guild_ids() -> list[int]:
    """Returns a list of all guild IDs currently excluded from cleanup."""
    return sorted(list(_read_excluded_guild_ids()))

def is_guild_excluded_from_cleanup(guild_id: int) -> bool:
    """Checks if a guild ID is in the cleanup exclusion list."""
    return guild_id in _read_excluded_guild_ids()

