def setup_premium_db():
    conn = sqlite3.connect("premium.db")
    cursor = conn.cursor()

    cursor.execute("""
        CREATE TABLE IF NOT EXISTS premium (
            server_id INTEGER,
            achievement_name TEXT,
            count INTEGER DEFAULT 1,
            PRIMARY KEY (server_id, achievement_name)
        );
    """)
    
    conn.commit()
    conn.close()

def is_guild_premium(guild_id: int) -> bool:
    try:
        with open("war_premium.txt", "r") as f:
            premium_ids = {line.strip() for line in f if line.strip().isdigit()}
        return str(guild_id) in premium_ids
    except FileNotFoundError:
        return False
    except Exception as e:
        print(f"Premium file read error: {e}")
        return False

def get_war_background_db():
    return sqlite3.connect("war_background.db")

def setup_war_background_db():
    with get_war_background_db() as conn:
        c = conn.cursor()
        c.execute("""
            CREATE TABLE IF NOT EXISTS war_backgrounds (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                url TEXT NOT NULL,
                is_premium INTEGER DEFAULT 0
            )
        """)
        c.execute("""
            CREATE TABLE IF NOT EXISTS guild_war_background (
                guild_id INTEGER PRIMARY KEY,
                background_id INTEGER,
                custom_url TEXT,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """)
        conn.commit()

def get_guild_war_background(guild_id: int) -> tuple[int | None, str | None]:
    with get_war_background_db() as conn:
        c = conn.cursor()
        c.execute(
            "SELECT background_id, custom_url FROM guild_war_background WHERE guild_id = ?",
            (guild_id,)
        )
        row = c.fetchone()
        if row:
            return row[0], row[1]
    return None, None

def get_war_background_url(guild_id: int) -> str | None:
    bg_id, custom_url = get_guild_war_background(guild_id)
    if custom_url:
        return custom_url
    if bg_id is None:
        return None
    with get_war_background_db() as conn:
        c = conn.cursor()
        c.execute("SELECT url FROM war_backgrounds WHERE id = ?", (bg_id,))
        row = c.fetchone()
        return row[0] if row else None

def set_guild_war_background(guild_id: int, background_id: int | None, custom_url: str | None):
    with get_war_background_db() as conn:
        c = conn.cursor()
        c.execute(
            """
            INSERT OR REPLACE INTO guild_war_background
            (guild_id, background_id, custom_url, updated_at)
            VALUES (?, ?, ?, CURRENT_TIMESTAMP)
            """,
            (guild_id, background_id, custom_url)
        )
        conn.commit()

setup_war_background_db()

class BannerSelect(Select):
    def __init__(self, banners, guild_id, is_premium_guild):
        options = []
        for banner_id, name, is_premium in banners:
            label = f"{name}{' (Premium)' if is_premium else ''}"
            disabled = is_premium and not is_premium_guild
            options.append(discord.SelectOption(
                label=label[:100],
                value=str(banner_id),
                description=f"ID: {banner_id}",
                emoji="🛡️" if not is_premium else "✨",
                default=False
            ))
        super().__init__(
            placeholder="Select a war banner to equip...",
            min_values=1,
            max_values=1,
            options=options,
            disabled=len(options) == 0
        )
        self.guild_id = guild_id

    async def callback(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.manage_guild:
            await interaction.response.send_message(
                "Only members with **Manage Server** permission can equip banners.",
                ephemeral=True
            )
            return

        banner_id = int(self.values[0])
        db = get_db()
        c = db.cursor()

        c.execute("SELECT is_premium FROM war_banners WHERE banner_id = ?", (banner_id,))
        row = c.fetchone()
        if not row:
            await interaction.response.send_message("Banner not found.", ephemeral=True)
            return

        is_premium_banner = row[0]

        if is_premium_banner:
            # Your current premium check from war_premium.txt
            is_premium_guild = False
            try:
                with open("war_premium.txt", "r", encoding="utf-8") as f:
                    premium_ids = {line.strip() for line in f if line.strip().isdigit()}
                is_premium_guild = str(self.guild_id) in premium_ids
            except FileNotFoundError:
                pass
            except Exception as e:
                print(f"Premium file error in callback: {e}")

            if not is_premium_guild:
                await interaction.response.send_message(
                    "This banner requires **premium access**.\nYour server doesn't have it yet.",
                    ephemeral=True
                )
                return

        # Equip
        c.execute("""
            INSERT OR REPLACE INTO guild_active_war_banner
            (guild_id, banner_id, equipped_at)
            VALUES (?, ?, CURRENT_TIMESTAMP)
        """, (self.guild_id, banner_id))
        db.commit()

        await interaction.response.send_message(
            f"✅ Banner equipped successfully! (ID: {banner_id})",
            ephemeral=True
        )


class WarBackgroundSelect(Select):
    def __init__(self, view: "WarBackgroundView", backgrounds, is_premium_guild: bool):
        options = []
        current_bg_id, current_custom = view.current_bg_id, view.current_custom_url
        prem_id = []
        for bg_id, url, is_premium in backgrounds:
            disabled = bool(is_premium) and not is_premium_guild
            label = f"Background {bg_id}"
            description = "Premium" if is_premium else "Free"
            options.append(discord.SelectOption(
                label=label[:100],
                value=str(bg_id),
                description=description,
                emoji="✨" if is_premium else "🖼️",
                default=(current_bg_id == bg_id and not current_custom)
            ))
            if is_premium:
                prem_id.append(bg_id)
        
        options.append(discord.SelectOption(
            label="Add your own",
            value="custom",
            description="Use a link to your image",
            emoji="➕",
            default=bool(current_custom)
        ))
        super().__init__(
            placeholder="Select a war background...",
            min_values=1,
            max_values=1,
            options=options,
            disabled=len(options) == 0
        )
        self.view_ref = view
        self.is_premium_guild = is_premium_guild
        self.prem_id = prem_id

    async def callback(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.manage_guild:
            await interaction.response.send_message(
                "Only members with **Manage Server** permission can set war backgrounds.",
                ephemeral=True
            )
            return

        choice = self.values[0]
        if choice == "custom" and not self.is_premium_guild:
            await interaction.response.send_message("Get Goldi Premium through `!donate` to add this background")
            return
        elif choice == "custom" and self.is_premium_guild:
            await interaction.response.send_message(
                "Upload a **GIF** to use as the war background (must be an attachment).",
                ephemeral=True
            )

            def check(m: discord.Message):
                return (
                    m.author.id == interaction.user.id
                    and m.channel.id == interaction.channel.id
                    and m.attachments
                )

            try:
                msg = await interaction.client.wait_for("message", timeout=60, check=check)
            except asyncio.TimeoutError:
                await interaction.followup.send("❌ Timeout: no attachment received.", ephemeral=True)
                return

            attachment = msg.attachments[0]
            if not attachment.filename.lower().endswith(".gif") and not attachment.filename.lower().endswith(".png"):
                await interaction.followup.send("❌ Only GIF or PNG attachments are allowed.", ephemeral=True)
                return

            # Use the Discord CDN URL directly
            link = attachment.url
            set_guild_war_background(interaction.guild_id, None, link)
            self.view_ref.current_bg_id = None
            self.view_ref.current_custom_url = link

        else:
            bg_id = int(choice)
            if bg_id in self.prem_id and not self.is_premium_guild:
                await interaction.response.send_message("Get Goldi Premium through `!donate` to add this background")
                return
            set_guild_war_background(interaction.guild_id, bg_id, None)
            self.view_ref.current_bg_id = bg_id
            self.view_ref.current_custom_url = None

        self.view_ref.refresh_layout()
        await interaction.message.edit(view=self.view_ref)

from discord.ui import MediaGallery
from discord import MediaGalleryItem
class WarBackgroundView(LayoutView):
    def __init__(self, ctx: commands.Context):
        super().__init__(timeout=180)
        self.ctx = ctx
        self.guild_id = ctx.guild.id
        self.is_premium_guild = is_guild_premium(self.guild_id)
        self.backgrounds = []
        self.current_bg_id, self.current_custom_url = get_guild_war_background(self.guild_id)
        self.refresh_layout()

    def _load_backgrounds(self):
        with get_war_background_db() as conn:
            c = conn.cursor()
            c.execute("SELECT id, url, is_premium FROM war_backgrounds ORDER BY id ASC")
            self.backgrounds = c.fetchall()

    def refresh_layout(self):
        self.clear_items()
        self._load_backgrounds()

        container = Container()
        container.add_item(TextDisplay(f"# {self.ctx.guild.name} war background"))
        container.add_item(TextDisplay("—" * 22))

        select_row = ActionRow()
        select_row.add_item(WarBackgroundSelect(self, self.backgrounds, self.is_premium_guild))
        container.add_item(select_row)

        current_url = self.current_custom_url or (
            next((u for (i, u, _) in self.backgrounds if i == self.current_bg_id), None)
        )
        if current_url:
            container.add_item(MediaGallery(
                MediaGalleryItem(current_url)
            ))
        else:
            container.add_item(TextDisplay("_No war background set._"))

        container.add_item(
            TextDisplay("Use the dropdown above to set the war background for this server.\n**For Premium Servers:** Make sure you upload a .gif attachment for custom")
        )
        self.add_item(container)
@bot.command(name="admin_upload_background")
async def admin_upload_background(ctx: commands.Context, tier: str = None):
    if ctx.author.id not in owner_ids:
        return await ctx.send("Only owner can use this command.")

    # --- Handle tier ---
    tier_key = str(tier or "").strip().lower()
    if tier_key not in {"free", "premium"}:
        return await ctx.send(
            "Usage: `!admin_upload_background <free|premium>` + attach a file (GIF/MP4)."
        )

    # --- Ensure there is an attachment ---
    if not ctx.message.attachments:
        return await ctx.send("❌ Please attach a GIF or MP4 file to upload.")

    attachment = ctx.message.attachments[0]
    if not any(attachment.filename.lower().endswith(ext) for ext in [".gif", ".png"]):
        return await ctx.send("❌ Only GIF or MP4 files are allowed.")

    link = attachment.url  # ✅ Discord CDN link

    is_premium = 1 if tier_key == "premium" else 0

    with get_war_background_db() as conn:
        c = conn.cursor()
        c.execute(
            "INSERT INTO war_backgrounds (url, is_premium) VALUES (?, ?)",
            (link, is_premium)
        )
        conn.commit()

    await ctx.send(f"✅ War background uploaded.\n{link}")

@bot.command(name="equipbanner")
@commands.guild_only()
@commands.has_permissions(manage_guild=True)
async def equip_banner(ctx: commands.Context):
    """
    Show available war banners in a dropdown and let server admins equip one.
    Usage: !equipbanner
    """
    db = get_db()           # your main / per-guild db
    c = db.cursor()

    try:
        # Fetch all banners
        c.execute("""
            SELECT banner_id, name, is_premium
            FROM war_banners
            ORDER BY name ASC
        """)
        banners = c.fetchall()

        if not banners:
            await ctx.send("No war banners are available yet.")
            return

        # Check if this guild is premium using war_premium.txt
        is_premium_guild = False
        try:
            with open("war_premium.txt", "r", encoding="utf-8") as f:
                premium_ids = {line.strip() for line in f if line.strip().isdigit()}
            is_premium_guild = str(ctx.guild.id) in premium_ids
        except FileNotFoundError:
            # File doesn't exist → no premium guilds
            pass
        except Exception as read_error:
            print(f"Error reading war_premium.txt: {read_error}")

        # Current equipped banner
        c.execute("""
            SELECT b.name, b.is_premium
            FROM guild_active_war_banner e
            JOIN war_banners b ON e.banner_id = b.banner_id
            WHERE e.guild_id = ?
        """, (ctx.guild.id,))
        current = c.fetchone()

        embed = discord.Embed(
            title="War Banner Selection",
            color=discord.Color.blue(),
            description="Choose a banner from the dropdown to equip it server-wide."
        )

        if current:
            name, is_prem = current
            status = " (Premium)" if is_prem else ""
            embed.add_field(
                name="Currently Equipped",
                value=f"**{name}**{status}",
                inline=False
            )
        else:
            embed.add_field(name="Currently Equipped", value="None", inline=False)

        embed.set_footer(text="Only Manage Server permission can change • Dropdown expires in 2 minutes")

        view = View(timeout=120)
        view.add_item(BannerSelect(banners, ctx.guild.id, is_premium_guild))

        await ctx.send(embed=embed, view=view)

    except Exception as e:
        await ctx.send("An error occurred while loading banners.")
        print(f"Equip banner error: {e}")
    
