@bot.command(name="uploadbanner", aliases=["addbanner", "uploadglobal"])
@commands.check(lambda ctx: ctx.author.id == ALLOWED_USER_ID)
async def upload_global_banner(ctx: commands.Context, *, args: str = None):
    """
    Upload global war banner (owner only)
    !uploadbanner "Banner Name"
    !uploadbanner "Banner Name" premium
    Attach an image file.
    """
    is_premium = False
    name = args

    if args and args.lower().endswith(" premium"):
        is_premium = True
        name = args[:-8].strip() or None

    if not ctx.message.attachments:
        await ctx.send(
            "Please attach an image file.\n\n"
            f"Examples:\n"
            f"!uploadbanner \"My Banner\"\n"
            f"!uploadbanner \"Elite Banner\" premium"
        )
        return

    attachment = ctx.message.attachments[0]

    if not attachment.content_type or not attachment.content_type.startswith("image/"):
        await ctx.send("Only image files allowed (png, jpg, jpeg, gif, webp).")
        return

    if attachment.size > 8 * 1024 * 1024:
        await ctx.send("File too large (max 8 MB recommended).")
        return

    # Safe filename
    ext = attachment.filename.rsplit('.', 1)[-1].lower() if '.' in attachment.filename else 'png'
    safe_name = (name or "unnamed").strip().replace(" ", "_")[:40]
    filename = f"{safe_name}_{ctx.message.id}.{ext}"

    # Local backup (optional but recommended)
    local_path = os.path.join(BANNERS_FOLDER, filename)
    await attachment.save(local_path)

    # ────────────────────────────────
    # Upload to logging channel → get permanent CDN URL
    # ────────────────────────────────
    log_channel = bot.get_channel(LOG_CHANNEL_ID)
    if not log_channel:
        await ctx.send("Error: Logging channel not found. Cannot upload banner.")
        return

    try:
        upload_msg = await log_channel.send(
            content=f"Banner upload | Name: {name or 'Unnamed'} | Premium: {is_premium} | By {ctx.author} ({ctx.author.id})",
            file=discord.File(local_path, filename=filename)
        )
        stored_url = upload_msg.attachments[0].url   # ← This is the public HTTPS URL you need!
    except discord.HTTPException as e:
        await ctx.send(f"Failed to upload to log channel: {e}")
        return

    # ── Database part ──
    db = get_db()
    c = db.cursor()

    try:
        c.execute("""
            INSERT INTO war_banners
            (name, description, image_url, is_premium, created_by_user_id, created_at)
            VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
        """, (
            name or f"Banner {ctx.message.id}",
            None,  # description - add input later if needed
            stored_url,          # ← now public URL
            1 if is_premium else 0,
            ctx.author.id
        ))

        banner_id = c.lastrowid
        db.commit()

        status = "Premium" if is_premium else "Regular"
        embed = discord.Embed(
            title=f"Global {status} Banner Uploaded",
            color=0xe91e63 if is_premium else 0x2ecc71,
            description=(
                f"**Name:** {name or 'Unnamed'}\n"
                f"**ID:** `{banner_id}`\n"
                f"**URL:** {stored_url}\n"
                f"**Local backup:** `{filename}`"
            )
        )
        embed.set_image(url=stored_url)  # ← preview right away
        await ctx.send(embed=embed)

    except Exception as e:
        db.rollback()
        await ctx.send(f"Error saving to database: {str(e)}")
        print(f"Upload error: {e}")

    finally:
        if db:
            db.close()  # only if your get_db() opens new connection each time   

