@bot.tree.command(name="premium_toggle", description="Add or remove a premium")
@app_commands.describe(guild_id="The ID of the guild to exclude (defaults to current guild if in one).") 
@app_commands.autocomplete(category=autocomplete_premium)
@app_commands.choices(action= [app_commands.Choice(name = 'Add', value = 'add'),
                              app_commands.Choice(name = 'Remove', value = 'remove')])
async def add_guild_i(interaction: discord.Interaction, category: str, action: app_commands.Choice[str], guild_id: str = None):
    if not interaction.guild and not guild_id:
        await interaction.response.send_message("Please provide a guild ID or use this command inside a server.", ephemeral=True)
        return

    if interaction.user.id not in bot.owner_ids:
        await interaction.response.send_message("Please join support server for more info (/bot_info)", ephemeral=True)
        return

    target_guild_id = int(guild_id) if guild_id else interaction.guild.id

    if action.value == "add":
        if category == "Invite":
            if add_guild_to_cleanup_exclusion(target_guild_id):
                await interaction.response.send_message(
                    f"Guild `{target_guild_id}` has been added to the cleanup exclusion list. "
                    "Its rejoin data files will no longer be automatically deleted.",
                    ephemeral=False
                )
            else:
                await interaction.response.send_message(
                    f"Guild `{target_guild_id}` is already excluded from cleanup.",
                    ephemeral=True
                )
            return

        if category == "war":
            file = "war_premium.txt"
            existing_ids = set()
            if os.path.exists(file):
                with open(file, "r", encoding="utf-8") as f:
                    existing_ids = {line.strip() for line in f if line.strip()}

            if str(target_guild_id) in existing_ids:
                await interaction.response.send_message(f"Guild `{target_guild_id}` already has war premium.", ephemeral=True)
                return

            existing_ids.add(str(target_guild_id))
            with open(file, "w", encoding="utf-8") as f:
                for gid in sorted(existing_ids, key=int):
                    f.write(f"{gid}\n")
            await interaction.response.send_message("Premium added", ephemeral=False)
            return

        if category == "giveaway and vouch":
            folder = "last_gw"
            os.makedirs(folder, exist_ok=True)
            file_path = os.path.join(folder, f"{target_guild_id}.json")
            data = {
                "last_gw_value": 0,
                "last_gw_timestamp": datetime.now(timezone.utc).isoformat()
            }
            with open(file_path, "w", encoding="utf-8") as f:
                json.dump(data, f, indent=4)
            await interaction.response.send_message(
                f"Guild `{target_guild_id}` has been added to premium.",
                ephemeral=False
            )
            return

        conn = sqlite3.connect("premium.db")
        cursor = conn.cursor()
        cursor.execute(
            """
            INSERT INTO premium (server_id, achievement_name, count)
            VALUES (?, ?, 1)
            ON CONFLICT(server_id, achievement_name)
            DO UPDATE SET count = count + 1;
            """,
            (target_guild_id, category),
        )
        conn.commit()
        conn.close()
        await interaction.response.send_message(
            f"Guild `{target_guild_id}` has been added to the partner list.",
            ephemeral=False
        )
        return
    else:
        if category == "Invite":
            if remove_guild_from_cleanup_exclusion(target_guild_id):
                await interaction.response.send_message(
                    f"Guild `{target_guild_id}` has been removed from the cleanup exclusion list. "
                    "Its rejoin data files will now be subject to the 14-day cleanup.",
                    ephemeral=False
                )
            else:
                await interaction.response.send_message(
                    f"Guild `{target_guild_id}` is not currently excluded from cleanup.",
                    ephemeral=True
                )
            return

        if category == "war":
            file = "war_premium.txt"
            if not os.path.exists(file):
                await interaction.response.send_message(f"Guild `{target_guild_id}` does not have war premium.", ephemeral=True)
                return
            with open(file, "r", encoding="utf-8") as f:
                existing_ids = {line.strip() for line in f if line.strip()}
            if str(target_guild_id) not in existing_ids:
                await interaction.response.send_message(f"Guild `{target_guild_id}` does not have war premium.", ephemeral=True)
                return
            existing_ids.remove(str(target_guild_id))
            with open(file, "w", encoding="utf-8") as f:
                for gid in sorted(existing_ids, key=int):
                    f.write(f"{gid}\n")
            await interaction.response.send_message("Premium removed", ephemeral=False)
            return

        if category == "giveaway and vouch":
            file_path = os.path.join("last_gw", f"{target_guild_id}.json")
            if os.path.exists(file_path):
                os.remove(file_path)
                await interaction.response.send_message(
                    f"Guild `{target_guild_id}` has been removed from giveaway and vouch premium.",
                    ephemeral=False
                )
            else:
                await interaction.response.send_message(
                    f"Guild `{target_guild_id}` does not have giveaway and vouch premium.",
                    ephemeral=True
                )
            return

        conn = sqlite3.connect("premium.db")
        cursor = conn.cursor()
        cursor.execute(
            """
            SELECT count FROM premium
            WHERE server_id = ? AND achievement_name = ?;
            """,
            (target_guild_id, category),
        )
        result = cursor.fetchone()

        if result is None:
            conn.close()
            await interaction.response.send_message(
                f"No `{category}` premium entry found for guild `{target_guild_id}`.",
                ephemeral=True
            )
            return

        if result[0] > 1:
            cursor.execute(
                """
                UPDATE premium
                SET count = count - 1
                WHERE server_id = ? AND achievement_name = ?;
                """,
                (target_guild_id, category),
            )
        else:
            cursor.execute(
                """
                DELETE FROM premium
                WHERE server_id = ? AND achievement_name = ?;
                """,
                (target_guild_id, category),
            )

        conn.commit()
        conn.close()
        await interaction.response.send_message("Premium removed", ephemeral=False)

def delete_guild_invite_data_from_db(guild_id: int):
    """Deletes all invite_stats records for a given guild."""
    conn = sqlite3.connect('invite_stats.db')
    cursor = conn.cursor()
    try:
        cursor.execute("DELETE FROM invite_stats WHERE guild_id = ?", (guild_id,))
        conn.commit()
        print(f"Deleted all invite_stats data for guild ID: {guild_id}")
        return True
    except sqlite3.Error as e:
        print(f"Error deleting invite_stats for guild {guild_id}: {e}")
        conn.rollback()
        return False
    finally:
        conn.close()
def get_total_invites_for_guild(guild_id: int) -> int:
    conn = sqlite3.connect('invite_stats.db')
    cursor = conn.cursor()
    total = 0
    try:
        # Sum the lengths of all 'invites' lists for the given guild
        cursor.execute("SELECT invites FROM invite_stats WHERE guild_id = ?", (guild_id,))
        rows = cursor.fetchall()
        for row in rows:
            if row[0]:
                try:
                    invites_list = json.loads(row[0])
                    total += len(invites_list)
                except json.JSONDecodeError:
                    print(f"Warning: Could not decode invites JSON for guild {guild_id}, row: {row[0]}")
    except sqlite3.Error as e:
        print(f"Error getting total invites for guild {guild_id}: {e}")
    finally:
        conn.close()
    return total
from typing import Optional
class DeleteDataView(View):
    def __init__(self, guild_id: int, original_message_id: Optional[int] = None):
        super().__init__(timeout=None) # Set timeout=None for persistence
        self.guild_id = guild_id
        self.original_message_id = original_message_id # To update the specific message

    @discord.ui.button(label="Delete Server Invite Data", style=discord.ButtonStyle.red, 
                       custom_id="delete_invite_data_placeholder") 
    async def delete_data_button_callback(self, interaction: discord.Interaction, button: Button):

        target_guild_id = int(self.guild_id)
        if not interaction.user.guild_permissions.administrator:
            await interaction.response.send_message(
                "You have admin permission to purge data (contact a senior manager)", ephemeral=True
            )
            return

        await interaction.response.defer(ephemeral=True) 
        success = delete_guild_invite_data_from_db(target_guild_id)

        log_channel = bot.get_channel(int(LOG_CHANNEL_ID_STR))
        
        if success:
            response_msg = f"✅ Successfully deleted all invite data for guild ID `{target_guild_id}`."
            if log_channel:
                await log_channel.send(f"⚠️ **Invite Data Purged:** {interaction.user.mention} deleted invite data for guild ID `{target_guild_id}` via button.")
        else:
            response_msg = f"❌ Failed to delete invite data for guild ID `{target_guild_id}`. Check bot console for errors."
            if log_channel:
                await log_channel.send(f"🚨 **Invite Data Purge Failed:** {interaction.user.mention} attempted to delete data for guild ID `{target_guild_id}` but it failed.")
        button.disabled = True
        button.label = "Data Deleted" if success else "Deletion Failed"
        button.style = discord.ButtonStyle.gray
        await interaction.followup.send(response_msg, ephemeral=True)

