def get_task_identifier(task_obj: tasks.Loop) -> str:
    """
    Safely attempts to get a unique identifier for a tasks.Loop object.
    It tries various attributes in a preferred order.
    """
    # Option 1: Official 'name' attribute (preferred for tasks.Loop objects)
    # This should now work if your 2.4.0 installation is fully functional.
    if hasattr(task_obj, 'name') and task_obj.name is not None:
        return task_obj.name

    # Option 2: Name of the underlying coroutine function (very common and reliable fallback)
    # The 'coro' attribute points to the original async function decorated.
    if hasattr(task_obj, 'coro') and hasattr(task_obj.coro, '__name__') and task_obj.coro.__name__:
        return task_obj.coro.__name__

    # Option 3: Name of the 'callback' function (often same as coro, but a good alternative)
    # This was the one previously causing issues, but included for completeness in a chain.
    if hasattr(task_obj, 'callback') and hasattr(task_obj.callback, '__name__') and task_obj.callback.__name__:
        return task_obj.callback.__name__
    
    # Fallback: If no proper name can be found, generate a unique string.
    # This is a last resort. If this happens, persistence might not work reliably
    # as the identifier could change on bot restarts.
    print(f"WARNING: Could not find a stable identifier for task object: {task_obj}. Using a generated fallback string.")
    return f"unnamed_task_{id(task_obj)}_{datetime.now().timestamp()}"


def save_task_schedules(tasks_to_save: list[tasks.Loop]):
    """
    Saves the next scheduled run time for specified tasks to a JSON file.
    Uses get_task_identifier for robust identification.
    Overwrites the file if it exists, or creates it if it doesn't.
    """
    data = {}
    for task_obj in tasks_to_save:
        task_identifier = get_task_identifier(task_obj)
        if task_obj.next_iteration:
            data[task_identifier] = task_obj.next_iteration.astimezone(timezone.utc).isoformat()

    try:
        # Overwrite or create the file
        with open(SCHEDULE_FILE, 'w') as f:
            json.dump(data, f, indent=4)

        print("Task schedules saved successfully.")
    except Exception as e:
        print(f"Error saving task schedules: {e}")

def load_task_schedules() -> dict[str, datetime]:
    """
    Loads the next scheduled run times from the JSON file.
    """
    if not os.path.exists(SCHEDULE_FILE):
        return {} 

    try:
        with open(SCHEDULE_FILE, 'r') as f:
            data = json.load(f)
        
        loaded_schedules = {}
        for task_identifier, iso_time_str in data.items():
            # Convert ISO string back to a datetime object, ensuring it's timezone-aware UTC.
            loaded_schedules[task_identifier] = datetime.fromisoformat(iso_time_str).astimezone(timezone.utc)
        print("Task schedules loaded.")
        return loaded_schedules
    except Exception as e:
        print(f"Error loading task schedules: {e}")
        return {} 

def start_persistent_task(task_obj: tasks.Loop, loaded_schedules: dict[str, datetime], current_utc_time: datetime, default_initial_delay_seconds: int = 0):
    """
    Starts a discord.ext.tasks.Loop object, attempting to resume its schedule
    from a previously loaded state.
    Uses get_task_identifier for robust identification.
    """
    # Get the identifier using our new helper function
    task_identifier = get_task_identifier(task_obj) 

    # If the identifier is a generic fallback, issue a warning for debugging.
    if task_identifier.startswith("unnamed_task_"):
        print(f"WARNING: Task {task_obj} could not be identified properly. Persistence might not work reliably for it, as its identifier may change between restarts.")
    
    if not task_obj.is_running():
        next_run_time_obj = loaded_schedules.get(task_identifier)
        
        initial_delay = default_initial_delay_seconds

        if next_run_time_obj:
            time_difference_seconds = (next_run_time_obj - current_utc_time).total_seconds()
            
            if time_difference_seconds > 0:
                initial_delay = time_difference_seconds
                print(f"Scheduling '{task_identifier}' to run in {initial_delay:.2f} seconds based on saved schedule.")
            else:
                initial_delay = 0
                print(f"Task '{task_identifier}' was past due ({abs(time_difference_seconds):.0f}s). Running immediately then resuming normal interval.")
        else:
            print(f"No saved schedule found for '{task_identifier}'. Starting with default initial delay of {initial_delay:.2f} seconds.")
        
        task_obj.start()
    else:
        print(f"Task '{task_identifier}' is already running.")
