@bot.tree.error
async def on_app_command_error(interaction: discord.Interaction, error: discord.app_commands.AppCommandError):
    command_name = getattr(interaction.command, "qualified_name", None) or getattr(interaction.command, "name", None) or str((interaction.data or {}).get("name", "<unknown>"))
