@bot.tree.command(name="timestamp", description="Generate a timestamp")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
@app_commands.describe(time="Time until timestamp time. E.g 1d10h8m59s")
async def timestamp(interaction: discord.Interaction, time: str):
    try:
        seconds = parse_time_string(time)
        now = datetime.now(timezone.utc)
        future = now + timedelta(seconds=seconds)
        unix_ts = int(future.timestamp())
        formats = {
            "f": "Short Date/Time",
            "F": "Long Date/Time",
            "d": "Short Date",
            "D": "Long Date",
            "t": "Short Time",
            "T": "Long Time",
            "R": "Relative Time"
        }
        embed = discord.Embed(
            title="📅 Discord Timestamp Formats",
            description=f"Time in `{time}` from now (`{future.strftime('%Y-%m-%d %H:%M:%S')} UTC`):",
            color=discord.Color.blurple()
        )
        for fmt, label in formats.items():
            tag = f"<t:{unix_ts}:{fmt}>"
            embed.add_field(name=f"`{label}`", value=f"{tag}", inline=False)
        await interaction.response.send_message(embed=embed)
    except Exception as e:
        await interaction.response.send_message(f"❌ Error: {e}", ephemeral=True)

# Uno
import time
import io
def create_uno_card_image(number: str, color: str) -> io.BytesIO:
    width, height = 300, 300
    card = Image.new("RGBA", (width, height), color=color)

    # --- Create a rotated white ellipse base ---
    ellipse_w, ellipse_h = int(width * 0.8), int(height * 0.5)
    ellipse = Image.new("RGBA", (ellipse_w, ellipse_h), (0, 0, 0, 0))
    ellipse_draw = ImageDraw.Draw(ellipse)
    ellipse_draw.ellipse((0, 0, ellipse_w, ellipse_h), fill=(255, 255, 255, 255))  # solid white

    rotated_ellipse = ellipse.rotate(45, expand=True)  # rotate 45 degrees
    ex, ey = rotated_ellipse.size
    ellipse_pos = ((width - ex) // 2, (height - ey) // 2)
    card.paste(rotated_ellipse, ellipse_pos, rotated_ellipse)

    draw = ImageDraw.Draw(card)
    font_size = int(height * 0.5)
    font_path = os.path.join("fonts", "ComicNeue-Bold.ttf")
    try:
        font = ImageFont.truetype(font_path, font_size)
    except:
        #print("Fallback to default font")
        font = ImageFont.load_default()

    if number == 'reverse':
        try:
            reverse_icon_path = 'reverse.png'
            reverse_icon = Image.open(reverse_icon_path).convert("RGBA")
            icon_size = (180, 180)
            reverse_icon = reverse_icon.resize(icon_size, Image.Resampling.LANCZOS)
            padding = 57
            position = (width - icon_size[0] - padding, height - icon_size[1] - padding)
            card.paste(reverse_icon, position, reverse_icon)
        except Exception as e:
            print(f"Failed to load/paste reverse icon: {e}")

    elif number == 'wild':
        # Draw smaller rotated ellipse overlay with 4 colored quarters

        # Bounding box for smaller ellipse (inside rotated white base)
        inset = 70
        bbox_inner = [ellipse_pos[0] + inset, ellipse_pos[1] + inset, ellipse_pos[0] + ex - inset, ellipse_pos[1] + ey - inset]

        # We'll draw 4 colored pie slices on the smaller ellipse
        colors = ["red", "blue", "green", "yellow"]
        start_angle = 0

        # Create a mask for the pie slices on transparent background
        pie_mask = Image.new("RGBA", (width, height), (0, 0, 0, 0))
        pie_draw = ImageDraw.Draw(pie_mask)

        for c in colors:
            pie_draw.pieslice(bbox_inner, start=start_angle, end=start_angle + 90, fill=c)
            start_angle += 90

        # Paste the colored pie slices on the card
        border_width = 8
        draw.rectangle([(0, 0), (width, height)], outline="white", width=border_width)
        card = Image.alpha_composite(card, pie_mask)

    elif number == '+4':
        try:
            reverse_icon_path = '+4.png'
            reverse_icon = Image.open(reverse_icon_path).convert("RGBA")
            icon_size = (140, 140)
            reverse_icon = reverse_icon.resize(icon_size, Image.Resampling.LANCZOS)
            padding = 77
            position = (width - icon_size[0] - padding, height - icon_size[1] - padding)
            card.paste(reverse_icon, position, reverse_icon)
        except Exception as e:
            print(f"Failed to load/paste reverse icon: {e}")

    elif number == 'block':
        try:
            reverse_icon_path = 'block.png'
            reverse_icon = Image.open(reverse_icon_path).convert("RGBA")
            icon_size = (140, 140)
            reverse_icon = reverse_icon.resize(icon_size, Image.Resampling.LANCZOS)
            padding = 77
            position = (width - icon_size[0] - padding, height - icon_size[1] - padding)
            card.paste(reverse_icon, position, reverse_icon)
        except Exception as e:
            print(f"Failed to load/paste reverse icon: {e}")
    
    elif number == '+2':
        try:
            reverse_icon_path = f'{color}_+2.png'
            reverse_icon = Image.open(reverse_icon_path).convert("RGBA")
            icon_size = (140, 140)
            reverse_icon = reverse_icon.resize(icon_size, Image.Resampling.LANCZOS)
            padding = 77
            position = (width - icon_size[0] - padding, height - icon_size[1] - padding)
            card.paste(reverse_icon, position, reverse_icon)
        except Exception as e:
            print(f"Failed to load/paste reverse icon: {e}")

    else:
        text = str(number)
        bbox = draw.textbbox((0, 0), text, font=font)
        text_width = bbox[2] - bbox[0]
        text_height = bbox[3] - bbox[1]
        x = (width - text_width) / 2 - 3
        y = (height - text_height) / 2 - 42
        draw.text((x, y), text, font=font, fill=color)

    # --- Optional border ---
    border_width = 8
    draw.rectangle([(0, 0), (width, height)], outline="white", width=border_width)

    # --- Save to buffer ---
    buffer = io.BytesIO()
    card.convert("RGB").save(buffer, format="PNG")
    buffer.seek(0)
    return buffer
def random_card():
    rand = random.randint(1, 108)
    if rand < 26:
        color = 'red'
    elif 25 < rand < 51:
        color = 'green'
    elif 50 < rand < 76:
        color = 'yellow'
    elif 75 < rand < 101:
        color = 'blue'
    elif 100 < rand < 109:
        color = 'black'

    if color == 'black':
        rand = random.randint(1,2)
        if rand == 1:
            number = '+4'
        if rand == 2:
            number = 'wild'
    else:
        number = random.randint(0, 12)
        if number == 10:
            number = 'block'
        elif number == 11:
            number = 'reverse'
        elif number == 12:
            number = '+2'
    return f'{color}_{number}'
class ConfirmJoinView(View):
    def __init__(self, author_id: int, player: discord.User, file_path: str):
        super().__init__(timeout=60)
        self.author_id = author_id
        self.player = player
        self.file_path = file_path
        self.result = None

    @discord.ui.button(label="Accept", style=discord.ButtonStyle.success)
    async def accept(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.player.id:
            await interaction.response.send_message("You're not the invited player!", ephemeral=True)
            return

        # Add to party file
        with open(self.file_path, 'a') as f:
            f.write(f"{self.player.id}\n")

        await interaction.response.edit_message(content=f"{self.player.name} has joined the party!", view=None)
        self.stop()

    @discord.ui.button(label="Decline", style=discord.ButtonStyle.danger)
    async def decline(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.player.id:
            await interaction.response.send_message("You're not the invited player!", ephemeral=True)
            return

        await interaction.response.edit_message(content=f"{self.player.name} declined the invite.", view=None)
        self.stop()
