    import traceback

    @app_commands.command(name="start", description="Play a game of uno")
    @app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
    @app_commands.user_install()
    @app_commands.guild_install()
    @app_commands.choices(
    mode=[
        app_commands.Choice(name='Classic', value='Classic'),
        app_commands.Choice(name='Pokemon', value='Pokemon')])
    async def uno_start(self, interaction: discord.Interaction, mode: str):
        try:
            print(f"UNO start command called by user {interaction.user} in guild {interaction.guild}")

            folder = 'uno'
            os.makedirs(folder, exist_ok=True)
            file_path = os.path.join(folder, f'{interaction.guild.id}.txt')
            print(f"Looking for file: {file_path}")

            if not os.path.exists(file_path):
                await interaction.response.send_message('Use `/uno join` first.')
                print("File not found, aborting.")
                return

            with open(file_path, 'r') as file:
                lines = file.readlines()
                user_cards = {}
                turn_order = []
                leader_id = lines[0].strip()
                print(f"Leader ID: {leader_id}, Command user ID: {interaction.user.id}")

                if not int(interaction.user.id) == int(leader_id):
                    await interaction.response.send_message(
                        'Only party leader can do this\nIf you are admin, please set yourself as party leader first `/uno set_leader`\nIf you are not, you can reset party first `/uno reset`',
                        ephemeral=True
                    )
                    print("User is not party leader, aborting.")
                    return

                for line in lines:
                    user_id = line.strip()
                    if user_id:
                        turn_order.append(user_id)
                        cards = [random_card() for _ in range(7)]
                        user_cards[user_id] = cards
                print(f"Turn order: {turn_order}")

            if mode == 'Pokemon':
                filepath = os.path.join("uno", f"{str(interaction.guild.id)}_pokemon.json")
                if not os.path.exists(filepath):
                    await interaction.response.send_message('Use `/uno set_pokemon` first.')
                    return
                else:
                    with open(filepath, "r") as f:
                        data = json.load(f)
                for line in lines:
                    user_id = line.strip()
                    name = f'{user_id}_uses'
                    poke_name = data.get(str(user_id)) 
                    if int(user_id) >0:
                        if poke_name is None:
                            await interaction.response.send_message(f'<@{user_id}> did not set a pokemon\n`/uno set_pokemon` to set one')
                            return
                    else:
                        continue
                    filepath2 = os.path.join("uno pokemon", f"{poke_name}.json")
                    with open(filepath2, "r") as f:
                        data2 = json.load(f)
                    data[name] = data2['limit']
                with open(filepath, "w") as f:
                    json.dump(data, f, indent=4)

            start_card = random_card()
            while start_card == 'black_wild' or start_card == 'black_+4':
                start_card = random_card()
            game_state = {
                "table": start_card,
            }
            game_state.update(user_cards)

            future_time = int(time.time()) + 3 * 60
            discord_timestamp = f"<t:{future_time}:R>"

            # Main game embed: show full order with card counts
            embed = build_game_embed(game_state, turn_order, game_state["table"], discord_timestamp)
            
            table_card = game_state["table"]
            color, number = table_card.split("_")
            buffer = create_uno_card_image(number, color)
            filename = f"{color}_{number}.png"
            file = discord.File(fp=buffer, filename=filename)
            embed.set_image(url=f"attachment://{filename}")

            thread = None
            channel = bot.get_channel(interaction.channel.id)
            if channel is None:
                pass
            else:
                thread = await interaction.channel.create_thread(
                    name="UNO Game Thread 🎮",
                    auto_archive_duration=60
                )
                print(f"Created thread: {thread.name}")
                mentions = " ".join(f"<@{uid}>" for uid in turn_order)
                await thread.send(f"🎉 UNO has started!\n{mentions}")
                print("Mentioned all players in the thread.")
            use_channel_send = False
            try:
                channel = bot.get_channel(interaction.channel.id)
                if channel is not None:
                    use_channel_send = True
            except Exception:
                channel = None
            if thread:
                view = UnoView(game_state, turn_order, mode, thread, channel)
            else:
                view = UnoView(game_state, turn_order, mode, None, None)
            # Send initial interaction response (private ack)
            #msg = await interaction.response.send_message(embed=embed, view=view, files=[file])
            #print("Sent initial game message (interaction response).")

            #sent_msg = await interaction.original_response()

            # Decide whether to use channel-send behaviour or keep editing the single message
            # channel is None >= keep same behaviour (edit original message). Otherwise, send messages in the same channel/thread.

            view.use_channel_send = use_channel_send
            # target where public updates are posted: prefer thread if present, else the original channel
            view.target = channel

            if view.use_channel_send and view.target is not None:
                # send a public main game message into the channel/thread and set that as the message reference
                public_msg = await view.target.send(embed=embed, view=view, files=[file])
                view.message = public_msg
                # close image buffer after sending to free memory
                try:
                    buffer.close()
                except Exception:
                    pass
                print("Sent public initial game message to channel/thread.")
            else:
                msg = await interaction.response.send_message(embed=embed, view=view, files=[file])
                sent_msg = await interaction.original_response()
                view.message = sent_msg
                # close image buffer after sending to free memory
            try:
                buffer.close()
            except Exception:
                pass
            
        except Exception as e:
            print(f"Error in uno_start command: {e}")
            traceback.print_exc()
            if not interaction.response.is_done():
                await interaction.response.send_message("An error occurred while starting the UNO game.", ephemeral=True)


