    @app_commands.command(name="set_leader", description="set leader for uno party")
    @app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
    @app_commands.user_install()
    @app_commands.guild_install()
    async def uno_set(self, interaction: discord.Interaction, player: discord.User):
            folder = 'uno'
            os.makedirs(folder, exist_ok=True)
            file_path = os.path.join(folder, f'{interaction.guild.id}.txt')
            if not os.path.exists(file_path):
                await interaction.response.send_message('Use `/uno join` first.')
                return
            else:
                chosen_id = str(player.id)
                with open(file_path, 'r') as f:
                    lines = [line.strip() for line in f if line.strip()]
                    leader_id = lines[0]
                if interaction.user.guild_permissions.administrator:
                    pass
                elif int(interaction.user.id) == int(leader_id):
                    pass
                else:
                    await interaction.response.send_message('Only party leader can do this\nIf you are admin, please set youself as party leader first', ephemeral=True)
                    return

                # Reorder so that chosen_id comes first
                if chosen_id in lines:
                    lines.remove(chosen_id)
                lines.insert(0, chosen_id)

                # Write back to file
                with open(file_path, 'w') as f:
                    f.write("\n".join(lines) + "\n")
                await interaction.response.send_message(f'<@{chosen_id} is now the party leader')

