    @app_commands.command(name="config", description="show a uno card")
    @app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
    @app_commands.user_install()
    @app_commands.guild_install()
    @app_commands.choices(
    allow=[
        app_commands.Choice(name='All pokemon', value='All pokemon'),
        app_commands.Choice(name='Unlocked in this server only', value='Unlocked in this server only')])
    @app_commands.autocomplete(ban=ban_autocomplete)
    async def uno_config(self, interaction: discord.Interaction, allow: str = None, ban: str = None):
        if not interaction.user.guild_permissions.administrator:
            await interaction.response.send_message('Only admin can do this', ephemeral = True)
            return
        guild_id = str(interaction.guild.id)
        os.makedirs(SERVER_POKEMON_DIR, exist_ok=True)
        file_path = os.path.join(SERVER_POKEMON_DIR, f"{guild_id}.json")

        # Load or create server config
        if os.path.exists(file_path):
            with open(file_path, "r") as f:
                data = json.load(f)
        else:
            data = {
                "available_pokemon": [],
                "allowed_pokemon": True,
                "banned_pokemon": []
            }
        if not allow:
            pass
        else:
            if allow == 'All pokemon':
                # Update allowed setting
                data["allowed_pokemon"] = True
            else:
                data["allowed_pokemon"] = False

        # Ban selected Pokémon
        if ban and ban not in data["banned_pokemon"]:
            data["banned_pokemon"].append(ban)

        with open(file_path, "w") as f:
            json.dump(data, f, indent=4)

        if data["allowed_pokemon"] == True:
            va = 'All pokemon set allowed'
        elif data["allowed_pokemon"] == False:
            va = 'Only those unlocked in this server or in the default pack is allowed'
        if data["banned_pokemon"]:
            vb = ''
            for i, poke in enumerate(data["banned_pokemon"]):
                vb += f'{i}. {poke}'
        else:
            vb = 'None'
        embed = discord.Embed(title="UNO Pokémon Config", color=discord.Color.green())
        embed.add_field(name="Allowed Pokémon", value=va, inline=False)
        embed.add_field(name="Banned Pokémon", value=vb, inline=False)
        await interaction.response.send_message(embed=embed)
