@bot.tree.command(name="instant_calc", description="Calculate move damage from your attacker to an opponent team")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
@app_commands.describe(
    attacker_name="The name of your Pokémon (e.g. Zacian)",
    opponent_field="Paste the full embed field value of the opponent's Pokémon"
)
async def instant_calc(interaction: discord.Interaction, attacker_name: str, opponent_field: str, visible:bool = False):
    await interaction.response.defer(ephemeral=not visible)

    # Parse opponent Pokémon from pasted field
    pattern = r"(?:<:\w+:\d+>\s*)?L\d+ \d+\.\d+% ([\w\s'-]+)<:\w+:\d+>"
    bold_pattern = r"\*\*(?:<:\w+:\d+>\s)?L\d+ \d+\.\d+% ([\w\s'-]+)<:\w+:\d+>\*\*"
    defenders = []

    for line in opponent_field.splitlines():
        match = re.search(pattern, line)
        if match:
            defenders.append(match.group(1))
        else:
            match = re.match(bold_pattern, line)
            if match:
                defenders.append(match.group(1))

    if not defenders:
        return await interaction.followup.send("❌ Could not detect any valid Pokémon names in the input.")

    # Check for moves file
    move_file = f"moves/{attacker_name.title()}_moves.txt"
    if not os.path.exists(move_file):
        alert_channel = bot.get_channel(int(LOG_CHANNEL_ID_STR))
        await alert_channel.send(f"❌ Move file not found for **{attacker_name.title()}**.")
        return await interaction.followup.send(f"❌ Move file not found for **{attacker_name.title()}**.")

    with open(move_file, "r") as f:
        moves = f.read().strip().split('/')

    for defender in defenders:
        embed_resp = discord.Embed(title=f"{attacker_name.title()} vs {defender}", color=discord.Color.blurple())
        for move in moves:
            try:
                _, base, _ = dmg_calc(move, attacker_name, defender)
                _, debuff, _ = dmg_calc(move, attacker_name, defender, def_debuff=1)
            except Exception as e:
                print(f"[ERROR] {move} - {e}")
                continue

            embed_resp.add_field(
                name=f"{move}",
                value=(
                    f"**Normal range:** {round(base*0.8)} / {round(base*0.9)} / {round(base)} / {round(base*1.1)} / {round(base*1.2)}\n"
                    f"**1 defense debuff:** {round(debuff*0.8)} / {round(debuff*0.9)} / {round(debuff)} / "
                    f"{round(debuff*1.1)} / {round(debuff*1.2)}"
                ),
                inline=False
            )

        await interaction.followup.send(embed=embed_resp, ephemeral=not visible)

@bot.command()
@commands.has_permissions(administrator=True)
async def calc_disable(ctx):
    guild_id = str(ctx.guild.id)
    file_path = "disabled.txt"

    # Create file if it doesn't exist
    if not os.path.exists(file_path):
        with open(file_path, "w") as f:
            pass

    with open(file_path, "r") as f:
        disabled_ids = [line.strip() for line in f]

    if guild_id in disabled_ids:
        return await ctx.send("❌ The calc command is already disabled in this server.")

    with open(file_path, "a") as f:
        f.write(f"{guild_id}\n")

    await ctx.send("✅ The calc command has been disabled in this server. (!calc_enable to turn it back on)")

@bot.command()
@commands.has_permissions(administrator=True)
async def calc_enable(ctx):
    guild_id = str(ctx.guild.id)
    file_path = "disabled.txt"

    if not os.path.exists(file_path):
        return await ctx.send("Calc is already enabled in this server.")

    with open(file_path, "r") as f:
        lines = [line.strip() for line in f]

    if guild_id not in lines:
        return await ctx.send("Calc is already enabled in this server.")

    with open(file_path, "w") as f:
        for line in lines:
            if line != guild_id:
                f.write(line + "\n")

    await ctx.send("✅ The calc command has been re-enabled.")

#gunslinger commands
import glob

GUN_FOLDER = "gunslinger"

# ---------- helpers ----------

def ensure_folder():
    os.makedirs(GUN_FOLDER, exist_ok=True)

def find_duel_file(user_id: int) -> str | None:
    """Return the first duel file that involves this user."""
    uid = str(user_id)
    files = glob.glob(os.path.join(GUN_FOLDER, f'{uid}vs*.json')) + \
            glob.glob(os.path.join(GUN_FOLDER, f'*vs{uid}.json'))
    return files[0] if files else None

def user_in_duel(user_id: int) -> bool:
    return find_duel_file(user_id) is not None

def duel_filename(a: int, b: int) -> str:
    """Consistently order ids so you never create two files for the same pair."""
    ensure_folder()
    a, b = sorted((a, b))
    return os.path.join(GUN_FOLDER, f'{a}vs{b}.json')

# ---------- view for confirmation ----------

class DuelConfirmView(discord.ui.View):
    def __init__(self, challenger: discord.Member, opponent: discord.Member, timeout: float = 60):
        super().__init__(timeout=timeout)
        self.challenger = challenger
        self.opponent = opponent
        self.result = None  # "accepted" / "declined" / None (timeout)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        # Only the opponent can press the buttons
        if interaction.user.id != self.opponent.id:
            await interaction.response.send_message("This isn't your duel request.", ephemeral=True)
            return False
        return True

    async def on_timeout(self):
        # Disable buttons on timeout
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True

    @discord.ui.button(label="Accept", style=discord.ButtonStyle.success)
    async def accept(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.result = "accepted"
        # Disable both buttons
        for child in self.children:
            child.disabled = True
        await interaction.response.edit_message(view=self)
        self.stop()

    @discord.ui.button(label="Decline", style=discord.ButtonStyle.danger)
    async def decline(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.result = "declined"
        for child in self.children:
            child.disabled = True
        await interaction.response.edit_message(view=self)
        self.stop()

# ---------- command ----------

@bot.command(name='duel', aliases=['gunslinger_start', 'gun_start', 'gunslinger'])
async def duel(ctx, arg: str = None):
    # Cancel path
    if arg and arg.lower() in ('x', 'cancel', 'stop'):
        filename = find_duel_file(ctx.author.id)
        if not filename:
            return await ctx.send("You don't have an active duel to cancel.")
        try:
            os.remove(filename)
        except OSError:
            pass
        return await ctx.send("Duel cancelled.")

    # Must provide opponent
    if not arg:
        return await ctx.send('Use `!duel @player` to challenge someone, or `!duel x` to cancel your duel.')

    # Try to resolve opponent as a mention or ID
    try:
        opponent = await commands.MemberConverter().convert(ctx, arg)
    except commands.MemberNotFound:
        return await ctx.send("Couldn't find that player.")

    if opponent.id == ctx.author.id:
        return await ctx.send("You can't duel yourself.")

    # Already in duel checks
    if user_in_duel(ctx.author.id):
        return await ctx.send("You are already in an active duel.")
    if user_in_duel(opponent.id):
        return await ctx.send(f"{opponent.mention} is already in an active duel.")

    # Ask for confirmation
    view = DuelConfirmView(ctx.author, opponent)
    msg = await ctx.send(
        f"{opponent.mention}, **{ctx.author.mention}** challenged you to a duel! Do you accept?",
        view=view
    )

    await view.wait()

    if view.result != "accepted":
        if view.result is None:
            await msg.edit(content=f"Duel request to {opponent.mention} **timed out**.", view=view)
        else:
            await msg.edit(content=f"{opponent.mention} **declined** the duel.", view=view)
        return

    if user_in_duel(ctx.author.id) or user_in_duel(opponent.id):
        return await msg.edit(content="One of you started another duel while waiting. Request cancelled.", view=view)

    filename = duel_filename(ctx.author.id, opponent.id)
    data = {
        str(ctx.author.id): 0,
        str(opponent.id): 0
    }
    with open(filename, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2)

    embed = discord.Embed(
        title=f'Duel started: {ctx.author.display_name} vs {opponent.display_name}',
        description=(
            'Welcome to the world of gunslingers!\n'
            'Now you can choose `!reload` or `!shoot`.\n'
            'If you reload, you have a 1/10 chance to get a bullet.\n'
            'Once you have a bullet, you can shoot and win the game.'
        ),
        color=discord.Color.random()
    )
    await msg.edit(content=None, embed=embed, view=None)


@bot.command(name='reload', aliases = ['r'])
async def reload_(ctx):
    filename = find_duel_file(ctx.author.id)
    if not filename:
        return await ctx.send("You're not in an active duel.")

    with open(filename, "r", encoding="utf-8") as f:
        data = json.load(f)

    me = str(ctx.author.id)
    now = datetime.now(timezone.utc)

    # Check time of last reload
    last_reload_str = data.get(f'{me}_time')
    if last_reload_str:
        try:
            last_reload = datetime.fromisoformat(last_reload_str)
        except Exception:
            last_reload = None

        if last_reload and (now - last_reload).total_seconds() < 1:
            return await ctx.send("⏳ You must wait a second before reloading again.")

    # 1/10 chance to load a bullet
    if random.randint(1, 10) == 1:
        data[me] = data.get(me, 0) + 1

    # Update the time regardless of reload success
    data[f'{me}_time'] = now.isoformat()

    with open(filename, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2)

    await ctx.send("🔫 You reloaded the gun, but the bullet may or may not exist.")


def draw_loser_static(member: discord.abc.User, gunshot_path: str = "gunshot.png") -> io.BytesIO:
    # --- fetch avatar ---
    try:  # discord.py 2.x
        pfp_url = member.display_avatar.replace(format="png", size=256).url
    except AttributeError:
        pfp_url = member.avatar.url

    try:
        resp = requests.get(pfp_url, timeout=10)
        resp.raise_for_status()
        pfp = Image.open(BytesIO(resp.content)).convert("RGBA")
    except (requests.Timeout, requests.ConnectionError, Exception) as e:
        logging.warning(f"Failed to fetch avatar: {e}")
        return io.BytesIO()  # Return empty buffer on error
    
    w, h = pfp.size
    size = min(w, h)
    if (w, h) != (size, size):
        pfp = pfp.resize((size, size), Image.LANCZOS)
        w = h = size

    # --- load & scale gunshot sprite ---
    gunshot = Image.open(gunshot_path).convert("RGBA")
    target = int(size * 0.5)  # 50% of pfp size
    gunshot = gunshot.resize((target, target), Image.LANCZOS)

    # Center position
    gx = (w - target) // 2
    gy = (h - target) // 2

    # Composite
    final_img = pfp.copy()
    final_img.alpha_composite(gunshot, (gx, gy))

    # Save as PNG in-memory
    buf = io.BytesIO()
    final_img.save(buf, format="PNG")
    buf.seek(0)
    return buf
def draw_loser(member: discord.abc.User, gunshot_path: str = "gunshot.png") -> io.BytesIO:
    # --- fetch avatar ---
    try:  # discord.py 2.x
        pfp_url = member.display_avatar.replace(format="png", size=256).url
    except AttributeError:
        pfp_url = member.avatar.url

