# server duels
DUEL_LOGS_FOLDER = "duel_logs"
os.makedirs(DUEL_LOGS_FOLDER, exist_ok=True)

def load_duel_log(guild_id, rarity):
    file_name = f"{rarity}_{guild_id}.json"
    file_path = os.path.join(DUEL_LOGS_FOLDER, file_name)
    if os.path.exists(file_path):
        with open(file_path, "r", encoding="utf-8") as f:
            return json.load(f)
    return {}

def save_duel_log(guild_id, rarity, data):
    file_name = f"{rarity}_{guild_id}.json"
    file_path = os.path.join(DUEL_LOGS_FOLDER, file_name)
    with open(file_path, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=4)

@bot.command(name='log')
async def duel_log(ctx, loser: discord.Member, rarity: str = None):
    if rarity is None:
        return await ctx.send("Please specify rarity: `rare` or `comm`.")

    rarity = rarity.lower()
    if rarity not in ["rare", "comm"]:
        return await ctx.send("Rarity must be `rare` or `comm`.")

    if loser.id == ctx.author.id:
        return await ctx.send("You cannot log on yourself!")

    # Define the confirmation view
    class Duel_Log_ConfirmView(View):
        def __init__(self, author, loser):
            super().__init__(timeout=60)
            self.value = None
            self.author = author
            self.loser = loser

        @discord.ui.button(label="✅ Confirm", style=discord.ButtonStyle.green)
        async def confirm(self, interaction: discord.Interaction, button: Button):
            if interaction.user.id != self.loser.id and not interaction.user.guild_permissions.administrator:
                return await interaction.response.send_message("You cannot confirm this duel.", ephemeral=True)

            self.value = True
            self.stop()
            await interaction.response.send_message("Duel confirmed!", ephemeral=True)

        @discord.ui.button(label="❌ Cancel", style=discord.ButtonStyle.red)
        async def cancel(self, interaction: discord.Interaction, button: Button):
            if interaction.user.id != self.loser.id and not interaction.user.guild_permissions.administrator:
                return await interaction.response.send_message("You cannot cancel this duel.", ephemeral=True)

            self.value = False
            self.stop()
            await interaction.response.send_message("Duel cancelled.", ephemeral=True)

    view = Duel_Log_ConfirmView(ctx.author, loser)
    await ctx.send(f"{loser.mention}, do you confirm this duel loss?", view=view)

    # Wait for interaction or timeout
    await view.wait()

    if view.value is None:
        return await ctx.send("⏰ Confirmation timed out. Duel log cancelled.")
    if view.value is False:
        return await ctx.send("❌ Duel cancelled by user/admin.")

    # Load duel log for this rarity
    log_data = load_duel_log(ctx.guild.id, rarity)

    winner_id = str(ctx.author.id)
    loser_id = str(loser.id)

    if winner_id not in log_data:
        log_data[winner_id] = {"wins": 0, "loses": 0, "points": 0}
    if loser_id not in log_data:
        log_data[loser_id] = {"wins": 0, "loses": 0, "points": 0}

    # Update stats
    log_data[winner_id]["wins"] += 1
    log_data[loser_id]["loses"] += 1

    config_path = os.path.join("duel_log_config", f"{ctx.guild.id}_config.json")
    if os.path.exists(config_path):
        with open(config_path, "r", encoding="utf-8") as f:
            config = json.load(f)
        system = config["system"]
        roles = config["roles"]
    else:
        system = "relative"
        roles = {}
    if system == "flat (100 win, 100 lose)":
        wp = lp = 100
        log_data[winner_id]["points"] += 100
        log_data[loser_id]["points"] -= 100
    elif system == "flat (100 win, 50 lose)":
        wp = 100
        lp = 50
        log_data[winner_id]["points"] += 100
        log_data[loser_id]["points"] -= 50
    elif system == "diminishing":
        wp = (log_data[winner_id]["wins"]+1)**(1/2)*100 - (log_data[winner_id]["wins"])**(1/2)*100
        lp = (log_data[loser_id]["loses"]+1)**(1/2)*50 - (log_data[loser_id]["loses"])**(1/2)*50
        log_data[winner_id]["points"] = (log_data[winner_id]["wins"]+1)**(1/2)*100 - log_data[winner_id]["loses"]**(1/2)*50
        log_data[loser_id]["points"] = (log_data[loser_id]["wins"])**(1/2)*100 - (log_data[loser_id]["loses"]+1)**(1/2)*50
    elif system == "relative":
        diff = log_data[winner_id]["points"] - log_data[loser_id]["points"]
        wp = 100 - diff
        lp = wp/2
        if 150 > wp > 49:
            log_data[winner_id]["points"] += wp
            log_data[loser_id]["points"] -= lp
        elif wp > 149:
            wp = 150
            lp = wp/2
            log_data[winner_id]["points"] += wp
            log_data[loser_id]["points"] -= lp
        else:
            wp = 50
            lp = wp/2
            log_data[winner_id]["points"] += wp
            log_data[loser_id]["points"] -= lp
    

    save_duel_log(ctx.guild.id, rarity, log_data)

    # --- Role update after logging points ---
    async def update_roles(user_id, member, guild, points, roles_config):
        """Update roles for a given user based on their points."""
        if not roles_config:
            return

        # Convert keys to int for sorting
        role_requirements = {int(k): v for k, v in roles_config.items()}

        # Find the highest threshold the user qualifies for
        qualified_role_id = None
        for threshold, role_id in sorted(role_requirements.items()):
            if points >= threshold:
                qualified_role_id = int(role_id)

        if qualified_role_id:
            qualified_role = guild.get_role(qualified_role_id)

            # Remove other reward roles
            for r in member.roles:
                if str(r.id) in role_requirements.values() and r.id != qualified_role_id:
                    await member.remove_roles(r)

            # Add the qualified role
            if qualified_role not in member.roles:
                await member.add_roles(qualified_role)
        else:
            # Remove all reward roles if none qualify
            for r in member.roles:
                if str(r.id) in role_requirements.values():
                    await member.remove_roles(r)

    # Update both winner and loser roles
    await update_roles(ctx.author.id, ctx.author, ctx.guild, log_data[winner_id]["points"], roles)
    await update_roles(loser.id, loser, ctx.guild, log_data[loser_id]["points"], roles)

    # Send confirmation message
    await ctx.send(
        f"✅ Duel recorded: **{ctx.author.display_name}** wins against **{loser.display_name}** "
        f"({'Rare' if rarity=='rare' else 'Common'} Duel).\n+{wp} for {ctx.author.display_name}\n-{lp} for {loser.display_name}"
    )

@bot.command(name="duel_points")
@commands.has_permissions(manage_guild=True)
async def duel_points(ctx, member: discord.Member, rarity: str, action: str, amount: int):
    """
    Manually change duel points for a user.
    Usage: !duel_points @member <rare|comm> <add|remove|set> <amount>
    """
    rarity = rarity.lower()
    if rarity not in ["rare", "comm"]:
        return await ctx.send("⚠️ Rarity must be `rare` or `comm`.")
    if action.lower() not in ["add", "remove", "set"]:
        return await ctx.send("⚠️ Action must be `add`, `remove`, or `set`.")

    # Load duel log
    log_data = load_duel_log(ctx.guild.id, rarity)
    user_id = str(member.id)
    if user_id not in log_data:
        log_data[user_id] = {"wins": 0, "loses": 0, "points": 0}

    old_points = log_data[user_id]["points"]

    # Adjust points
    if action == "add":
        log_data[user_id]["points"] += amount
    elif action == "remove":
        log_data[user_id]["points"] = max(0, log_data[user_id]["points"] - amount)
    elif action == "set":
        log_data[user_id]["points"] = max(0, amount)

    new_points = log_data[user_id]["points"]
    save_duel_log(ctx.guild.id, rarity, log_data)

    # Load duel log config for roles
    config_path = os.path.join("duel_log_config", f"{ctx.guild.id}_config.json")
    if os.path.exists(config_path):
        with open(config_path, "r", encoding="utf-8") as f:
            config = json.load(f)
        roles = config.get("roles", {})
    else:
        roles = {}

    async def update_roles(member, guild, points, roles_config):
        if not roles_config:
            return

        role_requirements = {int(k): v for k, v in roles_config.items()}
        qualified_role_id = None
        for threshold, role_id in sorted(role_requirements.items()):
            if points >= threshold:
                qualified_role_id = int(role_id)

        if qualified_role_id:
            qualified_role = guild.get_role(qualified_role_id)

            # Remove lower roles
            for r in member.roles:
                if str(r.id) in role_requirements.values() and r.id != qualified_role_id:
                    await member.remove_roles(r)

            if qualified_role not in member.roles:
                await member.add_roles(qualified_role)
        else:
            # Remove all reward roles if none qualify
            for r in member.roles:
                if str(r.id) in role_requirements.values():
                    await member.remove_roles(r)

    await update_roles(member, ctx.guild, new_points, roles)

    await ctx.send(
        f"✅ Updated **{member.display_name}**’s duel points for `{rarity}`:\n"
        f"Old: `{old_points}` → New: `{new_points}`"
    )
@duel_points.error
async def duel_points_error(ctx, error):
    if isinstance(error, commands.MissingPermissions):
        await ctx.send("❌ You need **Manage Server** permission to use this command.")
    elif isinstance(error, commands.MissingRequiredArgument):
        await ctx.send("Usage: `!duel_points @member <rare|comm> <add|remove|set> <amount>`")
    else:
        raise error

@bot.command()
@commands.has_permissions(administrator=True)
async def reset_duel_lb(ctx, rarity: str = None, player: discord.User = None):
    if player:
        log_data = load_duel_log(ctx.guild.id, rarity)
        log_data[str(player.id)]["wins"] = 0
        log_data[str(player.id)]["loses"] = 0
        log_data[str(player.id)]["points"] = 0
        save_duel_log(ctx.guild.id, rarity, log_data)
        await ctx.send(f"Duel log has been reset for {player.mention}.")
    else:
        if rarity == "rare":
            save_duel_log(ctx.guild.id, "rare", {})
        elif rarity == "comm":
            save_duel_log(ctx.guild.id, "comm", {})
        else:
            save_duel_log(ctx.guild.id, "rare", {})
            save_duel_log(ctx.guild.id, "comm", {})
        await ctx.send("Duel log has been reset.")

@bot.command()
async def transform(ctx):
    user_id = ctx.author.id

    with connect_poke_db() as conn:
        c = conn.cursor()

        c.execute(
            "SELECT pokemon, transforming FROM poke WHERE player_id = ?",
            (user_id,)
        )
        row = c.fetchone()

        if not row or not row[0]:
            return await ctx.send(
                "You haven't selected a Pokémon. "
                "(Use `!poke set <pokemon>` to choose one)"
            )

        pokemon, state = row

        if state == 0:
            # ✅ Transform ON
            c.execute(
                "UPDATE poke SET transforming = 1 WHERE player_id = ?",
                (user_id,)
            )

            transformed[user_id] = pokemon  # 🔥 cache it
            transformed_cosmetics[user_id] = get_equipped_pokemon_cosmetic(user_id, pokemon)

            await ctx.send(
                f"{ctx.author.mention} transformed into **{pokemon}**!\n"
                "Use the command again to transform back.\n"
                "-# While transformed, you can use animated emoji with `:emoji_name:`"
            )

        else:
            # ❌ Transform OFF
            c.execute(
                "UPDATE poke SET transforming = 0 WHERE player_id = ?",
                (user_id,)
            )

            transformed.pop(user_id, None)  # 🔥 remove from cache
            transformed_cosmetics.pop(user_id, None)

            await ctx.send(
                f"{ctx.author.mention} returned to normal!"
            )

#Poke game:
def setup_poke(conn):
    c = conn.cursor()
    c.execute("""
    CREATE TABLE IF NOT EXISTS poke (
        player_id INTEGER PRIMARY KEY,
        pokemon TEXT,
        pokemon_list TEXT,
        move_list TEXT,
        pve TEXT,
        pvp TEXT,
        team_fight TEXT,
        raid TEXT,
        coins INTEGER,
        bag TEXT,
        win INTEGER,
        lose INTEGER,
        wild INTEGER,
        achivements TEXT,
        cooldown INTEGER
    )
    """)
    try:
        c.execute("""ALTER TABLE poke ADD COLUMN transforming INTEGER DEFAULT 0;""")
    except Exception:
        pass
    try:
        c.execute("""ALTER TABLE poke ADD COLUMN custom_pokemon TEXT;""")
    except Exception:
        pass
    conn.commit()

def ensure_player(conn, user_id: int):
    c = conn.cursor()
    c.execute("""
        INSERT INTO poke (player_id, coins, bag, win, lose, wild, cooldown)
        VALUES (?, 0, '{}', 0, 0, 0, 0)
        ON CONFLICT(player_id) DO NOTHING
    """, (user_id,))
    conn.commit()

