def battle_mec(move_log, move, p1_stats, p2_stats, p1_types, p2_types, p1_debuff, p2_debuff):
    move_info = get_move_info(move)
    type_multiplier = get_effectiveness(move_info[2], p2_types)
    effect, stats, amounts = get_move_effect(move)
    healing_moves = ["giga drain", "leech life", "draining kiss", "horn leech", "mega drain", "absorb", "dream eater", "parabolic charge", "drain punch"]
    if len(p1_types) != 1:
        stab = 1.5 if move_info[2]==p1_types[1] or move_info[2]==p1_types[0] else 1
    else:
        stab = 1.5 if move_info[2]==p1_types[0] else 1
    heal = 0
    dmg =0
    bonus = 0
    movepath = os.path.join('move_data', f'{move.lower()}.json')
    with open(movepath, "r") as f:
        move_data = json.load(f)
    if move_data.get('chain', None):
        last_move = move_log[-1]
        _,_,types = get_move_info(last_move)
        if types == move_info[2]:
            bonus = int(move_data['bonus'])  
    if move_info[1] == "physical":
        if p1_debuff[1] < 0:
            calc_atk = math.floor((2*p1_stats[1] + 31 + 5 + 5) *(2/(2-p1_debuff[1])))
        else:
            calc_atk = math.floor((2*p1_stats[1] + 31 + 5 + 5)*(1 + 0.5*p1_debuff[1]))
        if p2_debuff[2] < 0:
            calc_def = math.floor((2*p2_stats[2] + 31 + 5 + 5) * (2/(2 - p2_debuff[2])))
        else:
            calc_def = math.floor((2*p2_stats[2] + 31 + 5 + 5) * (1 + 0.5*p2_debuff[2]))
        dmg = math.floor((42*(move_info[0]+bonus)*calc_atk/calc_def/50 + 2) * stab * type_multiplier)
        if move in healing_moves:
            heal = dmg * 0.5
        else: 
            heal = 0
    elif move_info[1] == "special":
        if p1_debuff[3] < 0:
            calc_atk = math.floor((2*p1_stats[3] + 31 + 5 + 5) *(2/(2-p1_debuff[3])))
        else:
            calc_atk = math.floor((2*p1_stats[3] + 31 + 5 + 5)*(1 + 0.5*p1_debuff[3]))
        if p2_debuff[4] < 0:
            calc_def = math.floor((2*p2_stats[4] + 31 + 5 + 5) * (2/(2 - p2_debuff[4])))
        else:
            calc_def = math.floor((2*p2_stats[4] + 31 + 5 + 5) * (1 + 0.5*p2_debuff[4]))
        dmg = math.floor((42*(move_info[0]+bonus)*calc_atk/calc_def/50 + 2) * stab * type_multiplier)
        if move in healing_moves:
            heal = dmg * 0.5
        elif move == 'oblivion wing':
            heal = dmg * 0.75
        else:
            heal = 0
    if "Heals the target for half its max HP." in effect or "Heals the user by half its max HP." in effect:
        heal = (2*p1_stats[0] + 31 + 5 + 110)/2
    max_heal = (2*p1_stats[0] + 31 + 5 + 110)
    if heal > max_heal:
        heal = max_heal
    return dmg, heal

def max_bp():
    folder_path = "move_data"  # folder with your JSON files
    highest_moves = {}

    for filename in os.listdir(folder_path):
        if filename.endswith(".json"):
            file_path = os.path.join(folder_path, filename)
            
            with open(file_path, "r", encoding="utf-8") as f:
                move = json.load(f)

            move_type = move.get("type")
            base_power = move.get("base_power", 0)
            if not base_power:
                base_power = 0

            # If this type not seen yet or this move is >= current highest BP
            if (move_type not in highest_moves) or (base_power >= highest_moves[move_type]["base_power"]):
                highest_moves[move_type] = {
                    "name": move.get("name"),
                    "base_power": base_power
                }
    return highest_moves

def max_usable_bp():
    folder_path = "move_data"  # folder with your JSON files
    special_moves_file = "special_moves.txt"
    highest_moves = {}

    # Read existing special moves into a set for quick lookup
    if os.path.exists(special_moves_file):
        with open(special_moves_file, "r", encoding="utf-8") as f:
            special_moves_set = {line.strip() for line in f if line.strip()}
    else:
        special_moves_set = set()

    for filename in os.listdir(folder_path):
        if filename.endswith(".json"):
            file_path = os.path.join(folder_path, filename)
            
            with open(file_path, "r", encoding="utf-8") as f:
                move = json.load(f)

            move_name = move.get("name", "")
            move_type = move.get("type", "")
            base_power = move.get("base_power", 0) or 0

            # If move has BP > 150 and is not in special_moves.txt, append it
            if base_power > 150 and move_name not in special_moves_set:
                with open(special_moves_file, "a", encoding="utf-8") as f:
                    f.write(move_name + "\n")
                special_moves_set.add(move_name)

            # Skip adding to highest_moves if it's in special_moves
            if move_name in special_moves_set:
                continue

            # If this type not seen yet or this move is >= current highest BP
            if (move_type not in highest_moves) or (base_power >= highest_moves[move_type]["base_power"]):
                highest_moves[move_type] = {
                    "name": move_name,
                    "base_power": base_power
                }

    return highest_moves

word_to_num = {
    "one": 1,
    "two": 2,
    "three": 3,
    "four": 4,
    "five": 5,
    "six": 6,
}

def parse_stat_changes(effect_text, rng_mode=False):
    stat_map = ["HP", "Attack", "Defense", "Special Attack", "Special Defense", "Speed"]
    changes = {stat: 0 for stat in stat_map}

    # Chance handling
    chance_match = re.search(r"(\d+)%\s+chance", effect_text, re.IGNORECASE)
    if chance_match:
        chance = max(0, min(100, int(chance_match.group(1))))
        if rng_mode:
            if random.random() >= (chance / 100.0):
                return changes
        else:
            if chance < 50:
                return changes
            elif 49 < chance < 99 and random.random() > 0.5:
                return changes

    def apply_clause(clause, changes):
        has_raise = bool(re.search(r"\braises?\b", clause, re.IGNORECASE))
        has_lower = bool(re.search(r"\blowers?\b", clause, re.IGNORECASE))
        if not (has_raise ^ has_lower):
            return

        direction = "raise" if has_raise else "lower"
        multiplier = 1 if direction == "raise" else -1

        pattern = r"(?:the user's|its|user's)\s+(.+?)\s+by\s+(\w+)\s+stage"
        matches = re.findall(pattern, clause, re.IGNORECASE)

        for stat_list, stage_text in matches:
            stats = re.split(r",| and ", stat_list)

            num_stages = word_to_num.get(stage_text.lower(), None)
            if num_stages is None:
                try:
                    num_stages = int(stage_text)
                except:
                    num_stages = 1

            for stat_name in stats:
                stat_name = stat_name.strip()
                for key in changes:
                    if key.lower() == stat_name.lower():
                        changes[key] += multiplier * num_stages
                        break

    # Split into sentences/clauses and apply simple logic per clause
    for clause in re.split(r"[.!?]", effect_text):
        clause = clause.strip()
        if clause:
            apply_clause(clause, changes)

    return changes

def parse_target_stat_changes(effect_text, rng_mode=False):
    stat_map = ["HP", "Attack", "Defense", "Special Attack", "Special Defense", "Speed"]
    changes = {stat: 0 for stat in stat_map}

    # Mode-gated chance handling.
    chance_match = re.search(r"(\d+)%\s+chance", effect_text, re.IGNORECASE)
    if chance_match:
        chance = max(0, min(100, int(chance_match.group(1))))
        if rng_mode:
            if random.random() >= (chance / 100.0):
                return changes
        else:
            if chance < 50:
                return changes
            elif 99 > chance > 49 and random.random() > 0.5:
                return changes

    # Detect Raises or Lowers
    direction_match = re.search(r"(Raises|Lowers|lower|raise)", effect_text, re.IGNORECASE)
    if not direction_match:
        return changes
    direction = direction_match.group(1).lower()
    multiplier = 1 if direction in ["raises", "raise"] else -1

    # Match all "<stats> by <number> stage(s)"
    pattern = r"(?:the target's|its|target's)\s+(.+?)\s+by\s+(\w+)\s+stage"
    matches = re.findall(pattern, effect_text, re.IGNORECASE)

    for stat_list, stage_text in matches:
        # Split multiple stats separated by commas or 'and'
        stats = re.split(r",| and ", stat_list)
        num_stages = word_to_num.get(stage_text.lower(), None) or int(stage_text)

        for stat_name in stats:
            stat_name = stat_name.strip()
            for key in changes:
                if key.lower() == stat_name.lower():
                    changes[key] += multiplier * num_stages
                    break

    return changes

def add_to_lists(conn, player_id, new_pokemon=None, new_move=None):
    c = conn.cursor()

    # Get the current lists
    c.execute("SELECT pokemon_list, move_list FROM poke WHERE player_id = ?", (player_id,))
    row = c.fetchone()
    if not row:
        return  # Player doesn't exist

    pokemon_list = json.loads(row[0]) if row[0] else []
    move_list = json.loads(row[1]) if row[1] else []

    # Append new values if given
    if new_pokemon and new_pokemon not in pokemon_list:
        pokemon_list.append(new_pokemon)
    if new_move and new_move not in move_list:
        move_list.append(new_move)

    # Save back to DB
    c.execute(
        "UPDATE poke SET pokemon_list = ?, move_list = ? WHERE player_id = ?",
        (json.dumps(pokemon_list), json.dumps(move_list), player_id)
    )
    conn.commit()

