        # Check ultimate move usage
        log_key = f"{user_key}_log"
        if move_data.get('ultimate', None) and move in data[log_key]:
            return await ctx.send("You can only use Ultimate move one time per game")

        data[log_key].append(move)

        if "Disrupt chain moves (does not work on boss pokemon);" in get_move_effect(move)[0]:
            try:
                number_to_remove = int(get_move_effect(move)[0][-1]) 
            except ValueError:
                number_to_remove = 1 
            logs = data.get(f"{target_key}_log", [])
            if logs:
                remove_count = min(number_to_remove, len(logs))
                logs = logs[:-remove_count]

                data[f"{target_key}_log"] = logs

        # Get user's Pokémon stats
        pokemon = data[user_key]
        user_stats = get_pokemon_stats(pokemon)

        # Calculate cooldown
        cd_key = f"{user_key}_cd"
        x = 10 - math.floor((2*user_stats[0][5] + 31 + 5 + 5))/100
        if data[cd_key]:
            diff = time.time() - float(data[cd_key])
            if diff < x:
                return await ctx.send('You are still on cd')
            else:
                data[cd_key] = time.time()
        else:
            data[cd_key] = time.time()

