                c.execute("UPDATE poke SET win = win + 1 WHERE player_id = ?", (int(data[user_key+'_id']),))
                c.execute("UPDATE poke SET lose = lose + 1 WHERE player_id = ?", (int(data[target_key+'_id']),))
