        alive_slots = []
        for team_prefix, id_prefix in [("t1", "t1"), ("t2", "t2")]:
            for i in range(1, 4):
                player_id = data.get(f"{id_prefix}{i}_id")
                hp = data.get(f"{id_prefix}{i}_hp")
                if player_id and hp and hp > 0:
                    alive_slots.append((f"{team_prefix}_p{i}", f"{id_prefix}{i}_id"))

        if not alive_slots:
            return await ctx.send("No available targets!")

        # --- Create a select menu for the user to pick target ---
        options = [discord.SelectOption(label=f"<@{pid}> ({slot})", value=f"{slot}|{pid}") for slot, pid in alive_slots]

        class TargetSelect(discord.ui.View):
            def __init__(self):
                super().__init__(timeout=30)
                self.target_slot = None
                self.target_id = None

            @discord.ui.select(placeholder="Select a target", options=options)
            async def select_callback(self, select, interaction):
                self.target_slot, self.target_id = select.values[0].split("|")
                self.stop()

        view = TargetSelect()
        await ctx.send("Select a target to use the move on:", view=view)
        await view.wait()

        if not view.target_slot:
            return await ctx.send("Target selection timed out.")

        target_slot = view.target_slot
        target_id = int(view.target_id)
        target_hp_slot = target_slot.replace("p", "1") if "t1" in target_slot else target_slot.replace("p", "1")

        # --- Determine which slot is the user ---
        user_slot = None
        for i in range(1, 4):
            for team_prefix, id_prefix in [("t1", "t1"), ("t2", "t2")]:
                if data.get(f"{id_prefix}{i}_id") == ctx.author.id:
                    user_slot = f"{team_prefix}_p{i}"
                    break
            if user_slot:
                break

        if not user_slot:
            return await ctx.send("You are not in this team fight!")

