@poke.command(name='team_fight', aliases=['war'])
async def team_fight(ctx, opp: str = None):
    conn = connect_poke_db()
    c = conn.cursor()
    if opp and opp.lower() in ['x', 'cancel']:
        c.execute("SELECT team_fight FROM poke WHERE player_id = ?", (ctx.author.id,))
        row = c.fetchone()
        if row and row[0]:
            filepath = os.path.join("poke", row[0])
            if os.path.exists(filepath):
                os.remove(filepath)

            # Load the JSON to get all participants
            with open(os.path.join("poke", row[0]), "r") as f:
                data = json.load(f)
            
            # Collect all player IDs from both teams
            players_in_duel = [
                data.get("t11_id"), data.get("t12_id"), data.get("t13_id"),
                data.get("t21_id"), data.get("t22_id"), data.get("t23_id")
            ]
            players_in_duel = [pid for pid in players_in_duel if pid]

            # Clear team_fight for all participants
            c.execute(f"UPDATE poke SET team_fight = NULL WHERE player_id IN ({','.join(['?']*len(players_in_duel))})", tuple(players_in_duel))
            conn.commit()
            conn.close()
            return await ctx.send("Cancelled")
        else:
            return await ctx.send("You are not in a duel")
    c.execute("SELECT pve FROM poke WHERE player_id = ?", (int(ctx.author.id),))
    row1 = c.fetchone()
    c.execute("SELECT pvp FROM poke WHERE player_id = ?", (int(ctx.author.id),))
    row2 = c.fetchone()
    c.execute("SELECT team_fight FROM poke WHERE player_id = ?", (int(ctx.author.id),))
    row3 = c.fetchone()
    c.execute("SELECT raid FROM poke WHERE player_id = ?", (int(ctx.author.id),))
    row4 = c.fetchone()
    try:
        if (row1 and row1[0]) or (row2 and row2[0]) or (row3 and row3[0]) or (row4 and row4[0]):
            conn.close()
            return await ctx.send('You are already in a duel, try !poke use [move]')
    except Exception as e:
        print(e)
    c.execute("SELECT pokemon FROM poke WHERE player_id = ?", (ctx.author.id,))
    row = c.fetchone()
    if not row:
        conn.close()
        return await ctx.send("You have no Pokémon to start a team fight.")
    pokemon = row[0]
    stats, types = get_pokemon_stats(pokemon)
    hp = (2*stats[0] + 31 + 5 + 110) * 6

    # Create duel JSON
    data = {
        "t1_p1": pokemon, "t1_p2": None, "t1_p3": None,
        "t2_p1": None, "t2_p2": None, "t2_p3": None,
        "t11_id": ctx.author.id, "t12_id": None, "t13_id": None,
        "t21_id": None, "t22_id": None, "t23_id": None,
        "t1_log": [], "t2_log": [],
        "t11_stats": [0,0,0,0,0,0], "t12_stats": [0,0,0,0,0,0], "t13_stats": [0,0,0,0,0,0],
        "t21_stats": [0,0,0,0,0,0], "t22_stats": [0,0,0,0,0,0], "t23_stats": [0,0,0,0,0,0],
        "t11_hp": hp, "t12_hp": None, "t13_hp": None,
        "t21_hp": None, "t22_hp": None, "t23_hp": None,
        "t11_status": None, "t12_status": None, "t13_status": None,
        "t21_status": None, "t22_status": None, "t23_status": None,
        "t11_cd": None, "t12_cd": None, "t13_cd": None,
        "t21_cd": None, "t22_cd": None, "t23_cd": None
    }
    folder = 'poke'
    os.makedirs(folder, exist_ok=True)
    filepath = os.path.join(folder, f'team_{ctx.author.id}.json')
    with open(filepath, "w") as f:
        json.dump(data, f, indent=4)

    view = TeamFightJoinView(f'team_{ctx.author.id}.json')
    c.execute("UPDATE poke SET team_fight = ? WHERE player_id = ?", (f'team_{ctx.author.id}.json', ctx.author.id))
    conn.commit()

    await ctx.send(f"A team fight has started! Click below to join Team 1 or Team 2.", view=view)

