@poke.command(name="taunt")
async def taunt(ctx):
    conn = connect_poke_db()
    c = conn.cursor()

    # Get the raid file name for this player
    c.execute("SELECT raid FROM poke WHERE player_id = ?", (ctx.author.id,))
    row = c.fetchone()
    if not row or not row[0]:
        conn.close()
        return await ctx.send("❌ You are not currently in a raid!")

    filepath = os.path.join("poke", row[0])  # e.g. team_123456789.json

    if not os.path.exists(filepath):
        conn.close()
        return await ctx.send("⚠️ Raid data file missing!")

    with open(filepath, "r") as f:
        data = json.load(f)

    # Check if this user is part of this raid (safety check)
    if ctx.author.id not in [data.get("p1_id"), data.get("p2_id"), data.get("p3_id")]:
        conn.close()
        return await ctx.send("❌ You are not part of this raid!")

    # Determine which player slot the author occupies
    player_key = None
    for i in range(1, 4):
        if data.get(f"p{i}_id") == ctx.author.id:
            player_key = f"p{i}"
            break
    if not player_key:
        conn.close()
        return await ctx.send("❌ Could not find your player slot in this raid!")
    # Check if taunt is already active
    if data.get("target"):
        conn.close()
        return await ctx.send("❌ Someone has already used taunt!")
    # Apply taunt
    data["target"] = ctx.author.id
    hp_key = player_key +'_hp'
    increase = 0
    if data.get("p1_id"):
        increase += 50
    if data.get("p2_id"):
        increase += 50
    if data.get("p3_id"):
        increase += 50
    data[hp_key] = int(data[hp_key]) + increase

    with open(filepath, "w") as f:
        json.dump(data, f, indent=4)

    conn.close()
    await ctx.send(f"🗯️ {ctx.author.mention} used **Taunt** and gained additional {increase} HP! The boss is now forced to target them.")

