@poke.command(name="inv", aliases=['bal', 'inventory', 'balance'])
async def poke_inv(ctx, user: str = None):
    # 🔍 Resolve user (mention / ID / self)
    if user is None:
        target = ctx.author
    else:
        if user.isdigit():
            user_id = int(user)
        else:
            try:
                user_id = int(user.replace("<@", "").replace("!", "").replace(">", ""))
            except:
                return await ctx.send("❌ Invalid user format.")

        try:
            target = await ctx.bot.fetch_user(user_id)
        except:
            return await ctx.send("❌ Could not find that user.")

    conn = connect_poke_db()
    ensure_player(conn, target.id)  # ✅ FIX: use target, not ctx.author
    c = conn.cursor()

    c.execute(
        "SELECT coins, pokemon_list, move_list, bag FROM poke WHERE player_id = ?",
        (target.id,)
    )
    row = c.fetchone()
    conn.close()

    if not row:
        return await ctx.send(f"<@{target.id}> doesn't have a profile yet.")

    coins, pokemon_list_json, move_list_json, bag_json = row

    # 📦 Convert JSON
    import json
    pokemon_list = json.loads(pokemon_list_json) if pokemon_list_json else []
    move_list = json.loads(move_list_json) if move_list_json else []
    bag = json.loads(bag_json) if bag_json else []

    # ✉️ Embed
    embed = discord.Embed(
        title=f"{target.name}'s Profile",
        color=discord.Color.gold()
    )

    embed.add_field(name="💰 ARCs", value=str(coins), inline=False)
    embed.add_field(
        name="🐾 Pokémon List",
        value=", ".join(pokemon_list) if pokemon_list else "None",
        inline=False
    )
    embed.add_field(
        name="⚡ Move List",
        value=", ".join(move_list) if move_list else "None",
        inline=False
    )
    embed.add_field(
        name="🎒 Inventory",
        value=", ".join(bag) if bag else "Empty",
        inline=False
    )

    # 🖼 Avatar (works for User too)
    avatar_url = target.display_avatar.url
    embed.set_thumbnail(url=avatar_url)

    await ctx.send(embed=embed)

def _guild_has_war_premium(guild_id: int | None) -> bool:
    if not guild_id or not os.path.exists("war_premium.txt"):
        return False
    with open("war_premium.txt", "r") as f:
        lines = f.read().splitlines()
    return any(str(guild_id) == line.strip() for line in lines)


def execute_daily_claim(player_id: int, guild_id: int | None) -> dict:
    conn = connect_poke_db()
    ensure_player(conn, player_id)
    c = conn.cursor()
    c.execute("SELECT cooldown FROM poke WHERE player_id = ?", (player_id,))
    row = c.fetchone()
    now = time.time()
    cooldown = 86400
    last_claim = float(row[0]) if row and row[0] is not None else 0
    if now < last_claim + cooldown:
        conn.close()
        return {
            "ok": False,
            "message": f"Claim again in {int((last_claim + cooldown) - now)} seconds!",
        }

    def get_player_moves() -> set[str]:
        cur = conn.cursor()
        cur.execute("SELECT move_list FROM poke WHERE player_id = ?", (player_id,))
        move_row = cur.fetchone()
        if not move_row or not move_row[0]:
            return set()
        try:
            return set(json.loads(move_row[0]))
        except json.JSONDecodeError:
            return set()

    starter_moves = ["sky link", "fairy glitter", "abnormality"]
    war_premium = _guild_has_war_premium(guild_id)
    arc_amount = 50 if war_premium else 30

    c.execute("UPDATE poke SET cooldown = ? WHERE player_id = ?", (now, player_id))
    c.execute("UPDATE poke SET coins = coins + ? WHERE player_id = ?", (arc_amount, player_id))

    existing_moves = get_player_moves()
    added_moves = [move for move in starter_moves if move not in existing_moves]
    for move in added_moves:
        add_to_lists(conn, player_id, new_move=move)

    conn.commit()
    conn.close()
    return {
        "ok": True,
        "arc_amount": arc_amount,
        "war_premium": war_premium,
        "added_moves": added_moves,
    }


def format_daily_claim_messages(claim_result: dict) -> list[str]:
    if not claim_result.get("ok"):
        return [claim_result["message"]]
    messages = []
    added_moves = claim_result.get("added_moves") or []
    if added_moves:
        messages.append("Starter gift:\n" + "\n".join(f"{idx + 1}. `{move}`" for idx, move in enumerate(added_moves)))
        messages.append("You have gain access to all standard Pokemon (check any pokedex to view full list)\nFor special pokemon, use !poke dex")
    else:
        messages.append("You already have all starter moves! 🎉")
    bonus_text = " (+20 extra thanks to Premium)" if claim_result.get("war_premium") else ""
    messages.append(f"You have obtained {claim_result['arc_amount']} ARCs from daily gifts{bonus_text}")
    return messages


def build_server_claim_embed(guild: discord.Guild, breakdown: dict) -> discord.Embed:
    embed = discord.Embed(
        title="Claim rewards for your server",
        description=(
            f"Click confirm to claim **{breakdown['claim_arcs']}** arcs. "
            "By clicking, your server will automatically get an advertisement on Goldi Hub."
        ),
        color=discord.Color.gold(),
    )
    boss_counts = breakdown["boss_counts"]
    boss_count_text = ", ".join(f"{tier}:{boss_counts.get(tier, 0)}" for tier in SERVER_POINT_VALID_BOSS_TIERS)
    detail_lines = [
        f"Number of members: {breakdown['member_count']} x 0.25 = {breakdown['member_reward']:.2f}",
        f"Number of duels: {breakdown['duel_count']} x 0.5 = {breakdown['duel_reward']:.2f}",
        f"Boss slaying tier: {breakdown['boss_progress_label']}",
        f"Boss defeats stored: {boss_count_text}",
        f"Boss reward total: {breakdown['boss_kills']} x {breakdown['boss_multiplier']} = {breakdown['boss_reward']:.2f}",
        f"Total reward: {breakdown['total_reward']:.2f} -> {breakdown['claim_arcs']} arcs",
    ]
    embed.add_field(name="Detail:", value="\n".join(detail_lines), inline=False)
    embed.set_footer(text=f"Server: {guild.name}")
    return embed


def build_server_advertisement_embed(guild: discord.Guild, breakdown: dict, invite_link: str | None) -> discord.Embed:
    embed = build_server_claim_embed(guild, breakdown)
    embed.title = f"{guild.name} server advertisement"
    embed.description = f"{guild.name} has just claimed **{breakdown['claim_arcs']}** arcs."
    embed.add_field(name="Server Invite", value=invite_link or "Invite unavailable", inline=False)
    return embed


async def create_permanent_server_invite(guild: discord.Guild) -> str | None:
    if guild is None:
        return None
    me = guild.me or guild.get_member(bot.user.id if bot.user else 0)
    if me is None:
        return None
    channels_to_try = []
    if guild.system_channel:
        channels_to_try.append(guild.system_channel)
    channels_to_try.extend(guild.text_channels)
    seen_channel_ids = set()
    for channel in channels_to_try:
        if channel.id in seen_channel_ids:
            continue
        seen_channel_ids.add(channel.id)
        permissions = channel.permissions_for(me)
        if not permissions.create_instant_invite:
            continue
        try:
            invite = await channel.create_invite(
                max_age=0,
                max_uses=0,
                unique=False,
                reason="Server claim advertisement invite",
            )
            return invite.url
        except Exception:
            continue
    return None


class ServerClaimConfirmView(discord.ui.View):
    def __init__(self, guild_id: int, claimer_id: int):
        super().__init__(timeout=180)
        self.guild_id = int(guild_id)
        self.claimer_id = int(claimer_id)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.claimer_id:
            await interaction.response.send_message("Only the original claimant can use these buttons.", ephemeral=True)
            return False
        return True

    async def _disable_view(self, interaction: discord.Interaction):
        for child in self.children:
            child.disabled = True
        try:
            await interaction.message.edit(view=self)
        except Exception:
            pass

    @discord.ui.button(label="Confirm", style=discord.ButtonStyle.success)
    async def confirm(self, interaction: discord.Interaction, button: discord.ui.Button):
        guild = interaction.guild or interaction.client.get_guild(self.guild_id)
        if guild is None:
            return await interaction.response.send_message("This server is no longer available.", ephemeral=True)

        await flush_server_point_cache_once()
        server_row = get_server_point_row(guild.id)
        now = int(time.time())
        last_claim = int(server_row.get("claim_time") or 0)
        if now < last_claim + SERVER_CLAIM_COOLDOWN:
            remaining = int((last_claim + SERVER_CLAIM_COOLDOWN) - now)
            return await interaction.response.send_message(
                f"Server claim is on cooldown for another {remaining} seconds.",
                ephemeral=True,
            )

        breakdown = calculate_server_claim_breakdown(guild, server_row)
        if breakdown["claim_arcs"] <= 0:
            return await interaction.response.send_message("This server has no rewards to claim yet.", ephemeral=True)

        invite_link = await create_permanent_server_invite(guild)
        with connect_server_point_db() as conn:
            ensure_server_point_row(conn, guild.id)
            c = conn.cursor()
            c.execute(
                """
                UPDATE server_points
                SET monthly_points = monthly_points + ?,
                    claim_time = ?,
                    total_points = total_points + ?,
                    server_invite = ?,
                    server_duels = 0,
                    server_boss = ?
                WHERE server_id = ?
                """,
                (
                    breakdown["claim_arcs"],
                    now,
                    breakdown["claim_arcs"],
                    invite_link,
                    json.dumps({}),
                    guild.id,
                ),
            )
            conn.commit()

        modify_coins(interaction.user.id, breakdown["claim_arcs"])
        await clear_server_point_cache_for_server(guild.id)

        if SERVER_ADVERTISEMENT_CHANNEL_ID:
            ad_channel = interaction.client.get_channel(SERVER_ADVERTISEMENT_CHANNEL_ID)
            if ad_channel is None:
                try:
                    ad_channel = await interaction.client.fetch_channel(SERVER_ADVERTISEMENT_CHANNEL_ID)
                except Exception:
                    ad_channel = None
            if ad_channel:
                try:
                    await ad_channel.send(embed=build_server_advertisement_embed(guild, breakdown, invite_link))
                except Exception:
                    traceback.print_exc()

        await self._disable_view(interaction)
        success_embed = build_server_claim_embed(guild, breakdown)
        success_embed.description = f"Claim confirmed. **{breakdown['claim_arcs']}** arcs were added to your balance."
        if invite_link:
            success_embed.add_field(name="Server Invite", value=invite_link, inline=False)
        await interaction.response.edit_message(embed=success_embed, view=self)

    @discord.ui.button(label="Cancel", style=discord.ButtonStyle.secondary)
    async def cancel(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._disable_view(interaction)
        await interaction.response.edit_message(content="Server claim cancelled.", embed=None, view=self)


async def prepare_server_claim(guild: discord.Guild, user: discord.Member | discord.User) -> tuple[bool, str | None, discord.Embed | None, discord.ui.View | None]:
    if guild is None:
        return False, "This command can only be used in a server.", None, None
    if user != guild.owner and not user.guild_permissions.administrator:
        return False, "Only the server owner or an admin can use this command.", None, None

    await flush_server_point_cache_once()
    server_row = get_server_point_row(guild.id)
    now = int(time.time())
    last_claim = int(server_row.get("claim_time") or 0)
    if now < last_claim + SERVER_CLAIM_COOLDOWN:
        remaining = int((last_claim + SERVER_CLAIM_COOLDOWN) - now)
        return False, f"Server claim is on cooldown for another {remaining} seconds.", None, None

    breakdown = calculate_server_claim_breakdown(guild, server_row)
    if breakdown["claim_arcs"] <= 0:
        return False, "This server has no rewards to claim yet.", None, None

    return True, None, build_server_claim_embed(guild, breakdown), ServerClaimConfirmView(guild.id, user.id)


