@poke.command(name="move_info", aliases=['move', 'moveinfo', 'mi'])
async def move_info(ctx, *, move: str = None):
    if not move:
        return await ctx.send('Please enter a move name')

    # Get move basic info
    base_power, category, move_type = get_move_info(move)
    if not move_type:
        return await ctx.send(f"Could not find move `{move}`")

    # Get effect description + stat debuffs
    effect_description, debuffed_stats, debuff_amounts = get_move_effect(move)

    # Find which types it's super effective against
    type_chart = get_effectiveness(move_type)  # dummy check to access chart
    # Instead of checking effectiveness vs Pokémon, list which types are 2x
    super_effective_types = [
        t for t, multiplier in type_chart[move_type].items() if multiplier >= 2
    ]

    if category.capitalize() == 'Special':
        hex_code = "#12F1F9"
        color = discord.Color(int(hex_code.lstrip("#"), 16))
    elif category.capitalize() == 'Physical':
        hex_code = "#FF3535"
        color = discord.Color(int(hex_code.lstrip("#"), 16))
    else:
        hex_code = "#22014D"
        color = discord.Color(int(hex_code.lstrip("#"), 16))

    cat_emo = CATEGORY_EMOJIS.get(f"{category.lower()}", "")
    ty_emo = TYPE_EMOJIS.get(f"{move_type.lower()}", "")
    embed = discord.Embed(
        title=move.capitalize(),
        description=f"**Category:** {category.capitalize()}{cat_emo}\n**Type:** {move_type.capitalize()}{ty_emo}",
        color=color
    )

    embed.add_field(name="Base Power", value=str(base_power), inline=True)

    if effect_description:
        embed.add_field(name="Effect", value=effect_description, inline=False)

    if super_effective_types:
        embed.add_field(
            name="Super Effective Against",
            value=", ".join([t.capitalize() for t in super_effective_types]),
            inline=False
        )

    await ctx.send(embed=embed)

