def search_moves(
    category=None,
    min_bp=None,
    move_type=None,
    recovery=False,
    semi_heal=False,
    debuffs=None,
    buffs=None,
    chain=False,
    ultimate=False,
    self_debuff=None
):
    """
    Search moves stored as JSON files in moves_data/ with given filters.
    """
    results = []

    for filename in os.listdir(move_data_folder):
        if not filename.endswith(".json"):
            continue

        move_data = load_json_data(os.path.join(move_data_folder, filename))

        # Extract core info
        name = move_data.get("name", "")
        bp = move_data.get("base_power", 0)
        cat = move_data.get("category", "").lower()
        mtype = move_data.get("type", "").lower()
        effect_entries = move_data.get("effect_entries", [])

        # Extra flags
        is_chain = move_data.get("chain", False)
        is_ultimate = move_data.get("ultimate", False)
        healing_moves = ["giga drain", "leech life", "draining kiss", "horn leech", "mega drain", "absorb", "dream eater", "parabolic charge", "drain punch", "oblivion wing"]

        # 1. Category filter
        if category and cat != category.lower():
            continue

        # 2. Base Power filter
        if min_bp and (bp is None or bp < min_bp):
            continue

        # 3. Type filter
        if move_type and mtype != move_type.lower():
            continue

        # 4. Recovery filter if effect mentions healing)
        if recovery and (
            "Heals the target for half its max HP." not in effect_entries and
            "Heals the user by half its max HP." not in effect_entries):
            continue

        # 5. Semi-heal list filter
        if semi_heal and name not in healing_moves:
            continue

        # 6. Debuff filter (check effect_entries text)
        if debuffs:
            user_target_changes = parse_target_stat_changes(get_move_effect(name)[0])
            if user_target_changes.get(debuffs.capitalize(), 0) > -1:
                continue

        # 7. Buff filter (check effect_entries text)
        if buffs:
            user_changes = parse_stat_changes(get_move_effect(name)[0])
            if user_changes.get(buffs.capitalize(), 0) < 1:
                continue

        # 8. Chain filter
        if chain and not is_chain:
            continue

        # 9. Ultimate filter
        if ultimate and not is_ultimate:
            continue

        if self_debuff:
            user_changes = parse_stat_changes(get_move_effect(name)[0])
            if user_changes.get(self_debuff.capitalize(), 0) > -1:
                continue

        # ✅ Passed all filters → add to results
        results.append({
            "name": name,
            "bp": bp,
            "category": cat,
            "type": mtype,
            "ultimate": is_ultimate,
            "chain": is_chain,
            "effects": effect_entries
        })

    return results

