def build_move_embed(moves, page: int, per_page: int = 25):
    start = page * per_page
    end = start + per_page
    chunk = moves[start:end]

    embed = discord.Embed(
        title=f"Move Search Results (Page {page+1}/{(len(moves)-1)//per_page+1})",
        color=discord.Color.blue()
    )

    for move in chunk:
        move_name = move.get("name", "Unknown").capitalize()
        bp = move.get("bp", "—")
        cat = move.get("category", "status").lower()
        typ = move.get("type", "normal").lower()

        cat_emoji = CATEGORY_EMOJIS.get(cat, "")
        type_emoji = TYPE_EMOJIS.get(typ, "")

        embed.add_field(
            name=f"{cat_emoji}{type_emoji} {move_name}",
            value=f"**BP:** {bp}",
            inline=True
        )

    return embed


class MovePagination(View):
    def __init__(self, moves, per_page=25):
        super().__init__(timeout=120)
        self.moves = moves
        self.per_page = per_page
        self.page = 0

    @discord.ui.button(label="⬅️ Prev", style=discord.ButtonStyle.secondary)
    async def previous(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page > 0:
            self.page -= 1
            await interaction.response.edit_message(embed=build_move_embed(self.moves, self.page, self.per_page), view=self)

    @discord.ui.button(label="➡️ Next", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, button: discord.ui.Button):
        if (self.page + 1) * self.per_page < len(self.moves):
            self.page += 1
            await interaction.response.edit_message(embed=build_move_embed(self.moves, self.page, self.per_page), view=self)


def _build_moveset_lines(pokemon_name: str) -> list[str] | None:
    pokemon = name_finder(pokemon_name.lower())
    poke_data, _, _ = load_pokemon_data_for_lookup(pokemon, allow_fake=True)
    if not poke_data:
        return None
    moves = poke_data.get("moves_via_level_up", [])
    if not moves:
        return []

    parsed_moves = []
    for m in moves:
        move_name = str(m.get("move", "")).strip().lower()
        if not move_name:
            continue
        move_name = move_name.replace("-"," ")
        level = m.get("level_learned_at", 0)
        bp, category, move_type = get_move_info(move_name)
        bp = 0 if bp is None else bp
        type_emoji = TYPE_EMOJIS.get(str(move_type).lower(), "❓")
        category_emoji = CATEGORY_EMOJIS.get(str(category).lower(), "❓")
        parsed_moves.append((int(level) if str(level).isdigit() else 0, move_name, bp, type_emoji, category_emoji))

    parsed_moves.sort(key=lambda x: (x[0], x[1]))
    return [
        f"Level {level} -- {move_name.title()} {bp} {type_emoji} {category_emoji}"
        for level, move_name, bp, type_emoji, category_emoji in parsed_moves
    ]


def _build_moveset_embed(pokemon_name: str, lines: list[str], page: int, per_page: int = 12) -> discord.Embed:
    max_page = max(0, (len(lines) - 1) // per_page)
    start = page * per_page
    end = start + per_page
    chunk = lines[start:end]
    description = "\n".join(chunk) if chunk else "No moves found."
    embed = discord.Embed(
        title=f"{pokemon_name.title()} Moveset",
        description=description,
        color=discord.Color.blue(),
    )
    embed.set_footer(text=f"Page {page + 1}/{max_page + 1} • Total: {len(lines)}")
    return embed


class MovesetPaginationView(discord.ui.View):
    def __init__(self, owner_id: int, pokemon_name: str, lines: list[str], per_page: int = 12):
        super().__init__(timeout=180)
        self.owner_id = owner_id
        self.pokemon_name = pokemon_name
        self.lines = lines
        self.per_page = per_page
        self.page = 0
        self.max_page = max(0, (len(lines) - 1) // per_page)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.owner_id:
            await interaction.response.send_message("This pagination is not for you.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="⬅️ Prev", style=discord.ButtonStyle.secondary)
    async def previous(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page > 0:
            self.page -= 1
        await interaction.response.edit_message(
            embed=_build_moveset_embed(self.pokemon_name, self.lines, self.page, self.per_page),
            view=self,
        )

    @discord.ui.button(label="➡️ Next", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page < self.max_page:
            self.page += 1
        await interaction.response.edit_message(
            embed=_build_moveset_embed(self.pokemon_name, self.lines, self.page, self.per_page),
            view=self,
        )

FAKEMON_ALLOWED_TYPES = [
    "normal", "fighting", "flying", "poison", "ground", "rock", "bug", "ghost", "steel",
    "fire", "water", "grass", "electric", "psychic", "ice", "dragon", "dark", "fairy",
]
FAKEMON_STATS_ORDER = [
    ("hp", "HP"),
    ("attack", "Attack"),
    ("defense", "Defense"),
    ("special-attack", "Sp. Attack"),
    ("special-defense", "Sp. Defense"),
    ("speed", "Speed"),
]

def _fakemon_base_power(move_name: str) -> int:
    bp, _, _ = get_move_info(move_name)
    return int(bp or 0)

def _fakemon_is_high_prio_high_bp(move_name: str) -> bool:
    prio = int(get_move_priority(move_name) or 0)
    bp = _fakemon_base_power(move_name)
    return prio > 0 and bp > 59

def _fakemon_is_guaranteed_def_drop(move_name: str) -> bool:
    effect_text, _, _ = get_move_effect(move_name)
    effect_text = str(effect_text or "")
    if not effect_text:
        return False
    try:
        target_changes = parse_target_stat_changes(effect_text) or {}
        _ = parse_stat_changes(effect_text) or {}
    except Exception:
        return False
    lowers_def = (target_changes.get("Defense", 0) or 0) < 0
    has_explicit_chance = "chance" in effect_text.lower()
    if has_explicit_chance:
        return "100% chance" in effect_text.lower() and lowers_def
    return lowers_def

def _validate_fakemon_moves(moves: list[str], *, require_non_empty: bool = True) -> tuple[bool, str | None]:
    clean_moves = [str(m).strip().lower() for m in (moves or []) if str(m).strip()]
    if require_non_empty and not clean_moves:
        return False, "Add at least one move before saving."
    if len(clean_moves) > 4:
        return False, "Max 4 moves."

    bp_values = []
    for mv in clean_moves:
        bp, _, _ = get_move_info(mv)
        if bp is None:
            return False, f"Move `{mv}` was not found in move_data."
        if int(bp) > 150:
            return False, f"`{mv}` has BP {bp}. Only moves below 151 BP are allowed."
        bp_values.append(int(bp))

    if clean_moves:
        avg_bp = sum(bp_values) / len(bp_values)
        if avg_bp > 100:
            return False, f"Average BP is {avg_bp:.1f}. It must stay at 100 or below."

    #has_def_drop = any(_fakemon_is_guaranteed_def_drop(mv) for mv in clean_moves)
    has_def_drop = False
    for mv in clean_moves:
        if mv in ["superpower", "Superpower","close combat", "close-combat","Close Combat","Close-Combat","Dragon Ascent","Dragon-Ascent","dragon ascent","dragon-ascent"]:
            has_def_drop = True
            break
    has_high_prio_combo = any(_fakemon_is_high_prio_high_bp(mv) for mv in clean_moves)
    if has_def_drop and has_high_prio_combo:
        return (
            False,
            "Cannot combine a guaranteed Defense-drop move with a move that has priority > 1 and BP > 60."
        )

    return True, None

class FakemonTypeSecondSelect(discord.ui.Select):
    def __init__(self, parent_view: "FakemonCreateView", type1: str):
        options = [discord.SelectOption(label="None", value="none")] + [
            discord.SelectOption(label=t.title(), value=t) for t in FAKEMON_ALLOWED_TYPES
        ]
        super().__init__(
            placeholder="Choose second type (or None)",
            min_values=1,
            max_values=1,
            options=options[:25],
        )
        self.parent_view = parent_view
        self.type1 = type1

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.parent_view.owner_id:
            return await interaction.response.send_message("This builder is not for you.", ephemeral=True)
        second = self.values[0]
        self.parent_view.types = [self.type1] if second == "none" else [self.type1, second]
        self.parent_view.refresh_layout()
        if self.parent_view.message:
            await self.parent_view.message.edit(view=self.parent_view)
        await interaction.response.edit_message(content="Types updated.", view=None)

class FakemonTypeSelect(discord.ui.Select):
    def __init__(self, parent_view: "FakemonCreateView"):
        options = [discord.SelectOption(label=t.title(), value=t) for t in FAKEMON_ALLOWED_TYPES]
        super().__init__(
            placeholder="Click to change type",
            min_values=1,
            max_values=1,
            options=options[:25],
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.parent_view.owner_id:
            return await interaction.response.send_message("This builder is not for you.", ephemeral=True)
        selected_type = self.values[0]
        view = discord.ui.View(timeout=120)
        view.add_item(FakemonTypeSecondSelect(self.parent_view, selected_type))
        await interaction.response.send_message("Select your second type (or None).", view=view, ephemeral=True)

