class FakemonMoveAddModal(discord.ui.Modal):
    def __init__(self, parent_view: "FakemonCreateView"):
        super().__init__(title="Add Move")
        self.parent_view = parent_view
        self.move_name = TextInput(label="Move name", placeholder="e.g. sky attack", required=True)
        self.add_item(self.move_name)

    async def on_submit(self, interaction: discord.Interaction):
        if interaction.user.id != self.parent_view.owner_id:
            return await interaction.response.send_message("This builder is not for you.", ephemeral=True)
        move = str(self.move_name.value or "").strip().lower()
        bp, _, _ = get_move_info(move)
        if bp is None:
            return await interaction.response.send_message("Move not found in move_data.", ephemeral=True)
        if int(bp) > 150:
            return await interaction.response.send_message("Only moves with BP below 151 can be added.", ephemeral=True)
        if move in self.parent_view.moves:
            return await interaction.response.send_message("That move is already in the list.", ephemeral=True)

        trial_moves = self.parent_view.moves + [move]
        ok, err = _validate_fakemon_moves(trial_moves, require_non_empty=True)
        if not ok:
            return await interaction.response.send_message(err, ephemeral=True)

        self.parent_view.moves = trial_moves
        self.parent_view.refresh_layout()
        if self.parent_view.message:
            await self.parent_view.message.edit(view=self.parent_view)
        await interaction.response.send_message(f"Added `{move}`.", ephemeral=True)

class FakemonMoveSelect(discord.ui.Select):
    def __init__(self, parent_view: "FakemonCreateView"):
        options = [discord.SelectOption(label="Add New", value="add_new"), discord.SelectOption(label="Add New 2", value="add_new2")]
        for idx, mv in enumerate(parent_view.moves[:24], start=1):
            options.append(
                discord.SelectOption(
                    label=f"Remove #{idx}",
                    description=mv[:90],
                    value=f"remove:{idx-1}",
                )
            )
        super().__init__(
            placeholder="Click to change moves",
            min_values=1,
            max_values=1,
            options=options,
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.parent_view.owner_id:
            return await interaction.response.send_message("This builder is not for you.", ephemeral=True)
        selected = self.values[0]
        if selected == "add_new" or selected == "add_new2":
            return await interaction.response.send_modal(FakemonMoveAddModal(self.parent_view))

        if not selected.startswith("remove:"):
            return await interaction.response.send_message("Invalid move selection.", ephemeral=True)
        idx = int(selected.split(":", 1)[1])
        if idx < 0 or idx >= len(self.parent_view.moves):
            return await interaction.response.send_message("Move index out of range.", ephemeral=True)
        trial_moves = [m for i, m in enumerate(self.parent_view.moves) if i != idx]
        ok, err = _validate_fakemon_moves(trial_moves, require_non_empty=True)
        if not ok:
            return await interaction.response.send_message(
                f"Cannot remove that move: {err}",
                ephemeral=True,
            )
        removed = self.parent_view.moves[idx]
        self.parent_view.moves = trial_moves
        self.parent_view.refresh_layout()
        if self.parent_view.message:
            await self.parent_view.message.edit(view=self.parent_view)
        await interaction.response.send_message(f"Removed `{removed}`.", ephemeral=True)

