class FakemonAddButton(discord.ui.Button):
    def __init__(self, parent_view: "FakemonCreateView"):
        label = "Update" if getattr(parent_view, "edit_mode", False) else "Add"
        super().__init__(label=label, style=discord.ButtonStyle.success)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.parent_view.owner_id:
            return await interaction.response.send_message("This builder is not for you.", ephemeral=True)
        ok, err = _validate_fakemon_moves(self.parent_view.moves, require_non_empty=True)
        if not ok:
            return await interaction.response.send_message(err, ephemeral=True)

        total_stats = sum(int(v) for v in self.parent_view.stats.values())
        if total_stats > 670:
            return await interaction.response.send_message("Total stats exceed 670.", ephemeral=True)

        base_data, _, _ = load_pokemon_data_for_lookup(self.parent_view.sprite_species, allow_fake=True)
        if not base_data:
            return await interaction.response.send_message("Failed to load base sprite Pokémon data.", ephemeral=True)

        os.makedirs(fakemon_data_folder, exist_ok=True)
        if self.parent_view.edit_mode:
            file_path = self.parent_view.file_path
            if not file_path or not os.path.exists(file_path):
                return await interaction.response.send_message("Original fakemon file was not found.", ephemeral=True)
            try:
                with open(file_path, "r", encoding="utf-8") as f:
                    existing_payload = json.load(f)
            except Exception:
                existing_payload = {}
            file_stem = str(existing_payload.get("name") or os.path.splitext(os.path.basename(file_path))[0]).strip().lower()
            next_id = int(existing_payload.get("id") or 1)
        else:
            duplicate_name = _find_duplicate_fakemon(
                self.parent_view.types,
                self.parent_view.stats,
                self.parent_view.moves,
            )
            if duplicate_name:
                return await interaction.response.send_message(
                    f"There is already a fakemon that is exactly the same called `{duplicate_name}`.",
                    ephemeral=True,
                )
            t1 = self.parent_view.types[0][:2].lower()
            t2 = self.parent_view.types[1][:2].lower() if len(self.parent_view.types) > 1 else ""
            sprite_slug = re.sub(r"\s+", "_", str(self.parent_view.sprite_species).strip().lower())
            file_prefix = f"{sprite_slug}_{t1}{t2}"

            existing_ids = []
            try:
                for entry in os.listdir(fakemon_data_folder):
                    if not entry.endswith(".json"):
                        continue
                    m = re.match(rf"^{re.escape(file_prefix)}(\d+)\.json$", entry)
                    if m:
                        existing_ids.append(int(m.group(1)))
            except Exception:
                existing_ids = []
            next_id = (max(existing_ids) + 1) if existing_ids else 1
            file_stem = f"{file_prefix}{next_id}"
            file_path = os.path.join(fakemon_data_folder, f"{file_stem}.json")

        normal_sprite = self.parent_view.sprite_url or get_pokemon_info(self.parent_view.sprite_species, shiny=False, allow_fake=True)[2]
        shiny_sprite = get_pokemon_info(self.parent_view.sprite_species, shiny=True, allow_fake=True)[2] or normal_sprite
        existing_creator = interaction.user.id
        if self.parent_view.edit_mode:
            try:
                existing_creator = int(existing_payload.get("creator", interaction.user.id))
            except Exception:
                existing_creator = interaction.user.id
        payload = {
            "id": next_id,
            "name": file_stem,
            "height": int(base_data.get("height", 10)),
            "weight": int(base_data.get("weight", 100)),
            "types": self.parent_view.types[:],
            "stats": {
                "hp": int(self.parent_view.stats["hp"]),
                "attack": int(self.parent_view.stats["attack"]),
                "defense": int(self.parent_view.stats["defense"]),
                "special-attack": int(self.parent_view.stats["special-attack"]),
                "special-defense": int(self.parent_view.stats["special-defense"]),
                "speed": int(self.parent_view.stats["speed"]),
            },
            "abilities": list(base_data.get("abilities", []) or ["ball fetch"]),
            "moves_via_level_up": [
                {"move": mv, "level_learned_at": 1}
                for mv in self.parent_view.moves
            ],
            "moves_via_breeding": [],
            "egg_groups": list(base_data.get("egg_groups", [])),
            "sprites": {
                "default_front": normal_sprite,
                "shiny_front": shiny_sprite,
            },
            "fake": True,
            "creator": existing_creator
        }

        with open(file_path, "w", encoding="utf-8") as f:
            json.dump(payload, f, indent=4)

        if self.parent_view.edit_mode:
            await interaction.response.send_message(f"✅ Fakemon updated: `{file_stem}`", ephemeral=True)
        else:
            await interaction.response.send_message(f"✅ Fakemon saved as `{file_path}`", ephemeral=True)

class FakemonCreateView(discord.ui.LayoutView):
    def __init__(self, owner_id: int, *, edit_payload: dict | None = None, file_path: str | None = None):
        super().__init__(timeout=900)
        self.owner_id = int(owner_id)
        self.message = None
        self.file_path = file_path
        self.edit_mode = bool(edit_payload and file_path)
        self.types = ["normal"]
        self.stats = {
            "hp": 100,
            "attack": 100,
            "defense": 100,
            "special-attack": 100,
            "special-defense": 100,
            "speed": 100,
        }
        self.moves: list[str] = []
        self.sprite_species = "pikachu"
        self.sprite_url = get_pokemon_info("pikachu", shiny=False, allow_fake=True)[2]
        if self.edit_mode:
            self._apply_edit_payload(edit_payload or {})
        self.refresh_layout()

    def _apply_edit_payload(self, payload: dict):
        poke_name = str(payload.get("name") or "pikachu").strip().lower()
        poke_types = [str(t).strip().lower() for t in (payload.get("types") or []) if str(t).strip()]
        if poke_types:
            self.types = poke_types[:2]
        stats = payload.get("stats") or {}
        for key in self.stats.keys():
            if key in stats:
                try:
                    self.stats[key] = int(stats[key])
                except Exception:
                    pass
        moves = []
        for entry in payload.get("moves_via_level_up", []) or []:
            mv = str((entry or {}).get("move") or "").strip().lower()
            if mv:
                moves.append(mv)
        self.moves = moves[:24]
        sprite = (((payload.get("sprites") or {}).get("default_front")) or "").strip()
        if sprite:
            self.sprite_url = sprite
        self.sprite_species = poke_name or "pikachu"

    def _types_text(self) -> str:
        if len(self.types) == 1:
            return f"**Types:** {self.types[0]}"
        return f"**Types:** {self.types[0]} / {self.types[1]}"

    def _stats_text(self) -> str:
        lines = ["**Stats:**"]
        for key, label in FAKEMON_STATS_ORDER:
            lines.append(f"- {label}: {self.stats[key]}")
        lines.append(f"- Total: {sum(int(v) for v in self.stats.values())}/670")
        return "\n".join(lines)

    def _moves_text(self) -> str:
        if not self.moves:
            return "**Moves:**\n1. _(none yet)_"
        lines = ["**Moves:**"]
        for i, mv in enumerate(self.moves, start=1):
            lines.append(f"{i}. {mv}")
        avg_bp = sum(_fakemon_base_power(mv) for mv in self.moves) / max(1, len(self.moves))
        lines.append(f"Average BP: {avg_bp:.1f}")
        return "\n".join(lines)

    def refresh_layout(self):
        self.clear_items()
        container = Container()
        container.add_item(TextDisplay("# Fakemon Editor" if self.edit_mode else "# Fakemon Builder"))
        container.add_item(TextDisplay(self._types_text()))
        print("bp1")

        type_row = ActionRow()
        type_row.add_item(FakemonTypeSelect(self))
        container.add_item(type_row)
        print("bp2")

        container.add_item(TextDisplay(self._stats_text()))
        stats_row = ActionRow()
        stats_row.add_item(FakemonStatSelect(self))
        container.add_item(stats_row)
        print("bp3")

        container.add_item(TextDisplay(self._moves_text()))
        moves_row = ActionRow()
        moves_row.add_item(FakemonMoveSelect(self))
        container.add_item(moves_row)
        print("bp4")

        if self.sprite_url:
            container.add_item(
                MediaGallery(
                    MediaGalleryItem(media=self.sprite_url)
                )
            )
        else:
            container.add_item(TextDisplay("_No sprite set._"))
        print("bp5")

        sprite_row = ActionRow()
        sprite_row.add_item(FakemonSpriteSelect(self))
        container.add_item(sprite_row)
        print("bp6")

        button_row = ActionRow()
        button_row.add_item(FakemonAddButton(self))
        container.add_item(button_row)

        self.add_item(container)
        print("bp7")

