@poke.command(name="redeem")
async def poke_redeem(ctx):
    """Move legacy move-shop purchases from bag into move_list."""
    conn = connect_poke_db()
    ensure_player(conn, ctx.author.id)
    c = conn.cursor()

    c.execute("SELECT bag, move_list FROM poke WHERE player_id = ?", (ctx.author.id,))
    row = c.fetchone()

    bag = json.loads(row[0]) if row and row[0] else {}
    move_list = json.loads(row[1]) if row and row[1] else []

    move_lookup = {m.lower(): m for m in moves.keys()}
    moved_unique = []
    moved_tokens = 0

    for bag_item in list(bag.keys()):
        normalized = str(bag_item).lower()
        if normalized not in move_lookup:
            continue

        canonical_move = move_lookup[normalized]
        try:
            amount = int(bag.get(bag_item, 0) or 0)
        except Exception:
            amount = 0

        if amount <= 0:
            del bag[bag_item]
            continue

        moved_tokens += amount
        del bag[bag_item]

        if canonical_move not in move_list:
            move_list.append(canonical_move)
            moved_unique.append(canonical_move)

    if moved_tokens == 0:
        conn.close()
        return await ctx.send("No shop-move items were found in your inventory to redeem.")

    c.execute(
        "UPDATE poke SET bag = ?, move_list = ? WHERE player_id = ?",
        (json.dumps(bag), json.dumps(move_list), ctx.author.id),
    )
    conn.commit()
    conn.close()

    if moved_unique:
        preview = ", ".join(sorted(moved_unique)[:10])
        if len(moved_unique) > 10:
            preview += f", and {len(moved_unique) - 10} more"
        return await ctx.send(
            f"✅ Redeemed {moved_tokens} shop-move inventory item(s) into your move list. Added {len(moved_unique)} new move(s): {preview}."
        )

    await ctx.send(
        f"✅ Redeemed {moved_tokens} shop-move inventory item(s). You already owned all of those moves in your move list."
    )

@poke.command(name="dex", aliases = ['pokedex'])
async def poke_dex(ctx, *, pokemon: str = None):
    if not pokemon:
        return await ctx.send("Please enter a pokemon")
    stats, types = get_pokemon_stats(pokemon.lower())
    if not isinstance(stats, list):
        return await ctx.send("Wrong Pokemon Name, name should be same as pokedex")
    desc = ', '.join(types)
    embed = discord.Embed(title = f'{pokemon.title()}', description = desc, color = discord.Color.random())
    if pokemon.lower() in [p.lower() for p in pokemons]:
        embed.add_field(name = 'Special Pokemon Classification', value = 'ARC (shop)')
    elif pokemon.lower() in ['detective pikachu']:
        embed.add_field(name = 'Special Pokemon Classification', value = 'Event (returning)')
    #elif pokemon.lower() in []:
    #    embed.add_field(name = 'Special Pokemon Classification', value = 'Event (legacy)')
    elif pokemon.lower() in ['gigantamax slaking']:
        embed.add_field(name = 'Special Pokemon Classification', value = 'Raid/PVE')
    elif pokemon.lower() in ['engo']:
        embed.add_field(name = 'Special Pokemon Classification', value = 'Unique')
    total = sum(stats)
    embed.add_field(name = 'Stats:', value = f'**💖 HP:** {stats[0]}\n**⚔️ Atk:** {stats[1]}\n**🛡️ Def:** {stats[2]}\n**💥 SpAtk:** {stats[3]}\n**🧿 SpDef:** {stats[4]}\n**🏎️ Spd:** {stats[5]}\n**Total:** {total}\n')
    await ctx.send(embed=embed)


