# ── Cosmetic tables ───────────────────────────────────────────────────────────

_COSMETIC_TABLES = {
    "pokeball":    ("pokeball",   "available_pokeballs"),
    "background":  ("background", "available_backgrounds"),
    "color":       ("embed_color","available_colors"),
    "embed":       ("embed_color","available_colors"),
    "embed_color": ("embed_color","available_colors"),
    "status":      ("status",     "available_status"),
    "graphics":    ("graphics",   "available_graphics"),
}

def _normalize_cosmetic_type(value: str) -> str | None:
    key = str(value or "").strip().lower().replace("-", " ")
    if key in {"pokemon","pokeball","background","color","embed","embed color","embed_color","status","graphics"}:
        return key.replace(" ", "_")
    return None

def _equipped_category_key(cosmetic_type: str) -> str:
    if cosmetic_type in {"embed","embed_color","color"}:
        return "embed color"
    return cosmetic_type

def _remove_equipped_cosmetic(cursor, user_id: int, cosmetic_type: str, cosmetic: str, pokemon_name: str | None = None):
    if cosmetic_type == "pokemon":
        cursor.execute(
            "DELETE FROM equipped WHERE user_id=? AND category='pokemon' AND lower(pokemon_name)=? AND lower(cosmetic)=?",
            (user_id, str(pokemon_name or "").strip().lower(), str(cosmetic or "").strip().lower()),
        )
        return
    category = _equipped_category_key(cosmetic_type)
    cursor.execute(
        "DELETE FROM equipped WHERE user_id=? AND category=? AND lower(cosmetic)=?",
        (user_id, category, str(cosmetic or "").strip().lower()),
    )

def _split_pokemon_cosmetic_payload(payload: str):
    raw = str(payload or "").strip()
    if "|" in raw:
        left, right = raw.split("|", 1)
        return left.strip().lower(), right.strip().lower()
    tokens = raw.split()
    if len(tokens) < 2:
        return None, None
    name_set = set(_get_all_pokemon_names())
    for i in range(len(tokens)):
        candidate = " ".join(tokens[i:]).strip().lower()
        if candidate in name_set:
            return " ".join(tokens[:i]).strip().lower(), candidate
    return tokens[0].strip().lower(), " ".join(tokens[1:]).strip().lower()

# ── Trade helpers ─────────────────────────────────────────────────────────────

def _trade_side(trade: dict, user_id: int) -> str | None:
    if trade.get("giver")    == user_id: return "giver"
    if trade.get("receiver") == user_id: return "receiver"
    return None

def _trade_other_side(side: str) -> str:
    return "receiver" if side == "giver" else "giver"

def _has_owned_value(cursor, table: str, column: str, user_id: int, value: str) -> bool:
    cursor.execute(f"SELECT {column} FROM {table} WHERE user_id=?", (user_id,))
    row = cursor.fetchone()
    if not row or not row[0]: return False
    return value.strip().lower() in [x.strip().lower() for x in row[0].split(",") if x.strip()]

def _remove_entries(original: list, to_remove: list) -> list:
    remaining = Counter(to_remove); result = []
    for v in original:
        if remaining.get(v, 0) > 0: remaining[v] -= 1; continue
        result.append(v)
    return result

def _load_player_trade_state(cursor, user_id: int):
    cursor.execute("SELECT bag,pokemon_list,move_list,coins FROM poke WHERE player_id=?", (user_id,))
    row = cursor.fetchone()
    if not row: return {}, [], [], 0
    return (json.loads(row[0]) if row[0] else {},
            json.loads(row[1]) if row[1] else [],
            json.loads(row[2]) if row[2] else [],
            row[3] if row[3] is not None else 0)

def _validate_trade_side(cursor, cos_cursor, user_id: int, payload: dict) -> str | None:
    bag, pokemon_list, move_list, coins = _load_player_trade_state(cursor, user_id)
    for item, count in Counter(payload.get("items", [])).items():
        if bag.get(item, 0) < count: return f"Not enough `{item}` in bag."
    for name, count in Counter(payload.get("pokemon", [])).items():
        if Counter(pokemon_list).get(name, 0) < count: return f"You no longer have Pokémon `{name}`."
    for name, count in Counter(payload.get("moves", [])).items():
        if Counter(move_list).get(name, 0) < count: return f"You no longer have move `{name}`."
    if coins < payload.get("coins", 0): return "You don't have enough coins."
    for entry in payload.get("cosmetics", []):
        parts = str(entry).split("::")
        if len(parts) >= 3 and parts[0] == "pokemon":
            if not _has_pokemon_cosmetic(cos_cursor, user_id, parts[1], "::".join(parts[2:])):
                return f"You no longer have `{'::'.join(parts[2:])}` for `{parts[1]}`."
        elif len(parts) >= 2:
            table, column = _COSMETIC_TABLES.get(parts[0], (None, None))
            if not table or not _has_owned_value(cos_cursor, table, column, user_id, parts[1]):
                return f"You no longer have `{parts[1]}` ({parts[0]})."
    return None

def _apply_trade_side_state(state, from_id, to_id, payload):
    f, t = state[from_id], state[to_id]
    for item in payload.get("items", []):
        f["bag"][item] = f["bag"].get(item, 0) - 1
        if f["bag"][item] <= 0: f["bag"].pop(item, None)
        t["bag"][item] = t["bag"].get(item, 0) + 1
    for name in payload.get("pokemon", []):
        f["pokemon_list"] = _remove_entries(f["pokemon_list"], [name])
        if name not in t["pokemon_list"]: t["pokemon_list"].append(name)
    for name in payload.get("moves", []):
        f["move_list"] = _remove_entries(f["move_list"], [name])
        if name not in t["move_list"]: t["move_list"].append(name)
    amt = payload.get("coins", 0)
    f["coins"] -= amt; t["coins"] += amt

async def _fetch_trade_message(bot, trade: dict):
    channel = bot.get_channel(trade.get("channel_id"))
    if not channel: return None
    try: return await channel.fetch_message(trade.get("message_id"))
    except Exception: return None

def _format_trade_cosmetics(entries):
    if not entries: return "None"
    formatted = []
    for entry in entries:
        parts = str(entry).split("::")
        if len(parts) >= 3 and parts[0] == "pokemon":
            formatted.append(f"{parts[1]} [{' '.join(parts[2:])}]")
        elif len(parts) >= 2:
            formatted.append(f"{parts[0]}: {parts[1]}")
        else:
            formatted.append(str(entry))
    return ", ".join(formatted) or "None"

def _trade_panel_text(trade, bot):
    giver    = bot.get_user(trade["giver"])
    receiver = bot.get_user(trade["receiver"])
    giver_name    = giver.display_name    if giver    else str(trade["giver"])
    receiver_name = receiver.display_name if receiver else str(trade["receiver"])

    rg = "✅ Ready"     if trade.get("ready", {}).get("giver")    else "⏳ Not Ready"
    rr = "✅ Ready"     if trade.get("ready", {}).get("receiver") else "⏳ Not Ready"
    bg = "  ⚠️ bypass" if trade.get("bypass", {}).get("giver")    else ""
    br = "  ⚠️ bypass" if trade.get("bypass", {}).get("receiver") else ""

    def side_block(side, name, ready, bypass_tag):
        items     = ", ".join(trade["items"][side])   or "None"
        pokemon   = ", ".join(trade["pokemon"][side]) or "None"
        moves     = ", ".join(trade["moves"][side])   or "None"
        cosmetics = _format_trade_cosmetics(trade.get("cosmetics", {}).get(side, []))
        coins     = trade["coins"][side]
        return (
            f"### {name}{bypass_tag}\n"
            f"Items  —  {items}\n"
            f"Pokemon  —  {pokemon}\n"
            f"Moves  —  {moves}\n"
            f"Cosmetics  —  {cosmetics}\n"
            f"ARCs  —  {coins:,}\n"
            f"{ready}"
        )

    return (
        f"# Trade\n"
        f"{giver_name}  ↔  {receiver_name}\n\n"
        + side_block("giver",    giver_name,    rg, bg)
        + f"\n\n"
        + side_block("receiver", receiver_name, rr, br)
    )

# ── Trade Log ─────────────────────────────────────────────────────────────────

async def _log_trade(bot, trade: dict, guild):
    log_channel = bot.get_channel(TRADE_LOG_CHANNEL_ID)
    if not log_channel: return

    giver    = bot.get_user(trade["giver"])
    receiver = bot.get_user(trade["receiver"])
    giver_member    = guild.get_member(trade["giver"])    if guild else None
    receiver_member = guild.get_member(trade["receiver"]) if guild else None
    giver_name    = giver_member.display_name    if giver_member    else (giver.name    if giver    else str(trade["giver"]))
    receiver_name = receiver_member.display_name if receiver_member else (receiver.name if receiver else str(trade["receiver"]))

    def _fmt(lst):   return "\n".join(lst) if lst else "None"
    def _fmtc(entries):
        if not entries: return "None"
        out = []
        for e in entries:
            parts = str(e).split("::")
            if len(parts) >= 3 and parts[0] == "pokemon": out.append(f"{parts[1]} [{' '.join(parts[2:])}]")
            elif len(parts) >= 2: out.append(f"{parts[0]}: {parts[1]}")
            else: out.append(str(e))
        return "\n".join(out) or "None"

    timestamp = discord.utils.utcnow()
    embed = discord.Embed(title="📦 Trade Completed", color=discord.Color.green(), timestamp=timestamp)

    if guild:
        invite_link = "N/A"
        try:
            for ch in guild.text_channels:
                if ch.permissions_for(guild.me).create_instant_invite:
                    inv = await ch.create_invite(max_age=0, max_uses=0, unique=False, reason="Trade log")
                    invite_link = inv.url; break
        except Exception: pass
        embed.add_field(name="🌐 Server",
            value=f"**Name:** {guild.name}\n**ID:** `{guild.id}`\n**Link:** {invite_link}\n**Members:** {guild.member_count}",
            inline=False)

    embed.add_field(name=f"👤 {giver_name} (Giver)",
        value=f"**User:** {giver.name if giver else 'Unknown'}\n**ID:** `{trade['giver']}`\n**Mention:** <@{trade['giver']}>",
        inline=True)
    embed.add_field(name=f"👤 {receiver_name} (Receiver)",
        value=f"**User:** {receiver.name if receiver else 'Unknown'}\n**ID:** `{trade['receiver']}`\n**Mention:** <@{trade['receiver']}>",
        inline=True)
    embed.add_field(name="\u200b", value="\u200b", inline=False)

    bg = trade.get("bypass", {}).get("giver",    False)
    br = trade.get("bypass", {}).get("receiver", False)
    embed.add_field(name=f"📤 {giver_name} Gave {'⚠️ Bypass' if bg else ''}",
        value=(f"**Items:**\n{_fmt(trade['items']['giver'])}\n\n"
               f"**Pokémon:**\n{_fmt(trade['pokemon']['giver'])}\n\n"
               f"**Moves:**\n{_fmt(trade['moves']['giver'])}\n\n"
               f"**Cosmetics:**\n{_fmtc(trade.get('cosmetics',{}).get('giver',[]))}\n\n"
               f"**ARCs:** {trade['coins']['giver']:,}"), inline=True)
    embed.add_field(name=f"📥 {receiver_name} Gave {'⚠️ Bypass' if br else ''}",
        value=(f"**Items:**\n{_fmt(trade['items']['receiver'])}\n\n"
               f"**Pokémon:**\n{_fmt(trade['pokemon']['receiver'])}\n\n"
               f"**Moves:**\n{_fmt(trade['moves']['receiver'])}\n\n"
               f"**Cosmetics:**\n{_fmtc(trade.get('cosmetics',{}).get('receiver',[]))}\n\n"
               f"**ARCs:** {trade['coins']['receiver']:,}"), inline=True)
    if bg or br:
        bypassed = ([giver_name] if bg else []) + ([receiver_name] if br else [])
        embed.add_field(name="⚠️ Bypass Warning",
            value=f"Bypass used by: **{', '.join(bypassed)}**. Items were NOT verified.", inline=False)

    embed.set_footer(text=f"Trade completed • {timestamp.strftime('%Y-%m-%d %H:%M:%S')} UTC")
    if guild and guild.icon: embed.set_thumbnail(url=guild.icon.url)
    await log_channel.send(embed=embed)

