# ── Trade Confirm View ────────────────────────────────────────────────────────

class TradeConfirmView(LayoutView):
    def __init__(self, requester: discord.Member, target: discord.Member, timeout: float = 60):
        super().__init__(timeout=timeout)
        self.requester = requester
        self.target    = target
        self.result    = None
        self._build()

    def _build(self):
        self.clear_items()
        c = Container()
        c.add_item(TextDisplay(
            f"## Trade Request\n"
            f"**{self.requester.display_name}** wants to trade with **{self.target.mention}**.\n"
            f"Do you accept?"
        ))
        btn_accept  = discord.ui.Button(label="Accept",  style=discord.ButtonStyle.success, custom_id=f"tr_accept_{self.target.id}")
        btn_decline = discord.ui.Button(label="Decline", style=discord.ButtonStyle.danger,  custom_id=f"tr_decline_{self.target.id}")
        btn_accept.callback  = self._cb_accept
        btn_decline.callback = self._cb_decline
        row = ActionRow()
        row.add_item(btn_accept)
        row.add_item(btn_decline)
        c.add_item(row)
        self.add_item(c)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.target.id:
            await interaction.response.send_message("This isn't your trade request.", ephemeral=True)
            return False
        return True

    async def on_timeout(self):
        self.clear_items()
        c = Container()
        c.add_item(TextDisplay("## Trade Request\nTimed out — no response."))
        self.add_item(c)

    async def _cb_accept(self, interaction: discord.Interaction):
        self.result = "accepted"
        self.clear_items()
        c = Container()
        c.add_item(TextDisplay(f"## Trade Request\n✅ **{self.target.display_name}** accepted!"))
        self.add_item(c)
        await interaction.response.edit_message(view=self)
        self.stop()

    async def _cb_decline(self, interaction: discord.Interaction):
        self.result = "declined"
        self.clear_items()
        c = Container()
        c.add_item(TextDisplay(f"## Trade Request\n❌ **{self.target.display_name}** declined."))
        self.add_item(c)
        await interaction.response.edit_message(view=self)
        self.stop()

# ── Trade Panel View ──────────────────────────────────────────────────────────

class TradePanelView(LayoutView):
    def __init__(self, trade: dict, bot):
        super().__init__(timeout=300)
        self.trade = trade
        self.bot   = bot
        self.refresh_layout()

    def refresh_layout(self):
        self.clear_items()
        c = Container()
        c.add_item(TextDisplay(_trade_panel_text(self.trade, self.bot)))
        c.add_item(discord.ui.Separator())

        btn_confirm = discord.ui.Button(label="Confirm", style=discord.ButtonStyle.success,
                                        custom_id=f"tp_confirm_{self.trade['giver']}_{self.trade['receiver']}")
        btn_cancel  = discord.ui.Button(label="Cancel",  style=discord.ButtonStyle.danger,
                                        custom_id=f"tp_cancel_{self.trade['giver']}_{self.trade['receiver']}")
        btn_confirm.callback = self._cb_confirm
        btn_cancel.callback  = self._cb_cancel

        row = ActionRow()
        row.add_item(btn_confirm)
        row.add_item(btn_cancel)
        c.add_item(row)
        c.add_item(TextDisplay("-# !poke ta to add items to your offer"))
        self.add_item(c)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id not in (self.trade.get("giver"), self.trade.get("receiver")):
            await interaction.response.send_message("This trade is not yours.", ephemeral=True)
            return False
        return True

    async def _cb_confirm(self, interaction: discord.Interaction):
        trade = self.trade
        if trade.get("status") != "active":
            return await interaction.response.send_message("This trade is no longer active.", ephemeral=True)
        side = _trade_side(trade, interaction.user.id)
        if not side:
            return await interaction.response.send_message("You are not part of this trade.", ephemeral=True)

        trade["ready"][side] = True
        self.refresh_layout()
        await interaction.response.edit_message(view=self)

        if not all(trade["ready"].values()):
            return

        # both ready — execute
        conn = connect_poke_db()
        ensure_player(conn, trade["giver"]); ensure_player(conn, trade["receiver"])
        c = conn.cursor()
        with sqlite3.connect("cosmetics.db") as cos_conn:
            cos_cursor = cos_conn.cursor()
            for chk_side, chk_id in (("giver", trade["giver"]), ("receiver", trade["receiver"])):
                if trade.get("bypass", {}).get(chk_side): continue
                reason = _validate_trade_side(c, cos_cursor, chk_id, {
                    "items":     trade["items"][chk_side],
                    "pokemon":   trade["pokemon"][chk_side],
                    "moves":     trade["moves"][chk_side],
                    "cosmetics": trade["cosmetics"][chk_side],
                    "coins":     trade["coins"][chk_side],
                })
                if reason:
                    conn.close()
                    for uid in (trade["giver"], trade["receiver"]): ongoing_trades.pop(uid, None)
                    return await interaction.followup.send(f"Trade failed: {reason}")

            state = {}
            for uid in (trade["giver"], trade["receiver"]):
                bag, plist, mlist, coins = _load_player_trade_state(c, uid)
                state[uid] = {"bag": bag, "pokemon_list": plist, "move_list": mlist, "coins": coins}

            _apply_trade_side_state(state, trade["giver"], trade["receiver"],
                {"items": trade["items"]["giver"], "pokemon": trade["pokemon"]["giver"],
                 "moves": trade["moves"]["giver"], "coins":   trade["coins"]["giver"]})
            _apply_trade_side_state(state, trade["receiver"], trade["giver"],
                {"items": trade["items"]["receiver"], "pokemon": trade["pokemon"]["receiver"],
                 "moves": trade["moves"]["receiver"], "coins":   trade["coins"]["receiver"]})

            for uid, data in state.items():
                c.execute("UPDATE poke SET bag=?,pokemon_list=?,move_list=?,coins=? WHERE player_id=?",
                    (json.dumps(data["bag"]), json.dumps(data["pokemon_list"]),
                     json.dumps(data["move_list"]), data["coins"], uid))

            for from_side, to_side in (("giver","receiver"), ("receiver","giver")):
                from_id = trade[from_side]; to_id = trade[to_side]
                for entry in trade.get("cosmetics", {}).get(from_side, []):
                    parts = str(entry).split("::")
                    if len(parts) >= 3 and parts[0] == "pokemon":
                        pn = parts[1]; cn = "::".join(parts[2:])
                        _remove_pokemon_cosmetic(cos_cursor, from_id, pn, cn)
                        _remove_equipped_cosmetic(cos_cursor, from_id, "pokemon", cn, pokemon_name=pn)
                        _append_pokemon_cosmetic(cos_cursor, to_id, pn, cn)
                    elif len(parts) >= 2:
                        ct = parts[0]; cn = parts[1]
                        table, column = _COSMETIC_TABLES.get(ct, (None, None))
                        if table:
                            _remove_owned_value(cos_cursor, table, column, from_id, cn)
                            _remove_equipped_cosmetic(cos_cursor, from_id, ct, cn)
                            _append_owned_value(cos_cursor, table, column, to_id, cn)
            cos_conn.commit()

        conn.commit(); conn.close()
        for uid in (trade["giver"], trade["receiver"]): ongoing_trades.pop(uid, None)
        await _log_trade(self.bot, trade, None)

        giver_user    = self.bot.get_user(trade["giver"])
        receiver_user = self.bot.get_user(trade["receiver"])
        gn = giver_user.display_name    if giver_user    else str(trade["giver"])
        rn = receiver_user.display_name if receiver_user else str(trade["receiver"])

        self.clear_items()
        done = Container()
        done.add_item(TextDisplay(f"# Trade Complete\n**{gn}** and **{rn}** received their items."))
        self.add_item(done)
        await interaction.message.edit(view=self)

    async def _cb_cancel(self, interaction: discord.Interaction):
        trade = self.trade
        for uid in (trade["giver"], trade["receiver"]): ongoing_trades.pop(uid, None)
        self.clear_items()
        c = Container()
        c.add_item(TextDisplay(f"# Trade Canceled\nCanceled by **{interaction.user.display_name}**."))
        self.add_item(c)
        await interaction.response.edit_message(view=self)

# ── Trade Search Modal ────────────────────────────────────────────────────────

class TradeSearchModal(discord.ui.Modal, title="Search"):
    query = discord.ui.TextInput(label="Search", placeholder="Type to filter...", required=True, max_length=50)

    def __init__(self, parent_view):
        super().__init__()
        self.parent_view = parent_view

    async def on_submit(self, interaction: discord.Interaction):
        self.parent_view.search_query = self.query.value.strip().lower()
        self.parent_view.refresh_layout()
        await interaction.response.edit_message(view=self.parent_view)

# ── Trade Arc Modal ───────────────────────────────────────────────────────────

class TradeArcModal(discord.ui.Modal, title="Add ARCs to Trade"):
    amount = discord.ui.TextInput(label="ARC Amount", placeholder="e.g. 500", required=True, max_length=20)

    def __init__(self, parent_view):
        super().__init__()
        self.parent_view = parent_view

    async def on_submit(self, interaction: discord.Interaction):
        view = self.parent_view
        try:    amt = parse_money_string(self.amount.value)
        except: return await interaction.response.send_message("Invalid ARC amount.", ephemeral=True)
        if amt <= 0: return await interaction.response.send_message("Enter a positive amount.", ephemeral=True)

        side       = _trade_side(view.trade, interaction.user.id)
        other_side = _trade_other_side(side)

        conn = connect_poke_db(); c = conn.cursor()
        c.execute("SELECT coins FROM poke WHERE player_id=?", (interaction.user.id,))
        row = c.fetchone(); conn.close()
        coins = row[0] if row else 0
        if view.trade["coins"][side] + amt > coins:
            return await interaction.response.send_message("You don't have enough ARCs.", ephemeral=True)

        view.trade["coins"][side] += amt
        view.trade["ready"][side] = False
        if view.trade["ready"].get(other_side): view.trade["ready"][other_side] = False

        msg = await _fetch_trade_message(view.bot, view.trade)
        if msg: await msg.edit(view=TradePanelView(view.trade, view.bot))

        view.refresh_layout()
        await interaction.response.edit_message(view=view)

# ── Trade Add View ────────────────────────────────────────────────────────────

class TradeAddView(LayoutView):
    def __init__(self, trade: dict, bot, user_id: int):
        super().__init__(timeout=180)
        self.trade        = trade
        self.bot          = bot
        self.user_id      = user_id
        self.category     = None
        self.cos_type     = None
        self.search_query = ""
        self.refresh_layout()

    def _side(self):
        return _trade_side(self.trade, self.user_id)

    def _offer_text(self):
        side = self._side()
        if not side: return "Not in trade."
        items     = ", ".join(self.trade["items"][side])   or "None"
        pokemon   = ", ".join(self.trade["pokemon"][side]) or "None"
        moves     = ", ".join(self.trade["moves"][side])   or "None"
        cosmetics = _format_trade_cosmetics(self.trade.get("cosmetics", {}).get(side, []))
        coins     = self.trade["coins"][side]
        return (
            f"### Your current offer\n"
            f"Items  —  {items}\n"
            f"Pokemon  —  {pokemon}\n"
            f"Moves  —  {moves}\n"
            f"Cosmetics  —  {cosmetics}\n"
            f"ARCs  —  {coins:,}"
        )

    def _filter(self, name: str) -> bool:
        return not self.search_query or self.search_query in name.lower()

    def _search_label(self) -> str:
        return f"Search  [{self.search_query}]" if self.search_query else "Search"

    def _pokemon_options(self):
        side = self._side()
        conn = connect_poke_db(); c = conn.cursor()
        c.execute("SELECT pokemon_list FROM poke WHERE player_id=?", (self.user_id,))
        row = c.fetchone(); conn.close()
        plist = json.loads(row[0]) if row and row[0] else []
        already = set(self.trade["pokemon"][side])
        seen = set(); opts = []
        for p in plist:
            if p not in already and p not in seen and self._filter(p):
                opts.append(discord.SelectOption(label=p.title(), value=p))
                seen.add(p)
        return opts[:25]

    def _item_options(self):
        side = self._side()
        conn = connect_poke_db(); c = conn.cursor()
        c.execute("SELECT bag FROM poke WHERE player_id=?", (self.user_id,))
        row = c.fetchone(); conn.close()
        bag = json.loads(row[0]) if row and row[0] else {}
        trade_counts = Counter(self.trade["items"][side])
        opts = []
        for item, count in bag.items():
            avail = count - trade_counts.get(item, 0)
            if avail > 0 and self._filter(item):
                opts.append(discord.SelectOption(label=f"{item}  (x{avail})", value=item))
        return opts[:25]

    def _move_options(self):
        side = self._side()
        conn = connect_poke_db(); c = conn.cursor()
        c.execute("SELECT move_list FROM poke WHERE player_id=?", (self.user_id,))
        row = c.fetchone(); conn.close()
        mlist = json.loads(row[0]) if row and row[0] else []
        already = set(self.trade["moves"][side])
        seen = set(); opts = []
        for m in mlist:
            if m not in already and m not in seen and self._filter(m):
                opts.append(discord.SelectOption(label=m.title(), value=m))
                seen.add(m)
        return opts[:25]

    def _cosmetic_type_options(self):
        return [
            discord.SelectOption(label="Pokemon Cosmetic", value="pokemon"),
            discord.SelectOption(label="Pokeball",         value="pokeball"),
            discord.SelectOption(label="Background",       value="background"),
            discord.SelectOption(label="Color",            value="color"),
            discord.SelectOption(label="Status",           value="status"),
            discord.SelectOption(label="Graphics",         value="graphics"),
        ]

    def _cosmetic_value_options(self):
        side = self._side()
        already = set(self.trade.get("cosmetics", {}).get(side, []))
        opts = []
        with sqlite3.connect("cosmetics.db") as cos_conn:
            cos_cursor = cos_conn.cursor()
            if self.cos_type == "pokemon":
                cos_cursor.execute(
                    "SELECT pokemon_name, available_cosmetics FROM pokemon WHERE user_id=?",
                    (self.user_id,)
                )
                rows = cos_cursor.fetchall()
                for pname, coslist in rows:
                    if not coslist: continue
                    for cos in coslist.split(","):
                        cos = cos.strip()
                        if not cos: continue
                        entry = f"pokemon::{pname}::{cos}"
                        label = f"{pname.title()} [{cos}]"
                        if entry not in already and self._filter(label):
                            opts.append(discord.SelectOption(label=label[:100], value=entry[:100]))
            else:
                table, column = _COSMETIC_TABLES.get(self.cos_type, (None, None))
                if table:
                    cos_cursor.execute(f"SELECT {column} FROM {table} WHERE user_id=?", (self.user_id,))
                    row = cos_cursor.fetchone()
                    if row and row[0]:
                        for cos in row[0].split(","):
                            cos = cos.strip()
                            if not cos: continue
                            entry = f"{self.cos_type}::{cos}"
                            if entry not in already and self._filter(cos):
                                opts.append(discord.SelectOption(label=cos.title(), value=entry))
        return opts[:25]

    def refresh_layout(self):
        self.clear_items()
        c = Container()

        header = f"## Add to Trade\n\n{self._offer_text()}"
        if self.search_query:
            header += f"\n-# Searching: **{self.search_query}**"
        c.add_item(TextDisplay(header))
        c.add_item(discord.ui.Separator())

        # category select
        cat_sel = discord.ui.Select(
            placeholder="Choose what to add...",
            custom_id=f"ta_cat_{self.user_id}",
            options=[
                discord.SelectOption(label="Pokemon",  value="pokemon",  default=self.category=="pokemon"),
                discord.SelectOption(label="Item",     value="item",     default=self.category=="item"),
                discord.SelectOption(label="Move",     value="move",     default=self.category=="move"),
                discord.SelectOption(label="ARCs",     value="arc",      default=self.category=="arc"),
                discord.SelectOption(label="Cosmetic", value="cosmetic", default=self.category=="cosmetic"),
            ]
        )
        cat_sel.callback = self._cb_category
        row_cat = ActionRow()
        row_cat.add_item(cat_sel)
        c.add_item(row_cat)

        # search + clear (shown for list categories)
        if self.category in ("pokemon", "item", "move", "cosmetic"):
            btn_search = discord.ui.Button(
                label=self._search_label(),
                style=discord.ButtonStyle.primary,
                custom_id=f"ta_search_{self.user_id}"
            )
            btn_search.callback = self._cb_search
            row_search = ActionRow()
            row_search.add_item(btn_search)
            if self.search_query:
                btn_clear = discord.ui.Button(
                    label="Clear Search",
                    style=discord.ButtonStyle.secondary,
                    custom_id=f"ta_clearsearch_{self.user_id}"
                )
                btn_clear.callback = self._cb_clear_search
                row_search.add_item(btn_clear)
            c.add_item(row_search)

        # item/pokemon/move select
        if self.category in ("pokemon", "item", "move"):
            opts = {"pokemon": self._pokemon_options,
                    "item":    self._item_options,
                    "move":    self._move_options}[self.category]()
            if opts:
                sel = discord.ui.Select(
                    placeholder=f"Select {self.category}(s) to add...",
                    custom_id=f"ta_items_{self.user_id}",
                    options=opts,
                    max_values=min(len(opts), 10),
                )
                sel.callback = self._cb_add_items
                row_items = ActionRow()
                row_items.add_item(sel)
                c.add_item(row_items)
            else:
                c.add_item(TextDisplay(
                    f"-# No {self.category}s found"
                    + (f" matching **{self.search_query}**." if self.search_query else ".")
                ))

        elif self.category == "arc":
            btn_arc = discord.ui.Button(
                label="Enter ARC Amount",
                style=discord.ButtonStyle.primary,
                custom_id=f"ta_arc_{self.user_id}"
            )
            btn_arc.callback = self._cb_arc
            row_arc = ActionRow()
            row_arc.add_item(btn_arc)
            c.add_item(row_arc)

        elif self.category == "cosmetic":
            # step 1 — type
            type_sel = discord.ui.Select(
                placeholder="Select cosmetic type...",
                custom_id=f"ta_costype_{self.user_id}",
                options=self._cosmetic_type_options(),
            )
            type_sel.callback = self._cb_cos_type
            row_costype = ActionRow()
            row_costype.add_item(type_sel)
            c.add_item(row_costype)

            # step 2 — value
            if self.cos_type:
                opts = self._cosmetic_value_options()
                if opts:
                    val_sel = discord.ui.Select(
                        placeholder=f"Select {self.cos_type} cosmetic(s)...",
                        custom_id=f"ta_cosval_{self.user_id}",
                        options=opts,
                        max_values=min(len(opts), 10),
                    )
                    val_sel.callback = self._cb_add_cosmetics
                    row_cosval = ActionRow()
                    row_cosval.add_item(val_sel)
                    c.add_item(row_cosval)
                else:
                    c.add_item(TextDisplay(
                        f"-# No {self.cos_type} cosmetics found"
                        + (f" matching **{self.search_query}**." if self.search_query else ".")
                    ))

        # done button
        btn_done = discord.ui.Button(
            label="Done",
            style=discord.ButtonStyle.secondary,
            custom_id=f"ta_done_{self.user_id}"
        )
        btn_done.callback = self._cb_done
        row_done = ActionRow()
        row_done.add_item(btn_done)
        c.add_item(row_done)

        self.add_item(c)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("This is not your trade panel.", ephemeral=True)
            return False
        return True

    async def _cb_category(self, interaction: discord.Interaction):
        self.category     = interaction.data["values"][0]
        self.cos_type     = None
        self.search_query = ""
        if self.category == "arc":
            await interaction.response.send_modal(TradeArcModal(self))
            return
        self.refresh_layout()
        await interaction.response.edit_message(view=self)

    async def _cb_cos_type(self, interaction: discord.Interaction):
        self.cos_type     = interaction.data["values"][0]
        self.search_query = ""
        self.refresh_layout()
        await interaction.response.edit_message(view=self)

    async def _cb_search(self, interaction: discord.Interaction):
        await interaction.response.send_modal(TradeSearchModal(self))

    async def _cb_clear_search(self, interaction: discord.Interaction):
        self.search_query = ""
        self.refresh_layout()
        await interaction.response.edit_message(view=self)

    async def _cb_add_items(self, interaction: discord.Interaction):
        side       = self._side()
        other_side = _trade_other_side(side)
        selected   = interaction.data["values"]
        added      = []

        if self.category == "pokemon":
            for v in selected:
                if v not in self.trade["pokemon"][side]:
                    self.trade["pokemon"][side].append(v); added.append(v.title())
        elif self.category == "item":
            for v in selected:
                self.trade["items"][side].append(v); added.append(v)
        elif self.category == "move":
            for v in selected:
                if v not in self.trade["moves"][side]:
                    self.trade["moves"][side].append(v); added.append(v.title())

        if added:
            self.trade["ready"][side] = False
            if self.trade["ready"].get(other_side): self.trade["ready"][other_side] = False
            msg = await _fetch_trade_message(self.bot, self.trade)
            if msg: await msg.edit(view=TradePanelView(self.trade, self.bot))

        self.search_query = ""
        self.refresh_layout()
        await interaction.response.edit_message(view=self)

    async def _cb_add_cosmetics(self, interaction: discord.Interaction):
        side       = self._side()
        other_side = _trade_other_side(side)
        selected   = interaction.data["values"]
        added      = []

        for entry in selected:
            if entry not in self.trade["cosmetics"][side]:
                self.trade["cosmetics"][side].append(entry); added.append(entry)

        if added:
            self.trade["ready"][side] = False
            if self.trade["ready"].get(other_side): self.trade["ready"][other_side] = False
            msg = await _fetch_trade_message(self.bot, self.trade)
            if msg: await msg.edit(view=TradePanelView(self.trade, self.bot))

        self.search_query = ""
        self.refresh_layout()
        await interaction.response.edit_message(view=self)

    async def _cb_arc(self, interaction: discord.Interaction):
        await interaction.response.send_modal(TradeArcModal(self))

    async def _cb_done(self, interaction: discord.Interaction):
        self.clear_items()
        c = Container()
        c.add_item(TextDisplay("Offer updated. Use the trade panel to confirm or keep adding."))
        self.add_item(c)
        await interaction.response.edit_message(view=self)
        self.stop()

