#  COMMANDS
# ═════════════════════════════════════════════════════════════════════════════

@poke.command(name="trade", aliases=["t"])
async def poke_trade(ctx, member: discord.Member):
    if ctx.author.id in ongoing_trades or member.id in ongoing_trades:
        return await ctx.send("Either you or the other user is already in a trade.")
    if member.bot:
        return await ctx.send("You cannot trade with bots.")

    view = TradeConfirmView(ctx.author, member)
    await ctx.send(view=view)
    await view.wait()

    if view.result != "accepted":
        return

    if ctx.author.id in ongoing_trades or member.id in ongoing_trades:
        return await ctx.send("One of you started another trade while waiting. Trade canceled.")

    trade = {
        "giver":    ctx.author.id,
        "receiver": member.id,
        "items":     {"giver": [], "receiver": []},
        "pokemon":   {"giver": [], "receiver": []},
        "moves":     {"giver": [], "receiver": []},
        "cosmetics": {"giver": [], "receiver": []},
        "coins":     {"giver": 0,  "receiver": 0},
        "ready":     {"giver": False, "receiver": False},
        "message_id":  None,
        "channel_id":  ctx.channel.id,
        "status":      "active",
        "bypass":    {"giver": False, "receiver": False},
    }
    ongoing_trades[ctx.author.id] = trade
    ongoing_trades[member.id]     = trade

    panel = TradePanelView(trade, ctx.bot)
    msg   = await ctx.send(view=panel)
    trade["message_id"] = msg.id


@poke.command(name="trade_add", aliases=["ta"])
async def poke_trade_add(ctx, cat: str = None):
    trade = ongoing_trades.get(ctx.author.id)
    if not trade:                       return await ctx.send("You are not in an active trade.")
    if trade.get("status") != "active": return await ctx.send("This trade is not active.")
    side = _trade_side(trade, ctx.author.id)
    if not side:                        return await ctx.send("You are not part of this trade.")

    view = TradeAddView(trade, ctx.bot, ctx.author.id)
    if cat and cat.strip().lower() in ("pokemon", "item", "move", "arc", "cosmetic"):
        view.category = cat.strip().lower()
        if view.category != "arc":
            view.refresh_layout()

    await ctx.send(view=view)



# --- Trade Finish
@poke.command(name="trade_finish", aliases = ['tc'])
async def poke_trade_finish(ctx):
    trade = ongoing_trades.get(ctx.author.id)
    if not trade:
        return await ctx.send("You are not in an active trade.")
    if trade.get("status") != "active":
        return await ctx.send("This trade is not active.")

    # mark ready
    user_id = ctx.author.id
    side = _trade_side(trade, user_id)
    if not side:
        return await ctx.send("You are not part of this trade.")
    other_side = _trade_other_side(side)
    other_id = trade[other_side]
    trade["ready"][side] = True

    msg = await _fetch_trade_message(ctx.bot, trade)
    if msg:
        await msg.edit(embed=get_trade_embed(trade, ctx.bot))

    if all(trade["ready"].values()):
        conn = connect_poke_db()
        ensure_player(conn, trade["giver"])
        ensure_player(conn, trade["receiver"])
        c = conn.cursor()
        with sqlite3.connect("cosmetics.db") as cos_conn:
            cos_cursor = cos_conn.cursor()
            if not trade.get("bypass", {}).get("giver"):
                reason = _validate_trade_side(
                    c,
                    cos_cursor,
                    trade["giver"],
                    {
                        "items": trade["items"]["giver"],
                        "pokemon": trade["pokemon"]["giver"],
                        "moves": trade["moves"]["giver"],
                        "cosmetics": trade["cosmetics"]["giver"],
                        "coins": trade["coins"]["giver"],
                    },
                )
                if reason:
                    conn.close()
                    await ctx.send(f"Trade failed: {reason}")
                    if trade["giver"] in ongoing_trades:
                        del ongoing_trades[trade["giver"]]
                    if trade["receiver"] in ongoing_trades:
                        del ongoing_trades[trade["receiver"]]
                    return
            if not trade.get("bypass", {}).get("receiver"):
                reason = _validate_trade_side(
                    c,
                    cos_cursor,
                    trade["receiver"],
                    {
                        "items": trade["items"]["receiver"],
                        "pokemon": trade["pokemon"]["receiver"],
                        "moves": trade["moves"]["receiver"],
                        "cosmetics": trade["cosmetics"]["receiver"],
                        "coins": trade["coins"]["receiver"],
                    },
                )
                if reason:
                    conn.close()
                    await ctx.send(f"Trade failed: {reason}")
                    if trade["giver"] in ongoing_trades:
                        del ongoing_trades[trade["giver"]]
                    if trade["receiver"] in ongoing_trades:
                        del ongoing_trades[trade["receiver"]]
                    return

            state = {}
            for uid in (trade["giver"], trade["receiver"]):
                bag, plist, mlist, coins = _load_player_trade_state(c, uid)
                state[uid] = {
                    "bag": bag,
                    "pokemon_list": plist,
                    "move_list": mlist,
                    "coins": coins,
                }

            _apply_trade_side_state(
                state,
                trade["giver"],
                trade["receiver"],
                {
                    "items": trade["items"]["giver"],
                    "pokemon": trade["pokemon"]["giver"],
                    "moves": trade["moves"]["giver"],
                    "coins": trade["coins"]["giver"],
                },
            )
            _apply_trade_side_state(
                state,
                trade["receiver"],
                trade["giver"],
                {
                    "items": trade["items"]["receiver"],
                    "pokemon": trade["pokemon"]["receiver"],
                    "moves": trade["moves"]["receiver"],
                    "coins": trade["coins"]["receiver"],
                },
            )

            for uid, data in state.items():
                c.execute(
                    "UPDATE poke SET bag = ?, pokemon_list = ?, move_list = ?, coins = ? WHERE player_id = ?",
                    (
                        json.dumps(data["bag"]),
                        json.dumps(data["pokemon_list"]),
                        json.dumps(data["move_list"]),
                        data["coins"],
                        uid,
                    ),
                )

            for entry in trade.get("cosmetics", {}).get("giver", []):
                parts = str(entry).split("::")
                if len(parts) >= 3 and parts[0] == "pokemon":
                    pokemon_name = parts[1]
                    cosmetic_name = "::".join(parts[2:])
                    _remove_pokemon_cosmetic(cos_cursor, trade["giver"], pokemon_name, cosmetic_name)
                    _remove_equipped_cosmetic(cos_cursor, trade["giver"], "pokemon", cosmetic_name, pokemon_name=pokemon_name)
                    _append_pokemon_cosmetic(cos_cursor, trade["receiver"], pokemon_name, cosmetic_name)
                elif len(parts) >= 2:
                    cosmetic_type = parts[0]
                    cosmetic_name = parts[1]
                    table, column = _COSMETIC_TABLES.get(cosmetic_type, (None, None))
                    if table:
                        _remove_owned_value(cos_cursor, table, column, trade["giver"], cosmetic_name)
                        _remove_equipped_cosmetic(cos_cursor, trade["giver"], cosmetic_type, cosmetic_name)
                        _append_owned_value(cos_cursor, table, column, trade["receiver"], cosmetic_name)

            for entry in trade.get("cosmetics", {}).get("receiver", []):
                parts = str(entry).split("::")
                if len(parts) >= 3 and parts[0] == "pokemon":
                    pokemon_name = parts[1]
                    cosmetic_name = "::".join(parts[2:])
                    _remove_pokemon_cosmetic(cos_cursor, trade["receiver"], pokemon_name, cosmetic_name)
                    _remove_equipped_cosmetic(cos_cursor, trade["receiver"], "pokemon", cosmetic_name, pokemon_name=pokemon_name)
                    _append_pokemon_cosmetic(cos_cursor, trade["giver"], pokemon_name, cosmetic_name)
                elif len(parts) >= 2:
                    cosmetic_type = parts[0]
                    cosmetic_name = parts[1]
                    table, column = _COSMETIC_TABLES.get(cosmetic_type, (None, None))
                    if table:
                        _remove_owned_value(cos_cursor, table, column, trade["receiver"], cosmetic_name)
                        _remove_equipped_cosmetic(cos_cursor, trade["receiver"], cosmetic_type, cosmetic_name)
                        _append_owned_value(cos_cursor, table, column, trade["giver"], cosmetic_name)

            cos_conn.commit()
        conn.commit()
        conn.close()

        if trade["giver"] in ongoing_trades:
            del ongoing_trades[trade["giver"]]
        if trade["receiver"] in ongoing_trades:
            del ongoing_trades[trade["receiver"]]
        # ✅ Log the completed trade
        await _log_trade(ctx.bot, trade, ctx.guild)
        giver_name = await get_member_display_name_safely(ctx.guild, int(trade["giver"]))
        receiver_name = await get_member_display_name_safely(ctx.guild, int(trade["receiver"]))
        await ctx.send(f"Trade completed! {giver_name} and {receiver_name} received their items.")
    else:
        await ctx.send("You are ready for trade. Waiting for the other user to finish.")

@poke.command(name="trade_cancel", aliases = ['tx'])
async def poke_trade_cancel(ctx):
    trade = ongoing_trades.get(ctx.author.id)
    if not trade:
        return await ctx.send("You are not in an active trade.")

    # Remove trade from ongoing
    if trade["giver"] in ongoing_trades:
        del ongoing_trades[trade["giver"]]
    if trade["receiver"] in ongoing_trades:
        del ongoing_trades[trade["receiver"]]

    await ctx.send("Trade canceled.")

"""POKER_MAX_PLAYERS = 6
ongoing_poker = {}  # channel_id -> PokerGame


def _poker_rank_value(rank: str) -> int:
    order = "23456789TJQKA"
    return order.index(rank) + 2


def _poker_card_display(card: tuple[int, str]) -> str:
    rank_map = {11: "J", 12: "Q", 13: "K", 14: "A"}
    rank = rank_map.get(card[0], str(card[0]))
    return f"{rank}{card[1]}"


def _poker_deck() -> list[tuple[int, str]]:
    suits = ["♠", "♥", "♦", "♣"]
    ranks = "23456789TJQKA"
    deck = [(_poker_rank_value(r), s) for r in ranks for s in suits]
    random.shuffle(deck)
    return deck


def _straight_high(ranks: list[int]) -> int | None:
    unique = sorted(set(ranks), reverse=True)
    if 14 in unique:
        unique.append(1)
    for i in range(len(unique) - 4):
        start = unique[i]
        seq = [start - j for j in range(5)]
        if all(val in unique for val in seq):
            return start
    return None


def _evaluate_hand(cards: list[tuple[int, str]]) -> tuple[int, list[int]]:
    ranks = [c[0] for c in cards]
    suits = [c[1] for c in cards]
    rank_counts = Counter(ranks)
    suit_counts = Counter(suits)

    flush_suit = None
    for suit, count in suit_counts.items():
        if count >= 5:
            flush_suit = suit
            break

    if flush_suit:
        flush_ranks = sorted([r for r, s in cards if s == flush_suit], reverse=True)
        straight_flush_high = _straight_high(flush_ranks)
        if straight_flush_high:
            return 8, [straight_flush_high]

    four_kind = [r for r, c in rank_counts.items() if c == 4]
    if four_kind:
        four = max(four_kind)
        kicker = max([r for r in ranks if r != four])
        return 7, [four, kicker]

    three_kind = sorted([r for r, c in rank_counts.items() if c == 3], reverse=True)
    pairs = sorted([r for r, c in rank_counts.items() if c == 2], reverse=True)
    if three_kind and (pairs or len(three_kind) > 1):
        trip = three_kind[0]
        pair = pairs[0] if pairs else three_kind[1]
        return 6, [trip, pair]

    if flush_suit:
        flush_ranks = sorted([r for r, s in cards if s == flush_suit], reverse=True)
        return 5, flush_ranks[:5]

    straight_high = _straight_high(ranks)
    if straight_high:
        return 4, [straight_high]

    if three_kind:
        trip = three_kind[0]
        kickers = sorted([r for r in ranks if r != trip], reverse=True)[:2]
        return 3, [trip] + kickers

    if len(pairs) >= 2:
        high_pair, low_pair = pairs[0], pairs[1]
        kicker = max([r for r in ranks if r not in (high_pair, low_pair)])
        return 2, [high_pair, low_pair, kicker]

    if pairs:
        pair = pairs[0]
        kickers = sorted([r for r in ranks if r != pair], reverse=True)[:3]
        return 1, [pair] + kickers

    return 0, sorted(ranks, reverse=True)[:5]


def _best_player_score(game, player) -> tuple[int, list[int]]:
    if player.is_dealer and not game.multiplayer and player.dealer_hands:
        best = None
        for hand in player.dealer_hands:
            score = _evaluate_hand(hand + game.community)
            if best is None or score > best:
                best = score
        return best if best is not None else (0, [])
    return _evaluate_hand(player.hand + game.community)


class PokerPlayer:
    def __init__(self, user_id: int, is_dealer: bool = False):
        self.user_id = user_id
        self.is_dealer = is_dealer
        self.hand: list[tuple[int, str]] = []
        self.dealer_hands: list[list[tuple[int, str]]] = []
        self.folded = False
        self.bet: int | None = None
        self.real_bet: int = 0


class PokerGame:
    def __init__(self, owner_id: int, channel_id: int, multiplayer: bool):
        self.owner_id = owner_id
        self.channel_id = channel_id
        self.multiplayer = multiplayer
        self.started = False
        self.ended = False
        self.message_id: int | None = None
        self.players: dict[int, PokerPlayer] = {}
        self.deck: list[tuple[int, str]] = []
        self.community: list[tuple[int, str]] = []
        self.pending: set[int] = set()
        self.status_text = "Waiting for players."
        self.pot = 0
        self.raise_used = False
        self.host_bet: int | None = None
        self.timeout_task: asyncio.Task | None = None
        self.free_mode = False

    def active_player_ids(self) -> list[int]:
        return [pid for pid, p in self.players.items() if not p.folded and not p.is_dealer]

    def player_state(self, user_id: int) -> PokerPlayer | None:
        return self.players.get(user_id)

    def start(self):
        self.deck = _poker_deck()
        for player in self.players.values():
            if player.is_dealer and not self.multiplayer:
                dealer_cards = [self.deck.pop() for _ in range(6)]
                player.dealer_hands = [
                    dealer_cards[0:2],
                    dealer_cards[2:4],
                    dealer_cards[4:6],
                ]
                player.hand = player.dealer_hands[0]
            else:
                player.hand = [self.deck.pop(), self.deck.pop()]
        self.started = True
        self.status_text = "Game started. Make your choice: Call or Fold."
        self.pending = set(self.active_player_ids())
        self.raise_used = False

    def reveal_next_card(self):
        if len(self.community) < 1 and self.deck:
            self.community.append(self.deck.pop())
            self.community.append(self.deck.pop())
            self.community.append(self.deck.pop())
            self.status_text = f"Community card {len(self.community)} revealed."
        elif 2 < len(self.community) < 6 and self.deck:
            self.community.append(self.deck.pop())
            self.status_text = f"Community card {len(self.community)} revealed."

    def resolve_showdown(self) -> tuple[list[int], str]:
        active = [p for p in self.players.values() if not p.folded]
        if len(active) == 1:
            winner = active[0]
            name = "Dealer" if winner.is_dealer else str(winner.user_id)
            return [winner.user_id], f"{name} wins by default."

        best_score = None
        winners = []
        for player in active:
            score = _best_player_score(self, player)
            if best_score is None or score > best_score:
                best_score = score
                winners = [player.user_id]
            elif score == best_score:
                winners.append(player.user_id)
        return winners, "Showdown resolved."


def _poker_player_name(guild: discord.Guild | None, user_id: int, is_dealer: bool) -> str:
    if is_dealer:
        return "Dealer"
    if guild:
        member = guild.get_member(user_id)
        if member:
            return member.display_name
    return str(user_id)


def _poker_render_text(game: PokerGame, guild: discord.Guild | None) -> str:
    community = " ".join(_poker_card_display(c) for c in game.community) or "(none)"
    lines = [
        f"Poker Table ({'Multiplayer' if game.multiplayer else 'Single Player'})",
        f"Community Cards: {community}",
        f"Pot: {game.pot}",
        f"Status: {game.status_text}",
        "Players:"
    ]
    for pid, player in game.players.items():
        name = _poker_player_name(guild, pid, player.is_dealer)
        if player.folded:
            state = "folded"
        elif player.is_dealer:
            state = "dealer"
        elif pid in game.pending:
            state = "waiting"
        else:
            state = "called"
        bet_text = f", bet {player.bet}" if player.bet is not None else ""
        hand_text = ""
        if game.ended and player.hand:
            if player.is_dealer and not game.multiplayer and player.dealer_hands:
                parts = []
                for idx, hand in enumerate(player.dealer_hands, start=1):
                    cards = " ".join(_poker_card_display(c) for c in hand)
                    parts.append(f"dealer hand {idx}: {cards}")
                hand_text = ", " + " | ".join(parts)
            else:
                hand_cards = " ".join(_poker_card_display(c) for c in player.hand)
                hand_text = f", hand {hand_cards}"
        lines.append(f"- {name}: {state}{bet_text}{hand_text}")
    return "\n".join(lines)


async def _poker_send_hands(bot, guild: discord.Guild | None, game: PokerGame):
    for pid, player in game.players.items():
        if player.is_dealer:
            continue
        user = bot.get_user(pid) or (guild.get_member(pid) if guild else None)
        if not user:
            continue
        hand = " ".join(_poker_card_display(c) for c in player.hand)
        try:
            await user.send(f"Your poker hand: {hand}")
        except Exception:
            pass


class PokerJoinButton(discord.ui.Button):
    def __init__(self, game: PokerGame):
        super().__init__(label="Join", style=discord.ButtonStyle.success)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        if self.game.started or self.game.ended:
            return await interaction.response.send_message("This game has already started.", ephemeral=True)
        if interaction.user.id in self.game.players:
            return await interaction.response.send_message("You already joined.", ephemeral=True)
        if len(self.game.players) >= POKER_MAX_PLAYERS:
            return await interaction.response.send_message("Table is full.", ephemeral=True)
        if self.game.host_bet is None:
            return await interaction.response.send_message("Host bet is not set yet.", ephemeral=True)
        if not _poker_can_pay(interaction.user.id, self.game.host_bet):
            return await interaction.response.send_message("Not enough ARCs to join.", ephemeral=True)
        player = PokerPlayer(interaction.user.id)
        player.bet = self.game.host_bet
        self.game.players[interaction.user.id] = player
        self.game.status_text = "Waiting for players."
        await interaction.response.defer()
        await _poker_update_message(interaction.client, self.game, interaction.guild)


class PokerStartButton(discord.ui.Button):
    def __init__(self, game: PokerGame):
        super().__init__(label="Start", style=discord.ButtonStyle.primary)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.game.owner_id:
            return await interaction.response.send_message("Only the host can start.", ephemeral=True)
        if self.game.started or self.game.ended:
            return await interaction.response.send_message("Game already started.", ephemeral=True)
        if len(self.game.players) < 2:
            return await interaction.response.send_message("Need at least 2 players to start.", ephemeral=True)
        if any(p.bet is None for p in self.game.players.values() if not p.is_dealer):
            return await interaction.response.send_message("All players must set a bet before starting.", ephemeral=True)
        insufficient = []
        for pid, player in self.game.players.items():
            if player.is_dealer:
                continue
            if player.bet is None:
                continue
            if not _poker_can_pay(pid, player.bet):
                insufficient.append(pid)
        if insufficient:
            names = [await get_member_display_name_safely(interaction.guild, int(pid)) for pid in insufficient]
            return await interaction.response.send_message(
                f"Not enough ARCs to start for: {', '.join(names)}",
                ephemeral=True
            )
        # Ante on start
        for pid, player in self.game.players.items():
            if player.is_dealer or player.bet is None:
                continue
            modify_coins(pid, -player.bet)
            self.game.pot += player.bet
        self.game.start()
        if self.game.timeout_task:
            self.game.timeout_task.cancel()
            self.game.timeout_task = None
        await _poker_send_hands(interaction.client, interaction.guild, self.game)
        await interaction.response.defer()
        await _poker_update_message(interaction.client, self.game)


class PokerCallButton(discord.ui.Button):
    def __init__(self, game: PokerGame):
        super().__init__(label="Call", style=discord.ButtonStyle.success)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        player = self.game.player_state(interaction.user.id)
        if not self.game.started or self.game.ended or not player or player.folded or player.is_dealer:
            return await interaction.response.send_message("You can't act right now.", ephemeral=True)
        if interaction.user.id not in self.game.pending:
            return await interaction.response.send_message("You already acted this round.", ephemeral=True)
        if player.bet is None:
            return await interaction.response.send_message("You don't have a bet set.", ephemeral=True)
        if not _poker_can_pay(interaction.user.id, player.bet):
            player.folded = True
            self.game.pending.discard(interaction.user.id)
            await interaction.response.send_message("Not enough ARCs to call. You folded.", ephemeral=True)
            await _poker_advance_round(interaction.client, self.game, interaction.guild)
            return

        modify_coins(interaction.user.id, -player.bet)
        self.game.pot += player.bet
        self.game.pending.discard(interaction.user.id)
        await interaction.response.defer()
        await _poker_advance_round(interaction.client, self.game, interaction.guild)


class PokerFoldButton(discord.ui.Button):
    def __init__(self, game: PokerGame):
        super().__init__(label="Fold", style=discord.ButtonStyle.danger)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        player = self.game.player_state(interaction.user.id)
        if not self.game.started or self.game.ended or not player or player.folded or player.is_dealer:
            return await interaction.response.send_message("You can't act right now.", ephemeral=True)
        if interaction.user.id not in self.game.pending:
            return await interaction.response.send_message("You already acted this round.", ephemeral=True)

        player.folded = True
        self.game.pending.discard(interaction.user.id)
        await interaction.response.defer()
        await _poker_advance_round(interaction.client, self.game, interaction.guild)


class PokerRaiseButton(discord.ui.Button):
    def __init__(self, game: PokerGame):
        super().__init__(label="Raise", style=discord.ButtonStyle.primary)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        player = self.game.player_state(interaction.user.id)
        if not self.game.started or self.game.ended or not player or player.folded or player.is_dealer:
            return await interaction.response.send_message("You can't act right now.", ephemeral=True)
        if interaction.user.id not in self.game.pending:
            return await interaction.response.send_message("You already acted this round.", ephemeral=True)
        if self.game.raise_used:
            return await interaction.response.send_message("Raise already used this round.", ephemeral=True)
        if player.bet is None:
            return await interaction.response.send_message("You don't have a bet set.", ephemeral=True)
        double_bet = player.bet * 2
        if not _poker_can_pay(interaction.user.id, double_bet):
            return await interaction.response.send_message("Not enough ARCs to raise.", ephemeral=True)

        modify_coins(interaction.user.id, -double_bet)
        self.game.pot += double_bet
        self.game.raise_used = True
        self.game.pending.discard(interaction.user.id)

        if not self.game.multiplayer:
            dealer = next((p for p in self.game.players.values() if p.is_dealer), None)
            if dealer and player.bet is not None:
                self.game.pot += double_bet

        self.game.pending = set(self.game.active_player_ids()) - {interaction.user.id}
        await interaction.response.defer()
        await _poker_advance_round(interaction.client, self.game, interaction.guild)


class PokerBetModal(Modal):
    def __init__(self, game: PokerGame, user_id: int):
        super().__init__(title="Poker Bet (1-50)")
        self.game = game
        self.user_id = user_id
        self.bet_input = TextInput(label="Bet amount", placeholder="Enter a number between 1 and 50")
        self.add_item(self.bet_input)

    async def on_submit(self, interaction: discord.Interaction):
        try:
            amount = int(str(self.bet_input.value).strip())
        except Exception:
            return await interaction.response.send_message("Invalid bet amount.", ephemeral=True)
        if amount < 1 or amount > 50:
            return await interaction.response.send_message("Bet must be between 1 and 50.", ephemeral=True)
        if self.game.started or self.game.ended:
            return await interaction.response.send_message("This game has already started.", ephemeral=True)
        if self.user_id in self.game.players:
            return await interaction.response.send_message("You already joined.", ephemeral=True)
        if len(self.game.players) >= POKER_MAX_PLAYERS:
            return await interaction.response.send_message("Table is full.", ephemeral=True)
        player = PokerPlayer(self.user_id)
        player.bet = amount
        self.game.players[self.user_id] = player
        self.game.status_text = "Waiting for players."
        await interaction.response.defer()
        await _poker_update_message(interaction.client, self.game, interaction.guild)


def _poker_build_view(game: PokerGame, guild: discord.Guild | None) -> LayoutView:
    view = LayoutView(timeout=None)
    container = Container()
    container.add_item(TextDisplay(_poker_render_text(game, guild)))

    action_row = ActionRow()
    if not game.started and not game.ended:
        action_row.add_item(PokerJoinButton(game))
        action_row.add_item(PokerStartButton(game))
    elif game.started and not game.ended:
        action_row.add_item(PokerCallButton(game))
        action_row.add_item(PokerFoldButton(game))
        action_row.add_item(PokerRaiseButton(game))
    if action_row.children:
        container.add_item(action_row)
    view.add_item(container)
    return view


async def _poker_timeout_if_not_started(bot, game: PokerGame, delay: int = 180):
    try:
        await asyncio.sleep(delay)
    except asyncio.CancelledError:
        return
    if not game.started and not game.ended:
        game.ended = True
        game.status_text = "No one joined in time. Game expired."
        ongoing_poker.pop(game.channel_id, None)
        await _poker_update_message(bot, game)


async def _poker_update_message(bot, game: PokerGame, guild: discord.Guild | None = None):
    channel = bot.get_channel(game.channel_id)
    if not channel or not game.message_id:
        return
    try:
        msg = await channel.fetch_message(game.message_id)
    except Exception:
        try:
            msg = await channel.send(view=_poker_build_view(game, guild))
            game.message_id = msg.id
            return
        except Exception:
            return
    try:
        await msg.edit(view=_poker_build_view(game, guild))
    except Exception:
        return


def _poker_get_balance(user_id: int) -> int:
    conn = connect_poke_db()
    ensure_player(conn, user_id)
    c = conn.cursor()
    c.execute("SELECT coins FROM poke WHERE player_id = ?", (user_id,))
    row = c.fetchone()
    conn.close()
    return row[0] if row and row[0] is not None else 0


def _poker_can_pay(user_id: int, amount: int) -> bool:
    return _poker_get_balance(user_id) >= amount


async def _poker_prompt_bet(ctx, initial_amount: int | None = None) -> int | None:
    if initial_amount is not None:
        if 1 <= initial_amount <= 50:
            return initial_amount
        await ctx.send("Bet must be between 1 and 50.")
        return None

    prompt = await ctx.send("How much do you want to gamble? (1-50)")

    def check(message: discord.Message):
        return message.author.id == ctx.author.id and message.channel.id == ctx.channel.id

    try:
        reply = await ctx.bot.wait_for("message", timeout=30.0, check=check)
    except asyncio.TimeoutError:
        await ctx.send("Bet prompt timed out. Try again.")
        return None

    try:
        amount = int(str(reply.content).strip())
    except Exception:
        await ctx.send("Invalid bet amount.")
        return None
    if amount < 1 or amount > 50:
        await ctx.send("Bet must be between 1 and 50.")
        return None
    return amount


async def _poker_advance_round(bot, game: PokerGame, guild: discord.Guild | None):
    active_non_dealer = game.active_player_ids()
    active_all = [pid for pid, p in game.players.items() if not p.folded]
    if (game.multiplayer and len(active_non_dealer) <= 1) or (not game.multiplayer and len(active_all) <= 1):
        game.ended = True
        winners = active_non_dealer or active_all
        if winners:
            name = _poker_player_name(guild, winners[0], game.players[winners[0]].is_dealer)
            payout = 0
            if game.pot > 0:
                if not game.multiplayer and not game.players[winners[0]].is_dealer:
                    payout = game.pot * 2
                else:
                    payout = game.pot
                if not game.players[winners[0]].is_dealer:
                    modify_coins(winners[0], payout)
            game.status_text = f"{name} wins by default. (payout {payout})"
        else:
            game.status_text = "No winners."
        await _poker_update_message(bot, game, guild)
        return

    if not game.pending:
        if len(game.community) < 3:
            game.reveal_next_card()
            game.pending = set(game.active_player_ids())
            game.raise_used = False
        else:
            game.ended = True
            winners, _ = game.resolve_showdown()
            if winners:
                names = [_poker_player_name(guild, pid, game.players[pid].is_dealer) for pid in winners]
                payout = 0
                if game.pot > 0:
                    if not game.multiplayer:
                        non_dealer_winners = [pid for pid in winners if not game.players[pid].is_dealer]
                        if non_dealer_winners:
                            payout = game.pot * 2
                            modify_coins(non_dealer_winners[0], payout)
                    else:
                        payout = game.pot // len(winners)
                        remainder = game.pot - (payout * len(winners))
                        for idx, pid in enumerate(winners):
                            modify_coins(pid, payout + (remainder if idx == 0 else 0))
                game.status_text = f"Winner: {', '.join(names)} (payout {payout})"
            else:
                game.status_text = "No winners."
        await _poker_update_message(bot, game, guild)
        return

    await _poker_update_message(bot, game, guild)


@bot.command(name="poker", aliases=["pk"])
async def poker(ctx, mode: str = None, amount: int | None = None):
    if mode and mode.lower() in {"x", "cancel", "stop"}:
        game = ongoing_poker.pop(ctx.channel.id, None)
        if not game:
            return await ctx.send("No poker game to cancel.")
        game.ended = True
        game.status_text = "Game cancelled."
        if game.timeout_task:
            game.timeout_task.cancel()
            game.timeout_task = None
        await _poker_update_message(ctx.bot, game, ctx.guild)
        return await ctx.send("Poker cancelled.")

    if ctx.channel.id in ongoing_poker and not ongoing_poker[ctx.channel.id].ended:
        return await ctx.send("A poker game is already running in this channel.")

    if mode and mode.isdigit() and amount is None:
        amount = int(mode)
        mode = None

    if mode and mode.lower() == "solo":
        bet = await _poker_prompt_bet(ctx, amount)
        if bet is None:
            return
        if not _poker_can_pay(ctx.author.id, bet):
            return await ctx.send("Not enough ARCs to start a solo game.")
        game = PokerGame(ctx.author.id, ctx.channel.id, multiplayer=False)
        player = PokerPlayer(ctx.author.id)
        player.bet = bet
        game.players[ctx.author.id] = player
        dealer_id = 0
        game.players[dealer_id] = PokerPlayer(dealer_id, is_dealer=True)
        modify_coins(ctx.author.id, -bet)
        game.pot += bet
        game.start()
        ongoing_poker[ctx.channel.id] = game
        msg = await ctx.send(view=_poker_build_view(game, ctx.guild))
        game.message_id = msg.id
        await _poker_send_hands(ctx.bot, ctx.guild, game)
        await _poker_update_message(ctx.bot, game, ctx.guild)
        return

    if mode and mode.lower() not in {"multi"}:
        return await ctx.send("Usage: `!poker` for multiplayer, `!poker solo` for single player.")

    bet = await _poker_prompt_bet(ctx, amount)
    if bet is None:
        return
    if not _poker_can_pay(ctx.author.id, bet):
        return await ctx.send("Not enough ARCs to host a multiplayer game.")

    game = PokerGame(ctx.author.id, ctx.channel.id, multiplayer=True)
    host = PokerPlayer(ctx.author.id)
    host.bet = bet
    host.real_bet = bet
    game.players[ctx.author.id] = host
    game.host_bet = bet
    ongoing_poker[ctx.channel.id] = game
    msg = await ctx.send(view=_poker_build_view(game, ctx.guild))
    game.message_id = msg.id
    game.timeout_task = asyncio.create_task(_poker_timeout_if_not_started(ctx.bot, game, delay=180))"""

@poke.command(name="admin_give", aliases=['g'])
async def poke_give(ctx, user: str, category: str, *, name_or_amount: str):
    """Owner-only: Give coins, items, pokemon, moves, TM, or exchange coupons to a user."""
    
    if ctx.author.id not in owner_ids:
        return await ctx.send("❌ You must be a bot owner to use this command.")

    # 🔍 Resolve user (ID / mention)
    if user.isdigit():
        user_id = int(user)
        try:
            target = await ctx.bot.fetch_user(user_id)
        except:
            return await ctx.send("❌ Could not find that user.")
    else:
        try:
            user_id = int(user.replace("<@", "").replace("!", "").replace(">", ""))
            target = await ctx.bot.fetch_user(user_id)
        except:
            return await ctx.send("❌ Invalid user format.")

    category = category.lower()

    conn = connect_poke_db()
    ensure_player(conn, user_id)  # ✅ FIX: ensure target, not ctx.author
    c = conn.cursor()

    # -------------------
    # Handle Coins
    # -------------------
    if category in ["coins", "arc"]:
        try:
            amount = int(name_or_amount)
        except:
            return await ctx.send("❌ Please enter a valid number for coins.")

        c.execute("UPDATE poke SET coins = coins + ? WHERE player_id = ?", (amount, user_id))
        conn.commit()
        conn.close()
        return await ctx.send(f"✅ Gave {amount} coins to {target.name}.")

    # -------------------
    # Exchange Coupons
    # -------------------
    elif category in ["exchange_coupon", "exchange-coupon", "exchange coupon", "coupon", "exchange"]:
        try:
            amount = int(name_or_amount)
        except:
            return await ctx.send("❌ Please enter a valid number for exchange coupons.")
        if amount <= 0:
            return await ctx.send("❌ Amount must be greater than 0.")

        try:
            conn_cos = sqlite3.connect("cosmetics.db")
            c_cos = conn_cos.cursor()
            _increment_coupon(c_cos, user_id, shiny=False, amount=amount)
            conn_cos.commit()
            conn_cos.close()
        except:
            conn.close()
            return await ctx.send("❌ Failed to update exchange coupons.")

        conn.close()
        return await ctx.send(f"✅ Gave {amount} exchange coupon(s) to {target.name}.")

    elif category in ["shiny_exchange_coupon", "shiny-exchange-coupon", "shiny exchange coupon", "shinycoupon", "shiny coupon"]:
        try:
            amount = int(name_or_amount)
        except:
            return await ctx.send("❌ Please enter a valid number for shiny exchange coupons.")
        if amount <= 0:
            return await ctx.send("❌ Amount must be greater than 0.")

        try:
            conn_cos = sqlite3.connect("cosmetics.db")
            c_cos = conn_cos.cursor()
            _increment_coupon(c_cos, user_id, shiny=True, amount=amount)
            conn_cos.commit()
            conn_cos.close()
        except:
            conn.close()
            return await ctx.send("❌ Failed to update shiny exchange coupons.")

        conn.close()
        return await ctx.send(f"✅ Gave {amount} shiny exchange coupon(s) to {target.name}.")

    # -------------------
    # Items
    # -------------------
    elif category == "item":
        c.execute("SELECT bag FROM poke WHERE player_id = ?", (user_id,))
        row = c.fetchone()
        bag = json.loads(row[0]) if row and row[0] else {}

        bag[name_or_amount] = bag.get(name_or_amount, 0) + 1

        c.execute("UPDATE poke SET bag = ? WHERE player_id = ?", (json.dumps(bag), user_id))
        conn.commit()
        conn.close()
        return await ctx.send(f"✅ Gave 1 `{name_or_amount}` to {target.name}.")

    # -------------------
    # Moves
    # -------------------
    elif category == "move":
        c.execute("SELECT move_list FROM poke WHERE player_id = ?", (user_id,))
        row = c.fetchone()
        mlist = json.loads(row[0]) if row and row[0] else []

        if name_or_amount not in mlist:
            mlist.append(name_or_amount)

        c.execute("UPDATE poke SET move_list = ? WHERE player_id = ?", (json.dumps(mlist), user_id))
        conn.commit()
        conn.close()
        return await ctx.send(f"✅ Gave move `{name_or_amount}` to {target.name}.")

    # -------------------
    # Pokémon
    # -------------------
    elif category == "pokemon":
        c.execute("SELECT pokemon_list FROM poke WHERE player_id = ?", (user_id,))
        row = c.fetchone()
        plist = json.loads(row[0]) if row and row[0] else []

        if name_or_amount not in plist:
            plist.append(name_or_amount)

        c.execute("UPDATE poke SET pokemon_list = ? WHERE player_id = ?", (json.dumps(plist), user_id))
        conn.commit()
        conn.close()
        return await ctx.send(f"✅ Gave Pokémon `{name_or_amount}` to {target.name}.")

    # -------------------
    # TM
    # -------------------
    elif category.endswith("tm"):
        c.execute("SELECT move_list FROM poke WHERE player_id = ?", (user_id,))
        row = c.fetchone()
        mlist = json.loads(row[0]) if row and row[0] else []

        if name_or_amount not in mlist:
            mlist.append(name_or_amount)

        c.execute("UPDATE poke SET move_list = ? WHERE player_id = ?", (json.dumps(mlist), user_id))
        conn.commit()
        conn.close()
        return await ctx.send(f"✅ Gave TM `{name_or_amount}` to {target.name}.")

    else:
        conn.close()
        return await ctx.send("❌ Unknown category. Use: coins, item, move, pokemon, or tm.")

