POKEMON_DIR = "pokemon_data"
MOVE_DIR = "move_data"

def load_all_pokemon(folder=POKEMON_DIR):
    pokemons = []
    if not os.path.isdir(folder):
        return pokemons
    for file in os.listdir(folder):
        if file.endswith(".json"):
            with open(os.path.join(folder, file), "r", encoding="utf-8") as f:
                pokemons.append(json.load(f))
    return pokemons

def load_all_move():
    moves = {}
    for file in os.listdir(MOVE_DIR):
        if file.endswith(".json"):
            with open(os.path.join(MOVE_DIR, file), "r") as f:
                move = json.load(f)
                moves[move["name"]] = move
    return moves

# 1. Search Pokémon by type
def search_pokemon_by_type(pokemon_list, type_name):
    return [p["name"] for p in pokemon_list if type_name in p["types"]]

# 2. Search Pokémon that learns a specific move
def search_pokemon_by_move(pokemon_list, move_name):
    return [
        p["name"]
        for p in pokemon_list
        if any(m["move"] == move_name for m in p["moves_via_level_up"])
    ]

# 3. Search Pokémon that learns moves of a specific type
def search_pokemon_by_move_type(pokemon_list, move_dict, move_type):
    # find all moves of the requested type
    moves_of_type = {m["name"] for m in move_dict.values() if m["type"] == move_type}
    results = []
    for p in pokemon_list:
        learned_moves = {m["move"] for m in p["moves_via_level_up"]}
        if learned_moves & moves_of_type:  # set intersection
            results.append(p["name"])
    return results

POKEMON_TYPES = [
    "normal", "fire", "water", "grass", "electric", "ice",
    "fighting", "poison", "ground", "flying", "psychic",
    "bug", "rock", "ghost", "dragon", "dark", "steel", "fairy"
]

class PaginationView(discord.ui.View):
    def __init__(self, results, per_page=20):
        super().__init__(timeout=180)
        self.results = results
        self.per_page = per_page
        self.page = 0
        self.max_page = (len(results) - 1) // per_page

    def get_embed(self):
        start = self.page * self.per_page
        end = start + self.per_page
        chunk = self.results[start:end]

        embed = discord.Embed(
            title=f"Pokémon Search Results (Page {self.page+1}/{self.max_page+1})",
            description="\n".join(f"• {name}" for name in chunk),
            color=discord.Color.green()
        )
        embed.set_footer(text=f"Total results: {len(self.results)}")
        return embed

    @discord.ui.button(label="⬅️ Prev", style=discord.ButtonStyle.secondary)
    async def prev(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page > 0:
            self.page -= 1
            await interaction.response.edit_message(embed=self.get_embed(), view=self)

    @discord.ui.button(label="➡️ Next", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page < self.max_page:
            self.page += 1
            await interaction.response.edit_message(embed=self.get_embed(), view=self)

@bot.tree.command(name="pokemon_search", description="Search for a list of Pokémon")
@app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
@app_commands.describe(
    type1="First Pokémon type (or 'any')",
    type2="Second Pokémon type (or 'any')",
    learns="Specific move the Pokémon must learn (or 'any')",
    learns_move_type="Move type the Pokémon must learn (ignores status moves) (or 'any')",
    keyword="Search Pokémon name by keyword (e.g. 'mega', 'alola')",
    ability="Search by ability",
    rarity = "rarity of pokemon (rare or common)",
    min_total="Minimum total base stats",
    max_total="Maximum total base stats",
    min_hp="Minimum HP stat",
    min_attack="Minimum Attack stat",
    min_defense="Minimum Defense stat",
    min_spatk="Minimum Special Attack stat",
    min_spdef="Minimum Special Defense stat",
    min_speed="Minimum Speed stat",
    exact_speed="Exact speed stat",
    fake="Fakemon or Pokemon"
)
@app_commands.choices(
    type1=[app_commands.Choice(name=t.capitalize(), value=t) for t in POKEMON_TYPES] + [app_commands.Choice(name="Any", value="any")],
    type2=[app_commands.Choice(name=t.capitalize(), value=t) for t in POKEMON_TYPES] + [app_commands.Choice(name="Any", value="any")],
    learns_move_type=[app_commands.Choice(name=t.capitalize(), value=t) for t in POKEMON_TYPES] + [app_commands.Choice(name="Any", value="any")]
)
async def pokemon_search(
    interaction: discord.Interaction,
    type1: str = "any",
    type2: str = "any",
    learns: str = "any",
    learns_move_type: str = "any",
    keyword: str = None,
    ability: str = "any",
    rarity: str = None,
    min_total: int = 0,
    max_total: int = 9999,
    min_hp: int = 0,
    min_attack: int = 0,
    min_defense: int = 0,
    min_spatk: int = 0,
    min_spdef: int = 0,
    min_speed: int = 0,
    exact_speed: int = None,
    fake: bool = False
):
    await interaction.response.defer()
    results = []
    data_folder = fakemon_data_folder if fake else POKEMON_DIR
    pokemons = load_all_pokemon(data_folder)
    moves = load_all_move()
    learns = learns.replace(" ", "-")

    for p in pokemons:
        if p.get("class"):
            continue

        if rarity and rarity.lower() == "rare":
            if p not in rares:
                continue
        elif rarity and rarity.lower() != "rare":
            if p in rares:
                continue
        # --- Type filtering ---
        if type1 != "any" and type1 not in p["types"]:
            continue
        if type2 != "any" and type2 not in p["types"]:
            continue
        if type1 != "any" and type2 != "any":
            if not (type1 in p["types"] and type2 in p["types"]):
                continue

        # --- Learns specific move ---
        if learns != "any":
            all_moves = {m["move"] for m in p.get("moves_via_level_up", [])}
            if learns not in all_moves:
                continue

        # --- Learns move of specific type (excluding status moves) ---
        if learns_move_type != "any":
            moves_of_type = {
                m["name"] for m in moves.values()
                if m["type"] == learns_move_type and m["category"] != "status"
            }
            learned_moves = {m["move"] for m in p.get("moves_via_level_up", [])}
            if not (learned_moves & moves_of_type):
                continue

        # --- Keyword search ---
        if keyword and keyword.lower() not in p["name"].lower():
            continue

        # ability
        if ability != "any" and ability not in p["abilities"]:
            continue

        # --- Stat filtering ---
        stats, _ = get_pokemon_stats(p["name"])
        if isinstance(stats, str):  # skip if "poke not found"
            continue

        total = sum(stats)
        hp, attack, defense, spatk, spdef, speed = stats

        if not (min_total <= total <= max_total):
            continue
        if hp < min_hp or attack < min_attack or defense < min_defense:
            continue
        if spatk < min_spatk or spdef < min_spdef or speed < min_speed:
            continue
        if exact_speed:
            if speed != exact_speed:
                continue

        results.append(f"{p['name']}")

    if not results:
        await interaction.followup.send("No Pokémon found with the given criteria.")
    else:
        view = PaginationView(results)
        await interaction.followup.send(embed=view.get_embed(), view=view)

