def add_random_stats(stats: dict, total_points: int):
    keys = list(stats.keys())
    remaining = total_points

    while remaining > 0:
        if total_points > 50:
            max_step = 50
        else:
            max_step = total_points
        stat = random.choice(keys)
        add = random.randint(1, min(remaining, max_step))  # choose 1–20 per step, adjust max as desired
        stats[stat] += add
        remaining -= add
    return stats
def get_custom_pokemon(player_id):
    conn = connect_poke_db()
    ensure_player(conn, player_id)
    c = conn.cursor()
    row = c.execute("SELECT custom_pokemon FROM poke WHERE player_id=?", (player_id,)).fetchone()
    conn.close()
    if not row or not row[0]:
        return None
    file_path = os.path.join(pokemon_data_folder, f"{row[0].lower()}.json")
    if not os.path.exists(file_path):
        return None
    with open(file_path, "r") as f:
        return json.load(f), file_path
def save_custom_pokemon(data, file_path):
    with open(file_path, "w") as f:
        json.dump(data, f, indent=4)

def _list_fakemon_created_by(user_id: int) -> list[dict]:
    entries = []
    if not os.path.isdir(fakemon_data_folder):
        return entries
    for filename in os.listdir(fakemon_data_folder):
        if not filename.endswith(".json"):
            continue
        file_path = os.path.join(fakemon_data_folder, filename)
        try:
            with open(file_path, "r", encoding="utf-8") as f:
                payload = json.load(f)
        except Exception:
            continue
        try:
            creator = int(payload.get("creator"))
        except Exception:
            continue
        if creator != int(user_id):
            continue
        name = str(payload.get("name") or os.path.splitext(filename)[0]).strip().lower()
        types = [str(t).strip().lower() for t in (payload.get("types") or []) if str(t).strip()]
        entries.append(
            {
                "name": name,
                "file_path": file_path,
                "types": types,
                "total_stats": sum(int(v) for v in (payload.get("stats") or {}).values()),
                "payload": payload,
            }
        )
    entries.sort(key=lambda x: x["name"])
    return entries

class FakemonOwnedListView(discord.ui.View):
    def __init__(self, owner_id: int, entries: list[dict], per_page: int = 12):
        super().__init__(timeout=180)
        self.owner_id = int(owner_id)
        self.entries = entries
        self.per_page = max(1, int(per_page))
        self.page = 0
        self.max_page = max(0, (len(self.entries) - 1) // self.per_page)
        self.message: discord.Message | None = None

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.owner_id:
            await interaction.response.send_message("This list is not for you.", ephemeral=True)
            return False
        return True

    def _build_embed(self) -> discord.Embed:
        start = self.page * self.per_page
        end = start + self.per_page
        lines = []
        for idx, entry in enumerate(self.entries[start:end], start=start + 1):
            types = "/".join(entry.get("types") or ["unknown"])
            lines.append(f"**{idx}.** `{entry['name']}` | {types} | BST `{entry['total_stats']}`")
        desc = "\n".join(lines) if lines else "No entries."
        embed = discord.Embed(
            title="Your Fakemon",
            description=desc,
            color=discord.Color.blurple(),
        )
        embed.set_footer(text=f"Page {self.page + 1}/{self.max_page + 1} • /custom_pokemon edit <name>")
        return embed

    async def _refresh(self, interaction: discord.Interaction):
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                if child.custom_id == "fakemon_prev":
                    child.disabled = self.page <= 0
                elif child.custom_id == "fakemon_next":
                    child.disabled = self.page >= self.max_page
        await interaction.response.edit_message(embed=self._build_embed(), view=self)

    @discord.ui.button(label="Prev", style=discord.ButtonStyle.secondary, custom_id="fakemon_prev")
    async def prev_page(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page > 0:
            self.page -= 1
        await self._refresh(interaction)

    @discord.ui.button(label="Next", style=discord.ButtonStyle.secondary, custom_id="fakemon_next")
    async def next_page(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.page < self.max_page:
            self.page += 1
        await self._refresh(interaction)

class CustomPokemonCommands(app_commands.Group):
    def __init__(self):
        super().__init__(name="custom_pokemon", description="All custom pokemon commands")
    
    async def item_autocomplete(self, interaction: discord.Interaction, current: str):
        return [
            app_commands.Choice(name=item, value=item.lower())
            for item in CUSTOM_ITEMS
            if current.lower() in item.lower()
        ][:25]  # limit max 25 for Discord

    async def stat_autocomplete(self, interaction: discord.Interaction, current: str):
        return [
            app_commands.Choice(name=s.title(), value=s)
            for s in CUSTOM_STATS
            if current.lower() in s.lower()
        ]
    async def owned_fakemon_autocomplete(self, interaction: discord.Interaction, current: str):
        created = _list_fakemon_created_by(interaction.user.id)
        current_lower = str(current or "").lower()
        choices = []
        for entry in created:
            name = entry["name"]
            if current_lower and current_lower not in name.lower():
                continue
            choices.append(app_commands.Choice(name=name, value=name))
            if len(choices) >= 25:
                break
        return choices

    @app_commands.command(name="edit", description="Edit a fakemon you created")
    @app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
    @app_commands.autocomplete(name=owned_fakemon_autocomplete)
    async def custom_pokemon(
        self,
        interaction: discord.Interaction,
        name: str,
        sprite_url: str = None
    ):
        await interaction.response.defer()
        player_id = int(interaction.user.id)
        target_name = str(name or "").strip().lower()
        if not target_name:
            return await interaction.followup.send("Please provide the fakemon name you created.")

        creator_entries = _list_fakemon_created_by(player_id)
        target = None
        for entry in creator_entries:
            if entry["name"] == target_name:
                target = entry
                break

        if target is None:
            return await interaction.followup.send(
                "❌ You can only edit fakemon where you are the `creator`.",
                ephemeral=True,
            )

        payload = target["payload"]
        if sprite_url:
            sprite_url = str(sprite_url).strip()
            if sprite_url.startswith("http"):
                payload.setdefault("sprites", {})
                payload["sprites"]["default_front"] = sprite_url
                payload["sprites"]["shiny_front"] = sprite_url

        view = FakemonCreateView(
            player_id,
            edit_payload=payload,
            file_path=target["file_path"],
        )
        msg = await interaction.followup.send(view=view)
        view.message = msg
    @app_commands.command(name="delete", description="Delete custom Pokémon")
    async def delete_custom_pokemon(self, interaction: discord.Interaction, user: discord.User, reason: str):
        if interaction.user.id not in owner_ids:
            return await interaction.response.send_message("You must be bot owner to delete pokemon.")

        await interaction.response.defer()

        conn = connect_poke_db()
        setup_poke(conn)
        ensure_player(conn, interaction.user.id)
        c = conn.cursor()

        player_id = user.id
        row = c.execute("SELECT custom_pokemon FROM poke WHERE player_id=?", (player_id,)).fetchone()

        if not row or row[0] == None:
            return await interaction.followup.send("❌ No custom Pokémon to delete.")

        name = row[0]
        file_path = os.path.join(pokemon_data_folder, f"{name}.json")

        # Remove file
        if os.path.exists(file_path):
            os.remove(file_path)

        # Remove name from txt
        remove_pokemon_name(name)

        # Clear DB field
        c.execute("UPDATE poke SET custom_pokemon=NULL WHERE player_id=?", (player_id,))
        conn.commit()
        conn.close()
        try:
            await user.send(
                f"⚠️ Your custom Pokémon **{name}** has been deleted by a bot admin.\n"
                f"Reason: {reason}"
            )
        except Exception:
            # User may have DMs closed
            pass

        await interaction.followup.send(f"🗑 Custom Pokémon **{name}** deleted successfully.")

    @app_commands.command(name="use", description="Use items on your custom Pokémon")
    @app_commands.autocomplete(item=item_autocomplete, stat=stat_autocomplete)
    async def use_custom_item(
        self,
        interaction: discord.Interaction,
        item: str,  # must exist in bag
        quantity: int,
        stat: str = None,
        primary_type: str = None,
        secondary_type: str = None
    ):
        player_id = interaction.user.id
        await interaction.response.defer()

        # 1️⃣ Get bag and custom pokemon
        conn = connect_poke_db()
        ensure_player(conn, interaction.user.id)
        c = conn.cursor()
        row = c.execute("SELECT bag, custom_pokemon FROM poke WHERE player_id=?", (player_id,)).fetchone()
        if not row or not row[1]:
            conn.close()
            return await interaction.followup.send("❌ You don't have a custom Pokémon.")

        bag = json.loads(row[0] or "{}")
        poke_name = row[1]
        file_path = os.path.join(pokemon_data_folder, f"{poke_name.lower()}.json")
        if not os.path.exists(file_path):
            conn.close()
            return await interaction.followup.send("❌ Pokémon file not found.")

        with open(file_path, "r") as f:
            poke_data = json.load(f)

        # 2️⃣ Check if player has enough of the item
        item_key = item.lower()
        if bag.get(item_key, 0) < quantity:
            conn.close()
            return await interaction.followup.send(f"❌ You only have {bag.get(item_key,0)} of {item.title()} in your bag. (You can obtain more from the !poke shop)")

        # 3️⃣ Apply item effect
        stats = poke_data["stats"]
        total_stats = sum(stats.values())
        changed = False
        msg = ""

        # Evolution/boost items
        if item_key == "evolution potion":
            if total_stats >= 680:
                return await interaction.followup.send("⚠️ Pokémon stats too high for Evolution Potion.")
            for _ in range(quantity):
                stats = add_random_stats(stats, 10)
            changed = True
            msg = f"✅ Evolution Potion applied {quantity}x, stats increased randomly."

        elif item_key == "max evolution boost":
            if total_stats >= 680:
                return await interaction.followup.send("⚠️ Pokémon stats too high for Max Evolution Boost.")
            for _ in range(quantity):
                stats = add_random_stats(stats, 100)
            changed = True
            msg = f"✅ Max Evolution Boost applied {quantity}x, stats increased randomly."

        elif item_key == "limit break":
            if total_stats >= 780:
                return await interaction.followup.send("⚠️ Pokémon stats too high for Limit Break.")
            for _ in range(quantity):
                stats = add_random_stats(stats, 5)
            changed = True
            msg = f"✅ Limit Break applied {quantity}x, stats increased randomly."

        # Stat enhancers/removers
        elif item_key in ["stats enhancer (10)", "stats enhancer (1)", "stats remover (10)", "stats remover (1)"]:
            if not stat:
                return await interaction.followup.send("⚠️ You must choose a stat.")
            stat_key = stat.value
            amount = {"stats enhancer (10)":10, "stats enhancer (1)":1, "stats remover (10)":-10, "stats remover (1)":-1}[item_key] * quantity
            stats[stat_key] = max(1, stats[stat_key] + amount)
            changed = True
            msg = f"✅ {stat_key.title()} {'increased' if amount>0 else 'decreased'} by {abs(amount)}."

        # Type changer
        elif item_key == "type changer":
            if not primary_type:
                return await interaction.followup.send("⚠️ Must provide primary type.")
            types = [primary_type.lower()]
            if secondary_type and secondary_type.lower() != primary_type.lower():
                types.append(secondary_type.lower())
            poke_data["types"] = types
            changed = True
            msg = f"✅ Pokémon types changed to: {', '.join(types)}."

        # TM move
        elif item_key in CUSTOM_TM:
            # Add TM move
            move_name = item_key.replace(" tm","")
            for _ in range(quantity):
                poke_data["moves_via_level_up"].append({"move": move_name, "level_learned_at":1})

        else:
            conn.close()
            return await interaction.followup.send("❌ Unknown item or missing parameters.")

        # 4️⃣ Deduct items from bag
        bag[item_key] -= quantity
        if bag[item_key] <= 0:
            del bag[item_key]

        # 5️⃣ Save updates
        poke_data["stats"] = stats
        save_custom_pokemon(poke_data, file_path)
        c.execute("UPDATE poke SET bag=? WHERE player_id=?", (json.dumps(bag), player_id))
        conn.commit()
        conn.close()

        await interaction.followup.send(msg)

    @app_commands.command(name="view", description="View fakemon you created")
    async def view_custom_pokemon(self, interaction: discord.Interaction):
        player_id = interaction.user.id
        await interaction.response.defer()
        entries = _list_fakemon_created_by(player_id)
        if not entries:
            return await interaction.followup.send("❌ You have not created any fakemon yet.")

        view = FakemonOwnedListView(player_id, entries, per_page=10)
        for child in view.children:
            if isinstance(child, discord.ui.Button):
                if child.custom_id == "fakemon_prev":
                    child.disabled = True
                if child.custom_id == "fakemon_next":
                    child.disabled = view.max_page <= 0
        await interaction.followup.send(embed=view._build_embed(), view=view)
import discord
from discord import app_commands
from discord.ui import View, Select, Modal, TextInput
import sqlite3
import os
import asyncio

# ----------------------------------------------------
# DATABASE
# ----------------------------------------------------
def get_autorole_db(guild_id):
    os.makedirs("autoroles", exist_ok=True)
    db_file = os.path.join("autoroles", f"{guild_id}.db")
    conn = sqlite3.connect(db_file)
    c = conn.cursor()
    # Create tables if not exist
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_badge_count (
        badges_required INTEGER,
        role_id INTEGER
    )""")
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_specific_badge (
        badge_name TEXT,
        role_id INTEGER
    )""")
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_specific_elite_badge (
        elite_badge_id INTEGER,
        role_id INTEGER
    )""")
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_elite_count (
        elite_count_required INTEGER,
        role_id INTEGER
    )""")
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_achievement (
        achievement_name TEXT,
        role_id INTEGER
    )""")
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_gym_leader (
        role_id INTEGER
    )""")
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_gym_manager (
        role_id INTEGER
    )""")
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_mvp (
        role_id INTEGER
    )""")
    c.execute("""
    CREATE TABLE IF NOT EXISTS autorole_clan_leader (
        role_id INTEGER
    )""")
    conn.commit()
    return conn

# ----------------------------------------------------
# EMBED BUILDER
# ----------------------------------------------------
async def build_autorole_embed(guild: discord.Guild) -> discord.Embed:
    """
    Build the autorole embed.  
    Conditional tables: show 'value : @Role'  
    Simple tables: show '@Role'  
    Remove any role from the DB if it no longer exists.
    """
    embed = discord.Embed(
        title="🎛️ Autorole Configuration",
        description="Current autorole conditions for this server.",
        color=discord.Color.blurple()
    )

    # Tables that have a "condition value" (number or badge/achievement)
    conditional_tables = {
        "Obtain X number of badges": "autorole_badge_count",
        "Obtain specific badge": "autorole_specific_badge",
        "Obtain specific elite badge": "autorole_specific_elite_badge",
        "Obtain X elite badges": "autorole_elite_count",
        "Achieve specific achievement": "autorole_achievement",
    }

    # Tables that are "simple roles"
    simple_tables = {
        "Become Gym Leader": "autorole_gym_leader",
        "Become Gym Manager": "autorole_gym_manager",
        "Become MVP in Clan War": "autorole_mvp",
        "Become Clan Leader": "autorole_clan_leader",
    }

    # Process conditional tables
    for name, table in conditional_tables.items():
        conn = get_autorole_db(guild.id)
        c = conn.cursor()

        # Fetch all rows; for simplicity all tables have (value?, role_id)
        c.execute(f"SELECT * FROM {table}")
        rows = c.fetchall()

        values_list = []
        for r in rows:
            if len(r) == 1:
                # Only role_id
                role_id = r[0]
                value = ""
            else:
                # value + role_id
                value, role_id = r
            role = guild.get_role(role_id)
            if role:
                if value:
                    values_list.append(f"{value} : <@&{role_id}>")
                else:
                    values_list.append(f"<@&{role_id}>")
            else:
                # Remove missing role from DB
                c.execute(f"DELETE FROM {table} WHERE role_id=?", (role_id,))
        conn.commit()
        conn.close()

        embed.add_field(name=name, value="\n".join(values_list) or "None", inline=False)

    # Process simple tables
    for name, table in simple_tables.items():
        conn = get_autorole_db(guild.id)
        c = conn.cursor()

        c.execute(f"SELECT role_id FROM {table}")
        rows = c.fetchall()

        role_mentions = []
        for r in rows:
            role_id = r[0]
            role = guild.get_role(role_id)
            if role:
                role_mentions.append(f"<@&{role_id}>")
            else:
                c.execute(f"DELETE FROM {table} WHERE role_id=?", (role_id,))
        conn.commit()
        conn.close()

        embed.add_field(name=name, value="\n".join(role_mentions) or "None", inline=False)

    return embed


# ----------------------------------------------------
# ROLE SELECT VIA MESSAGE
# ----------------------------------------------------
async def ask_for_role(interaction: discord.Interaction, save_callback, view):
    if not interaction.user.guild_permissions.administrator:
        return await interaction.response.send_message(
            "Only admins can use this.", ephemeral=True
        )

    await interaction.response.send_message(
        "Please type the role you want to assign (example: @Champion).",
        ephemeral=True
    )

    def check(m):
        return (
            m.author.id == interaction.user.id
            and m.channel.id == interaction.channel.id
        )

    try:
        msg = await interaction.client.wait_for("message", timeout=30, check=check)
    except asyncio.TimeoutError:
        return await interaction.followup.send(
            "Timed out. Please try again.",
            ephemeral=True
        )

    digits = "".join(ch for ch in msg.content if ch.isdigit())
    role = interaction.guild.get_role(int(digits)) if digits else None

    if not role:
        return await interaction.followup.send(
            "Invalid role. Please mention a valid role.",
            ephemeral=True
        )

    await save_callback(interaction, role, view)
    await interaction.followup.send(
        f"Autorole saved! ({role.mention})",
        ephemeral=True
    )

