def setup_streak_db():
    conn = get_elo_db()
    c = conn.cursor()
    c.execute("""
        CREATE TABLE IF NOT EXISTS ranked_streaks (
            winner_id INTEGER,
            loser_id INTEGER,
            queue_type TEXT,
            streak INTEGER DEFAULT 0,
            PRIMARY KEY (winner_id, loser_id, queue_type)
        )
    """)
    conn.commit()
    conn.close()

setup_streak_db()

def increment_streak(winner_id: int, loser_id: int, queue_type: str) -> int:
    """Increment win streak for winner vs this specific loser. Returns new streak count."""
    conn = get_elo_db()
    c = conn.cursor()
    c.execute("""
        INSERT INTO ranked_streaks (winner_id, loser_id, queue_type, streak)
        VALUES (?, ?, ?, 1)
        ON CONFLICT(winner_id, loser_id, queue_type)
        DO UPDATE SET streak = streak + 1
    """, (winner_id, loser_id, queue_type))
    c.execute(
        "SELECT streak FROM ranked_streaks WHERE winner_id=? AND loser_id=? AND queue_type=?",
        (winner_id, loser_id, queue_type)
    )
    streak = c.fetchone()[0]
    conn.commit()
    conn.close()
    return streak

def reset_streak(winner_id: int, loser_id: int, queue_type: str):
    """Reset streak when the loser finally wins."""
    conn = get_elo_db()
    c = conn.cursor()
    c.execute("""
        INSERT INTO ranked_streaks (winner_id, loser_id, queue_type, streak)
        VALUES (?, ?, ?, 0)
        ON CONFLICT(winner_id, loser_id, queue_type)
        DO UPDATE SET streak = 0
    """, (winner_id, loser_id, queue_type))
    conn.commit()
    conn.close()



def _normalize_ranked_queue_type(value: str | None) -> str | None:
    if not value:
        return None
    key = str(value).strip().lower()
    if key in ("rare", "ranked rare"):
        return "ranked rare"
    if key in ("common", "ranked common"):
        return "ranked common"
    return None

def _ensure_ranked_player(cursor, user_id: int, queue_type: str):
    cursor.execute(
        """
        INSERT OR IGNORE INTO ranked_elo (user_id, queue_type, rating, highest_rating, wins, losses)
        VALUES (?, ?, 1000, 1000, 0, 0)
        """,
        (user_id, queue_type),
    )

def get_ranked_stats(user_id: int, queue_type: str):
    queue_type = _normalize_ranked_queue_type(queue_type)
    if not queue_type:
        return 1000, 0, 0
    conn = get_elo_db()
    c = conn.cursor()
    _ensure_ranked_player(c, user_id, queue_type)
    c.execute(
        "SELECT rating, wins, losses FROM ranked_elo WHERE user_id=? AND queue_type=?",
        (user_id, queue_type),
    )
    row = c.fetchone()
    conn.commit()
    conn.close()
    if not row:
        return 1000, 0, 0
    return int(row["rating"]), int(row["wins"]), int(row["losses"])

def get_ranked_stats_with_highest(user_id: int, queue_type: str):
    """Get current rating, highest rating, wins, losses for a user and queue type."""
    queue_type = _normalize_ranked_queue_type(queue_type)
    if not queue_type:
        return 1000, 1000, 0, 0
    conn = get_elo_db()
    c = conn.cursor()
    _ensure_ranked_player(c, user_id, queue_type)
    c.execute(
        "SELECT rating, highest_rating, wins, losses FROM ranked_elo WHERE user_id=? AND queue_type=?",
        (user_id, queue_type),
    )
    row = c.fetchone()
    conn.commit()
    conn.close()
    if not row:
        return 1000, 1000, 0, 0
    return int(row["rating"]), int(row["highest_rating"]), int(row["wins"]), int(row["losses"])

def update_ranked_stats(user_id: int, queue_type: str, rating: int | None = None, wins_delta: int = 0, losses_delta: int = 0):
    queue_type = _normalize_ranked_queue_type(queue_type)
    if not queue_type:
        return
    conn = get_elo_db()
    c = conn.cursor()
    _ensure_ranked_player(c, user_id, queue_type)
    if rating is not None:
        rating = int(rating)
        # Update highest_rating if the new rating is higher
        c.execute(
            """
            UPDATE ranked_elo
            SET rating = ?, highest_rating = MAX(highest_rating, ?), wins = wins + ?, losses = losses + ?
            WHERE user_id=? AND queue_type=?
            """,
            (rating, rating, int(wins_delta), int(losses_delta), user_id, queue_type),
        )
    else:
        c.execute(
            """
            UPDATE ranked_elo
            SET wins = wins + ?, losses = losses + ?
            WHERE user_id=? AND queue_type=?
            """,
            (int(wins_delta), int(losses_delta), user_id, queue_type),
        )
    conn.commit()
    conn.close()

def get_ranked_leaderboard(queue_type: str, limit: int = 100):
    queue_type = _normalize_ranked_queue_type(queue_type)
    if not queue_type:
        return []
    conn = get_elo_db()
    c = conn.cursor()
    c.execute(
        """
        SELECT user_id, wins, losses, rating
        FROM ranked_elo
        WHERE queue_type=?
        ORDER BY rating DESC, wins DESC, user_id ASC
        LIMIT ?
        """,
        (queue_type, limit),
    )
    rows = c.fetchall()
    conn.close()
    return [(int(r["user_id"]), int(r["wins"]), int(r["losses"]), int(r["rating"])) for r in rows]

def _calculate_elo_delta(rating_a: int, rating_b: int, score_a: float, k: int = 32) -> float:
    expected_a = 1 / (1 + 10 ** ((rating_b - rating_a) / 800))
    return (score_a - expected_a) * k

def _calculate_elo_delta_lose(rating_a: int, rating_b: int, score_a: float, k: int = 32) -> float:
    expected_a = 1 / (1 + 10 ** ((rating_b - rating_a + 50) / 800))
    return (score_a - expected_a) * k
