def _award_ranked_status_cosmetic(user_id: int, highest_rating: int) -> bool:
    cosmetic = _status_cosmetic_by_rating(highest_rating)
    if not cosmetic:
        return False
    conn = sqlite3.connect("cosmetics.db")
