def cleanup_old_logs(days: int = 14):
    cutoff = int(time.time()) - days * 86400
    conn = get_queue_db()
    c = conn.cursor()
    c.execute("DELETE FROM queue_logs WHERE timestamp < ?", (cutoff,))
    conn.commit()
    conn.close()

