class HistoryView(discord.ui.View):
    def __init__(self, entries, user, items_per_page=5):
        super().__init__(timeout=120)
        self.entries = entries
        self.user = user
        self.page = 0
        self.items_per_page = items_per_page

    def build_embed(self):
        embed = discord.Embed(title=f"Battle History for {self.user.display_name}")
        start = self.page * self.items_per_page
        end = start + self.items_per_page
        chunk = self.entries[start:end]

        for row in chunk:
            dt = time.strftime('%Y-%m-%d %H:%M:%S', time.localtime(row['timestamp']))
            outcome = "Win" if row["winner_id"] == self.user.id else "Loss"
            server_name = "DM" if row["server_id"] is None else f"Server ID {row['server_id']}"
            embed.add_field(name=f"{dt}", value=f"{row['type']} in {server_name} → {outcome}", inline=False)

        embed.set_footer(text=f"Page {self.page + 1}/{(len(self.entries) - 1) // self.items_per_page + 1}")
        return embed

    @discord.ui.button(label="⬅️", style=discord.ButtonStyle.gray)
    async def prev_page(self, interaction: discord.Interaction, button):
        if self.page > 0:
            self.page -= 1
            await interaction.response.edit_message(embed=self.build_embed(), view=self)

    @discord.ui.button(label="➡️", style=discord.ButtonStyle.gray)
    async def next_page(self, interaction: discord.Interaction, button):
        if (self.page + 1) * self.items_per_page < len(self.entries):
            self.page += 1
            await interaction.response.edit_message(embed=self.build_embed(), view=self)

