class ChallengeNumberModal(discord.ui.Modal, title="Enter Player Number"):
    number = discord.ui.TextInput(label="Player Number")

    def __init__(self, interaction, entries, queue_type):
        super().__init__()
        self.entries = entries
        self.interaction = interaction
        self.queue_type = queue_type

    async def on_submit(self, interaction: discord.Interaction):
        try:
            idx = int(self.number.value) - 1
        except:
            return await interaction.response.send_message("Invalid number.", ephemeral=True)

        if idx < 0 or idx >= len(self.entries):
            return await interaction.response.send_message("Out of range.", ephemeral=True)

        target = self.entries[idx]
        challenger = self.interaction.user

        # After selecting player → ask for server location
        if self.queue_type in ["p2 common", "p2 rare", "improved p2 battle", "showdown battle"]:
            options = [
                discord.SelectOption(label="Current Server"),
                discord.SelectOption(label="Target Server"),
                discord.SelectOption(label="Remote")
            ]
        else:
            options = [
                discord.SelectOption(label="Current Server"),
                discord.SelectOption(label="Target Server")
            ]

        view = ServerLocationView(challenger, target, self.queue_type, options)
        await interaction.response.send_message(
            f"Select where to host the match vs <@{target['user_id']}>:",
            view=view,
            ephemeral=True
        )
