# ---------------------------------------------------------
# Helper: Create an invite link for a server
# ---------------------------------------------------------
async def generate_invite_link(guild: discord.Guild):
    """Return invite link or None if cannot create."""
    try:
        for channel in guild.text_channels:
            perms = channel.permissions_for(guild.me)
            if perms.create_instant_invite:
                invite = await channel.create_invite(max_age=300, max_uses=1)
                return str(invite)
        return None
    except:
        return None


