class ServerLocationView(discord.ui.View):
    def __init__(self, challenger, target, q_type, options):
        super().__init__(timeout=60)
        self.challenger = challenger
        self.target = target       # dict: contains user_id + server_id
        self.q_type = q_type
        self.options = options

        # Dropdown
        select = discord.ui.Select(
            placeholder="Choose location...",
            options=options
        )
        select.callback = self.select_callback
        self.add_item(select)

        # Add message button
        self.add_item(MessageButton(target["user_id"]))

    # ---------------------------------------------------------
    # Main callback for dropdown select
    # ---------------------------------------------------------
    async def select_callback(self, interaction: discord.Interaction):
        selected = interaction.data["values"][0]

        # Get defender user
        user = interaction.client.get_user(self.target["user_id"])
        if not user:
            user = await interaction.client.fetch_user(self.target["user_id"])

        # -------- LOCATION CHOSEN --------
        # CURRENT SERVER
        if selected == "Current Server":
            guild = interaction.guild
            if guild is None:
                return await interaction.response.send_message(
                    "❌ You are not inside a server.", ephemeral=True
                )

            invite = await generate_invite_link(guild)
            if invite is None:
                # Retry selection
                new_view = ServerLocationView(self.challenger, self.target, self.q_type, self.options)
                return await interaction.response.send_message(
                    "❌ I cannot create an invite link for this server.\n"
                    "Please choose again.",
                    view=new_view,
                    ephemeral=True
                )

            location_text = f"challenger location: {guild.name} {invite}"

        # TARGET SERVER
        elif selected == "Target Server":
            target_server_id = self.target["server_id"]
            if target_server_id is None:
                return await interaction.response.send_message(
                    "❌ Defender did not queue from a server.\n"
                    "Please choose a different location.",
                    ephemeral=True
                )

            guild = interaction.client.get_guild(target_server_id)
            if guild is None:
                return await interaction.response.send_message(
                    "❌ I cannot access the defender’s server.",
                    ephemeral=True
                )

            invite = await generate_invite_link(guild)
            if invite is None:
                new_view = ServerLocationView(self.challenger, self.target, self.q_type, self.options)
                return await interaction.response.send_message(
                    "❌ Cannot create invite for defender’s server.\n"
                    "Please choose again.",
                    view=new_view,
                    ephemeral=True
                )

            location_text = f"your location: {guild.name} {invite}"

        else:
            # Remote option → no invite
            location_text = "remote (no invite link required)"

        # -------- SEND DM TO DEFENDER --------
        try:
            # This view should be defined somewhere else in your code
            view = AcceptDeclineView(self.challenger, interaction.user, location_text)

            await user.send(
                f"**{self.challenger.display_name}** is challenging you to a **{self.q_type}** match.\n"
                f"You have **5 minutes** to respond.\n\n"
                f"📍 Location: **{location_text}**",
                view=view
            )
        except:
            return await interaction.response.send_message(
                "❌ Could not DM the defender.",
                ephemeral=True
            )

        await interaction.response.send_message("Challenge sent!", ephemeral=True)

class AcceptDeclineView(discord.ui.View):
    def __init__(self, challenger, defender, location):
        super().__init__(timeout=300)
        self.challenger = challenger
        self.defender = defender
        self.location = location

    @discord.ui.button(label="Accept", style=discord.ButtonStyle.green)
    async def accept(self, interaction, button):
        # TODO: send server invite based on location

        if "remote" in self.location:
            await start_remote_battle(
                challenger=self.challenger,
                defender=self.defender,
                q_type=self.q_type,
                channel=interaction.channel
            )
        
        else:
            await interaction.response.send_message(
                "You accepted! Sending invites…"
            )

            await self.challenger.send(
                f"Your challenge was **accepted** by {interaction.user.mention}! (Location: {self.location})"
            )

    @discord.ui.button(label="Decline", style=discord.ButtonStyle.red)
    async def decline(self, interaction, button):
        await interaction.response.send_modal(DeclineReasonModal(self.challenger))

class DeclineReasonModal(discord.ui.Modal, title="Reason for Declining"):
    reason = discord.ui.TextInput(label="Reason")

    def __init__(self, challenger):
        super().__init__()
        self.challenger = challenger

    async def on_submit(self, interaction):
        await self.challenger.send(
            f"Your challenge was declined.\n**Reason:** {self.reason.value}"
        )
        await interaction.response.send_message("Sent.", ephemeral=True)

class QueueSearchView(discord.ui.View):
    def __init__(self, entries, page=0):
        super().__init__(timeout=120)
        self.entries = entries
        self.page = page
        self.items_per_page = 10
    @discord.ui.button(label="⬅️")
    async def prev_page(self, interaction, button):
        if self.page > 0:
            self.page -= 1
        await interaction.response.edit_message(embed=self.build(), view=self)

    @discord.ui.button(label="➡️")
    async def next_page(self, interaction, button):
        if (self.page+1)*self.items_per_page < len(self.entries):
            self.page += 1
        await interaction.response.edit_message(embed=self.build(), view=self)

    @discord.ui.button(label="Challenge", style=discord.ButtonStyle.green)
    async def challenge(self, interaction, button):
        modal = ChallengeNumberModal(interaction, self.entries, self.entries[0]["type"])
        await interaction.response.send_modal(modal)

    def build(self):
        embed = discord.Embed(title="Queue Search Results")
        start = self.page * self.items_per_page
        end = start + self.items_per_page
        chunk = self.entries[start:end]

        for i, row in enumerate(chunk, start=1+start):
            name = f"{i}. <@{row['user_id']}>"
            if row["type"] == "p2 gym":
                value = f"Gym Type: {row['gym_type']}\nBounty: {row['gym_bounty']}"
            else:
                value = " "
            embed.add_field(name=name, value=value, inline=False)
        
        embed.set_footer(text="all queue commands can be disabled by \queue disable")

        return embed

