@bot.command(name="global_kick", aliases=["gkick"])
async def global_kick(ctx, member: discord.Member):
    clan_name, clan = get_clan_by_leader(ctx.author.id)
    if not clan_name or not clan:
        return await ctx.send("❌ You are not a global clan leader.")
    if clan.get("locked"):
        return await ctx.send("🔒 This clan is locked. Leader kick is disabled.")
    if member.id == ctx.author.id:
        return await ctx.send("❌ You cannot kick yourself.")
    if member.id not in set(clan.get("members", [])):
        return await ctx.send("❌ That user is not in your global clan.")

    _unequip_global_clan_inventory_cosmetics_for_user(int(member.id), int(clan["id"]))
    with _connect_global_clan_db() as conn:
        c = conn.cursor()
        c.execute(
            "DELETE FROM global_clan_members WHERE clan_id = ? AND user_id = ?",
            (int(clan["id"]), int(member.id)),
        )
        conn.commit()

    await ctx.send(f"✅ {member.mention} has been kicked from **{clan_name}**.")

@bot.command(name="global_leave", aliases=["leaveglobal", "leave_gc", "glc"])
async def leave_global_clan(ctx):
    clan_name, _, data = find_user_global_clan(ctx.author.id)

