@clan.command(name="extract")
async def extract(ctx, name: str):
    # Permission check (same as create)
    if not discord.utils.get(ctx.author.roles, name="Clan") and not ctx.author.guild_permissions.administrator:
        return await ctx.send(
            "You need the **Clan** role to use this command."
        )

    # Load global clan
    global_clan = load_clan(name)
    if not global_clan:
        return await ctx.send(f"Global clan **{name}** not found.")

    leader_id = global_clan.get("leader")
    if not leader_id:
        return await ctx.send("Global clan has no leader data.")

    leader = ctx.guild.get_member(leader_id)
    if not leader:
        return await ctx.send(
            "Clan leader is not in this server. Invite them first."
        )

    conn = get_db_connection(ctx.guild.id)
    setup_database(conn)
    create_track_table(conn)
    c = conn.cursor()

    # Check if clan already exists locally
    c.execute("SELECT 1 FROM clans WHERE clan_name = ?", (name,))
    if c.fetchone():
        conn.close()
        return await ctx.send(f"Local clan **{name}** already exists.")

    # Insert local clan
    c.execute(
        "INSERT INTO clans (clan_name, leader_id) VALUES (?, ?)",
        (name, leader.id)
    )
    conn.commit()
    conn.close()

    # Assign autoroles to leader
    conn_role = get_autorole_db(ctx.guild.id)
    cr = conn_role.cursor()
    cr.execute("SELECT role_id FROM autorole_clan_leader")
    role_rows = cr.fetchall()
    cr.close()

    assigned_roles = []
    for (role_id,) in role_rows:
        role = ctx.guild.get_role(role_id)
        if role:
            try:
                await leader.add_roles(role, reason="Extracted global clan leader")
                assigned_roles.append(role.mention)
            except Exception as e:
                print(e)
        else:
            cr = conn_role.cursor()
            cr.execute("DELETE FROM autorole_clan_leader WHERE role_id=?", (role_id,))
            conn_role.commit()
            cr.close()

    conn_role.close()

    await ctx.send(
        f"✅ Global clan **{name}** has been extracted locally.\n"
        f"👑 Leader: {leader.mention}\n"
        f"🎭 Roles assigned: {', '.join(assigned_roles) if assigned_roles else 'None'}"
    )

