# Create the /global command group
global_group = app_commands.Group(name="global", description="Manage and interact with Global Clans")

@global_group.command(name="info", description="View information about your current global clan")
async def global_info(interaction: discord.Interaction):
    clan_name, _, clan = find_user_global_clan(interaction.user.id)

    if not clan:
        return await interaction.response.send_message("❌ You are not in any global clan.", ephemeral=True)

    # Clan basic info
    icon = get_clan_icon(clan_name)
    rating_emoji, rating = get_clan_rating(clan_name)
    banner = get_clan_banner(clan_name)

    # Leader
    leader_id = clan.get("leader")
    leader = interaction.guild.get_member(leader_id) if interaction.guild else None
    leader_name = leader.display_name if leader else f"<@{leader_id}>"

    # Members
    member_lines = []
    for uid in clan.get("members", []):
        member = interaction.guild.get_member(uid) if interaction.guild else None
        member_lines.append(member.display_name if member else f"<@{uid}>")

    members_text = "\n".join(member_lines) if member_lines else "No members"

    # Embed
    embed = discord.Embed(
        title=f"{icon} {clan_name} {rating_emoji}",
        description=(
            f"{rating_emoji} **Rating:** {rating}\n"
            f"👑 **Leader:** {leader_name}"
        ),
        color=discord.Color.blue()
    )

    embed.add_field(
        name=f"👥 Members ({len(member_lines)})",
        value=members_text,
        inline=False
    )

    file = None
    if banner:
        banner_image = None
        if banner == "demolisher":
            banner_image = "demolisher.jpg"
        elif banner == "destroyer":
            banner_image = "destroyer.jpg"
        elif banner == "cat":
            banner_image = "1200.jpg"
        elif banner == "dragon":
            banner_image = "1400.jpg"
        elif banner == "hidden":
            banner_image = "1100.jpg"
        elif banner == "warlord":
            banner_image = "warlord.jpg"  
        if banner_image and os.path.exists(banner_image):
            file = discord.File(banner_image, filename=banner_image)
            embed.set_image(url=f"attachment://{banner_image}")

    if file:
        await interaction.response.send_message(embed=embed, file=file)
    else:
        await interaction.response.send_message(embed=embed)


@global_group.command(name="create", description="Create a new global clan (Cost: 100 ARCs)")
@app_commands.choices(
    icon=[app_commands.Choice(name=i, value=i) for i in ICON_CHOICES],
    banner=[app_commands.Choice(name=b, value=b) for b in BANNER_CHOICES]
)
async def global_create(interaction: discord.Interaction, name: str, leader: discord.Member, icon: app_commands.Choice[str] = None, banner: app_commands.Choice[str] = None):
    await interaction.response.defer()
    _ensure_global_clan_db()
    
    icon_val = icon.value if icon else "pokeball"
    banner_val = banner.value if banner else "warlord"

    if interaction.user.id not in owner_ids:
        conn = connect_poke_db()
        ensure_player(conn, interaction.user.id)
        c = conn.cursor()
        c.execute(
            "UPDATE poke SET coins = coins - 100 WHERE player_id = ? AND coins >= 100",
            (interaction.user.id,)
        )
        if c.rowcount == 0:
            conn.close()
            return await interaction.followup.send("Not enough ARCs\nYou need 100 ARCs to create a global clan.\nYou can claim ARCs by playing `/poke minigame`, defeat bot in `/pve_battle`, daily claim from `/poke claim`, reach higher ratings in queue battle, and simply winning wars.")
        conn.commit()
        conn.close()

    key = _normalize_name(name)
    if not key:
        return await interaction.followup.send("❌ Invalid clan name.")
    if _load_global_clan_record_by_name(key):
        return await interaction.followup.send("❌ Clan already exists.")

    members = load_clan_members()
    if leader.id in members:
        return await interaction.followup.send("❌ Leader is already in a clan.")

    with _connect_global_clan_db() as conn:
        c = conn.cursor()
        c.execute(
            """
            INSERT INTO global_clans (name, name_lower, leader_id, icon, banner, rating, locked)
            VALUES (?, ?, ?, ?, ?, 1000, 0)
            """,
            (str(name).strip(), key, int(leader.id), _normalize_name(icon_val), _normalize_name(banner_val)),
        )
        clan_id = int(c.lastrowid)
        c.execute(
            "INSERT OR IGNORE INTO global_clan_members (clan_id, user_id) VALUES (?, ?)",
            (clan_id, int(leader.id)),
        )
        conn.commit()

    await interaction.followup.send(f"✅ Global clan **{name}** created with leader **{leader.display_name}**.")
    
    alert_channel = interaction.client.get_channel(int(LOG_CHANNEL_ID_STR))
    if alert_channel:
        await alert_channel.send(f"Global clan {name} created by {leader.name} ({leader.mention})")


