@global_group.command(name="extract", description="Extract a global clan locally")
async def global_extract_cmd(interaction: discord.Interaction, name: str):
    if not discord.utils.get(interaction.user.roles, name="Clan") and not interaction.user.guild_permissions.administrator:
        return await interaction.response.send_message("You need the **Clan** role or Administrator permissions to use this command.", ephemeral=True)

    global_clan = load_clan(name)
    if not global_clan:
        return await interaction.response.send_message(f"Global clan **{name}** not found.", ephemeral=True)

    leader_id = global_clan.get("leader")
    if not leader_id:
        return await interaction.response.send_message("Global clan has no leader data.", ephemeral=True)

    leader = interaction.guild.get_member(leader_id)
    if not leader:
        return await interaction.response.send_message("Clan leader is not in this server. Invite them first.", ephemeral=True)

    await interaction.response.defer()

    conn = get_db_connection(interaction.guild_id)
    setup_database(conn)
    create_track_table(conn)
    c = conn.cursor()

    c.execute("SELECT 1 FROM clans WHERE clan_name = ?", (name,))
    if c.fetchone():
        conn.close()
        return await interaction.followup.send(f"Local clan **{name}** already exists.")

    c.execute(
        "INSERT INTO clans (clan_name, leader_id) VALUES (?, ?)",
        (name, leader.id)
    )
    conn.commit()
    conn.close()

    conn_role = get_autorole_db(interaction.guild_id)
    cr = conn_role.cursor()
    cr.execute("SELECT role_id FROM autorole_clan_leader")
    role_rows = cr.fetchall()
    cr.close()

    assigned_roles = []
    for (role_id,) in role_rows:
        role = interaction.guild.get_role(role_id)
        if role:
            try:
                await leader.add_roles(role, reason="Extracted global clan leader")
                assigned_roles.append(role.mention)
            except Exception as e:
                print(e)
        else:
            cr = conn_role.cursor()
            cr.execute("DELETE FROM autorole_clan_leader WHERE role_id=?", (role_id,))
            conn_role.commit()
            cr.close()
    conn_role.close()

    await interaction.followup.send(
        f"✅ Global clan **{name}** has been extracted locally.\n"
        f"👑 Leader: {leader.mention}\n"
        f"🎭 Roles assigned: {', '.join(assigned_roles) if assigned_roles else 'None'}"
    )


