def store_gacha_rewards(user_id: int, results: list[str]):
    db = get_db()
    c = db.cursor()

    for reward in results:
        r = reward.lower().strip()

        # ---------- SHINY POKÉMON ----------
        if r.startswith("shiny "):
            pokemon = r.replace("shiny ", "").title()
            c.execute("""
                INSERT OR IGNORE INTO pokemons (user_id, pokemon, shiny)
                VALUES (?, ?, 1)
            """, (user_id, pokemon))
            continue

        # ---------- POKÉMON CHIP (UNLOCK) ----------
        if r.endswith(" chip") and "fragments" not in r:
            pokemon = r.replace(" chip", "").title()
            c.execute("""
                INSERT OR IGNORE INTO pokemons (user_id, pokemon, shiny)
                VALUES (?, ?, 0)
            """, (user_id, pokemon.capitalize()))
            continue

        # ---------- CHIP FRAGMENTS ----------
        if "chip fragments" in r:
            name, _, qty = r.partition(" x")
            amount = int(qty)
            item = name.lower()

            c.execute("""
                INSERT INTO inventory (user_id, item, amount)
                VALUES (?, ?, ?)
                ON CONFLICT(user_id, item)
                DO UPDATE SET amount = amount + ?
            """, (user_id, item, amount, amount))
            continue

        # ---------- TM FRAGMENTS ----------
        if "tm fragments" in r:
            name, _, qty = r.partition(" x")
            amount = int(qty)
            item = name.lower()

            c.execute("""
                INSERT INTO inventory (user_id, item, amount)
                VALUES (?, ?, ?)
                ON CONFLICT(user_id, item)
                DO UPDATE SET amount = amount + ?
            """, (user_id, item, amount, amount))
            continue

        # ---------- TM (FULL MOVE) ----------
        if r.endswith(" tm"):
            move = r.replace(" tm", "").title()
            c.execute("""
                INSERT OR IGNORE INTO moves (user_id, move)
                VALUES (?, ?)
            """, (user_id, move))
            continue

        # ---------- EVERYTHING ELSE → ITEM ----------
        c.execute("""
            INSERT INTO inventory (user_id, item, amount)
            VALUES (?, ?, 1)
            ON CONFLICT(user_id, item)
            DO UPDATE SET amount = amount + 1
        """, (user_id, r))

    db.commit()
    db.close()



