class PokemonSelect(discord.ui.Select):
    def __init__(self, game, pid, callback, extra_options):
        options = []

        for name, emojis in extra_options:
            options.append(
                discord.SelectOption(
                    label=name,
                    emoji=emojis,
                    default=False,
                    description="Already taken" if name in game.taken_pokemon else None
                )
            )

        super().__init__(
            placeholder="Pick your Pokémon",
            options=options
        )

        self.game = game
        self.pid = pid
        self._cb = callback

    async def callback(self, interaction: discord.Interaction):
        choice = self.values[0]

        if choice in self.game.taken_pokemon:
            await interaction.response.send_message(
                "❌ That Pokémon is already taken."
            )
            return

        self.game.taken_pokemon.add(choice)
        if choice == "Squirtle":
            self.game.spawn_rain_tiles()

        await self._cb(interaction, choice)

class ActionView(discord.ui.View):
    def __init__(self, game: ArcadeGame, pid: int):
        super().__init__(timeout=None)
        self.game = game
        self.pid = pid
        self.pokemon = game.pokemon[pid]
        game.views.append(self)

        attack_type = game.selected_attack[self.pid]
        self.attack_type = attack_type
        atk_emoji = ACTION_EMOJIS[attack_type][pid]
        def_emoji = ACTION_EMOJIS["defense"][pid]

        # ---------------- ACTION EMBED ----------------
        self.embed = discord.Embed(title=f"🎮 {self.game.players[pid].display_name}'s Actions")
        self.embed.add_field(name="🧭 Movement", value="⬆️ ⬇️ ⬅️ ➡️", inline=False)
        self.embed.add_field(name="⚔️ Attack", value="Directional / Auto / Tackle", inline=False)
        self.embed.add_field(name="🛡️ Defense", value="Place walls in a direction", inline=False)

        # ---------------- MOVEMENT BUTTONS ----------------
        for d, emoji in [("left","⬅️"),("up","⬆️"),("down","⬇️"),("right","➡️")]:
            self.add_item(self._btn(f"{emoji}", 0, lambda i, dir=d: self._act(i, "move", dir)))

        # ---------------- ATTACK BUTTONS ----------------
        if attack_type in ["razor leaf", "surf", "will-o-wisp", "stone edge", "electro ball", "blizzard", "ice shard", "sky attack", "moonblast", "shadow ball"]:
            for d, emoji in [("up",f"{atk_emoji} ↑"),("down",f"{atk_emoji} ↓"),("left",f"{atk_emoji} ←"),("right",f"{atk_emoji} →")]:
                self.add_item(self._btn(emoji, 1, lambda i, dir=d: self._act(i, "attack", dir)))
        elif attack_type == "tackle":
            for d, emoji in [("left","🤜 ←"),("up","🤜 ↑"),("down","🤜 ↓"),("right","🤜 →")]:
                self.add_item(self._btn(emoji, 1, lambda i, dir=d: self._act(i, "tackle", dir)))
        elif attack_type in ["frenzy plant", "leech life", "future sight", "dark pulse", "draco meteor"]:
            self.add_item(self._btn(f"{atk_emoji} ACTIVATE", 1, lambda i: self._act(i, "attack", None)))

        # ---------------- DEFENSE BUTTONS ----------------
        for d, emoji in [("left",f"{def_emoji} ←"),("up",f"{def_emoji} ↑"),("down",f"{def_emoji} ↓"),("right",f"{def_emoji} →")]:
            self.add_item(self._btn(emoji, 2, lambda i, dir=d: self._act(i, "defense", dir)))

    # ---------------- BUTTON FACTORY ----------------
    def _btn(self, label: str, row: int, handler):
        button = discord.ui.Button(label=label, style=discord.ButtonStyle.secondary, row=row)
        async def callback(interaction: discord.Interaction):
            await handler(interaction)
        button.callback = callback
        return button

    # ---------------- ACTION HANDLER ----------------
    async def _act(self, interaction: discord.Interaction, action: str, direction: str | None):
        if interaction.user != self.game.players[self.pid]:
            await interaction.response.send_message("❌ Not your controls.", ephemeral=True)
            return

        if not self.game.can_act(self.pid):
            await interaction.response.send_message("⏳ Action on cooldown or you are under heavy hinderance.", ephemeral=True, delete_after=2)
            return

        self.game.set_cd(self.pid)

        if action == "move":
            self.game.move(self.pid, direction)
        elif action == "attack":
            self.game.attack(self.pid, self.attack_type, direction)
        elif action == "tackle":
            self.game.tackle(self.pid, direction)
        elif action == "defense":
            self.game.attack(self.pid,"defense", direction)

        await interaction.response.defer()

class AttackSelect(discord.ui.Select):
    def __init__(self, game, pid, callback, extra_options):
        options = [discord.SelectOption(label=a) for a in extra_options]
        super().__init__(placeholder="Pick your attack type", options=options)
