        COST = 100

        db = get_db()
        c = db.cursor()

        c.execute("SELECT coins FROM players WHERE user_id=?", (uid,))
        row = c.fetchone()

        if row[0] >= COST:
            c.execute(
                "UPDATE players SET coins = coins - ? WHERE user_id=?",
                (COST, uid)
            )
            db.commit()
