# ---------- EVOLUTION SELECT ----------
class PokemonEvolveSelect(discord.ui.Select):
    def __init__(self, user_id, stone, options):
        super().__init__(
            placeholder="Select Pokémon",
            options=options
        )
        self.user_id = user_id
        self.stone = stone

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message(
                "❌ Not your Pokémon.",
                ephemeral=True
            )
            return

        base = self.values[0]
        evolved = EVOLUTIONS[(base, self.stone)]

        db = get_db()
        c = db.cursor()

        c.execute(
            "DELETE FROM pokemons WHERE user_id=? AND pokemon=?",
            (self.user_id, base)
        )
        c.execute(
            "INSERT OR IGNORE INTO pokemons VALUES (?, ?, 0)",
            (self.user_id, evolved)
        )
        c.execute(
            "UPDATE inventory SET amount = amount - 1 WHERE user_id=? AND item=?",
            (self.user_id, self.stone)
        )

        db.commit()
        db.close()

        await interaction.response.send_message(
            f"✨ **{base} evolved into {evolved}!**",
            ephemeral=True
        )

# ---------------- COMMAND ---------------- #
class ArcadeCommands(app_commands.Group):
    def __init__(self):
        super().__init__(name="arcade", description="All arcade game related commands")
    @app_commands.command(name="duel", description="Start an arcade Pokémon fight")
    @app_commands.describe(opponent="User or bot to fight")
    async def arcade(self, interaction: discord.Interaction, opponent: discord.User | None = None, difficulty: int=1):
        await interaction.response.defer()
        if difficulty not in [1,2,3,4,5]:
            await interaction.followup.send("Here is a list of difficulties (use the number):\n1: razor leaf\n2: blizzard\n3: stone edge\n4: will-o-wisp\n5: random moves")
        game = ArcadeGame(interaction.user, opponent, interaction.channel, difficulty)
        
        # ---------------- Pokémon + Attack Selection ---------------- #
        async def pick_pokemon_and_attack(user, pid):
            done = asyncio.Event()

            # Fetch extra Pokémon and attacks from DB
            db = get_db()
            c = db.cursor()
            
            # Extra Pokémon
            c.execute("SELECT pokemon FROM pokemons WHERE user_id=?", (user.id,))
            extra_pokemons = [row[0] for row in c.fetchall()]
            
            # Extra attacks / TMs
            c.execute("SELECT move FROM moves WHERE user_id=?", (user.id,))
            extra_attacks = [row[0] for row in c.fetchall()]
            
            db.close()

            async def on_attack_pick(inter, attack_choice):
                if inter.user != user:
                    await inter.response.send_message("❌ Not your selection.", ephemeral=True)
                    return
                game.selected_attack[pid] = attack_choice
                await inter.response.edit_message(
                    content=f"✅ Pokémon: {game.pokemon[pid]}, Attack: {attack_choice}",
                    view=None
                )
                done.set()

            async def on_pokemon_pick(inter, pokemon_name):
                if inter.user != user:
                    await inter.response.send_message("❌ Not your selection.", ephemeral=True)
                    return
                game.pokemon[pid] = pokemon_name
                emoji = POKEMONS.get(pokemon_name, "❔")
                if emoji == "❔":
                    emoji = pokemon_emojis.get(pokemon_name, "❔")
                game.emoji[pid] = emoji

                # Attack select
                attack_options = [a for a in ATTACK_OPTIONS]
                attack_options += [a.lower() for a in extra_attacks]

                view2 = discord.ui.View()
                view2.add_item(AttackSelect(game, pid, on_attack_pick, extra_options=attack_options))
                await inter.response.send_message(
                    f"{user.mention}, pick your attack type",
                    view=view2
                )

            # Build Pokémon select options
            pokemon_options = [(p, POKEMONS.get(p, "❔")) for p in POKEMONS.keys()]
            pokemon_options += [(p, pokemon_emojis.get(p, "❔")) for p in extra_pokemons]

            view1 = discord.ui.View()
            view1.add_item(PokemonSelect(game, pid, on_pokemon_pick, extra_options=pokemon_options))
            await interaction.followup.send(
                f"{user.mention}, pick your Pokémon",
                view=view1
            )

            await done.wait()
        # ---------------- Pick Players ---------------- #
        # 1️⃣ First player picks Pokémon + attack
        await pick_pokemon_and_attack(interaction.user, 0)

        # 2️⃣ Then the second player picks
        if opponent and not opponent.bot:
            await pick_pokemon_and_attack(opponent, 1)
        else:
            # Bot picks Pokémon and attack
            available = [p for p in POKEMONS if p not in game.taken_pokemon]
            choice = random.choice(available)
            game.taken_pokemon.add(choice)
            game.pokemon[1] = choice
            game.emoji[1] = POKEMONS[choice]
            game.selected_attack[1] = random.choice(ATTACK_OPTIONS)

        # ---------------- Send Game Embeds & Views ---------------- #
        game.status_message = await interaction.followup.send(
            embeds=[game.health_embed(), game.grid_embed()]
        )

        # Action views
        await interaction.followup.send("Your actions", view=ActionView(game, 0), ephemeral=True)
        if not game.is_bot:
            await interaction.channel.send(f"{opponent.mention}, your actions", view=ActionView(game, 1))

        # ---------------- FRAME LOOP ---------------- #
        while game.running:
            if time.time() - game.started_at >= game.timeout:
                await interaction.channel.send("⏰ Game timed out!")
                break

            await asyncio.sleep(FRAME_TIME)
            game.step()
            if game.is_bot:
                game.bot_action()
            await game.status_message.edit(
                embeds=[game.health_embed(), game.grid_embed()]
            )

        #print(game.is_bot, game.winner_pid)
        if game.is_bot and game.winner_pid == 0:
            quest = check_quest_completion(game.players[0].id, game.pokemon[0], game.difficulty)
            if quest:
                await interaction.channel.send(quest)

        # ---------------- Cleanup ---------------- #
        for v in game.views: v.stop()
        game.projectiles.clear()
        game.walls.clear()
        game.pos.clear()
        game.hp.clear()
        await interaction.channel.send("🏁 Game Over \n-# You got 1 coin.")

