@bot.command(name="owneradditem")
async def owneradditem(ctx, member: commands.MemberConverter, item: str, amount: int):
    """Owner-only: Add any item or coins to a player"""
    if ctx.author.id not in owner_ids:
        return ctx.send("You do not have permission")
    db = get_db()
    c = db.cursor()

    if item.lower() == "coins":
        # Ensure player exists
        c.execute("INSERT OR IGNORE INTO players (user_id, coins) VALUES (?, 0)", (member.id,))
        # Add coins
        c.execute("UPDATE players SET coins = coins + ? WHERE user_id=?", (amount, member.id))
        db.commit()
        db.close()
        await ctx.send(f"✅ Added {amount} coins to {member.mention}.")
        return

    # Generic inventory item
    c.execute("INSERT OR IGNORE INTO inventory (user_id, item, amount) VALUES (?, ?, 0)", (member.id, item))
    c.execute("UPDATE inventory SET amount = amount + ? WHERE user_id=? AND item=?", (amount, member.id, item))
    db.commit()
    db.close()
    await ctx.send(f"✅ Added {amount}x **{item}** to {member.mention}.")

GLOBAL_LEADER_FILE = "global_leader.json"
ITEMS_PER_PAGE = 5  # leaders per page (for gym search)

class LeaderPaginator(discord.ui.View):
    def __init__(self, pages, interaction):
        super().__init__(timeout=120)
        self.pages = pages
        self.index = 0
        self.interaction = interaction

    async def update(self, interaction):
        await interaction.response.edit_message(
            embed=self.pages[self.index],
            view=self
        )

    @discord.ui.button(label="◀", style=discord.ButtonStyle.secondary)
    async def prev(self, interaction: discord.Interaction, _):
        if interaction.user != self.interaction.user:
            return
        self.index = (self.index - 1) % len(self.pages)
        await self.update(interaction)

    @discord.ui.button(label="▶", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, _):
        if interaction.user != self.interaction.user:
            return
        self.index = (self.index + 1) % len(self.pages)
        await self.update(interaction)

class GLCommands(app_commands.Group):
    def __init__(self):
        super().__init__(
            name="global_leader",
            description="All global leader related commands"
        )

    badge_choices = [
        app_commands.Choice(name=badge, value=badge)
        for badge in GYM_TYPES
    ]

    @app_commands.command(
        name="add",
        description="Add yourself to the global leader list"
    )
    @app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
    @app_commands.choices(gym_type=badge_choices)
    async def gla(
        self,
        interaction: discord.Interaction,
        gym_type: str,
        server_invite1: str = None,
        server_invite2: str = None,
        server_invite3: str = None,
    ):
        # --- Verify gym leader achievement ---
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(
            "SELECT 1 FROM certificates WHERE user_id = ? AND achievement = ?",
            (interaction.user.id, "Verified Gym Leader"),
        )
        verified_leader = cursor.fetchone()
        cursor.close()
        conn.commit()
        conn.close()

        if not verified_leader:
            return await interaction.response.send_message(
                "You are not a global leader. Become one first.\n"
                "Check `/achievement verified gym leader`.\n"
                "Pro tip: ask in the support server (invite in `/bot_info`).",
                ephemeral=True
            )

        # --- Collect server invites ---
        servers = [
            s for s in (server_invite1, server_invite2, server_invite3)
            if s is not None
        ]

        if not servers:
            return await interaction.response.send_message(
                "You must choose **at least 1 server** where challengers can challenge you.",
                ephemeral=True
            )

        # --- Load or create JSON ---
        if os.path.exists(GLOBAL_LEADER_FILE):
            with open(GLOBAL_LEADER_FILE, "r", encoding="utf-8") as f:
                try:
                    data = json.load(f)
                except json.JSONDecodeError:
                    data = {}
        else:
            data = {}

        # Ensure gym key exists
        data.setdefault(gym_type, [])

        # --- Add or update leader ---
        updated = False

        for idx, (user_id, _) in enumerate(data[gym_type]):
            if user_id == interaction.user.id:
                data[gym_type][idx] = (interaction.user.id, servers)
                updated = True
                break

        if not updated:
            data[gym_type].append(
                (interaction.user.id, servers)
            )

        # --- Save ---
        with open(GLOBAL_LEADER_FILE, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=4)

        action = "updated" if updated else "added"

        await interaction.response.send_message(
            f"✅ Your **{gym_type} Global Leader** entry has been **{action}**!\n"
            f"Servers registered: {len(servers)}"
        )
    
    @app_commands.command(
        name="search",
        description="Search global leaders by gym type, or use 'all' / 'nothing'"
    )
    @app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
    async def gl_search(
        self,
        interaction: discord.Interaction,
        gym_type: str = "All"
    ):
        if not os.path.exists(GLOBAL_LEADER_FILE):
            return await interaction.response.send_message(
                "No global leaders have been registered yet.",
                ephemeral=True
            )

        with open(GLOBAL_LEADER_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)

        gym_type = gym_type.title()

        # ------------------------------
        # SEARCH: ALL / NOTHING
        # ------------------------------
        if gym_type in ("All", "Nothing"):
            pages = []

            for gym, leaders in data.items():
                if not leaders:
                    continue

                embed = discord.Embed(
                    title="🌍 Global Gym Leaders",
                    description=f"**Gym Type:** {gym}\nClick next page for more",
                    color=discord.Color.gold()
                )

                for idx, (user_id, servers) in enumerate(leaders, start=1):
                    member = interaction.client.get_user(user_id)
                    name = member.display_name if member else "Unknown User"
                    ping = f"<@{user_id}>"

                    name = f"**{idx}. {name} ({ping})**\n"
                    value = "\n".join(servers)

                    embed.add_field(
                        name=name,
                        value=value,
                        inline=False
                    )

                pages.append(embed)

            if not pages:
                return await interaction.response.send_message(
                    "No leaders found.",
                    ephemeral=True
                )

            view = LeaderPaginator(pages, interaction)
            await interaction.response.send_message(
                embed=pages[0],
                view=view
            )
            return

        # ------------------------------
        # SEARCH: SPECIFIC GYM
        # ------------------------------
        if gym_type not in data or not data[gym_type]:
            return await interaction.response.send_message(
                f"No leaders found for **{gym_type}** gym.",
                ephemeral=True
            )

        leaders = data[gym_type]
        pages = []

        total_pages = math.ceil(len(leaders) / ITEMS_PER_PAGE)

        for page in range(total_pages):
            embed = discord.Embed(
                title=f"🏆 {gym_type} Global Leaders",
                color=discord.Color.blue()
            )

            start = page * ITEMS_PER_PAGE
            end = start + ITEMS_PER_PAGE

            for user_id, servers in leaders[start:end]:
                member = interaction.client.get_user(user_id)
                name = member.display_name if member else "Unknown User"
                ping = f"<@{user_id}>"

                embed.add_field(
                    name=f"{name} ({ping})",
                    value="\n".join(servers),
                    inline=False
                )

            embed.set_footer(text=f"Page {page + 1}/{total_pages}")
            pages.append(embed)

        view = LeaderPaginator(pages, interaction)
        await interaction.response.send_message(
            embed=pages[0],
            view=view
        )

    @app_commands.command(
        name="remove",
        description="Remove a global leader entry"
    )
    @app_commands.allowed_contexts(guilds=True, dms=True, private_channels=True)
    async def gl_remove(
        self,
        interaction: discord.Interaction,
        gym_type: str,
        user: discord.User | None = None
    ):
        """
        gym_type:
        - specific gym name (e.g. Fire)
        - 'all' to remove from all gyms

        user:
        - optional, OWNER ONLY
        """

        # -----------------------------
        # Permission check
        # -----------------------------
        target_user = interaction.user

        if user is not None:
            if interaction.user.id not in owner_ids:
                return await interaction.response.send_message(
                    "❌ Only the bot owner can remove other users' entries.",
                    ephemeral=True
                )
            target_user = user

        if not os.path.exists(GLOBAL_LEADER_FILE):
            return await interaction.response.send_message(
                "No global leader data exists yet.",
                ephemeral=True
            )

        with open(GLOBAL_LEADER_FILE, "r", encoding="utf-8") as f:
            try:
                data = json.load(f)
            except json.JSONDecodeError:
                data = {}

        gym_type = gym_type.title()
        removed_from = []

        # -----------------------------
        # REMOVE FROM ALL GYMS
        # -----------------------------
        if gym_type == "All":
            for gym, leaders in data.items():
                original_len = len(leaders)
                data[gym] = [
                    (uid, servers)
                    for uid, servers in leaders
                    if uid != target_user.id
                ]
                if len(data[gym]) != original_len:
                    removed_from.append(gym)

        # -----------------------------
        # REMOVE FROM ONE GYM
        # -----------------------------
        else:
            if gym_type not in data:
                return await interaction.response.send_message(
                    f"No entries found under **{gym_type}**.",
                    ephemeral=True
                )

            original_len = len(data[gym_type])
            data[gym_type] = [
                (uid, servers)
                for uid, servers in data[gym_type]
                if uid != target_user.id
            ]

            if len(data[gym_type]) == original_len:
                return await interaction.response.send_message(
                    f"❌ No entry found for {target_user.mention} under **{gym_type}**.",
                    ephemeral=True
                )

            removed_from.append(gym_type)

        # -----------------------------
        # Clean empty gyms
        # -----------------------------
        data = {
            gym: leaders
            for gym, leaders in data.items()
            if leaders
        }

        # Save
        with open(GLOBAL_LEADER_FILE, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=4)

        # -----------------------------
        # Response
        # -----------------------------
        if not removed_from:
            return await interaction.response.send_message(
                "No entries were removed.",
                ephemeral=True
            )

        await interaction.response.send_message(
            f"🗑️ Removed **{target_user.mention}** from: **{', '.join(removed_from)}**",
            ephemeral=True
        )


@bot.command(name="dm_achievement")
async def dm_achievement(ctx, achievement: str, *, message: str):
    if ctx.author.id not in owner_ids:
        return

    conn = get_db_connection()
    cursor = conn.cursor()
    cursor.execute(
        "SELECT DISTINCT user_id FROM certificates WHERE achievement = ?",
        (achievement,)
    )
    rows = cursor.fetchall()
    cursor.close()
    conn.close()

    if not rows:
        return await ctx.send(
            f"No users found with achievement **{achievement}**."
        )

    sent = 0
    failed = 0

    await ctx.send(
        f"📨 Sending DMs to **{len(rows)}** users with achievement **{achievement}**..."
    )

    for (user_id,) in rows:
        try:
            user = await ctx.bot.fetch_user(user_id)
            if user.bot:
                continue

            await user.send(message)
            sent += 1
            await asyncio.sleep(0.7)  # rate-limit safety

        except discord.Forbidden:
            failed += 1
        except discord.HTTPException:
            failed += 1

    embed = discord.Embed(
        title="📬 Achievement DM Report",
        color=discord.Color.green()
    )
    embed.add_field(name="Achievement", value=achievement, inline=False)
    embed.add_field(name="Sent", value=sent)
    embed.add_field(name="Failed", value=failed)
    embed.add_field(name="Total", value=len(rows))

    await ctx.send(embed=embed)

DB_PATH_ABL = "analysis_blacklist.db"

# In-memory cache: {guild_id: set(channel_ids)}
blacklist_cache = {}

# Ensure database and table exist
def init_db_abl():
    conn = sqlite3.connect(DB_PATH_ABL)
    c = conn.cursor()
    c.execute("""
        CREATE TABLE IF NOT EXISTS blacklisted_channels (
            guild_id INTEGER,
            channel_id INTEGER,
            PRIMARY KEY (guild_id, channel_id)
        )
    """)
    conn.commit()
    conn.close()

# Load database into cache at startup
def load_cache():
    global blacklist_cache
    blacklist_cache = {}
    if not os.path.exists(DB_PATH_ABL):
        return
    conn = sqlite3.connect(DB_PATH_ABL)
    c = conn.cursor()
    c.execute("SELECT guild_id, channel_id FROM blacklisted_channels")
    for guild_id, channel_id in c.fetchall():
        if guild_id not in blacklist_cache:
            blacklist_cache[guild_id] = set()
        blacklist_cache[guild_id].add(channel_id)
    conn.close()
init_db_abl()
@bot.command()
async def analysis_toggle(ctx, channel: discord.TextChannel):
    # Only allow server admins
    if not ctx.author.guild_permissions.administrator:
        await ctx.send("❌ You must be a server admin to use this command.")
        return

    guild_id = ctx.guild.id
    channel_id = channel.id

    # Ensure guild cache exists
    if guild_id not in blacklist_cache:
        blacklist_cache[guild_id] = set()

    conn = sqlite3.connect(DB_PATH_ABL)
    c = conn.cursor()

    if channel_id in blacklist_cache[guild_id]:
        # Channel already blacklisted, remove it
        c.execute("DELETE FROM blacklisted_channels WHERE guild_id = ? AND channel_id = ?", (guild_id, channel_id))
        blacklist_cache[guild_id].remove(channel_id)
        await ctx.send(f"✅ Channel {channel.mention} has been removed from the analysis blacklist.")
    else:
        # Check if guild already has 5 channels
        if len(blacklist_cache[guild_id]) >= 5:
            await ctx.send("❌ You can only have up to 5 blacklisted channels per server.")
        else:
            # Add channel to database and cache
            c.execute("INSERT INTO blacklisted_channels (guild_id, channel_id) VALUES (?, ?)", (guild_id, channel_id))
            blacklist_cache[guild_id].add(channel_id)
            await ctx.send(f"✅ Channel {channel.mention} has been added to the analysis blacklist.\nUse same command again to turn it back on")

    conn.commit()
    conn.close()

# Load cache on startup
load_cache()


POKEMON_DATA_FOLDER = "pokemon_data"

# {player_id: [name, url]}
CAST_CACHE = {}

# ===================== HELPERS =====================

def find_pokemon_in_text(text: str):
    """
    Search for a Pokémon name inside text.
    Returns (Name, SpriteURL) or None
    """
    text_lower = text.lower()

    for filename in os.listdir(POKEMON_DATA_FOLDER):
        path = os.path.join(POKEMON_DATA_FOLDER, filename)

        try:
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
        except Exception:
            continue

        name = data.get("name")
        if not name:
            continue

        if name.lower() in text_lower or name.lower() == text_lower:
            sprite = None
            if "shiny" in text_lower:
                sprite = data.get("sprites", {}).get("shiny_front")
            else:
                sprite = data.get("sprites", {}).get("default_front")
            if sprite:
                return name.capitalize(), sprite

    return None

# ===================== COMMANDS =====================

@bot.command(name="cast")
async def cast(ctx, *, arg: str):
    user_id = ctx.author.id

    # End casting
    if arg.lower() == "end":
        if user_id in CAST_CACHE:
            del CAST_CACHE[user_id]
            await ctx.send(f"🎬 Cast ended for {ctx.author.mention}")
        else:
            await ctx.send("You are not casting anything.")
        return

    # 1) Pokémon name detection
    pokemon = find_pokemon_in_text(arg)
    if pokemon:
        name, url = pokemon
        CAST_CACHE[user_id] = [name, url]
        await ctx.send(f"✨ {ctx.author.mention} is now casting **{name}** \nUse `!cast end` to end cast")
        return

    # 2) Manual name + URL
    url_match = re.search(r"(https?://\S+)", arg)
    if not url_match:
        await ctx.send("❌ No Pokémon found and no valid URL provided.")
        return

    url = url_match.group(1)
    name = arg.replace(url, "").strip()

    if not name:
        await ctx.send("❌ Please provide a name along with the URL.")
        return

    CAST_CACHE[user_id] = [name, url]
    await ctx.send(f"✨ {ctx.author.mention} is now casting **{name}**\nUse `!cast end` to end cast")

@bot.command(name="cast_list")
async def cast_list(ctx):
    if not CAST_CACHE:
        await ctx.send("🎭 No one is currently being cast.")
        return

    embed = discord.Embed(
        title="🎭 Current Cast List",
        color=discord.Color.purple()
    )

    for user_id, (name, _) in CAST_CACHE.items():
        member = ctx.guild.get_member(user_id)
        display_name = member.display_name if member else "Unknown"

        embed.add_field(
            name=f"<@{user_id}> ({display_name})",
            value=name,
            inline=False
        )

    await ctx.send(embed=embed)

