def fetch_riddle():
    # Free API endpoint (open source)
    url = "https://riddles-api.vercel.app/random"
    res = requests.get(url)
    if res.status_code != 200:
        return None
    data = res.json()
    return data.get("riddle"), data.get("answer")

def clean_text(text):
    return "".join([c for c in text if c.isalnum() or c == " "])

def magic_odd(text):
    return "".join([c for i, c in enumerate(text) if i % 2 == 0])

def magic_even(text):
    return "".join([c for i, c in enumerate(text) if i % 2 == 1])

def magic_two_begin_end(text):
    return text[:2] + text[-2:]

def magic_reverse(text):
    return text[::-1]

def magic_numbers(text):
    alphabet = "abcdefghijklmnopqrstuvwxyz"
    result = ""
    for ch in text:
        if ch.isalpha():
            result += str(alphabet.index(ch.lower()) + 1)
    return result

def apply_magic(answer, mode):
    ans = clean_text(answer.replace(" ", ""))

    if mode == "odd":
        return magic_odd(ans)
    elif mode == "even":
        return magic_even(ans)
    elif mode == "begin_end":
        return magic_two_begin_end(ans)
    elif mode == "reverse":
        return magic_reverse(ans)
    elif mode == "numbers":
        return magic_numbers(ans)
    return ans


