@bot.command(name="magic_of_the_day", aliases=["mod", "guess_magic", "md"])
async def magic_of_the_day(ctx):
    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    # Check if entries exist
    cursor.execute("SELECT time, question, answer, magic, extra FROM daily_questions ORDER BY time ASC")
    rows = cursor.fetchall()

    # If entries exist and are less than 24 hours old
    if rows and (time.time() - rows[-1][0] < 86400):
        embed = discord.Embed(
            title="🪄 Magic of the Day",
            description="Use !guess to guess the magic words",
            color=discord.Color.dark_purple()
        )

        for i, row in enumerate(rows, start=1):
            _, question, answer, magic, extra = row
            embed.add_field(
                name=f"{i}. {question}",
                value=f"**The magic words are {extra}**",
                inline=False
            )

        await ctx.send(embed=embed)
        conn.close()
        return

    # Otherwise, fetch new riddles
    riddles = []
    for _ in range(3):
        r = fetch_riddle()
        if r:
            riddles.append(r)
        else:
            await ctx.send("❌ Failed to fetch riddles from API.")
            conn.close()
            return

    # Choose random magic mode
    magic_modes = {
        "odd": "Those that are odd",
        "even": "Those that are even",
        "begin_end": "The two beginning and the end",
        "reverse": "The other way around",
        "numbers": "The numbers"
    }
    mode = random.choice(list(magic_modes.keys()))
    magic_text = magic_modes[mode]

    # Delete old entries
    cursor.execute("DELETE FROM daily_questions")

    timestamp = int(time.time())

    # Insert all 3 riddles
    for q, a in riddles:
        magic = apply_magic(a, mode)
        cursor.execute("""
            INSERT INTO daily_questions (time, question, answer, magic, extra)
            VALUES (?, ?, ?, ?, ?)
        """, (timestamp, q, a, magic, magic_text))
        timestamp += 1  # ensure unique PK

        # Add magic to magic table (based on first riddle's magic)
        name = magic
        usage = name
        damage = random.choice([0, random.randint(1000, 2000)])
        element = random.choice(["earth", "fire", "water", "wind"])
        heal = 0 if damage != 0 else random.randint(800, 1600)
        status = None
        cooldown = random.randint(3, 10)
        mp = random.randint(1000, 2000)

        cursor.execute("""
            INSERT OR REPLACE INTO magic
            (name, usage, damage, element, effect, heal, status, cooldown, mp)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (name, usage, damage, element, None, heal, status, cooldown, mp))

    conn.commit()
    conn.close()

    # Send embed with all 3
    embed = discord.Embed(
        title="🪄 Magic of the Day",
        description="Use !guess to guess the magic words",
        color=discord.Color.dark_purple()
    )

    for i, (q, a) in enumerate(riddles, start=1):
        embed.add_field(
            name=f"Question {i}",
            value=f"{q}\n**The magic words are {magic_text}**",
            inline=False
        )

    await ctx.send(embed=embed)

@bot.command(name="guess")
async def guess(ctx, *, user_guess: str):
    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    # Fetch today's riddles
    cursor.execute("SELECT question, answer, magic FROM daily_questions ORDER BY time ASC")
    rows = cursor.fetchall()

    if not rows:
        await ctx.send("❌ There are no riddles for today yet. Use `!magic_of_the_day` first.")
        conn.close()
        return

    # Check user guess against all 3 riddles
    found = False
    matched_magic = None

    for q, a, m in rows:
        if user_guess.strip().lower() == a.strip().lower() or user_guess.strip().lower() == m.strip().lower():
            found = True
            matched_magic = m
            break

    if not found:
        await ctx.send("❌ Wrong answer. Try again!")
        conn.close()
        return

    # Ensure player exists
    cursor.execute("SELECT * FROM players WHERE user_id = ?", (ctx.author.id,))
    player = cursor.fetchone()

    if not player:
        cursor.execute("""
            INSERT INTO players (user_id, gear, magic, equiped_gear, equiped_magic)
            VALUES (?, ?, ?, ?, ?)
        """, (ctx.author.id, "[]", "[]", "[]", "[]"))
        conn.commit()

    # Add magic to player's magic list
    cursor.execute("SELECT magic FROM players WHERE user_id = ?", (ctx.author.id,))
    current_magic = cursor.fetchone()[0]

    # If empty, just set it
    if not current_magic or current_magic == "[]":
        cursor.execute(
            "UPDATE players SET magic = ? WHERE user_id = ?",
            (json.dumps([matched_magic]), ctx.author.id)
        )
    else:
        # If already exists, don't add duplicates
        magic_list = json.loads(current_magic)

        if matched_magic in magic_list:
            await ctx.send("✅ You already have this magic!")
            conn.close()
            return

        magic_list.append(matched_magic)

        cursor.execute(
            "UPDATE players SET magic = ? WHERE user_id = ?",
            (json.dumps(magic_list), ctx.author.id)
        )

    conn.commit()
    conn.close()

    await ctx.send(f"✅ Correct! You've received the magic: **{matched_magic}**\n!equip to equip your new magic")

