def _chant_stage(value: int) -> int:
    return max(0, min(5, int(value)))

def _chant_element_for_stage(stage: int, profile_name: str | None = None) -> str:
    profile = CHANT_MAGIC_PROFILES.get(profile_name or CHANT_MAGIC_NAME)
    return profile["stages"][_chant_stage(stage)]["element"]

def _apply_chant_vulnerability(damage: float, defender_cache: dict, element: str | None) -> float:
    chant_type = defender_cache.get("chant_type")
    if element and chant_type and str(element).lower() != str(chant_type).lower():
        return damage * 1.5
    return damage

