class PagedEquipView(View):
    def __init__(self, ctx, items, item_type, per_page=5):
        super().__init__(timeout=90)
        self.ctx = ctx
        self.items = items
        self.item_type = item_type  # "gear" or "magic"
        self.per_page = per_page
        self.page = 0
        self.message = None

    def get_embed(self):
        start = self.page * self.per_page
        end = start + self.per_page
        page_items = self.items[start:end]

        embed = discord.Embed(
            title=f"📦 {self.item_type.capitalize()} Inventory",
            description="\n".join(f"• {i}" for i in page_items) or "Empty",
            color=discord.Color.dark_gold()
        )
        embed.set_footer(text=f"Page {self.page + 1}/{max(1, (len(self.items)-1)//self.per_page + 1)}")
        return embed
    def equip_item(self, item):
        user_id = self.ctx.author.id
        item_type = self.item_type
        conn = sqlite3.connect("magic.db")
        cursor = conn.cursor()

        cursor.execute(
            f"SELECT equiped_{item_type} FROM players WHERE user_id = ?",
            (user_id,)
        )
        data = cursor.fetchone()[0]
        equipped = json.loads(data) if data else []

        max_limit = 10

        if item in equipped:
            conn.close()
            return

        # Keep only 9 before adding the newly equipped item.
        while len(equipped) >= max_limit:
            equipped.pop(0)

        equipped.append(item)

        cursor.execute(
            f"UPDATE players SET equiped_{item_type} = ? WHERE user_id = ?",
            (json.dumps(equipped), user_id)
        )

        conn.commit()
        conn.close()

    def resolve_item_name(self, raw_choice: str):
        choice = str(raw_choice or "").strip().lower()
        if not choice:
            return None
        for item in self.items:
            if str(item).strip().lower() == choice:
                return item
        return None

    @discord.ui.button(label="⬅️", style=discord.ButtonStyle.secondary)
    async def prev(self, interaction: discord.Interaction, button: Button):
        if interaction.user != self.ctx.author:
            return
        self.page = max(0, self.page - 1)
        await interaction.response.edit_message(embed=self.get_embed(), view=self)

    @discord.ui.button(label="➡️", style=discord.ButtonStyle.secondary)
    async def next(self, interaction: discord.Interaction, button: Button):
        if interaction.user != self.ctx.author:
            return
        max_page = (len(self.items) - 1) // self.per_page
        self.page = min(max_page, self.page + 1)
        await interaction.response.edit_message(embed=self.get_embed(), view=self)

    @discord.ui.button(label="Equip", style=discord.ButtonStyle.success)
    async def equip(self, interaction: discord.Interaction, button: Button):
        if interaction.user != self.ctx.author:
            return

        await interaction.response.send_message(
            f"✏️ Type the **name** of the {self.item_type} you want to equip:",
            ephemeral=True
        )

        def check(m):
            return m.author == self.ctx.author and m.channel == self.ctx.channel

        msg = await self.ctx.bot.wait_for("message", timeout=30, check=check)
        selected_item = self.resolve_item_name(msg.content)
        if not selected_item:
            await self.ctx.send("❌ Item not found.")
            return

        self.equip_item(selected_item)
        await self.ctx.send(f"✅ Equipped **{selected_item}** as {self.item_type}!\n!arm to start using magic.")
    async def on_timeout(self):
        for item in self.children:
            item.disabled = True
        try:
            await self.message.edit(view=self)
        except:
            pass

    
MAGIC_LABEL_PAD_CHAR = " "

class MagicEquipButton(discord.ui.Button):
    def __init__(self, view: "MagicEquipView", spell: str, equipped: bool, label: str):
        style = discord.ButtonStyle.success if equipped else discord.ButtonStyle.secondary
        super().__init__(label=label[:80], style=style)
        self.magic_view = view
        self.spell = spell

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.magic_view.ctx.author.id:
            await interaction.response.send_message("This menu is not for you.", ephemeral=True)
            return
        self.magic_view.equip_item(self.spell)
        self.magic_view.refresh_layout()
        await interaction.response.edit_message(view=self.magic_view)


class MagicEquipPageSelect(discord.ui.Select):
    def __init__(self, view: "MagicEquipView"):
        options = []
        for i in range(view.max_page + 1):
            options.append(
                discord.SelectOption(
                    label=f"Page {i + 1}/{view.max_page + 1}",
                    value=str(i),
                    default=(i == view.page),
                )
            )
        super().__init__(placeholder="Select page...", options=options, min_values=1, max_values=1)
        self.magic_view = view

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.magic_view.ctx.author.id:
            await interaction.response.send_message("This menu is not for you.", ephemeral=True)
            return
        self.magic_view.page = int(self.values[0])
        self.magic_view.refresh_layout()
        await interaction.response.edit_message(view=self.magic_view)


class MagicEquipView(LayoutView):
    def __init__(self, ctx, items, per_page=4):
        super().__init__(timeout=90)
        self.ctx = ctx
        self.items = items
        self.per_page = per_page
        self.page = 0
        self.max_page = max(0, (len(self.items) - 1) // self.per_page)
        self.message = None
        self.refresh_layout()

    def _fetch_equipped(self):
        conn = sqlite3.connect("magic.db")
        cursor = conn.cursor()
        cursor.execute(
            "SELECT equiped_magic FROM players WHERE user_id = ?",
            (self.ctx.author.id,)
        )
        row = cursor.fetchone()
        conn.close()
        equipped = json.loads(row[0]) if row and row[0] else []
        return set(equipped)

    def equip_item(self, item):
        user_id = self.ctx.author.id
        conn = sqlite3.connect("magic.db")
        cursor = conn.cursor()
        cursor.execute(
            "SELECT equiped_magic FROM players WHERE user_id = ?",
            (user_id,)
        )
        data = cursor.fetchone()[0]
        equipped = json.loads(data) if data else []
        max_limit = 10
        if item in equipped:
            conn.close()
            return False
        while len(equipped) >= max_limit:
            equipped.pop(0)
        equipped.append(item)
        cursor.execute(
            "UPDATE players SET equiped_magic = ? WHERE user_id = ?",
            (json.dumps(equipped), user_id)
        )
        conn.commit()
        conn.close()
        return True

    def refresh_layout(self):
        self.clear_items()
        container = Container()
        container.add_item(
            TextDisplay(
                f"# Magic Inventory\nPage {self.page + 1}/{self.max_page + 1} • Total: {len(self.items)}"
            )
        )

        start = self.page * self.per_page
        end = start + self.per_page
        page_items = self.items[start:end]
        equipped = self._fetch_equipped()
        target_label_len = 79

        for spell in page_items:
            row = ActionRow()
            is_equipped = spell in equipped
            prefix = "✅ " if is_equipped else "⬜ "
            base_label = f"{spell}"
            pad_len = max(0, target_label_len - len(base_label))
            label = f"{base_label}{MAGIC_LABEL_PAD_CHAR * pad_len}{prefix}"
            row.add_item(MagicEquipButton(self, spell, is_equipped, label))
            container.add_item(row)

        if self.max_page > 0:
            row = ActionRow()
            row.add_item(MagicEquipPageSelect(self))
            container.add_item(row)

        self.add_item(container)

@bot.command(name="equip", aliases = ["magic"])
async def equip_magic(ctx):
    ensure_player2(ctx.author.id)

    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    cursor.execute(
        "SELECT magic FROM players WHERE user_id = ?",
        (ctx.author.id,)
    )
    row = cursor.fetchone()
    magic = row[0]

    magic_list = json.loads(magic) if magic else []

    # If player has no magic → GIVE DEFAULTS AND SAVE
    if not magic_list:
        magic_list = [m for m in DEFAULT_MAGIC]
        cursor.execute(
            "UPDATE players SET magic = ? WHERE user_id = ?",
            (json.dumps(magic_list), ctx.author.id)
        )
        conn.commit()
    else:
        if "fire ball" not in magic_list:
            for m in DEFAULT_MAGIC:
                if m not in magic_list:
                    magic_list.append(m)

            cursor.execute(
                "UPDATE players SET magic = ? WHERE user_id = ?",
                (json.dumps(magic_list), ctx.author.id)
            )
            conn.commit()

    conn.close()

    # Magic inventory
    magic_view = MagicEquipView(ctx, magic_list, per_page=4)
    msg = await ctx.send(view=magic_view)
    magic_view.message = msg

