def hp_bar(current_hp, max_hp=10000):

    total = 10

    filled = max(
        0,
        min(
            total,
            round((current_hp / max_hp) * total)
        )
    )

    return (
        "🟩" * filled +
        "⬛" * (total - filled)
    )


def add_log(battle, text):

    battle["logs"].append(text)

    if len(battle["logs"]) > 10:
        battle["logs"] = battle["logs"][-10:]


def alive_players(battle):

    return [
        pid
        for pid, pdata in battle["players"].items()
        if pdata["alive"]
    ]

class MagicBattleView(discord.ui.LayoutView):

    def __init__(self, battle):

        super().__init__(timeout=None)

        hp_lines = []

        for pid, pdata in battle["players"].items():

            icon = "🤖" if pdata["npc"] else "👤"

            hp_lines.append(
                f"{icon} {pdata['name']}\n"
                f"{hp_bar(pdata['hp'])}\n"
                f"{max(0,int(pdata['hp']))}/10000 HP\n"
            )

        hp_text = "\n".join(hp_lines)

        log_text = "\n".join(
            battle["logs"][-10:]
        )

        container = discord.ui.Container(
            discord.ui.TextDisplay(
                f"# ⚔️ Magic Battle\n\n{hp_text}"
            ),
            discord.ui.Separator(),
            discord.ui.TextDisplay(
                f"## Battle Log\n{log_text or 'Battle starting...'}"
            )
        )

        self.add_item(container)

async def create_f2p_profile():

    conn = sqlite3.connect("magic.db")
    conn.row_factory = sqlite3.Row

    cursor = conn.cursor()

    magic_data = {}

    for spell in F2P_MAGIC:

        cursor.execute(
            """
            SELECT
                damage,
                heal,
                effect,
                element,
                usage
            FROM magic
            WHERE name = ?
            """,
            (spell,)
        )

        row = cursor.fetchone()

        if row:

            magic_data[spell] = {
                "damage": row["damage"] or 0,
                "heal": row["heal"] or 0,
                "effect": row["effect"],
                "element": row["element"],
                "usage": row["usage"]
            }

    conn.close()

    return {
        "magic": magic_data,
        "element_buffs": {},
        "element_resists": {},
        "special": [],
        "leech": 0
    }

async def start_magic_battle(
    channel,
    players,
    mode="f2p"
):

    battle = {
        "players": {},
        "logs": [],
        "started": time.time(),
        "turn_index": 0
    }

    for pid, pdata in players.items():

        if pdata["npc"]:

            profile = await create_f2p_profile()

        else:

            if mode == "standard":

                profile = await load_player_profile(pid)

            else:

                profile = await create_f2p_profile()

        battle["players"][pid] = {

            "name": pdata["name"],

            "npc": pdata["npc"],

            "alive": True,

            "hp": 10000,

            "effect": [],

            "profile": profile
        }

    view = MagicBattleView(battle)

    battle_message = await channel.send(
        view=view
    )

    asyncio.create_task(
        run_magic_battle(
            battle,
            battle_message
        )
    )
def pick_spell(player):

    magic_dict = player["profile"]["magic"]

    if not magic_dict:
        return None

    available = []

    current_effects = set(
        player.get("effect", [])
    )

    current_hp = player["hp"]

    for spell_name, spell_data in magic_dict.items():

        effect = spell_data.get("effect")

        effect_list = (
            effect
            if isinstance(effect, list)
            else [effect] if effect else []
        )

        skip = False

        # already guarded
        if (
            "guard" in effect_list
            and "guard" in current_effects
        ):
            skip = True

        # already taunting
        if (
            "taunt" in effect_list
            and "taunt" in current_effects
        ):
            skip = True

        # don't heal at full HP
        if (
            spell_data.get("heal", 0)
            and current_hp >= 9300
        ):
            skip = True

        if not skip:
            available.append(spell_name)

    if not available:
        available = list(
            magic_dict.keys()
        )

    return random.choice(
        available
    )
def choose_target(
    battle,
    attacker_id,
    spell_data
):

    heal = spell_data.get(
        "heal",
        0
    )

    effect = spell_data.get(
        "effect"
    )

    if heal:
        return attacker_id

    effect_list = (
        effect
        if isinstance(effect, list)
        else [effect] if effect else []
    )

    self_target_effects = {
        "guard",
        "taunt"
    }

    for eff in effect_list:

        if eff in self_target_effects:
            return attacker_id

        if (
            eff.endswith("_buff")
            or eff.endswith("_buff2")
            or eff.endswith("_buff3")
        ):
            return attacker_id

    candidates = []

    for pid, pdata in battle["players"].items():

        if pid == attacker_id:
            continue

        if not pdata["alive"]:
            continue

        candidates.append(pid)

    if not candidates:
        return attacker_id

    return random.choice(candidates)
async def run_magic_battle(
    battle,
    battle_message
):

    while True:

        alive = alive_players(battle)

        if len(alive) <= 1:
            break

        player_order = list(
            battle["players"].keys()
        )

        if not player_order:
            break

        current_index = (
            battle["turn_index"]
            % len(player_order)
        )

        attacker_id = player_order[
            current_index
        ]

        battle["turn_index"] += 1

        attacker = battle["players"][
            attacker_id
        ]

        if not attacker["alive"]:

            await asyncio.sleep(1)
            continue

        spell_name = pick_spell(attacker)

        if not spell_name:

            await asyncio.sleep(1)
            continue

        spell_data = (
            attacker["profile"]["magic"]
            .get(spell_name, {})
        )

        target_id = choose_target(
            battle,
            attacker_id,
            spell_data
        )

        await process_magic_battle_cast(
            battle,
            attacker_id,
            target_id,
            spell_name
        )

        try:

            await battle_message.edit(
                view=MagicBattleView(
                    battle
                )
            )

        except Exception:
            pass

        await asyncio.sleep(1)

    winners = alive_players(battle)

    winner_name = (
        battle["players"][winners[0]]["name"]
        if winners
        else "Nobody"
    )

    add_log(
        battle,
        f"🏆 WINNER: {winner_name}"
    )

    try:

        await battle_message.edit(
            view=MagicBattleView(
                battle
            )
        )

    except Exception:
        pass
async def process_magic_battle_cast(
    battle,
    attacker_id,
    target_id,
    spell_name
):

    attacker = battle["players"][attacker_id]
    target = battle["players"][target_id]

    if not attacker["alive"]:
        return

    if not target["alive"]:
        return

    profile = attacker["profile"]

    magic_dict = profile.get("magic", {})

    if spell_name not in magic_dict:
        return

    magic_data = magic_dict[spell_name]

    damage = magic_data.get("damage", 0) or 0
    heal = magic_data.get("heal", 0) or 0
    effect = magic_data.get("effect")
    element = magic_data.get("element")

    special = profile.get("special", [])
    leech = profile.get("leech", 0)

    # --------------------------
    # Frozen check
    # --------------------------

    if "frozen" in attacker["effect"]:

        attacker["effect"].remove("frozen")

        add_log(
            battle,
            f"❄️ {attacker['name']} is frozen and loses a turn."
        )

        return

    # --------------------------
    # Burn damage
    # --------------------------

    if "burn" in attacker["effect"]:

        burn_damage = max(
            1,
            int(attacker["hp"] * 0.03)
        )

        attacker["hp"] -= burn_damage

        add_log(
            battle,
            f"🔥 {attacker['name']} took {burn_damage} burn damage."
        )

        if attacker["hp"] <= 0:

            attacker["alive"] = False

            add_log(
                battle,
                f"☠️ {attacker['name']} burned to death."
            )

            return

    # --------------------------
    # Healing spell
    # --------------------------

    if heal:

        if "healing_power" in special:

            bonus_heal = max(
                0,
                (10000 - int(target["hp"])) // 3
            )

            heal += bonus_heal

        target["hp"] = min(
            10000,
            target["hp"] + heal
        )

        add_log(
            battle,
            f"❤️ {attacker['name']} healed {target['name']} for {int(heal)} HP."
        )

        return

    # --------------------------
    # Gear elemental buffs
    # --------------------------

    if element:

        gear_buffs = profile.get(
            "element_buffs",
            {}
        )

        damage *= (
            1 +
            gear_buffs.get(
                element,
                0
            ) / 100
        )

    # --------------------------
    # Element buff stacks
    # --------------------------

    buff_multiplier = 1.0
    buff_used = []

    for eff in attacker["effect"]:

        if not element:
            continue

        if eff == f"{element}_buff":

            buff_multiplier *= 1.5
            buff_used.append(eff)

        elif eff == f"{element}_buff2":

            buff_multiplier *= 1.55
            buff_used.append(eff)

        elif eff == f"{element}_buff3":

            buff_multiplier *= 1.6
            buff_used.append(eff)

    for used in buff_used:

        try:
            attacker["effect"].remove(used)
        except ValueError:
            pass

    damage *= buff_multiplier

    round_number = battle.get(
        "round",
        1
    )

    damage_multiplier = (
        1.1 **
        ((round_number - 1) // 25)
    )

    damage *= damage_multiplier

    # --------------------------
    # Washed attacker
    # --------------------------

    if "washed" in attacker["effect"]:
        damage *= 0.90

    # --------------------------
    # Spell voice
    # --------------------------

    if "spell_voice" in special:
        damage *= 1.15

    # --------------------------
    # Frozen land
    # --------------------------

    if (
        "frozen_land" in special
        and element == "water"
    ):
        effect = "frost"

    # --------------------------
    # Guard + Taunt
    # --------------------------

    reduction = 1

    if "guard" in target["effect"]:
        reduction *= 0.85

    if "taunt" in target["effect"]:
        reduction *= 0.90

    damage *= reduction

    # --------------------------
    # Weaken
    # --------------------------

    if "weaken" in target["effect"]:
        damage *= 1.10

    # --------------------------
    # Element resist
    # --------------------------

    resist = (
        target["profile"]
        .get(
            "element_resists",
            {}
        )
        .get(
            element,
            0
        )
    )

    damage *= (
        1 -
        resist / 100
    )

    # --------------------------
    # Apply damage
    # --------------------------

    target["hp"] -= damage

    add_log(
        battle,
        f"⚔️ {attacker['name']} used {spell_name} on "
        f"{target['name']} for {int(damage)} damage."
    )

    # --------------------------
    # Leech
    # --------------------------

    if leech:

        leech_heal = (
            damage *
            leech /
            100
        )

        attacker["hp"] += leech_heal

        add_log(
            battle,
            f"🩸 {attacker['name']} leeched "
            f"{int(leech_heal)} HP."
        )

    # --------------------------
    # Effects
    # --------------------------

    if effect:

        effects = (
            effect
            if isinstance(effect, list)
            else [effect]
        )

        for eff in effects:

            if (
                eff in {
                    "weaken",
                    "washed"
                }
                and eff in target["effect"]
            ):
                continue

            target["effect"].append(eff)

        add_log(
            battle,
            f"✨ {target['name']} gained effect: {effect}"
        )

        # Frost -> Frozen

        if "frost" in effects:

            frost_count = (
                target["effect"]
                .count("frost")
            )

            if frost_count >= 3:

                target["effect"].append(
                    "frozen"
                )

                removed = 0
                new_effects = []

                for e in target["effect"]:

                    if (
                        e == "frost"
                        and removed < 3
                    ):
                        removed += 1
                        continue

                    new_effects.append(e)

                target["effect"] = new_effects

                add_log(
                    battle,
                    f"❄️ {target['name']} is frozen!"
                )

    # --------------------------
    # Death
    # --------------------------

    if target["hp"] <= 0:

        target["hp"] = 0

        if (
            "fiery_rebirth"
            in target["profile"].get(
                "special",
                []
            )
        ):

            now = time.time()

            last_ts = target.get(
                "fiery_rebirth_ts",
                0
            )

            if now - last_ts >= 600:

                target[
                    "fiery_rebirth_ts"
                ] = now

                target["hp"] = 3000

                add_log(
                    battle,
                    f"🔥 {target['name']} revived with 3000 HP!"
                )

                return

        target["alive"] = False

        add_log(
            battle,
            f"☠️ {target['name']} fainted!"
        )
async def load_player_profile(user_id):

    conn = sqlite3.connect("magic.db")
    conn.row_factory = sqlite3.Row
    cursor = conn.cursor()

    # ----------------------------------
    # Equipped gear
    # ----------------------------------

    cursor.execute(
        """
        SELECT *
        FROM player_gear
        WHERE user_id = ?
        AND LOWER(equiped)='set'
        LIMIT 1
        """,
        (user_id,)
    )

    set_row = cursor.fetchone()

    if set_row:

        gear_rows = [set_row]

    else:

        cursor.execute(
            """
            SELECT *
            FROM player_gear
            WHERE user_id = ?
            AND LOWER(equiped)
            IN ('weapon','armor')
            """,
            (user_id,)
        )

        rows = cursor.fetchall()

        have_weapon = any(
            str(r["equiped"]).lower() == "weapon"
            for r in rows
        )

        have_armor = any(
            str(r["equiped"]).lower() == "armor"
            for r in rows
        )

        gear_rows = (
            rows
            if (have_weapon and have_armor)
            else []
        )

    element_buffs = {}
    element_resists = {}
    special_effects = []
    leech = 0

    for gear in gear_rows:

        effect_names = [
            gear["primary_effect"]
        ] + [
            gear[f"effect{i}"]
            for i in range(2, 8)
            if gear[f"effect{i}"]
        ]

        for effect_name in effect_names:

            effect_name = normalize_effect_name(
                effect_name
            )

            cursor.execute(
                """
                SELECT *
                FROM effect_dict
                WHERE name = ?
                """,
                (effect_name,)
            )

            effect_row = cursor.fetchone()

            if not effect_row:
                continue

            number = effect_row["number"] or 0
            element = effect_row["element"]
            effect_type = effect_row["effect"]
            special = effect_row["special"]

            if special:

                special_effects.append(
                    effect_name
                )

                continue

            if effect_type == "buff":

                element_buffs[element] = (
                    element_buffs.get(
                        element,
                        0
                    ) + number
                )

            elif effect_type == "resistance":

                element_resists[element] = (
                    element_resists.get(
                        element,
                        0
                    ) + number
                )

            elif effect_type == "leech":

                leech += number

    if "absolute_defence" in special_effects:

        for elem in [
            "fire",
            "water",
            "earth",
            "wind",
            "dark",
            "light"
        ]:

            element_buffs[elem] = (
                element_buffs.get(elem, 0)
                - 10
            )

            element_resists[elem] = (
                element_resists.get(elem, 0)
                + 15
            )

    if "healing_power" in special_effects:

        for elem in [
            "fire",
            "water",
            "earth",
            "wind",
            "dark",
            "light"
        ]:

            element_buffs[elem] = (
                element_buffs.get(elem, 0)
                - 30
            )

    # ----------------------------------
    # Equipped magic
    # ----------------------------------

    cursor.execute(
        """
        SELECT magic, equiped_magic
        FROM players
        WHERE user_id = ?
        """,
        (user_id,)
    )

    row = cursor.fetchone()

    if not row:

        conn.close()

        return await create_f2p_profile()

    owned_magic = (
        json.loads(row["magic"])
        if row["magic"]
        else []
    )

    equipped_magic = (
        json.loads(row["equiped_magic"])
        if row["equiped_magic"]
        else []
    )

    final_magic = []

    if equipped_magic:

        owned_set = set(
            owned_magic
        )

        for spell in equipped_magic:

            if (
                spell in owned_set
                and spell not in final_magic
            ):
                final_magic.append(spell)

            if len(final_magic) >= 10:
                break

    else:

        final_magic = owned_magic[:10]

    # ----------------------------------
    # No magic -> F2P fallback
    # ----------------------------------

    if not final_magic:

        conn.close()

        return await create_f2p_profile()

    magic_data = {}

    for spell in final_magic:

        cursor.execute(
            """
            SELECT
                damage,
                heal,
                effect,
                element,
                usage
            FROM magic
            WHERE name = ?
            """,
            (spell,)
        )

        magic_row = cursor.fetchone()

        if magic_row:

            magic_data[spell] = {
                "damage": magic_row["damage"] or 0,
                "heal": magic_row["heal"] or 0,
                "effect": magic_row["effect"],
                "element": magic_row["element"],
                "usage": magic_row["usage"]
            }

    conn.close()

    # if every spell lookup failed
    if not magic_data:

        return await create_f2p_profile()

    return {
        "magic": magic_data,
        "element_buffs": element_buffs,
        "element_resists": element_resists,
        "special": special_effects,
        "leech": leech
    }
@bot.command(name="riddle_answer", aliases=["answers"])
async def riddle_answer(ctx):
    if ctx.author.id not in owner_ids:
        return await ctx.send("Only owner or premium can view answers to riddles")
    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    cursor.execute("""
        SELECT time, question, answer, magic
        FROM daily_questions
        ORDER BY time ASC
    """)
    rows = cursor.fetchall()
    conn.close()

    if not rows:
        return await ctx.send("❌ No riddles found in the database.")

    embed = discord.Embed(
        title="📜 Riddle Answers",
        color=discord.Color.gold()
    )

    for i, (timestamp, question, answer, magic) in enumerate(rows, start=1):
        embed.add_field(
            name=f"{i}. {question}",
            value=(
                f"🧠 **Answer:** `{answer}`\n"
                f"🪄 **Magic:** `{magic}`\n"
                f"⏱️ **Time:** <t:{timestamp}:R>"
            ),
            inline=False
        )

    await ctx.send(embed=embed)

@bot.command(name="forge")
async def forge(ctx, *, gear_name: str):
    """Forge a gear using arcs (coins)."""
    gear_name = gear_name.strip().lower()

    # ------------------------------
    # Define all valid forgeable gear here
    # ------------------------------
    valid_gear = {
        "fire_staff": "fire_buff3",
        "water_staff": "water_buff3",
        "earth_staff": "earth_buff3",
        "wind_staff": "wind_buff3",
        "fire_armor": "fire_defence3",
        "water_armor": "water_defence3",
        "earth_armor": "earth_defence3",
        "wind_armor": "wind_defence3",
        "storm dragon armor": "frozen_land",
        "phoenix spirit stone": "fiery_rebirth",
        "guardian knight": "absolute_defence",
        "benevolent priest set": "healing_power",
        "malevolent witch set": "spell_voice"
    }

    if gear_name not in valid_gear:
        await ctx.send(f"❌ `{gear_name}` is not a valid gear to forge.")
        return

    primary_effect = valid_gear[gear_name]
    is_special = gear_name in ["storm dragon armor", "phoenix spirit stone"]

    # ------------------------------
    # Check coins in poke.db
    # ------------------------------
    conn_poke = connect_poke_db()
    cursor_poke = conn_poke.cursor()
    cursor_poke.execute("SELECT coins FROM poke WHERE player_id = ?", (ctx.author.id,))
    row = cursor_poke.fetchone()
    if not row or row[0] < 50:
        await ctx.send("❌ You need at least 50 arcs to forge this gear.")
        conn_poke.close()
        return

    cursor_poke.execute("UPDATE poke SET coins = coins - 50 WHERE player_id = ?", (ctx.author.id,))
    conn_poke.commit()
    conn_poke.close()

    # ------------------------------
    # Generate additional effects
    # ------------------------------
    conn_magic = sqlite3.connect("magic.db")
    cursor_magic = conn_magic.cursor()
    cursor_magic.execute("SELECT name FROM effect_dict WHERE special = 0 AND name != ?", (primary_effect,))
    all_effects = [r[0] for r in cursor_magic.fetchall()]

    additional_effects = []
    if is_special:
        chances = [0.10, 0.06, 0.03, 0.01, 0.01, 0.01]  # up to 6 additional effects for special gear
        max_add = 6
    else:
        chances = [0.10, 0.06, 0.03]  # normal gear
        max_add = 3

    for chance in chances:
        if len(additional_effects) >= max_add:
            break
        if random.random() < chance:
            effect = random.choice(all_effects)
            additional_effects.append(effect)

    # ------------------------------
    # Insert forged gear into player_gear
    # ------------------------------
    conn_magic = sqlite3.connect("magic.db")
    cursor_magic = conn_magic.cursor()

    # generate a random gear_id
    gear_id_db = f"{gear_name.replace(' ', '_')}_{random.randint(1000,9999)}"

    columns = ["user_id", "gear_id", "name", "primary_effect"]
    values = [ctx.author.id, gear_id_db, gear_name.title(), primary_effect]

    for i in range(max_add):
        columns.append(f"effect{i+2}")
        values.append(additional_effects[i] if i < len(additional_effects) else None)

    columns.append("equiped")
    values.append("none")

    cursor_magic.execute(
        f"INSERT INTO player_gear ({', '.join(columns)}) VALUES ({', '.join(['?']*len(values))})",
        values
    )
    conn_magic.commit()
    conn_magic.close()

    await ctx.send(
        f"🛠️ You have successfully forged **{gear_name.title()}**!\n"
        f"Primary Effect: `{primary_effect}`\n"
        f"Additional Effects: `{', '.join(additional_effects) if additional_effects else 'None'}`"
    )


@bot.command(name="return")
async def return_magic(ctx, *, magic_name: str = None):
    if not magic_name:
        return await ctx.send("Usage: `!return <magic>`")
    magic_key = str(magic_name or "").strip().lower()
    if not magic_key:
        return await ctx.send("Usage: `!return <magic>`")
    if magic_key in NON_RETURNABLE_MAGIC:
        return await ctx.send("❌ This magic cannot be returned.")

    ensure_player2(ctx.author.id)
    conn = sqlite3.connect("magic.db")
    c = conn.cursor()
    c.execute("SELECT magic, equiped_magic FROM players WHERE user_id = ?", (ctx.author.id,))
    row = c.fetchone()
    magic_list = json.loads(row[0]) if row and row[0] else []
    equipped = json.loads(row[1]) if row and row[1] else []

    match = next((m for m in magic_list if str(m).lower() == magic_key), None)
    if not match:
        conn.close()
        return await ctx.send("❌ You don't have that magic.")

    magic_list.remove(match)
    equipped = [m for m in equipped if str(m).lower() != magic_key]

    c.execute(
        "UPDATE players SET magic = ?, equiped_magic = ? WHERE user_id = ?",
        (json.dumps(magic_list), json.dumps(equipped), ctx.author.id)
    )

    # Remove from magic DB if no one else has it
    c.execute("SELECT user_id, magic FROM players")
    rows = c.fetchall()
    still_exists = False
    for uid, magic_json in rows:
        if int(uid) == int(ctx.author.id):
            continue
        try:
            other_list = json.loads(magic_json) if magic_json else []
        except Exception:
            other_list = []
        if any(str(m).lower() == magic_key for m in other_list):
            still_exists = True
            break

    if not still_exists:
        c.execute(
            "DELETE FROM magic WHERE lower(name) = ? OR lower(usage) = ?",
            (magic_key, magic_key)
        )

    conn.commit()
    conn.close()

    arcs = random.randint(20, 50)
    conn_poke = connect_poke_db()
    ensure_player(conn_poke, ctx.author.id)
    cursor_poke = conn_poke.cursor()
    cursor_poke.execute(
        "UPDATE poke SET coins = coins + ? WHERE player_id = ?",
        (arcs, ctx.author.id)
    )
    conn_poke.commit()
    conn_poke.close()

    player_cache.pop(ctx.author.id, None)
    await ctx.send(
        f"✅ Returned **{match}** and received **{arcs}** ARCs."
    )


async def _attempt_original_magic(user_id: int, send_fn, magic_name: str, element: str, cost: int, dmg_min: int, dmg_max: int, bypass: bool = False):
    magic_name = str(magic_name or "").strip().lower()
    element = str(element or "").strip().lower()
    if not magic_name or not element:
        return await ctx.send("Usage: `!original_magic <element> <magic words>`")

    if not bypass:
        conn = connect_poke_db()
        ensure_player(conn, user_id)
        c = conn.cursor()
        c.execute(
            "UPDATE poke SET coins = coins - ? WHERE player_id = ? AND coins >= ?",
            (int(cost), user_id, int(cost))
        )
        if c.rowcount == 0:
            conn.close()
            return await send_fn(f"❌ You need **{cost} ARCs** to attempt creating an original magic.")
        conn.commit()
        conn.close()

    success = True if bypass else random.random() <= 0.01
    if not success:
        return await send_fn("💥 The magic creation failed...")

    final_damage = random.randint(int(dmg_min), int(dmg_max))

    ensure_player2(user_id)
    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    cursor.execute("SELECT name FROM magic WHERE name = ?", (magic_name,))
    if cursor.fetchone():
        conn.close()
        return await send_fn("❌ A magic with this name already exists.")

    cursor.execute(
        """
        INSERT INTO magic (name, usage, damage, element, effect, heal, status, cooldown, mp)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (magic_name, magic_name, final_damage, element, None, None, None, 0, 0)
    )

    cursor.execute("SELECT magic FROM players WHERE user_id = ?", (user_id,))
    row = cursor.fetchone()
    magic_list = json.loads(row[0]) if row and row[0] else []
    if magic_name not in magic_list:
        magic_list.append(magic_name)
    cursor.execute(
        "UPDATE players SET magic = ? WHERE user_id = ?",
        (json.dumps(magic_list), user_id)
    )

    conn.commit()
    conn.close()

    await send_fn(
        f"✨ **Original Magic Created!**\n"
        f"🔮 Name: **{magic_name}**\n"
        f"🌟 Element: **{element}**\n"
        f"💥 Damage: **{final_damage}**\n"
        f"📦 Added to your magic inventory!"
    )


class OriginalMagicCostView(discord.ui.View):
    def __init__(self, author_id: int, magic_name: str, element: str):
        super().__init__(timeout=60)
        self.author_id = int(author_id)
        self.magic_name = magic_name
        self.element = element
        self.used = False

    async def _lock(self, interaction: discord.Interaction):
        self.used = True
        for child in self.children:
            if isinstance(child, discord.ui.Button):
                child.disabled = True
        await interaction.response.edit_message(view=self)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author_id:
            await interaction.response.send_message("Not your selection!", ephemeral=True)
            return False
        if self.used:
            await interaction.response.send_message("This choice has already been used.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="10 ARCs", style=discord.ButtonStyle.secondary)
    async def ten_arcs(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._lock(interaction)
        await _attempt_original_magic(
            interaction.user.id,
            interaction.channel.send,
            self.magic_name,
            self.element,
            cost=10,
            dmg_min=1400,
            dmg_max=1700,
            bypass=False
        )

    @discord.ui.button(label="50 ARCs", style=discord.ButtonStyle.primary)
    async def fifty_arcs(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._lock(interaction)
        await _attempt_original_magic(
            interaction.user.id,
            interaction.channel.send,
            self.magic_name,
            self.element,
            cost=50,
            dmg_min=1600,
            dmg_max=2300,
            bypass=False
        )


@bot.command(name="original_magic")
async def original_magic(ctx, element: str, *, magic_words: str):

    magic_name = str(magic_words or "").strip().lower()
    element = str(element or "").strip().lower()
    if not magic_name or not element:
        return await ctx.send("Usage: `!original_magic <element> <magic words>`")
    if element not in ["water", "fire", "earth", "wind", "light", "dark"]:
        return await ctx.send("Usage: `!original_magic <element> <magic words>`")

    view = OriginalMagicCostView(ctx.author.id, magic_name, element)
    await ctx.send("Choose your ARC tier:", view=view)

def paginate_list(items, page, per_page=10):
    total_pages = math.ceil(len(items) / per_page)
    if page < 1: page = 1
    if page > total_pages: page = total_pages
    start = (page - 1) * per_page
    end = start + per_page
    return items[start:end], total_pages


