@bot.command(name="magic_list")
async def magic_list(ctx, page: int = 1):
    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    cursor.execute("SELECT name FROM magic ORDER BY name ASC")
    rows = cursor.fetchall()
    conn.close()

    if not rows:
        return await ctx.send("❌ No magic found in database.")

    names = [r[0] for r in rows]
    page_items, total_pages = paginate_list(names, page, per_page=10)

    embed = discord.Embed(
        title="📜 Magic List",
        description=f"Page {page}/{total_pages}",
        color=discord.Color.blurple()
    )

    embed.add_field(
        name="Magic Names",
        value="\n".join(f"• {n}" for n in page_items),
        inline=False
    )

    await ctx.send(embed=embed)


