@bot.command(name="magic_info")
async def magic_info(ctx, *, magic_name: str):
    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    cursor.execute("SELECT * FROM magic WHERE name = ?", (magic_name,))
    row = cursor.fetchone()
    conn.close()

    if not row:
        return await ctx.send("❌ Magic not found.")

    name, usage, damage, element, effect, heal, status, cooldown, mp = row

    embed = discord.Embed(
        title=f"🪄 Magic Details: {name}",
        color=discord.Color.dark_purple()
    )

    embed.add_field(name="Usage", value=usage, inline=True)
    embed.add_field(name="Damage", value=str(damage), inline=True)
    embed.add_field(name="Element", value=element, inline=True)
    embed.add_field(name="Heal", value=str(heal), inline=True)
    effect_display = str(effect)
    if effect == "clear_chant":
        effect_display = "clear_chant (clears opponent chant)"
    elif effect == "clear_status":
        effect_display = "clear_status (clears opponent status)"
    embed.add_field(name="Effect", value=effect_display, inline=True)
    embed.add_field(name="Status", value=str(status), inline=True)
    embed.add_field(name="Cooldown", value=str(cooldown), inline=True)
    embed.add_field(name="MP", value=str(mp), inline=True)

    if name in CHANT_MAGIC_PROFILES:
        stages = CHANT_MAGIC_PROFILES[name]["stages"]
        stage_lines = []
        for idx, stage in enumerate(stages):
            stage_effect = stage.get("effect")
            stage_effect_text = "None" if not stage_effect else stage_effect
            self_heal = stage.get("self_heal", 0) or 0
            heal_text = f", self heal {self_heal}" if self_heal else ""
            stage_lines.append(
                f"{idx}: {stage['element']} | dmg {stage['damage']} | effect {stage_effect_text}{heal_text}"
            )
        embed.add_field(
            name="Chant Stages",
            value="\n".join(stage_lines),
            inline=False
        )
        embed.add_field(
            name="Chant Sentences",
            value="\n".join(CHANT_SENTENCES_BY_PROFILE.get(name, CHANT_SENTENCES)),
            inline=False
        )
    elif name == SILENCE_MAGIC_NAME and effect != "clear_chant":
        embed.add_field(
            name="Special Effect",
            value="Clears opponent chant on hit",
            inline=False
        )

    await ctx.send(embed=embed)
import string
class Cipher:
    def __init__(self):
        self.shift = random.randint(1, 25)
        self.shuffle = list(string.ascii_lowercase)
        random.shuffle(self.shuffle)

    def caesar(self, text):
        out = ""
        for c in text.lower():
            if c.isalpha():
                out += chr((ord(c) - 97 + self.shift) % 26 + 97)
            else:
                out += c
        return out

    def monoalphabetic(self, text):
        mapping = dict(zip(string.ascii_lowercase, self.shuffle))
        return "".join(mapping.get(c, c) for c in text.lower())

    def runic(self, text):
        runes = "áš áš¢áš¦áš¨áš±áš²áš·áš¹ášºáš¾á›á›ƒá›‡á›ˆá›‰á›Šá›á›’á›–á›—á›šá›œá›žá›Ÿ"
        mapping = dict(zip(string.ascii_lowercase, runes))
        return "".join(mapping.get(c, c) for c in text.lower())
    
    def runic_decode(self, text):
        runes = "áš áš¢áš¦áš¨áš±áš²áš·áš¹ášºáš¾á›á›ƒá›‡á›ˆá›‰á›Šá›á›’á›–á›—á›šá›œá›žá›Ÿ"
        mapping = dict(zip(runes, string.ascii_lowercase))
        return "".join(mapping.get(c, c) for c in text)

cipher = Cipher()

