def encrypt(text, grimoire_type):
    if grimoire_type == "caesar":
        return cipher.caesar(text)
    if grimoire_type == "mono":
        return cipher.monoalphabetic(text)
    if grimoire_type == "rune":
        return cipher.runic(text)
    return text

# -------------------- VIEW --------------------

class GrimoireView(discord.ui.View):
    def __init__(self, user_id):
        super().__init__(timeout=120)
        self.user_id = user_id
        self.page = 0
        self.book = 0

    def embed(self):
        grimoire = GRIMOIRES[self.book]
        page_text = GRIMOIRE_TEXT[self.book][self.page]
        encrypted = encrypt(page_text, grimoire["type"])


        desc = f"```{encrypted}```"

        if self.page == 0:
            desc += f"\n**Translated:**\n*{page_text}*"

        embed = discord.Embed(
            title=f"{grimoire['name']} — Page {self.page + 1}/6",
            description=desc,
            color=discord.Color.dark_purple()
        )
        embed.set_footer(text="use !learn <words>")
        return embed

    async def interaction_check(self, interaction: discord.Interaction):
        return interaction.user.id == self.user_id

    @discord.ui.button(label="⬅", style=discord.ButtonStyle.secondary)
    async def left(self, interaction: discord.Interaction, _):
        self.page = (self.page - 1) % 6
        await interaction.response.edit_message(embed=self.embed(), view=self)

    @discord.ui.button(label="⬆", style=discord.ButtonStyle.primary)
    async def up(self, interaction: discord.Interaction, _):
        self.book = (self.book + 1) % len(GRIMOIRES)
        self.page = 0
        await interaction.response.edit_message(embed=self.embed(), view=self)

    @discord.ui.button(label="⬇", style=discord.ButtonStyle.primary)
    async def down(self, interaction: discord.Interaction, _):
        self.book = (self.book - 1) % len(GRIMOIRES)
        self.page = 0
        await interaction.response.edit_message(embed=self.embed(), view=self)
    
    @discord.ui.button(label="➡", style=discord.ButtonStyle.secondary)
    async def right(self, interaction: discord.Interaction, _):
        self.page = (self.page + 1) % 6
        await interaction.response.edit_message(embed=self.embed(), view=self)

