@bot.command(name="admin_destroy_magic")
async def admin_destroy_magic(ctx, *, magic_name: str):
    if ctx.author.id not in owner_ids:
        return await ctx.send("❌ You must be a bot owner to use this command.")

    magic_name = str(magic_name or "").strip().lower()
    if not magic_name:
        return await ctx.send("Usage: `!admin_destroy_magic <magic>`")

    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    cursor.execute("DELETE FROM magic WHERE name = ?", (magic_name,))
    deleted_magic = cursor.rowcount

    cursor.execute("SELECT user_id, magic, equiped_magic FROM players")
    rows = cursor.fetchall()
    updated_players = 0
    for user_id, magic_json, equipped_json in rows:
        try:
            magic_list = json.loads(magic_json) if magic_json else []
        except Exception:
            magic_list = []
        try:
            equipped_list = json.loads(equipped_json) if equipped_json else []
        except Exception:
            equipped_list = []

        new_magic = [m for m in magic_list if str(m).lower() != magic_name]
        new_equipped = [m for m in equipped_list if str(m).lower() != magic_name]

        if new_magic != magic_list or new_equipped != equipped_list:
            cursor.execute(
                "UPDATE players SET magic = ?, equiped_magic = ? WHERE user_id = ?",
                (json.dumps(new_magic), json.dumps(new_equipped), user_id)
            )
            updated_players += 1

    conn.commit()
    conn.close()

    await ctx.send(
        f"✅ Deleted `{magic_name}` from magic database ({deleted_magic} rows). "
        f"Updated {updated_players} player(s)."
    )

