def _build_non_returnable_magic():
    names = set()
    for m in DEFAULT_MAGIC:
        names.add(str(m).strip().lower())
    for m in CHANT_DROP_MAGIC:
        names.add(str(m).strip().lower())
    for m in LEARNABLE_WORDS.values():
        names.add(str(m).strip().lower())
    for passage in PASSAGES.values():
        for key in ("base_magic", "high_magic", "sacred_magic"):
            val = passage.get(key)
            if val:
                names.add(str(val).strip().lower())
    return names

NON_RETURNABLE_MAGIC = _build_non_returnable_magic()

def add_magic_to_player(cursor, user_id, magic_name):
    cursor.execute("SELECT magic FROM players WHERE user_id = ?", (user_id,))
    result = cursor.fetchone()

    if result and result[0]:
        magic_list = json.loads(result[0])
    else:
        magic_list = []

    if magic_name not in magic_list:
        magic_list.append(magic_name)
        cursor.execute(
            "UPDATE players SET magic = ? WHERE user_id = ?",
            (json.dumps(magic_list), user_id)
        )


