@bot.command()
async def meditate(ctx, *, guess: str = None):
    ensure_player2(ctx.author.id)

    conn = sqlite3.connect("magic.db")
    cursor = conn.cursor()

    cursor.execute(
        "SELECT element, sentence_index, word_index, last_used FROM meditation WHERE user_id = ?",
        (ctx.author.id,)
    )
    progress = cursor.fetchone()

    now = int(time.time())

    # Start meditation if none exists
    if not progress:
        element = random.choice(list(PASSAGES.keys()))
        sentence_index = 0
        word_index = 0

        cursor.execute(
            "INSERT INTO meditation (user_id, element, sentence_index, word_index, last_used) VALUES (?, ?, ?, ?, ?)",
            (ctx.author.id, element, sentence_index, word_index, now)
        )

        # Give base magic
        add_magic_to_player(cursor, ctx.author.id, PASSAGES[element]["base_magic"])

        conn.commit()
        conn.close()

        await ctx.send(
            f"🧘 You meditate upon **{element.upper()}**.\n"
            f"📜 *{PASSAGES[element]['text'][0].split('.')[0]}...*\n"
            f"✨ You learn **{PASSAGES[element]['base_magic']}**.\nUse !meditate <sentence> to begin your journey"
        )
        return

    element, sentence_index, word_index, last_used = progress
    passage = PASSAGES[element]
    sentence = passage["text"][sentence_index]
    words = sentence.split()

    # Guessing mode
    if guess:
        if guess.strip().lower() == sentence.strip().lower():
            sentence_index += 1
            word_index = 0

            # Unlock buffs at 5 and 10
            if sentence_index == 5:
                add_magic_to_player(cursor, ctx.author.id, passage["high_magic"])
            if sentence_index == 10:
                add_magic_to_player(cursor, ctx.author.id, passage["sacred_magic"])

            # Completed the whole passage
            if sentence_index >= 10:
                cursor.execute("DELETE FROM meditation WHERE user_id = ?", (ctx.author.id,))
                conn.commit()
                conn.close()
                await ctx.send(
                    "✨ You have completed the passage.\n"
                    "🔮 A new passage will be chosen next time you meditate."
                )
                return

            cursor.execute(
                "UPDATE meditation SET sentence_index = ?, word_index = ? WHERE user_id = ?",
                (sentence_index, word_index, ctx.author.id)
            )
            conn.commit()
            conn.close()
            await ctx.send("✅ Correct. The next sentence reveals itself.")
        else:
            conn.close()
            await ctx.send("❌ That is not the correct sentence.")
        return

    # Daily word reveal (enforced)
    if now - last_used < 86400:
        remaining = 86400 - (now - last_used)
        hours = remaining // 3600
        minutes = (remaining % 3600) // 60
        await ctx.send(f"⏳ You must wait {hours}h {minutes}m to meditate again.")
        conn.close()
        return

    # Daily word reveal
    if word_index < len(words):
        await ctx.send(f"📖 **Word revealed:** `{words[word_index]}`")
        word_index += 1
        cursor.execute(
            "UPDATE meditation SET word_index = ?, last_used = ? WHERE user_id = ?",
            (word_index, now, ctx.author.id)
        )
        conn.commit()
    else:
        await ctx.send("🕯️ The sentence is complete. You may now guess it using `!meditate <sentence>`.")

    # Reminder for buff unlocks
    remaining_to_high = max(0, 5 - (sentence_index + 1))
    remaining_to_sacred = max(0, 10 - (sentence_index + 1))

    if remaining_to_high > 0 and remaining_to_high <= 5:
        await ctx.send(f"⚠️ {remaining_to_high} more sentence(s) until **High {element.capitalize()} Buff**.")
    elif remaining_to_sacred > 0 and remaining_to_sacred <= 10:
        await ctx.send(f"⚠️ {remaining_to_sacred} more sentence(s) until **Sacred {element.capitalize()} Buff**.")

    conn.close()

