import aiosqlite      

SCHEMA = """
CREATE TABLE IF NOT EXISTS guild_settings (
    guild_id    TEXT PRIMARY KEY,
    sold_log    TEXT,
    unsold_log  TEXT,
    auction_ch  TEXT,
    base_price  INTEGER DEFAULT 100,
    increment   INTEGER DEFAULT 10,
    timer_secs  INTEGER DEFAULT 30,
    prefix      TEXT DEFAULT '!'
);
CREATE TABLE IF NOT EXISTS auctioneers (
    guild_id  TEXT,
    user_id   TEXT,
    PRIMARY KEY (guild_id, user_id)
);
CREATE TABLE IF NOT EXISTS wallets (
    guild_id  TEXT,
    user_id   TEXT,
    balance   INTEGER DEFAULT 0,
    PRIMARY KEY (guild_id, user_id)
);
CREATE TABLE IF NOT EXISTS inventory (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id    TEXT,
    user_id     TEXT,
    item_name   TEXT,
    base_price  INTEGER,
    amount_paid INTEGER,
    won_at      TEXT
);
CREATE TABLE IF NOT EXISTS queue (
    id                  INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id            TEXT,
    item_name           TEXT,
    image_url           TEXT DEFAULT NULL,
    base_price_override INTEGER DEFAULT NULL,
    position            INTEGER
);
CREATE TABLE IF NOT EXISTS auction_history (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id    TEXT,
    item_name   TEXT,
    winner_id   TEXT DEFAULT NULL,
    winning_bid INTEGER DEFAULT NULL,
    status      TEXT,
    ended_at    TEXT
);
CREATE TABLE IF NOT EXISTS bid_log (
    id         INTEGER PRIMARY KEY AUTOINCREMENT,
    guild_id   TEXT,
    auction_id INTEGER,
    user_id    TEXT,
    amount     INTEGER,
    placed_at  TEXT
);
"""

# ─────────────────────────────────────────────
# DATABASE CLASS
# ─────────────────────────────────────────────

class AuctionDatabase:
    def __init__(self, db_path: str = "auction_bot.db",
                 connection: Optional[aiosqlite.Connection] = None):
        self.db_path = db_path
        self._external_connection = connection
        self._conn: Optional[aiosqlite.Connection] = None

    async def initialize(self):
        if self._external_connection is not None:
            self._conn = self._external_connection
        else:
            self._conn = await aiosqlite.connect(self.db_path)

        await self._conn.executescript(SCHEMA)

        for migration in [
            "ALTER TABLE inventory ADD COLUMN base_price INTEGER DEFAULT 0",
            "ALTER TABLE queue ADD COLUMN image_url TEXT DEFAULT NULL",
        ]:
            try:
                await self._conn.execute(migration)
            except Exception:
                pass
        await self._conn.commit()

    async def close(self):
        if self._conn and self._external_connection is None:
            await self._conn.close()
            self._conn = None

    async def execute(self, query: str, params: tuple = None):
        try:
            cursor = (
                await self._conn.execute(query, params)
                if params
                else await self._conn.execute(query)
            )
            await self._conn.commit()
            return cursor
        except Exception as e:
            print(f"[AuctionDB ERROR] {datetime.utcnow().isoformat()} — {query} — {e}")
            raise

    async def fetchone(self, query: str, params: tuple = None):
        try:
            cursor = (
                await self._conn.execute(query, params)
                if params
                else await self._conn.execute(query)
            )
            row = await cursor.fetchone()
            await cursor.close()
            return row
        except Exception as e:
            print(f"[AuctionDB ERROR] {datetime.utcnow().isoformat()} — {query} — {e}")
            raise

    async def fetchall(self, query: str, params: tuple = None):
        try:
            cursor = (
                await self._conn.execute(query, params)
                if params
                else await self._conn.execute(query)
            )
            rows = await cursor.fetchall()
            await cursor.close()
            return rows
        except Exception as e:
            print(f"[AuctionDB ERROR] {datetime.utcnow().isoformat()} — {query} — {e}")
            raise


# ─────────────────────────────────────────────
# DATABASE HELPERS
# ─────────────────────────────────────────────

async def ensure_guild_exists(db: AuctionDatabase, guild_id: str):
    row = await db.fetchone(
        "SELECT guild_id FROM guild_settings WHERE guild_id = ?", (guild_id,)
    )
    if not row:
        await db.execute(
            "INSERT INTO guild_settings (guild_id) VALUES (?)", (guild_id,)
        )


async def get_guild_settings(db: AuctionDatabase, guild_id: str) -> Optional[dict]:
    row = await db.fetchone(
        "SELECT * FROM guild_settings WHERE guild_id = ?", (guild_id,)
    )
    if row:
        return dict(zip(
            ["guild_id", "sold_log", "unsold_log", "auction_ch",
             "base_price", "increment", "timer_secs", "prefix"],
            row
        ))
    return None


async def set_guild_setting(db: AuctionDatabase, guild_id: str, setting: str, value):
    await db.execute(
        f"UPDATE guild_settings SET {setting} = ? WHERE guild_id = ?",
        (value, guild_id)
    )


async def add_auctioneer(db: AuctionDatabase, guild_id: str, user_id: str):
    await db.execute(
        "INSERT OR IGNORE INTO auctioneers (guild_id, user_id) VALUES (?, ?)",
        (guild_id, user_id)
    )


async def remove_auctioneer(db: AuctionDatabase, guild_id: str, user_id: str):
    await db.execute(
        "DELETE FROM auctioneers WHERE guild_id = ? AND user_id = ?",
        (guild_id, user_id)
    )


async def get_auctioneers(db: AuctionDatabase, guild_id: str) -> list:
    rows = await db.fetchall(
        "SELECT user_id FROM auctioneers WHERE guild_id = ?", (guild_id,)
    )
    return [r[0] for r in rows] if rows else []


async def get_balance(db: AuctionDatabase, guild_id: str, user_id: str) -> int:
    row = await db.fetchone(
        "SELECT balance FROM wallets WHERE guild_id = ? AND user_id = ?",
        (guild_id, user_id)
    )
    return row[0] if row else 0


async def set_balance(db: AuctionDatabase, guild_id: str, user_id: str, amount: int):
    await db.execute(
        "INSERT OR REPLACE INTO wallets (guild_id, user_id, balance) VALUES (?, ?, ?)",
        (guild_id, user_id, max(0, amount))
    )


async def add_balance(db: AuctionDatabase, guild_id: str, user_id: str, amount: int):
    current = await get_balance(db, guild_id, user_id)
    await set_balance(db, guild_id, user_id, current + amount)


async def remove_balance(db: AuctionDatabase, guild_id: str, user_id: str, amount: int):
    current = await get_balance(db, guild_id, user_id)
    await set_balance(db, guild_id, user_id, current - amount)


async def add_to_inventory(db: AuctionDatabase, guild_id: str, user_id: str,
                           item_name: str, base_price: int, amount_paid: int):
    await db.execute(
        "INSERT INTO inventory "
        "(guild_id, user_id, item_name, base_price, amount_paid, won_at) "
        "VALUES (?, ?, ?, ?, ?, ?)",
        (guild_id, user_id, item_name, base_price, amount_paid,
         datetime.utcnow().isoformat())
    )


async def get_inventory(db: AuctionDatabase, guild_id: str, user_id: str) -> list:
    rows = await db.fetchall(
        "SELECT item_name, base_price, amount_paid FROM inventory "
        "WHERE guild_id = ? AND user_id = ? ORDER BY won_at DESC",
        (guild_id, user_id)
    )
    return rows or []


async def clear_inventory(db: AuctionDatabase, guild_id: str, user_id: str):
    await db.execute(
        "DELETE FROM inventory WHERE guild_id = ? AND user_id = ?",
        (guild_id, user_id)
    )


async def add_to_queue(db: AuctionDatabase, guild_id: str, item_name: str,
                       base_price_override: int = None, image_url: str = None):
    row = await db.fetchone(
        "SELECT MAX(position) FROM queue WHERE guild_id = ?", (guild_id,)
    )
    next_pos = (row[0] or 0) + 1 if row else 1
    await db.execute(
        "INSERT INTO queue (guild_id, item_name, image_url, base_price_override, position) "
        "VALUES (?, ?, ?, ?, ?)",
        (guild_id, item_name, image_url, base_price_override, next_pos)
    )


async def get_queue(db: AuctionDatabase, guild_id: str) -> list:
    rows = await db.fetchall(
        "SELECT id, item_name, base_price_override, position, image_url "
        "FROM queue WHERE guild_id = ? ORDER BY position",
        (guild_id,)
    )
    return rows or []


async def remove_from_queue(db: AuctionDatabase, guild_id: str, queue_id: int):
    row = await db.fetchone(
        "SELECT position FROM queue WHERE id = ?", (queue_id,)
    )
    await db.execute(
        "DELETE FROM queue WHERE id = ? AND guild_id = ?", (queue_id, guild_id)
    )
    if row:
        await db.execute(
            "UPDATE queue SET position = position - 1 "
            "WHERE guild_id = ? AND position > ?",
            (guild_id, row[0])
        )


async def clear_queue(db: AuctionDatabase, guild_id: str):
    await db.execute("DELETE FROM queue WHERE guild_id = ?", (guild_id,))


async def get_first_queue_item(db: AuctionDatabase, guild_id: str):
    return await db.fetchone(
        "SELECT id, item_name, base_price_override, image_url FROM queue "
        "WHERE guild_id = ? ORDER BY position LIMIT 1",
        (guild_id,)
    )


async def move_queue_item(db: AuctionDatabase, guild_id: str,
                          from_pos: int, to_pos: int):
    item = await db.fetchone(
        "SELECT id FROM queue WHERE guild_id = ? AND position = ?",
        (guild_id, from_pos)
    )
    if not item:
        return
    if from_pos < to_pos:
        await db.execute(
            "UPDATE queue SET position = position - 1 "
            "WHERE guild_id = ? AND position > ? AND position <= ?",
            (guild_id, from_pos, to_pos)
        )
    else:
        await db.execute(
            "UPDATE queue SET position = position + 1 "
            "WHERE guild_id = ? AND position >= ? AND position < ?",
            (guild_id, to_pos, from_pos)
        )
    await db.execute(
        "UPDATE queue SET position = ? WHERE id = ?", (to_pos, item[0])
    )


async def create_auction(db: AuctionDatabase, guild_id: str,
                         item_name: str, base_price: int) -> int:
    cursor = await db.execute(
        "INSERT INTO auction_history (guild_id, item_name, status) VALUES (?, ?, ?)",
        (guild_id, item_name, "ACTIVE")
    )
    await db._conn.commit()
    return cursor.lastrowid


async def close_auction(db: AuctionDatabase, guild_id: str, auction_id: int,
                        status: str, winner_id: str = None, winning_bid: int = None):
    await db.execute(
        "UPDATE auction_history "
        "SET status = ?, winner_id = ?, winning_bid = ?, ended_at = ? WHERE id = ?",
        (status, winner_id, winning_bid, datetime.utcnow().isoformat(), auction_id)
    )


async def add_bid_log(db: AuctionDatabase, guild_id: str, auction_id: int,
                      user_id: str, amount: int):
    await db.execute(
        "INSERT INTO bid_log (guild_id, auction_id, user_id, amount, placed_at) "
        "VALUES (?, ?, ?, ?, ?)",
        (guild_id, auction_id, user_id, amount, datetime.utcnow().isoformat())
    )


async def get_bid_log(db: AuctionDatabase, guild_id: str, auction_id: int) -> list:
    rows = await db.fetchall(
        "SELECT user_id, amount, placed_at FROM bid_log "
        "WHERE guild_id = ? AND auction_id = ? ORDER BY placed_at",
        (guild_id, auction_id)
    )
    return rows or []


