# ─────────────────────────────────────────────

class PaginatedView(discord.ui.LayoutView):
    def __init__(self, page: int, total_pages: int):
        super().__init__()
        self.page        = page
        self.total_pages = total_pages
        self._rebuild()

    def _rebuild(self):
        self.clear_items()
        self.add_item(self.build_container(self.page))
        if self.total_pages > 1:
            self.add_item(self._nav_row())

    def _nav_row(self) -> discord.ui.ActionRow:
        prev_btn = discord.ui.Button(
            label="Prev", style=discord.ButtonStyle.secondary,
            custom_id="page_prev", disabled=self.page <= 1,
        )
        counter_btn = discord.ui.Button(
            label=f"{self.page} / {self.total_pages}",
            style=discord.ButtonStyle.secondary,
            custom_id="page_counter", disabled=True,
        )
        next_btn = discord.ui.Button(
            label="Next", style=discord.ButtonStyle.secondary,
            custom_id="page_next", disabled=self.page >= self.total_pages,
        )
        prev_btn.callback = self._prev
        next_btn.callback = self._next
        return discord.ui.ActionRow(prev_btn, counter_btn, next_btn)

    def build_container(self, page: int) -> discord.ui.Container:
        raise NotImplementedError

    async def _prev(self, interaction: discord.Interaction):
        self.page = max(1, self.page - 1)
        self._rebuild()
        await interaction.response.edit_message(view=self)

    async def _next(self, interaction: discord.Interaction):
        self.page = min(self.total_pages, self.page + 1)
        self._rebuild()
        await interaction.response.edit_message(view=self)


