class InventoryView(PaginatedView):
    ITEMS_PER_PAGE = 10

    def __init__(self, user: discord.User, all_items: list, page: int = 1):
        self.user      = user
        self.all_items = all_items
        total_pages    = max(
            1, (len(all_items) + self.ITEMS_PER_PAGE - 1) // self.ITEMS_PER_PAGE
        )
        super().__init__(page, total_pages)

    def build_container(self, page: int) -> discord.ui.Container:
        start = (page - 1) * self.ITEMS_PER_PAGE
        items = self.all_items[start:start + self.ITEMS_PER_PAGE]
        components: list = [
            discord.ui.TextDisplay("# INVENTORY"),
            discord.ui.TextDisplay(f"{self.user.mention}"),
            _sep(visible=True),
        ]
        if not items:
            components.append(discord.ui.TextDisplay("*No items in inventory.*"))
        else:
            for i, (item_name, base_price, amount_paid) in enumerate(items, start=start + 1):
                components.append(discord.ui.TextDisplay(
                    f"**{i}. {item_name}**\n"
                    f"Base Price  —  `{base_price:,}`\n"
                    f"Sold For    —  `{amount_paid:,}`"
                ))
                components.append(_sep(visible=True))
        components.append(discord.ui.TextDisplay(
            f"-# Page {page} of {self.total_pages}  ·  "
            f"{len(self.all_items)} item(s) total"
        ))
        return discord.ui.Container(*components, accent_color=COLOR_PRIMARY)


# ─────────────────────────────────────────────
# QUEUE VIEW  (paginated)
# ─────────────────────────────────────────────

class QueueView(PaginatedView):
    ITEMS_PER_PAGE = 20

    def __init__(self, queue_items: list, page: int = 1):
        self.queue_items = queue_items
        total_pages      = max(
            1, (len(queue_items) + self.ITEMS_PER_PAGE - 1) // self.ITEMS_PER_PAGE
        )
        super().__init__(page, total_pages)

    def build_container(self, page: int) -> discord.ui.Container:
        start = (page - 1) * self.ITEMS_PER_PAGE
        items = self.queue_items[start:start + self.ITEMS_PER_PAGE]
        if not items:
            body = "*The queue is currently empty.*"
        else:
            lines = []
            for i, (item_id, item_name, bp_override, _, image_url) in enumerate(
                    items, start=start + 1):
                price_str = f"`{bp_override:,}`" if bp_override else "*default*"
                img_flag  = "  📎" if image_url else ""
                lines.append(f"**{i}.** {item_name}  —  {price_str}{img_flag}")
            body = "\n".join(lines)
        return discord.ui.Container(
            discord.ui.TextDisplay("# AUCTION QUEUE"),
            _sep(visible=True),
            discord.ui.TextDisplay(body),
            _sep(visible=True),
            discord.ui.TextDisplay(
                f"-# Page {page} of {self.total_pages}  ·  "
                f"{len(self.queue_items)} item(s) queued"
            ),
            accent_color=COLOR_PRIMARY,
        )


# ─────────────────────────────────────────────
# BID HISTORY VIEW  (paginated)
# ─────────────────────────────────────────────

class BidHistoryView(PaginatedView):
    BIDS_PER_PAGE = 15

    def __init__(self, bids: list, page: int = 1):
        self.bids   = bids
        total_pages = max(
            1, (len(bids) + self.BIDS_PER_PAGE - 1) // self.BIDS_PER_PAGE
        )
        super().__init__(page, total_pages)

    def build_container(self, page: int) -> discord.ui.Container:
        start = (page - 1) * self.BIDS_PER_PAGE
        rows  = self.bids[start:start + self.BIDS_PER_PAGE]
        if not rows:
            body = "*No bids have been placed yet.*"
        else:
            lines = []
            for i, (user_id, amount, placed_at) in enumerate(rows, start=start + 1):
                time_part = (
                    placed_at.split("T")[1][:5] if "T" in placed_at else placed_at
                )
                lines.append(f"**{i}.** <@{user_id}>  —  `{amount:,}`  —  `{time_part}`")
            body = "\n".join(lines)
        return discord.ui.Container(
            discord.ui.TextDisplay("# BID HISTORY"),
            _sep(visible=True),
            discord.ui.TextDisplay(body),
            _sep(visible=True),
            discord.ui.TextDisplay(
                f"-# Page {page} of {self.total_pages}  ·  "
                f"{len(self.bids)} bid(s) total"
            ),
            accent_color=COLOR_PRIMARY,
        )


