class _SetupChannelSelect(discord.ui.View):
    def __init__(self, setting_key: str, label: str):
        super().__init__(timeout=60)
        self.setting_key = setting_key
        self.label_str   = label

    @discord.ui.select(
        cls=discord.ui.ChannelSelect,
        placeholder="Pick a channel…",
        channel_types=[discord.ChannelType.text],
    )
    async def pick(self, interaction: discord.Interaction,
                   select: discord.ui.ChannelSelect):
        channel = select.values[0]
        await ensure_guild_exists(auction_db, str(interaction.guild_id))
        await set_guild_setting(
            auction_db, str(interaction.guild_id),
            self.setting_key, str(channel.id)
        )
        await interaction.response.send_message(
            view=SuccessView(f"{self.label_str} set to {channel.mention}"),
            ephemeral=True,
        )
        self.stop()

