class AuctionInfoView(discord.ui.LayoutView):
    def __init__(self, prefix: str, base_price: int, increment: int, timer: int,
                 channels: dict, auctioneer_count: int):
        super().__init__()

        auction_ch = channels.get("auction_ch") or "*not set*"
        sold_log   = channels.get("sold_log")   or "*not set*"
        unsold_log = channels.get("unsold_log") or "*not set*"

        self.add_item(discord.ui.Container(
            discord.ui.TextDisplay("# AUCTION SETTINGS"),
            _sep(visible=True),
            discord.ui.TextDisplay(
                f"**Prefix** — `{prefix}`\n"
                f"**Base Price** — `{base_price:,}`\n"
                f"**Increment** — `{increment:,}`\n"
                f"**Timer** — `{timer}s`\n"
                f"**Auctioneers** — `{auctioneer_count}`"
            ),
            _sep(visible=True),
            discord.ui.TextDisplay(
                f"**Auction Channel** — {auction_ch}\n"
                f"**Sold Log** — {sold_log}\n"
                f"**Unsold Log** — {unsold_log}"
            ),
            _sep(visible=True),
            discord.ui.TextDisplay("-# Press a button below to edit a setting directly."),
            accent_color=COLOR_INFO,
        ))

        # Row 1 — numeric settings
        bp_btn    = discord.ui.Button(label="Set Base Price",  style=discord.ButtonStyle.primary,   custom_id="ainfo_setbp",    row=0)
        inc_btn   = discord.ui.Button(label="Set Increment",   style=discord.ButtonStyle.primary,   custom_id="ainfo_setinc",   row=0)
        timer_btn = discord.ui.Button(label="Set Timer",       style=discord.ButtonStyle.primary,   custom_id="ainfo_settimer", row=0)

        # Row 2 — channel settings
        ach_btn    = discord.ui.Button(label="Auction Channel", style=discord.ButtonStyle.secondary, custom_id="ainfo_ach",    row=1)
        sold_btn   = discord.ui.Button(label="Sold Log",        style=discord.ButtonStyle.secondary, custom_id="ainfo_sold",   row=1)
        unsold_btn = discord.ui.Button(label="Unsold Log",      style=discord.ButtonStyle.secondary, custom_id="ainfo_unsold", row=1)

        bp_btn.callback     = self._on_bp
        inc_btn.callback    = self._on_inc
        timer_btn.callback  = self._on_timer
        ach_btn.callback    = self._on_ach
        sold_btn.callback   = self._on_sold
        unsold_btn.callback = self._on_unsold

        self.add_item(discord.ui.ActionRow(bp_btn, inc_btn, timer_btn))
        self.add_item(discord.ui.ActionRow(ach_btn, sold_btn, unsold_btn))

    async def _is_authorized(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id == interaction.guild.owner_id:
            return True
        auctioneers = await get_auctioneers(auction_db, str(interaction.guild_id))
        return str(interaction.user.id) in auctioneers

    async def _deny(self, interaction: discord.Interaction):
        await interaction.response.send_message(
            view=PermissionDeniedView(), ephemeral=True
        )

    async def _on_bp(self, interaction: discord.Interaction):
        if not await self._is_authorized(interaction): return await self._deny(interaction)
        await interaction.response.send_modal(_SetBasePriceModal())

    async def _on_inc(self, interaction: discord.Interaction):
        if not await self._is_authorized(interaction): return await self._deny(interaction)
        await interaction.response.send_modal(_SetIncrementModal())

    async def _on_timer(self, interaction: discord.Interaction):
        if not await self._is_authorized(interaction): return await self._deny(interaction)
        await interaction.response.send_modal(_SetTimerModal())

    async def _on_ach(self, interaction: discord.Interaction):
        if not await self._is_authorized(interaction): return await self._deny(interaction)
        await interaction.response.send_message(
            view=_SetupChannelSelect("auction_ch", "Auction channel"), ephemeral=True
        )

    async def _on_sold(self, interaction: discord.Interaction):
        if not await self._is_authorized(interaction): return await self._deny(interaction)
        await interaction.response.send_message(
            view=_SetupChannelSelect("sold_log", "Sold log channel"), ephemeral=True
        )

    async def _on_unsold(self, interaction: discord.Interaction):
        if not await self._is_authorized(interaction): return await self._deny(interaction)
        await interaction.response.send_message(
            view=_SetupChannelSelect("unsold_log", "Unsold log channel"), ephemeral=True
        )


