class ConfirmView(discord.ui.LayoutView):
    def __init__(self, prompt: str, timeout: float = 30):
        super().__init__(timeout=timeout)
        self.confirmed: Optional[bool] = None
        confirm_btn = discord.ui.Button(
            label="Confirm", style=discord.ButtonStyle.danger,   custom_id="confirm_yes",
        )
        cancel_btn = discord.ui.Button(
            label="Cancel",  style=discord.ButtonStyle.secondary, custom_id="confirm_no",
        )
        confirm_btn.callback = self._confirm
        cancel_btn.callback  = self._cancel
        self.add_item(discord.ui.Container(
            discord.ui.TextDisplay("# CONFIRM ACTION"),
            _sep(visible=True),
            discord.ui.TextDisplay(prompt),
            accent_color=COLOR_WARN,
        ))
        self.add_item(discord.ui.ActionRow(confirm_btn, cancel_btn))

    async def _confirm(self, interaction: discord.Interaction):
        self.confirmed = True
        self.stop()
        await interaction.response.defer()

    async def _cancel(self, interaction: discord.Interaction):
        self.confirmed = False
        self.stop()
        await interaction.response.defer()


