# AUCTION STATE
# ─────────────────────────────────────────────

auction_db = AuctionDatabase("auction_bot.db")
_active_auctions: dict = {}


def get_auction(guild_id: str): return _active_auctions.get(str(guild_id))
def set_auction(guild_id: str, data: dict): _active_auctions[str(guild_id)] = data
def clear_auction(guild_id: str): _active_auctions.pop(str(guild_id), None)


# ─────────────────────────────────────────────
# PERMISSION CHECKS
# ─────────────────────────────────────────────

def _check_is_auctioneer():
    async def predicate(ctx):
        if not ctx.guild: return False
        if ctx.author.id == ctx.guild.owner_id: return True
        await ensure_guild_exists(auction_db, str(ctx.guild.id))
        auctioneers = await get_auctioneers(auction_db, str(ctx.guild.id))
        return str(ctx.author.id) in auctioneers
    return commands.check(predicate)

def _check_is_owner():
    async def predicate(ctx):
        return ctx.author.id == ctx.guild.owner_id
    return commands.check(predicate)


# ─────────────────────────────────────────────
# COUNTDOWN LABELS
# ─────────────────────────────────────────────

_COUNTDOWN_LABELS = {5: "5️⃣", 4: "4️⃣", 3: "3️⃣", 2: "2️⃣", 1: "1️⃣"}


# ─────────────────────────────────────────────
# AUCTION ENGINE
# ─────────────────────────────────────────────

async def countdown_timer(guild_id: str, auction_channel_id: int):
    """
    Ticks every second.
    • Above 5 s  → edits the live embed normally.
    • 5 s → 1 s  → posts a plain dramatic message each tick, deletes it after
                   1 s so each number feels like a new beat.  The live embed
                   is NOT edited during this window so the image stays clean.
    • 0 s        → cleans up and hands off to _close_auction_auto.
    """
    try:
        _cd_msg = None  # holds the current countdown channel message

        while True:
            await asyncio.sleep(1)
            auction = get_auction(guild_id)
            if not auction:
                return

            if not auction.get("paused", False):
                auction["time_remaining"] -= 1

            time_left = auction["time_remaining"]
            channel   = bot.get_channel(auction_channel_id)

            if time_left > 5:
                # Normal tick — keep the live embed updated
                try:
                    if auction.get("auction_message") and channel:
                        updated = AuctionLiveView(
                            auction["item_name"], auction["base_price"],
                            auction["current_bid"],
                            f"<@{auction['top_bidder_id']}>"
                            if auction["top_bidder_id"] else "None",
                            auction.get("increment", 10),
                            time_left,
                            image_url=auction.get("image_url"),
                        )
                        await auction["auction_message"].edit(view=updated)
                except Exception as e:
                    print(f"[TIMER] view update failed: {e}")

            elif 1 <= time_left <= 5:
                # Dramatic countdown — delete last message, post fresh one
                if _cd_msg:
                    try:
                        await _cd_msg.delete()
                    except Exception:
                        pass
                    _cd_msg = None

                if channel:
                    try:
                        label   = _COUNTDOWN_LABELS[time_left]
                        _cd_msg = await channel.send(
                            f"## {label}  —  **PLACE YOUR BIDS NOW!**"
                        )
                    except Exception as e:
                        print(f"[TIMER] countdown msg failed: {e}")

            if time_left <= 0:
                # Clean up any dangling countdown message
                if _cd_msg:
                    try:
                        await _cd_msg.delete()
                    except Exception:
                        pass
                break

        await _close_auction_auto(guild_id, auction_channel_id)

    except asyncio.CancelledError:
        return
    except Exception as e:
        print(f"[TIMER ERROR] {e}")


async def _close_auction_auto(guild_id: str, auction_channel_id: int):
    try:
        auction = get_auction(guild_id)
        if not auction:
            return
        db      = auction_db
        channel = bot.get_channel(auction_channel_id)

        settings = await db.fetchone(
            "SELECT sold_log, unsold_log FROM guild_settings WHERE guild_id = ?",
            (guild_id,)
        )
        image_url = auction.get("image_url")

        if auction["bidder_count"] > 0:
            winner_id   = auction["top_bidder_id"]
            winning_bid = auction["current_bid"]
            await remove_balance(db, guild_id, winner_id, winning_bid)
            await add_to_inventory(db, guild_id, winner_id, auction["item_name"],
                                   auction["base_price"], winning_bid)
            await close_auction(db, guild_id, auction["auction_db_id"], "SOLD",
                                winner_id, winning_bid)
            if settings and settings[0]:
                sold_ch = bot.get_channel(int(settings[0]))
                if sold_ch:
                    try:
                        await sold_ch.send(view=SoldView(
                            auction["item_name"], f"<@{winner_id}>",
                            winning_bid, auction["bidder_count"],
                            image_url=image_url,
                        ))
                    except Exception as e:
                        print(f"[ERROR] sold view: {e}")
            if channel:
                try:
                    await channel.send(
                        f"Auction closed. **{auction['item_name']}** sold to "
                        f"<@{winner_id}> for {winning_bid:,}."
                    )
                except Exception as e:
                    print(f"[ERROR] sold confirm: {e}")
        else:
            await close_auction(db, guild_id, auction["auction_db_id"], "UNSOLD")
            if settings and settings[1]:
                unsold_ch = bot.get_channel(int(settings[1]))
                if unsold_ch:
                    try:
                        await unsold_ch.send(view=UnsoldView(
                            auction["item_name"], auction["base_price"],
                            image_url=image_url,
                        ))
                    except Exception as e:
                        print(f"[ERROR] unsold view: {e}")
            if channel:
                try:
                    await channel.send(
                        f"Auction closed. **{auction['item_name']}** went unsold."
                    )
                except Exception as e:
                    print(f"[ERROR] unsold confirm: {e}")

        clear_auction(guild_id)
        await asyncio.sleep(5)

        next_item = await get_first_queue_item(db, guild_id)
        if next_item and channel:
            try:
                await channel.send("Next item starting in 5 seconds...")
                await asyncio.sleep(5)
                await start_next_auction(guild_id, auction_channel_id)
            except Exception as e:
                print(f"[ERROR] auto-next auction: {e}")
        elif channel:
            try:
                await channel.send("All items have been auctioned. Queue is empty.")
            except Exception as e:
                print(f"[ERROR] queue-empty msg: {e}")
    except Exception as e:
        print(f"[ERROR] _close_auction_auto: {e}")


async def start_next_auction(guild_id: str, auction_channel_id: int):
    try:
        db = auction_db
        await ensure_guild_exists(db, guild_id)
        next_item = await get_first_queue_item(db, guild_id)
        if not next_item:
            ch = bot.get_channel(auction_channel_id)
            if ch:
                await ch.send("All items have been auctioned. Queue is empty.")
            return

        queue_id, item_name, bp_override, image_url = next_item
        settings = await db.fetchone(
            "SELECT base_price, increment, timer_secs "
            "FROM guild_settings WHERE guild_id = ?", (guild_id,)
        )
        if not settings:
            return

        base_price = bp_override or settings[0]
        increment  = settings[1]
        timer      = settings[2]

        await remove_from_queue(db, guild_id, queue_id)
        channel = bot.get_channel(auction_channel_id)

        if channel:
            intro_msg = await channel.send(
                view=AuctionIntroView(item_name, base_price, image_url=image_url)
            )
            await asyncio.sleep(5)
            try:
                await intro_msg.delete()
            except Exception:
                pass

        auction_id   = await create_auction(db, guild_id, item_name, base_price)
        auction_data = {
            "item_name": item_name, "base_price": base_price,
            "current_bid": 0, "top_bidder_id": None,
            "top_bidder_name": None, "bidder_count": 0,
            "bid_history": [], "paused": False, "time_remaining": timer,
            "auction_message": None, "timer_task": None,
            "auction_db_id": auction_id, "increment": increment,
            "image_url": image_url,
        }
        set_auction(guild_id, auction_data)

        if channel:
            live_view = AuctionLiveView(
                item_name, base_price, 0, "None", increment, timer,
                image_url=image_url,
            )
            msg = await channel.send(view=live_view)
            try:
                await msg.pin()
            except Exception:
                pass
            auction_data["auction_message"] = msg
            set_auction(guild_id, auction_data)
            task = asyncio.create_task(countdown_timer(guild_id, auction_channel_id))
            auction_data["timer_task"] = task
            set_auction(guild_id, auction_data)
    except Exception as e:
        print(f"[ERROR] start_next_auction: {e}")


async def place_bid(guild_id: str, user_id: str,
                    username: str, auction_channel_id: int) -> tuple:
    try:
        db      = auction_db
        auction = get_auction(guild_id)

        if not auction:
            return False, "No active auction right now!"
        if str(user_id) == str(auction["top_bidder_id"]):
            return False, "You are already the top bidder! Wait for someone else to bid."

        increment   = auction.get("increment", 10)
        current_bid = auction["current_bid"]
        new_bid     = (
            (current_bid + increment) if current_bid > 0
            else (auction["base_price"] + increment)
        )

        bal_row = await db.fetchone(
            "SELECT balance FROM wallets WHERE guild_id = ? AND user_id = ?",
            (guild_id, str(user_id))
        )
        balance = bal_row[0] if bal_row else 0

        if balance < new_bid:
            return (
                False,
                f"Insufficient balance. Your balance: {balance:,}, required: {new_bid:,}"
            )

        auction["current_bid"]     = new_bid
        auction["top_bidder_id"]   = str(user_id)
        auction["top_bidder_name"] = username

        if str(user_id) not in [str(b["user_id"]) for b in auction.get("bid_history", [])]:
            auction["bidder_count"] += 1

        auction["bid_history"].append({
            "user_id": str(user_id), "amount": new_bid,
            "time": datetime.utcnow().isoformat()
        })

        await add_bid_log(db, guild_id, auction["auction_db_id"], str(user_id), new_bid)

        # Cancel the running coroutine so we can restart it cleanly
        if auction.get("timer_task"):
            auction["timer_task"].cancel()
            try:
                await auction["timer_task"]
            except asyncio.CancelledError:
                return

        settings   = await db.fetchone(
            "SELECT timer_secs FROM guild_settings WHERE guild_id = ?", (guild_id,)
        )
        full_timer = settings[0] if settings else 30

        # Only extend the clock when ≤10 s remain; spam above that changes nothing
        if auction["time_remaining"] <= 10:
            auction["time_remaining"] = full_timer

        auction["paused"] = False
        set_auction(guild_id, auction)

        task = asyncio.create_task(countdown_timer(guild_id, auction_channel_id))
        auction["timer_task"] = task
        set_auction(guild_id, auction)

        if auction.get("auction_message"):
            channel = bot.get_channel(auction_channel_id)
            if channel:
                updated = AuctionLiveView(
                    auction["item_name"], auction["base_price"],
                    new_bid, f"<@{user_id}>", increment,
                    auction["time_remaining"],
                    image_url=auction.get("image_url"),
                )
                try:
                    await auction["auction_message"].edit(view=updated)
                except Exception as e:
                    print(f"[ERROR] bid view update: {e}")

        return True, f"bid {new_bid}"

    except Exception as e:
        print(f"[ERROR] place_bid: {e}")
        return False, "An error occurred while placing your bid."


