def _parse_queue_entry(entry: str) -> tuple:
    entry = entry.strip()
    if entry.startswith('"'):
        end = entry.find('"', 1)
        if end == -1: return None, None
        item_name = entry[1:end]
        rest = entry[end + 1:].strip()
        if rest:
            try: return item_name, int(rest)
            except ValueError: return None, None
        return item_name, None
    parts = entry.split()
    if not parts: return None, None
    item_name = parts[0]
    if len(parts) > 1:
        try: return item_name, int(parts[1])
        except ValueError: return None, None
    return item_name, None

@bot.group(name="items", invoke_without_command=True)
async def cmd_items(ctx):
    if ctx.invoked_subcommand is None:
        await ctx.send(view=ErrorView("Usage: `!items (add|list|remove|clear|move)`"), delete_after=5)

@cmd_items.command(name="add")
@is_auctioneer
async def cmd_items_add(ctx, *, args: str = None):
    if not args and not ctx.message.attachments:
        return await ctx.send(
            view=ErrorView('`!items add "Item" [price]`  —  attach a .jpg/.png/.gif to include an image'),
            delete_after=8,
        )
    guild_id = str(ctx.guild.id)
    await ensure_guild_exists(db, guild_id)

    attachment_url = None
    for att in ctx.message.attachments:
        if att.filename.lower().endswith((".jpg", ".jpeg", ".png", ".gif")):
            attachment_url = att.url
            break

    if not args:
        return await ctx.send(
            view=ErrorView('Attachment found but no item name given. Use `!items add "Item Name"`'),
            delete_after=8,
        )

    items_added = []
    if "," in args:
        for entry in args.split(","):
            name, price = _parse_queue_entry(entry)
            if name:
                await add_to_queue(db, guild_id, name, price, attachment_url)
                items_added.append((name, price))
    else:
        if args.startswith('"'):
            end = args.find('"', 1)
            if end == -1:
                return await ctx.send(view=ErrorView("Unterminated quote."), delete_after=5)
            name  = args[1:end]
            rest  = args[end + 1:].strip()
            price = int(rest) if rest else None
        else:
            parts = args.split()
            name  = parts[0]
            price = int(parts[1]) if len(parts) > 1 else None
        await add_to_queue(db, guild_id, name, price, attachment_url)
        items_added.append((name, price))

    if items_added:
        lines = "\n".join(
            f"**{i}.** {n}  —  {str(p) if p else 'default price'}"
            + ("  📎" if attachment_url else "")
            for i, (n, p) in enumerate(items_added, 1)
        )
        await ctx.send(
            view=SuccessView(f"Added **{len(items_added)}** item(s) to the queue:\n\n{lines}"),
            delete_after=10,
        )
    else:
        await ctx.send(view=ErrorView("No valid items to add."), delete_after=5)

