@cmd_items.command(name="remove")
@is_auctioneer
async def cmd_items_remove(ctx, position: int = None):
    if position is None or position < 1:
        return await ctx.send(view=ErrorView("Usage: `!items remove <position>`"), delete_after=5)
    guild_id = str(ctx.guild.id)
    items = await get_queue(db, guild_id)
    if position > len(items):
        return await ctx.send(view=ErrorView("Position out of range."), delete_after=5)
    item_id   = items[position - 1][0]
    item_name = items[position - 1][1]
    await remove_from_queue(db, guild_id, item_id)
    await ctx.send(
        view=SuccessView(f"**{item_name}** removed from position **{position}**."),
        delete_after=10,
    )

@cmd_items.command(name="clear")
@is_auctioneer
async def cmd_items_clear(ctx):
    view = ConfirmView("This will remove **all items** from the queue. This cannot be undone.")
    msg = await ctx.send(view=view)
    await view.wait()
    try: await msg.delete()
    except Exception: pass
    if view.confirmed is True:
        await clear_queue(db, str(ctx.guild.id))
        await ctx.send(view=SuccessView("All items removed from the queue."), delete_after=10)
    elif view.confirmed is False:
        await ctx.send(view=InfoView("Queue clear cancelled."), delete_after=5)
    else:
        await ctx.send(view=InfoView("Confirmation timed out. Queue not cleared."), delete_after=5)

