"""
Discord Bot Suspension System — Global, No-Cog, Prefix + Slash Commands
Requirements: discord.py >= 2.4.0, aiosqlite
Install: pip install "discord.py>=2.4.0" aiosqlite
"""

import re
import os
import aiosqlite
from datetime import datetime, timezone
from typing import Optional, Union

import discord
from discord import app_commands
from discord.ext import commands, tasks


# ─── Config ────────────────────────────────────────────────────────────────────

DB_PATH = "suspensions.db"

OWNER_IDS: set[int] = {
    802809697421623318,
    923377321577185280,
}

COLOUR_RED   = 0xE24B4A
COLOUR_GREEN = 0x1D9E75
COLOUR_AMBER = 0xBA7517




# ─── Time helpers ──────────────────────────────────────────────────────────────

_TIME_RE = re.compile(
    r"(?:(\d+)\s*d(?:ays?)?)?"
    r"\s*(?:(\d+)\s*h(?:ours?)?)?"
    r"\s*(?:(\d+)\s*m(?:in(?:utes?)?)?)?"
    r"\s*(?:(\d+)\s*s(?:ec(?:onds?)?)?)?",
    re.IGNORECASE,
)



def format_duration(seconds: int) -> str:
    parts = []
    for label, size in (("day", 86400), ("hour", 3600), ("minute", 60), ("second", 1)):
        if seconds >= size:
            n, seconds = divmod(seconds, size)
            parts.append(f"{n} {label}{'s' if n != 1 else ''}")
    return ", ".join(parts) or "0 seconds"


# ─── Database ──────────────────────────────────────────────────────────────────

async def suspend():
    async with aiosqlite.connect(DB_PATH) as db:
        await db.execute("""
            CREATE TABLE IF NOT EXISTS suspensions (
                user_id    INTEGER PRIMARY KEY,
                reason     TEXT    NOT NULL,
                issued_by  INTEGER NOT NULL,
                issued_at  REAL    NOT NULL,
                expires_at REAL
            )
        """)
        await db.commit()


async def db_add_suspension(user_id: int, reason: str,
                            issued_by: int, expires_at: Optional[float]):
    async with aiosqlite.connect(DB_PATH) as db:
        await db.execute("""
            INSERT INTO suspensions (user_id, reason, issued_by, issued_at, expires_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(user_id) DO UPDATE SET
                reason=excluded.reason,
                issued_by=excluded.issued_by,
                issued_at=excluded.issued_at,
                expires_at=excluded.expires_at
        """, (user_id, reason, issued_by,
              datetime.now(timezone.utc).timestamp(), expires_at))
        await db.commit()


async def db_remove_suspension(user_id: int):
    async with aiosqlite.connect(DB_PATH) as db:
        await db.execute("DELETE FROM suspensions WHERE user_id = ?", (user_id,))
        await db.commit()


async def db_get_suspension(user_id: int) -> Optional[dict]:
    async with aiosqlite.connect(DB_PATH) as db:
        async with db.execute(
            "SELECT * FROM suspensions WHERE user_id = ?", (user_id,)
        ) as cur:
            row = await cur.fetchone()
    if row is None:
        return None
    cols = ["user_id", "reason", "issued_by", "issued_at", "expires_at"]
    return dict(zip(cols, row))


async def db_all_suspensions() -> list[dict]:
    async with aiosqlite.connect(DB_PATH) as db:
        async with db.execute("SELECT * FROM suspensions") as cur:
            rows = await cur.fetchall()
    cols = ["user_id", "reason", "issued_by", "issued_at", "expires_at"]
    return [dict(zip(cols, r)) for r in rows]


async def db_expired_suspensions() -> list[dict]:
    now = datetime.now(timezone.utc).timestamp()
    async with aiosqlite.connect(DB_PATH) as db:
        async with db.execute(
            "SELECT * FROM suspensions WHERE expires_at IS NOT NULL AND expires_at <= ?",
            (now,)
        ) as cur:
            rows = await cur.fetchall()
    cols = ["user_id", "reason", "issued_by", "issued_at", "expires_at"]
    return [dict(zip(cols, r)) for r in rows]


# ─── Suspension embed builder ──────────────────────────────────────────────────
# Build a rich "this user is suspended" embed from a db row.
# Used both for blocking commands AND for showing in commands that mention a
# suspended user (e.g. !battle @banneduser).

def build_suspension_embed(user: Union[discord.User, discord.Member], row: dict) -> discord.Embed:
    expires_text = (
        "**Permanent**"
        if row["expires_at"] is None
        else f"<t:{int(row['expires_at'])}:R> (<t:{int(row['expires_at'])}:f>)"
    )
    embed = discord.Embed(
        title="🔒 User suspended",
        description=(
            f"{user.mention} is **globally suspended** and cannot participate in commands."
        ),
        colour=COLOUR_RED,
        timestamp=datetime.now(timezone.utc),
    )
    embed.add_field(name="Reason",     value=row["reason"],          inline=False)
    embed.add_field(name="Expires",    value=expires_text,           inline=True)
    embed.add_field(name="Issued by",  value=f"<@{row['issued_by']}>", inline=True)
    embed.add_field(name="Issued at",  value=f"<t:{int(row['issued_at'])}:f>", inline=False)
    embed.set_thumbnail(url=user.display_avatar.url)
    return embed


# ─── Core suspension checker ───────────────────────────────────────────────────
# Call this at the top of ANY command that takes a user argument.
# If the user is suspended it replies with the rich embed and returns True
# (meaning "stop, this user is suspended").  Otherwise returns False.
#
# Works for both prefix Context and slash Interaction:
#
#   async def cmd_battle(ctx, user: discord.User):
#       if await check_user_suspended(user, ctx):
#           return
#       ... rest of command ...

async def check_user_suspended(
    user: Union[discord.User, discord.Member],
    dest: Union[commands.Context, discord.Interaction],
) -> bool:
    """
    Check whether `user` is suspended.
    If so, send the ban embed to `dest` and return True.
    Returns False if the user is clear.
    """
    row = await db_get_suspension(user.id)
    if row is None:
        return False

    # Auto-expire on the fly
    if row["expires_at"] and row["expires_at"] <= datetime.now(timezone.utc).timestamp():
        await db_remove_suspension(user.id)
        return False

    embed = build_suspension_embed(user, row)

    if isinstance(dest, commands.Context):
        await dest.send(embed=embed)
    else:  # discord.Interaction
        if dest.response.is_done():
            await dest.followup.send(embed=embed, ephemeral=True)
        else:
            await dest.response.send_message(embed=embed, ephemeral=True)

    return True


# ─── DM helpers ────────────────────────────────────────────────────────────────

async def dm_suspended(user: discord.User, reason: str, duration_str: str,
                       expires_at: Optional[float], is_permanent: bool):
    expires_text = (
        "Your suspension is **permanent**."
        if is_permanent
        else f"Your suspension expires <t:{int(expires_at)}:R>."
    )
    embed = discord.Embed(
        title="You have been suspended",
        description=(
            "You have been suspended from using bot commands globally.\n\n"
            f"**Reason:** {reason}\n"
            f"**Duration:** {duration_str}\n"
            f"{expires_text}\n\n"
            "If you believe this is a mistake, please contact a bot owner."
        ),
        colour=COLOUR_RED,
        timestamp=datetime.now(timezone.utc),
    )
    try:
        await user.send(embed=embed)
    except discord.Forbidden:
        pass


async def dm_unsuspended(user: discord.User):
    embed = discord.Embed(
        title="Suspension lifted",
        description=(
            "Your global bot suspension has been **lifted**.\n"
            "You may now use bot commands again."
        ),
        colour=COLOUR_GREEN,
        timestamp=datetime.now(timezone.utc),
    )
    try:
        await user.send(embed=embed)
    except discord.Forbidden:
        pass


# ─── Owner-only checks ─────────────────────────────────────────────────────────

def owner_only():
    """Prefix command check — restricts to OWNER_IDS."""
    async def predicate(ctx: commands.Context) -> bool:
        if ctx.author.id in OWNER_IDS:
            return True
        await ctx.reply("❌ This command is restricted to bot owners.", mention_author=False)
        return False
    return commands.check(predicate)



# ─── Global suspended check (prefix) ──────────────────────────────────────────

@bot.check
async def global_suspended_check(ctx: commands.Context) -> bool:
    if ctx.author.id in OWNER_IDS:
        return True

    row = await db_get_suspension(ctx.author.id)
    if row is None:
        return True

    if row["expires_at"] and row["expires_at"] <= datetime.now(timezone.utc).timestamp():
        await db_remove_suspension(ctx.author.id)
        return True

    embed = build_suspension_embed(ctx.author, row)
    await ctx.reply(embed=embed, mention_author=False)
    return False



# ─── Background expiry task ────────────────────────────────────────────────────

@tasks.loop(seconds=30)
async def expiry_loop():
    for s in await db_expired_suspensions():
        await db_remove_suspension(s["user_id"])
        try:
            user = await bot.fetch_user(s["user_id"])
            await dm_unsuspended(user)
        except discord.NotFound:
            pass


@expiry_loop.before_loop
async def before_expiry_loop():
    await bot.wait_until_ready()





# ─── Prefix commands ───────────────────────────────────────────────────────────

@bot.command(name="suspend")
@owner_only()
async def cmd_suspend(
    ctx: commands.Context,
    user: discord.User,
    duration: Optional[str] = None,
    *,
    reason: str = "No reason given",
):
    """
    Globally suspend a user from using bot commands.
    Usage : !suspend <@user|user_id> [duration] [reason]
    Examples:
      !suspend @user spam
      !suspend 123456789 1h30m repeated violations
      !suspend @user 2d ban evasion
    """
    if user.id == ctx.author.id:
        return await ctx.reply("❌ You cannot suspend yourself.", mention_author=False)
    if user.id in OWNER_IDS:
        return await ctx.reply("❌ You cannot suspend another bot owner.", mention_author=False)

    is_permanent = True
    expires_at: Optional[float] = None
    duration_str = "Permanent"

    if duration is not None:
        secs = parse_time_string(duration)
        if secs is None or secs <= 0:
            reason = f"{duration} {reason}".strip()
        else:
            is_permanent = False
            expires_at = datetime.now(timezone.utc).timestamp() + secs
            duration_str = format_duration(secs)

    await db_add_suspension(user.id, reason, ctx.author.id, expires_at)

    embed = discord.Embed(
        title="🔴 Permanently suspended" if is_permanent else "⏳ Timed suspension",
        colour=COLOUR_RED,
        timestamp=datetime.now(timezone.utc),
    )
    embed.add_field(name="User",     value=f"{user.mention} (`{user.id}`)", inline=True)
    embed.add_field(name="Duration", value=duration_str,                    inline=True)
    embed.add_field(name="Reason",   value=reason,                          inline=False)
    if not is_permanent:
        embed.add_field(
            name="Expires",
            value=f"<t:{int(expires_at)}:R> (<t:{int(expires_at)}:f>)",
            inline=False,
        )
    embed.set_thumbnail(url=user.display_avatar.url)
    embed.set_footer(text=f"Issued by {ctx.author}", icon_url=ctx.author.display_avatar.url)
    await ctx.send(embed=embed)
    await dm_suspended(user, reason, duration_str, expires_at, is_permanent)


@bot.command(name="unsuspend")
@owner_only()
async def cmd_unsuspend(ctx: commands.Context, user: discord.User):
    """Lift a user's global suspension. Usage: !unsuspend <@user|user_id>"""
    row = await db_get_suspension(user.id)
    if row is None:
        return await ctx.reply(f"ℹ️ {user.mention} is not currently suspended.", mention_author=False)

    await db_remove_suspension(user.id)
    embed = discord.Embed(
        title="✅ Suspension lifted",
        description=f"{user.mention}'s global suspension has been removed.",
        colour=COLOUR_GREEN,
        timestamp=datetime.now(timezone.utc),
    )
    embed.set_thumbnail(url=user.display_avatar.url)
    embed.set_footer(text=f"Removed by {ctx.author}", icon_url=ctx.author.display_avatar.url)
    await ctx.send(embed=embed)
    await dm_unsuspended(user)


@bot.command(name="suspensions")
@owner_only()
async def cmd_suspensions(ctx: commands.Context):
    """List all active global suspensions. Usage: !suspensions"""
    all_rows = await db_all_suspensions()
    now = datetime.now(timezone.utc).timestamp()
    active = [r for r in all_rows if r["expires_at"] is None or r["expires_at"] > now]

    if not active:
        embed = discord.Embed(
            title="✅ No active suspensions",
            description="No users are currently suspended.",
            colour=COLOUR_GREEN,
        )
        return await ctx.send(embed=embed)

    embed = discord.Embed(
        title=f"🔒 Active global suspensions ({len(active)})",
        colour=COLOUR_AMBER,
        timestamp=datetime.now(timezone.utc),
    )
    for s in active:
        try:
            user = await bot.fetch_user(s["user_id"])
            name = str(user)
        except discord.NotFound:
            name = f"Unknown ({s['user_id']})"
        expires = f"<t:{int(s['expires_at'])}:R>" if s["expires_at"] else "**Permanent**"
        embed.add_field(
            name=f"{name} ({s['user_id']})",
            value=f"**Reason:** {s['reason']}\n**Expires:** {expires}",
            inline=False,
        )
    await ctx.send(embed=embed)


@bot.command(name="suspendinfo")
@owner_only()
async def cmd_suspendinfo(ctx: commands.Context, user: discord.User):
    """Check a user's global suspension status. Usage: !suspendinfo <@user|user_id>"""
    row = await db_get_suspension(user.id)
    now = datetime.now(timezone.utc).timestamp()

    if row is None or (row["expires_at"] and row["expires_at"] <= now):
        embed = discord.Embed(
            title="✅ Not suspended",
            description=f"**{user}** has no active global suspension.",
            colour=COLOUR_GREEN,
        )
        embed.set_thumbnail(url=user.display_avatar.url)
        return await ctx.send(embed=embed)

    await ctx.send(embed=build_suspension_embed(user, row))







