# 📩 Command
@bot.command(name="dm")
async def dm(ctx: commands.Context, user: str, *, message: str):
    # 🔒 Owner check
    if ctx.author.id not in owner_ids:
        return await ctx.send("❌ You are not authorized to use this command.")

    # 🔍 Resolve user (ID or mention)
    if user.isdigit():
        user_id = int(user)
    else:
        try:
            user_id = int(user.replace("<@", "").replace("!", "").replace(">", ""))
        except:
            return await ctx.send("❌ Invalid user format.")

    try:
        target = await bot.fetch_user(user_id)
    except:
        return await ctx.send("❌ Could not find that user.")

    # ✉️ Embed
    embed = discord.Embed(
        title="📩 Message from Bot For Penalty",
        description=message,
        color=discord.Color.blurple()
    )
    embed.set_footer(text=f"Sent by {ctx.author}")

    view = DMContainer()

    try:
        await target.send(embed=embed, view=view)
        await ctx.send(f"✅ Message sent to `{target}`.")
    except discord.Forbidden:
        await ctx.send("❌ Cannot DM this user (DMs closed).")
    except Exception as e:
        await ctx.send(f"❌ Failed: {e}")

        
@bot.command(name="guildmembers", aliases=["gmembers", "gm"])
async def guild_members(ctx, guild_id: int = None):
    if ctx.author.id not in owner_ids:
        return await ctx.send("You don't have permission to use this command.")

    # ── Resolve guild ────────────────────────────────────────────────────────
    guild = bot.get_guild(guild_id) if guild_id else ctx.guild
    if not guild:
        return await ctx.send("Guild not found or bot is not in that guild.")

    # ── Fetch members — chunk the guild first to populate cache ─────────────
    try:
        await guild.chunk()  # forces full member list into cache
    except Exception:
        pass

    members = guild.members

    # Fallback: stream via fetch_members if chunk gave nothing
    if not members:
        try:
            members = [m async for m in guild.fetch_members(limit=None)]
        except Exception as e:
            return await ctx.send(f"Failed to fetch members: {e}")

    if not members:
        return await ctx.send("No members found. Make sure the **Server Members Intent** is enabled in the Developer Portal and `intents.members = True` is set in your bot.")

    total = len(members)
    bots   = sum(1 for m in members if m.bot)
    humans = total - bots

    lines = [
        f"`{m.id}` | **{discord.utils.escape_markdown(m.display_name)}** ({discord.utils.escape_markdown(m.name)}) {'🤖' if m.bot else ''}"
        for m in sorted(members, key=lambda m: m.display_name.lower())
    ]

    pages = [lines[i:i + 20] for i in range(0, len(lines), 20)]
    total_pages = len(pages)

    def make_embed(idx: int) -> discord.Embed:
        embed = discord.Embed(
            title=f"Members of {guild.name}",
            description="\n".join(pages[idx]),
            color=discord.Color.blurple(),
        )
        if guild.icon:
            embed.set_thumbnail(url=guild.icon.url)
        embed.add_field(name="Total",  value=str(total),  inline=True)
        embed.add_field(name="Humans", value=str(humans), inline=True)
        embed.add_field(name="Bots",   value=str(bots),   inline=True)
        embed.set_footer(text=f"Page {idx + 1}/{total_pages} • Guild ID: {guild.id}")
        return embed

    if total_pages == 1:
        return await ctx.send(embed=make_embed(0))

    # ── Button paginator ─────────────────────────────────────────────────────
    class Pages(discord.ui.View):
        def __init__(self):
            super().__init__(timeout=120)
            self.idx = 0
            self._update()

        def _update(self):
            self.first_btn.disabled = self.idx == 0
            self.prev_btn.disabled  = self.idx == 0
            self.next_btn.disabled  = self.idx == total_pages - 1
            self.last_btn.disabled  = self.idx == total_pages - 1

        async def _go(self, interaction: discord.Interaction):
            self._update()
            await interaction.response.edit_message(embed=make_embed(self.idx), view=self)

        @discord.ui.button(emoji="⏮️", style=discord.ButtonStyle.grey)
        async def first_btn(self, interaction: discord.Interaction, _):
            self.idx = 0
            await self._go(interaction)

        @discord.ui.button(emoji="◀️", style=discord.ButtonStyle.blurple)
        async def prev_btn(self, interaction: discord.Interaction, _):
            self.idx -= 1
            await self._go(interaction)

        @discord.ui.button(emoji="▶️", style=discord.ButtonStyle.blurple)
        async def next_btn(self, interaction: discord.Interaction, _):
            self.idx += 1
            await self._go(interaction)

        @discord.ui.button(emoji="⏭️", style=discord.ButtonStyle.grey)
        async def last_btn(self, interaction: discord.Interaction, _):
            self.idx = total_pages - 1
            await self._go(interaction)

        async def on_timeout(self):
            for c in self.children:
                c.disabled = True
            try:
                await msg.edit(view=self)
            except discord.NotFound:
                pass

    view = Pages()
    msg = await ctx.send(embed=make_embed(0), view=view)
# ─────────────────────────────────────────────
# MARKET CONFIG
# ─────────────────────────────────────────────

POKE_DB      = "poke.db"
COSMETICS_DB = "cosmetics.db"
TRIAL_SKIN_DB = "trial_skin.db"

VALID_CATEGORIES = {"pokemon", "pokeball", "status", "graphics", "embed_color", "background"}

_TABLE_MAP = {
    "pokeball":    ("pokeball",    "available_pokeballs"),
    "status":      ("status",      "available_status"),
    "graphics":    ("graphics",    "available_graphics"),
    "embed_color": ("embed_color", "available_colors"),
    "background":  ("background",  "available_backgrounds"),
}

COLOUR_GREEN  = discord.Color.green()
COLOUR_RED    = discord.Color.red()
COLOUR_GOLD   = discord.Color.gold()
COLOUR_ORANGE = discord.Color.orange()
COLOUR_BLURP  = discord.Color.blurple()


# ─────────────────────────────────────────────
# MARKET DATABASE
# ─────────────────────────────────────────────

def _connect_poke_db() -> sqlite3.Connection:
    return sqlite3.connect(POKE_DB)


def _connect_cosmetics_db() -> sqlite3.Connection:
    return sqlite3.connect(COSMETICS_DB)


def _connect_trial_skin_db(timeout: int = 30) -> sqlite3.Connection:
    conn = sqlite3.connect(TRIAL_SKIN_DB, timeout=timeout)
    conn.row_factory = sqlite3.Row
    return conn


def _unequip_trial_skin(user_id: int, pokemon_name: str, cosmetic: str):
    try:
        with sqlite3.connect(COSMETICS_DB) as db:
            db.execute(
                "DELETE FROM equipped WHERE user_id=? AND category='pokemon' AND lower(pokemon_name)=? AND lower(cosmetic)=?",
                (int(user_id), str(pokemon_name).strip().lower(), str(cosmetic).strip().lower())
            )
            db.commit()
    except Exception:
        pass


def _cleanup_expired_trial_skins():
    now = int(time.time())
    try:
        with _connect_trial_skin_db() as conn:
            cursor = conn.cursor()
            cursor.execute(
                "SELECT user_id, pokemon_name, cosmetic FROM trial_skin WHERE expires_at <= ?",
                (now,)
            )
            expired = cursor.fetchall()
            cursor.execute("DELETE FROM trial_skin WHERE expires_at <= ?", (now,))
            conn.commit()
        for row in expired:
            _unequip_trial_skin(row["user_id"], row["pokemon_name"], row["cosmetic"])
    except Exception:
        traceback.print_exc()


def _get_trial_cosmetics_for_pokemon(user_id: int, pokemon_name: str) -> list[str]:
    now = int(time.time())
    pokemon_name = str(pokemon_name or "").strip().lower()
    if not pokemon_name:
        return []
    try:
        with _connect_trial_skin_db() as conn:
            c = conn.cursor()
            c.execute(
                "SELECT cosmetic FROM trial_skin WHERE user_id=? AND lower(pokemon_name)=? AND expires_at > ?",
                (int(user_id), pokemon_name, now)
            )
            return [str(row[0]).strip().lower() for row in c.fetchall() if row[0]]
    except Exception:
        traceback.print_exc()
        return []


def _get_active_trial_skins(user_id: int) -> list[dict]:
    _cleanup_expired_trial_skins()
    with _connect_trial_skin_db() as conn:
        c = conn.cursor()
        c.execute(
            "SELECT pokemon_name, cosmetic, expires_at FROM trial_skin WHERE user_id=?",
            (int(user_id),)
        )
        return [dict(row) for row in c.fetchall()]


def _grant_trial_skin(user_id: int, pokemon_name: str, cosmetic: str, expires_at: int):
    with _connect_trial_skin_db() as conn:
        c = conn.cursor()
        c.execute(
            "INSERT OR REPLACE INTO trial_skin (user_id, pokemon_name, cosmetic, expires_at) VALUES (?, ?, ?, ?)",
            (int(user_id), str(pokemon_name).strip().lower(), str(cosmetic).strip().lower(), int(expires_at))
        )
        conn.commit()


def _setup_market_db():
    with _connect_cosmetics_db() as db:
        db.execute("""
            CREATE TABLE IF NOT EXISTS market (
                listing_id   TEXT PRIMARY KEY,
                seller_id    INTEGER NOT NULL,
                category     TEXT    NOT NULL,
                pokemon_name TEXT,
                cosmetic     TEXT    NOT NULL,
                price        INTEGER NOT NULL,
                listed_at    TEXT    DEFAULT CURRENT_TIMESTAMP,
                status       TEXT    DEFAULT 'active'
            )
        """)
        db.commit()
    print("Market DB ready.")

_setup_market_db()


# ─────────────────────────────────────────────
# MARKET INVENTORY HELPERS
# ─────────────────────────────────────────────

def _ensure_p(conn: sqlite3.Connection, user_id: int):
    conn.execute(
        "INSERT OR IGNORE INTO poke (player_id, coins, pokemon_list, move_list, bag) "
        "VALUES (?, 0, '[]', '[]', '{}')",
        (user_id,)
    )
    conn.commit()


def _user_owns_cosmetic(user_id: int, category: str, cosmetic: str,
                        pokemon_name=None) -> bool:
    with _connect_cosmetics_db() as db:
        c = db.cursor()
        if category == "pokemon":
            c.execute(
                "SELECT available_cosmetics FROM pokemon WHERE user_id=? AND pokemon_name=?",
                (user_id, pokemon_name)
            )
            row = c.fetchone()
            if bool(row) and cosmetic in (row[0] or "").split(","):
                return True
            return cosmetic in _get_trial_cosmetics_for_pokemon(user_id, pokemon_name)
        if category not in _TABLE_MAP:
            return False
        table, col = _TABLE_MAP[category]
        c.execute(f"SELECT {col} FROM {table} WHERE user_id=?", (user_id,))
        row = c.fetchone()
        return bool(row) and cosmetic in (row[0] or "").split(",")


def _user_can_equip_cosmetic(user_id: int, category: str, cosmetic: str,
                             pokemon_name=None) -> bool:
    if category == "pokemon":
        return _user_owns_cosmetic(user_id, category, cosmetic, pokemon_name) or user_has_global_clan_cosmetic(
            user_id,
            category,
            cosmetic,
            pokemon_name,
        )

    if category in _CATEGORY_MAP:
        category_key = category
    elif category in _CATEGORY_KEY.values():
        category_key = next(
            key for key, value in _CATEGORY_KEY.items() if value == category
        )
    else:
        return False

    _, _, defaults = _CATEGORY_MAP[category_key]
    table, col = _CATEGORY_MAP[category_key][0], _CATEGORY_MAP[category_key][1]
    with _connect_cosmetics_db() as db:
        cursor = db.cursor()
        cursor.execute(f"SELECT {col} FROM {table} WHERE user_id=?", (user_id,))
        row = cursor.fetchone()
    owned = set((row[0] or "").split(",")) if row else set()
    return cosmetic in (owned | defaults) or user_has_global_clan_cosmetic(user_id, category_key, cosmetic, None)


def _is_cosmetic_listed(user_id: int, category: str, cosmetic: str,
                        pokemon_name=None) -> bool:
    with _connect_cosmetics_db() as db:
        c = db.execute(
            """SELECT 1 FROM market
               WHERE seller_id=? AND category=? AND cosmetic=?
               AND (pokemon_name IS ? OR (pokemon_name IS NULL AND ? IS NULL))
               AND status='active'""",
            (user_id, category, cosmetic, pokemon_name, pokemon_name)
        )
        return c.fetchone() is not None


def _remove_cosmetic(db: sqlite3.Connection, user_id: int, category: str,
                     cosmetic: str, pokemon_name=None):
    if category == "pokemon":
        row = db.execute(
            "SELECT available_cosmetics FROM pokemon WHERE user_id=? AND pokemon_name=?",
            (user_id, pokemon_name)
        ).fetchone()
        if not row:
            return
        items = [x for x in (row[0] or "").split(",") if x and x != cosmetic]
        db.execute(
            "UPDATE pokemon SET available_cosmetics=? WHERE user_id=? AND pokemon_name=?",
            (",".join(items), user_id, pokemon_name)
        )
        return
    if category not in _TABLE_MAP:
        return
    table, col = _TABLE_MAP[category]
    row = db.execute(f"SELECT {col} FROM {table} WHERE user_id=?", (user_id,)).fetchone()
    if not row:
        return
    items = [x for x in (row[0] or "").split(",") if x and x != cosmetic]
    db.execute(f"UPDATE {table} SET {col}=? WHERE user_id=?", (",".join(items), user_id))


def _grant_cosmetic(db: sqlite3.Connection, user_id: int, category: str,
                    cosmetic: str, pokemon_name=None):
    if category == "pokemon":
        db.execute(
            "INSERT OR IGNORE INTO pokemon (user_id, pokemon_name, available_cosmetics) "
            "VALUES (?,?,'')", (user_id, pokemon_name)
        )
        row = db.execute(
            "SELECT available_cosmetics FROM pokemon WHERE user_id=? AND pokemon_name=?",
            (user_id, pokemon_name)
        ).fetchone()
        items = [x for x in (row[0] or "").split(",") if x]
        if cosmetic not in items:
            items.append(cosmetic)
        db.execute(
            "UPDATE pokemon SET available_cosmetics=? WHERE user_id=? AND pokemon_name=?",
            (",".join(items), user_id, pokemon_name)
        )
        return
    if category not in _TABLE_MAP:
        return
    table, col = _TABLE_MAP[category]
    db.execute(f"INSERT OR IGNORE INTO {table} (user_id, {col}) VALUES (?, '')", (user_id,))
    row = db.execute(f"SELECT {col} FROM {table} WHERE user_id=?", (user_id,)).fetchone()
    items = [x for x in (row[0] or "").split(",") if x]
    if cosmetic not in items:
        items.append(cosmetic)
    db.execute(f"UPDATE {table} SET {col}=? WHERE user_id=?", (",".join(items), user_id))


