def _error_view(msg: str) -> discord.ui.LayoutView:
    v = discord.ui.LayoutView()
    c = discord.ui.Container(
        discord.ui.TextDisplay("✗  **Error**"),
        discord.ui.Separator(),
        discord.ui.TextDisplay(msg),
        accent_colour=COLOUR_RED,
    )
    c._view = v
    v._children.insert(0, c)
    return v


def _simple_view(title: str, body: str, colour=None, footer: str = None) -> discord.ui.LayoutView:
    colour = colour or COLOUR_GOLD
    items  = [
        discord.ui.TextDisplay(f"**{title}**"),
        discord.ui.Separator(),
        discord.ui.TextDisplay(body),
    ]
    if footer:
        items += [discord.ui.Separator(), discord.ui.TextDisplay(f"-# {footer}")]
    v = discord.ui.LayoutView()
    c = discord.ui.Container(*items, accent_colour=colour)
    c._view = v
    v._children.insert(0, c)
    return v


def _success_view(title: str, body: str, footer: str = None) -> discord.ui.LayoutView:
    items = [
        discord.ui.TextDisplay(f"✓  **{title}**"),
        discord.ui.Separator(),
        discord.ui.TextDisplay(body),
    ]
    if footer:
        items += [discord.ui.Separator(), discord.ui.TextDisplay(f"-# {footer}")]
    v = discord.ui.LayoutView()
    c = discord.ui.Container(*items, accent_colour=COLOUR_GREEN)
    c._view = v
    v._children.insert(0, c)
    return v
    
async def block_if_listed(ctx, user_id: int, category: str,
                          cosmetic: str, pokemon_name=None) -> bool:
    if not _is_cosmetic_listed(user_id, category, cosmetic, pokemon_name):
        return False
    await ctx.send(view=_error_view(
        f"**{cosmetic}** is listed on the market and cannot be equipped.\n"
        "-# Use `market remove <id>` to delist it first."
    ))
    return True


# ─────────────────────────────────────────────
# MARKET UTILS
# ─────────────────────────────────────────────

def _short_id(full_uuid: str) -> str:
    return full_uuid[:8].upper()


def _parse_flags(flags: str) -> dict:
    result, parts, i = {}, flags.split(), 0
    while i < len(parts):
        if parts[i].startswith("--") and i + 1 < len(parts):
            result[parts[i][2:]] = parts[i + 1].lower()
            i += 2
        else:
            i += 1
    return result


def _resolve_listing(db: sqlite3.Connection, partial_id: str):
    partial_id = partial_id.upper()
    for row in db.execute("SELECT * FROM market WHERE status='active'").fetchall():
        if row[0].upper().startswith(partial_id):
            return row
    return None


def _listing_line(lid, cosmetic, pokemon_name, price) -> str:
    name = cosmetic + (f" ({pokemon_name.title()})" if pokemon_name else "")
    return f"`{_short_id(lid)}`  ·  {name}  ·  {price:,} coins"


