class BuyConfirmView(discord.ui.LayoutView):
    def __init__(self, listing_id: str, author_id: int, cosmetic: str, category: str,
                 pokemon_name, price: int):
        super().__init__(timeout=30)
        self.listing_id = listing_id
        self.author_id  = author_id
        self.result     = None
        name = cosmetic + (f" ({pokemon_name.title()})" if pokemon_name else "")

        confirm_btn = discord.ui.Button(
            label="✓ Confirm",
            style=discord.ButtonStyle.success,
            custom_id="market_confirm",
        )
        cancel_btn = discord.ui.Button(
            label="✗ Cancel",
            style=discord.ButtonStyle.danger,
            custom_id="market_cancel",
        )
        confirm_btn.callback = self._on_confirm
        cancel_btn.callback  = self._on_cancel

        action_row = discord.ui.ActionRow(confirm_btn, cancel_btn)

        container = discord.ui.Container(
            discord.ui.TextDisplay("**Confirm Purchase**"),
            discord.ui.Separator(),
            discord.ui.TextDisplay(
                f"{name}\n"
                f"{category.replace('_', ' ').title()}  ·  {price:,} coins"
            ),
            discord.ui.Separator(),
            discord.ui.TextDisplay(
                "-# Purchase is anonymous. Seller details are private."
            ),
            accent_colour=COLOUR_BLURP,
        )

        # add_item properly registers _view, _parent, and updates _total_children
        container.add_item(action_row)

        # add_item on LayoutView properly registers container and all nested children
        self.add_item(container)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author_id:
            await interaction.response.send_message(
                "✗ This confirmation isn't for you.", ephemeral=True
            )
            return False
        return True

    async def _on_confirm(self, interaction: discord.Interaction):
        with _connect_cosmetics_db() as db:
            if not _resolve_listing(db, self.listing_id):
                self.result = False
                self.stop()
                return await interaction.response.send_message(
                    "That listing is no longer available.", ephemeral=True
                )

        self.result = True
        self.stop()
        await interaction.response.defer()

    async def _on_cancel(self, interaction: discord.Interaction):
        self.result = False
        self.stop()
        await interaction.response.defer()
        
        
class MarketPageView(discord.ui.LayoutView):
    def __init__(self, pages: list[str], total: int, author_id: int):
        super().__init__(timeout=120)
        self.pages = pages
        self.total = total
        self.page = 0
        self.author_id = author_id

        self._inject_container()

        # get actual button objects
        self.prev_button = self.children[1]
        self.next_button = self.children[2]

        self.prev_button.disabled = True
        self.next_button.disabled = len(pages) <= 1

    def _make_container(self) -> discord.ui.Container:
        return discord.ui.Container(
            discord.ui.TextDisplay(f"**Market Listings**  ·  {self.total} result(s)"),
            discord.ui.Separator(),
            discord.ui.TextDisplay(self.pages[self.page]),
            discord.ui.Separator(),
            discord.ui.TextDisplay(
                f"-# Page {self.page + 1}/{len(self.pages)}"
                "  ·  market buy <id> to purchase"
            ),
            accent_colour=COLOUR_GOLD,
        )

    def _inject_container(self):
        self._children = [
            c for c in self._children
            if not isinstance(c, discord.ui.Container)
        ]

        container = self._make_container()
        container._view = self
        self._children.insert(0, container)

    async def interaction_check(self, interaction: discord.Interaction):
        if interaction.user.id != self.author_id:
            await interaction.response.send_message(
                "✗ This isn't your menu.",
                ephemeral=True
            )
            return False
        return True

    @discord.ui.button(label="< Prev", style=discord.ButtonStyle.secondary)
    async def prev_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.page -= 1

        self.prev_button.disabled = self.page == 0
        self.next_button.disabled = False

        self._inject_container()

        await interaction.response.edit_message(view=self)

    @discord.ui.button(label="Next >", style=discord.ButtonStyle.secondary)
    async def next_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.page += 1

        self.prev_button.disabled = False
        self.next_button.disabled = self.page == len(self.pages) - 1

        self._inject_container()

        await interaction.response.edit_message(view=self)

