@bot.command(name="checkcmd")
async def check_command(ctx, *, name: str):
    cmd = ctx.bot.get_command(name)
    if cmd is None:
        return await ctx.send(f"✗ Command `{name}` is NOT registered.")
    if isinstance(cmd, commands.Group):
        sub_list = ", ".join(c.name for c in cmd.commands) or "None"
        return await ctx.send(f"✓ `{name}` is a GROUP. Subcommands: {sub_list}")
    return await ctx.send(f"✓ `{name}` is a normal command.")


@cmd_market.command(name="list")
async def cmd_market_list(ctx, category: str, cosmetic: str, price: int, *, flags: str = ""):
    if price <= 0:
        return await ctx.send(view=_error_view("Price must be positive."))
    category = category.lower()
    if category not in VALID_CATEGORIES:
        return await ctx.send(view=_error_view(
            f"Invalid category. Choose: {', '.join(sorted(VALID_CATEGORIES))}"
        ))
    f            = _parse_flags(flags)
    pokemon_name = f.get("pokemon")
    if category == "pokemon" and not pokemon_name:
        return await ctx.send(view=_error_view(
            "Pokemon category requires `--pokemon <name>`."
        ))
    if not _user_owns_cosmetic(ctx.author.id, category, cosmetic, pokemon_name):
        return await ctx.send(view=_error_view("You don't own that cosmetic."))
    with _connect_cosmetics_db() as db:
        already = db.execute(
            """SELECT 1 FROM market
               WHERE seller_id=? AND category=? AND cosmetic=?
               AND (pokemon_name IS ? OR (pokemon_name IS NULL AND ? IS NULL))
               AND status='active'""",
            (ctx.author.id, category, cosmetic, pokemon_name, pokemon_name)
        ).fetchone()
        if already:
            return await ctx.send(view=_error_view(
                "You already have that cosmetic listed."
            ))
        lid = str(uuid.uuid4())
        _remove_cosmetic(db, ctx.author.id, category, cosmetic, pokemon_name)
        db.execute(
            "DELETE FROM equipped WHERE user_id=? AND category=? AND cosmetic=? "
            "AND (pokemon_name IS ? OR (pokemon_name IS NULL AND ? IS NULL))",
            (ctx.author.id, category, cosmetic, pokemon_name, pokemon_name)
        )
        db.execute(
            "INSERT INTO market (listing_id, seller_id, category, pokemon_name, cosmetic, price) "
            "VALUES (?,?,?,?,?,?)",
            (lid, ctx.author.id, category, pokemon_name, cosmetic, price)
        )
        db.commit()

    name = cosmetic + (f" ({pokemon_name.title()})" if pokemon_name else "")
    await ctx.send(view=_success_view(
        "Cosmetic Listed",
        f"{name}  ·  {price:,} coins\n"
        f"Category: {category.replace('_', ' ').title()}",
        footer=f"ID: {_short_id(lid)}",
    ))


@cmd_market.command(name="remove", aliases=["cancel"])
async def cmd_market_remove(ctx, listing_id: str):
    with _connect_cosmetics_db() as db:
        row = _resolve_listing(db, listing_id)
        if not row:
            return await ctx.send(view=_error_view("Listing not found."))
        lid, seller_id, category, pokemon_name, cosmetic, price, listed_at, _ = row
        if seller_id != ctx.author.id and not ctx.author.guild_permissions.administrator:
            return await ctx.send(view=_error_view("That's not your listing."))
        db.execute("UPDATE market SET status='cancelled' WHERE listing_id=?", (lid,))
        _grant_cosmetic(db, seller_id, category, cosmetic, pokemon_name)
        db.commit()

    await ctx.send(view=_simple_view(
        "Listing Removed",
        f"{cosmetic} has been returned to your inventory.",
        colour=COLOUR_ORANGE,
        footer=f"ID: {_short_id(lid)}",
    ))


@cmd_market.command(name="buy")
async def cmd_market_buy(ctx, listing_id: str):
    with _connect_cosmetics_db() as db:
        row = _resolve_listing(db, listing_id)
        if not row:
            return await ctx.send(view=_error_view("Listing not found or already sold."))
        lid, seller_id, category, pokemon_name, cosmetic, price, listed_at, _ = row

    if seller_id == ctx.author.id:
        return await ctx.send(view=_error_view("You can't buy your own listing."))

    poke_conn = _connect_poke_db()
    _ensure_p(poke_conn, ctx.author.id)
    _ensure_p(poke_conn, seller_id)
    buyer_coins = poke_conn.execute(
        "SELECT coins FROM poke WHERE player_id=?", (ctx.author.id,)
    ).fetchone()[0]

    if buyer_coins < price:
        poke_conn.close()
        return await ctx.send(view=_error_view(
            f"Need {price:,} coins  ·  you have {buyer_coins:,}."
        ))

    view = BuyConfirmView(listing_id, ctx.author.id, cosmetic, category, pokemon_name, price)
    msg  = await ctx.send(view=view)
    await view.wait()

    if view.result:
        with _connect_cosmetics_db() as db:
            fresh_row = _resolve_listing(db, listing_id)
            if not fresh_row:
                poke_conn.close()
                return await msg.edit(view=_error_view(
                    "Listing no longer available. No coins were spent."
                ))
            lid, seller_id, category, pokemon_name, cosmetic, price, listed_at, _ = fresh_row

    if view.result is None:
        poke_conn.close()
        return await msg.edit(view=_simple_view(
            "Timed Out",
            "No coins were spent.",
            colour=COLOUR_ORANGE,
        ))

    if not view.result:
        poke_conn.close()
        return await msg.edit(view=_error_view("Purchase cancelled. No coins were spent."))

    poke_conn.execute(
        "UPDATE poke SET coins = coins - ? WHERE player_id=?", (price, ctx.author.id)
    )
    poke_conn.execute(
        "UPDATE poke SET coins = coins + ? WHERE player_id=?", (price, seller_id)
    )
    poke_conn.commit()
    poke_conn.close()

    with _connect_cosmetics_db() as db:
        db.execute("UPDATE market SET status='sold' WHERE listing_id=?", (lid,))
        _grant_cosmetic(db, ctx.author.id, category, cosmetic, pokemon_name)
        db.commit()

    try:
        seller = bot.get_user(seller_id) or await bot.fetch_user(seller_id)
        name   = cosmetic + (f" ({pokemon_name.title()})" if pokemon_name else "")
        await seller.send(view=_success_view(
            "Cosmetic Sold",
            f"{name}  ·  {price:,} coins earned",
            footer=f"Listing ID: {_short_id(lid)}",
        ))
    except (discord.Forbidden, discord.NotFound):
        pass

    name = cosmetic + (f" ({pokemon_name.title()})" if pokemon_name else "")
    await msg.edit(view=_success_view(
        "Purchase Complete",
        f"{name}  ·  {price:,} coins spent",
    ))


@cmd_market.command(name="search", aliases=["browse"])
async def cmd_market_search(ctx, *, flags: str = ""):
    f               = _parse_flags(flags)
    name_filter     = f.get("n")
    category_filter = f.get("cat")
    pokemon_filter  = f.get("p")

    query, params = "SELECT * FROM market WHERE status='active'", []
    if name_filter:
        query += " AND LOWER(cosmetic) LIKE ?";  params.append(f"%{name_filter}%")
    if category_filter:
        query += " AND category=?";              params.append(category_filter)
    if pokemon_filter:
        query += " AND LOWER(pokemon_name)=?";   params.append(pokemon_filter)
    query += " ORDER BY listed_at DESC"

    with _connect_cosmetics_db() as db:
        rows = db.execute(query, params).fetchall()

    if not rows:
        return await ctx.send(view=_simple_view(
            "No Listings Found",
            "Try broadening your search filters.",
        ))

    PER_PAGE = 8
    pages    = []
    for i in range(0, len(rows), PER_PAGE):
        lines = []
        for row in rows[i:i + PER_PAGE]:
            lid, seller_id, category, pokemon_name, cosmetic, price, listed_at, _ = row
            lines.append(_listing_line(lid, cosmetic, pokemon_name, price))
        pages.append("\n".join(lines))

    if len(pages) == 1:
        class V(discord.ui.LayoutView):
            container = discord.ui.Container(
                discord.ui.TextDisplay(f"**Market Listings**  ·  {len(rows)} result(s)"),
                discord.ui.Separator(),
                discord.ui.TextDisplay(pages[0]),
                discord.ui.Separator(),
                discord.ui.TextDisplay("-# market buy <id> to purchase"),
                accent_colour=COLOUR_GOLD,
            )
        return await ctx.send(view=V())

    await ctx.send(view=MarketPageView(pages, len(rows), ctx.author.id))


