WHEEL_SEGMENTS = [
    (35, "arcs",      50,  200, "🪙 Arcs"),
    (25, "arcs",     200,  500, "🪙 Arcs+"),
    (10, "arcs",     500,  800, "💰 Arcs"),
    (10, "anime_coupon",       1,    1, "✨ Anime Coupon"),
    (12, "exchange_coupon",  1,    2, "🎟️ Coupon"),
    ( 8, "exchange_coupon",  3,    5, "🎟️ Coupons+"),
]

REWARD_COLOR = {
    "arcs":      discord.Color.gold(),
    "anime_coupon":      discord.Color.purple(),
    "exchange_coupon": discord.Color.teal(),
}
REWARD_EMOJI = {
    "arcs":      "🪙",
    "anime_coupon":      "✨",
    "exchange_coupon": "🎟️",
}

# ════════════════════════════════════════════════════════════════════════════
#  WHEEL SPIN EVENT + ANIME COIN EXCHANGE
#  Paste this entire block into your main bot file.
#
#  ┌─ ONLY THING YOU NEED TO CONFIGURE ─────────────────────────────────────┐
#  │  Set the two paths below to your actual .db file names, then call      │
#  │  _wheel_setup() inside your on_ready — no arguments needed.            │
#  └─────────────────────────────────────────────────────────────────────────┘
# ════════════════════════════════════════════════════════════════════════════

import random
import sqlite3
import time

# ── CONFIGURE THESE TWO PATHS ─────────────────────────────────────────────────
WHEEL_DB_PATH = "cosmetics.db"     # stores anime_coin, anime_coupon, event_cosmetics, pokemon cosmetics
POKE_DB_PATH  = "poke.db"          # existing db — only used to add coins to the poke table
# ─────────────────────────────────────────────────────────────────────────────

SPIN_COOLDOWN      = 10
SPIN_COST          = 1     # anime coins required per spin
EXCHANGE_COST      = 25
ANIME_COIN_PER_WIN = 1



# ── Internal connections (managed automatically) ──────────────────────────────

def _wcon():
    """Connection to the wheel database (anime_coin, coupons, cosmetics)."""
    c = sqlite3.connect(WHEEL_DB_PATH)
    c.row_factory = sqlite3.Row
    return c

def _pcon():
    """Connection to the main database that holds the poke/pokemon tables."""
    c = sqlite3.connect(POKE_DB_PATH)
    c.row_factory = sqlite3.Row
    return c

# ── DB helpers ────────────────────────────────────────────────────────────────

def _wheel_ensure_tables():
    with _wcon() as con:
        con.executescript("""
            CREATE TABLE IF NOT EXISTS anime_coin (
                user_id  INTEGER PRIMARY KEY,
                amount   INTEGER DEFAULT 0
            );
            CREATE TABLE IF NOT EXISTS anime_coupon (
                user_id      INTEGER PRIMARY KEY,
                amount       INTEGER DEFAULT 0,
                last_spin_ts INTEGER DEFAULT 0
            );
            CREATE TABLE IF NOT EXISTS event_cosmetics (
                id           INTEGER PRIMARY KEY AUTOINCREMENT,
                pokemon_name TEXT    NOT NULL,
                cosmetic     TEXT    NOT NULL,
                cost_coupons INTEGER DEFAULT 25,
                stock        INTEGER DEFAULT -1,
                added_at     TEXT    DEFAULT CURRENT_TIMESTAMP
            );
            CREATE TABLE IF NOT EXISTS pokemon (
                user_id             INTEGER NOT NULL,
                pokemon_name        TEXT    NOT NULL,
                available_cosmetics TEXT    DEFAULT \'\',
                PRIMARY KEY (user_id, pokemon_name)
            );
        """)

def _upsert_anime_coin(user_id, delta):
    with _wcon() as con:
        con.execute("""
            INSERT INTO anime_coin (user_id, amount) VALUES (?, ?)
            ON CONFLICT(user_id) DO UPDATE SET amount = amount + excluded.amount
        """, (user_id, delta))

def _upsert_coupon(user_id, delta):
    with _wcon() as con:
        con.execute("""
            INSERT INTO anime_coupon (user_id, amount) VALUES (?, ?)
            ON CONFLICT(user_id) DO UPDATE SET amount = amount + excluded.amount
        """, (user_id, delta))

def _get_anime_coin(user_id):
    with _wcon() as con:
        row = con.execute("SELECT amount FROM anime_coin WHERE user_id = ?", (user_id,)).fetchone()
    return row[0] if row else 0

def _get_coupon(user_id):
    with _wcon() as con:
        row = con.execute("SELECT amount FROM anime_coupon WHERE user_id = ?", (user_id,)).fetchone()
    return row[0] if row else 0

def _get_last_spin(user_id):
    with _wcon() as con:
        row = con.execute("SELECT last_spin_ts FROM anime_coupon WHERE user_id = ?", (user_id,)).fetchone()
    return row[0] if row else 0

def _set_last_spin(user_id, ts):
    with _wcon() as con:
        con.execute("""
            INSERT INTO anime_coupon (user_id, last_spin_ts) VALUES (?, ?)
            ON CONFLICT(user_id) DO UPDATE SET last_spin_ts = excluded.last_spin_ts
        """, (user_id, ts))

def _add_poke_coins(user_id, amount):
    # *** Change table/column names below to match your bot ***
    with _pcon() as con:
        con.execute("""
            INSERT INTO poke (user_id, coins) VALUES (?, ?)
            ON CONFLICT(user_id) DO UPDATE SET coins = coins + excluded.coins
        """, (user_id, amount))

def _get_cosmetics():
    with _wcon() as con:
        rows = con.execute(
            "SELECT id, pokemon_name, cosmetic, cost_coupons, stock "
            "FROM event_cosmetics WHERE stock != 0 ORDER BY id"
        ).fetchall()
    return [{"id": r[0], "pokemon_name": r[1], "cosmetic": r[2],
             "cost_coupons": r[3], "stock": r[4]} for r in rows]

# ── Spin logic ────────────────────────────────────────────────────────────────

def _weighted_pick(segments):
    total = sum(s[0] for s in segments)
    r, cumul = random.uniform(0, total), 0
    for seg in segments:
        cumul += seg[0]
        if r <= cumul:
            return seg
    return segments[-1]

def _do_spin(user_id):
    now       = int(time.time())
    remaining = SPIN_COOLDOWN - (now - _get_last_spin(user_id))
    if remaining > 0:
        return {"cooldown_remaining": remaining}

    # Check anime coin balance before spinning
    if _get_anime_coin(user_id) < SPIN_COST:
        return {"cooldown_remaining": 0, "no_coins": True}

    # Deduct cost
    _upsert_anime_coin(user_id, -SPIN_COST)
    _set_last_spin(user_id, now)
    _, reward_type, lo, hi, label = _weighted_pick(WHEEL_SEGMENTS)
    amount = random.randint(lo, hi)

    if reward_type == "poke_coins":
        try:
            _add_poke_coins(user_id, amount)
        except Exception as e:
            print(f"[WheelEvent] poke_coins error: {e}")
    elif reward_type == "anime_coin":
        _upsert_anime_coin(user_id, amount)
    elif reward_type == "exchange_coupon":
        _upsert_coupon(user_id, amount)

    return {"cooldown_remaining": 0, "reward_type": reward_type,
            "amount": amount, "label": label}

# ── Exchange logic ────────────────────────────────────────────────────────────

def _do_exchange(user_id, cosmetic_id):
    with _wcon() as con:
        row = con.execute(
            "SELECT id, pokemon_name, cosmetic, cost_coupons, stock "
            "FROM event_cosmetics WHERE id = ? AND stock != 0", (cosmetic_id,)
        ).fetchone()
    if row is None:
        return False, "❌ That cosmetic is not available."

    item    = {"id": row[0], "pokemon_name": row[1], "cosmetic": row[2],
               "cost_coupons": row[3], "stock": row[4]}
    cost    = item["cost_coupons"]
    balance = _get_coupon(user_id)
    if balance < cost:
        return False, f"❌ You need **{cost} coupons** but only have **{balance}**."

    with _wcon() as con:
        con.execute("UPDATE anime_coupon SET amount = amount - ? WHERE user_id = ?", (cost, user_id))
        if item["stock"] > 0:
            con.execute("UPDATE event_cosmetics SET stock = stock - 1 WHERE id = ?", (cosmetic_id,))

    poke, cosm = item["pokemon_name"], item["cosmetic"]
    with _wcon() as con:
        existing = con.execute(
            "SELECT available_cosmetics FROM pokemon WHERE user_id = ? AND pokemon_name = ?",
            (user_id, poke)
        ).fetchone()
        if existing:
            current = [c.strip() for c in (existing[0] or "").split(",") if c.strip()]
            if cosm not in current:
                current.append(cosm)
            con.execute(
                "UPDATE pokemon SET available_cosmetics = ? WHERE user_id = ? AND pokemon_name = ?",
                (",".join(current), user_id, poke)
            )
        else:
            con.execute(
                "INSERT INTO pokemon (user_id, pokemon_name, available_cosmetics) VALUES (?, ?, ?)",
                (user_id, poke, cosm)
            )
    return True, f"✅ You received **{cosm}** for **{poke.capitalize()}**!"

# ── Battle win hook ───────────────────────────────────────────────────────────

def grant_battle_anime_reward(winner_user_id):
    """Call inside announce_winner when a battle ends. No con needed."""
    if winner_user_id is None:
        return
    _upsert_anime_coin(winner_user_id, ANIME_COIN_PER_WIN)

# ── Embeds ────────────────────────────────────────────────────────────────────

def _spin_embed(result, user):
    if result["cooldown_remaining"] > 0:
        m, s = divmod(result["cooldown_remaining"], 60)
        return discord.Embed(
            title="⏳ On Cooldown",
            description=f"You can spin again in **{m}m {s}s**.",
            color=discord.Color.orange(),
        )
    if result.get("no_coins"):
        return discord.Embed(
            title="❌ Not Enough Anime Coins",
            description=f"You need **{SPIN_COST} ✨ Anime Coin** to spin.\nEarn coins by winning battles!",
            color=discord.Color.red(),
        )
    rt    = result["reward_type"]
    embed = discord.Embed(
        title="🎡 Wheel Spin!",
        description=(
            f"**{user.display_name}** spun the wheel and landed on…\n\n"
            f"## {REWARD_EMOJI.get(rt, '🎁')} {result['label']}\n"
            f"### +{result['amount']}"
        ),
        color=REWARD_COLOR.get(rt, discord.Color.green()),
    )
    embed.set_footer(text="Spin again in 1 hour  •  Use !exchange to spend coupons")
    return embed


    async def _guard(self, interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("This isn't your window.", ephemeral=True)
            return False
        return True

    async def _pick(self, interaction, offset):
        if not await self._guard(interaction):
            return
        items = self._page_items()
        if offset >= len(items):
            await interaction.response.send_message("No item at that slot.", ephemeral=True)
            return
        success, msg = _do_exchange(self.user_id, items[offset]["id"])
        if success:
            self._reload()
        await interaction.response.send_message(
            embed=discord.Embed(
                description=msg,
                color=discord.Color.green() if success else discord.Color.red(),
            ),
            ephemeral=True,
        )
        if success:
            await interaction.message.edit(embed=self.build_embed(), view=self)

    @discord.ui.button(label="1", style=discord.ButtonStyle.primary, row=0)
    async def pick_1(self, i, _): await self._pick(i, 0)

    @discord.ui.button(label="2", style=discord.ButtonStyle.primary, row=0)
    async def pick_2(self, i, _): await self._pick(i, 1)

    @discord.ui.button(label="3", style=discord.ButtonStyle.primary, row=0)
    async def pick_3(self, i, _): await self._pick(i, 2)

    @discord.ui.button(label="4", style=discord.ButtonStyle.primary, row=0)
    async def pick_4(self, i, _): await self._pick(i, 3)

    @discord.ui.button(label="5", style=discord.ButtonStyle.primary, row=0)
    async def pick_5(self, i, _): await self._pick(i, 4)

    @discord.ui.button(label="◀ Prev", style=discord.ButtonStyle.secondary, row=1)
    async def prev_page(self, interaction, _):
        if not await self._guard(interaction): return
        if self.page > 0:
            self.page -= 1
        await interaction.response.edit_message(embed=self.build_embed(), view=self)

    @discord.ui.button(label="Next ▶", style=discord.ButtonStyle.secondary, row=1)
    async def next_page(self, interaction, _):
        if not await self._guard(interaction): return
        if self.page < self._total_pages() - 1:
            self.page += 1
        await interaction.response.edit_message(embed=self.build_embed(), view=self)

# ── Setup — call _wheel_setup() inside your on_ready ─────────────────────────

def _wheel_setup():
    _wheel_ensure_tables()

    if bot.get_command("spinwheel"):
        return  # already registered (on_ready can fire again on reconnect)

    @bot.command(name="spinwheel", aliases=["spin"])
    async def spinwheel(ctx):
        # Run the logic first (cooldown + coin check, no reward yet)
        result = _do_spin(ctx.author.id)

        # Cooldown or no coins — just send the result embed immediately
        if result.get("cooldown_remaining", 0) > 0 or result.get("no_coins"):
            await ctx.reply(embed=_spin_embed(result, ctx.author), mention_author=False)
            return

        # ── Spin animation ────────────────────────────────────────────────
        segment_labels = [s[4] for s in WHEEL_SEGMENTS]  # all labels
        winning_label  = result["label"]

        # Delays in seconds: starts fast, slows to a stop (26 frames total)
        delays = (
            [0.07] * 6 +   # blazing fast
            [0.12] * 5 +   # fast
            [0.18] * 4 +   # medium
            [0.28] * 4 +   # slowing
            [0.45] * 4 +   # crawling
            [0.70] * 3     # almost stopped
        )

        def _spinning_embed(label, frame):
            """Build a wheel embed with the current segment highlighted."""
            lines = ""
            for seg_label in segment_labels:
                if seg_label == label:
                    lines += f"**➤ {seg_label}** ◀\n"
                else:
                    lines += f"　　{seg_label}\n"
            return discord.Embed(
                title="🎡 Spinning…",
                description=lines,
                color=discord.Color.yellow(),
            ).set_footer(text="▓" * (frame % 8 + 1) + "░" * (8 - frame % 8 - 1))

        # Send the first frame
        idx   = 0
        msg   = await ctx.reply(
            embed=_spinning_embed(segment_labels[idx % len(segment_labels)], 0),
            mention_author=False,
        )

        # Animate through frames
        for frame, delay in enumerate(delays, 1):
            idx += 1
            await asyncio.sleep(delay)
            await msg.edit(embed=_spinning_embed(segment_labels[idx % len(segment_labels)], frame))

        # Land on the winning segment
        await asyncio.sleep(0.3)
        winning_idx = next(
            (i for i, s in enumerate(WHEEL_SEGMENTS) if s[4] == winning_label), 0
        )
        await msg.edit(embed=_spinning_embed(winning_label, 99))

        # Brief pause so they see it land, then show the real result embed
        await asyncio.sleep(1.2)
        await msg.edit(embed=_spin_embed(result, ctx.author))
   

