@bot.command(name="exchange")
async def exchange(ctx):
    _ensure_cosmic_stock_table()
    unowned_cosmic = _get_unowned_cosmic_events(ctx.author.id)
    db_cosmetics   = _get_cosmetics()

    if not unowned_cosmic and not db_cosmetics:
        await ctx.reply("❌ No cosmetics available to exchange right now.", mention_author=False)
        return

    view  = ExchangeView(ctx.author.id, unowned_cosmic, db_cosmetics)
    embed = _build_exchange_embed(ctx.author.id, unowned_cosmic, db_cosmetics)
    await ctx.reply(embed=embed, view=view, mention_author=False)

