DB_PATH_TOS     = "tos.db"

TOS_URL     = "https://goldi-calc.github.io/goldi/"
PRIVACY_URL = "https://goldi-calc.github.io/goldi/"
TOS_VERSION = "1.0"
TOS_EXEMPT  = {"tos"}   # command names that skip the gate

# ── Database ──────────────────────────────────────────────────────────────────

async def tos_db():
    async with aiosqlite.connect(DB_PATH_TOS) as db:
        await db.execute("""
            CREATE TABLE IF NOT EXISTS tos_users (
                user_id     INTEGER PRIMARY KEY,
                accepted_at TEXT NOT NULL DEFAULT (datetime('now')),
                version     TEXT NOT NULL DEFAULT '1.0'
            )
        """)
        await db.commit()

async def has_accepted(user_id: int) -> bool:
    async with aiosqlite.connect(DB_PATH_TOS) as db:
        async with db.execute(
            "SELECT 1 FROM tos_users WHERE user_id = ?", (user_id,)
        ) as cur:
            return await cur.fetchone() is not None

async def mark_accepted(user_id: int):
    async with aiosqlite.connect(DB_PATH_TOS) as db:
        await db.execute(
            """
            INSERT INTO tos_users (user_id, version) VALUES (?, ?)
            ON CONFLICT(user_id) DO UPDATE SET
                accepted_at = datetime('now'), version = excluded.version
            """,
            (user_id, TOS_VERSION),
        )
        await db.commit()

# ── ToS prompt ────────────────────────────────────────────────────────────────

def tos_embed() -> discord.Embed:
    e = discord.Embed(
        title="📋 Terms of Service",
        description=(
            "You must accept our Terms of Service and Privacy Policy before using any commands.\n\n"
            f"[📄 Terms of Service]({TOS_URL})\n"
            f"[🔒 Privacy Policy]({PRIVACY_URL})\n\n"
            "Click **Accept** below to continue."
        ),
        color=discord.Color.blurple(),
    )
    e.set_footer(text=f"Version {TOS_VERSION}")
    return e

class TosView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=300)

    @discord.ui.button(label="✅ Accept", style=discord.ButtonStyle.success)
    async def accept(self, interaction: discord.Interaction, button: discord.ui.Button):
        await mark_accepted(interaction.user.id)
        for item in self.children:
            item.disabled = True
        e = tos_embed()
        e.color = discord.Color.green()
        e.set_footer(text="✅ Accepted — you can now use all commands.")
        await interaction.response.edit_message(embed=e, view=self)

    @discord.ui.button(label="❌ Decline", style=discord.ButtonStyle.danger)
    async def decline(self, interaction: discord.Interaction, button: discord.ui.Button):
        for item in self.children:
            item.disabled = True
        e = tos_embed()
        e.color = discord.Color.red()
        e.set_footer(text="❌ Declined — commands will remain locked.")
        await interaction.response.edit_message(embed=e, view=self)


# ── ToS middleware ────────────────────────────────────────────────────────────

@bot.before_invoke
async def gate_prefix(ctx: commands.Context):
    # TOS check
    if ctx.command and ctx.command.qualified_name not in TOS_EXEMPT:
        if not await has_accepted(ctx.author.id):
            await ctx.send(embed=tos_embed(), view=TosView())
            raise commands.CheckFailure
    # Suspension check
    if ctx.author.id not in OWNER_IDS:
        row = await db_get_suspension(ctx.author.id)
        if row:
            if row["expires_at"] and row["expires_at"] <= datetime.now(timezone.utc).timestamp():
                await db_remove_suspension(ctx.author.id)
            else:
                await ctx.send(embed=build_suspension_embed(ctx.author, row))
                raise commands.CheckFailure


async def gate_slash(interaction: discord.Interaction) -> bool:
    # TOS check
    name = interaction.command.qualified_name if interaction.command else None
    if name not in TOS_EXEMPT:
        if not await has_accepted(interaction.user.id):
            await interaction.response.send_message(embed=tos_embed(), view=TosView(), ephemeral=True)
            return False

    # Suspension check
    if interaction.user.id not in OWNER_IDS:
        row = await db_get_suspension(interaction.user.id)
        if row:
            if row["expires_at"] and row["expires_at"] <= datetime.now(timezone.utc).timestamp():
                await db_remove_suspension(interaction.user.id)
            else:
                await interaction.response.send_message(
                    embed=build_suspension_embed(interaction.user, row), ephemeral=True
                )
                return False

    return True

bot.tree.interaction_check = gate_slash

@bot.command()
async def clear_guild_cmds(ctx):
    if ctx.author.id in owner_ids:
        for guild in bot.guilds:
            bot.tree.clear_commands(guild=guild)
            await bot.tree.sync(guild=guild)
        synced = await bot.tree.sync()
        await ctx.send(
            f"Cleared all guild command copies and re-synced {len(synced)} global commands.\n"
            "Global commands can still take some time to appear in every guild."
        )


@bot.command(name="resync")
async def resync_command(ctx, command_name: str):
    if ctx.author.id in owner_ids:
        # Step 1: find command
        cmd = bot.tree.get_command(command_name)

        if not cmd:
            return await ctx.send(f"❌ Command `{command_name}` not found in tree.")

        # Step 2: remove it
        bot.tree.remove_command(command_name)
        await bot.tree.sync()

        await ctx.send(f"🗑️ Removed `/{command_name}` from Discord. Rebuilding...")

        # Step 3: re-add by reloading from globals (IMPORTANT)
        # This assumes the command is already defined in code
        reloaded = False

        for obj in globals().values():
            # check for app_commands.Command objects
            if isinstance(obj, commands.core.Command):
                continue

        # BEST PRACTICE: just re-sync full tree after code already has command defined
        # so we don't manually reconstruct it

        await bot.tree.sync()

        await ctx.send(f"✅ Re-synced `/{command_name}` successfully.")


DB = "server_activity.db"

ACTIVITIES = [
    "Mass Inc",
    "Tournament",
    "Gyms",
    "Events",
    "Giveaways",
    "Esport",
    "Boss Defeat"
]


#########################
# DATABASE
#########################

def init_activity_db():
    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    cur.execute("""
    CREATE TABLE IF NOT EXISTS activities(
        guild_id INTEGER,
        guild_name TEXT,
        activity TEXT,
        expires_at INTEGER,
        invite TEXT,
        PRIMARY KEY(guild_id, activity)
    )
    """)

    cur.execute("""
    CREATE TABLE IF NOT EXISTS updates(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        timestamp INTEGER,
        guild_name TEXT,
        activity TEXT,
        action TEXT
    )
    """)

    conn.commit()
    conn.close()
init_activity_db()

def save_activity(guild_id, guild_name, activity, expires_at, invite):

    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    cur.execute("""
    INSERT OR REPLACE INTO activities
    (guild_id, guild_name, activity, expires_at, invite)
    VALUES (?, ?, ?, ?, ?)
    """,
    (
        guild_id,
        guild_name,
        activity,
        expires_at,
        invite
    ))

    conn.commit()
    conn.close()


def remove_activity(guild_id, activity):

    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    cur.execute("""
    DELETE FROM activities
    WHERE guild_id=? AND activity=?
    """, (guild_id, activity))

    conn.commit()
    conn.close()


def log_update(guild_name, activity, action):

    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    cur.execute("""
    INSERT INTO updates
    (timestamp, guild_name, activity, action)
    VALUES (?, ?, ?, ?)
    """,
    (
        int(datetime.now(timezone.utc).timestamp()),
        guild_name,
        activity,
        action
    ))

    conn.commit()
    conn.close()


def recent_updates(limit=15):

    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    rows = cur.execute("""
    SELECT timestamp, guild_name, activity, action
    FROM updates
    ORDER BY timestamp DESC
    LIMIT ?
    """, (limit,)).fetchall()

    conn.close()

    if not rows:
        return "No recent updates."

    text = []

    for ts, guild, act, action in rows:

        text.append(
            f"<t:{ts}:t> **{guild}** {action} **{act}**!"
        )

    return "\n".join(text)

def get_boss_defeats(limit=50):

    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    rows = cur.execute("""
        SELECT guild_name, action, timestamp
        FROM updates
        WHERE activity='Boss Defeat'
        ORDER BY timestamp DESC
        LIMIT ?
    """, (limit,)).fetchall()

    conn.close()

    return rows
def get_activity_servers(activity):

    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    rows = cur.execute("""
    SELECT guild_name, invite, expires_at
    FROM activities
    WHERE activity=?
    ORDER BY guild_name ASC
    """, (activity,)).fetchall()

    conn.close()

    return rows


def search_server(name):

    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    row = cur.execute("""
    SELECT guild_name, invite
    FROM activities
    WHERE LOWER(guild_name) LIKE LOWER(?)
    LIMIT 1
    """, (f"%{name}%",)).fetchone()

    conn.close()

    return row


#########################
# PREMIUM
#########################

def is_premium(guild_id):

    if not os.path.exists("war_premium.txt"):
        return False

    with open("war_premium.txt", "r") as f:
        lines = f.readlines()

    return any(
        str(guild_id) == line.strip()
        for line in lines
    )


#########################
# INVITE CREATION
#########################

async def create_server_invite(guild):

    try:

        channel = next(
            (
                c for c in guild.text_channels
                if c.permissions_for(
                    guild.me
                ).create_instant_invite
            ),
            None
        )

        if not channel:
            return None

        invite = await channel.create_invite(
            max_age=0,
            max_uses=0,
            reason="Townhall activity"
        )

        return invite.url

    except:
        return None


#########################
# CLEANUP LOOP
#########################

@tasks.loop(minutes=1)
async def cleanup_activity_loop():

    conn = sqlite3.connect(DB)
    cur = conn.cursor()

    now = int(
        datetime.now(
            timezone.utc
        ).timestamp()
    )

    cur.execute("""
    DELETE FROM activities
    WHERE expires_at <= ?
    """, (now,))

    conn.commit()
    conn.close()


