class DurationModal(discord.ui.Modal):

    def __init__(self, activity, parent_view):

        super().__init__(
            title=f"{activity} Duration"
        )

        self.activity = activity
        self.parent_view = parent_view

        self.hours = discord.ui.TextInput(
            label="Duration (hours)",
            placeholder="1",
            required=True
        )

        self.add_item(self.hours)

    async def on_submit(
        self,
        interaction: discord.Interaction
    ):

        hours = int(self.hours.value)

        premium = is_premium(
            interaction.guild.id
        )

        limit = 6 if premium else 1

        if hours < 1 or hours > limit:

            return await interaction.response.send_message(
                f"Allowed: 1-{limit} hours.",
                ephemeral=True
            )

        expires = datetime.now(
            timezone.utc
        ) + timedelta(hours=hours)

        invite = await create_server_invite(
            interaction.guild
        )

        save_activity(
            interaction.guild.id,
            interaction.guild.name,
            self.activity,
            int(expires.timestamp()),
            invite
        )

        log_update(
            interaction.guild.name,
            self.activity,
            "started"
        )

        await interaction.response.edit_message(
            view=TownhallView()
        )


#########################
# TOGGLE BUTTON
#########################

class ActivityToggleButton(
    discord.ui.Button
):

    def __init__(self, activity):

        super().__init__(
            label="ON/OFF",
            style=discord.ButtonStyle.primary
        )

        self.activity = activity

    async def callback(
        self,
        interaction: discord.Interaction
    ):

        if not interaction.user.guild_permissions.mention_everyone:

            return await interaction.response.send_message(
                "Need Mention Everyone permission.",
                ephemeral=True
            )

        conn = sqlite3.connect(DB)
        cur = conn.cursor()

        existing = cur.execute("""
        SELECT 1
        FROM activities
        WHERE guild_id=? AND activity=?
        """,
        (
            interaction.guild.id,
            self.activity
        )).fetchone()

        conn.close()

        if existing:

            remove_activity(
                interaction.guild.id,
                self.activity
            )

            log_update(
                interaction.guild.name,
                self.activity,
                "ended"
            )

            return await interaction.response.edit_message(
                view=TownhallView()
            )

        await interaction.response.send_modal(
            DurationModal(
                self.activity,
                self.view
            )
        )

