class TownhallView(
    discord.ui.LayoutView
):

    def __init__(
        self,
        activity=None,
        page=0
    ):

        super().__init__(timeout=None)

        self.selected_activity = activity
        self.page = page

        container = discord.ui.Container(
            accent_color=0x5865F2
        )

        #################################
        # HEADER
        #################################

        container.add_item(
            discord.ui.TextDisplay(
                "# <a:Discord:1509950905557057668> Community Townhall"
            )
        )

        #################################
        # RECENT UPDATES
        #################################

        container.add_item(
            discord.ui.TextDisplay(
                "## <a:Updates:1509950495253467216> Recent Updates"
            )
        )

        container.add_item(
            discord.ui.TextDisplay(
                recent_updates()
            )
        )

        #################################
        # FIND INVITE
        #################################

        row1 = discord.ui.ActionRow()

        row1.add_item(
            FindInviteButton()
        )

        container.add_item(row1)

        #################################
        # SEARCH
        #################################

        container.add_item(
            discord.ui.TextDisplay(
                "## <:unknown:1355886105526009990> Search for Servers"
            )
        )

        row2 = discord.ui.ActionRow()

        row2.add_item(
            ActivityDropdown()
        )

        container.add_item(row2)

        #################################
        # SEARCH RESULTS
        #################################

        if activity:

            if activity == "Boss Defeat":

                results = get_boss_defeats()

            else:

                results = get_activity_servers(
                    activity
                )

            per_page = 5

            pages = max(
                1,
                math.ceil(
                    len(results) / per_page
                )
            )

            page = min(
                page,
                pages - 1
            )

            start = page * per_page
            end = start + per_page

            chunk = results[start:end]

            if chunk:

                text = []

                for i, row in enumerate(
                    chunk,
                    start=start+1
                ):

                    if activity == "Boss Defeat":

                        guild_name, action, ts = row

                        stamp = datetime.fromtimestamp(
                            ts,
                            timezone.utc
                        ).strftime("%d/%m %H:%M")

                        text.append(
                            f"{i}. {guild_name} in **{action}** ({stamp})"
                        )

                    else:

                        guild_name, invite, expires = row

                        remain = max(
                            0,
                            int(
                                (
                                    datetime.fromtimestamp(
                                        expires,
                                        timezone.utc
                                    ) -
                                    datetime.now(
                                        timezone.utc
                                    )
                                ).total_seconds() // 60
                            )
                        )

                        text.append(
                            f"{i}. **{guild_name}** ({remain}m left)"
                        )

                container.add_item(
                    discord.ui.TextDisplay(
                        "\n".join(text)
                    )
                )

            else:

                container.add_item(
                    discord.ui.TextDisplay(
                        "No active servers."
                    )
                )

            nav = discord.ui.ActionRow()

            nav.add_item(
                PrevButton()
            )

            nav.add_item(
                NextButton()
            )

            container.add_item(nav)

            container.add_item(
                discord.ui.TextDisplay(
                    f"Page {page+1}/{pages}"
                )
            )

        #################################
        # TOGGLE SECTION
        #################################

        container.add_item(
            discord.ui.TextDisplay(
                "## <a:Updates:1509950495253467216> Toggle Updates for your server"
            )
        )

        for activity_name in ACTIVITIES:

            section = discord.ui.Section(
                discord.ui.TextDisplay(
                    f"### {activity_name}\nEnable/disable activity."
                ),
                accessory=ActivityToggleButton(
                    activity_name
                )
            )

            container.add_item(
                section
            )

        container.add_item(
            discord.ui.TextDisplay(
                "Activity auto-expires every hour.\n"
                "Premium servers: up to 6 hours."
            )
        )

        self.add_item(
            container
        )


