class AutoActionView(discord.ui.LayoutView):

    PER_PAGE = 3

    def __init__(self, guild_id):

        super().__init__(timeout=300)

        self.guild_id = guild_id
        self.page = 0
        self.total_actions = 0

    async def build_layout(self):

        self.clear_items()

        conn = sqlite3.connect("auto_action.db")
        conn.row_factory = sqlite3.Row

        cur = conn.cursor()

        cur.execute(
            """
            SELECT *
            FROM auto_actions
            WHERE guild_id=?
            ORDER BY id
            """,
            (self.guild_id,)
        )

        rows = cur.fetchall()
        conn.close()

        self.total_actions = len(rows)

        max_pages = max(
            1,
            math.ceil(
                self.total_actions / self.PER_PAGE
            )
        )

        start = self.page * self.PER_PAGE
        end = start + self.PER_PAGE

        page_rows = rows[start:end]

        container = discord.ui.Container()

        container.add_item(
            discord.ui.TextDisplay(
                content=f"# Auto Actions\nPage {self.page + 1}/{max_pages}"
            )
        )

        if not page_rows:

            container.add_item(
                discord.ui.TextDisplay(
                    content="No auto actions configured."
                )
            )

        else:

            dropdown_row = discord.ui.ActionRow()

            dropdown_row.add_item(
                RemoveActionDropdown(
                    self,
                    page_rows
                )
            )

            container.add_item(dropdown_row)

            for idx, row in enumerate(
                page_rows,
                start=start + 1
            ):

                target = row["target_id"]

                text = [
                    f"### Action {idx}: {row['action']}",
                    f"Target: {'All' if target is None else f'<@{target}>'}",
                    f"Trigger: {row['keyword']}",
                    f"Message Type: {row['message_type']}",
                    f"Exact: {bool(row['exact'])}"
                ]

                if row["channel_id"]:
                    text.append(
                        f"Channel: <#{row['channel_id']}>"
                    )

                container.add_item(
                    discord.ui.TextDisplay(
                        content="\n".join(text)
                    )
                )

        self.add_item(container)

        button_row = discord.ui.ActionRow()

        prev_button = PreviousPageButton2()
        next_button = NextPageButton2()

        prev_button.disabled = self.page <= 0

        next_button.disabled = (
            self.page >= max_pages - 1
        )

        button_row.add_item(prev_button)
        button_row.add_item(next_button)

        self.add_item(button_row)

    async def refresh(
        self,
        interaction: discord.Interaction
    ):

        await self.build_layout()

        await interaction.response.edit_message(
            view=self
        )

from datetime import timedelta
def extract_component_text(components):

    parts = []

    def walk(items):

        for item in items:

            # TextDisplay
            if (
                getattr(item, "type", None)
                == discord.ComponentType.text_display
            ):
                text = getattr(
                    item,
                    "content",
                    None
                )

                if text:
                    parts.append(text)

            # Recurse through children
            children = getattr(
                item,
                "children",
                None
            )

            if children:
                walk(children)

    walk(components)

    return "\n".join(parts)

def extract_embed_text(message: discord.Message) -> str:

    parts = []

    for embed in message.embeds:

        # title
        if embed.title:
            parts.append(embed.title)

        # description
        if embed.description:
            parts.append(embed.description)

        # footer
        if embed.footer and embed.footer.text:
            parts.append(embed.footer.text)

        # author
        if embed.author and embed.author.name:
            parts.append(embed.author.name)

        # fields (name + value)
        for field in embed.fields:
            if field.name:
                parts.append(field.name)
            if field.value:
                parts.append(field.value)

    return "\n".join(parts)

class ForwardButtonView(discord.ui.View):

    def __init__(self, message, target_channel_id):
        super().__init__(timeout=180)  # 3 minutes

        self.message = message
        self.target_channel_id = target_channel_id

    @discord.ui.button(
        label="Forward Message",
        style=discord.ButtonStyle.primary
    )
    async def forward_button(
        self,
        interaction: discord.Interaction,
        button: discord.ui.Button
    ):

        target_channel = interaction.guild.get_channel(
            self.target_channel_id
        )

        if not target_channel:
            await interaction.response.send_message(
                "Channel not found.",
                ephemeral=True
            )
            return

        content = ""

        if self.message.content:
            content += self.message.content

        if self.message.embeds:
            await target_channel.send(
                embeds=self.message.embeds
            )
        else:
            await target_channel.send(content)

        await interaction.response.send_message(
            "Forwarded successfully.",
            ephemeral=True
        )

        self.stop()

    async def on_timeout(self):

        for item in self.children:
            item.disabled = True

def reconstruct_component(comp: discord.Component):
    # 1. Handle Container Layouts (Type 17)
    if comp.type == discord.ComponentType.container:
        accent_color = getattr(comp, "accent_color", None)
        spoiler = getattr(comp, "spoiler", False)
        
        ui_container = discord.ui.Container(accent_color=accent_color, spoiler=spoiler)
        
        # Recursively reconstruct and append nested children
        for child in getattr(comp, "children", []):
            reconstructed_child = reconstruct_component(child)
            if reconstructed_child:
                ui_container.add_item(reconstructed_child)
        
        # GUARDRAIL: Only return the container if it successfully received children
        return ui_container if len(ui_container.children) > 0 else None

    # 2. Handle Action Rows (Type 1) - Essential for nested structures
    elif comp.type == discord.ComponentType.action_row:
        ui_row = discord.ui.ActionRow()
        for child in getattr(comp, "children", []):
            reconstructed_child = reconstruct_component(child)
            if reconstructed_child:
                ui_row.add_item(reconstructed_child)
        
        return ui_row if len(ui_row.children) > 0 else None

    # 3. Handle Interactive Elements (Buttons)
    elif comp.type == discord.ComponentType.button:
        return discord.ui.Button(
            style=comp.style,
            label=comp.label,
            emoji=comp.emoji,
            custom_id=comp.custom_id,
            url=comp.url,
            disabled=comp.disabled
        )

    # 4. Handle Select Menus
    elif comp.type in (
        discord.ComponentType.string_select,
        discord.ComponentType.user_select,
        discord.ComponentType.role_select,
        discord.ComponentType.mentionable_select,
        discord.ComponentType.channel_select
    ):
        if comp.type == discord.ComponentType.string_select:
            return discord.ui.Select(
                custom_id=comp.custom_id,
                placeholder=comp.placeholder,
                min_values=comp.min_values,
                max_values=comp.max_values,
                disabled=comp.disabled,
                options=getattr(comp, "options", [])
            )
        # Handle specialized selects
        select_klass = {
            discord.ComponentType.user_select: discord.ui.UserSelect,
            discord.ComponentType.role_select: discord.ui.RoleSelect,
            discord.ComponentType.mentionable_select: discord.ui.MentionableSelect,
        }.get(comp.type)
        
        if select_klass:
            return select_klass(custom_id=comp.custom_id, placeholder=comp.placeholder, min_values=comp.min_values, max_values=comp.max_values, disabled=comp.disabled)
        
        if comp.type == discord.ComponentType.channel_select:
            return discord.ui.ChannelSelect(custom_id=comp.custom_id, placeholder=comp.placeholder, min_values=comp.min_values, max_values=comp.max_values, disabled=comp.disabled, channel_types=getattr(comp, "channel_types", []))

    # 5. Handle Content Layouts (Text / Media)
    elif comp.type == discord.ComponentType.text_display:
        return discord.ui.TextDisplay(content=getattr(comp, "content", ""))
        
    elif comp.type == discord.ComponentType.media_gallery:
        gallery = discord.ui.MediaGallery()
        for item in getattr(comp, "items", []):
            gallery.append_item(item)
        return gallery

    return None


async def handle_auto_actions(message: discord.Message):

    if not message.guild:
        return

    actions = AUTO_ACTION_CACHE.get(
        message.guild.id,
        []
    )

    if not actions:
        return

    is_embed = bool(message.embeds)

    is_container = any(
        getattr(component, "type", None)
        in (
            discord.ComponentType.container,
            17  # fallback
        )
        for component in getattr(
            message,
            "components",
            []
        )
    )

    content_parts = []

    if message.content:
        content_parts.append(message.content)

    if is_container:
        container_text = extract_component_text(message.components)
        if container_text:
            content_parts.append(container_text)

    if is_embed:
        embed_text = extract_embed_text(message)
        if embed_text:
            content_parts.append(embed_text)

    content = "\n".join(content_parts)

    is_plain = (
        not is_embed
        and not is_container
    )

    # Reusable object to suppress mentions across all sends
    no_pings = discord.AllowedMentions.none()

    for action in actions:

        try:
            # --------------------
            # Target Check
            # --------------------
            target_id = action.get("target_id")

            if (
                target_id is not None
                and int(target_id) != message.author.id
            ):
                continue

            # --------------------
            # Message Type Check
            # --------------------
            message_type = action.get("message_type", "any")

            if message_type == "embed" and not is_embed:
                continue

            if message_type == "container" and not is_container:
                continue

            if message_type == "plain" and not is_plain:
                continue

            # --------------------
            # Keyword Check
            # --------------------
            keyword = action.get("keyword", "").strip()

            if not keyword:
                continue

            exact = bool(action.get("exact", 1))

            if exact:
                if content.lower() != keyword.lower():
                    continue
            else:
                if keyword.lower() not in content.lower():
                    continue

            action_type = action.get("action")

            # --------------------
            # Respond
            # --------------------
            if action_type == "respond":

                response_text = action.get("response_text") or "Triggered."

                await message.channel.send(
                    response_text,
                    allowed_mentions=no_pings
                )

            # --------------------
            # Forward
            # --------------------
            elif action_type == "forward":

                channel_id = action.get("channel_id")

                if not channel_id:
                    continue

                target_channel = message.guild.get_channel(channel_id)

                if not target_channel:
                    continue

                response_text = action.get("response_text")

                # -------------------------
                # CONTAINER / CV2 MESSAGE
                # -------------------------
                if is_container:

                    try:
                        view = discord.ui.LayoutView()

                        # Rebuild each top-level component back into its proper hierarchy
                        for comp in message.components:
                            view.add_item(reconstruct_component(comp))
                            
                        await target_channel.send(view=view, allowed_mentions=no_pings)

                    except Exception as e:
                        print(f"Container forward failed: {e}")

                        # fallback
                        await target_channel.send(
                            f"**Forwarded Container Message**\n\n{content}",
                            allowed_mentions=no_pings
                        )

                # -------------------------
                # EMBED MESSAGE
                # -------------------------
                elif is_embed:

                    await target_channel.send(
                        content=response_text or None,
                        embeds=message.embeds,
                        allowed_mentions=no_pings
                    )

                # -------------------------
                # NORMAL MESSAGE
                # -------------------------
                else:

                    forwarded = (
                        f"**Forwarded Message**\n"
                        f"Author: {message.author.mention}\n"
                        f"Channel: {message.channel.mention}\n"
                        f"Message ID: {message.id}\n\n"
                        f"{content}"
                    )

                    if response_text:
                        forwarded += f"\n\n{response_text}"

                    await target_channel.send(forwarded, allowed_mentions=no_pings)

            # --------------------
            # Forward Button
            # --------------------
            elif action_type == "forward_button":

                channel_id = action.get("channel_id")

                if not channel_id:
                    continue

                target_channel = message.guild.get_channel(channel_id)

                if not target_channel:
                    continue

                response_text = action.get("response_text")

                view = ForwardButtonView(message, channel_id)

                text = (
                    f"**Forward Button Triggered**\n"
                    f"Author: {message.author.mention}\n"
                    f"Channel: {message.channel.mention}\n"
                    f"Message ID: {message.id}"
                )

                if response_text:
                    text += f"\n\n{response_text}"

                await message.channel.send(
                    content=text,
                    view=view,
                    allowed_mentions=no_pings
                )

            # --------------------
            # Mute
            # --------------------
            elif action_type == "mute":

                try:
                    await message.author.edit(
                        timed_out_until=(
                            discord.utils.utcnow()
                            + timedelta(days=28)
                        ),
                        reason=f"Auto Action triggered by keyword: {keyword}"
                    )

                    await message.channel.send(
                        f"{message.author.mention} has been muted indefinitely.",
                        allowed_mentions=no_pings
                    )

                except discord.Forbidden:
                    pass

                except Exception as e:
                    print(f"Auto mute failed: {e}")

        except Exception as e:
            print(
                f"Auto action error (guild={message.guild.id}, action={action.get('id')}): {e}"
            )

