BASE_DIR = os.path.dirname(os.path.abspath(__file__))

_FONT_SEARCH = [
    os.path.join(BASE_DIR, "font", "ComicNeue-Bold.ttf"),
    os.path.join(BASE_DIR, "font", "cosmic.ttf"),
]

def _find_font(bold: bool) -> str | None:
    suffix = "-Bold" if bold else ""
    for pat in _FONT_SEARCH:
        p = pat.format(suffix)
        if os.path.exists(p):
            return p
    return None

_FONT_REG_PATH  = os.path.join(BASE_DIR, "font", "Arial.ttf")
_FONT_BOLD_PATH = os.path.join(BASE_DIR, "font", "Arial_Bold.ttf")
from functools import lru_cache
@lru_cache(maxsize=32)
def _fnt(size: int, bold: bool = False) -> ImageFont.FreeTypeFont:
    path = _FONT_BOLD_PATH if bold else _FONT_REG_PATH
    if path:
        return ImageFont.truetype(path, size)
    return ImageFont.load_default()

