@lru_cache(maxsize=4)
def _felt_bg(w: int, h: int) -> Image.Image:
    img = Image.new("RGB", (w, h))
    pix = img.load()
    inner, outer = (26, 92, 48), (10, 46, 22)
    cx, cy  = w * 0.5, h * 0.4
    max_d   = math.hypot(max(cx, w - cx), max(cy, h - cy))
    for y in range(h):
        for x in range(w):
            d = min(math.hypot(x - cx, y - cy) / max_d, 1.0)
            pix[x, y] = (
                int(inner[0] + (outer[0] - inner[0]) * d),
                int(inner[1] + (outer[1] - inner[1]) * d),
                int(inner[2] + (outer[2] - inner[2]) * d),
            )
    return img


@lru_cache(maxsize=2)
def _card_back_image(small: bool) -> Image.Image:
    W, H = (40, 56) if small else (58, 84)
    img  = Image.new("RGB", (W, H), C["card_back2"])
    pix  = img.load()
    top, bot = C["card_back1"], C["card_back2"]
    for y in range(H):
        t = y / max(H - 1, 1)
        row = (
            int(top[0] + (bot[0] - top[0]) * t),
            int(top[1] + (bot[1] - top[1]) * t),
            int(top[2] + (bot[2] - top[2]) * t),
        )
        for x in range(W):
            pix[x, y] = row
    return img

# ══════════════════════════════════════════════════════════════════════════════
#  DRAWING PRIMITIVES
# ══════════════════════════════════════════════════════════════════════════════

def _rounded_rect(draw, x, y, w, h, r, fill=None, outline=None, lw=1):
    if fill:
        draw.rounded_rectangle([x, y, x + w, y + h], radius=r, fill=fill)
    if outline:
        draw.rounded_rectangle([x, y, x + w, y + h], radius=r, outline=outline, width=lw)


def _text_center(draw, cx, cy, text, font, fill):
    bb = font.getbbox(text)
    draw.text((cx - (bb[2]-bb[0])//2 - bb[0], cy - (bb[3]-bb[1])//2 - bb[1]),
              text, font=font, fill=fill)


def _text_left(draw, x, y, text, font, fill) -> int:
    bb = font.getbbox(text)
    draw.text((x - bb[0], y - bb[1]), text, font=font, fill=fill)
    return bb[2] - bb[0]


def _text_right(draw, x, y, text, font, fill):
    bb = font.getbbox(text)
    draw.text((x - (bb[2]-bb[0]) - bb[0], y - bb[1]), text, font=font, fill=fill)


def _tsz(text, font) -> tuple[int, int]:
    bb = font.getbbox(text)
    return bb[2] - bb[0], bb[3] - bb[1]

# ══════════════════════════════════════════════════════════════════════════════
#  CARD DRAWING
# ══════════════════════════════════════════════════════════════════════════════

def _suit_color(suit: str) -> tuple:
    return C["red"] if suit in ("♥", "♦") else C["black"]


def _draw_card(img: Image.Image, x: int, y: int, rank: int, suit: str,
               small: bool = False) -> None:
    W, H   = (40, 56) if small else (58, 84)
    col    = _suit_color(suit)
    rank_s = RANK_DISPLAY.get(rank, str(rank))
    draw   = ImageDraw.Draw(img)

    draw.rounded_rectangle([x+2, y+3, x+W+2, y+H+3], radius=5, fill=(0,0,0,70))
    _rounded_rect(draw, x, y, W, H, 5, fill=C["card_bg"], outline=C["card_border"])

    if small:
        fr, fs, fc, pad = _fnt(10,True), _fnt(9), _fnt(17), 3
    else:
        fr, fs, fc, pad = _fnt(13,True), _fnt(11), _fnt(28), 4

    rw, rh = _tsz(rank_s, fr)
    _text_left(draw, x+pad, y+pad, rank_s, fr, col)
    sx = x + pad + max(0, (rw - _tsz(suit, fs)[0]) // 2)
    _text_left(draw, sx, y+pad+rh+1, suit, fs, col)
    _text_center(draw, x+W//2, y+H//2+2, suit, fc, col)
    _text_right(draw, x+W-pad, y+H-pad-rh, rank_s, fr, col)


def _draw_card_back(img: Image.Image, x: int, y: int, small: bool = False) -> None:
    W, H = (40, 56) if small else (58, 84)
    draw  = ImageDraw.Draw(img)
    draw.rounded_rectangle([x+2, y+3, x+W+2, y+H+3], radius=5, fill=(0,0,0,55))

    back  = _card_back_image(small)
    mask  = Image.new("L", (W, H), 0)
    ImageDraw.Draw(mask).rounded_rectangle([0, 0, W, H], radius=5, fill=255)
    img.paste(back, (x, y), mask)

    draw.rounded_rectangle([x, y, x+W, y+H], radius=5, outline=C["card_back1"], width=1)
    pad = max(3, W//8)
    draw.rounded_rectangle([x+pad, y+pad, x+W-pad, y+H-pad], radius=2,
                           outline=(60, 80, 160))


def _draw_card_slot(img: Image.Image, x: int, y: int, small: bool = False) -> None:
    W, H = (40, 56) if small else (58, 84)
    draw = ImageDraw.Draw(img)
    draw.rounded_rectangle([x, y, x+W, y+H], radius=5,
                           fill=None, outline=C["card_slot_b"], width=2)
    _text_center(draw, x+W//2, y+H//2, "·", _fnt(18), C["card_slot_b"])

# ══════════════════════════════════════════════════════════════════════════════
#  CHIP
# ══════════════════════════════════════════════════════════════════════════════

def _draw_chip(draw, cx, cy, r=11):
    draw.ellipse([cx-r-1, cy-r-1, cx+r+1, cy+r+1], fill=(180,130,10))
    draw.ellipse([cx-r, cy-r, cx+r, cy+r], fill=C["chip2"])
    hr = max(1, r-3)
    draw.ellipse([cx-hr, cy-hr-1, cx+hr-2, cy+hr-3], fill=C["chip1"])

# ══════════════════════════════════════════════════════════════════════════════
#  PHASE PILLS
# ══════════════════════════════════════════════════════════════════════════════

def _draw_pills(img: Image.Image, cx: int, y: int, phase_step: int) -> int:
    draw   = ImageDraw.Draw(img)
    labels = ["ANTE", "PRE-FLOP", "FLOP", "SHOWDOWN"]
    f      = _fnt(9, True)
    GAP    = 7; PX, PY = 12, 4
    widths = [_tsz(l, f)[0] + PX*2 for l in labels]
    total  = sum(widths) + GAP*(len(labels)-1)
    x0     = cx - total//2
    ph     = _tsz("ANTE", f)[1] + PY*2

    x = x0
    for i, (lbl, w) in enumerate(zip(labels, widths)):
        if   i < phase_step:  bg,bd,tx = C["pill_done_bg"],   C["pill_done_bd"],   C["pill_done_tx"]
        elif i == phase_step: bg,bd,tx = C["pill_active_bg"], C["pill_active_bg"], C["pill_active_tx"]
        else:                 bg,bd,tx = None,                C["pill_inact_bd"],  C["pill_inact_tx"]
        if bg:
            _rounded_rect(draw, x, y, w, ph, 6, fill=bg)
        _rounded_rect(draw, x, y, w, ph, 6, outline=bd)
        _text_center(draw, x+w//2, y+ph//2, lbl, f, tx)
        x += w + GAP
    return y + ph

# ══════════════════════════════════════════════════════════════════════════════
#  BADGE
# ══════════════════════════════════════════════════════════════════════════════

def _draw_badge(draw, rx, cy, tag, key):
    f      = _fnt(9, True)
    bg, tx = C["badge_" + key]
    PX, PY = 8, 3
    tw, th = _tsz(tag, f)
    bw, bh = tw + PX*2, th + PY*2
    bx, by = rx - bw, cy - bh//2
    _rounded_rect(draw, bx, by, bw, bh, 4, fill=bg)
    _text_center(draw, bx+bw//2, by+bh//2, tag, f, tx)

# ══════════════════════════════════════════════════════════════════════════════
#  PLAYER PANEL
# ══════════════════════════════════════════════════════════════════════════════

_PMETA = {
    "waiting": ("panel_waiting_bg", "panel_waiting_bd", "wait",  "WAIT"),
    "called":  ("panel_called_bg",  "panel_called_bd",  "call",  "CALL"),
    "folded":  ("panel_folded_bg",  "panel_folded_bd",  "fold",  "FOLD"),
    "dealer":  ("panel_dealer_bg",  "panel_dealer_bd",  "deal",  "DEAL"),
    "winner":  ("panel_winner_bg",  "panel_winner_bd",  "win",   "WIN!"),
    "empty":   ("panel_empty_bg",   "panel_empty_bd",   "empty", "----"),
}


def _draw_player_panel(img, x, y, w, h, player: dict) -> None:
    draw      = ImageDraw.Draw(img)
    state     = player.get("state", "waiting")
    name      = player.get("name", "")[:16]
    hand      = player.get("hand", [])
    bet       = player.get("bet")
    show_hand = player.get("show_hand", False)
    is_you    = player.get("is_you", False)
    hand_name = player.get("hand_name", "")

    bg_k, bd_k, badge_k, badge_tag = _PMETA.get(state, _PMETA["empty"])

    if state == "folded":
        tmp  = Image.new("RGBA", (w, h), (0,0,0,0))
        ImageDraw.Draw(tmp).rounded_rectangle([0,0,w,h], radius=10,
                                              fill=(*C[bg_k], 140))
        img.paste(Image.new("RGB",(w,h),C[bg_k]), (x,y), tmp.split()[3])
    else:
        _rounded_rect(draw, x, y, w, h, 10, fill=C[bg_k])

    _rounded_rect(draw, x, y, w, h, 10, outline=C[bd_k],
                  lw=2 if state in ("waiting","winner") else 1)

    IP = 8
    CX, CY = x+IP, y+IP
    f_name = _fnt(11, True)
    nw = _text_left(draw, CX, CY, name, f_name, C["gold"] if is_you else C["green_text"])
    if is_you:
        _text_left(draw, CX+nw+3, CY+1, "(you)", _fnt(9), C["gold"])
    _draw_badge(draw, x+w-IP, CY+_tsz(name,f_name)[1]//2, badge_tag, badge_k)

    ROW2 = CY + _tsz(name, f_name)[1] + 7
    CW, CH, GAP = 40, 56, 4

    if state == "empty":
        _draw_card_slot(img, CX, ROW2, small=True)
        _draw_card_slot(img, CX+CW+GAP, ROW2, small=True)
    elif hand and (show_hand or state == "winner"):
        for i,(r,s) in enumerate(hand[:2]):
            _draw_card(img, CX+i*(CW+GAP), ROW2, r, s, small=True)
    elif hand:
        for i in range(min(2, len(hand))):
            _draw_card_back(img, CX+i*(CW+GAP), ROW2, small=True)
    else:
        n = 3 if state == "dealer" else 2
        for i in range(n):
            _draw_card_back(img, CX+i*(CW+GAP), ROW2, small=True)

    info_x = CX + 2*(CW+GAP) + 3
    info_y = ROW2 + 2
    draw   = ImageDraw.Draw(img)

    if bet is not None:
        if bet == 0:
            _text_left(draw, info_x, info_y+8, "FREE", _fnt(10,True), C["teal"])
        else:
            _draw_chip(draw, info_x+8, info_y+9, r=8)
            _text_left(draw, info_x+19, info_y+1,  str(bet), _fnt(12,True), C["gold"])
            _text_left(draw, info_x+19, info_y+15, "ARCs",   _fnt(9),       C["teal"])

    if hand_name:
        hn_y = info_y + (28 if (bet is not None and bet > 0) else 10)
        _text_left(draw, info_x, hn_y, hand_name, _fnt(9), C["win_green"])

# ══════════════════════════════════════════════════════════════════════════════
#  COMMUNITY BOARD
# ══════════════════════════════════════════════════════════════════════════════

def _draw_board(img, cx, y, community) -> int:
    draw = ImageDraw.Draw(img)
    f    = _fnt(9)
    lbl  = "COMMUNITY CARDS"
    _text_center(draw, cx, y, lbl, f, C["green_dim"])
    y += _tsz(lbl, f)[1] + 9

    CW, GAP = 58, 10
    total   = 5*CW + 4*GAP
    sx      = cx - total//2
    for i in range(5):
        cx_c = sx + i*(CW+GAP)
        if i < len(community):
            _draw_card(img, cx_c, y, community[i][0], community[i][1])
        else:
            _draw_card_slot(img, cx_c, y)
    return y + 84

# ══════════════════════════════════════════════════════════════════════════════
#  POT BAR
# ══════════════════════════════════════════════════════════════════════════════

def _draw_pot_bar(draw, cx, cy, pot):
    for dx,dy in [(0,0),(-4,-3),(-8,-6)]:
        _draw_chip(draw, cx-60+dx, cy+dy, r=11)
    x  = cx - 38
    lw = _text_left(draw, x, cy-7, "Pot", _fnt(10), C["teal"])
    pot_str = str(pot) if pot > 0 else "FREE"
    vw = _text_left(draw, x+lw+8, cy-14, pot_str, _fnt(22,True), C["gold"])
    if pot > 0:
        _text_left(draw, x+lw+8+vw+5, cy-4, "ARCs", _fnt(11), C["teal"])

# ══════════════════════════════════════════════════════════════════════════════
#  MAIN RENDER
# ══════════════════════════════════════════════════════════════════════════════

def _grid_layout(n_players: int) -> tuple[int, int, int, int]:
    if n_players <= 6:
        return 3, 200, 100, 10
    elif n_players <= 8:
        return 4, 162, 100, 8
    else:
        return 5, 128, 100, 7


def _build_table_image(
    mode: str,
    pot: int,
    status: str,
    community: list,
    players: list,
    phase_step: int,
) -> Image.Image:
    W = 720
    PAD, IP = 20, 18

    players = players[:20]
    n = max(len(players), 1)
    COLS, PANEL_W, PANEL_H, PANEL_GAP = _grid_layout(n)
    grid_rows = math.ceil(n / COLS)
    grid_h    = grid_rows * PANEL_H + (grid_rows-1) * PANEL_GAP

    total_h = (PAD + 16 + 40 + 6 + 28 + 40 + 32 + 14
               + 24 + 84 + 14 + 14 + grid_h + 24 + PAD)

    img  = _felt_bg(W, total_h).copy()
    draw = ImageDraw.Draw(img)

    draw.rounded_rectangle([0, 0, W, total_h], radius=22,
                           outline=C["frame_outer"], width=3)
    draw.rounded_rectangle([10, 10, W-10, total_h-10], radius=14,
                           outline=C["frame_inner"], width=1)

    cx  = W // 2
    cur = PAD + 16

    _text_left (draw, PAD+IP, cur+6,    "♠♥", _fnt(22,True), C["gold"])
    _text_right(draw, W-PAD-IP, cur+6,  "♦♣", _fnt(22,True), C["gold"])
    _text_center(draw, cx, cur+4, "POKER TABLE", _fnt(18,True), C["gold"])

    mode_lbl = "MULTIPLAYER" if mode == "Multiplayer" else "SOLO"
    f_m      = _fnt(9, True)
    mw, mh   = _tsz(mode_lbl, f_m)
    bw, bh   = mw+18, mh+6
    bx, by   = cx-bw//2, cur+26
    _rounded_rect(draw, bx, by, bw, bh, 4, fill=(106,78,16), outline=(160,120,32))
    _text_center(draw, cx, by+bh//2, mode_lbl, f_m, C["gold"])
    cur += 40 + 6

    cur = _draw_pills(img, cx, cur, phase_step) + 10
    draw = ImageDraw.Draw(img)

    _draw_pot_bar(draw, cx, cur+14, pot)
    cur += 40

    f_st = _fnt(12)
    s_t  = status[:80]
    sw, sh = _tsz(s_t, f_st)
    sb_x, sb_w = PAD+IP, W-2*(PAD+IP)
    sb_h = sh + 12
    _rounded_rect(draw, sb_x, cur, sb_w, sb_h, 7,
                  fill=C["status_bg"], outline=C["status_bd"])
    _text_center(draw, cx, cur+sb_h//2, s_t, f_st, C["green_text"])
    cur += sb_h + 14

    cur = _draw_board(img, cx, cur, community) + 14
    draw = ImageDraw.Draw(img)

    dw = W - 2*(PAD+IP)
    div_img = Image.new("RGBA", (dw, 1), (0,0,0,0))
    div_pix = div_img.load()
    for dx in range(dw):
        t     = dx / max(dw-1, 1)
        alpha = int(255 * 4 * t * (1-t))
        div_pix[dx, 0] = (*C["divider"], alpha)
    div_rgb  = Image.new("RGB", (dw, 1), C["divider"])
    img.paste(div_rgb, (PAD+IP, cur), div_img.split()[3])
    cur += 14

    gtw = COLS * PANEL_W + (COLS-1) * PANEL_GAP
    gx0 = cx - gtw // 2
    for i, p in enumerate(players):
        col = i % COLS
        row = i // COLS
        px  = gx0 + col*(PANEL_W+PANEL_GAP)
        py  = cur + row*(PANEL_H+PANEL_GAP)
        _draw_player_panel(img, px, py, PANEL_W, PANEL_H, p)

    return img

# ══════════════════════════════════════════════════════════════════════════════
#  PUBLIC RENDER API
# ══════════════════════════════════════════════════════════════════════════════

async def poker_browser_start():
    pass

async def poker_browser_stop():
    pass


async def _render_table_bytes(
    mode: str, pot: int, status: str,
    community: list, players: list, phase_step: int,
) -> io.BytesIO:
    img = _build_table_image(mode, pot, status, community, players, phase_step)
    buf = io.BytesIO()
    img.save(buf, format="PNG", optimize=True)
    buf.seek(0)
    return buf

# ══════════════════════════════════════════════════════════════════════════════
#  CARD / DECK LOGIC
# ══════════════════════════════════════════════════════════════════════════════

def _poker_rank_value(rank: str) -> int:
    return "23456789TJQKA".index(rank) + 2


def _poker_deck() -> list[tuple[int, str]]:
    suits = ["♠", "♥", "♦", "♣"]
    deck  = [(_poker_rank_value(r), s) for r in "23456789TJQKA" for s in suits]
    random.shuffle(deck)
    return deck


def _straight_high(ranks):
    unique = sorted(set(ranks), reverse=True)
    if 14 in unique:
        unique.append(1)
    for i in range(len(unique)-4):
        start = unique[i]
        if all(start-j in unique for j in range(5)):
            return start
    return None


def _evaluate_hand(cards):
    ranks       = [c[0] for c in cards]
    suits       = [c[1] for c in cards]
    rc          = Counter(ranks)
    sc          = Counter(suits)
    flush_suit  = next((s for s,c in sc.items() if c >= 5), None)

    if flush_suit:
        fr = sorted([r for r,s in cards if s == flush_suit], reverse=True)
        sf = _straight_high(fr)
        if sf: return 8, [sf]

    four = [r for r,c in rc.items() if c == 4]
    if four:
        f = max(four)
        return 7, [f, max(r for r in ranks if r != f)]

    trips = sorted([r for r,c in rc.items() if c == 3], reverse=True)
    pairs = sorted([r for r,c in rc.items() if c == 2], reverse=True)
    if trips and (pairs or len(trips) > 1):
        return 6, [trips[0], pairs[0] if pairs else trips[1]]
    if flush_suit:
        return 5, sorted([r for r,s in cards if s == flush_suit], reverse=True)[:5]

    sh = _straight_high(ranks)
    if sh: return 4, [sh]
    if trips:
        t = trips[0]
        return 3, [t] + sorted([r for r in ranks if r != t], reverse=True)[:2]
    if len(pairs) >= 2:
        hp, lp = pairs[0], pairs[1]
        return 2, [hp, lp, max(r for r in ranks if r not in (hp, lp))]
    if pairs:
        p = pairs[0]
        return 1, [p] + sorted([r for r in ranks if r != p], reverse=True)[:3]
    return 0, sorted(ranks, reverse=True)[:5]


def _best_player_score(game, player):
    if player.is_dealer and not game.multiplayer and player.dealer_hand:
        return _evaluate_hand(player.dealer_hand + game.community)
    return _evaluate_hand(player.hand + game.community)


def _hand_name(score) -> str:
    return HAND_NAMES[score[0]] if 0 <= score[0] < len(HAND_NAMES) else "?"

# ══════════════════════════════════════════════════════════════════════════════
#  DATA CLASSES
# ══════════════════════════════════════════════════════════════════════════════

class PokerPlayer:
    def __init__(self, user_id: int, is_dealer: bool = False):
        self.user_id:    int                    = user_id
        self.is_dealer:  bool                   = is_dealer
        self.hand:       list[tuple[int, str]]  = []
        self.dealer_hand: list[tuple[int, str]] = []
        self.folded:     bool                   = False
        self.bet:        int | None             = None


class PokerGame:
    def __init__(self, owner_id: int, channel_id: int, multiplayer: bool):
        self.owner_id:    int                    = owner_id
        self.channel_id:  int                    = channel_id
        self.multiplayer: bool                   = multiplayer
        self.started:     bool                   = False
        self.ended:       bool                   = False
        self.message_id:  int | None             = None
        self.players:     dict[int, PokerPlayer] = {}
        self.deck:        list[tuple[int, str]]  = []
        self.community:   list[tuple[int, str]]  = []
        self.pending:     set[int]               = set()
        self.status_text: str                    = "Waiting for players."
        self.pot:         int                    = 0
        self.raise_used:  bool                   = False
        self.host_bet:    int | None             = None
        self.timeout_task: asyncio.Task | None   = None
        self.free_mode = False

    def active_player_ids(self) -> list[int]:
        return [pid for pid, p in self.players.items()
                if not p.folded and not p.is_dealer]

    def active_dealer_ids(self) -> list[int]:
        return [pid for pid, p in self.players.items()
                if not p.folded and p.is_dealer]

    def player_state(self, user_id: int) -> PokerPlayer | None:
        return self.players.get(user_id)

    def start(self):
        self.deck = _poker_deck()
        for player in self.players.values():
            if player.is_dealer and not self.multiplayer:
                player.dealer_hand = [self.deck.pop(), self.deck.pop()]
                player.hand        = player.dealer_hand
            else:
                player.hand = [self.deck.pop(), self.deck.pop()]
        self.started     = True
        self.status_text = "Game started. Call, Raise, or Fold."
        self.pending     = set(self.active_player_ids())
        self.raise_used  = False

    def phase_step(self) -> int:
            if not self.started: return 0
            c = len(self.community)
            if c == 0: return 1  # Pre-flop
            if c == 3: return 2  # Flop
            if c == 4: return 3  # Turn
            return 4             # River (c == 5)

    def reveal_next_card(self):
        if len(self.community) == 0 and self.deck:
            # Pre-flop -> Flop (Deal 3 cards)
            self.community.append(self.deck.pop())
            self.community.append(self.deck.pop())
            self.community.append(self.deck.pop())
            self.status_text = "The Flop is dealt! 3 community cards revealed."
        elif len(self.community) == 3 and self.deck:
            # Flop -> Turn (Deal 1 card)
            self.community.append(self.deck.pop())
            self.status_text = "The Turn is dealt! 4 community cards revealed."
        elif len(self.community) == 4 and self.deck:
            # Turn -> River (Deal 1 card)
            self.community.append(self.deck.pop())
            self.status_text = "The River is dealt! Final community card revealed."

    def resolve_showdown(self) -> tuple[list[int], str]:
        active = [p for p in self.players.values() if not p.folded]
        if len(active) == 1:
            w = active[0]
            return [w.user_id], (DEALER_NAMES.get(w.user_id, str(w.user_id))) + " wins."
        best, winners = None, []
        for p in active:
            sc = _best_player_score(self, p)
            if best is None or sc > best:
                best, winners = sc, [p.user_id]
            elif sc == best:
                winners.append(p.user_id)
        return winners, "Showdown resolved."

# ══════════════════════════════════════════════════════════════════════════════
#  GAME → RENDER HELPERS
# ══════════════════════════════════════════════════════════════════════════════

async def _player_name(guild: discord.Guild | None, user_id: int, is_dealer: bool) -> str:
    if is_dealer:
        return DEALER_NAMES.get(user_id, "Dealer")
    if guild:
        member = guild.get_member(user_id)
        if member is None:
            try:
                member = await guild.fetch_member(user_id)
            except discord.NotFound:
                return str(user_id)

        return member.display_name
    return str(user_id)


def _resolve_winners(game: "PokerGame") -> set[int]:
    if not game.ended: return set()
    active = [p for p in game.players.values() if not p.folded]
    if not active: return set()
    best, w_ids = None, []
    for p in active:
        sc = _best_player_score(game, p)
        if best is None or sc > best: best, w_ids = sc, [p.user_id]
        elif sc == best: w_ids.append(p.user_id)
    return set(w_ids)


async def _game_to_render_kwargs(
    game: "PokerGame",
    guild: discord.Guild | None,
    viewer_id: int | None = None,
) -> dict:
    winners_set  = _resolve_winners(game)
    player_dicts = []

    for pid, p in game.players.items():
        name = await _player_name(guild, pid, p.is_dealer)

        if p.folded:               state = "folded"
        elif p.is_dealer:          state = "dealer"
        elif pid in game.pending:  state = "waiting"
        else:                      state = "called"
        if game.ended and pid in winners_set:
            state = "winner"

        show    = game.ended or (viewer_id is not None and pid == viewer_id)
        hand_nm = ""
        if game.ended and p.hand and not p.is_dealer:
            hand_nm = _hand_name(_best_player_score(game, p))

        player_dicts.append({
            "name":      name,
            "state":     state,
            "hand":      p.hand,
            "bet":       p.bet,
            "show_hand": show,
            "is_you":    pid == viewer_id,
            "hand_name": hand_nm,
        })

    return dict(
        mode       = "Multiplayer" if game.multiplayer else "Solo",
        pot        = game.pot,
        status     = game.status_text,
        community  = game.community,
        players    = player_dicts,
        phase_step = game.phase_step(),
    )


async def _build_poker_file(
    game: "PokerGame",
    guild: discord.Guild | None,
    viewer_id: int | None = None,
) -> discord.File:
    kwargs = await _game_to_render_kwargs(game, guild, viewer_id)
    buf    = await _render_table_bytes(**kwargs)
    return discord.File(buf, filename="poker_table.png")

# ══════════════════════════════════════════════════════════════════════════════
#  MESSAGE SENDING  (components v2 — Container + MediaGallery)
# ══════════════════════════════════════════════════════════════════════════════
async def _poker_update_message(bot, game, guild=None):
    channel = bot.get_channel(game.channel_id)
    if not channel:
        return

    if game.message_id:
        try:
            old = await channel.fetch_message(game.message_id)
            await old.delete()
        except Exception:
            pass

    kwargs = await _game_to_render_kwargs(game, guild)
    buf = await _render_table_bytes(**kwargs)

    file = discord.File(buf, filename="poker_table.png")
    view = PokerView(game)

    msg = await channel.send(
        file=file,
        view=view
    )

    game.message_id = msg.id

async def _poker_send_hands(bot, guild: discord.Guild | None,
                            game: "PokerGame") -> None:
    for pid, player in game.players.items():
        if player.is_dealer: continue
        user = bot.get_user(pid) or (guild.get_member(pid) if guild else None)
        if not user: continue
        try:
            f = await _build_poker_file(game, guild, viewer_id=pid)
            await user.send("🃏 **Your private hand — good luck!**", file=f)
        except Exception:
            pass

# ══════════════════════════════════════════════════════════════════════════════
#  BUTTONS
# ══════════════════════════════════════════════════════════════════════════════

class PokerJoinButton(discord.ui.Button):
    def __init__(self, game):
        super().__init__(label="Join", style=discord.ButtonStyle.success)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        g = self.game
        if g.started or g.ended:
            return await interaction.response.send_message("Game already started.", ephemeral=True)
        if interaction.user.id in g.players:
            return await interaction.response.send_message("You already joined.", ephemeral=True)
        if len([p for p in g.players.values() if not p.is_dealer]) >= POKER_MAX_PLAYERS:
            return await interaction.response.send_message("Table is full.", ephemeral=True)
        if g.host_bet is None:
            return await interaction.response.send_message("Host bet not set.", ephemeral=True)
        if not _poker_can_pay(interaction.user.id, g.host_bet):
            return await interaction.response.send_message("Not enough ARCs to join.", ephemeral=True)

        p = PokerPlayer(interaction.user.id)
        p.bet = max(g.host_bet, 1)
        p.real_bet = g.host_bet
        g.players[interaction.user.id] = p
        name = await _player_name(interaction.guild, interaction.user.id, False)
        g.status_text = (
            f"{name} joined.")
        await interaction.response.defer()
        await _poker_update_message(interaction.client, g, interaction.guild)


class PokerStartButton(discord.ui.Button):
    def __init__(self, game):
        super().__init__(label="Start", style=discord.ButtonStyle.primary)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        await interaction.response.defer()
        g = self.game
        if interaction.user.id != g.owner_id:
            return await interaction.followup.send("Only the host can start.", ephemeral=True)
        if g.started or g.ended:
            return await interaction.followup.send("Already started.", ephemeral=True)
        if len([p for p in g.players.values() if not p.is_dealer]) < 2:
            return await interaction.followup.send("Need at least 2 players.", ephemeral=True)

        # FIX: Check p.real_bet instead of p.bet so 0-ARC bets don't trigger this
        insufficient = [
            pid for pid, p in g.players.items()
            if not p.is_dealer and p.real_bet > 0 and not _poker_can_pay(pid, p.real_bet)
        ]
        if insufficient:
            names = []
            for pid in insufficient:
                name = await _player_name(interaction.guild, pid, False)
                names.append(name)
            return await interaction.followup.send(
                f"Not enough ARCs for: {', '.join(names)}", ephemeral=True)

        g.start()
        if g.timeout_task:
            g.timeout_task.cancel()
            g.timeout_task = None

        await _poker_send_hands(interaction.client, interaction.guild, g)
        await _poker_update_message(interaction.client, g, interaction.guild)


class PokerCallButton(discord.ui.Button):
    def __init__(self, game):
        super().__init__(label="Call", style=discord.ButtonStyle.success)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        g = self.game
        p = g.player_state(interaction.user.id)
        if not g.started or g.ended or not p or p.folded or p.is_dealer:
            return await interaction.response.send_message("You can't act right now.", ephemeral=True)
        if interaction.user.id not in g.pending:
            return await interaction.response.send_message("You already acted.", ephemeral=True)
        if p.bet is None:
            return await interaction.response.send_message("No bet set.", ephemeral=True)
            
        # FIX: Validate using p.real_bet so free play passes seamlessly
        if p.real_bet > 0 and not _poker_can_pay(interaction.user.id, p.real_bet):
            await interaction.response.defer()
            p.folded = True
            g.pending.discard(interaction.user.id)
            await _poker_advance_round(interaction.client, g, interaction.guild)
            return

        await interaction.response.defer()
        # FIX: Only deduct if there is an active currency stake
        if p.real_bet > 0:
            modify_coins(interaction.user.id, -p.real_bet)
            
        g.pot += p.bet  # Keeps adding the fake chip (1) to the pot tracker
        g.pending.discard(interaction.user.id)
        await _poker_advance_round(interaction.client, g, interaction.guild)


class PokerRaiseButton(discord.ui.Button):
    def __init__(self, game):
        super().__init__(label="Raise ↑", style=discord.ButtonStyle.primary)
        self.game = game

    async def callback(self, interaction: discord.Interaction):
        g = self.game
        p = g.player_state(interaction.user.id)
        if not g.started or g.ended or not p or p.folded or p.is_dealer:
            return await interaction.response.send_message("You can't act right now.", ephemeral=True)
        if interaction.user.id not in g.pending:
            return await interaction.response.send_message("You already acted.", ephemeral=True)
        if g.raise_used:
            return await interaction.response.send_message("Raise already used this round.", ephemeral=True)
        if p.bet is None:
            return await interaction.response.send_message("No bet set.", ephemeral=True)

        double_bet = p.bet * 2
        double_real_bet = p.real_bet * 2
        
        # FIX: Skip payment validation if the game is free mode
        if not g.free_mode and not _poker_can_pay(interaction.user.id, double_real_bet):
            return await interaction.response.send_message("Not enough ARCs to raise.", ephemeral=True)

        await interaction.response.defer()
        
        # FIX: Only deduct real coins if not in free mode
        if not g.free_mode and double_real_bet > 0:
            modify_coins(interaction.user.id, -double_real_bet)
            
        g.pot        += double_bet  # Increment pot by fake chip values
        g.raise_used  = True
        g.pending.discard(interaction.user.id)
        g.pending      = set(g.active_player_ids()) - {interaction.user.id}
        await _poker_advance_round(interaction.client, g, interaction.guild)

class PokerFoldButton(discord.ui.Button):

    def __init__(self, game):

        super().__init__(label="Fold", style=discord.ButtonStyle.danger)

        self.game = game



    async def callback(self, interaction: discord.Interaction):

        g = self.game

        p = g.player_state(interaction.user.id)

        if not g.started or g.ended or not p or p.folded or p.is_dealer:

            return await interaction.response.send_message("You can't act right now.", ephemeral=True)

        if interaction.user.id not in g.pending:

            return await interaction.response.send_message("You already acted.", ephemeral=True)



        # FIX: defer BEFORE modifying state and doing async work

        await interaction.response.defer()

        p.folded = True

        g.pending.discard(interaction.user.id)

        await _poker_advance_round(interaction.client, g, interaction.guild)
