#  BALANCE HELPERS
# ══════════════════════════════════════════════════════════════════════════════

def _poker_get_balance(user_id: int) -> int:
    conn = connect_poke_db()
    ensure_player(conn, user_id)
    c = conn.cursor()
    c.execute("SELECT coins FROM poke WHERE player_id = ?", (user_id,))
    row = c.fetchone()
    conn.close()
    return row[0] if row and row[0] is not None else 0


def _poker_can_pay(user_id: int, amount: int) -> bool:
    if amount == 0: return True
    return _poker_get_balance(user_id) >= amount

# ══════════════════════════════════════════════════════════════════════════════
#  BET PROMPT
# ══════════════════════════════════════════════════════════════════════════════

async def _poker_prompt_bet(ctx, initial_amount: int | None = None) -> int | None:
    if initial_amount is not None:
        if 0 <= initial_amount <= 50:
            return initial_amount
        await ctx.send("Bet must be between 0 and 50.")
        return None

    await ctx.send("How much do you want to bet? (0–50, 0 = free play)")

    def check(m: discord.Message):
        return m.author.id == ctx.author.id and m.channel.id == ctx.channel.id

    try:
        reply = await ctx.bot.wait_for("message", timeout=30.0, check=check)
    except asyncio.TimeoutError:
        await ctx.send("Bet prompt timed out.")
        return None

    try:
        amount = int(str(reply.content).strip())
    except Exception:
        await ctx.send("Invalid bet amount.")
        return None

    if not 0 <= amount <= 50:
        await ctx.send("Bet must be between 0 and 50.")
        return None
    return amount

# ══════════════════════════════════════════════════════════════════════════════
#  TIMEOUT
# ══════════════════════════════════════════════════════════════════════════════

async def _poker_timeout_if_not_started(bot, game: "PokerGame", delay: int = 180):
    try:
        await asyncio.sleep(delay)
    except asyncio.CancelledError:
        return
    if not game.started and not game.ended:
        game.ended       = True
        game.status_text = "No one joined in time. Game expired."
        ongoing_poker.pop(game.channel_id, None)
        await _poker_update_message(bot, game)

# ══════════════════════════════════════════════════════════════════════════════
#  ROUND ADVANCEMENT
# ══════════════════════════════════════════════════════════════════════════════

async def _poker_advance_round(bot, game: "PokerGame", guild: discord.Guild | None):
    active_nd  = game.active_player_ids()   # non-folded humans
    active_all = [pid for pid, p in game.players.items() if not p.folded]

    # Handle early fold defaults
    if (game.multiplayer     and len(active_nd)  <= 1) or \
       (not game.multiplayer and (len(active_all) <= 1 or len(active_nd) == 0)):

        game.ended = True
        winners    = active_nd or active_all
        if winners:
            wid    = winners[0]
            wp     = game.players[wid]
            wname  = await _player_name(guild, wid, wp.is_dealer)
            payout = 0
            
            if game.pot > 0 and not game.free_mode:
                payout = game.pot * 2 if (not game.multiplayer and not wp.is_dealer) else game.pot
                if not wp.is_dealer:
                    modify_coins(wid, payout)
            
            pot_txt = f" · payout {payout} ARCs" if (game.pot > 0 and not game.free_mode) else " (free game)"
            game.status_text = f"{wname} wins by default{pot_txt}"
        else:
            game.status_text = "No winners."
        await _poker_update_message(bot, game, guild)
        return

    # Still waiting on players to finish acting in the current street
    if game.pending:
        await _poker_update_message(bot, game, guild)
        return

    # CHANGE HERE: Advance through streets until 5 community cards are revealed
    if len(game.community) < 5:
        game.reveal_next_card()
        game.pending    = set(game.active_player_ids())
        game.raise_used = False   # Reset the raise usage for the new street
        await _poker_update_message(bot, game, guild)
        return

    # Showdown execution (Runs only after the River action is complete)
    game.ended = True
    winners, _ = game.resolve_showdown()
    if winners:
        payout = 0
        
        if game.pot > 0 and not game.free_mode:
            if not game.multiplayer:
                nd = [pid for pid in winners if not game.players[pid].is_dealer]
                if nd:
                    payout = game.pot * 2
                    modify_coins(nd[0], payout)
            else:
                base      = game.pot // len(winners)
                remainder = game.pot - base * len(winners)
                for i, pid in enumerate(winners):
                    modify_coins(pid, base + (remainder if i == 0 else 0))
                payout = base

        hand_parts = []
        for pid in winners:
            p = game.players[pid]
            if not p.is_dealer:
                sc = _best_player_score(game, p)
                name = await _player_name(guild, pid, False)
                hand_parts.append(f"{name} ({_hand_name(sc)})")
            else:
                hand_parts.append(DEALER_NAMES.get(pid, "Dealer"))

        pot_txt = f" · payout {payout} ARCs" if (game.pot > 0 and not game.free_mode) else " (free game)"
        game.status_text = f"Winner: {', '.join(hand_parts)}{pot_txt}"
    else:
        game.status_text = "No winners."

    await _poker_update_message(bot, game, guild)

