#  COMMAND
# ══════════════════════════════════════════════════════════════════════════════

@bot.command(name="poker", aliases=["pk"])
async def poker(ctx, mode: str = None, amount: int | None = None):
    """
    !poker             — multiplayer (prompts bet, 0 = free)
    !poker 20          — multiplayer, bet 20
    !poker 0           — multiplayer, free play
    !poker solo        — solo vs 3 AI dealers (prompts bet)
    !poker solo 15     — solo, bet 15
    !poker solo 0      — solo, free play
    !poker cancel      — cancel running game
    """

    # ── cancel ──
    if mode and mode.lower() in {"x", "cancel", "stop"}:
        game = ongoing_poker.pop(ctx.channel.id, None)
        if not game:
            return await ctx.send("No poker game to cancel.")
        game.ended       = True
        game.status_text = "Game cancelled."
        if game.timeout_task:
            game.timeout_task.cancel()
            game.timeout_task = None
        await _poker_update_message(ctx.bot, game, ctx.guild)
        return await ctx.send("Poker cancelled.")

    # ── already running ──
    if ctx.channel.id in ongoing_poker and not ongoing_poker[ctx.channel.id].ended:
        return await ctx.send("A poker game is already running here.")

    # `!poker 20` / `!poker 0` shorthand
    if mode and mode.lstrip("-").isdigit() and amount is None:
        amount = int(mode)
        mode   = None

    # ── solo ──
    if mode and mode.lower() == "solo":
        bet = await _poker_prompt_bet(ctx, amount)
        if bet is None: return
        if bet > 0 and not _poker_can_pay(ctx.author.id, bet):
            return await ctx.send("Not enough ARCs for a solo game.")

        game = PokerGame(ctx.author.id, ctx.channel.id, multiplayer=False)

        p     = PokerPlayer(ctx.author.id)
        p.bet = max(bet, 1)
        p.real_bet = bet
        game.players[ctx.author.id] = p
        if bet == 0:
            game.free_mode = True

        for did in DEALER_IDS:
            game.players[did] = PokerPlayer(did, is_dealer=True)

        if bet > 0:
            modify_coins(ctx.author.id, -bet)
        game.pot += bet
        game.start()
        ongoing_poker[ctx.channel.id] = game

        await _poker_send_hands(ctx.bot, ctx.guild, game)
        await _poker_update_message(ctx.bot, game, ctx.guild)
        return

    # ── unrecognised mode ──
    if mode and mode.lower() not in {"multi"}:
        return await ctx.send("Usage: `!poker` / `!poker solo` / `!poker cancel`")

    # ── multiplayer ──
    bet = await _poker_prompt_bet(ctx, amount)
    if bet is None: return
    if bet > 0 and not _poker_can_pay(ctx.author.id, bet):
        return await ctx.send("Not enough ARCs to host.")

    game      = PokerGame(ctx.author.id, ctx.channel.id, multiplayer=True)
    host      = PokerPlayer(ctx.author.id)
    host.bet  = max(bet, 1)
    host.real_bet = bet
    game.players[ctx.author.id] = host
    game.host_bet = bet
    if bet == 0:
        game.free_mode = True
    ongoing_poker[ctx.channel.id] = game

    await _poker_update_message(ctx.bot, game, ctx.guild)
    game.timeout_task = asyncio.create_task(
        _poker_timeout_if_not_started(ctx.bot, game, delay=180)
    )

