# ══════════════════════════════════════════════════════════════════════════════
#  CORE BLACKJACK ENGINE
# ══════════════════════════════════════════════════════════════════════════════

def _calculate_blackjack_score(hand: list[tuple[int, str]]) -> int:
    """Calculates the optimal Blackjack score for a given hand."""
    score = 0
    aces = 0
    for rank, _ in hand:
        if rank == 14:  # Ace
            aces += 1
            score += 11
        elif rank in (11, 12, 13):  # J, Q, K
            score += 10
        else:
            score += rank

    # Adjust for Aces if busting
    while score > 21 and aces > 0:
        score -= 10
        aces -= 1
    return score

def _get_poker_deck() -> list[tuple[int, str]]:
    """Helper generator to produce a fresh shuffled standard deck."""
    import random
    suits = ['♠', '♥', '♦', '♣']
    deck = [(rank, suit) for rank in range(2, 15) for suit in suits]
    random.shuffle(deck)
    return deck

class BlackjackGame:
    def __init__(self, game_id: int, initial_bet: int = 100, free_mode: bool = False):
        self.game_id = game_id
        self.deck = _get_poker_deck()
        self.free_mode = free_mode
        self.pot = 0 #if free_mode else initial_bet
        self.phase_step = 1  # 1 = Players Turn, 2 = Dealer Turn, 3 = Showdown
        self.status = "Players' turn to Hit or Stand/Fold."
        self.initial_bet = 0 if free_mode else initial_bet
        self.host_id = None
        self.phase_step = 0  # 0=lobby
        
        # Initialize Dealer (Top of Table layout)
        self.dealer = {
            "id": -1,
            "name": "NPC Dealer",
            "hand": [self.deck.pop(), self.deck.pop()],
            "state": "dealer",
            "bet": None,
            "show_hand": False,
            "hand_name": ""
        }
        
        self.players: list[dict] = []
        #print("i pot", self.pot)

    def add_player(self, player_id: int, name: str, is_you: bool = False):
        """Adds a player to the table and deals 2 cards."""
        if len(self.players) >= 5:  # Optimized horizontal layout bound
            return False
            
        self.players.append({
            "id": player_id,
            "name": name,
            "hand": [self.deck.pop(), self.deck.pop()],
            "state": "waiting",
            "bet": 0 if self.free_mode else self.initial_bet,
            "show_hand": True,
            "is_you": is_you,
            "hand_name": ""
        })
        if not self.free_mode and not is_you:
            self.pot += self.initial_bet
        #print(self.pot)
        return True

    def player_hit(self, player_id: int):
        """Deals a card to the player and checks for a bust."""
        p = next((x for x in self.players if x["id"] == player_id), None)
        if not p or p["state"] != "waiting":
            return False

        # Max out at 5 cards per block limit rules
        if len(p["hand"]) >= 5:
            return False

        p["hand"].append(self.deck.pop())
        score = _calculate_blackjack_score(p["hand"])
        p["hand_name"] = f"Score: {score}"

        if score > 21:
            p["state"] = "busted"  # Busted
            p["hand_name"] = f"Bust! ({score})"
            
        self._check_and_process_dealer_phase()
        return True

    def player_stand(self, player_id: int):
        """Stops drawing cards for the player."""
        p = next((x for x in self.players if x["id"] == player_id), None)
        if not p or p["state"] != "waiting":
            return False

        score = _calculate_blackjack_score(p["hand"])
        p["state"] = "called"  # Locks in hand state
        p["hand_name"] = f"Stood: {score}"
        
        self._check_and_process_dealer_phase()
        return True

    def _check_and_process_dealer_phase(self):
        #print("ENTER DEALER PHASE")

        if any(p["state"] == "waiting" for p in self.players):
           # print("Still waiting players")
            return

        self.phase_step = 2
        self.dealer["show_hand"] = True

        d_score = _calculate_blackjack_score(self.dealer["hand"])

        while d_score < 17 and len(self.dealer["hand"]) < 5:
            self.dealer["hand"].append(self.deck.pop())
            d_score = _calculate_blackjack_score(self.dealer["hand"])

        #print("Dealer score:", d_score)

        self.phase_step = 3

        for p in self.players:
            #print("Resolving", p["name"], p["state"])

            if p["state"] == "folded":
                continue

            p_score = _calculate_blackjack_score(p["hand"])

            if d_score > 21 or p_score > d_score and p_score < 22:
                p["state"] = "winner"
                modify_coins(p["id"], self.pot//len(self.players))
            elif p_score == d_score and p_score < 22:
                p["state"] = "called"
                #modify_coins(p["id"], -self.pot//len(self.players))
            else:
                p["state"] = "folded"
                modify_coins(p["id"], -self.pot//len(self.players))
            #print("Resolved", p["name"], p["state"])
        #print("DONE RESOLVING")


class BlackjackLobbyView(discord.ui.View):
    def __init__(self, game, ctx):
        super().__init__(timeout=180)
        self.game = game
        self.ctx = ctx
        self.message = None
    @discord.ui.button(label="Join",style=discord.ButtonStyle.success)
    async def join_button(self, interaction, button):

        if any(p["id"] == interaction.user.id for p in self.game.players):
            return await interaction.response.send_message(
                "You already joined.",
                ephemeral=True
            )

        self.game.add_player(
            interaction.user.id,
            interaction.user.display_name
        )

        await interaction.response.edit_message(
            content=self.build_lobby_text(),
            view=self
        )
    @discord.ui.button(label="Leave",style=discord.ButtonStyle.danger)
    async def leave_button(self, interaction, button):

        self.game.players = [
            p for p in self.game.players
            if p["id"] != interaction.user.id
        ]

        await interaction.response.edit_message(
            content=self.build_lobby_text(),
            view=self
        )
    @discord.ui.button(label="Start",style=discord.ButtonStyle.primary)
    async def start_button(self, interaction, button):

        if interaction.user.id != self.game.host_id:
            return await interaction.response.send_message(
                "Only the host can start.",
                ephemeral=True
            )

        if len(self.game.players) == 0:
            return await interaction.response.send_message(
                "Need at least 1 player.",
                ephemeral=True
            )

        self.game.phase_step = 1
        self.stop()

        for p in self.game.players:
            p["hand_name"] = (
                f"Points: "
                f"{_calculate_blackjack_score(p['hand'])}"
            )

        game_view = BlackjackView(self.game, self.ctx)

        img_buf = await _render_blackjack_table_canvas(self.game)

        file = discord.File(
            img_buf,
            filename="blackjack_table.png"
        )

        await interaction.response.edit_message(
            content=f"### {self.game.status}",
            attachments=[file],
            view=game_view
        )

        game_view.message = await interaction.original_response()
    def build_lobby_text(self):
        joined = "\n".join(
            f"• {p['name']}"
            for p in self.game.players
        )

        if not joined:
            joined = "Nobody joined yet."

        return (
            f"## Blackjack Lobby\n\n"
            f"Host: <@{self.game.host_id}>\n\n"
            f"{joined}\n\n"
            f"Starts automatically closing in "
            f"{int(self.timeout)} seconds."
        )
    async def on_timeout(self):
        if self.ctx.channel.id in ongoing_blackjack:
            del ongoing_blackjack[self.ctx.channel.id]

        try:
            await self.message.edit(
                content="Blackjack lobby expired.",
                view=None
            )
        except:
            pass
# ══════════════════════════════════════════════════════════════════════════════
#  DEDICATED BLACKJACK IMAGE CANVAS GENERATOR
# ══════════════════════════════════════════════════════════════════════════════

def _get_card_strings(rank: int, suit: str) -> tuple[str, str]:
    val_map = {11: "J", 12: "Q", 13: "K", 14: "A"}
    rank_str = val_map.get(rank, str(rank))
    return rank_str, suit

async def _render_blackjack_table_canvas(game: BlackjackGame) -> io.BytesIO:
    """Generates a unique customized Blackjack table layout using PIL."""
    # Create baseline canvas context (Width: 900px, Height: 550px)
    width, height = 900, 550
    image = Image.new("RGBA", (width, height), (20, 20, 20, 255))
    draw = ImageDraw.Draw(image)

    # Draw classic luxury felt casino table background inner arc
    draw.ellipse([50, -100, width - 50, height + 100], fill=(12, 74, 40, 255), outline=(194, 162, 102, 255), width=4)
    
    # Text Fonts fallback styling configurations
    try:
        font_title = ImageFont.truetype(_FONT_BOLD_PATH, 20)
        font_ui = ImageFont.truetype(_FONT_REG_PATH, 16)
    except Exception:
        font_title = None
        font_ui = None

    # Render Pot Display Info Banner text
    pot_str = "FREE PLAY MODE" if game.free_mode else f"TOTAL POT: {game.pot} Arcs"
    draw.text((width // 2, 230), pot_str, fill=(194, 162, 102, 255), anchor="mm", font=font_title)

    # ────── RENDER NPC DEALER (TOP CENTER) ──────
    d_x, d_y = width // 2, 40
    # Draw Dealer Title Tag Box
    draw.rectangle([d_x - 100, d_y, d_x + 100, d_y + 35], fill=(25, 25, 25, 220), outline=(150, 150, 150, 255))
    draw.text((d_x, d_y + 8), game.dealer["name"], fill=(255, 255, 255, 255), anchor="mm", font=font_ui)
    
    # Calculate score dynamic feedback alignment layout next to cards
    d_score_str = f"Score: {_calculate_blackjack_score(game.dealer['hand'])}" if game.dealer["show_hand"] else f"Showing: {_calculate_blackjack_score(game.dealer['hand'][:1])}"
    if game.dealer["state"] == "folded":
        d_score_str = "Bust!"
    draw.text((d_x, d_y + 22), d_score_str, fill=(230, 230, 100, 255), anchor="mm", font=font_ui)

    # Draw Dealer Hand cards horizontally below its label
    card_start_x = d_x - (len(game.dealer["hand"]) * 50) // 2
    card_y = d_y + 45
    for idx, card in enumerate(game.dealer["hand"]):
        cx = card_start_x + (idx * 52)
        if idx == 1 and not game.dealer["show_hand"]:
            # Hidden down-card styling design pattern
            draw.rectangle([cx, card_y, cx + 45, card_y + 65], fill=(40, 70, 120, 255), outline=(255, 255, 255, 255), width=2)
            draw.text((cx + 22, card_y + 32), "?", fill=(255, 255, 255, 255), anchor="mm", font=font_title)
        else:
            rank, suit = card
            r_s, s_s = _get_card_strings(rank, suit)
            color = (200, 30, 30, 255) if suit in ('♥', '♦') else (30, 30, 30, 255)
            
            draw.rectangle([cx, card_y, cx + 45, card_y + 65], fill=(255, 255, 255, 255), outline=(0, 0, 0, 255), width=1)
            draw.text((cx + 8, card_y + 12), r_s, fill=color, anchor="mm", font=font_ui)
            draw.text((cx + 22, card_y + 35), s_s, fill=color, anchor="mm", font=font_title)


    # ────── RENDER PLAYERS ROW (BOTTOM GRID) ──────
    num_players = len(game.players)
    if num_players > 0:
        spacing_x = width // (num_players + 1)
        for p_idx, p in enumerate(game.players):
            px = spacing_x * (p_idx + 1)
            py = 360

            # Match status badge context decoration border colors
            badge_border = (100, 255, 100, 255) if p["state"] == "called" else (255, 100, 100, 255) if p["state"] == "folded" else (240, 200, 50, 255) if p["state"] == "winner" else (200, 200, 200, 255)
            
            # Player Box Panel container bounds
            draw.rectangle([px - 85, py, px + 85, py + 40], fill=(15, 15, 15, 240), outline=badge_border, width=2)
            
            # Draw identity labels text items mapping
            display_name = f"⭐ {p['name']}" if p["is_you"] else p["name"]
            draw.text((px, py + 6), display_name, fill=(255, 255, 255, 255), anchor="mm", font=font_ui)
            
            # Points Indicator Text positioned cleanly right inside the block
            current_score = _calculate_blackjack_score(p["hand"])
            pts_text = p["hand_name"] if p["hand_name"] else f"Points: {current_score}"
            draw.text((px, py + 22), pts_text, fill=(180, 220, 255, 255), anchor="mm", font=font_ui)

            # Draw Hand block layout array horizontally supporting up to 5 cards max sequence
            p_card_start_x = px - (len(p["hand"]) * 42) // 2
            p_card_y = py + 50
            
            for idx, card in enumerate(p["hand"]):
                cx = p_card_start_x + (idx * 44)
                rank, suit = card
                r_s, s_s = _get_card_strings(rank, suit)
                color = (200, 30, 30, 255) if suit in ('♥', '♦') else (30, 30, 30, 255)
                
                draw.rectangle([cx, p_card_y, cx + 38, p_card_y + 56], fill=(255, 255, 255, 255), outline=(0, 0, 0, 255), width=1)
                draw.text((cx + 8, p_card_y + 10), r_s, fill=color, anchor="mm", font=font_ui)
                draw.text((cx + 19, p_card_y + 32), s_s, fill=color, anchor="mm", font=font_ui)

    # Save image object to payload bytes handler stream safely
    out = io.BytesIO()
    image.save(out, format="PNG")
    out.seek(0)
    return out


