class BlackjackView(discord.ui.View):
    def __init__(self, game: BlackjackGame, ctx):
        super().__init__(timeout=180.0)
        self.game = game
        self.ctx = ctx
        self.message = None

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        player_ids = [p["id"] for p in self.game.players]
        if interaction.user.id not in player_ids:
            await interaction.response.send_message(
                "This isn't your table! Type `!blackjack` to open your own table.", 
                ephemeral=True
            )
            return False
        return True

    async def _update_interface(self, interaction: discord.Interaction):
        """Re-renders the custom blackjack table image and updates the Discord active message frame state."""
        if self.game.phase_step == 3:
            self.disable_all_items()
            self.stop()
            if self.ctx.channel.id in ongoing_blackjack:
                del ongoing_blackjack[self.ctx.channel.id]

        # Call custom blackjack canvas rendering pipeline primitive
        img_buf = await _render_blackjack_table_canvas(self.game)
        file = discord.File(img_buf, filename="blackjack_table.png")
        
        await interaction.response.edit_message(
            content=f"### {self.game.status}", 
            attachments=[file], 
            view=self
        )

    @discord.ui.button(label="Hit", style=discord.ButtonStyle.blurple, emoji="🃏")
    async def hit_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        p = next((x for x in self.game.players if x["id"] == interaction.user.id), None)
        if not p or p["state"] != "waiting":
            return await interaction.response.send_message("You cannot hit right now.", ephemeral=True)

        if len(p["hand"]) >= 5:
            return await interaction.response.send_message("Maximum hand size limit (5 cards) reached!", ephemeral=True)

        self.game.player_hit(interaction.user.id)
        await self._update_interface(interaction)

    @discord.ui.button(label="Stand", style=discord.ButtonStyle.success, emoji="🛑")
    async def stand_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        p = next((x for x in self.game.players if x["id"] == interaction.user.id), None)
        if not p or p["state"] != "waiting":
            return await interaction.response.send_message("You cannot stand right now.", ephemeral=True)

        self.game.player_stand(interaction.user.id)
        await self._update_interface(interaction)

    @discord.ui.button(label="Fold", style=discord.ButtonStyle.danger, emoji="🏳️")
    async def fold_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        p = next((x for x in self.game.players if x["id"] == interaction.user.id), None)
        if not p or p["state"] != "waiting":
            return await interaction.response.send_message("You cannot fold right now.", ephemeral=True)

        p["state"] = "folded"
        p["hand_name"] = "Folded"
        
        self.game._check_and_process_dealer_phase()
        await self._update_interface(interaction)

    async def on_timeout(self):
        if self.message:
            self.disable_all_items()
            try:
                await self.message.edit(content="*Game timed out due to player inactivity.*", view=self)
            except discord.HTTPException:
                pass
            if self.ctx.channel.id in ongoing_blackjack:
                del ongoing_blackjack[self.ctx.channel.id]

    def disable_all_items(self):
        for item in self.children:
            item.disabled = True


# Global running games registry tracker
ongoing_blackjack: dict[int, BlackjackGame] = {}

@bot.command(name="blackjack", aliases=["bj"])
async def blackjack_cmd(ctx, amount: int = 100):

    if ctx.channel.id in ongoing_blackjack:
        return await ctx.send(
            "A blackjack game is already active."
        )
    if amount > 100:
        return await ctx.send("Small gambling can be done for fun, large gambling is harmful to your health.")
    elif amount <0:
        return await ctx.send("Negative money do not exist")
    initial_bet = amount
    if amount == 0:
        is_free = True
    else:
        is_free = False
    print("initial bet", initial_bet)

    game = BlackjackGame(
        game_id=ctx.channel.id,
        initial_bet=initial_bet,
        free_mode=is_free
    )

    game.host_id = ctx.author.id

    ongoing_blackjack[ctx.channel.id] = game

    view = BlackjackLobbyView(game, ctx)

    msg = await ctx.send(
        view.build_lobby_text(),
        view=view
    )

    view.message = msg

# Helper function to initialize and connect to the artist database
def get_artist_db_connection():
    conn = sqlite3.connect("artist.db")
    conn.execute("""
        CREATE TABLE IF NOT EXISTS artworks (
            artist_id INTEGER,
            cosmetic_name TEXT UNIQUE,
            path_name TEXT
        )
    """)
    conn.commit()
    return conn

# Helper function to look up user/artist names across cache and API fallbacks
async def get_artist_name(ctx, artist_id: int) -> str:
    member = ctx.guild.get_member(artist_id)
    if member:
        return member.display_name
    try:
        user = await ctx.bot.fetch_user(artist_id)
        return user.name
    except Exception:
        return f"User ID: {artist_id}"

