from discord.ext import commands
import discord

class CreditGalleryView(LayoutView):
    def __init__(self, ctx: commands.Context, rows_list: list):
        super().__init__(timeout=180)
        self.ctx = ctx
        self.rows_list = rows_list
        self.current_page = 0
        self.total_pages = len(rows_list)

    async def get_artist_display_name(self, artist_id: int) -> str:
        # Looking up member name inside guild cache/API fallbacks
        member = self.ctx.guild.get_member(artist_id)
        if member:
            return member.display_name
        try:
            user = await self.ctx.bot.fetch_user(artist_id)
            return user.name
        except Exception:
            return f"User ID: {artist_id}"

    async def refresh_layout(self):
        self.clear_items()
        
        # Pull data item matching current index
        artist_id, cosmetic_name, path_name = self.rows_list[self.current_page]
        
        # Build direct asset raw URL string
        image_url = f"https://raw.githubusercontent.com/Best1111-dev/Sprites/main/{path_name}"
        
        container = Container()
        
        # 1. Pokemon Cosmetic Name
        container.add_item(TextDisplay(f"## {cosmetic_name.title()}"))
        container.add_item(discord.ui.Separator()) # Render UI separator element
        
        # 2. Image Gallery Layout Item
        container.add_item(MediaGallery(
            MediaGalleryItem(image_url)
        ))
        container.add_item(discord.ui.Separator()) # Render UI separator element
        
        # 3. Dynamic async resolution for the author's tag line block
        # Because layout updates require text context immediately, 
        # we pull name string synchronously or resolve safely using a loop task
        artist_name = await self.get_artist_display_name(artist_id)
        
        # Text details positioned precisely below image asset container block
        details_text = (
            f"**Artist:** {artist_name}\n"
            f"Might be derivative of artwork by © The Pokemon Company\n"
            f"📁 `{self.current_page + 1} / {self.total_pages}`"
        )
        container.add_item(TextDisplay(details_text))
        self.add_item(container)
        
        # 4. Only append navigation control rows if multi-page galleries exist
        if self.total_pages > 1:
            nav_row = ActionRow()
            nav_row.add_item(discord.ui.Button(label="◀️ Previous", style=discord.ButtonStyle.secondary, custom_id="gallery_prev"))
            nav_row.add_item(discord.ui.Button(label="Next ▶️", style=discord.ButtonStyle.secondary, custom_id="gallery_next"))
            self.add_item(nav_row)

    # UI Interaction listeners overriding defaults to process pagination changes
    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        custom_id = interaction.data.get("custom_id")
        if custom_id in ["gallery_prev", "gallery_next"]:
            if custom_id == "gallery_prev":
                self.current_page = (self.current_page - 1) % self.total_pages
            else:
                self.current_page = (self.current_page + 1) % self.total_pages
                
            await self.refresh_layout()
            # Update container interface layout inside Discord context directly
            await interaction.response.edit_message(view=self)
            return True
        return await super().interaction_check(interaction)


@bot.command(name="credit", aliases=["dex", "cosmetic_view"])
async def credit(ctx, *, argument: str = None):
    conn = get_artist_db_connection()
    c = conn.cursor()
    c.execute("SELECT artist_id, cosmetic_name, path_name FROM artworks")
    rows = c.fetchall()
    conn.close()
    
    if not rows:
        return await ctx.send("❌ No cosmetic artwork credits found in the database.")
        
    filtered_rows = []
    
    if argument:
        argument_clean = argument.strip().lower()
        
        # Match Variant A: Target text maps directly to cosmetic name field
        cosmetic_match = [r for r in rows if r[1].strip().lower() == argument_clean]
        if cosmetic_match:
            filtered_rows = cosmetic_match
        else:
            # Match Variant B: Parsing string out as Snowflake ID or raw user string
            target_id = None
            if argument_clean.startswith("<@") and argument_clean.endswith(">"):
                uid_str = argument_clean.replace("<@", "").replace(">", "").replace("!", "")
                if uid_str.isdigit():
                    target_id = int(uid_str)
            elif argument_clean.isdigit():
                target_id = int(argument_clean)
                
            if target_id:
                filtered_rows = [r for r in rows if r[0] == target_id]
            else:
                # Try finding matched handle targets across local members
                member = discord.utils.find(
                    lambda m: m.name.lower() == argument_clean or m.display_name.lower() == argument_clean,
                    ctx.guild.members
                )
                if member:
                    filtered_rows = [r for r in rows if r[0] == member.id]
                else:
                    # Match Variant C: Partial sequence fallback match
                    filtered_rows = [r for r in rows if argument_clean in r[1].strip().lower()]
    else:
        # Match Variant D: Fallback to show global collections list
        filtered_rows = rows

    if not filtered_rows:
        return await ctx.send(f"❌ No registered artists or cosmetics found matching `{argument}`.")

    # Render view utilizing customized frame containers instead of Embed items
    view = CreditGalleryView(ctx, filtered_rows)
    await view.refresh_layout()
    await ctx.send(view=view)


