# 2. !claim_art COMMAND & APPROVAL PROCESS
# ==========================================
@bot.command(name="claim_art")
async def claim_art(ctx, *, cosmetic_name: str = None):
    if not cosmetic_name:
        return await ctx.send("❌ Please specify the cosmetic item name. Example: `!claim_art wolf king zacian`")
        
    if not ctx.message.attachments:
        return await ctx.send("❌ Please attach the PNG artwork file directly to your command message.")
        
    attachment = ctx.message.attachments[0]
    if not attachment.filename.lower().endswith(('.png', '.jpg', '.jpeg', '.webp')):
        return await ctx.send("❌ Attached file must be an image format.")
        
    # Read attachment payload bytes instantly
    png_bytes = await attachment.read()
    
    # Process path: substitute spaces with underscores
    clean_name = cosmetic_name.strip().replace(" ", "_")
    path_name = f"full_size_{clean_name}.png"

    class ArtApprovalView(discord.ui.View):
        def __init__(self):
            super().__init__(timeout=180) # 3-minute timeout window

        @discord.ui.button(label="Approve & Upload", style=discord.ButtonStyle.success)
        async def approve(self, interaction: discord.Interaction, button: discord.ui.Button):
            # Strict validation checking interaction user against global owner_ids list
            if interaction.user.id not in owner_ids:
                return await interaction.response.send_message("❌ Only bot owners can approve artwork claims.", ephemeral=True)
                
            await interaction.response.defer()
            button.disabled = True
            await interaction.message.edit(view=self)
            
            # Execute synchronous GitHub HTTP request within an optimized async worker thread
            success, error_msg = await asyncio.to_thread(_upload_sprite_to_github, path_name, png_bytes)
            
            if success:
                conn = get_artist_db_connection()
                c = conn.cursor()
                try:
                    c.execute("""
                        INSERT INTO artworks (artist_id, cosmetic_name, path_name)
                        VALUES (?, ?, ?)
                        ON CONFLICT(cosmetic_name) DO UPDATE SET artist_id=excluded.artist_id, path_name=excluded.path_name
                    """, (ctx.author.id, cosmetic_name.strip(), path_name))
                    conn.commit()
                    await interaction.channel.send(f"✅ Artwork successfully uploaded! `{cosmetic_name}` is now credited to {ctx.author.mention}.")
                except Exception as db_err:
                    await interaction.channel.send(f"⚠️ GitHub uploaded, but database registration failed: {db_err}")
                finally:
                    conn.close()
            else:
                await interaction.channel.send(f"❌ GitHub API error: {error_msg}")
                button.disabled = False
                await interaction.message.edit(view=self)

        async def on_timeout(self):
            for child in self.children:
                child.disabled = True
            try:
                await self.message.edit(view=self)
            except Exception:
                pass

    view = ArtApprovalView()
    msg = await ctx.send(
        f"⏳ **New Artwork Claim Verification Request**\n"
        f"• **Artist:** {ctx.author.mention}\n"
        f"• **Cosmetic:** `{cosmetic_name}`\n"
        f"• **Destination Path:** `{path_name}`\n"
        f"A bot owner must click approve within 3 minutes.", 
        view=view
    )
    view.message = msg


# ==========================================
# 3. !remove_art / !remove_artwork COMMAND
# ==========================================
@bot.command(name="remove_art", aliases=["remove_artwork"])
async def remove_art(ctx, *, cosmetic_name: str = None):
    if not cosmetic_name:
        return await ctx.send("❌ Please state the cosmetic name to remove.")
        
    conn = get_artist_db_connection()
    c = conn.cursor()
    c.execute("SELECT artist_id FROM artworks WHERE LOWER(cosmetic_name) = ?", (cosmetic_name.strip().lower(),))
    row = c.fetchone()
    
    if not row:
        conn.close()
        return await ctx.send(f"❌ No registered artwork entry found for `{cosmetic_name}`.")
        
    artist_id = row[0]
    
    # Check permissions: Original Artist or Bot Owner
    if ctx.author.id != artist_id and ctx.author.id not in owner_ids:
        conn.close()
        return await ctx.send("❌ Permission denied. Only the original artist or a bot owner can remove this artwork.")
        
    c.execute("DELETE FROM artworks WHERE LOWER(cosmetic_name) = ?", (cosmetic_name.strip().lower(),))
    conn.commit()
    conn.close()
    
    await ctx.send(f"🗑️ Successfully deleted `{cosmetic_name}` database records.")

