# --- Subscription Control Commands (Works in Servers & DMs) ---
@bot.command()
async def subscribe(ctx):
    global unsubscribed_users_cache
    user_id = ctx.author.id
    
    # If they are in the opt-out list, remove them to re-subscribe them
    if user_id in unsubscribed_users_cache:
        unsubscribed_users_cache.remove(user_id)
        await ctx.send("🔔 Success! You have re-subscribed to the Goldi Newsletter. You will receive updates again when using slash commands.")
    else:
        await ctx.send("ℹ️ You are already subscribed to the Goldi Newsletter by default!")

@bot.command()
async def unsubscribe(ctx):
    global unsubscribed_users_cache
    user_id = ctx.author.id
    
    # Add them to the opt-out list
    if user_id not in unsubscribed_users_cache:
        unsubscribed_users_cache.add(user_id)
        await ctx.send("🔕 You have unsubscribed from the Goldi Newsletter and will no longer receive updates.")
    else:
        await ctx.send("❌ You are already unsubscribed from the newsletter.")


