import traceback
# --- Main Bot Runner Block (Crucial for graceful shutdown) ---
async def main():
    # Load any extensions/cogs here if you have them
    # await bot.load_extension("your_cog_file")

    try:
        print("[MAIN] Starting bot...")
        # Use bot.start for more robust shutdown handling with asyncio
        await bot.start(TOKEN) 
        print("[MAIN] bot.start returned normally")
    except KeyboardInterrupt:
        print("\n[MAIN] KeyboardInterrupt detected. Initiating graceful shutdown...")
    except Exception:
        print("\n[MAIN] Shutdown detected via exception. Initiating graceful shutdown...")
        traceback.print_exc()
    finally:
        print("[MAIN] Entered finally block")
        # ==========================================
        # SAVE NEWSLETTER & OPT-OUT CACHES ON SHUTDOWN
        # ==========================================
        global newsletter_cache, sent_users_cache, unsubscribed_users_cache
        try:
            print("[MAIN] Writing newsletter and opt-out memory caches to disk...")
            data = {
                "content": newsletter_cache,
                "sent_users": list(sent_users_cache),
                "unsubscribed_users": list(unsubscribed_users_cache) # CHANGED
            }
            with open(DATA_FILE, "w") as f:
                json.dump(data, f, indent=4)
            print("[MAIN] Newsletter and opt-out caches saved securely.")
        except Exception as e:
            print(f"[MAIN] Failed to save newsletter cache: {e}")
        # ==========================================
        # Save task schedules
        #print("Saving task schedules during shutdown...")
        #save_task_schedules([clean_invite_joined_files_task, monitor_invite_counts_task])
        channel_id = 1333642558743515186
        alert_channel = bot.get_channel(channel_id)
        if alert_channel is None:
            alert_channel = await bot.fetch_channel(channel_id)
        try:
            await alert_channel.send('<a:red_dot:1383016307355553903>Bot is down')
        except Exception as e:
            print(f"[MAIN] Failed to send shutdown alert: {e}")
        #print("Task schedules saved.")
        
        # Close the bot's connection. This will also stop all tasks.
        if not bot.is_closed():
            print("[MAIN] Bot not closed yet; cancelling auction tasks")
            # Cancel all active auction timers
            for auction in _active_auctions.values():
                task = auction.get("timer_task")
                print(f"[MAIN] Cancelling active auction timer task: {task}")
                if task and not task.done():
                    task.cancel()
                    try:
                        await task
                    except asyncio.CancelledError:
                        print("[MAIN] Active auction timer task cancelled")
                        pass

            # Cancel old auction tasks too, if they exist
            try:
                print(f"[MAIN] Legacy auction_tasks present: {len(auction_tasks)}")
                for task in list(auction_tasks.values()):
                    print(f"[MAIN] Cancelling legacy auction task: {task}")
                    if task and not task.done():
                        task.cancel()
                        try:
                            await task
                        except asyncio.CancelledError:
                            print("[MAIN] Legacy auction task cancelled")
                            pass
            except NameError:
                print("[MAIN] auction_tasks name not found")
                pass

            try:
                print("[MAIN] Calling bot.close()")
                await bot.close()
            except Exception as e:
                print(f"[MAIN] bot.close() failed: {e}")
            finally:
                if 'auction_db' in globals():
                    try:
                        print("[MAIN] Closing auction_db")
                        await auction_db.close()
                    except Exception as e:
                        print(f"[MAIN] auction_db.close failed: {e}")

                pending = [
                    t for t in asyncio.all_tasks()
                    if t is not asyncio.current_task()
                ]
                if pending:
                    print(f"[MAIN] Pending tasks after bot.close: {len(pending)}")
                    for task in pending:
                        print(
                            f"[MAIN]   pending task: {task!r} "
                            f"done={task.done()} cancelled={task.cancelled()}"
                        )
                        if not task.done():
                            task.cancel()
                    try:
                        await asyncio.gather(*pending, return_exceptions=True)
                    except Exception as e:
                        print(f"[MAIN] gather pending tasks exception: {e}")

                print(f"[MAIN] Active threads: {threading.active_count()}")
                for th in threading.enumerate():
                    print(f"[MAIN]   thread: {th.name}, daemon={th.daemon}, alive={th.is_alive()}")
                try:
                    active_proc = multiprocessing.active_children()
                    print(f"[MAIN] Active multiprocessing children: {len(active_proc)}")
                    for proc in active_proc:
                        print(f"[MAIN]   process: pid={proc.pid}, name={proc.name}, alive={proc.is_alive()}")
                except Exception as e:
                    print(f"[MAIN] multiprocessing.active_children failed: {e}")
        else:
            print("[MAIN] Bot already closed")
            pending = [
                t for t in asyncio.all_tasks()
                if t is not asyncio.current_task()
            ]
            if pending:
                print(f"[MAIN] Pending tasks with bot already closed: {len(pending)}")
                for task in pending:
                    print(
                        f"[MAIN]   pending task: {task!r} "
                        f"done={task.done()} cancelled={task.cancelled()}"
                    )
                    if not task.done():
                        task.cancel()
                try:
                    await asyncio.gather(*pending, return_exceptions=True)
                except Exception as e:
                    print(f"[MAIN] gather pending tasks exception: {e}")
            print(f"[MAIN] Active threads: {threading.active_count()}")
            for th in threading.enumerate():
                print(f"[MAIN]   thread: {th.name}, daemon={th.daemon}, alive={th.is_alive()}")
            try:
                active_proc = multiprocessing.active_children()
                print(f"[MAIN] Active multiprocessing children: {len(active_proc)}")
                for proc in active_proc:
                    print(f"[MAIN]   process: pid={proc.pid}, name={proc.name}, alive={proc.is_alive()}")
            except Exception as e:
                print(f"[MAIN] multiprocessing.active_children failed: {e}")
        print("Bot connection gracefully closed.")

if __name__ == "__main__":
    # Ensure your bot object 'bot' is created before running main()
    # For example: bot = commands.Bot(command_prefix='!', intents=discord.Intents.default())
    
    # This is the standard way to run the async main function
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("[MAIN] KeyboardInterrupt received during run; exiting now.")
        sys.exit(0)
    except Exception as e:
        print(f"[MAIN] Unexpected exception in main runner: {e}")
        traceback.print_exc()
        sys.exit(1)
